INSERT INTO `data` VALUES (10001, 'c***曦', 5, '联想拯救者r7000 真的很不错，独立直显，打游戏非常通畅，一点都不会卡頓，真的很棒，开机不到8秒，双十一期间不到六千块，真的很实惠，物有所值，键盘自带光线，还会赠送鼠标，鼠标垫，清洁刷，背包，体积不重，续航很棒，堪称\n3050 天花板', '16G内存 512G固态 标配版', '2022-11-12 18:42:50', 7);
INSERT INTO `data` VALUES (10002, 'j***u', 5, 'LEGION\n联想拯救者R7000 p图设计师电\n只\n竞游戏笔记本电脑y RTX3050独..\n显卡效果非常棒!对于打游戏的人来说，太香了!物流也快，没几天就到了，服务态度也很好!画质高清，看起来很舒服，没有卡顿，完美!物流速度很快，东西收到特别满意，机身颇有设计感，满满的高级感很喜欢，运行也不错，客服人员也特别好回应很快，总而言之，产品很好，这台拯救者电脑真的外观非常漂亮!质感也很好!买来做设计的，配置也够高!开机速度也很快!', '32G内存 1TB固态 升级版', '2023-02-06 19:05:01', 5);
INSERT INTO `data` VALUES (10003, 'L***e', 5, '这一代小米 13感觉特别好，用习惯了苹果转过来的，手机电池耗电挺耐用，省电还是可以的，发热情况很好，玩游戏绝对不会卡，基本不发热，手机手感绝佳，机壳颜色也很不错，徕卡拍照一流，抵得过半个好相机。', '白色', '2023-01-18 01:49:59', 6);
INSERT INTO `data` VALUES (10004, 'h***3', 5, '外形外观：红米k60的外观很大气，外观很好看，黑色显得比较稳重，我觉得挺好看。\n\n屏幕音效：屏幕分辨率挺高的，看着很清晰，120hz刷新率很丝滑很顺畅，没有迟滞感。 \n运行速度：运行速度很快，多程序运行丝毫不会卡顿，使用感觉良好！\n总之一句话，性价比没的说！', '墨羽', '2023-01-26 21:13:33', 6);
INSERT INTO `data` VALUES (10005, '落***露', 5, 'redmi k60 刚发布就预定了，性价比挺高。处理器内存都足够用，屏幕成色挺好，预装了 MIUI14，系统非常流畅。', '墨羽', '2023-01-02 16:00:49', 4);
INSERT INTO `data` VALUES (10006, '丹***3', 5, '华为Mate20换红米k60\n满满的都是惊喜，屏幕超乎想象的好，选了很久，其他手机都好贵，想着2000多块钱买个手机试试，结果超乎我的想象，比华为Mate20，强太多太多了。我手机拍不出效果，还是甄姬比较惊艳。', '幽芒', '2023-01-01 18:20:24', 4);
INSERT INTO `data` VALUES (10007, 'K***源', 5, '平板真不错，送给妹妹的过年礼物，开心的不得了，好看好看真好看，流畅度很高，不卡，很轻薄，方便携带，运行速度很快，太喜欢了', '银色', '2023-01-24 15:13:46', 2);
INSERT INTO `data` VALUES (10008, '哆***啦', 5, 'ipad很好用的 建议可以买大内存的，以备不时之需。颜值非常高，系统很流畅，用来刷剧看视频很爽，可以用个四五年了哈哈镜哦。', '银色', '2023-01-18 16:51:44', 2);
INSERT INTO `data` VALUES (10009, '假***生', 5, '华硕无畏Pro15 2022锐龙版，是台比较均衡的高性能全能本。特别是比起上代无畏Pro15的进步很大，屏幕从上代的1080P分辨率的屏幕换成了2.8K 120Hz刷新率的OLED屏幕。 色彩上也有逐台的潘通校色且支持色彩切换，在开启HDR后全亮度类DC调光，也不用担心OLED的频闪问题。', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-14 10:10:23', 4);
INSERT INTO `data` VALUES (10010, 'w***9', 5, '这款笔记本拯救者r9000p运行速度非常快，很清晰，颜色绚丽，收到拆开箱子就非常喜欢，看着就高大尚，键盘手感也很棒，非常顺畅。', '专业电竞R9000P', '2022-10-18 22:20:03', 5);
INSERT INTO `data` VALUES (10011, '王***8', 5, '非常喜欢这款拯救者r7000p 性能爆炸颜值超高\n外形外观：外形时尚美观\n画面品质：高清份倍率高刷新率\n游戏效果：世面游戏随便玩\n包装保护：包装非常好没有磕碰\n运行速度：开机速度非常快也就几秒', '专业电竞R9000P', '2022-08-13 11:45:28', 4);
INSERT INTO `data` VALUES (10012, 'S***8', 5, '媳妇平时做点小设计，剪辑下视频，做做平面图之类的，没想买游戏本，出于有点私信，左挑右选，选择了联想拯救者R9000，各项配置完全够用，游戏很流畅，开启野兽那是杠杠的！外观大气，大Y标超级显眼，R7-6800H/RTX3060运行流畅，画质完美，游戏效果棒！京东物流依旧给力，外包装无破损，机器完美！', '【销量先锋】专业电竞R9000P', '2023-03-17 16:24:35', 3);
INSERT INTO `data` VALUES (10013, 'j***i', 5, '显卡效果非常棒！对于打游戏的人来说，太香了！物流也快，没几天就到了，服务态度也很好！画质高清，看起来很舒服，没有卡顿，完美！物流速度很快，东西收到特别满意，机身颇有设计感，满满的高级感很喜欢，运行也不错，客服人员也特别好回应很快，总而言之，产品很好，这台拯救者电脑真的外观非常漂亮！质感也很好！买来做设计的，配置也够高！开机速度也很快！最主要是太拉风了 外观材质：外观属实惊艳到我 特别酷帅到炸 电脑性能：电脑开机很快  我专业是数字媒体。', '16G内存 512G固态 标配版', '2022-10-21 09:36:43', 8);
INSERT INTO `data` VALUES (10014, 'l***6', 5, '京东的配送速度很快，点赞非常快非常好。经常在京东购买商品，配送速度保证时效，商品保质保量。\n外形外观：外形小巧灵动很好。\n屏幕音效：屏幕效果很好，音效也很好。6.36英寸E6直屏\n拍照效果：徕卡专业影像配备了徕卡光学镜头，后置5400万像素主镜头，1200万像素超广角镜头，1000万像素长焦镜头，前置3200万像素摄像头。\n运行速度：使用了最新的高通骁龙8第二代八核处理器，应用程序打开速度快。\n待机时间：待机时间长，搭载了4500毫安的大容量电池。充电速度快，支持无线充电。\n其他特色：支持IP68等级的防水防护。小米13是2023最期待最惊喜的旗舰手机，首先看了网络数码博主的测评，其次在线下体验了小米13手机，觉得手机的手感很好，是一款不错的直屏手机旗舰。手机整体的性能也很不错，跑分水平很高，电池容量大，续航时间长。小米13搭载了全新的MIUI14系统，不仅精简了系统的存储空间，而且可以对预装的系统程序有更好的可调节性。小米13是国货手机之光。', '黑色', '2023-01-03 14:54:21', 7);
INSERT INTO `data` VALUES (10015, '双***半', 5, 'apple ipad没什么好说的，看价位买呗。感觉这款9代性价比蛮高的。而且还是最后一款home键位的iPad，值得纪念。\n外观材质：一入既往的优秀\n屏幕效果：无懈可击\n运行速度：七分迅速，少三分，一分留给十代，一分留给air，一分留给pro。\n轻薄程度：尚可', '银色', '2023-02-04 16:35:47', 2);
INSERT INTO `data` VALUES (10016, 'P***8', 5, '还可以，安全下车，拍了银色，银色也很好看啦，ipad挺轻的，就是我的壳好重!\n外观材质：质感很好\n屏幕效果：很清晰，眼睛很舒服\n运行速度：运行很快\n轻薄程度：适中，黄金手感', '银色', '2022-02-18 22:16:21', 4);
INSERT INTO `data` VALUES (10017, '橘***柑', 5, '这个Apple  ipad主要是给孩子学习娱乐的，64内存够用了，哈哈，画质清晰，运行流畅，银色很漂亮哦，苹果平板电脑果然好，终于知道为什么大家伙都喜欢用苹果平板电脑了，还会继续支持，争当果粉\n外观材质：好\n屏幕效果：好\n运行速度：嗖嗖的\n轻薄程度：轻便\n其他特色：很好', '银色', '2022-11-02 00:24:26', 5);
INSERT INTO `data` VALUES (10018, '我***喆', 5, '外观精美，大小合适，字体清晰，运行速度很快，非常轻\n薄，颜色也好看，大人喜欢宝宝喜欢，功能不错，画面感\n很不错，学个英语，玩个游戏，喜欢很喜欢，屏幕清晰流\n畅。宝宝学习很方便，屏幕比老款太了不少，看视频很方\n便。菲常完美的一款iPad，这是我人生当中的第1个苹巢\n产品，非常的好用；屏幕啊，运行方面都特别的流畅，而\n且买的这支笔简直非常的好用，比安卓机都好用上万倍，\n真的是已经爱不释手了，他不管是游戏还是画画还是什么', '深空灰色', '2022-08-22 14:14:53', 4);
INSERT INTO `data` VALUES (10019, '修***哇', 5, '外观材质：iPad YYDS，平板电脑只有两种，一种是苹果，另一种是其他。外观高端大气上档次，简约时尚有气质。\n屏幕效果：屏幕效果更是不必赘述，视网膜级屏幕显示效果清晰多彩\n运行速度：这更是苹果一贯的擅长之处了，流畅无卡顿，纵享丝滑\n轻薄程度：随身携带犹如无物，非常轻便', '深空灰色', '2022-09-03 14:14:27', 5);
INSERT INTO `data` VALUES (10020, 'h***8', 5, '苹果ipad  9TH,性能好，屏幕大，触摸灵敏，电池耐用，是小孩在家上网课，大人娱乐之首选。打游戏也特别流畅，画面清晣。', '银色', '2022-11-06 17:57:39', 2);
INSERT INTO `data` VALUES (10021, '浅***风', 5, '不错第二天就到了，人生第一台iPad，好看，深空灰很高级。学生党，买来考研考公，希望可以成为生产力，成功上岸。\n外观材质：外观很好\n轻薄程度：很轻薄，比我的华为matebook轻一点\n屏幕效果：非全贴合屏，其实也没多大影响\n运行速度：运行速度杠杠的', '深空灰色', '2022-07-07 11:29:25', 5);
INSERT INTO `data` VALUES (10022, 'f***o', 5, '联想拯救者R9000X终于入手了，整机金属质感，颜值爆表。敲击键盘手感相当舒服。165Hz 10bit高色域屏，无论办公还是游戏，色彩还原度非常高，眼睛也不疲劳。更有AMD RX6800S独立显卡加持，性能完全能媲美台式机。', '轻薄电竞R9000X', '2022-11-21 12:15:01', 6);
INSERT INTO `data` VALUES (10023, 'j***7', 5, '16：10的屏幕真的非常大非常舒服，2.5K屏也是观感无敌，到手验机只通电了3小时确实不错，硬盘是三星的，拯救者r9000p确实是一款非常不错的游戏本，几乎没有缺陷，玩apex2.5k可以160帧，奥德赛高画质关抗锯齿有70帧左右', '【销量先锋】专业电竞R9000P', '2023-02-25 01:54:30', 6);
INSERT INTO `data` VALUES (10024, '售***人', 5, '想买个笔记本很久了，关注了不少品牌的机型，最后还是选择了R9000X2022，外观全金属质感很好，键盘手感舒适，屏幕不必多说，完美！双A平台性能强劲，完全满足了我的需求，甚至在未来的相当一段时间内都可以满足我的需求，很满意这款产品。', '轻薄电竞R9000X', '2022-11-19 19:40:26', 5);
INSERT INTO `data` VALUES (10025, 'j***h', 5, '联想拯救者R9000P，拿到手后，第一时间开箱。做工相当好，A壳金属手感一流，奔驰灯颜值高，外观真是太惊艳了。2K屏大爱，显示细腻，无论游戏办公，效果杠杠的。键盘布局合理，手感一流。独立显卡给力，这是一个五星水桶机，没有短板，给联想大大的赞。', 'R9000P', '2021-04-07 20:34:17', 8);
INSERT INTO `data` VALUES (10026, 'c***r', 5, '非常不错，这款 r9000p 2022 款玩游戏很流畅，对于我这种普通玩家来说已经够用了。fn+q 快捷切换三种模式也很便利。目前我给它配了个 拯救者 135w 氮化镓快充，但是玩大型游戏的话还是建议使用自带的 300w 充电器。 据说马上要新出一款 300w 氮化镓，希望能缩小体积减轻重量。还是很期待的。', '【销量先锋】专业电竞R9000P', '2023-03-07 14:16:25', 6);
INSERT INTO `data` VALUES (10027, '晼***儿', 5, '联想拯救者R9000X，高刷电竞，真不错，手感非常舒适，速度很快，还是超薄，在游戏本领域，能承受轻薄本的称号。我最怕重的本本了，但是真心说比之前用的笔记本舒适到那去了，外观颜值\n很漂亮，耐用。', '轻薄电竞R9000X', '2022-12-26 14:30:19', 6);
INSERT INTO `data` VALUES (10028, '小***8', 5, '联想拯救者R9000P值得拥有，运行速度快，游戏本的首推，有条件的可以上更高配置，屏幕 音效 运行 系统等都很厉害。', '【销量先锋】专业电竞R9000P', '2023-03-12 13:37:38', 2);
INSERT INTO `data` VALUES (10029, '枫***雪', 5, '包装保护：非常不错\n外形外观：高端大气上档次\n\n画面品质：非常清晰\n\n跑分评测：非常高\n\n运行速度：非常快\n游戏效果：非常快\n电脑中大大奔，拯救者R9000P\n采用满血版3060处理器，比3050快不少\n16G内存，最大可扩展64G\n外观采用铝合金材质，看起来高端大气上档次\n游戏随便玩，挖矿随便挖', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2021-11-20 19:40:02', 9);
INSERT INTO `data` VALUES (10030, 'u***8', 5, '专业电竞R9000P，标压R7...包装保护：包装很给力，包的很严实，有泡沫保护着，很赞\n外形外观：做工很精细，外观还是很漂亮的，\n画面品质：画面清晰，色彩丰富，整体很可以\n运行速度：开机速度快，打游戏运行起来很流畅，\n游戏效果：游戏页面看着很清晰，色彩鲜艳，运行起来\n没有卡顿的现象\n这次选购还是很喜欢的，大件都在京东买，物流也非常的快', '【销量先锋】专业电竞R9000P', '2023-03-13 14:03:06', 4);
INSERT INTO `data` VALUES (10031, '洋***爱', 5, '性能释放非常棒，做工细节完美，感觉很完美，这就是我想要的笔记本，9000 系列比 7000 系列有更好的散热和做工细节,如果你不是那么在乎性能，而是想要一个好屏幕，好散热的游戏本，3060 版本的 R9000P 将会是值得考虑的选择。', 'R9000P', '2021-04-07 23:27:23', 8);
INSERT INTO `data` VALUES (10032, '凡***购', 5, '外形外观：非常漂亮，买它是外观吸引了我\n屏幕音效：显示清晰，肉眼并看不到颗粒感，\n拍照效果：莱卡加持的相机果然不错，拍的照片很真实，特别是夜景，你肉眼看到什么样，拍出来就是什么样，非常奈斯！\n运行速度：运行速度非常流畅，一点都不卡顿。\n待机时间：待机时间中度使用一天，完全没有任何压力\n其他特色：手感好，重量轻，做工精，这是所有小米手机当中颜值最高的一款。', '黑色', '2022-12-15 21:01:40', 7);
INSERT INTO `data` VALUES (10033, '刘***c', 5, '目前到手感觉还行，可以冲一手兄弟们。性价比高，手感也很好！这款手机采用了骁龙8+性能铁三角组合，搭配12+256 GB的超大内存和MIUI13系统 使用是非常流畅的。另外该机还采用了120W+5000毫安的 续航套装，不仅续航表现出色，而且充电速度是非常快的。除此之外，该机还采用了一亿像素光学防抖后 置主摄和1.5K旗舰直屏等配置，外观方面，手机尺寸为6.67英寸，机身重202g.厚度为8.48mm。采用1.5K定制直屏（2712&times;1220），支持120Hz刷新率446PPi，观感接近2K屏幕，功耗却与1080P屏幕相近，且采用硬件 级低蓝光。超窄边框，2.4mm超小下巴。配置方面，搭 载高通骁龙8+处理器，CPU与GPU性能相比上 代都有 很大的提升。散 热方面，采用电竞级VC散热，覆盖面 积3725mm，12层堆叠。散热能力大幅度提升。续航方面，5000mAh大电量电池搭配120W闪充。拍摄方面，后置摄像头采用1亿像素主摄，支持OIS光学防 抖；8MP超广角摄像头;2MP微距摄像头。前置摄像头则采用20MP摄像头。屏下指纹重新回归，支持心率 监测、暗光解 锁   后续会追评！', '白色', '2023-01-02 17:37:33', 6);
INSERT INTO `data` VALUES (10034, '会***子', 5, '外形外观：白色太漂亮了，握感觉舒服。\n屏幕音效：终于有小屏旗舰了，米10太重了，13刚刚好。\n拍照效果：拍照杠杠滴。\n运行速度：运行速度很快\n其他特色：家里的1000m光纤终于可以跑满了。\n其他的慢慢体验。', '白色', '2022-12-16 13:03:02', 6);
INSERT INTO `data` VALUES (10035, '晩***榆', 5, '外形外观：手感不错，不愧是小屏旗舰，外观设计优雅大气\n屏幕音效：屏幕显示清晰，屏幕边框完美，音效逼真，还原真实\n拍照效果：拍摄清晰，莱卡联名，夜景很好，前置也很棒，随手出大片\n运行速度：骁龙8gen2，运行速度快，游戏毫无压力，旗舰处理器完美运行\n待机时间：待机时间长，小屏旗舰的优势\n其他特色：很喜欢这款手机，希望小米越来越好', '旷野绿', '2022-12-17 17:16:34', 5);
INSERT INTO `data` VALUES (10036, 'j***Y', 5, '外形外观：东西已经收到！手感不错！用料扎实！质量很好！平常用基本没有问题！\n屏幕音效：清晰，很好\n运行速度：反应灵敏\n拍照效果：成片效果好速度快', '旷野绿', '2023-03-10 11:06:29', 9);
INSERT INTO `data` VALUES (10037, 'V***箭', 5, '首发入手，还是很超值的，比水果机流畅，试了传说中的原神最高画质，一小时都不发热，帧数很高，稳定流畅，爽歪歪！水果机就不一样，要发烫的哦！小米13，冲！五星好评！', '远山蓝', '2022-12-17 09:23:11', 7);
INSERT INTO `data` VALUES (10038, 'L***e', 5, '这一代小米 13感觉特别好，用习惯了苹果转过来的，手机电池耗电挺耐用，省电还是可以的，发热情况很好，玩游戏绝对不会卡，基本不发热，手机手感绝佳，机壳颜色也很不错，徕卡拍照一流，抵得过半个好相机。', '白色', '2023-01-18 01:49:59', 6);
INSERT INTO `data` VALUES (10039, 'l***8', 5, '外形外观：就两个字:漂亮，握持手感很棒。\n屏幕音效：显示清晰，声音爆满，音效很好。\n拍照效果：莱卡加持，拍照有保障。\n运行速度：骁龙满血8gen2快的一匹。\n待机时间：刚拿到，需要用几天才知道，貌似续航还是很不错的。\n其他特色：手感绝佳，拍照清晰，声音好听，通话质量很好。', '远山蓝', '2023-02-08 18:37:02', 7);
INSERT INTO `data` VALUES (10040, 'L***光', 5, '超值&rdquo;游戏利器&mdash;&mdash;搭载AMD锐龙7 5800H以及RTX 3060显卡、16GB双通道内存、512GB SSD，拥有2.5K分辨率、165Hz刷新率16英寸屏幕的联想拯救者R9000P外观简约干练，硬朗冷酷\n\n　　联想拯救者R9000P的外观有浓厚的家族基因&mdash;&mdash;简约干练，却透露着硬朗冷酷的味道。\n\nA面中间为可控&ldquo;Y&rdquo;灯，很有辨识度。两侧对称的腰线增加了A面的层次感。此外，该机A面与D面均为金属材质，细腻的表面手感和质感都让人印象深刻，可以说一上手就能感受到扎实的做工。\n当然超高屏占比还可以提升视觉代入感，不过联想拯救者R9000P屏幕的优点还不止于此。这块16英寸屏幕拥有2560X1600高分辨率、165Hz高刷新率、100%sRGB高色域、3ms个高速响应时间、G-Sync与FreeSync双料防撕裂等特性，可以带来更细腻、逼真且顺畅的游戏画面。', 'R9000P/RTX3060/R7/165Hz 2.5k屏', '2021-09-22 10:21:38', 9);
INSERT INTO `data` VALUES (10041, 'j***g', 5, '外形外观：做工简洁，机器质感优秀，手感很好，AD金属面非常上档次！！\n画面品质：这块屏幕就是彻彻底底的加分项，效果太好了！细腻清晰，颜色也好！！\n跑分评测：跑分也是一众同等配置机型中的佼佼者，数一数二的性能发挥！！！\n运行速度：速度很快很流畅！！！\n\n买之前也对此了很多竞品机型，有机械的钛钽plus，微星GP76，最终选择了R9000p，非常满意！！！', 'R9000P', '2021-04-08 14:20:07', 8);
INSERT INTO `data` VALUES (10042, 'w***9', 5, '这款笔记本拯救者r9000p运行速度非常快，很清晰，颜色绚丽，收到拆开箱子就非常喜欢，看着就高大尚，键盘手感也很棒，非常顺畅。', '专业电竞R9000P', '2022-10-18 22:20:03', 5);
INSERT INTO `data` VALUES (10043, '小***c', 5, '包装保护：京东物流没的说，下单的第二天就送到了。包装很严实，好评！\n外形外观：R9000P的外观最经典，A面的Y形灯点亮非常好看且有质感。\n运行速度：运行速度真的是杠杠的，锐龙7系处理器真的很强！搭配RTX显卡一起，网游和大型3A单机游戏运行起来也是毫无压力！\n画面品质：2.5k分辨率的屏幕无需多言，冲就完事了！', '专业电竞R9000P', '2023-02-02 18:51:54', 4);
INSERT INTO `data` VALUES (10044, 'j***W', 5, '性能满足要求，时隔多年之后重回A卡阵营，双A平台功耗低，待机时间长，R9000X是一台日常办公和游戏都能兼顾的笔电，轻度游戏还是很不错的，重量控制的很好。配合固态的移动硬盘512G的存储也没什么问题。', '轻薄电竞R9000X', '2023-03-02 08:36:41', 5);
INSERT INTO `data` VALUES (10045, 'S***8', 5, '媳妇平时做点小设计，剪辑下视频，做做平面图之类的，没想买游戏本，出于有点私信，左挑右选，选择了联想拯救者R9000，各项配置完全够用，游戏很流畅，开启野兽那是杠杠的！外观大气，大Y标超级显眼，R7-6800H/RTX3060运行流畅，画质完美，游戏效果棒！京东物流依旧给力，外包装无破损，机器完美！', '【销量先锋】专业电竞R9000P', '2023-03-17 16:24:35', 3);
INSERT INTO `data` VALUES (10046, 'M***e', 5, '第一次买笔记本电脑 去年就一直关注R9000P了 我这边三月三加清明节放三天假 索性就就入手了 4月2日购买到4月3日到货 京东yyds 到货马上验机 生产日期3月21日的 屏幕无坏点完美屏 三星内存 海力士固态 验完机立马自己加装1T固态 用了3天没什么问题\n包装保护：无破损完美\n外形外观：精致 简洁大方 手感好\n画面品质：2.5K屏看起来很舒服很细腻\n跑分评测：没跑分 就是Win11用不是很习惯 慢慢摸索吧\n运行速度：很快 秒开\n游戏效果：我很少玩3A游戏 2.5K 165hz高刷完美适配各种网游', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-04-05 10:49:56', 8);
INSERT INTO `data` VALUES (10047, 'c***p', 5, '外形外观：非常好看，颜值高，小巧，便于携带\n屏幕音效：细腻美观，大小合适\n拍照效果：非常不错，比我的k30u好很多\n运行速度：12g非常快，很满意\n待机时间：还没用，试过后来评价\n其他特色：非常美观的直屏小手机，手感好，外观美', '黑色', '2022-12-17 20:46:57', 9);
INSERT INTO `data` VALUES (10048, 'u***a', 5, '外形外观：非常好看，质感很好\n屏幕音效：屏幕亮度好，显示细腻\n拍照效果：莱卡双摄，拍照清晰\n运行速度：非常流畅，****，省心省力\n待机时间：一天半左右，67w快充，不算太快，够用了', '黑色', '2023-01-20 09:52:13', 4);
INSERT INTO `data` VALUES (10049, 'j***d', 5, '不愧是是史上口碑最好的小米旗舰！用过索尼、三星、苹果、华为，综合感受最好的还是小米，对比iPhone14Pro也不遑多让！\n核心配置上，小米13采用6.36英寸四窄边直屏，搭载高通第二代骁龙8，后置5000万徕卡主摄、徕卡75mm长焦和徕卡超广角，电池为4500mAh，支持67W有线、50W无线闪充。\n我选择的是旷旷野绿外表，温和淡雅很喜欢！\n下单后显示排单到1月5号，结果12月27就送到了，比预定早了一个周！好评！', '旷野绿', '2023-01-05 19:03:03', 6);
INSERT INTO `data` VALUES (10050, '小***咪', 5, '外形外观：非常好看，摸起来非常舒服，还是不带壳舒服\n屏幕音效：很不错哦，加上环绕立体声感觉更棒，很赞\n拍照效果：很好，很喜欢，不过我自己用的不多\n运行速度：很快，非常喜欢\n待机时间：刚用，具体还不太知道，不过用了一两个小时，没掉多少电\n其他特色：用起来真的很舒服', '黑色', '2023-01-12 19:33:52', 4);
INSERT INTO `data` VALUES (10051, 'f***锋', 5, '外形外观：漂亮，手感极好\n屏幕音效：极好，护眼\n拍照效果：极好，焦距充足\n运行速度：极快\n待机时间：可以\n其他特色：轻便，屏幕漂亮\n京东速度，当天达，2023开年礼物，极好的小米手机\n小米换苹果多年，现在换回来。\n体验做技术，总在进步的小米手机，永远在路上', '远山蓝', '2023-01-02 08:28:44', 9);
INSERT INTO `data` VALUES (10052, 'C***7', 5, '外形外观：直边框太爽了，6.36尺寸握感很好，小尺寸真香\n屏幕音效：屏幕是1080p，但是不妨碍看4k?，双扬声器马马虎虎吧\n拍照效果：有莱卡的加持拍照真的上了还几个档次，很好看\n运行速度：我的是12+512，运行速度很快\n待机时间：本来很好的，不小心更新14.0.11版本结果耗电有点快，98的电看个短视频10分钟就掉1%电，双十一买的k50u更新14.0.10都没有掉这么快\n其他特色：莱卡拍照很好', '远山蓝', '2023-01-10 18:46:36', 8);
INSERT INTO `data` VALUES (10053, 'j***p', 3, '正在使用，但随机软件太多', '旷野绿', '2023-03-08 14:42:00', 2);
INSERT INTO `data` VALUES (10054, '是***胖', 5, '从米2一直用到了13运行速度: 畅快 拍照效果: 清晰 续航能力: 很好 小米13是我最满意的一块手机，特别这个尺寸手感特别好，单手操作很舒服，外观颜色炫酷，直角边框，是我最喜欢的！运行流畅，像素清晰，电池很给力，小米13集优点于一身，真的给我惊喜，物有所值，喜欢的不要犹豫了！', '旷野绿', '2023-01-17 23:19:31', 5);
INSERT INTO `data` VALUES (10055, '全***5', 5, '从小米8一直到如今的13，始终没有让我失望过。蜜柚14改进不少，运行速度有了大幅度的提升。电池的续航能力非常棒，用了一天还有50%的电量。拍照效果也是较之前的旗舰机有了大幅度的提升。推荐购买12GB的运行内存，性价比颇高。', '远山蓝', '2023-02-11 00:52:38', 6);
INSERT INTO `data` VALUES (10056, 'f***s', 4, '外形外观：13真香，比苹果14手感好很多，淡淡绿色很好看\n屏幕音效：屏幕看着很舒服，双扬声器声音大很动听\n拍照效果：徕卡镜头拍照很有效果，但是长焦和微距像素有点差\n运行速度：12+256加上MIUI14的系统非常流畅\n待机时间：大电池就是爽，67W充电快快快', '旷野绿', '2023-01-11 23:55:19', 5);
INSERT INTO `data` VALUES (10057, '阿***y', 5, '外形外观：美，窄边美\n屏幕音效：很棒\n拍照效果：夜景也不错，很大提升\n运行速度：很快\n待机时间：还正常', '远山蓝', '2023-02-11 11:19:59', 8);
INSERT INTO `data` VALUES (10058, '蓝***7', 5, '小米13这次真的很惊艳，顶级的性能，还有符合我审美的远山蓝外观，加上直屏和直边框，拿在手里手感真的是绝了，还有纳米皮，摸起来是真舒服啊，用惯了玻璃后盖再用这种纳米皮，舒服。另外徕卡相机拍照效果也很棒，收到手机第一时间拍开箱照，加个水印防盗图。\n最后，满分好评！', '远山蓝', '2022-12-22 16:29:08', 9);
INSERT INTO `data` VALUES (10059, '楼***意', 5, '小米13这款手机质量非常好，又是直屏的非常喜欢，我特别喜欢直屏的手机。最讨厌曲面屏的手机，等了好几代刚好小米13出了一个直屏，真的太喜欢了，无论是手机外观，还是手机性能，拍照功能都完全符合卖方的描述。我真的很喜欢。这完全超出了预期。交货速度非常快。包装非常仔细和紧密。物流公司有良好的服务态度，交货速度非常快。令人满意的购物质量非常好。我希望更多的朋友能信任它。京东的态度很好，以获得赞扬。交货很快，态度很好，我很满意！好，好！网上购物是如此快。我没想到京东的服务这么好，商品质量好，价格低，而且卖家非常热情。下次我会有机会再找你购物。找到你心中的宝贝是一件非常开心的事。', '白色', '2023-03-03 13:52:46', 7);
INSERT INTO `data` VALUES (10060, 's***d', 4, '很早以前曾经是小米CC9用户，家里也是全套小米智能设备&hellip;&hellip;这次突然看到小米13，突然有一种&ldquo;惊为天人&rdquo;感觉，手感更加一流，于是毫不犹豫马上买了。这个边框+屏幕的感觉，简直绝绝子。必须好评！\n\n虽然没有送无线充，但兼容50W小米无线充，正好有一个，完美适配。\n\n最意外的惊喜是徕卡，非常浓郁，很喜欢，跟之前的华为徕卡差不多，无缝连接了。\n\n总体是惊喜，价格能接受。\n\n吐槽也是有的，官方清水壳无法保护镜头盖，担心耐久性。', '远山蓝', '2023-01-07 15:26:15', 9);
INSERT INTO `data` VALUES (10061, '莫***剑', 5, '这次的小米13外形真的好，尺寸把握，手感，配置及拍照等方面可以媲美某果。该有的配置都有，CPU内存配置顶级，玩游戏毫无压力，拍照速度秒拍，徕卡成像也满足需求，可玩性高。搭配miui14操作流畅，特别是电池省电，不管玩游戏还是看视频，手机发热也低，小米13稳了。用个3年应该可以吧。', '黑色', '2023-03-16 10:58:56', 8);
INSERT INTO `data` VALUES (10062, '我***坏', 5, '外形外观：外观真的超级好看，直屏手机爱好者的最爱，棱角分明，后背是陶瓷的，很是舒服\n屏幕音效：屏幕120赫兹高刷，很舒服\n拍照效果：莱卡镜头，真的很值\n运行速度：骁龙888第二代处理器，加上米柚系统14很流畅\n待机时间：待机几小时还是100%\n其他特色：整体来说很满意，感觉是下一批钉子户', '白色', '2023-02-05 16:59:37', 8);
INSERT INTO `data` VALUES (10063, 'H***儿', 5, '来了来了，米13不错 黑色大气低调！ 今天的旷野绿也到手了，真的好看。还在犹豫的小伙伴直接上图给大家看效果！暗光下有点水泥灰的意思，强光也微绿的好看！ 很不错的一款手机，质感很好，配置够用！ 老伙计可以下岗了！哈哈', '旷野绿', '2023-01-23 22:42:05', 9);
INSERT INTO `data` VALUES (10064, '颜***丶', 5, '外形外观：手感极佳，外观非常好看漂亮，棱角分明，是我钟意的直屏款！\n屏幕音效：屏幕真是没话说，分辨率高，非常高清，给人一种非常舒适的观感！\n拍照效果：不愧是搭配徕卡的相机，像素非常棒，拍照流畅！\n运行速度：运行速度是我最看中的东西了，第二代骁龙8+处理器不是吹出来的，流畅度，反应速度简直神了！\n待机时间：充满电不管怎么玩都能用一天，不玩游戏日常使用时间更长，最起码能用12小时以上！\n其他特色：各方面都满足我对小米13的幻想，值了！', '黑色', '2023-01-05 16:42:07', 8);
INSERT INTO `data` VALUES (10065, '思***儿', 5, '外形外观：小巧机身配合圆润直边铝合金边框显得是那么和谐，后壳玻璃材质，温润有质感，散热好\n屏幕音效：全景杜比音效，双扬声器震撼场面音随心动\n拍照效果：莱卡镜头完美呈现，长焦镜头 高像素等\n运行速度：第二代骁龙处理器完美赶超水果机\n待机时间：能抗住深度使用七八个小时没问题，正常用，充满一天没问题 心动的小伙伴买它吧！', '旷野绿', '2023-02-11 01:32:28', 9);
INSERT INTO `data` VALUES (10066, '_***鑫', 5, '外形外观：外观好看，难得的直屏机\n屏幕音效：音响够用\n拍照效果：拍照好看，徕卡加成的镜头确实好看\n运行速度：推荐购买12G版本，12G的用起来很爽\n待机时间：待机时间早上出门充满电，晚上下班回家还能有一点电，很强', '白色', '2023-01-16 18:46:59', 7);
INSERT INTO `data` VALUES (10067, '龙***5', 5, '东东收到了，京东自营的商品，发货速度一向都是很快滴，快递小哥更是相当的给力。商品包装严密无破损，实物与店家所提供的图片信息一般无二。大年三十儿，晚上下单的，正月初一下午我就收到了货。商品不错，新机运行的速度挺快滴。新旧机置换方便、快捷，总体满意。', '黑色', '2023-01-22 21:29:02', 8);
INSERT INTO `data` VALUES (10068, 'j***q', 5, '外形外观：大小合适，白色的很漂亮，手感很好\n屏幕音效：显示清晰，边框很漂亮，音效逼真\n拍照效果：比小米11清晰很多，莱卡就是给力，拍的照片很真实\n运行速度：运行速度流畅，游戏无卡顿，长时间运行也不怎么热\n其他特色：白色的真的很漂亮，手感超级好，颜值很高', '白色', '2023-02-16 23:16:46', 3);
INSERT INTO `data` VALUES (10069, '摇***喵', 5, '手感非常的好，小巧也不是很重，总体非常好\n外形外观：漂亮。很喜欢，，手感真的很好，自带贴膜。哦哦哦\n屏幕音效：很好\n拍照效果：非常好，很喜欢。拍的美美的\n运行速度：棒，没有卡顿刚刚。顺滑\n物流也快。一直在京东购买', '白色', '2022-12-15 20:14:18', 3);
INSERT INTO `data` VALUES (10070, '杰***麦', 5, '昨天去店里体验了一下手感，然后昨晚直播间下单的，24期免息，送保温杯，小音箱，小台灯。\n买来做备用手机，平时自用水果11PM。之前的备用机是华为nova，2017年买的。\n不得不说小米13的手感很好，直框直屏，黑色和白色都非常好看，因为工作环境，只能选耐脏的黑色了。个人喜欢裸奔，所以原机的贴膜也撕了，套也不带了。\n到手就更新系统，删一些不要的应用，关闭扩展内存，关闭广告，开高刷，目前还没怎么使用，过段时间追平再说说续航、丝滑程度等等的感觉&hellip;&hellip;\n目前发现的就是用外放听歌的话，音质实在是邋遢极了&hellip;&hellip;', '黑色', '2023-02-02 22:08:53', 8);
INSERT INTO `data` VALUES (10071, 'x***8', 5, '使用后非常好，尤其是屏幕，感觉上了一个档次，非常清晰，质感也很好，用着非常顺手，颜色也很漂亮，买给老公的，大小也很合适。全家都是小米手机，忠实粉丝。', '旷野绿', '2022-12-26 20:55:34', 9);
INSERT INTO `data` VALUES (10072, '上***使', 5, '一直想换手机，但是比较纠结选择哪一款。\n原来手机是因为内存不够用，经常卡顿，这次换手机的目的很明确，大内存512。\n换新手机颜值也很重要，不光好用。\n原来远去锁定在小米身上，符合颜值加内存两方面的需求。\n颜色是儿子帮忙选的，相信年轻人的眼光，选的蓝色。\n到手后确实经验到我了，外观漂亮。\n系统丝滑，好用。拍照效果特棒。\n在官方直播间买的，还送了三件套礼物，不错。\n值得推荐', '远山蓝', '2023-02-05 21:15:42', 9);
INSERT INTO `data` VALUES (10073, 'g***9', 5, '外形外观：说实话，这次的外观彻底&plusmn;我了\n屏幕音效：杜比全景声身临其境太爽了\n拍照效果：相比于苹果小米13杠杠的，我手里的苹果13 pro Max都想扔了\n运行速度：运行速度快，完全不卡\n待机时间：待机时间长一天一充', '黑色', '2023-02-01 21:18:19', 3);
INSERT INTO `data` VALUES (10074, 'M***泷', 3, '好家伙 第二天就遇到问题，开免提对面听不到声音', '宝石蓝', '2023-03-10 16:26:23', 3);
INSERT INTO `data` VALUES (10075, 'S***r', 4, '1外观很精致，很漂亮。系统运行流畅快。不玩游戏，所以游戏性能就不评价。\n2/拍照效果非常好，对焦很快，比我的三星s10效果要好。\n3/外放声音不错，比我三年前的三星s10好多了。\n4/大小，看网上评测都把他称为小屏手机。但跟我的6.1寸的三星s10比起来明显更大/更厚/更沉。仅从外观精致/小巧这方面来看三星s10甩小米几条街。\n5/屏幕很好，买之前还在担心1080p的分辨率太低，8bit的色深是否影响显示效果，用了好几天感觉完全不影响，显示效果不比三星s10的2k屏差。', '旷野绿', '2023-02-09 16:42:22', 3);
INSERT INTO `data` VALUES (10076, '田***猫', 5, '外形外观：大方帅气\n屏幕音效：屏幕大小合适，音效很不错\n拍照效果：拍照效果绝了，清晰度高\n运行速度：顺滑\n待机时间：待机时间很久，平时一天玩手机，一天充一次电', '黑色', '2023-01-07 22:06:33', 3);
INSERT INTO `data` VALUES (10077, '西***哒', 5, '手感太棒了，等了好多年，终于出了，这一刻泪流满面，玻璃的手感久违了，用了好几年素皮快崩溃了，miui14非常流畅，也不热，打游戏稳稳的！', '旷野绿', '2022-12-30 15:41:50', 5);
INSERT INTO `data` VALUES (10078, '花***r', 5, '外形外观：非常漂亮，绝对是直屏第一\n屏幕音效：屏幕也很出色，没有发黄\n拍照效果：拍照算是不错的，虽然和12s ultra有距离\n运行速度：高通的大龙2，终于不是火龙了', '白色', '2022-12-17 13:46:23', 4);
INSERT INTO `data` VALUES (10079, '你***春', 5, '小巧的外形，玻璃的背板，我很喜欢。买的是256的内存，都说13是新的钉子户，我来试试水。虽然没有了哈曼卡顿，但是音质还是不错的，音量也很足，拍照方面简单的试了下，并没有感觉很大的变化，徕卡加持的感觉不是很明显，放大到最高倍数画面很是模糊，不经常拍照也不太懂这些东西，游戏方面的话就不给予评价了，因为玩游戏用的平板，毕竟mini6才是玩游戏首选，充电速度很快，67W的快充，我从百分之％20 到百分之％80用了大约15分钟左右，这个速度我很满意，待机方面的话还没有做测试，但是网上有评测视频，大家可以看一下。人脸识别速度很快，刷一下就开了。重点说一下这个震动反馈，手感很好，和苹果有的一拼！', '黑色', '2023-01-06 19:34:08', 3);
INSERT INTO `data` VALUES (10080, '6***4', 5, '觉得有用运行速度：畅快\n拍照效果：清晰\n续航能力：很好\n超窄边框直屏确实很惊艳，屏占比与颜值均有上佳表现；小尺寸机身＋两侧边缘弧形过渡，不仅单手操作颇为方便，手感也很舒适；骁龙8Gen2处理器搭配全新的MIUI14系统，性能与流畅度均为行业顶级水平，用户体验较为优秀；徕卡相机组合不容小觑，拍照实力在线。', '黑色', '2023-01-18 13:00:12', 3);
INSERT INTO `data` VALUES (10081, 'j***4', 5, '米6用到现在，看到米13的大小非常不错，大小在现在的手机里是一股清流，配置也很完美，加上8g2解决了功耗问题，成功让我有了换机冲动，上手后手感还是比原来的米6厚重不少，还需要适应一下，速度没得说顶级配置很丝滑，续航也很不错，电池比较耐用，充电速度满意，希望也能用5年', '黑色', '2023-01-05 09:09:50', 4);
INSERT INTO `data` VALUES (10082, 'j***z', 5, '小米13，12+256，真香，白色手机颜值很高，边框极窄，MIUI14系统丝滑，手感很棒，6.36寸的屏幕大小刚刚好，适合单手操控，莱卡认证的相机，拍照也超级棒。已经用了4款小米手机了，做的确实越来越好，小米mix2手感最棒，小米13性能最好，红米k50性价比最高，最开始用的小米note2曲面屏！家人以前也是用的水果手机，现在只用新国货小米手机！加油，希望小米手机越来越好！', '白色', '2023-02-07 10:46:20', 9);
INSERT INTO `data` VALUES (10083, 'j***y', 5, '外形外观：屏幕边框很细，看起来非常舒服，外观方正。\n屏幕音效：显示效果好，虽说是1080P的屏幕，但日常看起来区别不大。不仔细靠近看没区别\n拍照效果：拍照效果喜欢。夜间效果好。招牌字都看的清晰\n运行速度：使用了几天未见有卡顿现象，非常丝滑\n待机时间：日常使用一天没问题。67W快充不到40分钟充满。', '黑色', '2023-02-15 16:48:16', 6);
INSERT INTO `data` VALUES (10084, '林***天', 5, '非常不错的手机，手感好，用着舒服，好久没有用纯平手机了，安卓一股清流！只喜欢！小米确认不错，买就是了！各方面做得挺好的，快递一流！', '白色', '2023-03-08 23:57:30', 9);
INSERT INTO `data` VALUES (10085, '一***钙', 5, '老米粉很满意！小米8可以退休了。米13非常漂亮的手机 超薄 关键反应还挺快 屏幕也很完美 比想象中要好得多 到小米之家试了试  回家看了一下就下单了 第二天送到 值得推荐 这次相比以前型号提升很多 奈斯了啊小米 爱不释手了这次 大小也合适。手感方面不错，不愧是小屏旗舰，外观设计优雅，屏幕显示清晰，屏幕边框完美，音效逼真，还原真实，拍摄清晰，莱卡联名，夜景很好，前置也很棒，运行速度快，游戏毫无压力，待机时间长，很喜欢这款手机，还是挺不错的！', '黑色', '2023-01-05 21:33:17', 6);
INSERT INTO `data` VALUES (10086, 'D***n', 5, '外形外观：直边就很喜欢，金属边框很好看，\n拍照效果：画质清晰，照片还原度很高\n运行速度：很流畅，稳定，小米13yyds\n待机时间：明显提升了很多，一天一充完全没问题', '白色', '2022-12-19 22:55:13', 6);
INSERT INTO `data` VALUES (10087, 'X***_', 5, '连续三年的高端之作，手感真好。屏幕第一眼看上去感觉很棒。边框所有手机里面最窄的。我在手里面的感觉不大不小，刚刚好。单手操作很方便。性能也非常棒，玩起来的感觉散热也很好。', '远山蓝', '2022-12-23 10:42:18', 3);
INSERT INTO `data` VALUES (10088, '克***斯', 5, '外形外观：很好看，我比较喜欢蓝色，科技纳米皮很耐脏\n屏幕音效：屏幕很合适，小屏幕用起来很舒服\n拍照效果：很好，毕竟有莱卡\n运行速度：很快，很丝滑\n待机时间：很久，一天一充', '远山蓝', '2023-01-02 09:02:46', 5);
INSERT INTO `data` VALUES (10089, 'c***o', 5, '第一次用小米手机，买了这款小米13，个人感觉很不错，给我的感觉是用起来很&ldquo;柔软&rdquo;的感觉，很流畅。由于第一次使用小米系列，很多功能还不知道，用了之后再来追评。', '黑色', '2023-02-22 00:10:18', 4);
INSERT INTO `data` VALUES (10090, 'Y***x', 4, '外形外观：真的巨好看！买的时候还在纠结摄像头大小不一样会很丑  目前看来还是我多虑了  手机那一圈金属边看着真的很高级！真的很好看！谁懂啊！\n拍照效果：拍照效果目前还没发现有啥特别之处哈哈哈哈哈哈哈哈   但也还不错\n\n待机时间：待机可以用很久很久！过年在家基本上一整天都是在玩手机的  一天差不多充一次电  充电速度很快  剩余20的电量半个小时就可以充满', '白色', '2023-02-10 17:39:49', 3);
INSERT INTO `data` VALUES (10091, 'M***i', 5, '外形外观：个人感觉外观比宣传图还好看\n屏幕音效：杜比全景音效很棒\n拍照效果：拍照效果非常好\n运行速度：动画很流畅\n待机时间：中规中矩吧\n\n总体的使用感觉还是很好的（第一部小米手机）', '远山蓝', '2022-12-20 20:11:18', 3);
INSERT INTO `data` VALUES (10092, '朱***-', 5, '外形外观：外观很大气，黑色很有质感。\n拍照效果：拍照效果很好，尤其是徕卡拍出来的照片很出片\n运行速度：很好，很流畅，没有卡顿。\n待机时间：待机时间长，一般情况下使用一天一充。', '黑色', '2023-02-05 10:05:51', 2);
INSERT INTO `data` VALUES (10093, '柠***儿', 5, '外形外观：直角边框精致，一体型好，质感好，非常适合女孩子\n屏幕音效：可视角好，如果加上2k屏幕更完美\n拍照效果：徕卡相机照相非常棒，长焦也非常清楚，\n运行速度：速度非常快\n待机时间：待机时间也很长 \n整体来说小米13非常好，手机小巧玲珑，重量也轻，莱卡相机照相也非常完美，特别适合女孩子用', '旷野绿', '2022-12-27 11:17:56', 2);
INSERT INTO `data` VALUES (10094, '牧***z', 5, '使用四五天左右，个人感觉这一代成了，撼动了我这个米6钉子户，一直盼着出个小直屏，这不就来了，因为米6用的太久，这个跨度换过来给我的体验舒适度和新鲜感都比较满，总而言之对这代很满意，希望小米秉承小直屏做下去，我后面接着换。', '白色', '2022-12-29 17:30:21', 8);
INSERT INTO `data` VALUES (10095, '云***儿', 5, '比较轻巧，运行流畅，外形美观，各方面体验都不错，很均衡很满意的一款手机。', '白色', '2023-03-03 21:28:05', 9);
INSERT INTO `data` VALUES (10096, 'R***e', 3, '三星，双扬声器拉胯，', '黑色', '2023-02-01 15:06:52', 9);
INSERT INTO `data` VALUES (10097, 'S***V', 5, '外形外观：握持手感很好，不愧是小屏旗舰，大小刚合适。\n拍照效果：徕卡加持，随手出大片，特别是黑白风格，以及负一屏的快捷键，好用且好看。\n运行速度：高通2代处理器，运行速度流畅', '黑色', '2023-03-06 17:02:41', 6);
INSERT INTO `data` VALUES (10098, '浅***瓜', 5, '外形外观：我买的是蓝色的素皮的，手机确实挺轻，可以长时间握持，从米10换过来的，还是喜欢直角平。\n\n屏幕音效：屏幕很棒，感觉很清晰，很亮，防闪烁直接打开。\n拍照效果：快速，清晰，莱卡还得在摸索摸索摸索看下具体照片效果。\n\n运行速度：机器运行速度，超级流畅。\n待机时间：我觉得待机时间挺长的，耗电控制的很好。\n其他特色：充电速度，我很满意。机器重量也挺惊喜。总之好处＞瑕疵。', '远山蓝', '2023-01-12 16:21:16', 2);
INSERT INTO `data` VALUES (10099, 'j***a', 5, '以旧换新换掉了之前的iPhone12pro。手感很棒、很轻。小米13用的骁龙8gen2处理器，使用起来也非常流畅，不卡顿。充电速度完爆苹果手机，30分钟就能完全充满，待机时间也很长，下班回家还有36左右的电量。拍照的莱卡出片也很棒，景深有层次感，远景也很清晰。音效也不错，看爱奇艺视频。完全满足我对手机的要求。', '远山蓝', '2023-01-05 19:22:22', 3);
INSERT INTO `data` VALUES (10100, '米***-', 5, '小米13直屏屏幕很喜欢，不喜欢曲面屏，手感不错，摄像头好看，拍照也很好，续航不错，充电也快，MIUI系统用着也习惯，骁龙8 Gen2处理器，YYDS，选的是12GB+512GB黑色的，还能24期免息很给力！', '黑色', '2023-01-04 01:08:32', 3);
INSERT INTO `data` VALUES (10101, 'r***9', 5, '外形外观：经典直板，和手上的13pro很像很像&hellip;\n屏幕音效：显示中规中矩\n拍照效果：人像模式很赞\n运行速度：还行吧\n待机时间：不错，充电也快\n其他特色：小屏直板，手感极佳。', '黑色', '2023-03-18 19:44:04', 5);
INSERT INTO `data` VALUES (10102, 'j***e', 5, '外形外观：最喜欢这个，给10分\n\n运行速度：骁龙8gen2很牛的，不会卡顿\n\n拍照效果：莱卡相机很喜欢\n\n别处都有礼品，我买的没有，很难受，找客服没补发', '远山蓝', '2023-03-19 13:54:23', 8);
INSERT INTO `data` VALUES (10103, '泽***宇', 5, '收到了，苹果换回来的，还是选择了小米。手感非常不错，是心目中的小屏旗舰，外观设计中规中矩，屏幕边框很完美，显示清晰，音效逼真，拍摄清晰，莱卡联名，运行速度还不错，玩游戏无压力，待机时间很长。心中完美小屏直屏旗舰机。', '黑色', '2023-01-14 08:14:17', 7);
INSERT INTO `data` VALUES (10104, '小***2', 5, '一直关注小米手机，闺女也很喜欢，拍照效果好，内存大，分辨率也很高，反应快，非常不错，方方正正手感很好，皮质很有质感！', '远山蓝', '2022-12-31 20:37:05', 4);
INSERT INTO `data` VALUES (10105, 'j***8', 5, '外形外观：非常喜欢\n拍照效果：非常可以\n屏幕音效：非常好听\n运行速度：可以，就是连wifi有卡死\n待机时间：待机可以，但是在使用过程中掉电特快???', '远山蓝', '2022-12-20 00:17:10', 7);
INSERT INTO `data` VALUES (10106, 'c***u', 5, '收到了收到了，京东物流杠杠滴！隔天就到了。收货就迫不及待打开了，大小合适，?分量，做工精细手感特别棒。小米真的很给力。直角屏幕和曲面屏做了比较，曲面屏好看，但是手机外壳包不住侧边，?用袋子形状的东西，不然，放包里，很容易被压坏的。', '旷野绿', '2023-03-07 22:56:32', 9);
INSERT INTO `data` VALUES (10107, '幸***手', 5, '小米13，今天收到了，拆机，测试，使用一气呵成。非常满意，流畅、速度快、照片很清晰，值得拥有。使用一段时间再追评。', '黑色', '2022-12-17 19:25:52', 9);
INSERT INTO `data` VALUES (10108, '抱***车', 5, '外形外观：外形很漂亮，上次用小米还是mix2s，感觉这几年进步很大。\n屏幕音效：屏幕显示效果细腻，音效也不错。\n拍照效果：拍照没试，平时也拍的少。\n运行速度：速度很快。\n待机时间：待机有待观察，第一天刚到。用着看，备用机，平时就玩个游戏导个航。\n其他特色：下载了一大堆软件，感觉不热，试玩了一会游戏也不热，裸机握持很光滑，后面玻璃粘指纹，总体使用感觉还不错，其它的用了再追评吧。', '旷野绿', '2023-01-02 22:23:36', 6);
INSERT INTO `data` VALUES (10109, 'w***b', 5, '一直关注着小米13的发布，尤其是标准版是直屏，大爱直屏。虽然推迟了一次，但是发布当天就预约了，今天上午支付尾款，下午就收到了，13标准版，远山蓝12+512，手感非常不错，正在迁移数据，速度也很快，上一部是小米10pro，希望小米越做做好。', '远山蓝', '2022-12-14 17:37:16', 5);
INSERT INTO `data` VALUES (10110, '说***人', 5, '外形外观：样子很好看摸起来很舒服适合裸机但是后面也是指纹收集器屏幕音效：屏幕很清晰和k50至尊比起来颜@彩更胜一筹拍照效果：徕卡加成的情况下相较于k50至尊好很多运行速度：很流畅运行无卡顿用了一天没遇到卡顿的情况待机时间：还没有完整测试过其他特色：13香就完了做为备用机已经是很好的了', '黑色', '2022-12-16 15:29:46', 6);
INSERT INTO `data` VALUES (10111, 'j***6', 5, '外形外观：黑色，好看，颜值高，小巧，便于携带\n屏幕音效：很不错\n拍照效果：比之前的手机更清晰，适合拍照?\n运行速度：128g，非常快，很满意\n待机时间：早上出门100%，下班回家70%，很饱电\n其他特色：充电速度很快，半小时充电60%。我家龚二狗送的，很喜欢这个手机?', '黑色', '2023-01-05 19:35:39', 7);
INSERT INTO `data` VALUES (10112, '明***颢', 5, '外形外观：外观时尚好看，比两边圆弧边框的手感要好。\n屏幕音效：屏幕清晰高刷的，不错。\n拍照效果：男的不讲究摄像头，我老婆用的，她说不错。\n运行速度：非常快，新机也不卡顿。\n待机时间：反正不管啥手机都是一天一充的节奏。\n其他特色：该有的基本上都有了。', '白色', '2023-01-07 14:46:47', 6);
INSERT INTO `data` VALUES (10113, '喜***2', 5, '买的旷野绿，拿到机子倒腾数据，适应新机子界面操作，都很简单，爱不释手，一直想买个小屏手机，又不喜欢水果，一开始挺纠结颜色的，这个绿色是哪种略微发白吧，总之很喜欢吧。至于性能更没的说，拍照效果也不错。整体做工也算严谨，但还有很大提升空间。', '旷野绿', '2023-01-29 15:41:27', 7);
INSERT INTO `data` VALUES (10114, 'S***n', 5, '外形外观：外形外观：、外形很美。运行流畅。电池很耐用，且充电速度极快。拍照效果尤其好出色。软件设计越来越人性化，操作简单化。值得推荐的手机。', '黑色', '2022-12-26 23:39:03', 7);
INSERT INTO `data` VALUES (10115, '潜***3', 5, '用起来非常流畅，跟iOS16没有区别，各个功能小件用着都很舒服。特别这个颜色，看起来很温润，非常有亲和感。', '旷野绿', '2022-12-17 08:14:02', 8);
INSERT INTO `data` VALUES (10116, 'l***8', 5, '性价比：性价比还好，运行速度：快，非常快，很喜欢 拍照效果：很好，对比我用的小米10s拍照提升很高很喜欢。 电池续航：稳定，不掉电啊，小米优化厉害啊。 外观设计：感觉9分，挺好看，但不是特别经验 MIUI系统：对比原来还是提升明显快。', '黑色', '2023-01-03 19:40:18', 2);
INSERT INTO `data` VALUES (10117, 'H***k', 5, '外形外观：直板，手感好\n运行速度：运行流畅，miui14很好\n买过很多小米手机了，这部手机最满意！', '远山蓝', '2023-02-03 17:03:16', 4);
INSERT INTO `data` VALUES (10118, 'f***b', 5, '外形外观：很棒，再也不用那难用烂大街的曲面屏了\n屏幕音效：显示效果好，声音好听\n拍照效果：已经是非常棒了\n运行速度：运行速度快，丝滑\n待机时间：本人偶尔玩游戏，使用一天一充足够\n其他特色：红外真的很棒', '黑色', '2023-02-27 14:56:11', 2);
INSERT INTO `data` VALUES (10119, '安***分', 5, '从曲面屏又用回了直屏。边框方方正正，手感一级棒。也没有什么发热的感觉。续航一天妥妥没问题。大小适中，颜值，爱了，爱了。', '黑色', '2023-01-05 20:48:58', 7);
INSERT INTO `data` VALUES (10120, 'Z***2', 5, '外形外观：最强安卓小屏旗舰！高亮边框配合四窄边框屏幕，直男最爱！不接受反驳\n屏幕音效：三星顶级E6材质屏幕，更亮更省电！120Hz很丝滑，色彩与iPhone12有的一拼\n拍照效果：体验过就知道，拍照非常快！所见即所得，比iPhone拍完之后还要转几圈的速度快多了，徕卡画质甩iPhone12十几条街！广角、超广角、长焦都配齐了，拍照真的很棒\n运行速度：最新8Gne2处理器，配合12G内存，丝般顺滑\n待机时间：这次miui14处理器调度调得比较好，即使4500毫安电池也能用一天', '旷野绿', '2023-01-02 19:36:47', 8);
INSERT INTO `data` VALUES (10121, 's***9', 5, '新一代的小米真的非常不错，手感和小米六那一代非常的相似，然后，14代的系统也非常的出众，而且这一代的硬件配置经过了一大大的升级，无论是内存还是储存空间，都是一大跃进，我觉得这一代带给我们的惊喜会非常的大，希望大家也会很喜欢新一代的小米13', '远山蓝', '2022-12-15 20:09:01', 4);
INSERT INTO `data` VALUES (10122, 'h***3', 4, '外形外观：有质感，直屏我喜欢。\n屏幕音效：不错，没有特别在意。\n拍照效果：小屏幕旗舰里绝对顶，夜景肯定比12su差一点，白天毫无压力。\n运行速度：快速！！！\n待机时间：超级长，毕竟屏幕省电。\n其他特色：直屏，太好了！有点像iphone，但我不喜欢iphone！支持小米。', '远山蓝', '2023-01-10 13:45:09', 6);
INSERT INTO `data` VALUES (10123, '小***r', 5, '外形外观： 小巧玲珑 精致\n屏幕音效：屏幕清晰 音效\n拍照效果：莱卡镜头很可以\n运行速度：8gen2 超快\n待机时间：中度使用一天\n其他特色：尺寸把控很到位', '远山蓝', '2022-12-25 13:03:18', 5);
INSERT INTO `data` VALUES (10124, '明***居', 5, '外形外观：远山蓝，手感超好，尺寸大小合适。\n屏幕音效：双扬声器真的很震撼。\n拍照效果：徕卡加持，效果好\n运行速度：骁龙8gen2使用起来非常流畅。\n\n京东购物  ：依然是一如既往的快，让人放心。点赞\n快递员      ：服务热情，送货上门，\n京东自营购物给力！\n待机时间：大容量电池，正常工作，一天够用点赞', '远山蓝', '2023-01-06 01:15:51', 6);
INSERT INTO `data` VALUES (10125, 'j***9', 5, '外形外观：外观漂亮，手感好！\n屏幕音效：屏幕太清晰了，跟2k屏的手机比较一了一下，肉眼看不出区别。\n拍照效果：拍照足够用，除非你是摄影专业人士\n运行速度：应用秒开，反应特别快。\n下单之前，看了好多评价，有正面的也有反面的，当拿到手后，体会到这款手机的做工扎实，手感真好，显示细腻，拍照清晰，续航能力强到手后没充电，52的电（换机用了三个小时）才掉了10个电！小米这次成了！', '黑色', '2022-12-25 16:29:32', 7);
INSERT INTO `data` VALUES (10126, '喝***惊', 5, '这次的小米13用起来真的很不错比之前发布的数字旗舰机强太多了个人喜欢曲面屏就买了一部而且尺寸大小刚刚好用起来手感真的很舒服唯一就是电池充电只有67w希望下部旗舰机都能上120希望小米手机越做越好 还有系统广告有点多希望能改一改 直角边框很漂亮握感很舒服不硌手\n外形外观：漂亮直角边框很漂亮', '白色', '2023-02-08 16:06:20', 5);
INSERT INTO `data` VALUES (10127, 'j***x', 5, '外形外观：精致漂亮\n屏幕音效：三星同款\n拍照效果：不输苹果、华为\n运行速度：速度快快快\n待机时间：好\n其他特色：希望小米越来越好越来越精致', '黑色', '2023-03-16 22:10:13', 3);
INSERT INTO `data` VALUES (10128, 'M***a', 5, '外形外观： 外观是喜欢的类型 挺漂亮\n运行速度：12+256 运行速度很快 平时也不玩游戏 感觉买8G运存就够做了\n待机时间：待机感觉不是很友好\n其他特色：握感挺舒服  系统也很好用', '黑色', '2023-02-09 10:27:23', 2);
INSERT INTO `data` VALUES (10129, '是***啊', 4, '外形外观：很好看，很轻很薄\n屏幕音效：看着很爽，不愧是e6的屏幕，而且还有类dc调光\n待机时间：续航有一点点的差\n拍照效果：很爽，有莱卡的加持，确实不错\n运行速度：很快很快很快，miui14很舒服', '白色', '2022-12-21 11:22:33', 5);
INSERT INTO `data` VALUES (10130, '苏***1', 5, '外形外观：颜值很高\n\n屏幕音效：杜比全景音效，看视频很有感觉\n\n\n拍照效果：可以，本身对拍照要求不高\n\n运行速度：非常OK', '旷野绿', '2023-03-08 11:46:50', 3);
INSERT INTO `data` VALUES (10131, '小***1', 5, '手机做工确实不错，质感很好，试玩了下，反应很快，很流畅，小米换机很好用，一次性就将所有资料全部转移过来了，很方便，拍照也很好', '白色', '2022-12-15 13:34:31', 5);
INSERT INTO `data` VALUES (10132, 'h***张', 5, '小米手机一如既往的好用，用了多年的曲屏，感觉回归直屏的亲切感满满，这外观yyds，白色更好，温稳如玉。相机真徕卡，120hz真丝滑，尺寸刚刚好，重量轻盈，简直爱不释手，相对iphone而言各有所长，价格这块是真厚道！13真的很香！', '白色', '2023-01-04 08:29:44', 6);
INSERT INTO `data` VALUES (10133, 'G***g', 5, '1.外形外观：非常好看，颜值高，小巧，便于携带 有种iPhone13的感觉\n2.屏幕音效：细腻美观，大小合适握起来很舒服\n3.拍照效果：非常不错，比我的10u好很多\n4.运行速度：8g非常快，很满意.看来8gen2诚不欺我\n5.待机时间：还没用完， 期待久一点。\n其他特色：非常美观的直屏小手机，手感好，外观美总体来说，确实很不错，客服的服务态度也很棒，说话几乎马上就会回消息，物超所值，真心推荐不太爱评价，但这个是真的棒！质量很好，做工细致，包裹很严实，快递服务态度好，绝对好评！', '黑色', '2022-12-19 10:44:33', 3);
INSERT INTO `data` VALUES (10134, '佛***笑', 5, '小米13这款手机今天到手使用了半天多的时间。整体给我的感觉实话实说。外观非常好看。我握持非常舒服。系统还流畅，运行速度也很快。这个电池充电速度很快，然后耗电也相对来说比较慢。屏幕的色彩饱和度也挺好的。尤其是打开那个防屏闪功能，整个机子使用下来眼睛一点儿都不累。真心希望你拥有一部小米13。你会很开心。', '黑色', '2023-02-05 21:50:10', 3);
INSERT INTO `data` VALUES (10135, 'j***N', 5, '外形外观：外观很好看，握持手感很不错\n屏幕音效：三星的屏幕很不错，屏幕素质很好\n拍照效果：莱卡影像加持很不错\n运行速度：骁龙8gen2处理器速度很快\n待机时间：手机刚刚到，过几天再追评', '黑色', '2022-12-31 15:31:43', 3);
INSERT INTO `data` VALUES (10136, '旭***_', 5, '新手机，续航很好，釉白色很有质感，是我喜欢的样子～\n运行流畅，触控丝滑，IP68防尘抗水，手机泡水也不怕\n京东快递，速度没的说，嘎嘎高效\n用了几天了，总体使用体验很棒！', '白色', '2023-01-17 20:15:02', 6);
INSERT INTO `data` VALUES (10137, '汤***2', 5, '下单隔日到，京东快递666。\n对比了几款手机后才决定下单小米13，莱卡相机果然名不虚传，拍照很好看！\n手机颜值没得说，握感也很好。\n运行速度：运行速度超级快。\n外形外观：喜欢的就是最好的！\n待机时间：待机一天完全没问题，而且充电速度很快！', '黑色', '2022-12-31 10:33:24', 8);
INSERT INTO `data` VALUES (10138, '风***妍', 5, '外形外观：最爱的直边小屏，颜值高\n屏幕音效：屏幕显示清晰效果极佳，音效也不错\n拍照效果：徕卡加持，没有凑数镜头\n\n运行速度：最新骁龙8+的处理器，运行不会慢\n待机时间：试用期正常待机，充电快\n其他特色：小米13满足我的所有需求：小屏，直屏，旗舰，拍照，充电，续航，系统???', '远山蓝', '2023-02-13 17:31:47', 5);
INSERT INTO `data` VALUES (10139, '想***丶', 5, '外形外观：立体感非常强，手感非常强\n屏幕音效：声音相对我直接使用的小米10u要好\n运行速度：非常快，不卡顿，不掉帧\n待机时间：续航是我最满意的，待机真的强\n其他特色：金属边框真的可以', '白色', '2022-12-20 18:51:27', 5);
INSERT INTO `data` VALUES (10140, '释***然', 5, '小巧的直屏手机，非常的好用。轻巧 贴钢化膜也是完美贴合。米粉多次回购了。非常不错。满意?', '远山蓝', '2023-01-16 11:18:22', 4);
INSERT INTO `data` VALUES (10141, '蒲***蒲', 5, '外形外观：外观大小适合，手感无敌。我选的是素皮版，手感超好。\n屏幕音效：2k屏幕，音效无敌，杜比特音效。\n拍照效果：拍照无敌。莱卡加持，\n运行速度：8根2，无敌，游戏轻松拿下\n待机时间：一天左右，重度使用大半天\n其他特色：无敌。', '远山蓝', '2023-03-17 14:17:58', 5);
INSERT INTO `data` VALUES (10142, 'j***6', 5, '外形外观：金属边框很漂亮，太阳底下反光那种。\n屏幕音效：显示效果很赞，仿纸纹理看着很舒服。\n拍照效果：日常生活足够，我很少用手机拍照，相机就是当备忘录用。\n运行速度：安卓阵营目前最好的处理器，允许流畅度还是有保障的。\n待机时间：不玩游戏 但也是重度使用,一早上视频会议，外加各种接打电话，下班还用74的电。\n其他特色：广告相比之前的手机确实多了点，不知道现在的安卓机是不是都这样，但是可以一键关闭 还是很方便。', '白色', '2023-01-18 12:21:23', 5);
INSERT INTO `data` VALUES (10143, 'w***9', 5, '从iPhone换小米的，因为之前的iPhone屏幕是低调光，看一会辣眼睛，正好看到小米广告是dc调光的，6.3的屏幕手感很好，所以果断换成了小米13，事实证明确实对眼睛非常友好，希望所有的厂家本着对消费者负责的心态提供dc调光。同时希望小米加油早日把相机成像效果调教的更好，出厂的品控更好点。', '黑色', '2023-01-08 09:50:09', 8);
INSERT INTO `data` VALUES (10144, 'j***y', 5, '货到了，机子外观很好看，拿在手里很舒服手感很好，看着做工很精细，还没用呢，用用在说，想信京东，应该没问题，快递小哥太给力了，昨天下的单，今天就到了。', '黑色', '2022-12-31 16:26:22', 4);
INSERT INTO `data` VALUES (10145, '这***见', 5, '外形外观：设计很到位，虽然按照果子来的，但还是给人一种眼前一亮的感觉，就是要打破传统思维，挑战新设计新样式。新一代钉子户机子。\n屏幕音效：很不错哦，感觉很棒\n拍照效果：莱卡效果毋庸赘述，日常使用简直够用\n运行速度：最新骁龙处理器无敌。使用流畅性很好，一点不卡顿。\n待机时间：小屏旗舰4500电池也很不错了，不重度使用一天一冲完全没有问题\n其他特色：miui14很良心，自带的95％软件可以卸载，流畅度很好，bug还未发现。希望继续优化继续发扬', '白色', '2023-01-09 15:09:47', 5);
INSERT INTO `data` VALUES (10146, 'j***f', 5, '外形外观：外观非常好看，金属边框真的喜欢\n屏幕音效：屏幕非常清楚，音效全是杜比音效，非常完美\n拍照效果：用了徕卡真的无敌了，非常清楚，无论白天还是夜景\n运行速度：用上了全新骁龙，打游戏非常流畅，开最高画质都可以流畅运行', '旷野绿', '2022-12-20 14:44:06', 2);
INSERT INTO `data` VALUES (10147, 'x***i', 5, '包装完好，送货速度很快，必须给京东快递小哥点赞，当日送达，不耽误使用，京东值得信赖，一如既信赖。小米13手机运行流畅，速度很赞，刷新了对小米的印象，音效，屏幕，拍照都很香，力荐。远山蓝更是颜值高，长在了我的审美上，可以冲啊，兄弟们', '远山蓝', '2023-03-14 05:22:34', 4);
INSERT INTO `data` VALUES (10148, 'h***g', 2, '操作流程，反应速度快，nfc能复制加密卡很不错。屏幕显示清晰，比红米好很多。待机时间长，充电也快，反正不后悔，比苹果强。', '白色', '2023-01-06 22:40:17', 2);
INSERT INTO `data` VALUES (10149, 'D***n', 5, '外形外观：手机太漂亮，现在小米的做工越来越好了，握持手感很舒服\n屏幕音效：屏幕显示效果惊艳，显示细腻，音效很好\n拍照效果：本身我对拍照没有特殊要求，这个配置已经超出我的预期了\n运行速度：运行速度没得说，枭龙二代处理器名不虚传\n待机时间：常规使用一天多一充没问题', '黑色', '2023-02-25 09:35:41', 1);
INSERT INTO `data` VALUES (10150, '-***闷', 5, '外形外观：外观是我钟爱的，非常满意\n屏幕音效：音质不错，效果杠杠的\n拍照效果：这就不用我多说了，拍照就是一大卖点\n运行速度：最新的处理器，最流畅的芯片\n待机时间：4500毫安的电量，67w快充\n其他特色：小屏旗舰，2023非常受欢迎的一款旗舰产品', '远山蓝', '2023-02-28 21:43:10', 1);
INSERT INTO `data` VALUES (10151, '卓***A', 5, '外形外观：外形真是没得说，终于开始直面屏了，很喜欢\n屏幕音效：非常的好\n拍照效果：很强，可以的\n运行速度：非常流畅，可以的可以的，颜值很在线，非常喜欢?&hellip;&hellip;', '远山蓝', '2023-02-03 22:38:49', 1);
INSERT INTO `data` VALUES (10152, '7***m', 5, '外形外观：绿色很耐看，并不张扬，有点水泥灰的感觉，并且粘了指纹也不是很明显。正面边框挺窄，观感也不错。\n屏幕音效：屏幕显示效果不错，虽然是1080p的分辨率，但是6.38英寸的屏幕上显示很细腻，色彩很饱满。上下双扬声器很立体。\n拍照效果：超广角主摄长焦，一应俱全，徕卡加持，出品挺好的，色彩调的不错，很有味道。\n运行速度：第2代高通8处理器，12+256的存储组合运行速度非常快，嗖嗖的，很水桶的机器，绝对的另一个钉子户\n待机时间：4500毫安的电池中度使用一天没有问题，67瓦的充电对我来说也足够了，很快就能充满\n其他特色：综合实力很强的一部小米数字旗舰，手感很好，性能很强，做工不错。', '旷野绿', '2023-02-01 18:44:06', 4);
INSERT INTO `data` VALUES (10153, '花***_', 5, '心心念念的小13终于到啦，颜值直接爆表！终于有合适的小屏旗舰手机啦。各方面体验都很满意，徕卡镜头出片也很棒，年轻人的第一台徕卡（不是）！8+2打王者简直不要太轻松\n运行速度：12+256很流畅\n拍照效果：徕卡超级棒\n屏幕音效：直屏超窄边框\n外形外观：狂野绿好喜欢', '旷野绿', '2023-03-10 13:08:25', 5);
INSERT INTO `data` VALUES (10154, '巴***靠', 5, '这个手机超出了我的逾期本来想想着做备用机，没想到这手感超越水果\n外形外观：大小尺寸我的手很合适单手握持\n屏幕音效：这个屏幕也很惊艳肉眼看基本上跟果没区别。\n拍照效果：那效果绝对杠杠的，夜景去拍星空的话也是没问题。\n运行速度：我买的是12+256的。\n待机时间：不打游戏的话 只是上班下班基本两天', '旷野绿', '2023-01-16 18:43:12', 6);
INSERT INTO `data` VALUES (10155, 'X***9', 5, '外形外观：真的很漂亮很喜欢\n屏幕音效：很清晰\n待机时间：手机耗电有点快，我是用k40s换的还不如k40\n运行速度：新手机感觉还可以，用久了不知道', '白色', '2023-01-31 20:59:07', 2);
INSERT INTO `data` VALUES (10156, 'j***W', 1, '该说不说，旗舰就是旗舰，在这个价位已经很好了，电池容量虽然只有4500，但是很耐用\n外形外观：很小巧，握起来就很舒服，金属边框外加素皮，很巴适，尤其是金属边框，真的爱了，之前还担心太小不好用，打游戏打了几把，完全没这个问题。\n屏幕音效：屏幕也很不错\n拍照效果：莱卡就是好用，不会拍照的我，都能拍出比较不错的照片\n运行速度：最新的骁龙芯片，杠杠的，哈哈，以前用的都是中低端的芯片，相互比较一下，旗舰芯片好太多了', '远山蓝', '2023-02-03 20:06:51', 5);
INSERT INTO `data` VALUES (10157, 'K***p', 5, '很满意！\n续航强！\n很流畅！\n第一次遇到续航这么强的安卓手机比了一下，续航和iphone14promax一样，感觉超了一点！\n性能各方面很满意！\n像素也还可以，能正常用生活中！', '远山蓝', '2023-01-17 17:40:20', 2);
INSERT INTO `data` VALUES (10158, '陶***帅', 5, '外形外观：外观我是觉得真的好看，没什么边框了基本上，买给老婆的屏幕大小她很满意\n屏幕音效：三星的e6直屏效果很不错的，而且节约电量，这个手机口碑是真的挺好的，评价都很棒\n拍照效果：目前很不错，莱卡合作还是有提升\n运行速度：都是最强的配置', '白色', '2022-12-31 22:09:09', 5);
INSERT INTO `data` VALUES (10159, '珠***n', 5, '外形外观：窄边的，比以前的黑边小\n\n拍照效果：效果图特别好\n屏幕音效：声音好听\n运行速度：速度快\n待机时间：充电器功率大，特别快\n其他特色：买的经典蓝色，是喜欢的颜色，整体效果好，还能养宠物！', '远山蓝', '2022-12-18 12:15:20', 1);
INSERT INTO `data` VALUES (10160, 'h***o', 5, '设计好看有档次，尺寸大小合适，远山蓝的科技纳米皮手感非常好，屏幕显示细腻，看着很舒服，运行速度很流畅，拍照也很清晰，杜比音效给力，待机时间足够。', '远山蓝', '2023-02-13 15:48:37', 5);
INSERT INTO `data` VALUES (10161, 'j***k', 5, '外形外观：外观很好看\n拍照效果：拍出看起很自然，成像不错\n运行速度：运行速度很快，很流畅，不卡顿\n待机时间：续航时间真的很长，耐用', '白色', '2023-02-11 17:30:36', 5);
INSERT INTO `data` VALUES (10162, 'S***身', 5, '外形外观：完美，\n屏幕音效：可以 符合预期\n拍照效果：大师级别\n运行速度：快，非常快\n待机时间：尚可', '白色', '2022-12-28 12:56:23', 2);
INSERT INTO `data` VALUES (10163, 'j***g', 5, '屏幕音效：屏幕用的是超窄的屏幕看起来很舒服，但分辨率是1080p，但对我来说也还算接受的。音效用的是杜比全景音效听起来真的很不错\n拍照效果：拍出来的照片，很清晰。但手机上的莱卡相机不会用，这个只有专业拍摄的才会用吧。**有拍出来的照片，大家可以看一下效果。\n运行速度：运行速度很快很流畅，本人觉得还是喜欢的。\n外形外观：好看，手感很好。\n\n续航的话，连续玩可以用六个多小时，正常使用一天一充。\n\n用了五年多的小米8今天就在我这里退休了，后面开水使用小米13。\n一直在用小米的产品，望小米产品越来越好。', '黑色', '2023-03-18 00:23:10', 3);
INSERT INTO `data` VALUES (10164, '超***兰', 5, '外形外观：很漂亮，这个颜色也很新颖，看上去很有质感\n屏幕音效：声音特别好，看视频效果很不错\n拍照效果：拍照相比于之前好多了，很舒服，拍景色很不错\n运行速度：运营速度比较流畅没有卡顿，充电也很快69w真香', '旷野绿', '2023-02-11 14:36:30', 5);
INSERT INTO `data` VALUES (10165, '踏***花', 5, '礼物收到了，使用了几天感觉很是不错，性价比高，完全碾压水果手机，很是一次愉快的购物\n外形外观：好\n屏幕音效：棒\n拍照效果：秀\n运行速度：快\n待机时间：长\n其他特色：秀儿', '远山蓝', '2023-01-06 07:21:07', 5);
INSERT INTO `data` VALUES (10166, 'a***8', 5, '外形外观：小巧直屏手感好\n屏幕音效：屏幕显示清晰，看着舒服\n拍照效果：前后摄像头都不错\n待机时间：一个上午不怎么用待机还有95％\n运行速度：运行速度杠杠的满意。', '黑色', '2022-12-26 15:07:51', 5);
INSERT INTO `data` VALUES (10167, 'j***h', 5, '手机很不错的，120zhz触屏顺滑反应灵敏，看着也很清晰，手机的拍照像素很高清，前置美颜相机也很清晰，效果很好。性价比高，操作也是非常的方便的，非常好看，质量也是非常不错哦。', '白色', '2023-01-13 18:16:38', 2);
INSERT INTO `data` VALUES (10168, 'j***h', 5, '手机昨天就收到了，给老婆买的，老婆去拿的回来拆开那第一眼就爱了，白色的好看，手感很好，运行流畅性价比也高值得拥有。', '白色', '2023-01-18 12:38:35', 9);
INSERT INTO `data` VALUES (10169, 'J***F', 5, '外形外观：小米13手感很在线，没有瑕疵，很精致\n屏幕音效：不错\n拍照效果：拍照效果很清晰，主要给宝宝拍照，相片很真实\n运行速度：快速\n待机时间：待机时间：正常使用， 待机一天', '黑色', '2023-01-05 19:29:48', 5);
INSERT INTO `data` VALUES (10170, '鸾***月', 5, '小米13已经使用了几天了，谈谈这几天的感受，小米13新机搭载了一块屏占比高达93.3%的6.36英寸全面屏，屏幕边框仅有1.61毫米宽，配合上整机独特的外边框设计，拥有非常不错的沉浸体验感，这块屏我喜欢。这块屏幕拥有1900尼特的峰值亮度，支持显示HDR10、HDR 10+、杜比视界、HLG四项好莱坞HDR标准和超动态显示技术。其还支持自然护眼模式和全亮度DC调光，通过了SGS护眼认证，能够起到保护眼睛的效果。\n    值得说明的是这次的小米13系列采用了全新的科技纳米皮材料，但我这次买的黑色的，黑色的也很不错。\n   13搭载由5000万像素IMX800徕卡主摄+1200万像素徕\n  卡超广角+1000万像素徕卡长焦组成的后置三摄系。     不错不错，我喜欢。', '黑色', '2022-12-28 15:14:56', 7);
INSERT INTO `data` VALUES (10171, '街***雨', 5, '抢了好久终于抢到了。这是我心目中最完美的手机。尺寸、性能、信号、续航、拍照，这么多年了，终于出了一部让我百分百满意的手机。续航和信号要使用一段时间才能评价，刚在吃饭的时候拍了一张照片，拍照太给力了，车牌号目视一片漆黑，用小米13长焦拍出来竟然如此清晰，真是太惊喜了。', '黑色', '2022-12-25 18:18:10', 6);
INSERT INTO `data` VALUES (10172, '酷***饰', 5, '性价比高，手感也很好！这款手机采用了骁龙8+性能铁三角组合，搭配12+256 GB的超大内存和MIUI13系统 使用是非常流畅的。另外该机还采用了120W+5000毫安的\n续航套装，不仅续航表现出色，而且充电速度是非常快的。除此之外，该机还采用了一亿像素光学防抖后 置主摄和1.5K旗舰直屏等配置，外观方面，手机尺寸为6.67英寸，机身重202g.厚度为8.48mm。采用1.5K定制直屏（2712&times;1220），支持120Hz刷新率，446PPi，观感接近2K屏幕，功耗却与1080P屏幕相近，且采用硬件\n级低蓝光。超窄边框，2.4mm超小下巴。配置方面，搭\n载高通骁龙8+处理器，CPU与GPU性能相比上 代都有\n很大的提升。散 热方面，采用电竞级VC散热，覆盖面\n积3725mm，12层堆叠。散热能力大幅度提升。续航方面，5000mAh大电量电池搭配120W闪充。拍摄方面，后置摄像头采用1亿像素主摄，支持OIS光学防 抖；8MP超广角摄像头;2MP微距摄像头。前置摄像头则采用20MP摄像头。屏下指纹重新回归，支持心率 监测、暗光解\n锁', '白色', '2022-12-30 15:05:34', 4);
INSERT INTO `data` VALUES (10173, '独***妳', 5, '外形外观：外观党，颜色好看，手感好，握着很舒服。\n屏幕音效：显示细腻，看着很舒服。\n拍照效果：拍照功能强大，效果杠杠的。\n运行速度：运行速度很快，多软件同时进行，灰常流畅。\n待机时间：一天一充，挺好的 大电池。', '远山蓝', '2023-01-19 14:12:48', 4);
INSERT INTO `data` VALUES (10174, 'x***0', 4, '外形外观：远山蓝素皮，简单，清爽\n屏幕音效：音效杠杠，反正比我之前的都要好\n拍照效果：徕卡生动，更多模式，更加专业\n运行速度：12+256满足日常所需，第二代8加提升就是高\n待机时间：4500大电池满足日常所需\n其他特色：王者荣耀挺快的进的，不比专门的游戏手机差', '远山蓝', '2022-12-20 14:04:14', 2);
INSERT INTO `data` VALUES (10175, 'P***o', 4, '外形外观：之前去过米家 看了一下 真的不错呀 回来以后就下单了\n屏幕音效：屏幕音效：屏幕虽然是1080 但是好在屏幕小 看不出来 挺细腻的 最漂亮的是边框 真的没话说\n 外放相当不错了 这么小的个头 声音还这么饱满\n拍照效果：拍照对我这个非专业人士来讲 比我拿单反拍的好\n运行速度：很快 后台也很少杀 界面的流畅度 和苹果比差不了多少了\n待机时间：正常上下班不用手机办公 回到家还能剩很多\n其他特色：这是买的第二台了 刚开始给媳妇买的 媳妇发现越用越舒服 就又给自己买了台 还有就是它的手机壳真的很不错 虽然贵点 在东北这大冷天里 还是软软的 不打滑 就是往兜里揣挺涩的', '黑色', '2023-02-15 08:05:30', 6);
INSERT INTO `data` VALUES (10176, '爱***仔', 5, '首发就抢到了，手机很好，远山蓝的颜色，没有所谓的缝隙，皮质细腻，手感轻薄，大小合适，握持舒服，入手的12G的，运行很快，边框很窄，各位自己看看吧！', '远山蓝', '2022-12-16 22:16:03', 6);
INSERT INTO `data` VALUES (10177, 'j***0', 5, '外形外观：美丽大放\n屏幕音效：显示效果好\n拍照效果：清楚清晰清透\n运行速度：运行速度非常快\n待机时间：待机在体验中还给力，但是玩了把王者，掉电还行\n其他特色：外观好过iPhone 14', '远山蓝', '2022-12-14 17:58:16', 6);
INSERT INTO `data` VALUES (10178, '紫***泓', 5, '这次小米这款手机采用了骁龙8+性能铁 三角组合，搭配12+256 GB的超大内存和MIUI13系统 使用是非常流畅的。另外该机还采用了120W+5000毫安的续航套装，不仅续航表现出色，而且充电速度是非 常快的。除此之外，该机还采用了一亿像素光学防抖后 置主摄和1.5K旗舰直屏等配置，外观方面，手机尺寸为6.67英寸，机身重202g.厚度为8.48mm。采用1.5K定 制直屏（2712&times;1220），支持120Hz刷新率，446PPi，观感接近2 K屏幕，功耗却与1080P屏幕相近，且采用 硬件级低蓝光。超窄边框，2.4mm超小下巴。配置方 面，搭载高通骁龙8+处理器，CPU与GPU性能相比上 代都有很大的提升。散热能力大幅度提升。 续航方面，5000mAh大电量电池搭配120W闪充。拍 摄方面，后置摄像头采用1亿像素主摄，支持OIS光学防 抖；8MP超广角摄像头;2MP微距摄像头。前置摄像头则采用20MP摄像头。屏下指纹重新回归，支持心率 监测、暗光解锁。帮朋友买的，他很喜欢。', '旷野绿', '2022-12-28 19:15:46', 3);
INSERT INTO `data` VALUES (10179, '海***丝', 5, '以前用的小米10，用了三年了，但是总觉得太重太大。\n这次13出来就果断买了，重量轻巧，充电太快了，8g重度玩游戏也没有任何问题。\n外形外观：边框设计的真的非常窄，正面颜值看起来非常好看，这个屏占比很高。\n\n拍照效果：暂时觉得拍的照片生动活泼，风景等拍照有待体验\n运行速度：进软件很快，游戏和平精英尝试了几把没有感觉到卡顿，手机没明显发热。', '旷野绿', '2023-01-14 23:06:03', 5);
INSERT INTO `data` VALUES (10180, '耽***秀', 5, '外形外观：薄的太精致了，绝对小米这几年的力作\n屏幕音效：清晰通透\n拍照效果：中上水平，期待13pro，图片都用13拍的\n运行速度：骁龙8+2没的说\n待机时间：主管感觉目前比我的iPhone13强一点', '白色', '2022-12-17 09:59:47', 2);
INSERT INTO `data` VALUES (10181, '小***木', 5, '首先，上午下单下午就到了，中午抢到了一波首发。首先外观，个人很喜欢，看起来很高级，很有质感，拿在手里也很有手感，至于相机模块，我感觉还行，不算太好看，也不算丑。\n手机包装很好，手机用了好几天感觉还行，大致满意，没有十全十美的产品，iPhone也有人吐槽。自己喜欢就行，何必去管他人的言语。继续使用看看，如有问题再来评价。', '白色', '2022-12-17 20:22:01', 2);
INSERT INTO `data` VALUES (10182, '墨***量', 5, '完美的手机，边框极窄，正面无敌颜值。而且是直屏比我现在这曲面屏不知道好多少。不硌手，边框过渡很出色。就是突然用小屏有的不适应打游戏。系统我没升级，听说08系统耗电是最好的。系统很赞基本上感觉有MIUI9的感觉了。广告一关，简直了完美。', '旷野绿', '2023-02-17 18:26:29', 5);
INSERT INTO `data` VALUES (10183, 'u***a', 5, '手感一流，第二次购买了，\n外形外观：高级感，比其他几个牌子的好\n拍照效果：莱卡拍照没问题，清晰度高，质感好\n运行速度：比较流畅，高刷屏，玩游戏没问题\n待机时间：基本上一天多一点，不用到处找充电器，半个小时冲满', '黑色', '2023-02-23 17:05:22', 4);
INSERT INTO `data` VALUES (10184, 'j***f', 5, '手机好看又好用，电池续航确实很带劲，十年米粉了，这次小米13做工和体验都没得说，系统也好用，当然还有提升的空间，希望小米越来越好，永远相信美好的事情即将发生。\n试用几天，早上出门上班满电，正常使用习惯和强度（之前用的小米11），晚上下班还有大概30%多的电量，算是非常给力了，之前手机白天至少要充电一次的。', '黑色', '2022-12-21 23:50:58', 7);
INSERT INTO `data` VALUES (10185, 'j***f', 5, '手机用起来很不错，很喜欢，系统也很流畅miui14给力，今年最值得期待的小米手机，刚好喜欢小屏幕的，给力，也是给自己的新年礼物，加油', '白色', '2022-12-16 21:25:40', 8);
INSERT INTO `data` VALUES (10186, '那***忆', 3, '屏幕分辨率，运行速度，有很大提升，加油', '白色', '2023-02-22 13:35:43', 9);
INSERT INTO `data` VALUES (10187, 'A***n', 5, '外形外观：外观很惊艳，直角边设计非常小巧\n屏幕音效：三星E6屏显示效果还是非常好的，亮度也很高，全局类DC调光，眼睛不再累\n拍照效果：IMX800配合徕卡的调色，拍照还是很不错的\n运行速度：搭载miui14，运行速度非常快\n待机时间：小屏旗舰里的续航算不错的', '黑色', '2023-02-20 09:17:57', 4);
INSERT INTO `data` VALUES (10188, '严***为', 4, '外形尺寸刚刚好，不是很大，在当今大屏安卓手机满天飞的日子，这种尺寸的我非常喜欢，那个Pro就大了一些了。不习惯。屏幕素质很好，虽然分辨率只有1080p，但是够用了，拍照我没要求，能拍出照片就行。真要拍，我会选择DC，现在的骁龙8第二代已经很好了，经过系统优化，整机运行速度和苹果iOS差不多了，低频高频运行都很流畅。后背的素皮是我自己买了贴的，原来的玻璃后盖太滑了。为啥那个科技纳米皮没有全黑色呢？我喜欢全黑色的数码产品，不然镜头显得很突兀。小米这次的13很给力。\n另外，我习惯音量键在左边的，这个在右边的音量键好不习惯。', '黑色', '2023-01-04 17:20:48', 5);
INSERT INTO `data` VALUES (10189, '河***斯', 5, '外形外观：非常喜欢，独特的设计\n屏幕音效：虽然不是2k，但是很满意\n拍照效果：没用上一英寸大底，些许可惜\n运行速度：铁三角组合没的说', '白色', '2023-01-12 19:31:49', 5);
INSERT INTO `data` VALUES (10190, '落***伤', 5, '外观小巧，绿色饱和度很低，实际观感很棒。后盖边缘做了处理，单手握持很舒服。不过小米13屏幕 马达和扬声器不如小米11pro，互传的时候发热比11pro的888好多了。总之还是很值得的。', '旷野绿', '2023-01-24 12:54:37', 6);
INSERT INTO `data` VALUES (10191, 'j***o', 5, '本来还把算试试三星s23的，喜欢那小屏的手感和屏幕！但看完发布会后没了期待，直接入手小米13，外观，手感都满意，拍照比不上22但也满足日常使用了！音效续航比22好很多！', '黑色', '2023-02-03 18:30:47', 2);
INSERT INTO `data` VALUES (10192, 'j***0', 5, '当天下单当天到，速度真快啊\n外形外观：简洁大方\n拍照效果：拍照挺棒的，颜色很喜欢\n顺便买了个橙色的官方壳质感也很不错\n512G可以存很多照片\n运行速度：非常快，系统稳定好用', '白色', '2023-01-19 22:10:35', 5);
INSERT INTO `data` VALUES (10193, '骨***1', 5, '屏幕音效：屏幕不错，外放效果非常好，立体声双扬声器效果超棒\n外形外观：手感比想象中好很多，虽然直边手感好于苹果\n拍照效果：徕卡加持 效果超棒\n待机时间：得益于骁龙8gen2的低功耗水平，电池不增加的情况下 待机时间超长', '白色', '2023-02-08 14:31:14', 6);
INSERT INTO `data` VALUES (10194, '_***_', 5, '我是从米8转过来的。机身外观没得说，直屏是我喜欢的类型，手机拿到手上很舒服。莱卡加持的镜头拍照也提升了不少，很加分。系统流畅度感觉还要优化下，期待后面更好用。加油，国产！', '黑色', '2023-02-21 09:14:14', 3);
INSERT INTO `data` VALUES (10195, '玉***你', 5, '外形外观：我买的小米13是白色的，设计非常硬朗，直接立边，有当年小米4的风范，但是这次采用的是不锈钢的边框，硬度比较好，可以很好的的保护手机屏幕！\n屏幕音效：小米13的屏幕是一块直屏，屏幕素质比较好，通透性和显示效果都很棒。上下双扬声器，可以达到立体声的效果，属于中规中矩的效果！\n拍照效果：徕卡联名相机，拍照很棒，是我用过的手机里面拍照最好的一款！\n运行速度：MIUI14加上超强配置，使得小米13是小屏手机中的小钢炮，运行速度杠杠的，非常流畅！\n待机时间：中度使用一天妥妥的，中度使用在8个小时左右，有67w快充，不用为手机电量而焦虑！\n其他特色：小米13的设计长在了我的审美点上，还有全局动态高刷，用起来真的非常爽，这是一部值得推荐的手机！', '白色', '2022-12-18 15:34:55', 4);
INSERT INTO `data` VALUES (10196, '晚***浦', 5, 'Miui流畅度很高，外观很满意，精致板正，还是黑色的YY ds。续航能力还不错。读写速度快。', '黑色', '2022-12-17 20:01:20', 7);
INSERT INTO `data` VALUES (10197, '灰***2', 5, '手机质量很好，操作方便，反应速度灵敏，第一次用小米，真心好，手机也不发烫，续航时间长，耗电量不大，物美价廉，赞一个！', '黑色', '2023-01-30 21:30:07', 2);
INSERT INTO `data` VALUES (10198, '哟***_', 5, '说下认真的，小米6用到现在就是等出直屏手机，终于等到了，配置到位，旗舰机各方面还是比较均衡。窄边直屏，比较小尺寸的直边机 莱卡总体来说拍照体验很好 运行速度冰龙8 gen2这次太猛了可以又做钉子户了。', '黑色', '2022-12-31 19:41:54', 6);
INSERT INTO `data` VALUES (10199, '石***4', 5, '外形外观：外观非常漂亮的直屏手机，玻璃后盖圆润，有很好的握持感，金属边框大气上档次\n屏幕音效：屏幕虽然不是2k屏，但也不影响观感，显示效果细腻，双扬声器，杜比音效，声音通透\n拍照效果：有莱卡的加持，拍照效果很有质感，特别是莱卡经典模式，长焦拍摄也很清晰\n运行速度：miui14系统简洁，运行速度快，流畅\n待机时间：待机时间最满意，妥妥的一天一冲足够，亮屏时间六个小时\n其他特色：总体来说小米13性能均衡，无短板，算是近几年小米出的最好的手机', '黑色', '2023-01-13 14:06:01', 4);
INSERT INTO `data` VALUES (10200, 'j***明', 5, '手机下午收到货，就及时完成了换机使用。手机外观漂亮，手感极好。重量合适。屏幕音效好，显示效果也很好。拍照效果有莱卡加持，比先前发布的机型都有改进。远行速度有米柚14加持运行如风。', '黑色', '2022-12-26 22:51:25', 7);
INSERT INTO `data` VALUES (10201, '随***游', 5, '外形外观：非常高端大气上档次\n屏幕音效：屏幕素质很高\n拍照效果：很好\n运行速度：非常流畅\n待机时间：续航优秀', '黑色', '2022-12-19 13:39:00', 5);
INSERT INTO `data` VALUES (10202, 'j***c', 5, '这次买的小米13收到货后就被她惊讶到了！实机要比图片漂亮多了，完全比苹果手机好看！而且用起来丝滑流畅，打开APP简直叫快！拍照性能大赞??，照片真的太好了！太牛逼了！窝*，这么好的手机！惊得我叫出了声！', '远山蓝', '2023-02-03 19:06:19', 3);
INSERT INTO `data` VALUES (10203, 'j***x', 5, '换手机了，非常漂亮，小米13，抢手货，非常喜欢，手感特别好，购买了好多台小米手机了，这次的新品设计非常棒，特别是尺寸大小非常合理，用起来很方便，我是超级米粉。', '远山蓝', '2023-01-13 08:49:54', 8);
INSERT INTO `data` VALUES (10204, '0***m', 5, '手机很不错，用起来很流畅，手感还可以，也很漂亮，值得推荐。顺便买了个官方壳，很不错。', '白色', '2023-01-05 23:58:43', 9);
INSERT INTO `data` VALUES (10205, '柠***f', 5, '外形外观：这一代小米颜值还是可以的，手感很好\n屏幕音效：清晰细腻，眼睛看的很舒服，色彩方面很不错\n运行速度：新机运行起来一点都不卡，等后续再看', '黑色', '2022-12-23 14:20:32', 6);
INSERT INTO `data` VALUES (10206, '江***_', 5, '外形外观：小米小米\n屏幕音效：无敌无敌\n拍照效果：雷军雷军\n运行速度：牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛牛', '远山蓝', '2022-12-16 09:29:49', 3);
INSERT INTO `data` VALUES (10207, 'J***9', 5, '小米13确实是最完美的一代小米，比之前用过的优化了太多，也没有电池问题，做工精细，值得推荐。再配上莱卡镜头，拍照更上一层楼，系统优化流畅，不再卡顿，值得推荐。', '白色', '2023-01-25 12:56:49', 6);
INSERT INTO `data` VALUES (10208, 'l***8', 5, '外形外观：简洁明了大方，就因为外观直屏才抢购的\n屏幕音效：屏幕色彩真实，音效很好\n拍照效果：色彩真实\n运行速度：很好\n待机时间：待机时间挺长的满意', '黑色', '2022-12-16 17:31:58', 4);
INSERT INTO `data` VALUES (10209, 'j***d', 5, '这一代比上一代强多了，手感好，喜欢直屏手机\n外形外观：直屏手机非常喜欢，握在手里很舒服\n屏幕音效：可以还不错\n拍照效果：比较好的\n运行速度：非常快\n待机时间：长', '黑色', '2023-02-04 21:00:39', 3);
INSERT INTO `data` VALUES (10210, 'j***2', 5, '外形外观：简洁大方，远山蓝真的很好看，手感也很好\n拍照效果：拍照真的不错，随手一拍就是大片\n运行速度：很流畅\n待机时间：电池续航还行', '远山蓝', '2023-02-23 19:35:23', 5);
INSERT INTO `data` VALUES (10211, 'j***8', 5, '外形外观：6.36的规格刚合适\n屏幕音效：音质很棒\n拍照效果：拍照效果感觉比iPhone好\n运行速度：一个字，快。\n待机时间：刚上手，需进一步评测，但我想待机时间怎么都比iPhone14好。\n其他特色：外观很漂亮，我选的颜色我喜欢。', '旷野绿', '2023-02-09 13:51:47', 4);
INSERT INTO `data` VALUES (10212, 'a***6', 5, '用了一个星期了，感觉非常棒。非常的漂亮，特别是这个素皮，真的惊艳。拍照也特别的清晰。买的12G运存，速度非常的快，非常满意！', '远山蓝', '2023-01-21 11:40:51', 2);
INSERT INTO `data` VALUES (10213, '是***呀', 5, '线下体验了，觉得13手感不错，外观也不错就下单了。不愧是小屏旗舰，屏幕显示清晰，屏幕边框完美，音效逼真，还原真实，拍摄清晰，莱卡联名，夜景很好前置也很棒，运行速度快，游戏毫无压力，待机时间长，很喜欢这款手机，还是挺不错的', '白色', '2023-01-06 14:49:58', 4);
INSERT INTO `data` VALUES (10214, '我***神', 5, '外形外观：手感很不错，拿在手上杠杠的，舒服得一批。\n屏幕音效：画质很细腻，\n运行速度：非常流畅，很快。\n拍照效果：清晰，美颜。\n待机时间：非常的长，新机一天一充。', '黑色', '2023-01-14 18:57:30', 4);
INSERT INTO `data` VALUES (10215, '你***笑', 5, '方正中带些圆滑，尺寸刚好，不大不小。拍照效果：有徕卡滤镜，一流的相机，拍摄很清晰。 运行速度：soc和读写都很快，应用\n和游戏秒开，体验非常好。 待机时间：中强度用了12小\n时还有40%左右，充电也很快，足够耐用了', '黑色', '2023-01-20 16:06:49', 3);
INSERT INTO `data` VALUES (10216, '翠***霭', 5, '外形外观：直屏很满足我的需求，很喜欢远山蓝的颜色和质感。\n屏幕音效：显色清晰，杜比音量也很不错。\n拍照效果：蛮喜欢徕卡镜头自带的质感，长焦拍出来效果也挺好。\n运行速度：运行速度比旧手机快太多了。\n待机时间：续航能力还是挺强的，充满一次大概能成用大半天了。', '远山蓝', '2023-02-08 23:40:39', 6);
INSERT INTO `data` VALUES (10217, '张***根', 5, '外形外观：比较喜欢这个尺寸，比三星S22长点，6.1-6.2就完美了。\n屏幕音效：屏幕看上去挺惊艳的，峰值亮度很高，阳光下使用很不错。\n拍照效果：随手拍了几张，还是不错的。\n运行速度：速度杠杠的，很丝滑。\n待机时间：续航很好，比手上的S22强很多，回血也快很多。', '黑色', '2023-01-01 12:31:14', 4);
INSERT INTO `data` VALUES (10218, '天***边', 5, '给老婆买的，一直用的小米8，还能用，但是屏幕坏了，直接换小米13，很惊艳，尺寸女生用刚刚好，各项性能均衡，信号明显比我的小米11强很多。', '旷野绿', '2023-03-13 21:24:48', 2);
INSERT INTO `data` VALUES (10219, 's***8', 5, '外形外观：绿色很淡淡的，很好看\n屏幕音效：屏幕阳光下看十分清晰\n拍照效果： 拍照非常好，比上一代优化了不少\n运行速度：十分流程，不卡顿', '旷野绿', '2022-12-17 20:59:04', 5);
INSERT INTO `data` VALUES (10220, 'j***6', 5, '配置高，使用很流畅，整机大小很合适，外观和质感都在线，小米高端产品中的爆品，确实是13香使用体验很好，拍照效果出色', '白色', '2023-01-27 22:07:07', 2);
INSERT INTO `data` VALUES (10221, '津***哥', 5, '好用的很，运行速度快，快递也给力。这个小屏幕的机器，大爱。', '黑色', '2023-03-18 23:49:03', 8);
INSERT INTO `data` VALUES (10222, '七***徊', 5, '小屏直屏手机中非常均衡的一款了，有了8gen2，终于可以暂时告别火龙时代了，单层主板也让13的散热比13pro更厉害，13的续航非常?，因为功耗控制的好，续航甚至超越很多大电池手机。重量和厚度控制的非常非常好，这点在现在属实是很难得了。外观很精致，白色真的yyds。短焦指纹并不短板，识别位置对于小屏手机来说完全不是问题。和莱卡合作调教的相机也挺不错（下面是我拍的月亮哈哈哈）。\n\n至于13和13Pro之间我为什么选13。13Pro的主要优点是相机更极致、充电更快、屏幕分辨率给到2k、色深和触控采样率更高、马达更好。13的优点是散热更好，功耗控制更好、小屏直屏（这点见仁见智）、更轻的重量和更薄的厚度、在屏幕高亮度时不会失去护眼效果（13全程DC，而13Pro在高亮度下会由护眼的高频pwm调光切换到不护眼的低频PWM）。综上感觉13的优点更加契合我自己，这几天实际体验也很不错，系统很流畅，大部分广告都可以关，几乎没遇到什么bug，这次还上了ip68，好评！希望能多用一段时间', '白色', '2023-01-09 00:17:12', 4);
INSERT INTO `data` VALUES (10223, 'h***i', 5, '小米13 我梦寐以求的手机今天总于到手了，从上市到现在也有两个多月了吧，一直关注着 这款手机 6.36的直屏手机里面小米13应该是无敌了，显示效果非常的棒 相机这次又有莱卡的加持 性能完美 白色 搭配我买的黑色手机壳 相当漂亮', '白色', '2023-02-14 08:10:29', 5);
INSERT INTO `data` VALUES (10224, '爱***丘', 5, '超出预期，质量很好，做工精细，满意特别特别满意，超级好看，客服很有礼貌，很客气，良心商家，支持！真心喜欢，颜色、款式都非常棒！搞活动买的，外观和描述一致，美观实用，材质手感都不错，好评！', '黑色', '2023-01-15 12:02:41', 5);
INSERT INTO `data` VALUES (10225, 'j***7', 5, '外形外观：颜值很高，边框很窄\n拍照效果：多年没用小米，比之前的拍照好了很多\n运行速度：最新的处理器，很快\n待机时间：比原来苹果手机待机长了一些，明星耐用', '白色', '2023-01-14 16:27:10', 4);
INSERT INTO `data` VALUES (10226, 'a***1', 5, '外形外观：时尚！！简约！！美观！！大方！！\n屏幕音效：大小很合适，看起来很高清，拍照还是不错的\n运行速度：不错不错\n待机时间：这个还可以', '白色', '2023-02-12 18:49:05', 4);
INSERT INTO `data` VALUES (10227, '邓***耍', 5, '外形外观：外观设计很好看，非常满意！\n屏幕音效：屏幕很清晰，音效也还可以\n拍照效果：就是冲着莱卡的摄像头入手的，本想上13PRO的，可是老婆不批准，只能入手13的顶配了，不过拍照效果也真心挺不错的了！\n运行速度：运行速度：我目前运存是12+3G的，反应速度 相当顺滑！\n待机时间：因为最近家里刚添了对小龙凤，就偶尔发发信息购购物看一小会视频，午睡时听会歌，没时间重度使用手机，现在晚上七点半还剩62%的电量。', '黑色', '2023-03-18 19:31:04', 4);
INSERT INTO `data` VALUES (10228, '晓***6', 5, '外形外观：基本四边等宽，黑边非常窄，视觉效果一级8棒。正面，直屏，背面后盖基本上是2.5d玻璃，握持手感非常棒。\n运行速度：骁龙8gen2处理器相对于上一代来说提升非常大，尤其是对于发热的控制比较好。顶尖的处理器加上MIUI14的优化，非常的流畅。\n屏幕音效：1080P的屏幕，但是E6的材质，峰值亮度能达到1900尼特，户外看毫无压力，阳光屏名不虚传。音效无所谓，基本上不用外放，我不知道。\n拍照效果：拍照效果对我来说足够用日程，也就是工作需要拍一些照片能够看清楚成像，速度快就ok。', '黑色', '2023-01-20 18:09:49', 4);
INSERT INTO `data` VALUES (10229, '如***月', 5, '颜值非常高，体验也很好，目前颜值最高的手机，拍照也很好看，大爱。唯一就是电量不耐用', '旷野绿', '2023-01-12 15:42:49', 3);
INSERT INTO `data` VALUES (10230, 'j***6', 5, '外形外观：外观太好看了\n屏幕音效：屏幕很好，三星E6屏\n拍照效果：拍照效果很好\n运行速度：运行速度快\n待机时间：待机时间一天多\n其他特色：整体很满意', '黑色', '2023-03-08 18:25:07', 4);
INSERT INTO `data` VALUES (10231, '六***v', 5, '很不错的手机，莱卡的影像效果很赞。高通骁龙的最新处理器性能也是非常的出众！价格也很实惠,性价比很高的水桶机了,有望成为新一代&ldquo;米6钉子户&rdquo;了。?', '远山蓝', '2023-01-05 14:32:55', 6);
INSERT INTO `data` VALUES (10232, 'y***8', 5, '外形外观：外形小巧，手感很好\n屏幕音效：屏幕和音质都是很不错的\n拍照效果：拍照效果很不错，很满意莱卡联明的相机\n运行速度：运行速度流畅非常丝滑\n待机时间：待机时间还好吧，4500的电池续行不算特别优秀吧', '旷野绿', '2023-03-06 20:58:36', 4);
INSERT INTO `data` VALUES (10233, 'j***e', 5, '给老妈换的，真是全方位的好看，小米高端真成了?，拍照好，续航可以，手机不发烫，新一代水桶机yyds，搞得我也想再整一块儿玩玩了??????????', '旷野绿', '2023-01-24 20:52:47', 2);
INSERT INTO `data` VALUES (10234, 'a***9', 5, '外形外观：外观大气，大小适中，很有设计感，很喜欢这个外形，精致低调。\n屏幕音效：屏幕120赫兹不闪烁，看着舒服，亮度高，影像细腻，色彩艳丽不夸张，满满的靓丽。\n拍照效果：拍照很清晰，景深有层次感，远景也很清晰。\n运行速度：运行很快，打开软件速度很快。\n待机时间：待机达到要求。', '远山蓝', '2022-12-30 17:24:45', 3);
INSERT INTO `data` VALUES (10235, '风***宁', 4, '当天下单当天送达，非常快！手感非常好，非常轻薄，屏幕1080p比我之前用的2k没有明显落差，充电速度吗比之前120W要慢，整体体验非常好，值得购买。', '黑色', '2022-12-15 13:36:08', 6);
INSERT INTO `data` VALUES (10236, '姜***予', 5, '双12后抢的，很幸运昨天到手了。今早充满电，到下午还有一半真不错。而且换机功能真是颠覆了我的认知，跟克隆一样，东西一样不少布局都相同。徕卡相机拍照也清晰。还有高档的光学指纹锁，很满意.', '黑色', '2022-12-19 17:58:34', 6);
INSERT INTO `data` VALUES (10237, '呼***光', 4, '外形外观：外形还可以，我的素皮的，高级，但略显塑料感！\n屏幕音效：音频很好两个音效，不错！\n拍照效果：拍照还不错的！这个档位的差不多了\n运行速度：运行速度没得说，还可以，不错的手机！\n整体这个手机还不错，还有无线存电，很好！非常的不错这个价位！年轻朋友学生党，预算不充足的可以考虑！', '素皮晴蓝', '2023-01-12 17:57:01', 7);
INSERT INTO `data` VALUES (10238, 'u***a', 2, '外形外观：红米K60外观设计风格好看，炫酷\n屏幕音效：2k显示就是好，清晰度高，双扬声器，声音好听\n拍照效果：日常够用，不错\n运行速度：骁龙8?狂暴引擎，用起来顺畅\n待机时间：5500毫安大容量，告别一天两充\n其他特色：性价比超高，活动直降300，直接入手，你不会后悔，这配置同价位值得推荐，外观好看，电池容量大，运行快，日常拍照够用，完美搭配\n京东商城物流配送准时必达，今天拍明天到，一直喜欢在京东商城购物，省心省钱安心', '墨羽', '2023-02-26 19:42:20', 8);
INSERT INTO `data` VALUES (10239, '叼***灰', 5, '外形外观：外观大气，白色果然好看，黑色容易粘指纹\n屏幕音效：屏幕完美，观感比50好。\n拍照效果：拍照速度快，光学防抖不错。\n运行速度：速度快，打联盟有120选项。爱我的游戏平板还厉害。\n待机时间：待机时间问题不大，应该一整天没问题，毕竟也是5500大电池。\n其他特色：总体来说很满意，还有无线充，简直完美。', '晴雪', '2023-01-02 13:55:00', 6);
INSERT INTO `data` VALUES (10240, 'j***0', 4, '整体还是很不错的，电池也耐用\n运行速度：挺快\n拍照效果：还好\n外形外观：我都买黑的，这个没差\n屏幕音效：不错\n待机时间：较我小米10长挺多\n其他特色：miui14系统不错，流畅', '墨羽', '2023-03-09 18:54:27', 5);
INSERT INTO `data` VALUES (10241, '1***l', 5, '付款第二天就收到了，京东物流给力。使用了几天才来评价，可以负责任地说k60非常不错，这个价格买到了旗舰机的品质。外观很精致，素皮的手感不错，一点塑料感都没有。使用起来很流畅，屏幕色彩细致鲜艳，长时间使用也没有发烫。充电速度特别快，而且还有无线充。总之相当满意，推荐购买', '素皮晴蓝', '2023-01-17 21:37:09', 7);
INSERT INTO `data` VALUES (10242, 'f***8', 4, '外形外观：手感很棒，边框很窄。\n屏幕音效：看视频双音响音效很爽。\n拍照效果：拍照图片很细腻，比小米10Pro效果更好。\n运行速度：888+不是盖的，运行非常流畅，温控控制的很好。\n待机时间：5500毫安时大电池，出差一点顾虑都没有了，非常给力。', '墨羽', '2023-01-03 10:41:48', 4);
INSERT INTO `data` VALUES (10243, '琪***我', 5, '上午付款，晚上就收到了，不得不说京东快递的速度真快！这是家里的第三部红米手机，一如既往的好！\n运行速度：快\n外形外观：好看\n屏幕音效：非常好\n拍照效果：不错', '素皮晴蓝', '2022-12-31 19:27:28', 7);
INSERT INTO `data` VALUES (10244, '伟***哈', 5, '外形外观：外观设计的非常漂亮，握在手中非常的舒服。\n屏幕音效：屏幕显示的很好，2K分辨率不是吹嘘的。音效非常的棒。\n拍照效果：拍照效果非常的好，6400w像素完全拿捏。\n运行速度：骁龙8+ 处理器加持，运行速度极快。\n待机时间：待机时间很久，完全够用。', '素皮晴蓝', '2023-03-05 23:19:52', 4);
INSERT INTO `data` VALUES (10245, '一***草', 5, '外形外观：白色，干净利落\n屏幕音效：屏幕大，颜色真实，分辨率高\n拍照效果：清晰，反应速度快\n运行速度：得益于大内存，所以感觉还是很快的\n待机时间：刚开始用，还可以，5500毫安不打游戏看视频的话足够的，何况也是给长辈使用\n其他特色：大内存，价格优，送货快', '晴雪', '2023-02-26 09:35:10', 9);
INSERT INTO `data` VALUES (10246, '抠***B', 5, '非常满意！ K60比K40运行更流畅，玩王者荣耀，明显感觉操控性更强更灵敏。120赫兹高刷新特效全开，画质拉满视觉拉满。5500毫安电池确实给力！一口气玩7个小时，电量还有剩余。', '墨羽', '2023-01-26 15:21:49', 5);
INSERT INTO `data` VALUES (10247, '一***光', 5, '昨天下午下单，今天上午就收到了，京东物流就是给力！！期待的手机终于到手了！手机外观蛮不错的，玻璃后盖，白色款感觉很高档；2K屏幕很清晰；MIUI14真的很轻快很丝滑；拍照也很清晰，对我来说够用；杜比音效很赞。K60性价比绝对高，很多基础配置和Pro一样，我不怎么玩游戏，骁龙8+芯片已经很够用了，16+512感觉能用5年，嘿嘿！', '晴雪', '2023-01-01 15:03:36', 5);
INSERT INTO `data` VALUES (10248, '风***河', 5, '拿到手机也是玩了三天， 打王者的话大概充满 电，可以玩三个半个小时左右，剩余电量的话 到百分之二十八， 手机外观颜值还是可以的， 屏幕也很大，打王者不卡顿，看视频发语音， 声音很不错， 很有立体感，下载应用软件速度 也很快，总的来说， 这款手机的性价比还是比 较高， 我很满意！想买的别犹豫哇！没有廉价的感觉，很高端，特别棒！', '晴雪', '2023-03-04 22:21:29', 9);
INSERT INTO `data` VALUES (10249, 'L***g', 5, '一直用小米手机，基本都是每年一换，真的很好用\n外形外观：漂亮，手感很好\n屏幕音效：显示效果很细腻\n拍照效果：一般只用来扫码&hellip;\n运行速度：极度流程，和我的苹果没区别\n待机时间：一天没压力', '墨羽', '2023-01-05 17:07:29', 3);
INSERT INTO `data` VALUES (10250, '7***7', 5, '超出预期，质量很好，做工精细，满意\n外形外观：还可以，很顺滑，无瑕疵\n屏幕音效：国产屏幕很惊艳，不错\n拍照效果：我爱打游戏，满足需求\n运行速度：很好，发热明显比之前的要低\n待机时间：很好\n其他特色：整体感觉不错', '墨羽', '2023-01-04 10:40:50', 4);
INSERT INTO `data` VALUES (10251, 'b***n', 5, '外形外观：外观漂亮，素皮美观大方，手感很棒！\n屏幕音效：音效双扬声器效果不错\n拍照效果：拍照初步测试出片效果清晰\n运行速度：运行速度很快，骁龙 8+的加持，效果没得说\n待机时间：刚到手待测试\n之前还在挑选送给母亲的什么手机好，当天就看到 K60 的发布会，就直接预定下单。并且在昨天首批付下尾款，今天 2023 年一大早就收到手机了，全程开箱过程已记录，新年第一天，希望都会越来越好吧！', '素皮晴蓝', '2023-01-01 12:05:31', 9);
INSERT INTO `data` VALUES (10252, '旁***敏', 5, '外形外观：外观很好！手感也很不错，\n屏幕音效：屏幕很清晰，续航时间也长！\n拍照效果：拍照很清晰！\n运行速度：运行很流畅\n新年第一天，收到货很开心！物流棒棒哒?！', '晴雪', '2023-01-01 10:19:38', 4);
INSERT INTO `data` VALUES (10253, 'm***9', 5, '给老爸买的K系列最新款的手机，没想到春节期间也能准时送达，不得不给京东快递点个赞。老爸非常喜欢，说是暗搓搓心仪已久，运行速度很快，内存也大了，像素也能满足爱他摄影的要求，且自带滤镜。选了蓝色款的，外观色彩清新，有皮革质感，配套的透明保护套也非常实用。', '素皮晴蓝', '2023-01-27 11:28:51', 9);
INSERT INTO `data` VALUES (10254, 'j***d', 5, '小米K60性价比超高，第三次购买了。家里人都是小米K60了。屏幕是国产2k屏，显示效果非常好，续航一天无压力，颜值也比较高，拍照效果好，音效悦耳，运行速度快。总体来看是一款相当不错的中端机。女神节互赠礼品首选。', '晴雪', '2023-03-08 18:49:16', 5);
INSERT INTO `data` VALUES (10255, 'E***-', 3, '总的来说还算不错，加油加油加油加油', '晴雪', '2023-02-20 07:54:14', 2);
INSERT INTO `data` VALUES (10256, '骑***西', 5, '其他特色：外观干净漂亮，做工很不错，没发现什么瑕疵，个人感觉大小也挺合适，找了很久选的这款，大爱！已经收到啦，很不错，还有赠品，性价比太高啦，爱了爱了', '幽芒', '2023-03-17 12:31:36', 5);
INSERT INTO `data` VALUES (10257, '淘***玲', 5, '外形外观：外观好好看\n屏幕音效：屏幕音效好\n拍照效果：很清晰红米就是好\n运行速度：运行速度非常好\n待机时间：非常好', '墨羽', '2023-01-05 17:58:53', 4);
INSERT INTO `data` VALUES (10258, '落***寻', 5, '一直都是米粉，K60色彩鲜艳，充电也很快，就是配件感觉减少，其他性能非常到位！12+256G应该够用，感谢京东自营平台&hellip;\n一次很好的购物体验，服务周到，物流快速，配送也很周到，态度也很好，物有所值啊，果断好评！', '幽芒', '2023-01-07 07:15:01', 9);
INSERT INTO `data` VALUES (10259, '我***会', 5, '昨天支付的尾款，今天就收到了心爱的手机，真的太高兴了，这还得益于京东的物流速度，是真的好快啊。今年上半年刚买了k50系列，下半年就入手了这款k60系列，这也是首次红米手机出现无线充电功能，现在终于可以用上了，原本想买512GB以上内存的，无奈目前还未出来，不过这k60的内存也已经够用了，手机试用了下，流畅，玩游戏也很爽，各方面都还不错，处理器也不弱，这是一款非常值得入手的2023年的手机。', '墨羽', '2023-01-01 14:22:43', 9);
INSERT INTO `data` VALUES (10260, '吾***后', 5, '使用了几天后来评价。从其手机背面来看，素皮蓝的后壳，一种古色古香的色彩，很是招人喜欢。两个上下音效效果在播放具有杜比声效音乐时，会有一种心旷神怡的效果，听上去很美。屏幕显示效果很细腻，触控点灵活。拍照效果一般没有出色的表现。运行速度快，待机再不玩游戏前提下，能使用一天不需要充电。配送很快，售后服务目前还没有使用，希望出现问题能给予及时解决，先给个好评!', '素皮晴蓝', '2023-03-08 19:23:34', 8);
INSERT INTO `data` VALUES (10261, '北***虹', 5, '快递速度很快，全新未拆封正品新货，屏幕没有亮点，暗点，死点，孩子原来的K30P前置摄像头弹不出来了，还换性价比k系列，看中的是处理器和大存储，孩子非常满意，给亲全五分好评！！！', '晴雪', '2023-01-18 22:08:01', 6);
INSERT INTO `data` VALUES (10262, '木***0', 5, '外形外观：给老婆大人买的，后壳颜色真的不错\n屏幕音效：双扬声器器，真的很不错，有立体音效\n拍照效果：拍照成像效果非常满意\n运行速度：8+256正常运行，玩游戏够用\n待机时间：刚刚买来，后续追评运行时间', '幽芒', '2023-01-15 19:10:41', 3);
INSERT INTO `data` VALUES (10263, '微***染', 5, '手机外观非常漂亮，拍照效果特别强大，通话音质清晰，运行速度特别的快，屏显特别清楚，触摸手感非常好，对小米刮目相看流畅至极244 充电快速116 清晰度高114\n\n手机特别好用，反应速度\n外形外观：时尚，经典，直面屏\n屏幕音效：屏幕2k屏幕，清晰，明亮。拍照效果：不错，很清楚，性价比高。运行速度：非常快，一点也不卡顿，\n待机时间：很长，用起来舒服，很给力', '墨羽', '2023-01-19 11:53:20', 6);
INSERT INTO `data` VALUES (10264, 'j***x', 1, '给妈妈买的手机，昨天我下班回来，她给我说手机听不见声音，我给她打电话我也听不清。等我下班回去听她说不好用了，二话没说直接逛京东看手机，挑了几款让她选。最后选择了k60的图片。非要买个百元机，那就当百元机卖给她用。当天晚上下单，第二天中午就到了。京东物流，还是和以前一样快！工作于物流，理解他们。\n我也只是个学生，高考滑档壳就暂工作一段时间，买这个手机手里就剩下了800块，花了2600+的京东白条分期卖给她的。所有的软件授权挨个调试完成。她喜欢就好，希望妈妈永远快乐幸福?\n对于手机，综合来看:真不错，满足90％人群使用，两个月前买了一部iPhone13pro，手里还有一部麒麟芯片的华为手机。打算再努力努力，给自己再换回小米！（原来用小米手机，因为MIUI12系统，断了关系了）\n屏幕音效：优秀，立体音效，对于我妈来说，没啥用，哈。\n外形外观：素皮后盖，不错。显高档\n拍照效果：没具体使用，我是一个摄影爱好者。普通人基本需求能满足了。\n运行速度：8GB，再加3GB。很流畅\n待机时间：没问过。今天刚到的，才冲了1次电，新手机开机手机有50％的电量。我妈充电完毕后，各个功能调试完毕后还有77％。\n其他特色：好久没用小米系列旗舰机，没注意特色，我觉得特色就是真旗舰敢KO', '素皮晴蓝', '2023-02-13 21:41:41', 6);
INSERT INTO `data` VALUES (10265, 'g***9', 5, '手机非常好，屏幕清晰度高，系统流畅，红米手机越做越好了。\n运行速度：快\n屏幕音效：好\n外形外观：好\n拍照效果：好', '晴雪', '2023-03-10 14:04:51', 3);
INSERT INTO `data` VALUES (10266, 'x***9', 5, '外形外观：白色，看着很亮堂，手感也不错，做工精细\n屏幕音效：扬声器听起来悦耳，音效非常好，屏幕分辨率高显示很细腻，色彩不失真\n拍照效果：清晰，拍照够用\n运行速度：骁龙8+处理器已经很前卫了，选的12+256，近几年应该不会成为瓶颈\n待机时间：不知后续如何，特意选了个充电快的机型，担心用段时间电池成为瓶颈\n其他特色：红米系列第一款支持无线充电，后续配个无线充电器试试看，2天前刚买了一个同款同配置，希望能够不负期待，送的手环还好。', '晴雪', '2023-03-17 07:42:19', 7);
INSERT INTO `data` VALUES (10267, 'y***i', 2, '之前的红米k20Pro至尊版用了小4年，换了3次电池。这次下狠心直接升级换了k60，没失望，哪哪都好，2k屏真的很细腻。上下扬声器，横屏看视频立体声效果特别棒。评论视频是用k20拍的所以效果不好，用k60拍的效果简直杠杠的。还要提一下MIUI的****功能，真的很方便，之前刷机都是备份恢复没用过这功能，这次用好的一批。', '晴雪', '2023-01-06 23:04:41', 4);
INSERT INTO `data` VALUES (10268, 'l***8', 5, '外形外观：外形我买的是素皮的质感特别好，大方美观。\n屏幕音效：屏幕2k分辨率十分清晰。外放音质特别好，\n拍照效果：拍照效果特别棒\n运行速度：12G大运存。速度特别快，不卡顿。', '素皮晴蓝', '2023-03-20 10:36:09', 3);
INSERT INTO `data` VALUES (10269, '麦***店', 5, '外形外观：高端大气\n屏幕音效：很清楚\n拍照效果：像素很高\n运行速度：超级快\n待机时间：用一天没事', '墨羽', '2023-03-15 12:01:32', 3);
INSERT INTO `data` VALUES (10270, '朱***哦', 5, '屏幕音效：挺不错的，很满意！\n运行速度：很快，物有所值！\n待机时间：使用是比较长的，\n拍照效果：还不错?，挺满意的\n其他特色：充电很快，加上30W无线\n买给我弟弟的，日常玩玩游戏，主要看这性能也不错，挺棒的，性能、屏幕、影音都挺好的，性价比也高！很棒???', '墨羽', '2023-02-07 16:50:41', 3);
INSERT INTO `data` VALUES (10271, 'r***n', 5, '这款手机简直超值，价格优惠了300不说，关键很轻便，容量非常大，电池续航极为优秀，最关键的是它有无线充电，这2000块钱的手机有无线充电你受得了吗？绝对是性价比之王。当然屏幕什么不是三星的，但显示效果也可以了。', '墨羽', '2023-03-08 11:44:32', 8);
INSERT INTO `data` VALUES (10272, 'u***K', 5, '外形外观：幽芒色非常好看，特别是在有灯光的情况下\n屏幕音效：屏幕大，音效比起老手机来说好得多\n拍照效果：看不出有什么\n运行速度：很快，不愧是骁龙8+\n待机时间：电池大，待机时间长', '幽芒', '2023-03-09 14:09:06', 6);
INSERT INTO `data` VALUES (10273, '落***寻', 5, '红米系列新品，已经用了好几年了，这次是第二次购买了，这款K60新上市配置也不错，特地买了一款12+512G配置，应该够用了&hellip;也希望后续不再卡顿&hellip;\n五星好评，6400W像素，2K高光国产屏&hellip;确实优秀&hellip;\n京东自营物流真快，时效杠杠滴，8号晚上下单，9号就收到货品，确实给力，也谢谢客服的跟进，服务态度都不错&hellip;', '幽芒', '2023-01-09 21:28:31', 9);
INSERT INTO `data` VALUES (10274, 'j***t', 3, '外观手感略显廉价，勉强合格', '素皮晴蓝', '2023-03-08 21:18:07', 3);
INSERT INTO `data` VALUES (10275, '江***龙', 5, '春节的发货速度很快！特意买的高配，12+256，用着更流畅！整机的性价比很高，性能很好，30w无线充电同级别没有对手，这款机器很不错！宝贝已收到?，超级喜欢，颜值高又实用，超级喜欢！???跟实体店没有区别，还便宜，喜欢！性价比很高，很实惠，使用起来感觉很好，非常完美.^?^.好产品、好品质、好服务，宝贝确实值这个价钱，在这给商家点个赞?是正品，而且价格不贵，用着也很大气，一直在用，很好??宝贝收到了，很惊喜，质量非常好，很满意的一次购物。我会继续回购的，店家值得信赖', '晴雪', '2023-01-28 12:49:48', 4);
INSERT INTO `data` VALUES (10276, '萨***翼', 5, '好产品、好品质、好服务，宝贝确实值这个价钱，在这给商家点个赞?包装很完美，颜值很高，感觉物超所值！客服也非常耐心细致，发货快物流给力，以后还会再来??已经收到啦，很不错，还有赠品，性价比太高啦，爱了爱了趁着优惠，赶紧入手，是正品，包装也非常的好，没有破损，质量也是没得说，棒?精挑细选很久?，最后决定买这一款?，到货后果然没有让我失望，实物很漂亮?，做工很精细?，特别满意?这个真的太?了，?包装很精美，宝贝做工比较精细，商家特别好?，有问题都及时处理?，确实是一次相当满意的网购，还会再来的?大无语事件家人们！咱就是说，太好用了，狠狠的爱住了！物流满分?，包装快递满分?，配送员态度满分?，购物让人开心，吃土使我快乐~?????????', '幽芒', '2023-01-03 23:02:53', 9);
INSERT INTO `data` VALUES (10277, '齐***8', 5, '收到了，手机流畅不卡，使用满意，谢谢配送员师傅辛苦啦，过年期间能不休息还给派送，以后需换时还会再次光临购买的，本次给予全五星好评。', '幽芒', '2023-02-11 08:05:58', 8);
INSERT INTO `data` VALUES (10278, '再***西', 5, '一直用Redmi的K系列手机?，这次推出的K60了解配置后果断入手?。 \n这次配置的升级非常给力?，处理器直接搭载上台积电4**工艺的高通骁龙8+处理器?，支持智能稳帧技术的强悍性能，辅以优秀的能耗，运行游戏帧率非常稳定。实测《王者荣耀》?120Hz高刷高清游戏模式，2小时游戏平均帧率高达118.2Hz，玩游戏真的是超爽的?。\n峰值温度则控制在40度内，在游戏表现在真的很棒。 屏幕采用2 K分辨率超清屏，这块屏居然搭载在2千+这个价位上着实让我大感惊喜?。支持120Hz高刷、1400nit峰值亮度、687亿色原色屏?和1920Hz高频PWM调光，这样的触控快，画面质量好的旗舰屏，还支持屏下指纹，确实了是我的菜?。 摄影上之前看了很多评价说一般，而我真实的体验确实很好。\n6400万像素的超清主摄加持下，拍摄画面清晰度很高。支持OIS+EIS双防抖，拍照拍视频都很稳。内置7套经典胶片??，我喜欢高纯净度的那款，入手的朋友们可以用它拍摄，成像非常唯美好看。 \n续航上5500mAh大电池?续航相当给力，我上下班的时候一般都是2天一充。67W快充充电也很快??，支持30W无', '晴雪', '2023-02-19 19:18:50', 5);
INSERT INTO `data` VALUES (10279, 'j***n', 5, '包装:这次的手机盒子非常规整，一点磕碰都没有\n外观颜值：非常漂亮 材质手感：非常好 容量空间：空间很大 做工细。还是磨砂手感的很舒服\n运行速度：性能没话说，游戏效果也很好，很喜欢的最新系统\n喜欢的友友们可以直接冲，性价比不错的一款手机', '幽芒', '2023-03-06 19:33:15', 3);
INSERT INTO `data` VALUES (10280, 'A***c', 5, '外形外观：可以\n屏幕音效：超级流畅，超级丝滑，比1.5k的好多了。尊重这块两千元手机里最贵的屏幕谢谢。\n拍照效果：一般性。\n运行速度：超级流畅，我觉得是比原来的k30p强太多。不愧是新处理器。就是牛。太好了，一定要买。', '晴雪', '2023-03-08 22:17:27', 2);
INSERT INTO `data` VALUES (10281, 'l***r', 5, '红米K60真不错屏幕清晰，很通透，观感很不错，外观也好看，重量控制的也很棒，处理器够快，价格实惠，配置非常给力，miui系统也非常好用，我很喜欢，京东快递配送非常快', '墨羽', '2023-03-08 10:47:11', 3);
INSERT INTO `data` VALUES (10282, 'j***9', 5, '昨天下单，今天到，物流还是给力的！\n外形还不错，喜欢白色！配置和性价比也都很好！\n电池、续航和体验，因为刚到还没有使用，等再用一段时间，看看细节和体验如何！', '晴雪', '2023-01-01 12:58:56', 4);
INSERT INTO `data` VALUES (10283, 'l***k', 5, '外形外观：边框很窄  很满意  \n屏幕音效：开杜比全景声音效不错  有环绕声效果\n拍照效果：很不错  超过我的预期\n运行速度：流畅  120hz刷新率  飞一般的感觉\n待机时间：不算太长  日常使用一天一冲', '晴雪', '2023-01-10 14:11:31', 5);
INSERT INTO `data` VALUES (10284, '赵***州', 5, '外形外观：大屏幕，适合男生\n屏幕音效：2k屏幕，120hz，上下双喇叭\n拍照效果：效果不错，照片后期功能也多\n运行速度：流畅\n待机时间：大电池，还凑合\n其他特色：无线充电，特斯拉无线充终于用上了。\n\n特意用了几天后评价，MIUI14系统很好用。但也很新，部分软件兼容性有点问题，需要后续APP升级。', '墨羽', '2023-01-06 11:31:05', 2);
INSERT INTO `data` VALUES (10285, 'h***3', 5, '外形外观：红米k60的外观很大气，外观很好看，黑色显得比较稳重，我觉得挺好看。\n\n屏幕音效：屏幕分辨率挺高的，看着很清晰，120hz刷新率很丝滑很顺畅，没有迟滞感。 \n运行速度：运行速度很快，多程序运行丝毫不会卡顿，使用感觉良好！\n总之一句话，性价比没的说！', '墨羽', '2023-01-26 21:13:33', 6);
INSERT INTO `data` VALUES (10286, '我***的', 5, '非常好的手机外观非常好看，充电的速度，也是非常的快。 能一天待机，屏幕显示非常的清晰，推荐给大家购买。拍照也很好响应速度也非常的快，\n屏幕音效：非常的具有立体感\n运行速度：非常快\n拍照效果：很清晰', '素皮晴蓝', '2023-03-03 20:19:04', 6);
INSERT INTO `data` VALUES (10287, '城***天', 5, '外形外观：轻薄，握感很舒适，不硌手。\n屏幕音效：屏幕效果确实不错，显示清晰，边框很窄。\n运行速度：很流畅\n待机时间：还没实验', '素皮晴蓝', '2023-01-16 18:24:50', 2);
INSERT INTO `data` VALUES (10288, '彬***e', 5, '使用起来非常流畅，快递速度也很快，符合我的预期，很大方，屏幕音效：非常流畅，拍照效果OK，没打算当主力，待机时间：电池非常耐用，67w充电很快很快了', '墨羽', '2023-02-21 22:40:17', 6);
INSERT INTO `data` VALUES (10289, 'j***0', 5, '无线充和NFC都是实用的功能，还有高刷和高清的屏幕 观感也好很多，最开始担心中间孔很丑，但是开启暗黑模式之后几乎感觉不到，搭配一个充电底座，很方便。\n拍照很接近于真实的色彩，速度也不错\n相对于之前坚持用的k20pro，有很大的改观，对中间摄像头也不太抵触了。', '墨羽', '2023-02-15 16:37:12', 6);
INSERT INTO `data` VALUES (10290, '寻***w', 4, '外形外观：中规中矩\n屏幕音效：屏幕画面挺细腻，看着和13p差不多，\n拍照效果：可以\n运行速度：这配置性价比很高了\n待机时间：用了三天，作为副机，掉了40的电。充电也很快，比苹果快多了。', '晴雪', '2023-01-04 14:02:59', 5);
INSERT INTO `data` VALUES (10291, '裴***2', 5, '其他特色：小米手机忠实用户，这个价位能买到的唯一带无线充电的手机，这下能随时在车上充电了。\n外形外观：大气上档次，够时尚。\n屏幕音效：2k屏幕看起来非常不错。\n拍照效果：能满足日常生活需求。\n运行速度：新手机用起来还是很快的。', '墨羽', '2023-01-01 18:46:28', 3);
INSERT INTO `data` VALUES (10292, '落***露', 5, 'redmi k60 刚发布就预定了，性价比挺高。处理器内存都足够用，屏幕成色挺好，预装了 MIUI14，系统非常流畅。', '墨羽', '2023-01-02 16:00:49', 4);
INSERT INTO `data` VALUES (10293, '丹***3', 5, '华为Mate20换红米k60\n满满的都是惊喜，屏幕超乎想象的好，选了很久，其他手机都好贵，想着2000多块钱买个手机试试，结果超乎我的想象，比华为Mate20，强太多太多了。我手机拍不出效果，还是甄姬比较惊艳。', '幽芒', '2023-01-01 18:20:24', 4);
INSERT INTO `data` VALUES (10294, '静***天', 5, '不错，大品牌，质量好，做工也好，外观时尚，小巧，价格便宜，商品是京东自营的，售有很好的保障，发货快，送货也非常快，配送员准时热情配送值得赞。', '晴雪', '2023-01-04 10:39:59', 9);
INSERT INTO `data` VALUES (10295, 'j***T', 3, '手机是不错的\n外形外观：挺好看的', '晴雪', '2023-02-23 11:43:48', 2);
INSERT INTO `data` VALUES (10296, 'j***y', 5, '颜值挺好，打游戏流畅，不卡顿，快递非常快，头一天下单，第二天直接从德州发过来，直接到这个价位还支持无线充电，非常nice。\n外形外观：颜值完美。\n运行速度：非常流畅。', '幽芒', '2023-01-02 08:10:38', 3);
INSERT INTO `data` VALUES (10297, 'j***b', 4, '外形外观：个人没什么要求，但小米做的确实也不错，黑色看起来不花哨，很成熟，沉稳，\n屏幕音效：屏幕基本没什么可挑剔的，国产两K，足够用了\n拍照效果：基本够用，亮点是夜拍，效果非常好\n运行速度：运行速度非常快，用起来非常的丝滑，基本是使不完的劲\n待机时间：差不多一天半吧，电池大了就是不一样，很持久\n其他特色：无线充电真的很方便', '墨羽', '2023-01-12 17:16:39', 6);
INSERT INTO `data` VALUES (10298, '1***章', 5, '整体外观分量很足，从红米k20开始，机身重量都比较重。\n12+512的内存运行十分流畅，屏幕刷新感觉非常黏手，体验很好，具体性能再运行大应用的时候再看', '幽芒', '2023-02-18 12:31:12', 4);
INSERT INTO `data` VALUES (10299, 'J***7', 5, '外形外观：不错哦～白色版本，纯净背板，温润手感，摄像头模组看起来也很和谐\n屏幕音效：屏幕不错滴，高刷加2K分辨率以及超高色深色域，国产高端屏，音效双扬声器立体声场，很不错\n拍照效果：拍的快对焦快，素质一般，国产豪威CMOS传感器，过得去的素质，成本换到其他地方去了，这组摄像头模组够用够用\n运行速度：还挺快，几年那是没什么问题\n待机时间：5500毫安大电池，还有67W快充，还有中端手机里面罕见的30W无线充电，哇，中端机终于有无线充了，父母换机首选\n其他特色：无线充电！！！！！！30瓦功率！！！', '晴雪', '2023-01-25 23:57:30', 5);
INSERT INTO `data` VALUES (10300, 'j***3', 5, '包装很好，用起来很方便，运行速度很快，手机颜色很好看，很大气，拿起来很有质感，拍照效果很好，买的512g的，屏幕大，玩游戏超级棒，希望能多用一段时间！', '幽芒', '2023-02-16 16:52:29', 6);
INSERT INTO `data` VALUES (10301, '岁***3', 5, '外形外观：外观轻薄，拿在手上很舒服\n屏幕音效：屏幕2k分辨率，护眼。高清\n拍照效果：有光学防抖，拍照非常清晰\n运行速度：速度快骁龙8+玩游戏一点都不卡', '晴雪', '2023-03-19 12:16:27', 5);
INSERT INTO `data` VALUES (10302, 'L***論', 5, '外形外观：硬朗，时尚，超窄边框，超高屏占比。\n屏幕音效：屏幕超清晰，可高亮模式，声音大，很适合老年机。\n拍照效果：拍照能力极佳，自带美颜，功能适用。\n运行速度：运行稳定，无卡顿，但是应用内的广告多的可怕，推荐应用过多，导致会有流量浪费。\n待机时间：充电半小时，打游戏8小时！顶的很！\n其他特色：本身自带屏膜，自带透明保护套，充电器一套，卡针等&hellip;', '墨羽', '2023-02-13 22:19:36', 5);
INSERT INTO `data` VALUES (10303, 'j***B', 5, '外形外观：外观比较时尚，拿起来质感也很不错！\n屏幕音效：屏幕细腻，颜色纯正，分辨率也很高，音质不错，有独立杜比音效！\n拍照效果：拍照效果也很强，很清晰！\n运行速度：运行速度很快，没有杀后台的现象！\n待机时间：玩了一整天还有20%电量，待机效果不错。', '墨羽', '2023-03-15 21:07:38', 4);
INSERT INTO `data` VALUES (10304, 'C***e', 5, '从来没买过国产中高端手机，以前最多也就买过两千五的，但性能各方面比以前出色很多，不得不说这价格这性能分分钟比水果乐色好十几倍！', '墨羽', '2023-02-02 20:18:34', 8);
INSERT INTO `data` VALUES (10305, 'j***8', 5, '外观非常好看，非常满意，一直用小米，系统很人性化，旧手机两年了还在用，这次换个新手机，也可以直接体验MIUI14，相机非常强大，质感也很好，官方配的膜很贴心，67瓦快充实测不到一小时内充满，背后的新颖的三摄像头是非常漂亮是惊喜，总之很满意国画之光，支持小米。还标配30W无线快充非常棒！！', '晴雪', '2023-02-21 20:27:23', 3);
INSERT INTO `data` VALUES (10306, '顾***璃', 5, '手机非常不错，很好用，屏幕显示效果很惊艳，充电速度也很快，续航也很好，用一天也还剩很多电，音效也很好，通话音质很清晰，手机运行流畅不卡顿，好评', '晴雪', '2023-03-02 14:35:42', 3);
INSERT INTO `data` VALUES (10307, '叫***林', 5, '外形外观：外观好看，时尚，直屏也可以这么好看\n屏幕音效：屏幕分辨率很高，清晰细腻。4k的分辨率＋杜比视觉\n拍照效果：拍照效果也还可以，日常使用完全足够\n运行速度：速度贼快，骁龙8+处理器\n待机时间：充电快，待机时间长\n性价比十分高的一款手机，值得买。我买的8+256版本的', '墨羽', '2023-01-27 12:28:23', 5);
INSERT INTO `data` VALUES (10308, 'j***w', 5, '产品包装精致美观大气，目前用着非常不错，屏幕很大！而且手机信号很好。声音都大！家人们很喜欢！！！！真实评价，小米真的很好！还是得值得的！！！！\n拍照效果：很棒\n屏幕音效：大声洪亮\n外形外观：高科技全面屏', '素皮晴蓝', '2023-01-01 12:32:20', 5);
INSERT INTO `data` VALUES (10309, '大***刘', 5, '看完发布会果断下单，拍了白色，拿到后没让我失望，白色果然很好看。miui14很流畅，屏幕通透，高频调光很护眼，这块顶级国产屏真不是吹的！有骁龙8+的加持，玩游戏开最高画质很流畅，发热也不大。还支持无线充电，搭配49元无线充电器爽歪歪。', '晴雪', '2023-01-09 17:33:55', 5);
INSERT INTO `data` VALUES (10310, '萨***翼', 2, '特别特别棒，货比三家才买的，店主人很好，回答问题很有耐心，也很详细，有需要还会再来的宝贝收到咯??，真的很棒呀！?质量真是没话说，非常满意！?开心开心?包装非常好，很严实，值这个价格特别满意，好评必须好评宝贝收到，一如既往的好，包装很到位，质量还不错，很喜欢，大品牌值得信赖非常满意?，材质做工非常好，而且百搭，手感也很棒，非常nice，实用性非常强，赞?商品质量不错，细节、品质、做工都非常好，发货贼快，快递也给力，棒棒哒~???发货速度很快，东西包装的很好，价格优惠，我很满意?，还会回购发货速度很快，东西包装的很好，价格优惠，我很满意?，还会回购品质很不错?，性价比比较高的的商品?，喜欢的亲可以直接下手不要犹豫哦?当时买的时候还在犹豫价格，买来之后一点都不后悔，而且物流还快，可以入手', '墨羽', '2023-01-03 23:02:12', 9);
INSERT INTO `data` VALUES (10311, '西***狼', 5, '待电续航：续航能力超级不错，红米有很大进步哦。\n外观手感：感觉厚薄适中刚刚好，直屏也特别喜欢，大众白低调奢华有内涵。\n通用体验：我是华为粉转红米粉，操作系统没有违和感，一点不陌生，需要换机的可以考虑。\n配送服务：大爱京东自营，喀什地区3天就到了。\n服务保障：大爱京东，京东加油！！！！！', '晴雪', '2023-03-16 17:45:31', 2);
INSERT INTO `data` VALUES (10312, 'c***8', 5, '送儿子的新年礼物，他很喜欢，虽然，，，他是用来打游戏，但是反应是真的快，一点不卡机，外形好看，拿手上手感好，再不抢我手机用了?', '墨羽', '2023-02-02 22:23:01', 2);
INSERT INTO `data` VALUES (10313, 'j***d', 5, '外形外观：外观非常漂亮  妈妈跟喜欢\n屏幕音效：屏幕很高清 而且刷新率很高 很丝滑\n拍照效果：拍照效果棒棒的  非常清晰\n运行速度：运行速度杠杠的', '晴雪', '2023-01-21 12:45:33', 2);
INSERT INTO `data` VALUES (10314, 'Z***S', 5, '外形外观：漂亮大气，看起来很漂亮，拿在手里很舒服。\n屏幕音效：目前国产最好的2K屏幕，观感非常细腻舒服。\n拍照效果：6400W超清主摄，日常拍片觉得够用。\n运行速度：骁龙8+的Soc加最高规格的内存闪存组合，在加120的屏幕刷新率，比苹果14用快多了。\n待机时间：5500的大电池日常使用1-2天没有问题。\n其他特色：双扬声器、NFC、红外遥控，能给的都给了，良心手机厂商。', '晴雪', '2023-01-15 11:54:03', 5);
INSERT INTO `data` VALUES (10315, 'j***e', 5, '外形外观：宝贝收到后很满意，外形颜色也很喜欢，挑选好多家，果然没看错，希望把好物分享给大家??\n屏幕音效：屏幕真的不错，通透，明亮\n拍照效果：挺清晰的，夜景也不错\n运行速度：比我的老款手机快多了，12G大内存，真棒', '幽芒', '2023-03-04 19:33:04', 1);
INSERT INTO `data` VALUES (10316, 'z***7', 5, '一直信赖小米，小米也值得被信赖。上部手机是k20pro用了4年，现在除了电池不如从前，其他性能还是变化不大的。这次购买的k60。外观手感更好，流畅度极高，尤其是它的杜比特环声，做的特别好。值得推荐购买。这个价位机里面，首推k60。', '墨羽', '2023-03-06 11:05:12', 3);
INSERT INTO `data` VALUES (10317, 'j***H', 5, '这个红米k60目前用着非常不错，主要是这个屏幕太爽了，应该是我用过手机里面最好的屏幕了，很清晰，文字显示非常锐利，也很流畅。', '墨羽', '2023-01-27 19:02:45', 3);
INSERT INTO `data` VALUES (10318, '耶***李', 5, '心想事成，万事如意，在这辞旧迎新的日子，我拿着红米K60给大家拜年啦，祝大家新年快乐??\n\n新年换新机，骁龙8+超高处理器，让手机不再卡顿，同等配置里面应该是价格最低，性价比最高??\n\n2k高光屏幕，亮度?，色彩，护眼全面优化，长时间看手机，不疲劳。\n\n6400万高清摄像头，拍照?更清晰，更省心。\n\n67w超快速充电器，5500mA存储大电量，长续航，陪伴你放胆去闯~', '墨羽', '2023-01-21 14:31:25', 6);
INSERT INTO `data` VALUES (10319, '喜***生', 1, '外形外观：黑色墨羽真的很好看\n屏幕音效：2k屏幕物超所值，谁用谁知道，超清晰\n拍照效果：拍照还行，一般般\n运行速度：8+芯片杠杠的  开始还认为降频的不行  用起来和满血的无差别', '墨羽', '2023-02-26 15:24:02', 2);
INSERT INTO `data` VALUES (10320, 'j***d', 5, '运行速度：运行内存还是12G+3G的\n待机时间：待机一个晚上就少了3个电，\n其他特色：幽芒这个颜色非常漂亮，很喜欢\n拍照效果：防抖拍照很清晰\n屏幕音效：放歌的声音也很大，音质很好\n总体很满意的，是款性价比很高的手机', '幽芒', '2023-02-26 12:07:12', 5);
INSERT INTO `data` VALUES (10321, 'j***b', 5, '外形外观：白色特别好看 摸着也挺舒服的\n屏幕音效：2k屏幕 清晰\n运行速度：非常流畅\n待机时间：待机时间长 电池大', '晴雪', '2023-01-13 14:28:00', 5);
INSERT INTO `data` VALUES (10322, 'j***u', 5, '新骁龙8用着还是不错的，手感很好，很有质感，外观也很大气，5500ma大电池续航也不错，屏幕看着很清晰2k屏不错。', '晴雪', '2023-03-05 08:24:45', 3);
INSERT INTO `data` VALUES (10323, 'j***i', 5, '外形外观：简约大气，好看，磨砂摸着质感很不错\n\n待机时间：一天一冲基本可以，百分之十几的电，四十多分钟充满\n\n其他特色：整体不错，处理器满血版就更好了\n运行速度：整体流畅\n\n拍照效果：不是太看重，够用就行！', '幽芒', '2023-01-03 10:01:51', 4);
INSERT INTO `data` VALUES (10324, '3***e', 5, '手机真的特别好用，反应速度挺快，屏幕2k屏幕，显示很清晰，用起来很舒服，很给力，通话很清楚，电池容量很大，看视频很流畅，充电速度很快，摄像头拍照很清晰，很不错的一款性价比很高的好手机', '晴雪', '2023-01-30 09:53:43', 5);
INSERT INTO `data` VALUES (10325, '嗖***的', 5, '外形外观：科技感十足，还是喜欢直面屏\n运行速度：很快，暂时没有发现卡滞感\n拍照效果：很清晰，颜色很真\n待机时间：充满电，整整玩了一天，很强大，很好', '墨羽', '2023-01-04 08:58:15', 4);
INSERT INTO `data` VALUES (10326, '冰***冬', 5, '续航超长，我做4个小时火车，也不用担心手机没电了，\n充电宝基本也用不上了，\n手机很流畅，玩个王者荣耀一点不卡，\n颜值也很高，第一批买的，还送了京东年度会员，\n买东西信赖京东', '墨羽', '2023-02-19 11:06:43', 2);
INSERT INTO `data` VALUES (10327, '补***龟', 5, '外形外观：买了素皮和幽芒两种颜色的，都非常非常好看，素皮很适合男士，高级感慢慢的，买了送给父亲的，幽芒个人觉得非常漂亮，很适合女性，所以买来送给了姐姐\n屏幕音效：屏幕素质很好，立体双扬声器，还有认证，音效非常好\n拍照效果：拍照?也是非常好的\n运行速度：8G的运存，对于一般用户来说，已经够用了\n待机时间：新机待机时间还是非常长的，而且67瓦的充电器，充电速度非常快\n其他特色：出场自带MIUI14，嘎嘎好用，红米K60yyds', '素皮晴蓝', '2023-03-02 22:06:03', 5);
INSERT INTO `data` VALUES (10328, 'j***q', 5, '外形外观：简洁大方，后盖非常有质感。\n运行速度：飞快，而且不烫。\n屏幕音效：没的说。\n待机时间：待机时间长，配的充电器非常快。', '素皮晴蓝', '2023-03-17 22:05:10', 5);
INSERT INTO `data` VALUES (10329, '大***磊', 5, '性价比不错 挺喜欢的\n拍照效果：很好\n屏幕音效：很好\n外形外观：好\n运行速度：好\n待机时间：好', '墨羽', '2023-02-05 11:08:55', 6);
INSERT INTO `data` VALUES (10330, 'M***生', 5, '外形外观：设计大气时尚，尤其后盖儿更显得端庄。\n屏幕音效：必须支持国产屏。双效杜比认证立体声没得说。\n拍照效果：效果不输米12。追焦拍摄是一大亮点。\n运行速度：高性能处理器搭配12G内存。速度杠杠的。\n待机时间：大容量电池待机可以一整天搭配67瓦充电器，充电速度特别快，另外还具有无线充功能。', '幽芒', '2023-01-02 20:02:37', 5);
INSERT INTO `data` VALUES (10331, '-***-', 5, '外形外观：手机很好看很喜欢，颜色很高级\n屏幕音效：音效不错\n拍照效果：拍照效果也挺好的\n运行速度：运行速度很快，不卡顿，打游戏很流畅', '幽芒', '2023-01-18 16:59:58', 1);
INSERT INTO `data` VALUES (10332, 'j***v', 5, '外形外观：外观新颖时尚\n屏幕音效：屏幕反应迅速，流畅\n拍照效果：拍照效果非常棒，自拍效果好\n运行速度：运行速度快，高刷新率\n待机时间：电池容量大，满足整天玩\n其他特色：无线充电功能好，屏幕刷新率高', '素皮晴蓝', '2023-01-15 16:45:17', 4);
INSERT INTO `data` VALUES (10333, '戀***舊', 5, '外形外观：精致美观，边框很窄，大小合适。屏幕音效：颜色艳丽不伤眼，声音清晰柔和。拍照效果：很好。运行速度：很快，反应迅速，流畅。电池：耐用，用一天没问题，充电速度快。客服，很好，有问必答。', '素皮晴蓝', '2023-01-07 08:02:52', 3);
INSERT INTO `data` VALUES (10334, 'u***j', 5, '外形外观：素皮高级蓝色，有质感\n屏幕音效：清晰，顺畅\n拍照效果：拍照日常，人像真实清晰\n运行速度：流畅不卡顿\n其他特色：之前用的k20,相较于，k60更薄更轻，使用感更优质，且打包迁移功能太强大了，省心省事儿。', '素皮晴蓝', '2023-01-16 15:19:35', 4);
INSERT INTO `data` VALUES (10335, 'f***8', 5, '23点付款，第二天下午就收到了，京东物流给力。使用了2天才来评价，之前用的K30，可以负责任地说K60非常不错，这个价格买到了旗舰机的品质。外观很精致，使用起来很流畅，屏幕色彩细致鲜艳，长时间使用也没有发烫。充电速度特别快，而且还有无线充。总之相当满意，推荐购买。重点是缓解了我们存储焦虑。', '晴雪', '2023-01-20 12:54:20', 3);
INSERT INTO `data` VALUES (10336, 'x***g', 5, '手机拿到了，颜值很高，也很轻薄，握感舒适，黑色典雅，摄像不错，系统流畅，自带贴膜和手机壳，没有瑕疵，无线充好评。', '墨羽', '2023-01-09 18:00:34', 5);
INSERT INTO `data` VALUES (10337, '小***饱', 5, '包装的很好，冲着手机有无线充电去买的，手机有无线充电这个功能在这个价格很不错了，性能上够用了，价格还是可以接受，一直都是用的小米手机，感觉还是挺好用的，值得推荐，值得购买。', '素皮晴蓝', '2023-01-12 21:21:13', 4);
INSERT INTO `data` VALUES (10338, '迷***鸭', 5, '外形外观：中规中矩\n屏幕音效：显示效果不错，比较细腻，国产屏挺好的\n拍照效果：普通拍照没什么特别之处，总体上对得起价格\n运行速度：非常好，小米14系统不错，配上这个硬件很好\n待机时间：特别长，不是重度使用，两天一充\n其他特色：买的512大存储，再也不用删照片了', '幽芒', '2023-02-05 21:38:09', 4);
INSERT INTO `data` VALUES (10339, 'h***柒', 5, '外形外观：k60外观大气！特别喜欢非常战斗，黑色的大气无敌.\n屏幕音效：miu14系统搭载得这个音效，使用了几天，效果无敌，非常欣喜。\n拍照效果：这个拍照效果没的说，莱卡得摄像值得信赖不输小米13，k60真的超值，超出我的预期。\n运行速度：运行速度快的很，系统运行流畅的很，太棒了，这个手机用起来真的无敌，太满意了，', '墨羽', '2023-01-08 21:38:28', 5);
INSERT INTO `data` VALUES (10340, 'j***m', 5, '物流超快，手机拿手上很有质感，处理器棒棒哒，操作非常流畅，家里手机都是米，质量没说的，有需要再来', '晴雪', '2023-02-23 20:48:49', 4);
INSERT INTO `data` VALUES (10341, '小***七', 5, '手机收到了，家里用的都是小米手机，质量一直都很好，给妈妈买的，看了好几款，还是选择了K60，声音很大，电量也很大。Cpu也是比较好的。外壳还是皮质的。妈妈很喜欢。', '素皮晴蓝', '2023-01-31 21:35:11', 2);
INSERT INTO `data` VALUES (10342, '鸿***雁', 4, '手机一直都在京东买，因为服务好，售后好。之前的红米k30pro手机用了三年了，现在换了一个红米K60的，首先说他的拍照，像素什么的还是挺不错的。再说运行速度也还不错，毕竟是新机。外观的话也挺好看的。屏幕也很完美，音效挺好，是上下两个喇叭。玩游戏的话，运行也挺不错的。最后说这电量，感觉5G手机普遍都差不多。不是很耐用。', '素皮晴蓝', '2023-01-08 13:31:47', 2);
INSERT INTO `data` VALUES (10343, '史***凡', 4, '运行速度是绝对可以的！机器很快，很好的性能机，同价位的其他手机外形也许比他好，但是性能还是差的比较远！', '晴雪', '2023-03-06 15:01:40', 7);
INSERT INTO `data` VALUES (10344, 'j***5', 5, '现在买绝对是大冤种（我在说我自己），不过早买早享受，也无所谓了。手机还可以，我比较喜欢直屏，屏下指纹速度快，续航也好，还有无线充电，很满意。', '晴雪', '2023-01-17 08:19:53', 6);
INSERT INTO `data` VALUES (10345, '木***2', 5, '红米k60手机收到了，作为米粉，\n 1.手机颜色好看，大气，拿在手上手感好，使用起来，速度挺快，大电量不用天天充电挺好。照相效果也挺好，带广角的，有景深感。买的高配，性价比高，希望多用段时间。\n 2.其他特色：手机整体性价比较高； 拍照效果：很棒的，手机会自动根据不同环境会补光； 电池续航：快速充电，一般性充满电可用二天左右； 通信音质：很的，音质不错的； 运行速度：很快的，不卡顿； 显示效果不错', '晴雪', '2023-03-03 20:46:53', 4);
INSERT INTO `data` VALUES (10346, 'z***8', 5, '冲首发!很棒的手机，2K的屏幕显示很细腻,电池容量也大很有安全感，摄像头也有很大的提升，无线充电太方便了，随放随充，处理器超级超级快，无可挑剔,特意买的素皮后盖，手感很好。红米在性价比这块无人能敌!通信音质:音质很好,音质很好，声音清晰，听着很舒服显示效果:显示效果很好，色彩也很鲜艳其他特色:处理器不用多说，同档次没有对手。', '晴雪', '2023-01-09 08:43:48', 5);
INSERT INTO `data` VALUES (10347, '师***呀', 5, '手机第二天收到并立即使用，感觉良好，外观时尚大气，屏幕很清晰，边框很窄，系统运行流畅，120赫兹高刷特效全开，玩王者荣耀灵敏感十足，骁龙8十的加持，效果\n没得说，音效双扬声器效果不错，电池续航能力也很\n长，客服服务态度非常好，热情，大\n方，专业！给她点赞，物有所值，大品牌值得信赖。\n喜欢的小伙伴们可以放心购买！！！！!', '幽芒', '2023-03-13 09:00:26', 5);
INSERT INTO `data` VALUES (10348, '扛***哥', 5, '外形外观：白色的真的好看\n屏幕音效：激活看了下非常好，比较丝滑。拍照效果不错。值得这个价格。\n运行速度：运行速度快12+512就是给力，多300没有白花值得。', '晴雪', '2023-01-02 09:38:35', 2);
INSERT INTO `data` VALUES (10349, 'B***神', 5, '使用一天，很流畅，照相，音乐，游戏基本没问题，外观来看皮质后盖摸着手感还不错，用惯了玻璃后盖后软包裹还是很惊喜意外的，总体很赞。然后最后特别点一句，甄姬这个客服小姐姐很赞，哈哈哈', '幽芒', '2023-02-03 19:39:46', 5);
INSERT INTO `data` VALUES (10350, 'j***2', 5, '手机很好用，反应速度很快，2k屏幕，很清晰，一点也不卡顿，大容量电池很耐用，质量真的很好，下次一定还来购买', '晴雪', '2023-01-30 09:34:08', 6);
INSERT INTO `data` VALUES (10351, 'C***n', 5, '外形外观：以前用曲面屏现在换回直屏感觉还不错。边框很窄，后面蓝色素皮的材质也很喜欢。\n屏幕音效：国产好屏看着很舒服，双扬声音能听。\n拍照效果：扫码和一般扫街的程度，毕竟不是旗舰机所以无所谓\n运行速度：很快，MIUI配高刷屏感觉很好很流畅，没遇到掉帧的情况。\n待机时间：因为有了无线充电所以平常往那一放就不用管。开着高刷高分辨率正常用一天应该没问题。', '素皮晴蓝', '2023-01-06 15:53:27', 5);
INSERT INTO `data` VALUES (10352, '月***若', 5, '机收到了，屏幕真的很大，手感也不错。硬件上，用起来效果还不错，如果你不是游戏重度玩家，一般来说是够用了，玩玩王者、吃鸡还是可以的，手机电池容量很大，看视频不用担心没电，物流也很给力隔天就打了！', '墨羽', '2023-01-26 17:44:01', 1);
INSERT INTO `data` VALUES (10353, 'S***7', 5, '外形外观：外形外观：手机买给爸爸用的，他很喜欢素皮晴蓝这个颜色，这款手感也很好，感觉很有质感。 \n运行速度：很流畅，运行速度快\n拍照效果：很清晰\n屏幕音效：2k屏使用感还是不错的\n待机时间：充电很快，充满一次电可以用很久', '素皮晴蓝', '2023-01-17 15:03:23', 4);
INSERT INTO `data` VALUES (10354, '方***团', 5, 'K60外观设计漂亮，玻璃后盖，骁龙8+芯片运行速度快，2K屏幕显示不是吹的，声音也非常棒，6400w像素拍照效果非常好，试用了一下，玩游戏看视频非常流畅，总之这手机各方面都还不错，感谢京东自营平台打造的购物体验，物超所值。', '墨羽', '2023-03-11 22:21:24', 5);
INSERT INTO `data` VALUES (10355, 'N***a', 5, '等等了好久好久好久好久的k60直接首发下单的，正好给新年换了新手机，这次红米真的是满满的诚意，永远的性价比之王，用新手机很开心，很好用，MIUI14系统很流畅，快充充电也很快，续航很棒，总之买就对了~', '晴雪', '2023-01-05 12:18:41', 7);
INSERT INTO `data` VALUES (10356, 'j***8', 5, '机外观蛮不错的，玻璃后盖，白色款感觉很高档；2 K屏幕很清晰；MIUI14真的很轻快很丝滑；拍照也很清晰，对我来说够用；杜比音效很赞。K60性价比绝对高，很多基础配置和Pro一样，我不怎么玩游戏，骁龙8+芯片已经很够用了！客服很耐心，有问必答，很赞！！', '晴雪', '2023-01-20 14:44:15', 4);
INSERT INTO `data` VALUES (10357, '沙***泣', 5, '外形外观：大气上档次，外观时尚，手感不错！！\n屏幕音效：显示完美，细腻！！色泽显示逼真！！！\n拍照效果：摄像真好看！效果很好，各种实用功能非常好！！\n运行速度：处理器运行速度快，跑分不错哟哟哟！！有惊喜！！\n待机时间：一天一充，电池不错，待机可以！！\n其他特色：无线充电很爽！！！！', '墨羽', '2023-02-04 12:44:37', 3);
INSERT INTO `data` VALUES (10358, 'H***g', 5, '红米K60手机搭载了性能强悍的骁龙8+ Gen1旗舰芯片，日常使用、玩游戏都非常流畅。6.67英寸2K分辨率的居中挖孔直屏，比许多价格更贵的旗舰机型的分辨率都高，显示效果不仅非常清晰，而且120Hz刷新率，每一次滑动屏幕，都非常丝滑。5500mAh电池，续航非常强劲。', '墨羽', '2023-03-07 20:36:33', 1);
INSERT INTO `data` VALUES (10359, 'g***u', 5, '外形外观：舒适，养眼。\n屏幕音效：全面屏，声音效果杠杠滴，满意。\n拍照效果：高像素，拍照清晰。\n运行速度：8G运行内存，骁龙8+处理器，很流畅。\n其他特色：京东快递神速，当日达，满意。\n\n其他待使用一段时间后追评。', '素皮晴蓝', '2023-01-22 13:31:18', 4);
INSERT INTO `data` VALUES (10360, '修***战', 5, '手机外观设计很好看，性能配置也是满意，运行速度非常快，屏幕效果清晰不刺眼，拍照效果也是很满意的，价格实惠，物美价廉，质量好，物流快！', '素皮晴蓝', '2023-03-15 18:43:10', 6);
INSERT INTO `data` VALUES (10361, 'j***D', 5, '屏幕相当清晰2k屏是真的爽，比1.5k爽多了，12bit，色彩更丰富，尤其是晴雪配色好看到爆。平时不太爱玩游戏，游戏没测试，不过无线充电器还没到，没法检测无线充电功能，总之性价比很高，快递很快，12分推荐。', '晴雪', '2023-01-03 20:03:36', 5);
INSERT INTO `data` VALUES (10362, 'x***9', 4, '一直用小米系列手机，了解了下配置，非常有诚意。看了很多评价也都反应这款手机各方面性能都比较强悍。虽然是红米系列，但是论配置不输其他品牌的旗舰机，小米系统优化得应该也不会差了，果断入手。38节买给妈妈做礼物，老人用配置要求不是很高，但是看到新的处理器还是忍不住心动，老人用骁龙8+处理器12+256的配置很长时间内不会遭遇性能瓶颈了吧！到手后第一眼就很惊艳，屏幕细腻操作流畅白色机身清新脱俗拍照清晰音质悦耳充电很快，各方面都没有让我失望。', '晴雪', '2023-03-12 22:27:47', 6);
INSERT INTO `data` VALUES (10363, 'z***g', 5, '外观好看，运行速度嘎嘎快，很顺，很流畅。在峡谷里大战了几百回，没延迟，也告诉了我一个现实，输赢真不是手机的问题。系统如果可以一直这么流畅不臃肿，那真的很棒，五星好评。', '墨羽', '2023-01-03 09:18:49', 5);
INSERT INTO `data` VALUES (10364, '爱***马', 5, '炒鸡喜欢，炒鸡好看，早下手早享受\n外形外观：帅气\n屏幕音效：清晰\n拍照效果：细腻\n运行速度：快如闪电\n待机时间：超&rdquo;长啊', '素皮晴蓝', '2023-01-13 23:55:18', 4);
INSERT INTO `data` VALUES (10365, '思***里', 5, '外形外观：温润如玉\n屏幕音效：清晰\n运行速度：流畅\n选择K60就是看中它的性价比，第一次体验无线充感觉到出乎意料的好，方便，MIUI14系统很流畅，通话音质好，音频清晰无杂音，游戏没遇到断流，最关键的还是国产2K屏幕色彩亮度都俱佳。', '墨羽', '2022-12-31 22:14:24', 4);
INSERT INTO `data` VALUES (10366, '老***悠', 5, '外形外观：幽芒色颜色很好看，金属质感带渐变色。\n屏幕音效：触摸灵敏，刷新率也够高。不玩游戏，完全是够用的。\n运行速度：顺畅，12g内存也是足够的。\n\n作为给老妈用的手机，机器的性能和颜值都很合适，红米主要突出一个性价比高，用一段时间之后再来追评~', '幽芒', '2023-03-08 16:57:25', 5);
INSERT INTO `data` VALUES (10367, 'w***8', 5, '手机我一直选择在京东自营购买，收到货，第一时间拆包装，感觉质量还是很靠谱的，与卖家描述的还是一致的，非常满意，发货速度比较快，JD物流公司服务态度很好，运送速度很快，总的来说这次是很满意的一次购物。', '墨羽', '2023-02-25 17:14:07', 7);
INSERT INTO `data` VALUES (10368, 's***y', 5, '给老丈人购买的手机，内存大，处理速度快，屏幕也清晰，拍照老年人日常生活也够用了，总体感觉很不错，需要自己再买钢化膜贴上。', '墨羽', '2023-03-20 09:03:11', 2);
INSERT INTO `data` VALUES (10369, 'z***0', 5, '31号付款，隔天就从北京到了上海，送货很快，虽然是塑料边框，但这次有种金属质感，做工比想的好多了，屏幕也很清晰', '晴雪', '2023-01-01 21:50:43', 3);
INSERT INTO `data` VALUES (10370, 'j***b', 5, '刚刚收到，上午下单下午就收到了，配送非常给力，手机速度也挺好，手感不错，后续电池续航用用试试，再追评', '墨羽', '2023-02-13 18:59:35', 4);
INSERT INTO `data` VALUES (10371, '三***界', 5, '看发布会的时候就想买了，最近38.大促哦，果断入手！很不错，很流畅，无论游戏，看视频都够用了！真的是一款非常不错的产品！', '晴雪', '2023-03-11 17:01:33', 3);
INSERT INTO `data` VALUES (10372, '旐***彮', 5, '外观手感后壳磨砂手感，满满的塑料质感，绿色是变幻炫彩。上下双音响播放音乐时候比单音响的确实好太多（分辨不出来好在哪，也无法用语言描述）拍照比我原来的荣耀好。运存12g可以占用内存最大扩展到19g就很nice，待机时间没的说够用，充电大概30-40分钟从15%充满', '幽芒', '2023-03-07 09:11:19', 4);
INSERT INTO `data` VALUES (10373, 'g***f', 5, '绝对的哇塞，家里人从小米9到k40,k50,k60真的是铁铁的米粉了，感觉不错，推荐大家购买。屏幕质量很不错，反应速度快，价格也不错。', '素皮晴蓝', '2023-03-10 19:25:16', 6);
INSERT INTO `data` VALUES (10374, 'j***3', 5, '手机反应很快，也很好用， 很前卫  很时尚  屏幕清晰  不卡顿 很轻盈 拍照也很清晰 电池也挺抗用', '素皮晴蓝', '2023-01-13 18:24:26', 5);
INSERT INTO `data` VALUES (10375, 'j***w', 5, '外观：外观还行，可以接受 拍照效果：拍照效果很好 屏幕音效：屏幕比很清晰，看电影刷短视频都很nice 运行速度：运行速度快，不会发生卡顿 待机时间：待机时间长', '墨羽', '2023-01-15 21:40:48', 3);
INSERT INTO `data` VALUES (10376, '冰***水', 5, '直接说，推荐黑色，后面的效果真的是超级好看，我玩原神，这个很好用，出厂的MIUI14还是比较满意的，电池正常使用一天是够用的，双扬声器在放很清晰，我自己买了官网的硅胶保护壳手感直接拉满！想换机器预算2000多的，非常推荐这款屏下指纹识别也有了，心满意足，还有无线充电，还要啥自行车', '墨羽', '2023-01-06 19:31:01', 4);
INSERT INTO `data` VALUES (10377, 'y***2', 5, '用了一周左右，还挺不错的。\n外观大方简洁，平板，实用，官方配了屏幕保护膜和透明手机壳，很贴心。\n性能不错，很流畅，色彩艳丽，手机系统也很好，日常使用完全够。\n本人不打游戏，日常使用没问题，电池耐用。\n总体满意，暂时没有问题。', '晴雪', '2023-01-23 16:01:18', 3);
INSERT INTO `data` VALUES (10378, 'j***X', 1, '电池容量大，续航不错！价格合适，经济实惠，性价比很高！随机附带透明手机壳，67瓦充电器，充电速度快！运行速度也不错，刚买没几天降价一百块，还不给保价，这点差评！', '墨羽', '2023-03-03 18:13:50', 2);
INSERT INTO `data` VALUES (10379, 'J***杰', 5, '要不是k20p摔得稀烂，没打算换手机的，k60到手之后感觉很好，很流畅，充电快的一批。', '墨羽', '2023-01-01 16:43:11', 3);
INSERT INTO `data` VALUES (10380, 'x***9', 5, 'K60手机外观很漂亮，手感很棒，很顺滑，运行速度很快，屏幕很清晰，12+512G配置，续航时间长，拍照很清晰，整机的性价比很高，物超所值，京东配送速度非常快，到货包装完好无损，非常满意的一次购物！', '晴雪', '2023-02-19 16:14:51', 5);
INSERT INTO `data` VALUES (10381, 'w***1', 5, '外形外观：外观颜值：外观很好看\n\n屏幕音效：很灵敏\n\n拍照效果：很清晰\n运行速度：流畅\n\n其他特色：性价比比较高\n待机时间：比较长，新手机肯定长，之后不知道', '幽芒', '2023-01-03 18:56:40', 4);
INSERT INTO `data` VALUES (10382, '黄***o', 5, '红米K系列手机买的第三台！性价比之王，没有对手！\n颜色很斯文，好看。屏幕高清，后盖设计好看，手感好。最重要的是内存，Cpu都是顶级\n对比了市面上同级产品，没有对手', '晴雪', '2023-02-04 13:07:42', 5);
INSERT INTO `data` VALUES (10383, '曾***儿', 5, '小米k60手机美观大方，配置出众 尤其是屏幕，色彩艳丽亮度高，本人不怎么玩游戏，刚刚拿到手里，这么高的配置，想来应该很流畅！', '晴雪', '2023-03-10 09:12:21', 5);
INSERT INTO `data` VALUES (10384, '风***动', 5, '外形外观：手机握起来很舒服，很喜欢，手感很舒\n\n屏幕音效：效果很不错\n拍照效果：拍照的感觉一般化吧，不是非常的出色\n运行速度：运行速度非常的流畅', '墨羽', '2023-03-01 21:16:15', 4);
INSERT INTO `data` VALUES (10385, '风***帝', 5, '外形外观：买的白色的，很漂亮，美观大方，喜欢\n屏幕音效：屏幕非常清晰，音质也比较好\n拍照效果：拍照效果也是比较满意的，日常使用完全足够了\n运行速度：性能比较好，用起来很流畅，比之前的手机好太多', '晴雪', '2023-02-22 10:20:25', 3);
INSERT INTO `data` VALUES (10386, 'j***q', 3, '买手机还是到线下买，价格一样。线下还有礼品，他家啥都不送。', '墨羽', '2023-03-01 22:41:08', 3);
INSERT INTO `data` VALUES (10387, '孔***叔', 5, '外形外观：惊艳四座\n屏幕音效：很给力很给力\n拍照效果：绝对高大上\n运行速度：相当快，很给力的速度\n待机时间：大电池大电量超长待机\n其他特色：很给力的CPU', '墨羽', '2023-02-19 19:24:31', 4);
INSERT INTO `data` VALUES (10388, 'l***然', 5, '外形外观：颜值真的很好，看着非常喜欢\n屏幕音效：屏幕看着舒服\n拍照效果：拍照效果也可以\n运行速度：运行速度是真的很顶，配置真的很好\n待机时间：最让人喜欢的就是续航了', '墨羽', '2023-01-16 12:37:59', 4);
INSERT INTO `data` VALUES (10389, '夏***啦', 5, '本来就计划换手机，结果刚好K60新机发布，仔细看了看觉得还不错，就果断下单。快递第二天就送到了，果然很不错，除了外观没有旗舰机酷之外，别的都很好，性价比高。手机运行速度快，开软件对比之前用的手机确实快很多。游戏还没有玩，但相信游戏表现应该也不错。', '墨羽', '2023-01-04 09:20:13', 5);
INSERT INTO `data` VALUES (10390, 'j***小', 5, '外形外观：酷\n屏幕音效：高清，声音很好\n拍照效果：很清晰\n运行速度：12+256很快\n待机时间：大电池待机长', '墨羽', '2023-01-14 13:45:12', 4);
INSERT INTO `data` VALUES (10391, '熹***汐', 5, '京东的忠实粉丝，但是电子产品是第一次买，精挑细选很久?，最后决定买这一款?，到货后果然没有让我失望，实物很漂亮?，做工很精细?，特别满意?点赞京东 点赞小米???', '墨羽', '2023-02-24 10:49:28', 4);
INSERT INTO `data` VALUES (10392, 'j***d', 5, '黑色手包装盒配金色K60标示，简单大气上档次。买的黑\n配色，干净纯洁，手机拿在手里握感舒服，屏幕清晰，色\n彩鲜艳，高刷新。高通骁龙8+搭配14系统版本简洁流畅，\n体验超爽，通话音质清晰，相机反应速度快，成像清晰度。\n高，色彩艳丽。配备的这块2k高刷直屏，显示效果出众，比曲面屏好多了。', '晴雪', '2023-01-19 22:36:02', 3);
INSERT INTO `data` VALUES (10393, 'j***f', 5, '外形外观：考虑很久曲面屏和直屏，最终还是选直屏。中规中矩，好保护，不容易碎，用着习惯。\n屏幕音效：音效太好了，感觉声音从很多方向传过来，连铃音都很好听。', '墨羽', '2023-02-01 06:59:59', 6);
INSERT INTO `data` VALUES (10394, 'd***9', 5, '物流很快，包装严实，刚收到，外观好看，简洁大方，运行速度快，很流畅，满意', '墨羽', '2023-03-08 13:04:06', 3);
INSERT INTO `data` VALUES (10395, 'j***2', 5, '外形外观：素皮晴蓝这颜色很高大上\n运行速度：骁龙8+处理器，非常好\n屏幕音效：2k屏幕，显示效果好\n拍照效果：6400超清拍照，够用\n待机时间：充电速度很快，超长待机', '素皮晴蓝', '2023-01-05 17:57:07', 3);
INSERT INTO `data` VALUES (10396, 'z***9', 5, '收到了，物流没得说，快，包装好，机器收到，外观好看，电池容量大，运行速度快，这次相机用着也不错！！同价位里配置最高，同配置里，价格最低！！总结，性价比很不错！！', '晴雪', '2023-01-18 14:59:16', 5);
INSERT INTO `data` VALUES (10397, '还***豫', 5, '外形外观：挺好看的\n屏幕音效：2K屏显示效果佳，声音也可以\n拍照效果：本人不在意拍照\n运行速度：非常快，不卡顿\n待机时间：续航还可以\n其他特色：总得还是不错的', '墨羽', '2023-01-02 22:53:23', 3);
INSERT INTO `data` VALUES (10398, '蒙***健', 5, '外观漂亮，拍照效果也很好，通话音质清\n晰,运行速度特别的快，2k屏显特别清晰明亮，触摸手感非常舒服，67瓦充电快，又不伤电池', '墨羽', '2023-01-28 18:19:25', 4);
INSERT INTO `data` VALUES (10399, '三***界', 5, '本来想不换手机的，可架不住喜欢就买了，到手就眼前一亮，非常不错的手机！无论颜值性能流畅度那都是相当不错的了！都是旗舰水准。太棒了！', '素皮晴蓝', '2023-03-11 12:26:08', 3);
INSERT INTO `data` VALUES (10400, '星***6', 5, '正好赶上3.8节的活动，之前就喜欢这款手机了，外形挺好看的，手机用着流畅，也不卡，感觉这个手机质感，音效，屏幕清晰度都挺好的，挺满意的购物，相信小米，性价比拉满了，很满意。', '晴雪', '2023-03-16 12:19:45', 5);
INSERT INTO `data` VALUES (10401, 'b***i', 5, '早上付尾款下午到货。京东速度很厉害，手机不错。mi8迁移3小时搞定。选了16+512 大内存爱好者，多用一年', '晴雪', '2022-12-31 22:31:05', 4);
INSERT INTO `data` VALUES (10402, 'm***3', 5, '全新正品，原封机。家里孩子和父母买的都是红米手机，从K30一直买到k60，用的一直都很好，不管是外观还是性能都很优秀。从旧机资料转到新机非常方便，自带透明软壳，出厂有贴膜，到手即用。屏幕大，显示效果好，拍照清晰，性价比高，充电速度快，支持无线充，机器也很漂亮。京东物流很快，上午下单，下午就收到了。', '晴雪', '2023-01-24 17:35:37', 5);
INSERT INTO `data` VALUES (10403, '刘***6', 5, '外形外观：很好\n屏幕音效：可以\n拍照效果：可以\n运行速度：快\n待机时间：挺长\n刚拿到手机，体验一下，还可以', '墨羽', '2023-01-01 11:33:32', 4);
INSERT INTO `data` VALUES (10404, 'j***g', 5, '京东物流很快包装也很好，非常满意\n手机外形好看，背板是磨砂玻璃手感真的很好很滑，个人觉得比光面玻璃好，而且还不粘指纹，裸机在不同角度的光线下还有不同色彩，很绚烂，但是装上壳就不太明显了，但还是很好看！\n内存很大，运行速度很可以，打游戏运行流畅，主要是电池很大！可以用好久，而且充电很快，各方面性价比确实高，非常满意啦', '幽芒', '2023-01-19 13:15:43', 4);
INSERT INTO `data` VALUES (10405, '皖***李', 5, '手机收到了，直边略有弧形的机背很贴合手掌，精致漂亮的外观很讨人喜爱，打开手机预装的软件也不多，除去必要的应用大部分软件都可以卸载，这样手机更显得简洁流畅，通透的屏幕画面显示非常清晰，上下双喇叭，自带环绕立体声，声音非常悦耳，拍照清晰，画面真实，真是一款值得入手的好手机。', '晴雪', '2023-01-06 22:02:47', 5);
INSERT INTO `data` VALUES (10406, '银***季', 5, '外形外观：满意，拿到实机才觉得做工比网上说的要好看多了推荐白色\n屏幕音效：没的说，顶级\n拍照效果：一般，有待加强\n运行速度：很快\n待机时间：5500毫安时，待机一天还有的多', '晴雪', '2023-03-03 16:40:18', 3);
INSERT INTO `data` VALUES (10407, '茗***博', 5, '外形外观：给小舅子，后壳颜色真的不错\n屏幕音效：双扬声器器，真的很不错，有立体音效\n拍照效果：拍照成像效果非常满意\n运行速度：12+512正常运行，玩游戏够用\n待机时间：用了10天左右吧，感觉挺好的，后续追评运行时间', '墨羽', '2023-03-18 21:15:09', 3);
INSERT INTO `data` VALUES (10408, 'f***0', 5, '手机挺漂亮的，骁龙8处理器用起来很流畅无任何卡顿，蓝色素皮手感很好，颜色很漂亮很时尚，拍照也很清晰，这个价位这个配置的手机很喜欢，性价比极高', '素皮晴蓝', '2023-01-06 15:33:46', 2);
INSERT INTO `data` VALUES (10409, '终***e', 5, '手机的颜值在线，性能在线，使用的流畅度也是相当不错，8+Gen1的处理器完全没问题，MIUI14系统也是加分项', '晴雪', '2023-02-17 08:16:39', 2);
INSERT INTO `data` VALUES (10410, 'j***O', 5, '宝贝收到，打开一看，真的太漂亮了，功能强大，内存够大，运行速度很快，屏幕，音响效果都很好，拍照效果不错，5500大电池，估计待机时间一定让人满意。我孙女一定喜欢。宝贝包装很好，没有损坏。物流很快，快递员服务态度很好。', '素皮晴蓝', '2023-02-03 13:16:15', 5);
INSERT INTO `data` VALUES (10411, '绅***皮', 5, '外形外观：素皮青蓝确实很有质感，相比其他几个确实好看，手持手握感觉很舒服。\n屏幕音效：屏幕分辨率显示很棒，音效这块感觉还可以，就是这个斜对撑不知道设计师咋想的。\n拍照效果：能够满足日常生活，其他方面要求就算了\n运行速度：正常使用，完全满足要求。\n待机时间：用一段时间在说\n其他特色：整体性价比还是很高', '素皮晴蓝', '2023-03-05 18:37:17', 6);
INSERT INTO `data` VALUES (10412, 'M***M', 5, '外形外观：外观看着非常帅气的手机，手机握感很好，背面也很丝滑\n运行速度：开软件响应速度挺快的，游戏运行也比较稳定\n屏幕音效：屏幕分辨率高，刷新率也高看着很舒服', '墨羽', '2023-03-14 21:08:17', 4);
INSERT INTO `data` VALUES (10413, '过***活', 5, '首先点赞JD的物流速度，上午下单，下午就到货了，拿到新手机的那刻真的是有种久违的开心。\n体验了一下，打游戏运行完全无压力，体验杠杠的，屏幕素质也不错，红米这超高的性价比实实在在满足了我们这些刚步入社会年轻人的用机需求。', '墨羽', '2023-03-13 18:03:48', 2);
INSERT INTO `data` VALUES (10414, '只***P', 5, '外形外观：蓝色的素皮外观 很大气\n\n屏幕音效：2K屏幕清晰 音效可以\n运行速度：骁龙8+处理器 运行速度超快\n\n\n待机时间：5500毫安大容量电池 续航时间久\n\n其他特色：屏下指纹设计比侧面指纹好 方便 总体性价比比较高', '素皮晴蓝', '2023-01-03 10:34:07', 3);
INSERT INTO `data` VALUES (10415, '相***下', 5, '手机特别好用，反应速度快，外观时尚，经典，直面屏\n屏幕2k屏幕，清晰，明亮。拍照效果不错，很清楚，性价比高。运行速度非常快，一点也不卡顿，待机时间很长，用起来舒服，很给力，', '晴雪', '2023-01-15 22:17:26', 4);
INSERT INTO `data` VALUES (10416, '陶***-', 5, '外形外观：白色很好看\n屏幕音效：2k高刷很清楚\n待机时间：给我妈买的，等她再用几天', '晴雪', '2023-01-15 17:15:46', 3);
INSERT INTO `data` VALUES (10417, 'L***s', 5, '拍照效果：清晰\n续航能力：很好\n运行速度：畅快\n很棒到手质感很不错，这个颜色还带闪，摄像头比想象中的好看，特意买的大一点的内存，希望可以多用两年，很好很好很好看！！!', '墨羽', '2023-02-22 22:49:48', 4);
INSERT INTO `data` VALUES (10418, 'j***j', 5, '物流一如既往的快，包装也很严实，套了一层气泡袋。\n外形外观：黑色沉稳大气\n待机时间：半个小时从40%充到了94%，充电速度很快，67W很给力。中度使用，刷刷视频，看看小说，不打游戏用一天没问题\n个人第三部小米手机了，小米加油。', '墨羽', '2023-01-01 12:59:30', 4);
INSERT INTO `data` VALUES (10419, '再***见', 5, '外形外观：外观非常好看，晴雪的白色简直太美了\n屏幕音效：双扬声器，杜比音效，身临其境的感觉\n拍照效果：拍照效果也出奇的好，质感满满的\n运行速度：超级超级快，起飞?\n待机时间：5500毫安大电池，丝毫不虚，能用一整天不充电\n其他特色：套餐中+49元送的30W无线快充，简直太方便了，随手一放就能冲', '晴雪', '2023-01-09 23:09:09', 3);
INSERT INTO `data` VALUES (10420, '张***l', 5, '外形外观：外观设计很新颖，很漂亮，使用起来很方便，很喜欢\n屏幕音效：屏幕2k清晰度很好，外观也很漂亮，屏幕很清晰\n拍照效果：拍照嘎嘎快\n运行速度：运行流畅好用，外观漂亮，运行流畅，运行速度快\n待机时间：日常使用一天没问题，质量很好', '素皮晴蓝', '2023-01-12 16:35:26', 3);
INSERT INTO `data` VALUES (10421, 'j***q', 5, '外形外观：外观特别好看，手感很好，很舒服，颜值特别高。\n屏幕音效：屏幕细腻程度很好，音效很棒。\n拍照效果：拍照还不错，很清晰\n运行速度：运行速度很快。\n待机时间：时间很长，一整天没压力。', '晴雪', '2023-03-11 22:32:05', 4);
INSERT INTO `data` VALUES (10422, 'j***6', 5, '外观漂亮\n外形外观：漂亮\n屏幕音效：完美\n拍照效果：超出预期，质量很好，做工精细，满意\n运行速度：好产品、好品质、好服务，宝贝确实值这个价钱，在这给商家点个赞?\n待机时间：还行\n其他特色：第一次用小米手机，就是为了微信双开！非常满意！', '晴雪', '2023-01-01 23:17:30', 4);
INSERT INTO `data` VALUES (10423, '時***費', 5, '外形外观：颜值可以，很漂亮\n屏幕音效：2k屏幕，显示效果杠杠滴\n拍照效果：6400超清拍照，ois防抖，可以\n运行速度：骁龙8＋处理器，运行绝对可以\n待机时间：刚充好电，在用\n其他特色：个人感觉很喜欢', '晴雪', '2023-01-01 17:59:35', 3);
INSERT INTO `data` VALUES (10424, 'w***4', 5, '外形外观：大气时尚，手感不错\n屏幕音效：很好，高音低音质感好，中音有待加强\n拍照效果：一直用的小米手机，拍视频拍照都好\n运行速度：很强，新机就是牛\n买了好多小米手机都不错。k60pro应该更强。买过k40s，k50，k50pro都不错。大内存很够。性价比高。', '墨羽', '2023-01-05 20:51:23', 4);
INSERT INTO `data` VALUES (10425, '小***哥', 1, '外形外观：漂亮大气，颜色很正，做工精细\n屏幕音效：手感很好，很丝滑\n拍照效果：很清晰\n运行速度：卡卡快\n我是小米忠实粉丝，从小米一代用到了现在，上一个手机是K20pro,用了三年，要不是电池不行了，屏幕碎了我都不舍的换，现在也不卡，mix下拉屏那款我也很喜欢，不小心从五楼坠落，摔坏了主板，就是维修费太高。现在结婚了只能选性价比更高的了，确实好用。', '墨羽', '2023-03-07 13:40:16', 3);
INSERT INTO `data` VALUES (10426, '九***r', 5, '小米的手机依然更棒，蓝色的皮质外壳手感很不错，在这个价位全挺好的了\nMIUI系统更好用了，小部件很有意思\n12+3g的运存，很流畅\n总得来说，这个价位拿到12+512确实很值\n拍照也基本能满足日常需求，而且还有光学防抖\n2k屏加高刷，也很完美', '素皮晴蓝', '2023-03-10 11:11:41', 4);
INSERT INTO `data` VALUES (10427, '无***3', 5, '完美的手机屏幕，超级无敌快的充电，极速的操作系统，我爱红米，一级的芯片，真的是太棒了，红米这一代做的太完美了，还有好好听的声音喇叭啊&hellip;&hellip;推理你那买红米，打游戏一级棒！爱了爱了，真好，红米一切顶呱呱！红米诚意推荐！\n外形外观：好看\n屏幕音效：一流\n拍照效果：超棒\n运行速度：超快\n待机时间：超长', '墨羽', '2023-01-31 10:09:09', 4);
INSERT INTO `data` VALUES (10428, 'f***e', 5, '嗯！是的！又再一次的选择了小米！父母都是用的小米系列手机，前前后后已经快二十部了吧！\n这次选择了k60，512的存储，不用担心内存不够用。\n用了几天感觉很顺手，运行流畅，相机拍摄功能绝对满足日常需求！\n下次换手机还是会选择小米?！', '幽芒', '2023-02-23 22:24:05', 3);
INSERT INTO `data` VALUES (10429, '丑***猫', 5, '外形外观：外观漂亮大气，很显档次\n屏幕音效：简直太清晰了，\n\n拍照效果：清晰度高，颜色正，不失真\n\n运行速度：杠杠的\n\n待机时间：一天多没问题', '墨羽', '2023-02-17 10:30:09', 3);
INSERT INTO `data` VALUES (10430, '雨***吃', 2, '这代红米真的很给力，无论从性能上还是外观都很不错，后悔买mix买早了，pro也很不错，5500毫安大电池良心啊。如果是金属中框怕十三真的不抗揍了?总体来说，确实很不错，客服的服务态度也很棒，说话几乎马上就会回消息，物超所值，真心推荐', '墨羽', '2023-01-06 15:13:35', 2);
INSERT INTO `data` VALUES (10431, '东***7', 5, '外形外观：手感极佳 大小合适 刚好手握住\n屏幕音效：分辨率高 音质很好\n拍照效果：拍照清晰 夜景也不错\n运行速度：打游戏不卡 运行速度快\n待机时间：待机时间长 充电也可快', '晴雪', '2023-03-10 21:32:13', 3);
INSERT INTO `data` VALUES (10432, '尚***泰', 5, '拿到手了，外观设计感非常好，手感很好，有厚重感。开机很快，屏幕清晰，视觉效果不错，眼睛看着非常舒服。其它的功能逐步解封后再仔细体会。总之是真的非常非常满意。\n运行速度：很快。', '素皮晴蓝', '2023-01-10 12:23:06', 4);
INSERT INTO `data` VALUES (10433, '十***_', 5, '年前买了K60Pro，年后趁着优惠再次购买k60，性价比很高\n外形外观：颜值一如既往的好看\n屏幕音效：屏幕高清，长时间久看也不累\n运行速度：系统非常流程，打游戏持久稳定\n待机时间：充一次用一天不是问题\n其他特色：充电速度也非常快，充电也不发烫', '幽芒', '2023-03-17 20:26:00', 4);
INSERT INTO `data` VALUES (10434, '孟***o', 5, '用了半个多月，真的很丝滑，反应很快。外观质感一般，这个价格要什么自行车，戴个手机壳都一样。好评', '墨羽', '2023-01-19 18:41:22', 6);
INSERT INTO `data` VALUES (10435, 'j***l', 5, '很快就到了，全新正品?，包装很仔细，没有问题，机子试了一下，还是可以。，手感不错，电池正在试。也挺耐用的。', '幽芒', '2023-01-01 16:05:29', 2);
INSERT INTO `data` VALUES (10436, 'z***1', 5, '手机上午下单，下午就收到了。拿到手比较满意，是我需要的，性价比较高。花了一个多小时，把旧手机资料全部导入，很方便。不满意的地方，选择了以旧换新，结果旧手机拿去了没有下文了。', '幽芒', '2023-02-12 22:04:53', 5);
INSERT INTO `data` VALUES (10437, 'I***o', 5, '3千4小米12S，米粉旧机无缝切换，没有学习成本，原来的软件直接使用。性能好，拍照好，最主要的是，小屏，单手就能操作。值得拥有。京东快递员服务很好，送货上门，还等了10多分钟。', '黑色', '2022-11-16 16:35:27', 8);
INSERT INTO `data` VALUES (10438, '柳***7', 5, '外观比较小巧，适合女士使用。拍照效果很不错，不愧是莱卡的摄像头，尤其是几种模式切换，很贴切。屏幕效果也很好，很柔和，不刺眼。新机续航能力一天，不算太好。运行速度很快，完全没有卡顿现象。', '黑色', '2022-11-16 20:38:12', 8);
INSERT INTO `data` VALUES (10439, 'k***g', 5, '外形外观：简洁漂亮小巧\n屏幕音效：屏幕显示效果上乘，音效不错\n拍照效果：显示细腻，夜晚拍照清晰，分辨率高\n运行速度：比较快\n待机时间：一天一充\n其他特色：系统优化得很好，比较人性化', '黑色', '2022-09-08 18:17:18', 4);
INSERT INTO `data` VALUES (10440, 'j***x', 4, '一如既往的满意。  小米8使用了4年。 今天升级为小米12s。 反正也不打游戏。感觉还是不错的。 拍照说实话，一分钱一分货。 感觉都差不多。  不仔细看，拍照也看不出来莱卡相机拍的。  我只能说手机很流畅。充电也很快。充电没有仔细看。估计也就1小时', '黑色', '2022-08-30 08:52:07', 9);
INSERT INTO `data` VALUES (10441, '背***森', 5, '实物与描述相符，全新正品原盒未拆封未激活。这台是2022年10月产的机器，做工质量不错，手机背面是素皮材质，防滑效果不错，手机握持感很好，大小尺寸适合单手操控。赠品给的原厂皮质手机壳和80W无线充电座以及120W充电器。蔡司镜头和哈曼卡顿喇叭，配置很足，使用流畅。', '原野绿（素皮）', '2023-01-18 13:24:09', 9);
INSERT INTO `data` VALUES (10442, 'z***朵', 5, '外形外观：6.28英寸，180g拿在手里无敌握感，买的白色，后盖AG磨砂，防指纹，又丝滑yyds\n屏幕音效：屏幕音效：屏幕很通透，看着非常舒适，nice \n拍照效果：徕卡！！！全体起立！打开相机第一眼就惊艳了，绝对T0梯队\n运行速度：运行速度：8gen1+处理器，搭配256G储存，装软件也是秒装 ，安装时温度也是温和的，爽，不怕火龙了\n待机时间：刚拿到手，安装东西，目前使用20分钟才掉百分之2的电，很满意能效比！\n其他特色：小屏旗舰！唯一选择！爱了爱了！', '白色', '2022-07-07 10:13:23', 7);
INSERT INTO `data` VALUES (10443, 'j***3', 5, '从一加换回来的小米手机，这种小屏手机是真的没得顶，单手操作完全没有问题，主要是家里全部都是小米的家电，用回小米手机会方便很多，不过这前置摄像头是有点显眼，不如原来一加7pro看的顺眼，不过也非常好的，物流也非常不错！！', '白色', '2022-09-16 20:16:35', 5);
INSERT INTO `data` VALUES (10444, '大***w', 5, '刚入两天，目前比较顺手！麻雀虽小五脏俱全，两天用下来没什么问题。外观比较圆润加上手机不大，所以手感很好。拍照，屏幕都比较艳丽。电池续航再用几天追评。', '黑色', '2022-09-21 23:02:20', 9);
INSERT INTO `data` VALUES (10445, '云***t', 5, '自打小米明确定位了数字系列和红米系列的营销战略后，很久没买过小米数字系列的手机了。这次在我的劝说下，给老婆换上了小屏旗舰手机。确实宽度，手感优秀。素皮背壳非常的好看。骁龙8+也是非常的优秀。应该能满足很长一段时间的需求了。', '原野绿（素皮）', '2022-09-09 21:58:40', 5);
INSERT INTO `data` VALUES (10446, '我***徒', 5, '手持小米6来评价\n小米12S小屏旗舰，这个握感确实很nice.\n给我父亲买的，选择12+256，对于他而言，完全够用，运行速度够快，单手操作方便。\n67W秒冲+4500mAh续航一整天', '黑色', '2022-09-13 16:29:07', 4);
INSERT INTO `data` VALUES (10447, '自***l', 5, '这款手机外观小巧，拿在手上没有沉重感，非常适合女士使用，一手轻松把握，流畅度也很流畅，上网速度也不错', '紫色', '2022-11-06 08:47:49', 5);
INSERT INTO `data` VALUES (10448, '_***g', 5, '外形外观：很漂亮，手感一流\n拍照效果：刚刚的\n运行速度：很丝滑\n握持感很好，单手可操作\n其他特色：发热控制的很好。30度的天气。手机正常使用也就温温的，相比骁龙8的烫手简直好太多了。', '黑色', '2022-07-14 10:13:25', 2);
INSERT INTO `data` VALUES (10449, '乐***头', 5, '外形外观：外观买的是绿色皮质感特别好！瞬间感觉手里的iphone13不香了，全面屏的感觉很棒，触感很灵活，用了一天了，目前觉得没什么问题，很流畅，运行速度快，待机时间长！小米果然没有让我失望', '原野绿', '2022-07-07 20:56:51', 3);
INSERT INTO `data` VALUES (10450, 'j***r', 1, '真的非常棒，外放哈曼卡顿是我听过最好的外放?手感，观感，系统经过在网上学习之后无敌的好用赞????    必须要给京东小哥点赞，物流很快！?\n一开始买的OPPOfindx5感觉带电都不行退了，又买的小米12s', '黑色', '2022-08-02 21:04:00', 5);
INSERT INTO `data` VALUES (10451, 'j***x', 5, '外形外观：难得的小屏手机\n拍照效果：之前用的12pro，相比之下12s莱卡加持后，高光压制的更好了。可以随手拍，不糊\n运行速度：很流畅\n待机时间：续航很不错，一天半一充问题不大', '黑色', '2022-08-13 10:06:23', 6);
INSERT INTO `data` VALUES (10452, 'j***n', 4, '外形外观：尺寸绝对完美，手感超好，之前买过12，发热太恐怖卖了，这次看看发热怎么样&hellip;\n屏幕音效：屏幕素质不错，足够用了。\n拍照效果：拍照这次是亮点，不过和之前差不了多少。专业照相还是相机吧。\n运行速度：运行速度杠杠的，嗖一样的快\n待机时间：续航还有待体验，待后续评论。\n希望价格不要迅速下跌就行', '白色', '2022-07-07 10:43:28', 7);
INSERT INTO `data` VALUES (10453, 'l***6', 3, '给老婆买的，据她说用起来还行', '原野绿（素皮）', '2023-01-11 18:22:27', 6);
INSERT INTO `data` VALUES (10454, '张***s', 5, '手机质感非常好，使用起来很舒服，性能很流畅，运行游戏非常棒，拍照效果特别好，很清晰', '白色', '2022-08-20 10:02:06', 6);
INSERT INTO `data` VALUES (10455, '小***斌', 5, '手机是给母亲买的（评价图片是借的）；自己上手试用了两天，效果真的绝了；和最起初的小米真的是不同了，外观很大气，素皮手感也不错（带壳后期丢了这种感觉，但是真的很棒）；莱卡相机拍照也是不错，使用的两天也没有了以前888发热那么严重，总体来说真心好评。现在自己用的12pro max，后期换机直接不犹豫转米粉了。赞', '原野绿（素皮）', '2022-08-28 09:09:04', 7);
INSERT INTO `data` VALUES (10456, '1***鱼', 5, '外形外观：外形小巧，握持感很好，外观简约，后壳白色很好看\n屏幕音效：屏幕音效：屏幕显示挺清楚的，音效很好，清楚无杂质\n拍照效果：可以看图3积木，颜色鲜艳，也清楚\n运行速度：与原手机相比流畅太多，不卡顿\n待机时间：正常使用，无视频无游戏，一天半一充', '白色', '2023-01-04 19:45:30', 2);
INSERT INTO `data` VALUES (10457, 's***蓝', 5, '手机很不错，小巧精致，用起来很方便，运行速度快，还是喜欢小米的系统，用起来非常顺手。徕卡确实拍照好看', '白色', '2022-11-19 16:03:03', 4);
INSERT INTO `data` VALUES (10458, '凉***开', 5, '每一次都很满意，这次选的宝贝更加满意，以后还会一如既往地买下去非常值得信赖的品牌，质量有保障，价格还亲民，相当满意物超所值，商品设计完美，外观也很高大上，让人爱不释手。客服更是热情的没话说，这次购物很满意终于收到货了，非常非常喜欢，做工精致漂亮，已经被很多人夸了，真的太开心了，已经是他家的忠实粉丝了，以后还会继续买买买的真的推荐啊，快递速度特别的快，爱了爱了价格非常的美丽，东西还是不错的，会继续回购！全五分！奈斯奈斯～宝贝心仪很久了，趁活动时候买真的太划算了，喜欢的不要犹豫啊跟我在实体店买的一模一样！还是一样的好用，开心是正品，而且价格不贵，用着也很大气，一直在用，很好??货真价实，高颜值，高品质，一分钱一分货，材质外观和质量一看就很上档次，非常喜欢???????????', '黑色', '2022-09-10 20:58:35', 6);
INSERT INTO `data` VALUES (10459, '高***何', 5, '外形外观：小巧精致，一只手搞定，两个字方便。\n屏幕音效：很正点。\n拍照效果：比10S清晰很多，很给力。\n运行速度：我不打游戏，用着很快。\n待机时间：打电话，微信，视频，一天没用一半的电，给力的很\n从小米10S到小米12S，一如既往支持小米。\n有一点给我弄得不太确认了，我手机是啥颜色？？？', '原野绿（素皮）', '2022-10-16 17:22:22', 5);
INSERT INTO `data` VALUES (10460, '一***草', 5, '外形外观：简洁精炼大方\n屏幕音效：颜色靓丽，显示超清\n拍照效果：效果不错，夜景也是棒棒哒\n运行速度：速度快，不卡顿\n待机时间：暂时很不错，一天是足够了\n其他特色：背部手感很好，丝滑', '黑色', '2022-12-30 09:32:51', 2);
INSERT INTO `data` VALUES (10461, '小***2', 5, '没毛病。\n外形外观：好看，可靠，有点厚，男生用可以，看起来稳重一点。\n屏幕音效：屏幕显示完美120赫兹用起来很舒服\n拍照效果：拍照贼清晰啊，徕卡太牛了。\n运行速度：8g没问题，完全够用，比我原来12的k40好用一些。', '原野绿（素皮）', '2022-07-23 00:04:44', 5);
INSERT INTO `data` VALUES (10462, 'q***3', 5, '外形外观：白色无敌好看\n屏幕音效：杜比音效贼爽，屏幕没有什么不适，看着挺舒服的\n拍照效果：跟徕卡合作的不用多做介绍了吧\n运行速度：比我上一个iQOO9牛\n待机时间：续航非常满意', '白色', '2022-07-09 17:12:25', 2);
INSERT INTO `data` VALUES (10463, '萌***头', 5, '手机不错，发烫还是有，正常温度吧，毕竟没有不烫的手机，颜值白色很好看，手感确实不错。\n外形外观：这个白很好看。\n屏幕音效：屏幕没有那么通透，音效可以。\n拍照效果：拍照我很满意。', '白色', '2022-07-08 19:16:21', 2);
INSERT INTO `data` VALUES (10464, '叁***师', 5, '外形外观：手感无敌，颜值很高，素皮很舒服，是我想要的小屏旗舰\n拍照效果：拍照对我来说很不错了，徕卡加持。\n待机时间：待机一天一冲，续航很坚挺。', '原野绿（素皮）', '2022-11-11 21:34:32', 6);
INSERT INTO `data` VALUES (10465, 'j***t', 4, '拿到手体验4个多小时蛮喜欢的，照相和音乐都玩爆了我的苹果13，续航也和13差不多的，但是充点快这点我太喜欢了，方便我这个在外跑的人！小屏幕手机真心喜欢没办法手小哈哈哈哈！加油小米。', '黑色', '2022-07-12 22:03:18', 3);
INSERT INTO `data` VALUES (10466, '阿***道', 4, '外形外观：手感超级好，曲面屏幕曲面边框，比苹果还要好\n待机时间：待机时间非常令人满意，常规使用一天绝对够了\n拍照效果：拍照非常清楚，相比于苹果还差一点点\n运行速度：MIUI十三，系统的细节做的很好，但是软件的适配性差了一点\n屏幕音效：屏幕感觉还不错，两边都有扬声器音效还可以', '白色', '2022-11-09 19:39:02', 5);
INSERT INTO `data` VALUES (10467, 'f***r', 4, '外形外观：水桶机没啥特别，做工倒是很好，莱卡标看着舒服\n屏幕音效：完美屏，显示效果满意，曲面幅度很小没多大意义，换屏贼贵最好买保险。音质虽然有小金标应该是高通集成的dac，聊胜于无。支持畅听和aptx adaptive倒是很好。\n拍照效果：满意，相机还有专门的德味选项，有那么点意思。\n运行速度：硬件没的说。新机够快，MIUI现在优化还可以，用久了也不算太卡。\n待机时间：差不多一天一充，67w充电超快和笔记本一样功率。\n其他特色：小米换机很好用。', '黑色', '2022-12-19 14:34:59', 5);
INSERT INTO `data` VALUES (10468, '为***用', 5, '外形外观：美观纤巧。\n屏幕音效：图像清晰，音效佳。\n拍照效果：清晰，色度饱满。\n运行速度：流畅快速。\n待机时间：满足一天基本使用。\n其他特色：特别适合单手操作。', '白色', '2022-08-07 18:42:20', 5);
INSERT INTO `data` VALUES (10469, 'j***花', 5, '外形外观：外观很小巧，手感很好，\n屏幕音效：华星光电这块屏幕还不错，不算很惊艳，但是也足够细腻，显示效果还可以，\n拍照效果：拍照还算可以，毕竟有徕卡加持，整体效果还可以。\n运行速度：运行速度比较快，很丝滑！\n待机时间：骁龙8+嘛，功耗很低了，相对还算省电，具体看个人如何使用洛，\n其他特色：喜欢小屏幕的手机，可以来感受一下，用了感觉就不想在用大屏幕手机了，轻薄，小巧非常好！', '白色', '2022-09-03 19:50:47', 5);
INSERT INTO `data` VALUES (10470, 'c***g', 5, '在店里看好的，京东上plus有优惠，便宜，前一晚下单，第二天配送，包装完好，外观很好。不喜欢太大屏的，这款小巧些，很喜欢。传送数据也很方便，已经用了几天了，还没遇到什么问题。好多年了，一直用小米，从没用坏过，至今所有用过的机子都还在，每次都是内存不够，需要大一点内存才换新的。品质值得信赖！', '白色', '2022-11-09 14:36:50', 2);
INSERT INTO `data` VALUES (10471, '热***凉', 5, '外形外观：12s超级好看，我感觉是最好看的了，镜头模组没有很大，正好适中，我认为12系列是最好看的后面。而且紫色也特别好看，拿在手里特别好。\n屏幕音效：双扬声器确实比之前mix2s 的好多了，屏幕也挺好，细长，拿着挺舒服\n拍照效果：拍照可以的，虽然咱也看不出来啥，但是这个徕卡应该挺厉害的', '紫色', '2023-01-16 12:20:02', 5);
INSERT INTO `data` VALUES (10472, '林***雕', 5, '从米10换过来的，感觉非常好非常流畅，屏幕显示效果也不错，没有网上说的那么不堪，国产屏幕也可以的。\n拍照效果：拍照也很好，相机速度很快\n运行速度：运行速度没的说，12g运存足够了\n待机时间：待机一整天没问题，我的米10已经需要一天3充了\n外形外观：外观很酷，大小刚好，小屏里的旗舰', '黑色', '2022-09-17 23:10:58', 5);
INSERT INTO `data` VALUES (10473, 'J***娃', 5, '手感很好，大小合适，系统流畅，防误触比12好，红外无线充电都有，性价比超高，要是直屏就完美了。', '黑色', '2022-09-13 19:02:13', 3);
INSERT INTO `data` VALUES (10474, '我***-', 5, '手机非常漂亮，小屏爱好者的最爱。\n外形外观：白色的非常好看！\n屏幕音效：高刷屏幕用起来很顺手，颜色也很鲜艳。\n拍照效果：拍照配合莱卡的滤镜，随便一拍都是大片！\n运行速度：骁龙8+比之前两代火龙还太多，打游戏不掉帧，发热不严重。\n待机时间：中度使用一天妥妥的，配合快充，没有续航焦虑。\n其他特色：miui配合这代处理器，非常丝滑。', '白色', '2022-11-17 18:57:13', 1);
INSERT INTO `data` VALUES (10475, 'j***e', 5, '手机是给我妈妈买的 小米这些年做的手机真的不错 外观 做工都没有翻车 手机大小也很合适 女性拿着大小正好 素皮的背壳很漂亮 摄像功能很不错 莱卡的调教色彩很艳丽 继续体验 希望后续系统不要崩。', '原野绿（素皮）', '2022-07-17 18:03:57', 3);
INSERT INTO `data` VALUES (10476, '凭***风', 3, '数据传完之后，壁纸变成这样，真是吓我一跳！\n手机使用起来还可以。', '黑色', '2023-01-24 16:29:02', 1);
INSERT INTO `data` VALUES (10477, 'z***7', 5, '外形外观：小米12s的手感真的是棒，是这几年最好的安卓手机握持感，手机也很轻巧，单手操作无压力\n屏幕音效：屏幕显示细腻，足够用了，不用刻意追求高分辨率\n拍照效果：莱卡加持，拍照很不错，莱卡滤镜拍出来很好看\n待机时间：续航一级棒，用水果置换的小米，续航充电信号完胜\n运行速度：日常使用，游戏完全无压力，速度很快', '白色', '2022-07-19 22:38:55', 1);
INSERT INTO `data` VALUES (10478, '小***2', 5, '外形外观：手感一流\n拍照效果：莱卡的确厉害\n运行速度：很快\n屏幕音效：流畅昨天下单，今天刚到，开始试用了一会，的确跟不错，在用几天看看续航', '白色', '2022-08-11 23:34:05', 6);
INSERT INTO `data` VALUES (10479, 'j***p', 5, '手机放在购物车里好长的时间，趁着活动一咬牙就买了，用惯了小米，比较喜欢这款小屏，送了一个无线充电器，看着比以前MIX3送的那种圆盘式的高级许多。手机自带一张膜，清晰触摸反馈也好，还有两个手机壳可以先临时用。虽然对手机配置硬件性能以及使用体验不是很了解，可我真的很喜欢这一款。', '原野绿（素皮）', '2023-03-05 20:39:07', 5);
INSERT INTO `data` VALUES (10480, '亚***伦', 5, '终于，**思夜想的小米12s到了，真流畅啊，出乎我的意料，这个芯片比8gen1的好的不止一点，而且小屏手感真好??，小米手机很少做到这个边框和后盖结合到这么好的，手感好到感动落泪了都。', '白色', '2022-08-11 18:14:49', 3);
INSERT INTO `data` VALUES (10481, '****1', 5, '外形外观：帮岳母买的，她很喜欢！虽然是小了点，握感还不错手小比较适合，背板颜色也好看！\n屏幕音效：屏幕滑动顺滑，没卡顿的感觉！\n拍照效果：对焦速度真的快，照片清晰，加上算法加持出品真不错', '紫色', '2022-10-04 20:12:14', 5);
INSERT INTO `data` VALUES (10482, 'i***o', 5, '外形外观：本来想要蓝色的，但蓝色没有货，紫色的也很棒。\n屏幕音效：屏幕测试了，没有坏点。\n拍照效果：没在意，感觉不错\n运行速度：很棒\n待机时间：续航很好。\n其他特色：手感非常好。', '紫色', '2023-01-13 05:38:42', 4);
INSERT INTO `data` VALUES (10483, '星***想', 5, '颜值不错，收到后发现手感很好，有点以前三星s8的感觉，比大屏的那些方便很多。电池算够用，拍照自己感觉还不错吧，用了一段时间感觉比11pro好用。', '白色', '2022-12-12 12:35:46', 2);
INSERT INTO `data` VALUES (10484, '张***娥', 5, '小米12S小屏旗舰，音质好，像素高，小屏用着舒服，白色的最好看，简直太好了，很喜欢小米12S.', '白色', '2023-01-07 20:25:24', 3);
INSERT INTO `data` VALUES (10485, 'j***X', 5, '小屏手机可选也不多，这一款是很好的选择。从小米9换成12，然后又换过来的，不烫了，不卡了，续航改善明显。白色超级好看，套上自己喜欢的手机壳，学生用非常友好，希望能用的久。', '白色', '2022-09-03 11:43:55', 6);
INSERT INTO `data` VALUES (10486, 'y***i', 5, '外形外观：从6换过来的，手感一如既往的好。\n\n屏幕音效：全景音效很好，屏幕效果不错。\n\n拍照效果：拍照提升很大，不过莱卡滤镜怪怪的，不习惯这个质感。\n\n运行速度：运行流畅，不玩游戏，各种应用非常丝滑。\n\n\n待机时间：待机时间不错，无线充电很爽。', '黑色', '2022-07-30 17:42:46', 4);
INSERT INTO `data` VALUES (10487, 's***l', 1, '这款手机我心心念念了很久，在网上看各种测试视频，又去实体店看了好多次，刚好双十一买了，用了十几天了，现在来评价一下吧\n外形外观：外观很漂亮，白色的，有点偏透白，像那种珍珠的白色，简洁大气。手感是真的好，摸过就晓得了。\n屏幕音效：屏幕我看起来没有什么问题，国产屏越来越好了，可能网上有的人说屏幕不行，但是我个人也没用过更好的了，我觉得这个已经很不错了\n拍照效果：拍照是真的好看，毕竟莱卡影像+高通骁龙的算力，拍照比我的k30u好的不是一星半点\n运行速度：运行很流畅，日常使用很给力\n待机时间：这续航真的顶，不玩游戏一天妥妥的够用\n其他特色：从小米2S到小米12S,中间用过红米note4X,小米8se，小米8，红米k30u，尽管每一代手机都有缺点，但还是选择支持小米，希望以后越来越好吧。\n\n永远相信美好的事情即将发生！', '白色', '2022-11-30 15:00:54', 4);
INSERT INTO `data` VALUES (10488, '白***子', 5, '外形外观：小米12S的外观设计还是不错的，几乎全面微曲屏，特殊处理的蠕动视觉效果玻璃后盖，对称虫卵扬声器开孔，感觉比较满意。\n屏幕音效：这块国产屏素质很高，画面清晰通透，色彩鲜艳真实，属于中上水准。\n拍照效果：不太拍照，没有太多感受，扫码还是很好用的。\n运行速度：挺快。\n待机时间：中度使用一整天。', '黑色', '2022-11-25 13:50:06', 3);
INSERT INTO `data` VALUES (10489, 'j***t', 5, '速度快，物流没的说，天下第一快，，屏幕非常舒服，，最好的我感觉，非常喜欢，非常好，买手机，京东必须的，送了个手机皮套，原装充电器，充电线，点个赞，', '原野绿', '2022-07-13 22:30:35', 6);
INSERT INTO `data` VALUES (10490, '梦***记', 4, '用了三天，浅浅说下感受。首先续航很不错，我基本是高强度玩手机了，整天碰着手机玩，差不多半天左右才充一次电。然后玩游戏也很流畅，完全不会卡。拍照很好看！！真的很绝。手机的大小和曲面屏的弧度都很合心意。快递也很快。就是这手机有一个算不上问题的问题(在我看来)，就是它刚开始玩的时候会发热，但是过一会温度又会降下来', '白色', '2022-08-08 12:06:33', 5);
INSERT INTO `data` VALUES (10491, 'T***s', 5, '外形外观：手感蛮好，略微偏长，有点不习惯，整体OK\n屏幕音效：显示顺滑，比三星好太多，三星S22经常掉帧\n拍照效果：德味浓郁\n运行速度：很丝滑，比三星好太多\n待机时间：比三星好太多，同样强度三星到家18%,小米50%+\n其他特色：目前使用非常好，吊打三星', '黑色', '2022-07-30 10:09:27', 5);
INSERT INTO `data` VALUES (10492, 'h***y', 5, '拍照拍视频观感特别好，晴天阳光的气息都能从视频里看出来\n买给家里长辈用的，拿回来就有系统更新。 手机特别轻便小巧，希望8+能好用一点吧', '黑色', '2022-07-17 11:13:20', 2);
INSERT INTO `data` VALUES (10493, '孤***刻', 5, '外形外观：从小米12过来的，外形尺寸都一样，之前的膜和壳都通用\n屏幕音效：12S屏幕比12好，没有12屏幕的泛黄，音效很好\n拍照效果：徕卡加持果然提升很大\n运行速度：够用\n待机时间：后续用用再说', '白色', '2022-07-06 19:39:38', 3);
INSERT INTO `data` VALUES (10494, '-***鸽', 3, '最后一次买小米手机了，MIUI越来越没有以前好用了\n产品品控拉胯', '白色', '2023-03-02 19:50:54', 6);
INSERT INTO `data` VALUES (10495, '我***_', 5, '外观:之前都是用黑色的，这次选择白色很好看\n\n运行:速度流畅，不卡顿体验很好\n\n待机:电池耐用，持久\n\n体验:今天刚上手暂时来说不错，后续有什么再追评', '白色', '2022-07-06 22:37:54', 4);
INSERT INTO `data` VALUES (10496, '一***的', 5, '小米12s真的手感超级棒！各方面都有所提升，拍照很不错！运行流畅，反应快，够用好久了，\n外形外观：屏幕显示很不错，看起来特舒服，\n屏幕音效：音效真的很好，有质感 晚上听特舒服\n拍照效果：拍照绝绝子，真的不吹，可玩性很高\n运行速度：小米系统还是很好用的，比较喜欢\n待机时间：待机一天妥妥的\n其他特色：钉子户', '白色', '2022-10-31 10:56:49', 4);
INSERT INTO `data` VALUES (10497, 'p***h', 5, '手机尺寸很好，单手操作无压力，运行稳定，中度使用可以用一天半，67w快充很快，与小米11相比，散热好多了，不会发烫，满意，相机反应很快，值得购买', '黑色', '2022-08-20 20:22:33', 4);
INSERT INTO `data` VALUES (10498, 'D***n', 4, '外形外观：手感是我选择12s的最大原因，一把手就可以把控，而且很轻，我是手比较小的人，对我真的太友好了，手很舒服，一点都不累。\n屏幕音效：1080的分辨率还是差一点意思，音效就非常的小米，外放很通透。\n拍照效果：莱卡加持，尤其是那个水印我好喜欢！\n运行速度：12+256的版本，我应该是够用了，用个2年问题不大。\n待机时间：4500毫安时电池，中规中矩吧。', '黑色', '2022-10-23 20:44:53', 3);
INSERT INTO `data` VALUES (10499, '竹***u', 5, '手机非常好，很流畅，处理器很强不发热，屏幕细腻，用了10年的小米了，没有让我失望过，客服服务体验也很棒，客服很耐心，点赞好评！', '白色', '2022-08-25 12:52:32', 7);
INSERT INTO `data` VALUES (10500, 'c***x', 5, '早就已经中意这款手机了。今年8?中旬，自己曾经买过小米12，非常喜欢。这款手机问世，同样也是小屏，恰逢双11大促销，就又了这单。唯一的遗憾是受疫情影响今天才到货。这款手机的使用手感特别好，系统非常流畅，屏幕很清晰，充电速度也已经足够快了，非常满意！', '黑色', '2022-11-26 21:48:29', 6);
INSERT INTO `data` VALUES (10501, 'c***z', 5, '外形外观：非常漂亮的旗舰手机，手感太好了，一掌可握，非常便携，关键配置也非常高。\n屏幕音效：屏幕效果很好，虽不是2K屏，但效果非常细腻、色彩自然，看起来很舒服。\n拍照效果：新换的707摄像头照相非常好，细节上比原来的11要好不少。\n运行速度：运行速度飞快流畅，关键是不怎么发热了，这点太棒了。', '白色', '2022-07-09 08:47:40', 4);
INSERT INTO `data` VALUES (10502, 'P***0', 5, '外形外观：很漂亮，白色很好看\n屏幕音效：哈曼卡顿音效不错，上下都有喇叭\n拍照效果：很不错，够用\n运行速度：处理器很快\n待机时间：一天用完还剩40%左右，很耐用', '白色', '2022-12-03 16:47:16', 2);
INSERT INTO `data` VALUES (10503, 'j***h', 5, '外形外观:\nyyds\n屏幕音效:\n一手掌握，外观真的很nice,手感极佳。小屏\n运行速度: 了。\n120hz感觉就是不一样，双扬声器很舒服\n8g刷刷短视频，看看电视，打打游戏完全够用\n待机时间: 的。\n不打游戏的情况下，日常使用一天是没有问题', '黑色', '2022-12-16 13:39:29', 2);
INSERT INTO `data` VALUES (10504, 'T***5', 5, '?赶上做活动的时候入手的，这个价格一分钱一分货??，外观不错?，做工都不错?，物流超级快，点赞！外观设计漂亮，尺寸大小合适，包装仔细完整，宝贝手感不错，感觉很好，发货速度快，服务态度一流，给力！5星好评！', '蓝色', '2022-11-19 15:13:56', 2);
INSERT INTO `data` VALUES (10505, 'j***8', 5, '虽然是第一次买小米，之前比较犹豫，拿到实机第一眼就觉得小米已经进化了，真有质感，不亏是国产之光！货真价实，高颜值，高品质，一分钱一分货，材质外观和质量一看就很上档次，非常喜欢???????????', '黑色', '2022-07-13 18:34:56', 6);
INSERT INTO `data` VALUES (10506, '快***P', 5, '客服服务非常好，手机大小正合适，尤其适合我这小手的，携带方便，整体很运行很流畅，外观挺好看的，拍照也不错，总体挺满意的', '黑色', '2022-08-30 11:56:37', 6);
INSERT INTO `data` VALUES (10507, '茉***志', 5, '五星好评，客服专业\n外形外观：好看\n屏幕音效：很好\n拍照效果：清晰\n运行速度：流畅\n待机时间：够用', '黑色', '2022-11-28 16:03:15', 4);
INSERT INTO `data` VALUES (10508, '李***长', 5, '外形外观：小巧，适合小手的人！\n屏幕音效：显示效果好，音质听起来不错！\n拍照效果：拍照效果完美，自带美颜！\n运行速度：8+处理器，完美无瑕！速度嘎嘎的\n待机时间：待机时间不错！系统优化越来越好！\n其他特色：推荐购买小米手机！！！', '紫色', '2022-11-18 20:53:49', 3);
INSERT INTO `data` VALUES (10509, '福***丶', 5, '小米12S小屏旗舰 ，手感超级好 适合女人使用 ，外观好看时尚 ，骁龙8+性能稳定可靠，功耗优化的很好 ，lmx707+徕卡摄像非常棒，67w半个小时充满，50w无线，10w反向，妥妥的旗舰，再加个lp68防水就更好了', '白色', '2022-12-10 15:26:34', 4);
INSERT INTO `data` VALUES (10510, 'j***w', 5, '小米12S是小米旗舰机，\n外形外观：曲面屏，线条很好\n屏幕音效：杜比音效\n拍照效果：自带美颜，适合爱拍照的女生\n运行速度：很流畅\n待机时间：正常使用一天到晚还剩40%左右', '黑色', '2023-02-11 16:15:42', 3);
INSERT INTO `data` VALUES (10511, '疯***罗', 5, '很小巧精致，看了好多评测以后下单的，比骁龙8强多了，台积电稳的，用惯了大手机还是小手机舒服，也不重，方便放包里。看着很精致，而且有莱卡加持。很喜欢。iphone虽然生态无敌，但是使用上限制太多了，还是安卓用着舒服。', '白色', '2022-08-18 21:18:47', 4);
INSERT INTO `data` VALUES (10512, '大***闹', 5, '不错不错不错，大品牌值得信赖的产品，功能强大，价格实惠物美价廉，手机配置高，办公用足够了，给力的产品，玩游戏元可以，做工精细，手感很好，支持一下', '黑色', '2022-10-21 19:42:05', 5);
INSERT INTO `data` VALUES (10513, 'j***O', 5, '外形外观：大小合适， 不愧是小屏旗舰\n屏幕音效：这扬声孔的位置太nice了，音效很棒\n拍照效果：还行，中规中矩\n运行速度：不错，骁龙8gen1+很能打\n待机时间：一天一充', '白色', '2022-08-27 21:21:44', 3);
INSERT INTO `data` VALUES (10514, '童***寄', 5, '挺好，很快。\n买的时候享受了北京优惠券，感觉很划算的，\n手机很流畅，小屏旗舰，手感不错，\n拍照是莱卡，拍照进光量很大，照片很清晰。\n手机也不怎么烫，感觉这次的芯片还是很给力的，没有以前那么烫手了。\n进', '白色', '2022-07-27 12:57:08', 4);
INSERT INTO `data` VALUES (10515, '凌***y', 5, '外形外观：很满意，屏幕比米8大，但是整体尺寸比米8小。适合我。\n拍照效果：我用过的拍照最好的拍照手机了，足够我用。\n运行速度：相当快\n待机时间：相当满意，我的米8一天几十充\n其他特色：打光的指纹也没那么慢，还好啦，不错。', '白色', '2022-08-21 21:16:59', 4);
INSERT INTO `data` VALUES (10516, 'a***7', 5, '外形外观：12s大小正合适 一手掌握 手感很棒！\n运行速度：完全不卡 相当流畅\n拍照效果：不是专门拍照用的 不太清楚区别 就觉得拍的照片感觉都很不错\n屏幕音效：清晰 看的很舒服\n小米12s这款手机整体很不错，用了两天了，没什么发热现象，十分流畅，各方面都很满意，自我感觉很值得。', '黑色', '2022-07-28 14:44:56', 3);
INSERT INTO `data` VALUES (10517, 'j***9', 5, '外形外观：不错\n屏幕音效：不错\n拍照效果：莱卡的，拍出来效果满意\n运行速度：很流畅，价格也合适\n整体满意的，还送了快充座，非常实用，', '黑色', '2023-01-07 20:05:49', 3);
INSERT INTO `data` VALUES (10518, '阿***i', 5, '外形外观：很轻薄，比旗舰机型轻多了，拿着不称手，素皮手感超好，整机窄机身拿着很舒服\n\n屏幕音效：屏幕通透，音效对称双扬声器还不错\n\n拍照效果：徕卡加持的拍照效果十分不错，一般都用徕卡生动，成像明亮艳丽。防抖效果也好，关键是拍照速度很快\n\n运行速度：流程不卡顿，快充很快', '原野绿（素皮）', '2022-11-13 17:53:43', 2);
INSERT INTO `data` VALUES (10519, '金***金', 5, '小尺寸手感很好，适合女生或喜欢小屏的男生，拿着很顺手很舒服。最新的处理器，速度很快，应用秒开。内存12G足够大，能顶好几年。摄像头拍张也还不错。外放是哈曼卡顿，音质很棒。总体而言，非常满意。', '白色', '2022-08-13 11:51:26', 5);
INSERT INTO `data` VALUES (10520, '墨***一', 5, '心心念念的小屏旗舰终于入手了，原来想买12x，无奈没有无线充电，现在12s不仅有无线充电，而且cpu也是最新一代的功耗又低，比原来的手机凉快多了，而且手感超棒！。可惜没有长焦，无奈ヽ（?＿?；)ノ。', '白色', '2022-07-12 19:01:11', 5);
INSERT INTO `data` VALUES (10521, '透***1', 5, '外形外观：手感不错，拿手中很舒服\n运行速度：运行流畅\n收到手机就换机，用了几个小时掉电也不是很厉害，充电速度很快，等下载游戏了再试试', '白色', '2022-07-19 22:53:40', 4);
INSERT INTO `data` VALUES (10522, '月***殇', 5, '外形外观：颜色很好看，使用很流畅，充电也非常迅速。\n屏幕音效：声音非常清晰\n拍照效果：拍照像素很高，非常清晰。\n运行速度：运行速度非常流畅\n待机时间：待机时间非常持久\n其他特色：徕卡相机的滤镜也非常好看', '紫色', '2023-03-12 18:16:26', 2);
INSERT INTO `data` VALUES (10523, 'W***信', 5, '外形外观：很轻薄，手感超好，旗舰机乃至安卓机阵营中难得一见的小尺寸手机，整机窄机身拿着很舒服\n屏幕音效：得益于小尺寸，就算是1080p分辨率也能得到很清晰锐利的显示效果，音效方面不清楚是否有知名机构认证，但这立体式双扬声器音质还是不错的。\n拍照效果：拥有徕卡加持的拍照效果十分对我口味，一般都用徕卡生动，成像明亮艳丽。防抖效果也好，关键是拍照速度很快\n运行速度：买的高配12+256的，全新高通骁龙8+处理器，不打游戏日常使用流畅不卡顿。', '紫色', '2023-01-10 12:54:51', 4);
INSERT INTO `data` VALUES (10524, '秋***风', 5, '手机很好。很流畅。比我之前买的好用多了。电池也抗用。充满可以用一天左右，也不会发烫，棒棒\n外形外观：小尺寸。一只手刚好\n屏幕音效：这个不是很追求。感觉还可以\n拍照效果：拍照清晰\n运行速度：很流畅\n待机时间：充满可以用一天左右', '白色', '2022-11-21 17:35:36', 3);
INSERT INTO `data` VALUES (10525, 'T***7', 5, '手机收到了，目前还没有使用，等手机膜到了贴好再使用，先给个评论，手机很漂亮手感不错，其它方面待使用一段时间后再做追评。512G的，希望质量过关，可以用个好几年。', '黑色', '2022-11-14 11:23:27', 5);
INSERT INTO `data` VALUES (10526, 'c***b', 5, '外形外观：轻巧美观，质感很好\n屏幕音效：比我米10的屏幕看起来舒服，音效对称的喇叭效果也很好\n拍照效果：还不错，大底就是大底\n运行速度：运行速度：新机 必须流畅\n待机时间：正常，比我老手机4160的电池大。晚上充满隔天起来没掉电\n其他特色：手感真的好，又轻又舒服，白色质感很好，指纹解锁快，小米换机真方便', '白色', '2022-11-19 10:08:37', 3);
INSERT INTO `data` VALUES (10527, '老***s', 5, '老米粉了，习惯用小米的系统，骁龙8+很流畅，就喜欢这个小屏幕，所以果断选了12s，用了两天了，暂时很满意', '白色', '2022-07-09 10:51:01', 5);
INSERT INTO `data` VALUES (10528, '棄***爷', 5, '刚拿到手，目前使用各方面都不错，我比较喜欢这种小巧一手掌握的手机，可以说这是我的第一部莱卡嘛！非常喜欢?', '白色', '2022-07-06 19:38:24', 7);
INSERT INTO `data` VALUES (10529, '中***子', 4, '外形外观：手感很好，这个尺寸太合适了。\n屏幕音效：屏幕还可以，华星光电还是比三星稍差点。音效很棒，毕竟哈曼卡顿调校，还有杜比全景声。\n拍照效果：拍照效果：IMX 707，?莱卡，拍照可以，毕竟卖点就是莱卡调校啊。莱卡生动和经典拍照按自己的喜好选择，都很棒。\n运行速度：12G运存，运行流畅，MIUI目前没有遇到卡顿问题。\n待机时间：电池4500，还可以吧，比同样小尺寸的三星强。', '白色', '2022-07-07 18:08:52', 3);
INSERT INTO `data` VALUES (10530, 'W***D', 4, '给媳妇儿买的，她很喜欢\n外形外观：时尚大气上档次\n屏幕音效：杠杠的\n拍照效果：莱卡加持，价格合理\n运行速度：12的内存还是很流畅\n待机时间：一天一充差不多', '黑色', '2022-08-29 13:23:49', 3);
INSERT INTO `data` VALUES (10531, '最***言', 5, '手机第一时间拿到做了开箱，非常好，各方面都可以，之前准备入12，还是忍了忍等了会，终于等到12s，用小米好多年了。这次从9se换到10p换到12s感觉提升非常大，京东物流也特别快，很好。\n外形外观：小巧，单手握持没压力\n屏幕音效：双扬声器，非常可以\n拍照效果：莱卡水印，拍照一流\n运行速度：120高刷，丝滑流畅\n小米加油，雷总加油', '白色', '2022-07-06 18:38:56', 4);
INSERT INTO `data` VALUES (10532, 'y***3', 5, '外形外观：手机小巧，手感非常好\n拍照效果：莱卡调教下拍照色彩好看，质感好\n运行速度：运行速度快，基本与卡顿\n屏幕音效：音效也挺好的\n待机时间：待机时间长', '紫色', '2022-11-19 10:44:44', 2);
INSERT INTO `data` VALUES (10533, 'j***M', 4, '外形外观：很好手感 轻薄 单手操作完美 不像苹果13pro 久持后割手知感太强\n屏幕音效：屏幕显示清晰  音效也很好\n拍照效果：拍照主摄和12su差不了多小（只限主摄）\n运行速度：快 稳  \n待机时间：日用续航出色 手机发热也控制得很好玩游戏就不知了 \n其他特色：充电快', '原野绿（素皮）', '2022-08-18 11:53:56', 2);
INSERT INTO `data` VALUES (10534, 'f***y', 5, '看中这个手机主要是看中比较小。之前用的手机比这个大，有时候手上拿东西了手机感觉容易掉。这个大小我很喜欢。512内存，给娃拍照完全不担心存不下。打游戏也流畅，手机也没有很烫。', '白色', '2023-01-11 09:02:12', 3);
INSERT INTO `data` VALUES (10535, '自***安', 5, '外形外观：干净整洁，小巧可爱\n\n屏幕音效：显示清晰，音响效果还行，低音略有不足\n\n拍照效果：拍照效果很好，莱卡镜头就是不一样\n\n运行速度：速度没得说，非常流畅', '白色', '2022-11-22 16:05:44', 3);
INSERT INTO `data` VALUES (10536, '雪***翔', 5, '手感不错，系统吧就那么回事，那些手感不错，个人觉得手已经很大了，用过华为和平果，这个大小绝对合适，素皮后壳也很棒，', '原野绿（素皮）', '2022-11-06 02:27:29', 6);
INSERT INTO `data` VALUES (10537, 'L***7', 5, '外形外观：小巧轻薄，单手握持，很方便很好看\n屏幕音效：色彩细腻，看起来很舒适\n拍照效果：拍照速度！！！是真的快，刷刷刷连拍老舒服了\n运行速度：无卡顿，流畅运行\n待机时间：还在用，目前感觉确实不错\n其他特色：徕卡加持~妥妥的', '白色', '2022-07-07 19:41:07', 3);
INSERT INTO `data` VALUES (10538, '遗***狸', 5, '外形外观：经典的造型，手感很好\n屏幕音效：哈曼卡顿的音效不是盖的\n拍照效果：拍照算主流\n运行速度：很快，用个两三年没有压力', '紫色', '2022-09-14 19:04:23', 3);
INSERT INTO `data` VALUES (10539, 'j***稍', 5, '手机非常精致，小屏手机的天花板，手机运行速度非常快，没有888发热那么厉害，白色的非常漂亮，徕卡的摄像可以说是很棒了，大家抓紧购买的，闭眼入没有问题，小米的又一杰作哈哈', '白色', '2022-09-01 07:58:29', 5);
INSERT INTO `data` VALUES (10540, '水***6', 5, '手感非常好，对于女性很友好。正常使用没感觉发热。买得太晚抢不到紫色。如果自带的手机壳能够带打孔穿绳位置就更好了。\n拍照效果：超微距表现非常好，莱卡模式就见仁见智。\n待机时间：正常使用一天一充问题不大', '白色', '2023-03-08 20:02:47', 4);
INSERT INTO `data` VALUES (10541, '王***0', 4, '外形外观：白色，玲珑小巧精致，握感很好\n屏幕音效：屏幕流畅，分辨率高，使用体验很nice\n\n拍照效果：后置摄像头拍照真的很完美，色彩比苹果12pro更胜一筹\n\n待机时间：充一次电差不多管一天多，待机时间长\n运行速度：运行速度很快。\n\n其他特色：小功能窗口真的太方便了。', '白色', '2022-08-04 11:39:17', 2);
INSERT INTO `data` VALUES (10542, 'C***龍', 5, '值得购买的手机，做工非常精细。小屏安卓旗舰手机。\n67w快充够用，但肯定不如Pro的120w来的快速。', '原野绿（素皮）', '2022-11-16 20:09:12', 3);
INSERT INTO `data` VALUES (10543, '无***美', 5, '心心念的一款小屏手机终于双十一拿下了，外形美轮美奂小巧精致，曲面屏观感非常艳丽，指纹解锁的那一刻超级壁纸令人惊艳，使用了快一个月了，拍照自我感觉已经非常满意，运行速度非常丝滑顺手，待机时间眼看的质的飞跃很明显完全超呼预期！一如既往的支持小米！支持京东自营店！', '白色', '2022-12-08 16:18:42', 2);
INSERT INTO `data` VALUES (10544, 'l***g', 5, '昨天晚上下单，今天上午收到，好。紫色好斯文好好看，手感相当不错，带有透明套，颜值和预想的一样一样。开机试用系统流畅和充电方便，用过一段时间再来看看效果怎么样。目前非常满意。', '紫色', '2022-11-18 20:26:08', 5);
INSERT INTO `data` VALUES (10545, 'f***1', 5, '小米十用了一年多了，正好赶上骁龙活动置换的12s，用了半个月来谈谈使用感受\n外形外观：原野绿素皮版真的非常好看，文艺气息浓厚，持握手感很好，单手使用比之前的10要好太多\n屏幕音效：支持杜比音效，听音乐外放很好\n拍照效果：虽然是莱卡镜头，但是拍照的素质只能是中上水平，镜头缩放倍率一般\n运行速度：运行速度：新的 8? 处理器很快，功耗发热控制很不错，玩游戏发热不严重\n总而言之是一款挺不错的机子，置换的价格很香', '原野绿（素皮）', '2022-09-14 16:57:46', 3);
INSERT INTO `data` VALUES (10546, '申***亮', 5, '京东自营店\n有保证值得信赖！手机质量很好的哦！小米手机挺好的！\n外形外观：漂亮的很老婆喜欢啊\n屏幕音效：音质清晰度高\n拍照效果：效果真的好\n运行速度：流畅的很\n待机时间：很好', '原野绿（素皮）', '2023-01-28 20:59:42', 2);
INSERT INTO `data` VALUES (10547, '正***汉', 5, '小米12s外观不错，拿起来很轻巧顺手，续航非常给力，有了莱卡的加持相机感觉棒棒的，这次还送了80w无线充，开心！', '白色', '2022-11-06 16:16:22', 5);
INSERT INTO `data` VALUES (10548, 'i***u', 5, '外形外观：好看，顺手，拿在手里比较舒服。\n屏幕音效：屏幕清晰度和亮度都很不错，音乐外放效果也很好。\n拍照效果：拍照效果色彩度还原比较真实。\n运行速度：运行速度很快。\n待机时间：待机时间长。', '白色', '2022-09-23 15:23:45', 2);
INSERT INTO `data` VALUES (10549, '橙***维', 3, '外形外观：外观小巧玲珑，女生单手操作也没问题\n屏幕音效：屏幕自用体验感觉画质略差\n拍照效果：拍照效果不好比对，毕竟每个手机性能不一样\n运行速度：运行速度很快\n待机时间：一天一充\n其他特色：客服态度很好，有问题积极解决，售后也很好', '白色', '2022-09-05 08:01:27', 3);
INSERT INTO `data` VALUES (10550, 'g***6', 5, '小屏种草，拿到手以后觉得好用，特别是适合我，手比较小\n\n\n67瓦的有线充电\n\n50瓦无线充电很好用\n\n曲面屏本来很抵触，目前用下来觉得还可以。\n\n主摄像头 好评\n\n总之很满意', '蓝色', '2022-12-02 12:16:22', 4);
INSERT INTO `data` VALUES (10551, 'j***6', 5, '外形外观：漂亮，漂亮极了，岳母大大非常喜欢，。\n屏幕音效：屏幕也还行\n拍照效果：一般吧，勉强够用\n运行速度：还不错，没有什么问题\n待机时间：还可以，4500毫安呢\n其他特色：颜色手感极佳', '紫色', '2022-12-02 10:28:21', 3);
INSERT INTO `data` VALUES (10552, 'w***5', 5, '外形外观：手机外观很漂亮，手感也很好！\n屏幕音效：总体效果很OK的！刷屏率很好！120的！一级棒\n拍照效果：拍照效果很不错，徕卡联名的不错！\n运行速度：12+3的运行内存很强大，卡顿暂时没有发现！用着很好！大小合适！', '黑色', '2022-08-30 10:34:03', 3);
INSERT INTO `data` VALUES (10553, 'j***e', 4, '苹果转小米 看室友用的小米手机感觉手感不错 正好苹果一百年不变的外观也够了 所以想尝试一下安卓系统 这个手机的振动马达并不比苹果的差 整体手感也很好 扬声器声音调低音质不是特别好 但是声音放大的时候音质真的非常nice哈曼卡顿不是盖的 莱卡摄像头拍风景很漂亮 后置摄像头就一般般的自带一点美颜 不想苹果相机那样真实 整体来说还是非常不错 满足了我对曲面屏手机和小屏幕手机的执念（感觉造型很新颖，不像苹果手机那样死板）无线充电器有呼吸灯下面还有散热器 显得很高级充电也很快  赠送的保护壳也很商务高级 喜欢', '白色', '2023-02-03 20:37:49', 3);
INSERT INTO `data` VALUES (10554, '****组', 5, '外形外观：小巧，老婆单手握住轻巧\n屏幕音效：买来商务办公用的，足够了\n拍照效果：很少拍照，办公用足够了\n运行速度：反应快，不卡\n待机时间：这个有点麻烦，新机器商务办公用的多，不到晚上回家就得充电\n其他特色：客服专业??\n手机界面漂亮整洁，娃看了都喜欢', '黑色', '2022-12-05 13:57:17', 3);
INSERT INTO `data` VALUES (10555, 'D***h', 5, '媳妇的米9pro也用了三年了，机器本身没啥问题，就是电池掉电有点厉害了，趁这个机会换个新款，刚好双十一攒了些红包优惠券，直接用了，媳妇很喜欢，特别是徕卡摄像头效果非常好！', '紫色', '2022-11-17 14:55:41', 3);
INSERT INTO `data` VALUES (10556, 'l***4', 5, '外形外观：小型手机，方便一手使用，手感很好，曲屏带入和很先进\n屏幕音效：音效还可以，麦克和卡针很近，第一次小白容易弄错。\n拍照效果：拍照就不多说了，比以前的要好很多。\n运行速度：速度一流\n待机时间：中度正常使用，一天一宿吧，续航中规中矩。\n其他特色：延续小米的系统，有一些带入软件没有用，可以删掉。', '白色', '2022-07-28 20:41:56', 2);
INSERT INTO `data` VALUES (10557, 'A***儿', 5, '外观很时尚，曲面屏比较大气，手感摸着也不错，屏幕很清晰，摄像头是莱卡相机，拍照效果非常棒，运行速度也很流畅，性价比非常高，不错', '黑色', '2022-08-11 11:56:19', 4);
INSERT INTO `data` VALUES (10558, 'V***6', 5, '作为一个资深米粉，我认为我对于这个小米12s的评价应该是非常客观，非常具有代表性的。\n首先，我从小米六到换这个小米12s，我认为小米12s完全可以代替小米六，小米六的钉子户，你可以把小米六给扔了。\n其次，这些年小米手机的品质上的把控是有非常大的提升，手机的听筒采用微缝听筒，这一个也是很不错的。边框的割手感再也没有了。金属机身，对称扬声器，莱卡摄像头都是亮点。红米完全没办法和小米旗舰比。\n再次，小米12s处理器的更换和处理器的调度，应用打开的速度都已经是安卓霸榜。电池已经赶上了iPhone，还有哪一家手机能做的这么良心？\n结论，想要小屏旗舰，想要各方面都完美的可以下手了。', '白色', '2022-07-12 22:44:49', 4);
INSERT INTO `data` VALUES (10559, '小***途', 5, '正品，棒棒哒，价格很优惠，总而言之挺好的，还会再买\n外形外观：外观很小巧上手很轻\n屏幕音效：屏幕显示细腻\n拍照效果：拍照也比之前的强\n待机时间：相对小屏手机来说续航真的可以', '白色', '2022-12-07 12:21:45', 3);
INSERT INTO `data` VALUES (10560, 'j***y', 5, '外形外观：外形好看。\n屏幕音效：屏幕音效一级棒。\n拍照效果：拍照效果太棒了。\n运行速度：非常流畅。\n待机时间：待机时间很长。\n其他特色：一直是小米手机的忠实用户。', '白色', '2023-01-13 20:18:32', 2);
INSERT INTO `data` VALUES (10561, 'j***z', 5, '很好，大小是我喜欢的尺码，喜欢屏幕小的可以冲，拍照也很清晰，感觉挺棒的挺好的。', '白色', '2022-07-22 19:16:08', 2);
INSERT INTO `data` VALUES (10562, '希***X', 5, '小米手机，速度那是相当的快，握感也很好舒服，比我原来的手机好的太多了，操控性好，功能齐全，屏幕看着舒服，系统运行流畅，希望能一直这样流畅下去，无线充真的很方便，以后还会推荐朋友来买小米的手机。', '白色', '2023-01-25 13:09:20', 3);
INSERT INTO `data` VALUES (10563, 'y***3', 5, '外形外观：外观不错，后盖摸起来很护肤，做工不错。小屏旗舰，握持感很好。\n屏幕音效：屏幕色彩还可以，没绿屏，音质不错毕竟对称式双扬声器。\n拍照效果：拍照效果不错，莱卡加持。\n运行速度：运行速度很快，不怎么发烫，续航也还行。', '白色', '2022-08-05 18:01:39', 2);
INSERT INTO `data` VALUES (10564, '零***云', 5, '外形外观：小巧漂亮\n屏幕音效：屏幕漂亮靓丽，音效很舒服\n拍照效果：这很徕卡\n运行速度：流畅\n待机时间：时间长\n其他特色：运送速度快', '白色', '2022-08-22 12:36:54', 3);
INSERT INTO `data` VALUES (10565, '光***E', 5, '小屏手机爱好者的读音，手感简直了，只能说，小米S直击我得需求\n屏幕显示相当惊艳，并且流畅顺滑', '白色', '2022-09-03 10:41:03', 5);
INSERT INTO `data` VALUES (10566, 'j***h', 5, '外形外观：我觉得这款白色的小米12s很漂亮、精美，是我用过的我觉得最漂亮的手机\n屏幕音效：杜比全景声很好听，手机上下部的左侧都各有一个扬声器，立体感很好。\n拍照效果：有徕卡的加持，拍出的相片好看，成像速度也很快。\n运行速度：运行速度很快，我很满意\n待机时间：一天一般用，就一天一充，如果重度使用，一天两充，我觉得待机时间可以\n其他特色：希望这次买的小米12s不要再清除我的数据了，之前红米被我不小心按错键清除了数据，令我伤心了好久，强烈建议:小米能在清除数据的设置弄得更复杂些，不要不小心按了哪几个键就清除数据了！！京东物流真的很棒，11月10晚10点下单，11月11下午就收到了，爱京东，我觉得小米手机比红米手机更好，之前买的红米手机太重了，这个小米12s手感不重，单手操作很方便，而且比红米更好看。之前买的红米k30\npro后面充不进电，不过后面售后给我免费修好了，希望这次小米不要再出现这个问题。', '白色', '2022-11-21 22:10:22', 2);
INSERT INTO `data` VALUES (10567, '小***4', 5, '外形外观：非常小巧很喜欢\n屏幕音效：屏幕很细腻\n拍照效果：徕卡的效果没的说，杠杠滴\n运行速度：太丝滑了\n待机时间：续航目前来说很棒\n其他特色：小屏是真的趁手', '白色', '2022-08-27 08:56:56', 2);
INSERT INTO `data` VALUES (10568, 'v***h', 5, '用小米和米家产品很多年，但这是第一次用小米手机。双十一砸蛋500卷+24期价格比xx多便宜，到手感觉12s完全没选错，握在手里精致小巧，同时骁龙8+玩游戏温度也不太高，且全天开120hz续航也很不错，比我之前OPPO 888机型的好太多了。12s对比12s Pro系列，在屏幕、拍照、外观细节等等各方面都有阉割，但它是个小屏旗舰，这一点就够了，加上MIUI 13用了一周多还没发现什么bug，后台保活能力、动效流畅度都做的挺不错的。', '白色', '2022-11-20 17:33:10', 3);
INSERT INTO `data` VALUES (10569, 'M***1', 5, '第一次购买小米手机，感受超出我的预期，使用效果非常满意，外观设计经典，小巧精致携带方便，单手操作很轻松，手机反应非常快，各种操作非常灵敏，续航时间也很长基本上一天一充，充电速度超级快，还随机赠送原装手机壳跟无线充电套装，京东的服务品质非常满意！', '黑色', '2023-02-08 08:17:05', 3);
INSERT INTO `data` VALUES (10570, '2***m', 5, '新的骁龙8+处理器还不错，配置丰富，摄像很清晰，手机不大手感很不错！\n运行速度：快\n拍照效果：好\n屏幕音效：立体感强\n外形外观：精致', '紫色', '2022-07-07 17:28:32', 2);
INSERT INTO `data` VALUES (10571, 'j***0', 5, '使用流畅，拍照很顶，机身很小单手可握，也不沉，新系统很稳定，屏幕曲度小边缘不发绿，用着看着都很舒服????', '白色', '2022-08-19 09:35:26', 4);
INSERT INTO `data` VALUES (10572, '别***觉', 5, '外形外观：手感极好\n屏幕音效：哈曼卡顿YYDS，屏幕刷新率也很棒\n拍照效果：拍照很完美', '白色', '2023-03-05 00:13:07', 4);
INSERT INTO `data` VALUES (10573, '小***吉', 5, '上一次用小米还是四代的时候，近期正好想买台备用机，看到12S发售，7号上午下的单 下午就到了，先给JD物流点赞，机子很不错，大小重量色彩，等用过之后再追评吧，上组开箱图，喜欢不要犹豫！', '黑色', '2022-07-08 01:18:42', 6);
INSERT INTO `data` VALUES (10574, '呼***了', 5, '外形外观：真好看纯纯冲着好看下单的(??&omega;??)??\n屏幕音效：微曲手感好同时不影响观感，音效我听不出来和别的手机有不同\n拍照效果：比千元机好一点\n运行速度：非常流畅，miui还是很好用的\n待机时间：一般般', '白色', '2022-08-19 06:10:53', 2);
INSERT INTO `data` VALUES (10575, 'B***王', 5, '使用了这么多天，非常不错的手机，小巧精致，一只手拿着，握感很好。手机速度丝毫没有卡顿，也没有快速发热的情况出现，屏幕显示效果优秀，充电速度很快，节省了很多时间，避免了长期充电的情况。电耗还非常的不错，轻轻松松使用一天时间，整体素质非常优秀的手机。', '原野绿（素皮）', '2022-10-13 08:39:31', 3);
INSERT INTO `data` VALUES (10576, 'j***d', 5, '外形外观：非常不错，十分的小巧玲珑精致，感觉非常不错的小屏手机，十分方便于单手使用\n拍照效果：和莱卡联名的相机感觉非常不错\n运行速度：很流畅，不怎么杀后台，芯片功能看来很强大\n屏幕音效：屏幕显示很生动', '紫色', '2022-09-17 17:30:33', 2);
INSERT INTO `data` VALUES (10577, '小***a', 5, '刚刚拿到，外观非常好看，我买的黑色的，真好看，嘿嘿，屏幕是2k的，非常好，显示细腻，拍照效果是真的好啊，比我的苹果手机好多了，运行速度没话说，嗖嗖的快特别顶，电池容量挺好的，用一天没问题，手机握持感特别舒服，而且总体性能比苹果好多了', '黑色', '2022-11-19 17:09:36', 2);
INSERT INTO `data` VALUES (10578, '搁***P', 5, '外形外观：外形外观：6.28英寸，非常小巧，可以单手掌握，难得的小屏旗舰机.\n屏幕音效：屏幕完美显示120赫兹高速，双喇叭立体音、杜比音效nice.\n拍照效果：徕卡加持，夜晚拍照更清晰、分辨率高.', '白色', '2022-10-23 23:39:45', 3);
INSERT INTO `data` VALUES (10579, '周***丶', 5, '外形外观：使用感很好，手感也不错，颜值拉满\n\n拍照效果：目前还没出去实拍，室内没什么太大优势，\n\n运行速度：很流畅，丝滑度很不错', '原野绿（素皮）', '2022-11-10 21:52:18', 2);
INSERT INTO `data` VALUES (10580, 'j***4', 5, '外形外观：颜值超高\n屏幕音效：音效超级好\n拍照效果：还可以，本人要求不高\n运行速度：很流畅\n待机时间：还行\n其他特色：充电快，系统好', '白色', '2022-07-15 00:52:56', 2);
INSERT INTO `data` VALUES (10581, '我***启', 5, '还可以，小巧精致，做工精细，质量很好，符合要求。手机挺顺滑，适合手小的女士，外观也很时尚，系统流畅，屏幕顺滑。等用一段时间再过来评价。', '白色', '2022-11-20 12:30:36', 3);
INSERT INTO `data` VALUES (10582, 'g***2', 5, '小巧的手机，对手部关节很有帮助。单手超控非常省力。\n\n之前的手机导致肩周炎很严重啊。这个手机会缓解点。可以可以。', '原野绿（素皮）', '2022-12-26 10:40:12', 4);
INSERT INTO `data` VALUES (10583, 'h***6', 5, '第1次用小米手机这么多年了，主要是喜欢小屏手机，这个尺寸非常不错，以前喜欢魅族的手机，如果12S手感也蛮不错的，拿着很圆润，大小非常合适，主要是看中他的牌照，不玩游戏。双十一的等了10多天才终于发货。紫色蛮漂亮的。', '紫色', '2022-12-09 23:45:14', 3);
INSERT INTO `data` VALUES (10584, '哒***3', 5, '小米12s这次没让我失望，骁龙8+温控做的很强，在38度的户外电池温度才42度徕卡拍照很棒，今年都是直拍出片', '白色', '2022-07-12 14:45:11', 6);
INSERT INTO `data` VALUES (10585, 'G***6', 5, '外形外观：可能是今年手感最好的手机，对比了s22、13mini，只有这款称得上手感优秀\n屏幕音效：印象不错，复合近些年对小米音质的期待\n拍照效果：主摄真不错，徕卡也很有味道\n运行速度：无愧8gen2，速度功耗都不错', '白色', '2022-11-21 16:32:28', 2);
INSERT INTO `data` VALUES (10586, 'y***5', 2, '非常不错的一款手机！！！整体非常满意。续航能力很给力，小米9换了这把，续航非常明显。用小米换机功能不错，直接全部数据传输过来，新手机就可以直接继续用，很棒。小屏手机比较方便。手感不错，屏幕小细腻效果很好，没什么不好的。双十一3599扣下单的，全是低价了。拍照很快很好。音质也还不错。不足之处就是屏幕微曲，贴手机膜要贴全胶钢化膜或者全胶UV膜比较好。其他的都不好贴。', '原野绿（素皮）', '2022-12-03 09:53:47', 3);
INSERT INTO `data` VALUES (10587, 'j***h', 5, '屏幕很清晰，手机颜值高，单手握没有问题。第一部小米徕卡手机，很期待。用了半天，续航比我的小米10有提升', '白色', '2022-07-07 15:20:46', 4);
INSERT INTO `data` VALUES (10588, '山***秦', 3, '一般般 玩英雄联盟手游每局都会掉一下帧', '黑色', '2022-09-24 19:32:59', 7);
INSERT INTO `data` VALUES (10589, 'j***i', 5, '外形外观：实体店看的，第一眼就喜欢上了\n屏幕音效：感觉不错\n拍照效果：特别好，一直觉得小米拍照好\n运行速度：很快', '白色', '2022-07-15 13:02:54', 3);
INSERT INTO `data` VALUES (10590, 'N***9', 5, '外形外观：简约，好看\n屏幕音效：杜比音效\n拍照效果：很棒\n运行速度：流畅\n待机时间：一天一充，快充很完美\n第一次使用小米手机，功能很多，完美。', '黑色', '2022-09-10 12:58:50', 2);
INSERT INTO `data` VALUES (10591, 'm***5', 5, '就想要个小屏手机，小米这款非常合口味，单手即可操作，放在兜里也不大，非常好\n就是原来用的华为转到小米要有个适应过程。\n杜比音响真的很爽，打电话的声音都感觉是在耳边环绕，总觉得开了免提似的。', '白色', '2022-11-02 22:48:40', 3);
INSERT INTO `data` VALUES (10592, '瓶***咯', 5, '外形外观：喜欢屏幕窄手机的福音，可以单手握，选择的绿色，太好看了\n屏幕音效：效果如图，音效真的是棒\n拍照效果：拍照买来就是为了拍照的，结果太好看了，然后这手机成了女朋友的了，又要再买一个手机了', '原野绿', '2022-07-08 06:44:29', 3);
INSERT INTO `data` VALUES (10593, '淡***画', 5, '外形外观：看着很舒服。\n\n屏幕音效：一流的感觉。\n\n拍照效果：没的说，主打就是照相。\n\n运行速度：新手机速度都快。这个不用说。', '紫色', '2022-11-09 21:41:41', 2);
INSERT INTO `data` VALUES (10594, '那***范', 5, '外形外观：做工相当精致，白色的磨砂后盖也很耐看，最主要的是手机尺寸，单手握持手感棒极了。\n\n屏幕音效：屏幕分辨率够用，音效比原来的小米10强。\n\n拍照效果：能扫码就行，主要为了小屏。\n\n运行速度：非游戏党，日常使用毫无压力。', '白色', '2022-07-09 15:28:20', 4);
INSERT INTO `data` VALUES (10595, '穷***哈', 5, '小米12S昨天收到的，已经用了整整一天多了。\n  首先，这个拍照真的很厉害，有莱卡的加持确实非常好看。充电也很快，比同样67w的Note 11t Pro还快。手感也非常好，一只手就能握过来，手机不发烫，打游戏也很舒服，挺值得，满意', '黑色', '2022-11-16 17:17:06', 3);
INSERT INTO `data` VALUES (10596, 'C***O', 5, '五年苹果老用户了 看到小米出了新品12s系列 特别心动 有莱卡加持 这是我第一次购买小米手机 打破了我对国产的刻板印象 紫色机身超级好看 系统也很流畅 有很多苹果没有的小功能 高刷体验感很好 还可以分屏长截图 续航特别持久 可以用一整天 再也没有电池焦虑了', '紫色', '2022-08-06 10:35:39', 3);
INSERT INTO `data` VALUES (10597, '冰***D', 5, '第一次用小米手机，感觉非常好，外观大气，尺寸是我最满意的，适合单手握，运行速度很快，各类APP之间切换流畅顺滑，系统设计合理，诸多人性化设计让你感觉很贴心。', '黑色', '2022-11-04 13:45:45', 3);
INSERT INTO `data` VALUES (10598, 'l***7', 5, '外形外观：小屏旗舰握持手感一流\n\n拍照效果：徕卡加持，非常好\n运行速度：非常流畅，也没有明显发热\n屏幕音效：120hz屏幕加双扬声器，影音体验非常好', '紫色', '2022-07-06 20:42:28', 3);
INSERT INTO `data` VALUES (10599, '断***念', 5, '物流很快，次日久就到达。就是送的壳一如既往的这么简陋。手机功能很好，发热不严重。外观好看。包装精美。值得购买。屏幕显示清晰，速度快。', '白色', '2022-07-07 13:26:14', 5);
INSERT INTO `data` VALUES (10600, '小***1', 5, '包装完好，打开包装盒确实把我给惊艳到了，这应该是小屏幕中最好看的手机。上手感觉特别好，激活后用了一下，反应很快，处理器很给力，而且用了一个多小时也没有发烫的迹象，这点希望能持续下去。', '黑色', '2022-08-14 11:59:10', 6);
INSERT INTO `data` VALUES (10601, '惗***爱', 5, '外形外观：一直不能接受曲面屏，这个是微曲面，还是可以接受的。\n屏幕音效：音效很好，120高刷必须赞\n拍照效果：莱卡加持，效果杠杠的\n待机时间：一天一冲', '黑色', '2022-07-13 22:27:15', 2);
INSERT INTO `data` VALUES (10602, '我***姆', 5, '外形外观：手感非常好，很顺滑\n屏幕音效：屏幕一般。音效还不错，哈曼卡顿和杜比音效加持下还不错\n拍照效果：莱卡nb，非常棒，要是有个长焦就更好了\n待机时间：小屏幕来说，续航很好，妥妥一天', '白色', '2022-11-22 19:32:24', 1);
INSERT INTO `data` VALUES (10603, 'h***8', 5, '很好，机型大小适合女生，后壳曲度也贴合手掌。强大的8根1+处理器，配合小米影像大脑，自动追焦，徕卡调教，影像日用真的非常非常出色，随手抓拍，色彩喜人，德味很香~', '白色', '2022-09-08 06:33:17', 2);
INSERT INTO `data` VALUES (10604, 'j***g', 5, '一直期待的小屏旗舰，这次果断下手，音质没的说，比我在用的手机好很多，立体感很强，其他各方面也非常出色，买了高配，估计能用个4、5年不成问题。', '白色', '2022-07-11 00:25:35', 4);
INSERT INTO `data` VALUES (10605, '一***双', 5, '到货很快，上午买，晚上就到货了。小屏幕旗舰手机很棒，单手就可以操作，配置也很高，性价比超高，运营很流畅，白色很耐看，充电速度也很快，值得推荐哦！', '白色', '2022-10-24 18:52:42', 3);
INSERT INTO `data` VALUES (10606, '唐***r', 5, '手机很不错，莱卡拍照很清晰，颜值也高，屏幕显示很清晰，打游戏也流畅，充电快，机身设计很小巧，活动价格很划算，性价比很高，是的购买', '白色', '2022-11-17 21:57:38', 3);
INSERT INTO `data` VALUES (10607, 'c***9', 5, '外形外观：手感很好，外观也很不错\n屏幕音效：屏幕清晰无坏点，双扬声器很带感\n拍照效果：徕卡滤镜效果杠杠的\n运行速度：很流畅，目前没有任何卡顿\n\n                    目前来说，非常满意', '白色', '2022-07-12 00:37:44', 3);
INSERT INTO `data` VALUES (10608, '孟***酱', 5, '外形外观：这个小尺寸的手感真的非常优秀\n屏幕音效：还不错\n拍照效果：莱卡加持，还不错\n运行速度：挺好的\n待机时间：一天没问题\n其他特色：爱小尺寸的必入，手感非常优秀，使用起来也很流畅', '白色', '2022-08-11 12:17:28', 2);
INSERT INTO `data` VALUES (10609, '梅***1', 5, '拍照效果：对我最大的吸引力就是这个相机啦，拍照成像非常有质感，比较适合我这种笨蛋\n运行速度：刚刚到手的新机，速度肯定没得说\n在12s和12 Pro中间犹豫了很久，但想着毕竟是女生嘛，用小巧一点的会更方便，另外一款实在是又重手机又大，还是这个小巧点的更适合，终于满足了我单手操作的需求', '黑色', '2022-09-08 14:08:09', 2);
INSERT INTO `data` VALUES (10610, '五***者', 5, '由于家里的生态都是小米产品，所以手机从水果、华为转用小米。小米11pro、12pro、MIX4都用过，888、888+、8gen1用了个遍，一言难尽！可以说是饱受火龙之苦啊！无奈之下全部出掉后入手了一部K50凑合用，起码治愈了续航焦虑症。骁龙8+上市后得知居然不再是火龙了挺开森，又有了入手小米数字系列的打算，挑来挑去决定搞一部小屏的玩玩，于是用北京消费券买了这部12S，17号下单18号到手简单做个评价，总体来说比较满意，系统MIUI13.0.17稳定版非常流畅，外观方面各花入各眼，个人很喜欢小米12系列的设计，简约而不简单，质感很好，手感简直无敌，拿手里不要太舒服哈！我对拍照没要求小米总不会太辜负莱卡标吧&hellip;&hellip;', '黑色', '2022-08-18 17:52:10', 3);
INSERT INTO `data` VALUES (10611, 'S***_', 5, '超级喜欢的手感，我愿称之为安卓手感第一，而且现在升级处理器以后不烫了，续航也很好，拍照更厉害了，最重要就是配色，终于新增白色了，白色，yyds。', '白色', '2022-07-07 01:49:08', 4);
INSERT INTO `data` VALUES (10612, 'j***m', 5, '从荣耀9换过来的，因为一直都比较喜欢小屏手机，刚好小米12S手感好、配置高、充电速度也很快，徕卡加持拍照也很不错，能满足基本的拍摄需求，单手握持手感非常棒，这一代采用了新一代高通8加处理器，工号没有小米12那么大，发热效果也没有小米12那么严重，升级了MIUI14启动应用的速度也很快，喜欢小屏旗舰的可以考虑入手。', '白色', '2022-12-27 14:08:36', 3);
INSERT INTO `data` VALUES (10613, '江***禾', 5, '作为米粉，6号0点就付了尾款，当天傍晚就收到了，手机整体质感很好，这配置性能绝对没问题，就不希望有小毛病。另外拍照效果需要熟悉。', '原野绿', '2022-07-06 19:11:19', 3);
INSERT INTO `data` VALUES (10614, 'j***d', 5, '小米手机收到，拿在手里大小正好，颜色好看，使用流畅，方便，容量大，音效果好，拍照清晰，充电很快。喜欢这款小米手机。上午买晚上就送到了，京东速度快，好评。', '原野绿（素皮）', '2022-08-28 09:58:32', 2);
INSERT INTO `data` VALUES (10615, 'B***成', 5, '外形外观：很好的一款小屏手机，手感颜值这些都不错\n屏幕音效：屏幕和2k的日常使用区别不大，音效不错\n拍照效果：707的大底，莱卡的加持日常出片效果很棒\n待机时间：虽然电池只有4500，但是续航很顶，中度使用一天没有压力\n其他特色：客服也很专业\n总的来说是一款很均衡没有明显短板的手机，推荐入手', '白色', '2022-11-27 14:58:01', 1);
INSERT INTO `data` VALUES (10616, 'j***k', 5, '包装很好，颜值不错，质量也没有问题，白色非常好看，小组件很好玩哈哈哈，等我继续摸索\n拍照效果：非常好\n运行速度：非常快', '白色', '2022-07-07 19:57:58', 3);
INSERT INTO `data` VALUES (10617, 'Y***g', 5, '骁龙8+真的强炸了!!从11Pro换过来，用了两天，真的  绝了，没有很夸张的发烫，运行特别顺畅，而且续航也  特别顶。手机小巧玲珑，握着特别舒服，一手掌握的感  觉真的太美妙了!徕卡加持，成像特别快，早买早享受  了，从来没有用过小屏，没有想到小屏会这么舒畅，用  这个手机连心情都会变好', '紫色', '2022-11-04 15:28:10', 2);
INSERT INTO `data` VALUES (10618, 'y***1', 5, '大小刚刚好，手感很好，很轻巧，颜色特别漂亮，操作运行流畅，发热控制也不错，游戏也不卡顿，里边好看的壁纸也是一大堆都可以免费使用，老婆说她很满意。', '紫色', '2022-07-14 08:46:01', 2);
INSERT INTO `data` VALUES (10619, 'k***0', 5, '手感很好，一手掌握，素皮版可以不带套，更舒服。屏幕效果不错，响应很快，还没碰见卡顿，拍照非常快。一个建议希望能把边框的摩擦力再提高一些，手感会更好！', '原野绿（素皮）', '2022-07-29 21:52:50', 2);
INSERT INTO `data` VALUES (10620, 'i***c', 5, '1.由10pro到12s，第一感觉是轻便了很多，解救了我的小尾指。???\n2.相机是我喜欢的风格。\n3.32度的深圳没有发热的问题。\n4.续航中规中矩。\n5.512G是我需要的。\n6.整体质感不错，12系列的镜头布局是我喜欢的。\n7.京东的物流你永远可以相信。', '黑色', '2022-07-09 01:06:35', 4);
INSERT INTO `data` VALUES (10621, 'g***s', 5, '非常好的小屏幕手机，性能还非常给力，这就比较难得！\n外形外观：漂亮\n运行速度：很快\n待机时间：比大屏幕长很多', '黑色', '2022-07-14 17:49:51', 2);
INSERT INTO `data` VALUES (10622, 'j***i', 5, '外形外观：小巧轻薄，手感好。\n屏幕音效：显示效果很好，\n拍照效果：满意\n运行速度：流畅', '黑色', '2022-11-13 20:10:00', 2);
INSERT INTO `data` VALUES (10623, '張***泡', 1, '外形外观：很完美，小尺寸机子现在可不多了啊，白色的机身也很好看，给女朋友用，很适合她！\n屏幕音效：屏幕说的是可变刷新率，不知道行不行！对称式双扬声器，音效还是不错的！\n拍照效果：这一代小米有了徕卡的加持，拍照确实是要强了一些的！\n运行速度：到手还是MIUI13，我直接给升级到MIUI14，希望不再卡顿吧！', '白色', '2022-12-24 17:56:16', 3);
INSERT INTO `data` VALUES (10624, '飞***吧', 5, '用了一段时间了才来评价，，，，非常好用，外观清新好看，，，适合自己的，，，机身设计合理，，屏幕看电视也好，没有黑边，，，，，流畅，，，，比较喜欢，，，，而且拍照清晰，，，，，很好，，，。。。。。。好评，，，，，，，，，，，，，，，非常好用。。。', '原野绿（素皮）', '2022-12-29 10:39:02', 3);
INSERT INTO `data` VALUES (10625, '炎***珍', 5, '年度旗舰小米12s手机，性能强大流畅性非常丝滑，夏天使用中感觉温控也特别好，一点也不发烫，打游戏稳定接近满帧，手感小巧握起来很舒服，另外表扬一下:客服服务很好！', '白色', '2022-08-29 16:20:15', 4);
INSERT INTO `data` VALUES (10626, 'P***8', 5, '首先手机尺寸小，但是屏幕不小因为是全面屏。所以手感舒适，视觉效果好。系统很流畅，色彩丰富，可玩性高。\n白色很好看，物流很快，当日达。另外，客服服务态度很好，说话很温柔。', '白色', '2022-09-01 17:53:35', 2);
INSERT INTO `data` VALUES (10627, '亦***父', 5, '这款手机是帮老人选的，之前用的是小米8Se，习惯了小米系统就愿意接着用。几年下来各方面提升还是很明显的，屏幕、处理器、摄像、充电，手感非常不错。', '白色', '2022-10-26 21:53:53', 2);
INSERT INTO `data` VALUES (10628, '落***車', 5, '10月生产，全新未激活，3400多安全下车，手感无敌，质感很好，长在我的审美上了，非常满意！轻度游戏也没问题，电池耐用，充电很快，晚上未充电早上起床只有%30了，插入充电器，洗脸刷牙上厕所，然后就满电出门了..&hellip;...非常满意!', '白色', '2022-11-24 02:14:26', 2);
INSERT INTO `data` VALUES (10629, 'A***n', 5, '外形外观：手感非常好，不用担心单手操作的问题\n\n屏幕音效：120HZ刷新率感觉就是不一祥\n\n运行速度：目前使用过程中很流畅\n\n其他特色：系统优化的很好，之前用过一次小米手机，那是N年前了\n\n待机时间：目前还没有使用，等使用一段时间再来追评', '蓝色', '2022-11-11 08:59:55', 3);
INSERT INTO `data` VALUES (10630, 'B***成', 5, '外形外观：外观相对比较小巧，所以手感很不错\n屏幕音效：屏幕比较通透音质也还可以\n拍照效果：707的大底，莱卡的加持成片效果很不错，日常拍照完全够用\n运行速度：miui13修复了很多bug流畅性很好\n\n待机时间：虽然只有4500毫安的电池，但是续航能力很好\n其他特色：客服也很专业\n总的来说值得入手，日常体验不错', '白色', '2022-11-27 15:14:26', 1);
INSERT INTO `data` VALUES (10631, '肖***l', 5, '物流速度很快，第三天就收到手机了，而且旧机还能以旧换新，很不错呢！最重要的是价格还可以，性价比很高，虽然没有买到理想的黑色，但是蓝色款也很好看，清新淡雅的蓝色也挺适合我的。手机手感很好，很舒服，曲屏也很喜欢，总之非常满意的一次购物。', '蓝色', '2022-11-07 20:51:02', 3);
INSERT INTO `data` VALUES (10632, 'j***8', 5, '外形外观：惊艳好看绝绝子\n屏幕音效：双扬声器，度比音效嘎嘎好??\n拍照效果：莱卡相机绝绝子\n运行速度：很流畅\n待机时间：够用\n其他特色：小巧易携带使用', '白色', '2022-11-17 03:23:38', 2);
INSERT INTO `data` VALUES (10633, 'j***6', 5, '主要是小巧玲珑，手感真舒服，处理器很快，终于不热了。', '白色', '2022-07-27 07:54:03', 3);
INSERT INTO `data` VALUES (10634, 'c***0', 5, '该商品双十一买的，包装结实，物流快捷，价格实惠，用过了再来评价的，质量确实不错，而且很好用性价比很高，很好的东西，家人用了说很好，京东快递小哥配送也很快，很好很满意，期待以后多做活动更多优惠。全五星好评！', '紫色', '2022-12-19 20:26:35', 4);
INSERT INTO `data` VALUES (10635, '翼***光', 5, '外形外观：太喜欢小屏旗舰机的感觉了，看起来小巧\n屏幕音效：这种效果听起来太舒服了。\n拍照效果：试了一下原来莱卡的手机对比了一下，现在。小米的莱卡用起来更舒服。', '黑色', '2022-07-07 13:06:50', 5);
INSERT INTO `data` VALUES (10636, '蓝***军', 5, '小米12S手机大小刚刚好非常适合女孩子用，价钱又比小米官网便宜，还可以用旧手机抵押点钱，这个我认为非常好，旧手机又不浪费，旧手机要是丢了又污染环境回收了还抵押新手机钱！', '紫色', '2023-03-10 19:47:57', 3);
INSERT INTO `data` VALUES (10637, '小***1', 5, '外形外观：手感不错，大小不合适。很喜欢\n屏幕音效：很好，感应很好，玩游戏很好\n拍照效果：我对拍照就是个菜鸟，我个人觉得，很完美。\n运行速度：很快778处理器很好\n待机时间：不错，玩一天可以\n其他特色：小米手机很到位，保留了之前的3.5耳机，我很喜欢这一点。耳机口和充电器分开，很到位?', '子夜黑', '2023-01-02 07:35:06', 6);
INSERT INTO `data` VALUES (10638, 'h***h', 5, '小米note12pro极速版性能优异，配置丰富；屏幕显示细腻、真实、绚烂；摄像头像素高、数量多，成像效果清晰；手感舒服，做工精细，用料扎实；价格实惠，性价比非常高，推荐大家购买', '子夜黑', '2023-02-07 17:04:26', 7);
INSERT INTO `data` VALUES (10639, 'u***a', 5, '一直是小米的忠实用户，换手机必换小米手机，看了很多，综合考虑，入手note12pro极速版\n外形外观：外观轻薄，颜值超高\n屏幕音效：屏幕分辨率高，音效超好\n拍照效果：一亿像素，拍照清晰\n运行速度：运行速度快，流畅，游戏，刷视频不卡顿\n待机时间：待机时间长，充电时间短，很棒\n其他特色：颜值高，运行快，性价比超高，值得推荐\n京东物流配送快，今天买，明天到，快递小哥服务态度好，满意', '时光蓝', '2023-01-31 20:11:24', 7);
INSERT INTO `data` VALUES (10640, '洛***涌', 4, '运行速度：运行速度还是可以的，运行内存12个G，机身储存256个G，现在还可以\n屏幕音效：屏幕没有色差，屏幕显示非常的清晰，灵敏度也高音效质量也不错\n拍照效果：拍照的效果很好，很清晰，拍照和拍摄都很好\n待机时间：待机状态还是比较可以的，能用将近一天左右\n外形外观：外形外观都很好啊，手机的触感也很不错，挺大气的\n其他特色：其他的特色，NFC功能，刷公交卡以及小米健康，小米运动，其他的各个方面，还有CPUGPU，还有散热都还可以，特别特别要说的是充电功能特别棒', '微光绿', '2023-03-06 10:07:42', 2);
INSERT INTO `data` VALUES (10641, '楷***比', 5, '第一次买的小米品牌，看了很久这个了，买给长辈用的，整体来说还可以，充电速度很快，电池续航也挺满意的，流畅度也很不错', '子夜黑', '2023-01-16 14:34:04', 4);
INSERT INTO `data` VALUES (10642, '大***朵', 5, '外形外观：手感不错直板全屏手机。\n屏幕音效：支持120赫兹刷新率，上下两个扩音器，音量很大，颜色很正。屏幕清晰细腻。\n拍照效果：日常使用足够，不偏色，画面细节处理到位。\n运行速度：特地买的骁龙处理器，稳定速度快。日常使用不玩游戏足够。\n待机时间：正常使用一天还有40%电量。\n其他特色：电池容量大，充电速度快。运行速度挺快。性价比高。', '时光蓝', '2023-03-15 22:24:11', 6);
INSERT INTO `data` VALUES (10643, 'j***a', 5, '外形外观：漂亮，精致！好看！\n屏幕音效：声音很大，音效还凑合感觉，可能手机薄了就这样吧。\n拍照效果：像素很高照片逼真。日后到外面拍照再试试看，到底一亿像素好在哪里。\n运行速度：飞快目前是这样。\n待机时间：还不错吧。\n其他特色：待用一段时间再追加评论。', '时光蓝', '2023-01-01 18:32:11', 5);
INSERT INTO `data` VALUES (10644, '火***待', 5, '这手机外观相当美观，大气，屏幕大，音效良好，尤其拍照效果极好，速度极快，也正对应了板速版之说。早上手机坏了，中午时买的，下午就来了，物流速度没的说，真是一款性价比极高的好手机！', '子夜黑', '2023-02-22 17:39:37', 3);
INSERT INTO `data` VALUES (10645, '蜘***脚', 5, '外形外观：轻薄，漂亮，手感好\n屏幕音效：清晰，双喇叭\n拍照效果：三摄镜头很棒，效果非常好\n运行速度：速度快\n待机时间：待机时间长，充电快\n其他特色：不发热  质量好，家里人用的都是小米', '子夜黑', '2023-01-08 19:19:30', 5);
INSERT INTO `data` VALUES (10646, '韭***特', 5, '非常满意的手机，中端机，适合日常使用。美观、省电、好用、便宜。有出厂贴膜，有透明壳，到手即可使用，很省心。', '微光绿', '2023-02-24 07:52:35', 5);
INSERT INTO `data` VALUES (10647, '海***6', 5, '外形外观：轻薄身材、外观很漂亮\n屏幕音效：全面屏。\n拍照效果：很清晰。\n运行速度：运行很快。\n待机时间：一天充一次电，待机时间长。\n其他特色：直屏手机，67W快充', '子夜黑', '2023-01-04 17:04:35', 4);
INSERT INTO `data` VALUES (10648, '报***玲', 5, '手机非常好用。到手就调成简易模式，非常适合爸爸级别使用。字体又比较大图标也比较大，这个屏幕又比较护眼一点。所以说还是比较适合拿来爸爸妈妈用的，拍照1亿像素也很清晰。充电67w快处理器的话，嗯，刷抖音跟聊微信都还可以，也不会卡顿。反正配色也还好，都非常好。', '微光绿', '2023-03-12 20:01:18', 5);
INSERT INTO `data` VALUES (10649, '逆***6', 5, '已经买过七八个小米手机了，这次买了红米note12pro极速版，手机外观方正很漂亮，运行流畅，带了手机壳和屏幕膜，不用自己再买了。', '微光绿', '2023-01-03 15:50:49', 4);
INSERT INTO `data` VALUES (10650, '雅***华', 5, '外形外观：很棒，下巴也比较窄，小米的很多手机下巴都宽不好看，这个还挺好的。\n屏幕音效：oled这个价位还是可以的，性价比很高。\n拍照效果：可以\n运行速度：不错，小米的系统可以，优化一下，关掉广告好很多\n待机时间：可以\n其他特色：快充速度也都挺好的。', '子夜黑', '2023-02-24 09:22:37', 4);
INSERT INTO `data` VALUES (10651, 'M***g', 5, '外形外观：和外观很喜欢  特别是产品方方正正的外观绝对是这条街最靓的仔 哈哈而且这次的产品并不会很划手，这种外观设计理念也很符合贴近现在的年轻人\n屏幕音效：屏幕音效还可以吧  并不能要求这台机子像四五千 七八千或者一万多的机器有一样的音效，但整体感觉还是不错的，在同价位机器上 还是率胜一筹\n拍照效果：拍照效果很好  自带美颜功能 牛皮\n运行速度：刚买回来还可以，后续追评\n待机时间：待机时间还不清楚 今天没电后充满了感受下 这几天玩还是挺抗用的电量\n其他特色：摄像头也不错', '子夜黑', '2023-01-02 14:14:53', 4);
INSERT INTO `data` VALUES (10652, 's***i', 5, '新手机就是顺手好用，速度嘎嘎的，屏幕颜色还原度也不错，照片清晰度挺高的。手机样子好看，这个蓝色很鲜。', '时光蓝', '2023-01-08 22:18:45', 6);
INSERT INTO `data` VALUES (10653, 'h***r', 5, '这款手机颜值非常高，手感一流，精致简约，重量感刚刚好，屏幕很美观，色彩也很饱满。只是我拍照的手机是个老古董了，手机壳色彩实物比照片更柔和清爽。刚开机，还没有使用，以后在写体验感受。目前看，颜值满分?', '微光绿', '2023-01-11 18:15:50', 4);
INSERT INTO `data` VALUES (10654, '唐***8', 3, '无论材质还是做工都超出了预期，超值，穿起来也很好看哦。卖家发货也比预计提早了很多，还会再来。买吧，不会后悔的哦！全五分。', '时光蓝', '2023-03-14 13:55:17', 4);
INSERT INTO `data` VALUES (10655, '妖***娃', 5, '外形外观：漂亮 手感舒适\n屏幕音效：很好\n拍照效果：超棒\n运行速度：很快\n待机时间：观察中 67W充电快\n其他特色：棒棒的', '微光绿', '2023-01-09 16:09:32', 4);
INSERT INTO `data` VALUES (10656, '岁***寒', 4, '之前用的苹果11，以前也是小米的用户，几年没用发现小米的变化很大，严格的说是进步很大，性价比没得说，外观方方正正，边角我也看了严丝合缝，系统进步很大，骁龙778处理器比我预想的要快，游戏效果很不错，之前用苹果信号太差了，同样的卧室，苹果延迟小米就没有延迟。总得来说吧，这个价位这个手机闭眼入', '子夜黑', '2023-01-06 16:13:36', 3);
INSERT INTO `data` VALUES (10657, 't***8', 5, '看了好久选择了这款，系统流畅，外观设计很不错，配置也很高端，玩游戏，拍照什么完全满足了日常需求，很喜欢', '时光蓝', '2023-02-02 10:56:21', 5);
INSERT INTO `data` VALUES (10658, '清***-', 5, '外形外观：简约现代\n屏幕音效：画质细腻\n拍照效果：清洗逼真超高像素\n运行速度：刘畅不卡顿\n待机时间：一天一冲可以了\n其他特色：性价比高，?满意', '微光绿', '2023-01-04 20:16:41', 3);
INSERT INTO `data` VALUES (10659, '丑***怪', 5, '外形外观：轻轻薄薄，握感轻盈舒服，精致轻巧\n屏幕音效：OLED柔性直屏，显示细腻，非常好看。还有杜比视界全景声的立体音效，听音乐非常棒。\n拍照效果：光学防抖，让画面明亮，细节清晰.\n运行速度：高能效芯片，应付日常情况已经足够了。低功耗，续航优秀。\n待机时间：5000毫安电池，非常耐用。还有67瓦的快充，很好就充满电量。\n其他特色：还有多功能NFC.红外遥控，3.5mm耳机孔，IP53级防水，Wi-Fi6，X轴线性马达，立体声双扬声器。', '微光绿', '2023-01-01 10:32:22', 3);
INSERT INTO `data` VALUES (10660, '亦***心', 5, '性价比超级高，价格便宜，性能很优秀，样子也很漂亮，方方的感觉很好，屏幕很大，很清晰，送了充电器，很好用，太香了，太喜欢了', '子夜黑', '2023-01-27 22:13:24', 4);
INSERT INTO `data` VALUES (10661, '钢***琴', 5, '外形外观特别好看，有质感，适合男士使用。\n屏幕超清，刷新率高，好屏幕，音效也不错，扬声器效果很好。\n拍照效果非常不错，摄像头技术很成熟。\n运行速度很快。', '子夜黑', '2023-03-08 09:17:50', 3);
INSERT INTO `data` VALUES (10662, 'D***s', 5, '手机可太棒了，不愧是红米小钢炮，流畅性音质都特别的好，刚下载了王者吃鸡，都非常的流畅，一点都不掉帧，可太喜欢了', '微光绿', '2022-12-28 11:19:10', 1);
INSERT INTO `data` VALUES (10663, 'd***9', 5, '手机已收到，用着很好，家人很喜欢，运行速度也很快，充电速度也比其它款式手机快！！！！！！！！！！！！！！！！！！！！！！', '时光蓝', '2023-02-25 21:13:12', 6);
INSERT INTO `data` VALUES (10664, 'V***子', 5, '这款手机，还是挺好的，开机的速度很快，屏幕的显示也非常的棒，手机的颜值也很高。软件的打开速度也非常的不错。打游戏的也很好，是一款性价比非常高的手机。', '微光绿', '2023-02-08 15:47:46', 4);
INSERT INTO `data` VALUES (10665, 'k***g', 5, '外形外观：很大气雅致，很不错。\n屏幕音效：音响效果特别好。\n拍照效果：前置摄像头特别高，摄像功能强大\n运行速度：很不错。\n待机时间：很长。\nPS：充电极快。', '时光蓝', '2023-02-04 18:57:59', 3);
INSERT INTO `data` VALUES (10666, '哦***冉', 5, '收到货了好好用，而且颜色也很喜欢，今天充了一次电，充电特此快。，整体设计yyds，值得推荐～', '微光绿', '2023-03-09 09:46:50', 6);
INSERT INTO `data` VALUES (10667, '1***你', 5, '外形外观：手感不错，整体大气。\n屏幕音效：声音清晰有质感。\n拍照效果：拍照也进行了一步优化整体清晰。\n运行速度：运行速度非常流畅，具体的话还在测试中。\n待机时间：待机时间暂时看起来还是可以的。', '子夜黑', '2022-12-30 08:59:24', 3);
INSERT INTO `data` VALUES (10668, '木***n', 5, '外形外观：美\n屏幕音效：可以\n拍照效果：很好\n运行速度：快\n一直用小米的，它性能稳定，服务也很好，很周到，客服很好，有问有答，这个pro12极速版的，拍照?效果好，内存12G，运行速度快，储存卡256容量足够大，满意。发货速度也达到极速版了，前一天22点拍的，第二天十点就拿到了。总之很满意。', '子夜黑', '2023-02-08 09:32:11', 3);
INSERT INTO `data` VALUES (10669, 'J***-', 5, '真机到手还是蛮喜欢的，给长辈买的！系统流畅跟手，骁龙版红note12pro轻度游戏完全没问题，玩了一下午王者也并没有感觉机身发烫，拍照效果也清晰艳丽，性价比相当不错，反正我想要的功能它都有，红外，nfc，最最最重要的是还有3.5耳机接口，无论是游戏体验，拍照体验，还是续航体验基本满足我的使用需求了，家里换手机都首选小米！期待小米更好的产品，好把我小米11pro换掉！', '微光绿', '2023-02-09 14:48:21', 6);
INSERT INTO `data` VALUES (10670, 'r***m', 5, '外形外观：外形颜色新潮，手感很好\n屏幕音效：不错\n拍照效果：不错\n运行速度：快，爽', '微光绿', '2023-02-02 19:43:55', 4);
INSERT INTO `data` VALUES (10671, 'z***e', 5, '现在能够买到趁手的、2000元以下价位的手机，这可能是唯一的选择了。刚刚出的note 12 Pro，因为对处理器不满意，也不想买没有耳机插孔的k系列，以为今年就换不了手机了，没想到出了这个极速版，高通处理器还是不错的，非常轻薄，摄像头的设计也很高端，充电速度以及屏幕效果都非常满意。', '子夜黑', '2023-01-30 11:11:05', 4);
INSERT INTO `data` VALUES (10672, '海***f', 5, '运行速度很快，显示也很细腻，很轻薄，存电速度非常快，目前很满意。', '子夜黑', '2023-01-05 14:30:05', 2);
INSERT INTO `data` VALUES (10673, '繁***伤', 5, '手机很好看，绿色很清新，手感很好，轻巧细薄，很合手。67w快充，补电快，摆脱续航焦虑。赞??！', '微光绿', '2023-03-11 15:03:52', 4);
INSERT INTO `data` VALUES (10674, 'p***n', 5, '手机不错，系统挺流畅，电池够大，对我这种不玩游戏的人来说，简单刷个视频什么的完全够用了。保留了耳机插孔，这点很满意。几十块钱买个有线耳机比几百块钱买个蓝牙耳机使用效果强多了。', '子夜黑', '2023-03-12 19:35:41', 4);
INSERT INTO `data` VALUES (10675, '唐***8', 3, '无论材质还是做工都超出了预期，超值，穿起来也很好看哦。卖家发货也比预计提早了很多，还会再来。买吧，不会后悔的哦！全五分。', '子夜黑', '2023-03-14 13:55:09', 6);
INSERT INTO `data` VALUES (10676, '草***-', 5, '外形外观：很帅气\n屏幕音效：屏幕很大，声音很清晰\n拍照效果：拍照很漂亮\n运行速度：很流畅，非常喜欢\n其他特色：很有手感\n待机时间：给老人买的，很不错的', '子夜黑', '2023-01-12 14:39:42', 2);
INSERT INTO `data` VALUES (10677, '毕***运', 5, '最近几年只用国货手机，收到手机后立马拆开，很惊喜，杠杠滴  老红木也可以退休了     试用两三个小时感觉很不错 疫情期间  加上京东快递配送速度，必须得给个大大的赞', '时光蓝', '2022-12-31 15:08:45', 2);
INSERT INTO `data` VALUES (10678, 'c***5', 5, '外形外观：外观漂亮，颜色很正，摸起来很有质感\n屏幕音效：音效不错\n拍照效果：拍照效果清晰\n待机时间：待机时间正常使用一天充电一次', '时光蓝', '2023-03-04 12:22:27', 2);
INSERT INTO `data` VALUES (10679, 'j***b', 5, '外形外观：这颜值感觉是这个note系列最高的了，非常喜欢\n屏幕音效：音效这好家伙两边都有喇叭，听着非常舒服\n拍照效果：像素可以，这价格，这像素太强了\n运行速度：运行非常非常非常流畅五颗星\n待机时间：待机时间可以，充电也很快，67w超快充\n快递服务，没的说，五颗星，送货小哥辛苦了！！！！！', '微光绿', '2023-01-16 19:38:40', 2);
INSERT INTO `data` VALUES (10680, '星***3', 5, '手机颜值很高，是我喜欢的样子。手机荧幕十分清晰，做工不错，手握着很有感觉。手机功能方面音效很好、屏幕很清晰颜色正，手机运行相当快，应用之间的打开切换，没有卡顿。非常流畅，体验还是不错的。拍照效果也可以，很清晰。', '子夜黑', '2023-02-21 15:23:56', 3);
INSERT INTO `data` VALUES (10681, '半***影', 5, '外形外观：非常的大气，颜色也比较好看，非常符合我的购买预期，值得使用。\n屏幕音效：屏幕是属于比较清晰的那种，给妈妈用刚刚好。\n拍照效果：拍照效果不错，尤其是骁龙的芯片优化比较好。\n运行速度：运行速度快，同时开多个软件也不会卡顿。\n待机时间：待机时间比较长，使用很久还有电。', '时光蓝', '2023-01-05 20:20:46', 3);
INSERT INTO `data` VALUES (10682, 'g***9', 5, '手机用了几天，感觉很好，非常流畅，\n外形外观：外观精致，漂亮\n屏幕音效：顺畅\n拍照效果：拍照清晰\n运行速度：运行流畅', '微光绿', '2023-01-24 22:00:02', 3);
INSERT INTO `data` VALUES (10683, 't***a', 5, '手机屏幕大，很清晰，反正比我的iphone12pro清楚。男的一个手可以拿住，拍照是真清楚，现在手机都不错啊拍照，侧面指纹很灵敏，是可以按下去的物理按键带指纹识别的。安卓系统很快，升级到最新的MIUI了。国产手机就是功能特亲民，好用。出厂自带贴膜，送的手机壳。取卡针。总体来说，对得起这个价位了。当做备用机来用。非常满意。', '子夜黑', '2023-02-02 17:49:19', 2);
INSERT INTO `data` VALUES (10684, 'j***z', 5, '这个手机很不错，给老婆买的，骁龙778，平时不玩游戏，性能足够了，骁龙778处理器很省点，5000毫安电池应该可以用一天，相机也很好，足够平时用了，手机运行速度也很快！京东物流也很给力！', '子夜黑', '2023-02-26 09:49:02', 3);
INSERT INTO `data` VALUES (10685, 'C***p', 5, '手机很轻薄，电池也很大，充电速度也很快，给老爸买的，足够他用两年了，很不错，系统是MIUI14，很好用，拍照也很清晰，高像素给老爸拍照用', '子夜黑', '2023-01-17 22:12:07', 2);
INSERT INTO `data` VALUES (10686, '晨***c', 5, '轻薄好用\n外形外观：冷酷好看\n屏幕音效：屏幕清晰144高刷\n运行速度：很快最新系统\n好看好看好看好看好看好看好看好看', '子夜黑', '2023-01-12 19:17:10', 3);
INSERT INTO `data` VALUES (10687, 'j***2', 5, '超薄机身加上直边框超级精致，蓝色很高级哦。电池很耐用，音质嘎嘎好立体音，给父亲买的用着很好，刷视频打游戏完全没有问题。', '时光蓝', '2023-01-08 15:25:51', 3);
INSERT INTO `data` VALUES (10688, '长***1', 5, '给老人买的手机。快递还是一如既往的快。收到开箱之后首先感觉是这个手机比想象得要轻薄不少。手机的颜色很好看，三颗摄像头质感十足。屏幕显示非常好，声音也没的说。因为老人之前的手机就是小米的，使用小米换机非常方便，很快就完成全部数据的导入。', '微光绿', '2023-03-18 21:37:19', 4);
INSERT INTO `data` VALUES (10689, '享***阝', 5, '外形外观：美观，颜色靓丽，手感好\n\n屏幕音效：屏幕清晰，音质不错\n\n拍照效果：拍照效果好\n\n运行速度：运行速度超快\n整体性能非常好，1500元价位抗打之作', '时光蓝', '2023-01-03 18:13:17', 2);
INSERT INTO `data` VALUES (10690, 'u***5', 5, '1、宝贝收到啦，挺好用的，不卡，感觉挺喜欢的，下次推荐朋友也来买，各种功能不卡\n\n2、手机速度嗖嗖的，派送速度也不错。 整体比较满意呢。 背面是真的好看呀呀呀～\n\n3、拿回来用了，性能不错，电池耐用，声音挺大，音质不错，店家态度很好，很满意，好评。\n\n4、这个店老用户了，服务一如既往的好。物流速度给力！特别感谢客服樱桃耐心的导购\n\n5、手机收到了质量很好电池也很给力手机性能很好声音很大是一款很不错的产品', '时光蓝', '2023-01-05 14:29:19', 3);
INSERT INTO `data` VALUES (10691, 'H***H', 5, '外形外观：简约大气\n\n运行速度：打开软件速度很快，使用起来很顺畅，家人很喜欢。\n\n待机时间：大容量完爆以前的手机，使用一天没问题。\n\n其他特色：这个手机轻度游戏也是够了，现在的cpu性能对于绝大多数人都是溢出的，家里长辈用这个配置的手机是绰绰有余了，8g+256的配置用个三四年是没问题的。', '时光蓝', '2023-02-22 22:43:03', 2);
INSERT INTO `data` VALUES (10692, '风***m', 5, '外观好看，反应速度快，下单后第二天就收到了，\n屏幕音效：好\n拍照效果：拍照效果不错\n待机时间：充电很快\n其他特色：日常用应该够了', '子夜黑', '2023-02-19 11:45:30', 2);
INSERT INTO `data` VALUES (10693, '沙***女', 5, '手机很好喔，拍照清晰度高，待机时间又长，已经用上了', '子夜黑', '2023-01-08 22:29:14', 5);
INSERT INTO `data` VALUES (10694, 'j***k', 3, '妇女节活动时买的，没想到活动结束可降价了，这是什么销售模式？申请了保价，手机外观很满意，电池的话一天一充。期待后期好用吧', '微光绿', '2023-03-16 22:42:59', 3);
INSERT INTO `data` VALUES (10695, 'j***p', 5, '快递晚上买的转天就到了，100格电到晚上还能剩20格，待电不错不知道因为什么之前视频停不到声客那也解决了总体停好物流很快，物品完好无损，用起来很舒服，喜欢?', '时光蓝', '2023-01-09 16:09:24', 6);
INSERT INTO `data` VALUES (10696, 'j***8', 5, '红米Note 12 Pro屏幕很大，很清晰，操作便捷，上下都有声音口，音效很棒，运行速度很快，反应很灵敏，拍照和续航也都很满意，快充很快，太满意了。', '子夜黑', '2023-01-19 22:19:32', 2);
INSERT INTO `data` VALUES (10697, 'b***t', 5, '屏幕效果：好 运行速度：快 外形外观：漂亮 尺寸大小：刚好。待机时间长，重量，也刚好，不压手，物流快，性价比很高', '子夜黑', '2023-01-03 13:02:26', 3);
INSERT INTO `data` VALUES (10698, 'j***g', 5, '外形外观：很不错，典雅大方\n屏幕音效：不错，声音清晰\n拍照效果：很好，在这个价位里属于不错的了\n运行速度：也挺好的，目前来说比较快\n待机时间：短，非常给力\n给老爸买的，据他说是挺不错的', '子夜黑', '2023-01-04 08:40:19', 2);
INSERT INTO `data` VALUES (10699, 'y***g', 5, '绿色版本很漂亮， 很惊艳，非常的轻薄， 真的很漂亮。 双扬声器，非常好，屏幕细腻。高通的骁龙 778G的处理器很棒 很好，5000毫安大电量， 67瓦的快充也很棒。', '微光绿', '2022-12-29 13:15:06', 2);
INSERT INTO `data` VALUES (10700, '朕***朕', 5, '物流很快，物品完好无损，用起来很舒服，喜欢?产品包装精致美观大气，目前用着非常不错，真实评价，希望可以帮到集美们', '子夜黑', '2023-01-09 07:18:05', 5);
INSERT INTO `data` VALUES (10701, 'i***b', 5, '待机时间长，用着很流畅。实机挺好看的，一直用小米手机，老米粉了。', '子夜黑', '2022-12-31 16:45:26', 5);
INSERT INTO `data` VALUES (10702, 'H***子', 5, '外形外观：外观上带一点直框的 这一点设计真心喜欢的\n屏幕音效：屏幕音效很不错\n拍照效果：拍照清晰明了成像也不错\n运行速度：蛮流畅', '子夜黑', '2023-02-06 21:47:34', 3);
INSERT INTO `data` VALUES (10703, 'j***m', 5, '外形外观：轻巧，\n屏幕音效：立体声效，音乐听觉好。\n拍照效果：好，夜景很清析。\n运行速度：不错。\n待机时间：长。', '微光绿', '2023-01-05 19:30:41', 1);
INSERT INTO `data` VALUES (10704, '飞***4', 5, '拍照效果：试了下像素，确实是非常清晰，买对了\n外形外观：好\n屏幕音效：好\n运行速度：流水席\n待机时间：可以', '微光绿', '2023-03-08 14:38:35', 2);
INSERT INTO `data` VALUES (10705, '由***身', 5, '手机很好用，基本没有什么短板，骁龙778g老神u了十分稳定，耳机孔nfc指纹解锁红外快充大电池应有尽有，买给老爸用很合适', '微光绿', '2023-01-01 08:33:17', 3);
INSERT INTO `data` VALUES (10706, '尒***麻', 5, '外形外观：好看\n屏幕音效：不错\n拍照效果：很好\n运行速度：不卡\n待机时间：不错\n其他特色：重量轻，方便携带', '时光蓝', '2023-02-16 14:33:39', 1);
INSERT INTO `data` VALUES (10707, 'j***H', 5, '京东快递使命必达，说几号就几号，服务态度也超赞，宝贝很好，包装严实，新款手机拿在手里瞬间高大上，系统运行流畅。一键倒换数据。', '子夜黑', '2022-12-31 17:53:28', 4);
INSERT INTO `data` VALUES (10708, '树***蟹', 5, '性价比很高！超值版5g手机！值得购买！\n外形外观：时尚\n屏幕音效：环绕\n拍照效果：像素高\n运行速度：快', '子夜黑', '2023-03-07 11:44:04', 2);
INSERT INTO `data` VALUES (10709, '何***1', 5, '好的，实用，漂亮手感好，运行快，音质超好。给五星好评。而且照相非常清色。', '子夜黑', '2023-03-20 17:49:46', 3);
INSERT INTO `data` VALUES (10710, '是***啊', 5, '给家里人买的，主要需求有两点，屏幕好，电池大，1899的价格，非常轻薄，蓝色也非常好看，红米不错', '时光蓝', '2023-01-12 19:57:19', 4);
INSERT INTO `data` VALUES (10711, '爱***噶', 5, '目前家里有六部小米手机在用，大家都很喜欢，系统很流畅，硬件配置均衡。功能也比较全面，这款新买的非常喜欢。', '微光绿', '2022-12-29 15:18:47', 3);
INSERT INTO `data` VALUES (10712, 'j***i', 5, '手机一打开，就被惊艳到了。外观漂亮，颜色也比较清凉，哈哈。运行很快，还在摸索中，还不错。', '时光蓝', '2023-01-11 19:22:20', 3);
INSERT INTO `data` VALUES (10713, '爱***鱼', 5, '价格实惠，质量杠杠的，非常好的一次购物，下次还来性价比很高，很实惠，使用起来感觉很好，非常完美.^?^.物流超级超级快！质量也非常不错，的确物有所值?超级好用！还很美观！墙裂推荐！有需要再回购！很好看，制作工艺很精美，材质也很好！给个赞！', '子夜黑', '2023-02-15 00:04:07', 4);
INSERT INTO `data` VALUES (10714, 'j***n', 5, '由于新品外地调好货，物流比平时稍稍慢了两天，但货物到货后内外包装还是很好的。手机拆封来到外观颜色也很值喜欢，绿色很清新，大功率快充也不错，系统运行也很流畅。算是一次不错的购物体验。', '微光绿', '2023-01-12 21:28:15', 4);
INSERT INTO `data` VALUES (10715, 't***s', 5, '给父母买的，屏幕够大，看文字清晰。电池容量大，耐用，67w的充电速度也很快。用了几天没啥毛病。', '子夜黑', '2023-01-03 12:39:38', 3);
INSERT INTO `data` VALUES (10716, 'j***q', 5, '外形外观：很好看\n屏幕音效：很好\n拍照效果：很好\n运行速度：很好\n都很好', '微光绿', '2023-01-10 15:58:55', 3);
INSERT INTO `data` VALUES (10717, 'j***8', 5, '手机收到，已经给妈妈用了好一段时间了，妈妈反馈很不错，很喜欢，很流畅，比之前手机快多了，充电也快，另外京东物流是真的快，大件，贵重物品还就相信京东，哈哈', '时光蓝', '2023-02-24 16:18:47', 3);
INSERT INTO `data` VALUES (10718, '记***i', 5, '很好，很不错，续航时间都可以，推荐使用哦，外观也很好看，屏幕也非常好，音效也非常好，拍照效果非常清晰，运行速度也很快，拿着也很方便，推荐。', '子夜黑', '2023-02-19 04:02:45', 2);
INSERT INTO `data` VALUES (10719, '黄***戈', 5, '拍照效果：挺好\n外形外观：好看\n待机时间：耐用\n运行速度：很快\n其他特色：用了好几天了，感觉非常不错', '时光蓝', '2023-02-01 18:01:07', 1);
INSERT INTO `data` VALUES (10720, 'j***x', 5, '外形外观：时尚简约\n屏幕音效：很棒\n拍照效果：很棒\n运行速度：很快', '微光绿', '2023-01-18 19:00:00', 3);
INSERT INTO `data` VALUES (10721, '1***d', 5, '性能和外观都很棒，手感佳，正常使用续航两天，各APP运行流畅，配的充电器充电超快，拍照像素及功能也OK，内存可另扩展5G，性价比蛮高的。', '子夜黑', '2023-01-06 09:54:02', 2);
INSERT INTO `data` VALUES (10722, '消***堂', 5, '物流速度快，当天下单当天到手，外观大气上档次，屏幕清晰，声音大，老人很喜欢', '子夜黑', '2022-12-31 13:50:21', 4);
INSERT INTO `data` VALUES (10723, 'E***本', 5, '目前还买不到对应极速版的手机壳，256G内存也非常够用了，上一部8pro用了3年了，这部12pro的拍照有了质的变化。', '子夜黑', '2023-01-05 14:23:33', 3);
INSERT INTO `data` VALUES (10724, 'd***6', 5, '手感不错 屏幕显示清晰 外观颜色很漂亮 拍照很棒 音质很好 立体声双扬声器  软件更新速度很快 。昨天才发布的 今天就拿到新机了。', '微光绿', '2022-12-28 14:01:47', 2);
INSERT INTO `data` VALUES (10725, '悦***江', 5, '外形外观：颜值不错；\n屏幕音效：屏幕显示很亮眼，音效过得去；\n拍照效果：拍照效果好，功能强大\n运行速度：目前非常顺畅', '子夜黑', '2023-03-18 12:04:02', 1);
INSERT INTO `data` VALUES (10726, '乐***0', 5, '买给家人用的，骁龙778G性能比天玑版本好很多，非常适合家里需求不高的人使用，主摄白天也有不错的成像体验，预装的MIUI14非常流畅，这块OLED屏幕显示效果也非常惊艳，完全不像千元机。', '子夜黑', '2023-01-05 14:44:55', 3);
INSERT INTO `data` VALUES (10727, 'j***b', 5, '爸爸妈妈很喜欢，拍照也很清晰，音质也可以，买了一个大内存的，希望用两三年也不会卡', '子夜黑', '2023-01-14 18:48:33', 3);
INSERT INTO `data` VALUES (10728, '想***香', 5, '非常好看的手机，颜值很高。\n运行内存也很大，储存空间也大，可以装很多照片。\n手感轻盈，视野清晰，非常赞。', '时光蓝', '2023-02-21 16:47:02', 3);
INSERT INTO `data` VALUES (10729, '涛***5', 5, '运行速度：无卡顿，特别顺畅\n外形外观：美观大方\n屏幕音效：效果特别好\n拍照效果：特别清楚', '时光蓝', '2023-02-19 18:16:21', 2);
INSERT INTO `data` VALUES (10730, 'V***雪', 5, '这款手机挺不错的，拍摄效果非常不错，手机速度也很快，256的内存给爸爸用足够了！6寸的屏幕，用起来很舒服，屏幕分辨率对眼睛也友好！整体感觉不错。', '子夜黑', '2023-01-11 17:38:00', 2);
INSERT INTO `data` VALUES (10731, 'm***d', 5, '公司需要购买一台备用机，对比了几个牌子，最后还是选了这款，机型新，配置高，价格实惠，性价比很高，收到后试用了一下，系统流畅，操作灵敏，非常满意，好评！', '子夜黑', '2023-02-11 11:16:49', 3);
INSERT INTO `data` VALUES (10732, 'j***J', 5, '咱这京东物流就是没说的。大年初一早上的订单，特意订了京准时，结果真是准时。真的是很不错！一次买了两部手机，老妈老爸很喜欢！经济实惠能用几年没问题。外观好看。颜色也好看，手感不错，老人用屏幕也不错！', '时光蓝', '2023-01-22 20:22:30', 2);
INSERT INTO `data` VALUES (10733, 'j***d', 5, '屏幕音效：非常喜欢\n外形外观：很好看很喜欢\n拍照效果：非常喜欢这个手机很好很好用\n运行速度：很nice非常的漂亮\n哈哈哈哈哈哈', '子夜黑', '2023-01-31 17:53:25', 2);
INSERT INTO `data` VALUES (10734, 'm***儿', 5, '这款极速版，特别轻巧，拿着很舒服，用起来很流畅，不卡顿，反应也快，外观也挺好看的，一直比较相信京东自营的电子产品，比实体店便宜，东西也好。', '时光蓝', '2023-03-04 12:10:23', 2);
INSERT INTO `data` VALUES (10735, '白***轩', 5, '对于经常玩手机的父亲大人来说OLED屏不怕眼疲劳啦\n\n前置摄像头自带美颜效果真的是不错\n\n自带的杜比全景声音色听周董的歌也很不错\n\nwifi6联网也比之前用的手机更快更稳定了手机配色也很清新\n\n而且MIUI系统真的太丝滑了\n\n办公商务内存和电量也妥妥哒!性价比超高!', '子夜黑', '2023-02-09 22:33:49', 2);
INSERT INTO `data` VALUES (10736, '黄***8', 5, '物流非常快，昨天晚上下单，今天上午就收到了。买了给老妈用的，非常漂亮，屏幕清晰，****40分钟就将旧手机都数据都迁移了。还送了保温杯和伞，老妈非常喜欢！', '时光蓝', '2022-12-30 18:48:52', 3);
INSERT INTO `data` VALUES (10737, 'D***x', 5, '外形外观：好看，拿到手的手感比想象中要好很多\n运行速度：目前没有出现卡顿现象，还是比较顺畅的', '子夜黑', '2023-02-22 10:06:36', 2);
INSERT INTO `data` VALUES (10738, '7***0', 5, '是正品，信赖商家，宝贝质感很好，价格也适中，无限回购！\n?是正品，跟商店里买的是一样的，在这网购方便快捷，品质放心，还会光顾！.^?^.', '子夜黑', '2023-01-30 10:54:05', 2);
INSERT INTO `data` VALUES (10739, 'r***7', 5, '买给老妈用的，速度很快，音量也大，屏幕看起来很舒服，已经用过一段时间了，效果不错?，客服服务有耐心，解答详细，赞一个。', '时光蓝', '2023-02-13 21:09:40', 2);
INSERT INTO `data` VALUES (10740, '波***佛', 5, '机身大小正好，像素高，外观美丽，音效清晰，运行速度超快，黑色很正，帅气，物流也很快，给力', '子夜黑', '2023-03-04 23:15:31', 3);
INSERT INTO `data` VALUES (10741, 'j***l', 5, '运行速度：不错，完美购物\n屏幕音效：很好，很不错\n外形外观：漂亮', '微光绿', '2022-12-31 20:39:39', 3);
INSERT INTO `data` VALUES (10742, '遇***份', 5, '手感特别舒服，是双扬声器的，一亿像素，充电也很快，5000毫安大电池可以用一天', '微光绿', '2023-02-23 15:52:08', 4);
INSERT INTO `data` VALUES (10743, 'u***z', 5, '外形外观：非常好看\n屏幕音效：显示清晰音效杠杠的\n拍照效果：不错\n运行速度：很快', '时光蓝', '2023-01-09 11:38:57', 3);
INSERT INTO `data` VALUES (10744, 'j***s', 5, '小米手机家里人手一台，就是看中的小米手机性价比高。这款极速版，手感轻巧，使用顺畅，屏幕的色彩感觉很好，67W快冲速度快，电池使用时间长。', '子夜黑', '2023-02-16 19:43:29', 2);
INSERT INTO `data` VALUES (10745, '未***我', 5, '拍照效果：一亿的像素，拍照效果很不错的，性价比也比较高。\n运行速度：运行速度快，不卡\n待机时间：待机时间没试过，正常使用一天冲电足够', '子夜黑', '2023-02-28 16:58:17', 1);
INSERT INTO `data` VALUES (10746, '每***梦', 5, '两千块的手机很值了，系统很流畅，机身也很轻薄，用了一段时间觉得物有所值', '时光蓝', '2023-01-31 23:23:35', 4);
INSERT INTO `data` VALUES (10747, 'd***h', 5, '刚找了份工作，为了以后的工作方便顺利我就选择了这款手机，还送了保温杯和雨伞，挺好的，手机是清新的绿色，保温杯是白色，很好了，买的时候就为了以后工作方便所以存储买了大的，用了几天还不错很顺手', '微光绿', '2023-01-05 13:12:08', 3);
INSERT INTO `data` VALUES (10748, '圣***咯', 5, '昨下午纠结在买手机的时候，发现新出的note12pro极速版，看价格、配置都很划算，果断下单。京东这物流速度是真快，昨晚下的单早上就到了。拆开手机包装后，手机样式是真好看，爱不释手，今天试用了一天，一个字棒。', '子夜黑', '2022-12-28 23:21:48', 4);
INSERT INTO `data` VALUES (10749, 'k***n', 5, '很不错的一款手机，性价比很高，重量也可以，如果厚度再薄一些会更好，原装miui 14系统，用起来很流畅，价格比官网便宜。', '时光蓝', '2023-01-13 09:52:29', 3);
INSERT INTO `data` VALUES (10750, 'u***k', 5, '手机反应灵敏，上网无卡顿，外观很时尚，跟爱人买的，她非常满意。', '微光绿', '2022-12-30 21:24:00', 1);
INSERT INTO `data` VALUES (10751, '酸***_', 5, '微光绿   12+258\n活动的时候买滴价格是1999，直角边我拿着非常舒服，今天拿到手之后还和我的小米平板互联了一下延迟微小，拍照的话也就那样子，玩游戏画质很清晰，再用一段时间看看', '微光绿', '2023-01-11 22:56:48', 3);
INSERT INTO `data` VALUES (10752, 'f***o', 5, '字体够大，显示清晰，声音够大，爸爸很喜欢。预装MIUI14，旧的note9可以退休啦！', '子夜黑', '2023-01-28 11:52:49', 2);
INSERT INTO `data` VALUES (10753, 'A***安', 5, '不玩手机游戏，也过了拉风要面子的年纪，所以这几年一直用小米手机，感觉是性价比最高的手机，同等配置下比某某国产更亲民，完全满足日常生活所需。运行流畅，摄像头像素也完全满足日常拍摄，小米越来越好', '时光蓝', '2023-02-05 13:01:21', 4);
INSERT INTO `data` VALUES (10754, '徐***睿', 5, '不得不说，以前的小米\n现在的红米，性价比还是很高的\n首发一次性买了4部，送给家里长辈用\n还是很不错哦！\n性能可以的！给力！', '时光蓝', '2022-12-30 18:22:13', 5);
INSERT INTO `data` VALUES (10755, '1***1', 5, '挺好的，比现在用的红米9pro要轻。\n反应速度也挺快的。充电贼快。续航也很好。', '子夜黑', '2023-01-13 13:38:26', 2);
INSERT INTO `data` VALUES (10756, 'j***u', 5, '非常漂亮的手机，外观平滑，颜色美观，大电量，轻薄手感好，屏显非常细腻，很满意的手机', '微光绿', '2023-01-09 18:44:58', 3);
INSERT INTO `data` VALUES (10757, 'w***8', 5, '机器沉甸甸的用料足，外观大气，屏幕色彩艳丽，拍照清晰，颜色正\n价格实惠，很有性价比', '子夜黑', '2023-03-13 16:10:27', 3);
INSERT INTO `data` VALUES (10758, 'l***g', 5, '东西很棒的，屏幕很不错，手感也是很好，拍照像素很高，还带手机壳呢，真的是很方便，物流也是非常快早上下单晚上收很棒', '子夜黑', '2023-03-09 16:44:59', 2);
INSERT INTO `data` VALUES (10759, '齐***了', 5, '外形外观：好看实用\n拍照效果：清晰质感\n其他特色：顺畅不卡顿\n给家里老人用的，品质ok，用起来也很丝滑，推荐', '时光蓝', '2023-01-04 08:50:21', 1);
INSERT INTO `data` VALUES (10760, 'k***c', 5, '好评！！在京东上搜索了两天最终决定买了这款RedMI12pro手机，小米旗舰机上中高档了买不起了，用了几天后发现这款红米12pro手机真的不错，外形外观好看，手感也好，屏幕效果很好，运行速度很快，待机时间也长，充电速度很快。很满意。', '子夜黑', '2023-02-05 15:12:20', 3);
INSERT INTO `data` VALUES (10761, 'j***t', 5, '红米note12pro极速版已经使用了几天，非常好，画面清晰使用流畅，电池也给力。已经连续用了四部红米手机，性价比不二选择', '子夜黑', '2023-01-05 16:36:42', 3);
INSERT INTO `data` VALUES (10762, 'g***a', 5, '细节非常完美，整体来说真的很不错。778G处理器稳定。拍照不错，送的东西也很实用。红米性价比就是高。', '微光绿', '2023-01-07 10:49:06', 3);
INSERT INTO `data` VALUES (10763, '吕***花', 5, '手机用了十几天来评价，谈谈使用效果：速度很快，颜色柔和，音效好，功能很全，买的很值，值得推荐。', '时光蓝', '2023-01-17 15:40:40', 3);
INSERT INTO `data` VALUES (10764, '宛***6', 5, '手机收到了，质量很好，外观大气，比想象的好商品质量不错，细节、品质、做工都非常好，发货贼快，快递也给力，棒棒哒~???', '时光蓝', '2023-01-15 18:59:26', 2);
INSERT INTO `data` VALUES (10765, 'A***D', 5, '送货速度超级快。手机外观漂亮，拍照效果明显，照片清晰度高。没玩游戏，手机打开网页秒开。', '微光绿', '2023-01-28 11:53:34', 2);
INSERT INTO `data` VALUES (10766, '天***爱', 5, '精挑细选很久?，最后决定买这一款?，到货后果然没有让我失望，实物很漂亮?，做工很精细?，特别满意?东西比我想象中的还要完美，十分给力，值得入手', '时光蓝', '2023-01-06 19:55:37', 2);
INSERT INTO `data` VALUES (10767, 'j***a', 5, '红米出的新手机很好用，买给老人用的，流畅字也大声音大，120HZ刷新率看起来眼睛也不会痛，送了杯子和雨伞，用起来超棒', '子夜黑', '2023-01-05 11:54:33', 2);
INSERT INTO `data` VALUES (10768, 'a***g', 5, '一如既往选择京东自营购物，快递就是快、准时。\n手机的外观中规中矩，音效也清晰，拍照是买点，效果如描述的一样，整机运行流畅，这个价钱超值。\n五星好评！', '子夜黑', '2023-01-02 20:43:52', 3);
INSERT INTO `data` VALUES (10769, '勇***2', 5, '使用\n外形外观：好看 冷暖效果：制冷效果很好 静音效果：声音很小 节能省电：很省。\n屏幕音效：不次眼\n拍照效果：晰 \n运行速度：可以\n待机时间：够长\n其他特色：音质不错', '微光绿', '2023-02-04 08:54:54', 3);
INSERT INTO `data` VALUES (10770, 'u***x', 5, '手机用着很顺畅，外形很酷，屏幕清晰，拍照效果很好，运行很快，电池耐用，值得推荐！', '时光蓝', '2023-01-14 17:48:21', 2);
INSERT INTO `data` VALUES (10771, 'j***8', 5, '形外观：轻轻薄薄，握感轻盈舒服，精致轻巧。\n屏幕音效：OLED柔性直屏，显示细腻，非常好看。还\n有杜比视界全景声的立体音效，听音乐非常棒。\n拍照效果：索尼IMX766传感器和OIS光学防抖，让画面\n明亮，细节清晰。\n运行速度：天玑1080高能效芯片，应付日常情况已经\n足够了。低功耗，续航优秀。\n待机时间：5000毫安电池，非常耐用。还有67瓦的快\n充，很好就充满电量。\n其他特色：还有多功能NFC,红外遥控，3.5mm耳机孔，IP53级防水，Wi-Fi6，X轴线性马达，立体声双扬声器。', '子夜黑', '2023-01-27 10:54:41', 2);
INSERT INTO `data` VALUES (10772, 'C***E', 4, '直角边框加大机身让手感极其 十分 特别 非常差劲！还有大塑料机身一言难尽 好在是带壳用的。除了这两点在这个价位都挺满意 防杠：米1老粉', '时光蓝', '2023-02-04 20:01:31', 2);
INSERT INTO `data` VALUES (10773, '波***s', 5, '很好用的机器 轻巧 实惠 对性能没有太大要求所以我感觉够用了 电池容量蛮大续航不错', '子夜黑', '2023-01-05 14:12:22', 3);
INSERT INTO `data` VALUES (10774, '明***见', 5, '屏幕大小合适。用着反应速度快，整体可以。最新的系统，电池耐用，。很好的手机，值得购买，。', '微光绿', '2022-12-30 15:59:07', 2);
INSERT INTO `data` VALUES (10775, '活***风', 5, '手机质量不错，运行也很，给老爸买的，老爸小米6都用了好多年了，换了之后特别开心，京东物流也很给力，很快快到了', '时光蓝', '2023-01-04 14:09:59', 4);
INSERT INTO `data` VALUES (10776, 'j***6', 5, '外形外观：简单大气\n屏幕音效：物有所值\n拍照效果：堪比11\n\n运行速度：完全可以比得上小米11手机', '微光绿', '2023-03-14 23:26:00', 1);
INSERT INTO `data` VALUES (10777, '取***啊', 5, '手机很轻 外观很漂亮 买个老年人用挺合适的 价格各方面都合适 系统直接是miui14 边框挺窄的', '子夜黑', '2023-01-01 17:28:30', 2);
INSERT INTO `data` VALUES (10778, '5***y', 5, '趁着活动入手划算，发货快，包装得好，非常不错，全新体验，赞赞赞！小米手机亲民的价格，高级的配置。很喜欢。', '时光蓝', '2023-02-20 11:13:36', 4);
INSERT INTO `data` VALUES (10779, '伊***1', 5, '不错?，配送很快，机器也哇塞，比较轻便，运行也流畅，超出预期。还可以适配不同类型的图标，纪念一下我用了四年的smartisan os', '子夜黑', '2022-12-30 12:02:45', 1);
INSERT INTO `data` VALUES (10780, 'G***H', 5, '这是在京东上第二次买手机，因为第一次买手机，的质量和性价比都和实体店是一模一样的，而且价位要比实体店便宜很多，所以我这次又在京东上选了第二款手机，拍照效果特别的清晰，外形这个红米12 Pro也是我喜欢的样子，总的来说，红米的手机性价比特别高，支持红米，会一直关注京东。', '时光蓝', '2023-02-22 21:01:32', 4);
INSERT INTO `data` VALUES (10781, 'j***0', 5, '比较轻薄，性价比很高，整体成像不错，充电很快，日常使用够用了！', '子夜黑', '2023-01-12 12:48:02', 3);
INSERT INTO `data` VALUES (10782, 'j***3', 5, '挑选了很久型号，发现这个很合适，对比各个平台价格，京东是最实惠的，果断入手了，第二天就到了，使用体验非常棒，推荐推荐~', '微光绿', '2023-03-01 20:32:56', 2);
INSERT INTO `data` VALUES (10783, '你***乐', 5, '一直喜欢京东自营，送货速度很快。品质有保障。最喜欢的就是送货速度很快。手机好用，经常用小米红米手机日常使用加玩一部分游戏没有问题好评！', '微光绿', '2023-03-09 12:37:04', 4);
INSERT INTO `data` VALUES (10784, '久***头', 5, '外形外观：很漂亮，很惊艳，很美好，真的很漂亮。\n屏幕音效：双扬声器，非常好，屏幕细腻。有一点缺点，\n拍照效果：很好，三摄镜头很棒\n运行速度：天玑1080的处理器很棒\n待机时间：很好，充满电之后5000毫安时得容量，待机可以很久，67瓦的快充也很棒。\n其他特色：手机屏幕好大啊，手感很棒，很轻薄。', '子夜黑', '2023-01-03 04:06:37', 2);
INSERT INTO `data` VALUES (10785, '浮***i', 5, '小米手机一直在用，红米手机更是性价比首选，这次给家人换手机，又是选择了红米，挑定note12pro极速版，看中的是首发和骁龙处理器，120hz的高刷新率真是清晰惊艳，首发miui14更是流畅的一如既往，外壳没有拍上，也是颜值在线，家里人很满意。米粉冲就完事了~', '时光蓝', '2023-01-16 18:47:49', 2);
INSERT INTO `data` VALUES (10786, 'j***y', 3, '外观还是有点大了，我不打游戏电也只能管个一天，总体都一般吧能用，相素还是可以，拍风景挺好看。', '微光绿', '2023-03-20 14:23:57', 1);
INSERT INTO `data` VALUES (10787, '尹***_', 5, '给老妈买的，顶配，用起来也比较流畅，老人也很喜欢。\n外形外观：好看，正面也比较惊艳，屏占比很高。\n屏幕音效：老人觉得还不错，亮度还可以。\n拍照效果：这个感觉还可以，摄像头挺多。\n待机时间：很满意，充电也很快。\n运行速度：很流畅，正常用不打游戏肯定没问题。', '微光绿', '2023-01-25 10:26:36', 2);
INSERT INTO `data` VALUES (10788, '问***子', 5, '内存大，像素高，孩子很喜欢，质量不错。内存大，像素高，孩子很喜欢，质量不错。内存大，像素高，孩子很喜欢，质量不错。', '时光蓝', '2023-02-16 07:48:01', 2);
INSERT INTO `data` VALUES (10789, 'j***9', 5, '外形外观：轻薄，时尚，美观，大方\n屏幕音效：柔性直屏，显示细腻，杜比视界全景声的立体音效，追剧、听音乐都很棒\n拍照效果：IMX766传感器，让画面很清晰\n运行速度：天玑1080芯片，处理日常情况足够\n待机时间：5000毫安电池，耐用，67瓦快充，', '子夜黑', '2023-01-04 10:14:35', 2);
INSERT INTO `data` VALUES (10790, 'L***5', 5, '外形外观：外观时尚大方，很漂亮。\n屏幕音效：很好。音效很棒，单放好听。\n拍照效果：效果很好，清晰，色泽艳丽夺目。\n运行速度：目前运行速度很快。不知旧了如何。\n待机时间：可以一天\n其他特色：快充半小时即满。', '微光绿', '2023-01-26 04:05:31', 2);
INSERT INTO `data` VALUES (10791, '_***_', 5, '其他特色：给家里人买的，这个67W充电速度是真的快啊，比预期的效果还要赞，很赞！超级喜欢！', '时光蓝', '2023-01-21 20:12:45', 3);
INSERT INTO `data` VALUES (10792, 'j***p', 5, '非常好，价格实惠，反应快，使用中没有发热，值得购买', '时光蓝', '2023-02-02 13:01:26', 6);
INSERT INTO `data` VALUES (10793, '有***Q', 5, '感觉很不错，续航久，充电快，玩游戏也不发热，处理器运行也给力', '时光蓝', '2023-01-05 12:25:30', 2);
INSERT INTO `data` VALUES (10794, 'k***C', 5, '手机在京东购买一直很放心 这次给家里父母买这款 充电快续航长 屏幕素质不错 处理器也够用。总的来说很满意。小米还送了保温杯和雨伞 性价比很高。用了一段手机也不卡顿。', '时光蓝', '2023-01-05 11:48:42', 3);
INSERT INTO `data` VALUES (10795, '我***忌', 5, '宝贝收到咯??，真的很棒呀！?质量真是没话说，非常满意！?开心开心?物流速度真的是没话说，就是一个字：快。商品从外包装来看非常高档，真是一分钱一分货，贵有贵的道理', '微光绿', '2023-01-26 17:11:08', 3);
INSERT INTO `data` VALUES (10796, '苑***0', 5, '手机外观很漂亮，运行也很流畅，免电挺快的，总体感觉不错。', '微光绿', '2023-01-05 12:52:55', 3);
INSERT INTO `data` VALUES (10797, 'j***H', 5, '哇！收到手机的那一刻心里那是一个激动啊，特别喜欢，上手感非常好，快递也很快，其次客服小姐姐的热情服务令我非常满意，有问题回复也挺快，支持，以后改为小米粉喽！', '时光蓝', '2023-03-19 06:32:27', 2);
INSERT INTO `data` VALUES (10798, '小***士', 5, 'A***-\nPLUS会员\n\n很漂亮， 很惊艳，很美好， 真的很漂亮。 双扬声器，非常好，屏幕细腻。有一点缺 很好，三摄镜头很棒 天玑1080的处理器很棒 很好， 充满电之后5000毫安时得容量， 待 ，67瓦的快充也很棒。 手机屏幕好大啊，手感很棒，很轻薄。', '时光蓝', '2023-01-13 12:25:37', 3);
INSERT INTO `data` VALUES (10799, '香***苑', 5, '外形外观：没的说，真的特别好看。\n屏幕音效：屏幕也不错呀。直屏打游戏可以。\n拍照效果：可以的，很清晰。\n运行速度：没有运行多个游戏，还在体验中。\n待机时间：很长，我还没充过电。\n其他特色：直屏手机，对于我来说就是大了点，要是能有6英寸我简直是超级爱你了。', '时光蓝', '2023-02-22 17:11:31', 9);
INSERT INTO `data` VALUES (10800, 'j***h', 5, '给老妈买的  屏幕大  字体清晰  第一次购买小米的手机  初步拆开以后感受还是不错了  系统很流畅  小米的东西品质还是不错的  所以很多东西都买小米的', '时光蓝', '2023-01-09 02:02:44', 2);
INSERT INTO `data` VALUES (10801, 'j***9', 5, '外形外观：漂亮\n运行速度：很快\n其他特色：手感还不错，性价比高。', '子夜黑', '2022-12-29 11:02:08', 2);
INSERT INTO `data` VALUES (10802, 'j***z', 5, '这个手机的颜值还是很好看的，蓝色的外观比较精美，然后就是系统使用下来的话属于非常流畅的那种，', '时光蓝', '2022-12-28 18:24:32', 3);
INSERT INTO `data` VALUES (10803, '老***楊', 5, '买来给我老爸的，一直用的小米，前几天买了一款后电池容量小了点，就重新换了这款极速版的，效果还可以。客服小姐姐也很耐心的回答，快递小哥哥也很好。以后也会一直用的。', '子夜黑', '2023-02-13 18:29:43', 2);
INSERT INTO `data` VALUES (10804, 'u***i', 5, '很好用，性价高比很高，玩王者超级无敌，吃鸡也滑，真心不错', '微光绿', '2023-01-19 14:28:11', 4);
INSERT INTO `data` VALUES (10805, 'j***n', 5, '外形外观：绿色很清新\n屏幕音效：显示完美，音效不错\n拍照效果：拍照清晰\n运行速度：运行速度很快，MIUI14\n待机时间：待机时间久，电池大\n妈妈用的很满意???????????????', '微光绿', '2023-03-04 00:46:34', 5);
INSERT INTO `data` VALUES (10806, '沙***瓶', 5, '给老妈买的，颜值很高，用着很流畅，老妈特别喜欢，屏幕也不错，特别好，物流也很快，好评。', '子夜黑', '2023-01-06 23:42:56', 3);
INSERT INTO `data` VALUES (10807, '果***冷', 5, '外形外观：美观大方\n屏幕音效：很好\n拍照效果：杠杠的\n运行速度：很快\n待机时间：挺长的\n买给我姨的，她很喜欢，说去拍照很清晰，用起来很好！', '子夜黑', '2023-02-12 23:02:05', 6);
INSERT INTO `data` VALUES (10808, 't***荣', 5, '手机外形很漂亮，大容量电池待机时间长，充电很快音效不错，运行速度也快，非常喜欢！', '微光绿', '2023-01-18 23:32:32', 2);
INSERT INTO `data` VALUES (10809, 'i***o', 5, '商品评价:手机非常好看，朋友很喜欢 通信音质：非常清晰 信号很好第一次买小米的手机，给朋友买的 打游戏也非常流畅 对于这个价格来非常划算 性价比很高 先让她用段时间看看 好用了不介意再买一个', '微光绿', '2023-01-03 17:54:09', 2);
INSERT INTO `data` VALUES (10810, 'C***鸭', 5, '外形外观：好喜欢这个摄像头\n拍照效果：拍照很清晰\n而且手机比我之前的也轻了很多', '微光绿', '2023-02-25 01:54:51', 1);
INSERT INTO `data` VALUES (10811, 'X***i', 5, '小米搞活动下单的，价格实在，还赠送精美生活礼品，真心不错！买的小清新绿，手机很漂亮，实物比图片更好看，大机身大内存大容量，满足生活需求杠杠的', '时光蓝', '2023-01-06 16:42:13', 2);
INSERT INTO `data` VALUES (10812, '浮***真', 5, '货收到后就拆开用了，质量很好，东西和官网买的没区别！\n大品牌，用起来很放心，质量非常好，赶上活动购买非常的划算', '时光蓝', '2023-01-27 21:09:51', 3);
INSERT INTO `data` VALUES (10813, 'l***7', 5, '外形外观：颜值特别高，边框特别窄，手感特别好，白色特别好看。\n屏幕音效：国产屏幕很不错，音放效果很不错。\n拍照效果：主打就是拍照，非常清楚，拍照很快。\n运行速度：比想象中的快，一点也不卡。\n待机时间：待机特别久，都不怕我还想听充电特别快。', '时光蓝', '2023-02-22 23:30:35', 2);
INSERT INTO `data` VALUES (10814, 'x***c', 5, '京东就是快，而且品质比较有保障，给老公的生日礼物，他很喜欢，内存大，充电超级快，基本上半个多小时就能充满，赞?', '时光蓝', '2023-03-02 12:48:47', 1);
INSERT INTO `data` VALUES (10815, 'M***s', 5, '自营物流速度超级棒棒，品质也是不错的。小米品牌值得信赖，价廉物美。手外观很好 配置也很棒，自营的物流超级快，早上购买下午就送达了，5个小时时间。非常值得推荐。。', '时光蓝', '2023-03-15 01:32:07', 4);
INSERT INTO `data` VALUES (10816, 'J***2', 5, '外形外观：简洁大气\n屏幕音效：清晰、优美\n拍照效果：比苹果好太多，且不失真\n运行速度：快\n待机时间：长', '子夜黑', '2023-02-28 22:37:50', 1);
INSERT INTO `data` VALUES (10817, 's***g', 5, '好！非常好！质量好，和实体店一样，颜色正，是我喜欢的宝贝与描述基本一致，发货很快，值得一买', '子夜黑', '2023-02-21 18:17:27', 2);
INSERT INTO `data` VALUES (10818, '孔***美', 5, '外形外观：清薄，有手感\n屏幕音效：屏幕看起来，很干净\n很适合家里老人', '子夜黑', '2022-12-31 18:40:41', 2);
INSERT INTO `data` VALUES (10819, 'j***m', 5, '手机很好用。安兔兔跑分也是很不错。反应速度很快。小米手机还像以前一样做的很好。希望能更好。', '时光蓝', '2023-03-17 14:19:35', 2);
INSERT INTO `data` VALUES (10820, 's***8', 5, '外形外观：简洁，屏幕大\n\n屏幕音效：好\n拍照效果：漂亮\n运行速度：快，不卡\n待机时间：很长，一整天没问题', '时光蓝', '2023-02-22 14:36:28', 0);
INSERT INTO `data` VALUES (10821, '啵***走', 5, '不是第一次买红米手机了，非常好用，从未发热发烫过，还非常抗摔，也没有卡机死机的时候，每个手机能用好几年，在京东买比店里便宜两百块', '子夜黑', '2023-02-01 21:45:21', 2);
INSERT INTO `data` VALUES (10822, 'j***h', 5, '外观挺好的，颜色也挺好看的，开机速度很快，赞赞赞赞，我一直是这个牌子的忠实粉丝，不错不错??????推荐推荐', '子夜黑', '2023-03-06 12:38:29', 3);
INSERT INTO `data` VALUES (10823, 'j***c', 5, '小米忠粉，一直用红米，性价比高得没话说，安卓刚买，用得溜溜溜的，非常方便。物流很快，快递员直接送到家里，马上就能用上，赞！', '子夜黑', '2023-02-10 18:44:24', 2);
INSERT INTO `data` VALUES (10824, 'G***1', 4, '快递速度很快，手机重量轻了很多，也薄了很多。浅梦星河，闪闪发光，很适合女生。oled屏提高到了1920赫兹以上，直接观感对眼睛的友好程度确实和LCD差不多。印象深刻的是立体声效果。顶部和底部两个扬声器音腔应该是等大的。而且音色很好。音量放到最大时仍然好听，没有破音，但是后背壳有明显震动。Note12pro的提升了音量左右平衡。试了试拍照，有光学防抖加持，确实出片很快。照片质量也有了明显提升。待机时间很好，做完手机迁移，电量只掉了10%，内置的应用不多，而且第三方应用都能卸载。直角边框，手机自带原厂贴膜（非钢化膜）和清水套，手感很舒服，适合女生用。', '微光绿', '2023-02-07 09:51:26', 8);
INSERT INTO `data` VALUES (10825, '幸***l', 5, '颜值很高，运行也流畅，在这块和这款的正常版本以及K40犹豫了好久，最终还是选择了这款极速版，果然没有让我失望，原来是魅族粉，现在已经转红米了，这是自己用的第二款红米。', '微光绿', '2023-03-01 20:08:41', 2);
INSERT INTO `data` VALUES (10826, '小***了', 5, '小米新发布的手机，颜值还是很高的，绿色特别好看， 相信小米的品质，用了这么多年的小米手机了，喜欢小米，支持京东，京东发货特别快，快递小哥送货上门，当面签收，服务很好，价格方面赶上年货节的活动，优惠力度也很大，而且还送了好多礼品，送的书包?保温杯?雨伞，感谢京东的年货节活动，喜欢京东的购物体验，真的很棒，推荐大家来购买，打算再入手一台，太香了', '微光绿', '2023-01-10 09:48:10', 5);
INSERT INTO `data` VALUES (10827, 'j***Z', 5, '外形外观：很好\n运行速度：很快\n屏幕音效：也不错\n待机时间：很长久', '时光蓝', '2023-02-24 20:21:28', 1);
INSERT INTO `data` VALUES (10828, 'j***0', 5, '外形外观：很好看，简洁大方，很有质感屏幕音效：很棒??棒??拍照效果：很好，照片清晰度很高，颜@真运行速度：目前速度很快', '时光蓝', '2023-03-17 06:55:23', 9);
INSERT INTO `data` VALUES (10829, '南***枫', 5, '很好看，制作工艺很精美，材质也很好！给个赞！品质很不错?，性价比比较高的的商品?，喜欢的亲可以直接下手不要犹豫哦?', '微光绿', '2023-03-15 18:20:32', 2);
INSERT INTO `data` VALUES (10830, 'j***t', 5, '新出的小米手机还是非常不错的，性价比很高，处理器性能还是非常厉害的，打任何游戏都非常流畅，续航方面也不错。', '子夜黑', '2022-12-28 18:06:37', 3);
INSERT INTO `data` VALUES (10831, 'K***K', 5, '从没想过这么实惠的价格能买到这么好的宝贝，下次还来你家?赶上做活动的时候买的，这个价格一分钱一分货??，从外观看很美?，材质做工都不错?，感觉买值了，还有物流超级快，点赞！以前一直都是在实体店买，这次选择了网上买，不光是正品，价格还实惠！物流很快，物品完好无损，用起来很舒服，喜欢?', '子夜黑', '2023-01-18 22:04:34', 2);
INSERT INTO `data` VALUES (10832, 'j***I', 5, '31号付款，1号晚上拿到，京东快递就是快。小米手机性价比较高，一些人性化功能非常实用，请根据自己需求选手机配置。拿到新机，请先偷着乐一下，然后测试手机功能，声音，屏幕，通话质量，摄像头功能，充电功能等！没什么问题的话，就来这里，分享一下拿到新机的感受！', '时光蓝', '2023-02-22 09:35:13', 2);
INSERT INTO `data` VALUES (10833, 'z***8', 5, '外形外观：非常漂亮，姐姐很喜欢\n屏幕音效：非常大气\n拍照效果：非常满意\n运行速度：很流畅，满分\n待机时间：超长', '子夜黑', '2023-01-30 15:50:43', 4);
INSERT INTO `data` VALUES (10834, '富***8', 5, '手机不错，\n外形外观：非常好看\n屏幕音效：声音大，\n拍照效果：清晰\n运行速度：非常快\n待机时间：两天，充电速度快，半小时就满了', '时光蓝', '2023-03-22 10:16:03', 4);
INSERT INTO `data` VALUES (10835, 'j***c', 5, '看了好久，终于看到一款自己喜欢的手机，手机非常好用，值得购买，速度快，电池也很耐用，还有射频卡功能，推荐购买呢', '子夜黑', '2023-02-18 12:18:58', 3);
INSERT INTO `data` VALUES (10836, 't***0', 5, '屏幕很大，指纹解锁很方便，果然是快充，整体感觉很nice', '子夜黑', '2023-02-11 21:01:43', 2);
INSERT INTO `data` VALUES (10837, 'u***v', 5, '外形外观：外形外观：非常棒 \n屏幕音效：清晰不刺眼\n拍照效果：很好\n运行速度：流畅\n待机时间：待定\n其他特色：性价比高，京东目营有保障，物流快，为快递小哥点赞！', '清凉薄荷', '2023-03-19 14:01:18', 8);
INSERT INTO `data` VALUES (10838, '阿***丁', 5, '小米1??1??青春活力版是青春版的二次升级版，价格实惠，6期免息，降低还款压力；双扬声器，OLED 屏幕,支持最高90Hz刷新?率！8+256主流配置，处理器：骁龙778；安兔兔50余万跑分，性能超乎想象！！！你值?拥?的第②部手机。', '冰峰黑提', '2023-01-17 12:53:46', 6);
INSERT INTO `data` VALUES (10839, '云***清', 4, '无与伦比的美丽，无与伦比的丝滑！之前买了一台，拿回家一点电没有打不开，换了一台，到手电量百分之六十一，第一次电量不耐用，是虚电，用到百分之一后充满电，耐用多了，这是小米系列目前最后一款青春，价格很便宜，注意是Xiaomi不是Redmi，感觉还是要高大上一些的，总之很不错，很值得购买，音质不像别人说的那么差，感觉非常空灵通透的感觉，拍照呢，前置非常好，后置说的过去，一款非常有性价比的小米手机。', '冰峰黑提', '2023-03-17 21:09:59', 2);
INSERT INTO `data` VALUES (10840, '稻***乐', 5, '外形外观：超级喜欢，手机很轻薄，手感很棒，颜色好好看，很喜欢这个颜色呢\n拍照效果：很哇塞呀，物美价廉\n运行速度：运行很流畅，平常使用完全没有问题\n待机时间：待机时间长，电池很耐用', '清凉薄荷', '2022-12-16 15:50:24', 4);
INSERT INTO `data` VALUES (10841, '纳***轩', 5, '外形外观：外观非常漂亮，粉粉的，特别喜欢，不用光照下颜色还有变化\n屏幕音效：屏幕大，非常清晰\n拍照效果：拍照效果杠杠的\n运行速度：运行速度非常流畅，一点都不卡\n待机时间：待机一天没问题，33瓦快充速度真快', '樱花蜜粉', '2022-08-07 23:14:22', 4);
INSERT INTO `data` VALUES (10842, '冬***p', 5, '外形外观：非常漂亮，手感很好，\n拍照效果：清晰真实，\n运行速度：反应灵敏不卡屏，打开速度迅速，\n待机时间：待机时间长，持久给力\n其他特色：物美超值，物流速度很快', '清凉薄荷', '2023-03-16 23:31:16', 4);
INSERT INTO `data` VALUES (10843, 'I***杜', 5, '手机很薄很轻，屏幕靓丽鲜艳手感很好，高通\n778處理器十分流畅，日常使用玩玩游戏完全\n没有问题,平常使用电池一天一充,现在的优\n惠购买,性价比好过买红米note系列理想很\n图', '晴光白雪', '2023-03-16 21:09:01', 5);
INSERT INTO `data` VALUES (10844, 'j***7', 5, '外形外观：外形外观很好看，大小适宜。\n屏幕音效：屏幕显示清晰，很有质感，音效不错。\n拍照效果：拍照很清晰。\n运行速度：运行速度不卡顿，很流畅。\n待机时间：刚买的，手机只有1%的电，一会就充满了，待机了几小时，只掉了3%的电。\n其他特色：价格实惠，品质很好。', '冰峰黑提', '2023-03-16 18:36:38', 3);
INSERT INTO `data` VALUES (10845, 'i***0', 5, '买来不开机，充电了好久也没有反应，只有退货了。手机做工很好，很轻薄，手感不错，做工比红米的手机好的太多，送货也非常快，服务好。', '清凉薄荷', '2023-03-14 12:55:52', 5);
INSERT INTO `data` VALUES (10846, 'l***g', 5, '物流速度快，包装非常好，物流速度超给力！上午下单，当天下午就到货了，送给老人当做生日礼物用的，老人用完全够用，轻薄！拿着顺手，运行速度够用，照相也不错，性价比高！一家人用的都是小米手机！用习惯了，还会继续支持小米！支持京东！', '清凉薄荷', '2023-02-18 09:43:09', 7);
INSERT INTO `data` VALUES (10847, '人***g', 5, '骁龙778G又是一代神U，1300+到手，轻是真轻，握感超棒，新手机流畅。（22年2月出厂的，一丝丝电都没得。能亮屏（1%）就用了快5分钟)', '清凉薄荷', '2023-03-04 18:57:33', 4);
INSERT INTO `data` VALUES (10848, '男***得', 5, '外形外观：整天颜色很漂亮，是我喜欢的颜色\n屏幕音效：屏幕音效还好。\n拍照效果：拍照效果很好，很真实。\n运行速度：很好，喜欢\n待机时间：一天待机时间不用带充电器\n其他特色：整天还是很喜欢', '樱花蜜粉', '2023-02-28 12:04:04', 2);
INSERT INTO `data` VALUES (10849, '菊***方', 4, '外形外观：外形和小米11差不多，材质换成塑料，重量很轻便。\n拍照效果：扫码够用了\n运行速度：骁龙778很流畅，日常使用配上8g运存很不错，备用机，装的软件不多。\n待机时间：机器是22年3月生产的，放的时间很久，到手后电量很虚，第一次充电后用没多久就没电了。第二次充电后电池明显恢复正常了，用了很久电量还剩余很多。', '冰峰黑提', '2023-03-09 11:07:32', 2);
INSERT INTO `data` VALUES (10850, 'j***d', 5, '外形外观：外形美观 是我喜欢的款式\n屏幕音效：屏幕清晰音效很棒\n拍照效果：照片清晰 速度快\n运行速度：反应速度快 \n待机时间：充一次电看视频可以看一个白天\n其他特色：手感很好 颜色款式是我喜欢的 充电器充的很快 是快充 送的有手机套 送的贴膜 物流很快 快递员态度很好', '清凉薄荷', '2022-02-22 15:39:48', 3);
INSERT INTO `data` VALUES (10851, '夜****', 4, '首先 价格很好    华为778的处理器4000多\n小米这款绝对性价比之王   778处理器52万的跑分   我记得十二月份的时候  这款手机还是1799 。\n处理器中规中矩   内存8-128 绝对够用   颜色也比较年轻 很好看，都是亮色。\n美中不足就是电池 4250毫安  配的33w充电器 也够用，目前市面上  4500毫安左右的电池比较多 相差甚微  \n总体来讲我觉得性价比无敌 真的无敌了', '樱花蜜粉', '2023-02-09 21:28:24', 3);
INSERT INTO `data` VALUES (10852, 's***7', 5, '外形外观：外观漂亮\n屏幕音效：屏幕显示效果细腻\n拍照效果：还行吧，没仔细看\n运行速度：运行流畅\n其他特色：旧手机也是红米note,数据迁移方便快捷，nfc刷门禁和密码锁都很方便，老人以后出门不用带门口钥匙了', '晴光白雪', '2022-10-03 08:16:40', 3);
INSERT INTO `data` VALUES (10853, '拾***o', 5, '手机很轻外观挺好看比较轻薄，一千来块钱买给家里老人用的，电池容量很大轻度使用一天就一冲，重度使用2充也够了，性能也不错完全不卡顿屏幕90帧的高刷，和平精英还能开60帧呢', '樱花蜜粉', '2023-01-11 17:22:28', 5);
INSERT INTO `data` VALUES (10854, 'j***q', 5, '小米11青春活力版，真的很好，纤薄的机身，重量也很轻，很适合随身携带，装口袋里挺好，性能也很棒，流畅度很高，充电33W很迅速，不到一小时。值得。', '冰峰黑提', '2023-03-11 11:40:36', 3);
INSERT INTO `data` VALUES (10855, 'j***9', 3, '天马屏真的刺眼，其它都满意', '冰峰黑提', '2022-02-08 16:35:12', 1);
INSERT INTO `data` VALUES (10856, 'S***y', 5, '外形外观：外观设计简洁大方白色的很好看\n屏幕音效：手感一级棒，轻薄\n拍照效果：基本满足日常需求了\n运行速度：毫无卡顿！！！！！\n待机时间：重度使用一天没有问题，充电速度非常快', '冰峰黑提', '2022-11-06 12:43:18', 2);
INSERT INTO `data` VALUES (10857, 'j***g', 5, '外形外观：小米11系列 yyds 摄像头 排列应该是最好看的\n屏幕音效：显示效果不错  \n拍照效果：图片清晰 细腻 \n运行速度：miui14加持下  效果杠杠的  \n待机时间：重度使用下亮屏5小时左右吧', '樱花蜜粉', '2023-02-20 10:39:22', 3);
INSERT INTO `data` VALUES (10858, 'j***m', 5, '活动期间物流还这么给力。一直都在用小米手机。重量比之前的要轻一些。但是屏幕大了很多。充电器是额外配的。清晰度也不错。最主要是有****。这个太省心了，很多东西用习惯了不会轻易改，这样特别省事。', '冰峰黑提', '2022-11-09 09:12:11', 4);
INSERT INTO `data` VALUES (10859, 'Y***1', 5, '过年好多物流都停了，京东快递还是一如既往的快。包装很严实，还送了充电器。给父母买的，手机经常掉，这个价位的正合适。手机很不错，已经开机使用了。拍照很清晰，屏幕也很大。唯一的是 拿到手一点点电都没有，应该是放太久了吧。', '晴光白雪', '2023-01-19 00:43:48', 4);
INSERT INTO `data` VALUES (10860, 'j***v', 5, '外形外观：好轻好薄，非常好看\n屏幕音效：屏幕清晰，音效不错\n拍照效果：不错，够用\n运行速度：运行流畅，不发热性能够用\n待机时间：可以\n其他特色：11青春版活力这机型算是小米的隐藏菜单机型，不是老粉都不知道，这机型在配置上各方面都刚刚好，性能日常够用，外观好看轻薄，看上去精致高档买给老人真不错。', '樱花蜜粉', '2023-01-19 15:34:59', 2);
INSERT INTO `data` VALUES (10861, 'j***o', 5, '用了两天才过来评论，整体都不错。手机轻盈好用，快递送的很快！\n外形外观：好看\n运行速度：挺快的', '冰峰黑提', '2023-03-18 23:35:41', 4);
INSERT INTO `data` VALUES (10862, '小***-', 5, '小米手机真是极具性价比！一直以来支持小米品牌。\n外形外观：非常美观，颜色好看\n屏幕音效：非常不错\n拍照效果：拍照效果很好！\n运行速度：处理器很好，很流畅！', '樱花蜜粉', '2022-12-20 22:29:54', 3);
INSERT INTO `data` VALUES (10863, 't***6', 5, '外形外观：轻巧大气，握感不错\n屏幕音效：杜比音效，声音不错\n拍照效果：画面细腻，还有好多特效功能\n运行速度：速度很快，支付闪付', '清凉薄荷', '2022-11-21 19:38:47', 2);
INSERT INTO `data` VALUES (10864, 'j***a', 5, '外形外观：完全看中了很轻薄，真的很轻，放口袋不太会有下坠感。\n屏幕音效：双扬声器，外放音乐音质很不错，屏幕也还行。\n拍照效果：扫码足够了。\n运行速度：778g的不玩游戏日常使用完全够用了，50w跑分足够了。\n待机时间：到手系统预装的是miui12.5版本，续航很拉。亲测必须升级到miui13.0.3系统才行，续航超强，待机14小时耗电不到10%，太猛了。\n其他特色：以后买手机一定要认准台积电工艺，三星的辣鸡工艺必须劝退啊！！！', '樱花蜜粉', '2022-11-18 11:45:09', 2);
INSERT INTO `data` VALUES (10865, '隔***陳', 5, '京东购物一个是方便，这款手机给家里人买的，性能够用，屏幕显示也很大。\n外形外观：极窄的边款，超薄的机身，握感很好。\n待机时间：正常使用待机两天，主要支持快充，一小时就可以充电到90以上。\n拍照效果：可以，自带一些美化功能\n推荐购买。京东购物有的时候不是图价格优势，有时候图的是比官方还方便的售后。', '冰峰黑提', '2023-02-17 11:54:29', 2);
INSERT INTO `data` VALUES (10866, 'K***你', 5, '挺好的，轻巧，美观，2021年的存货，电池一点电都没有，充了半个小时充满，开机一切正常，性价比很高的一款手机，京东满意的一次购物。好评！', '冰峰黑提', '2023-03-18 21:13:32', 5);
INSERT INTO `data` VALUES (10867, '江***灯', 5, '暂时用着还可以，中间有一次卡住了，强制关机重启过，手机散热性能医一般，打游戏的建议慎重选择\n外形外观：外观看起来大气，非常不错黑色也很时尚', '冰峰黑提', '2022-09-01 10:39:23', 4);
INSERT INTO `data` VALUES (10868, 'j***r', 5, '运行速度：畅快\n拍照效果：清晰\n续航能力：很好\n喜欢小米，手感不错，滑动都很流畅，还是当天拍下神速发货，第二天就收到了，真的超级给力呀，各方面都试过了，没有任何问题', '冰峰黑提', '2023-01-06 21:49:22', 2);
INSERT INTO `data` VALUES (10869, '取***铁', 5, '这款小米11是非常耐看的，越看越有感觉！使用起来也飞快，桌面简单美观，落落大方！把手机翻开背面放在桌子上，朋友看了贼拉风！都有想买的冲动\n外形外观：很时尚，\n拍照效果：拍照效果很清晰，像素很高\n运行速度：速度很快，翻页一点都不顿\n外形外观：非常漂亮\n屏幕音效：很大的音响效果\n拍照效果：拍照清晰\n运行速度：很快\n待机时间：时间长', '清凉薄荷', '2023-02-06 23:58:39', 2);
INSERT INTO `data` VALUES (10870, '秦***明', 5, '外形外观：漂亮\n拍照效果：细腻\n运行速度：很快\n待机时间：还行\n其他特色：手感很好，大小适中', '晴光白雪', '2022-10-05 20:58:29', 3);
INSERT INTO `data` VALUES (10871, '想***2', 4, '外形外观：外观很好，大气上档次，不是特别的粉色，差点意思\n屏幕音效：还可以，音质不错\n拍照效果：平时够用，很好的，\n运行速度：很快，用着效果不错\n待机时间：一点电都没有了，都开不了机，充了挺长时间才能开机', '樱花蜜粉', '2023-03-12 18:50:46', 2);
INSERT INTO `data` VALUES (10872, '利***花', 5, '这个是真的好，材料和做工都特别精致，外观这一块做工真的非常棒，这颜值 我觉着我可以推荐给我朋友买 哈哈', '清凉薄荷', '2023-03-19 20:16:24', 4);
INSERT INTO `data` VALUES (10873, '小***机', 5, '小米11青春版，选的樱花蜜粉，外形外观，非常不错，手感也挺好，屏幕音效，屏幕的显示效果还是非常不错的看视频的效果非常棒，双扬声器音效还是非常不错的，拍照效果也很好，清晰度很高，运行速度非常快，无卡顿现象，待机时间，正常使用一天没有问题，充电速度很快支持无线充电。总的来说，非常满意。', '樱花蜜粉', '2023-01-31 10:17:40', 2);
INSERT INTO `data` VALUES (10874, '花***帅', 5, '快递也特别快，晚上十点下单，第二天九点就到了，非常棒，快递员，商家也很用心，礼品也送到了，手机来了就打开之后也特别好，颜色外观都非常不错。反应也挺快。', '樱花蜜粉', '2023-03-01 10:42:36', 5);
INSERT INTO `data` VALUES (10875, '楊***o', 5, '手机颜值非常不错，好看。手上手感很好，背面是玻璃质感的，看起像磨砂的感觉，手感丝滑，轻薄，用起来非常流畅，骁龙778G还是还是很给力的，给父辈用，完全没问题的。很nice  。拍照效果也非常不错，真香', '冰峰黑提', '2022-02-08 11:53:50', 7);
INSERT INTO `data` VALUES (10876, 'j***w', 5, '给我妈用的，手机非常轻，手机屏幕比较大，因为有活动送的有快充和手机壳。\n外形外观：外观比较时尚，也没有刘海屏，看着很顺眼。\n拍照效果：手机拍照很清晰，以前用的红米\n运行速度：新手机运行还是非常顺畅的。', '樱花蜜粉', '2022-08-30 09:29:58', 3);
INSERT INTO `data` VALUES (10877, 'j***c', 3, '挺好的就是不能用有线耳机', '樱花蜜粉', '2022-07-08 17:05:27', 4);
INSERT INTO `data` VALUES (10878, 'P***o', 5, '外形外观：外观很好看，特别漂亮！\n\n屏幕音效：屏幕亮度很好，音效也不错！\n拍照效果：拍照效果很好！\n运行速度：运行很流畅！\n待机时间：待机时间长！', '樱花蜜粉', '2023-01-19 22:24:14', 2);
INSERT INTO `data` VALUES (10879, 'w***1', 5, '小米这款手机的外形外观很美观耐看，屏幕音效也很好，拍照效果也不错，新手机运行速度快，就是待机时间不太长。很轻薄，使用手感也很好。', '冰峰黑提', '2023-02-05 11:09:19', 3);
INSERT INTO `data` VALUES (10880, '涛***方', 5, '给家里老人买的，老人很喜欢，外观轻薄，屏幕清晰，手机拿在手里比较轻巧，系统运行快速，反应很快。', '清凉薄荷', '2023-03-16 00:24:07', 4);
INSERT INTO `data` VALUES (10881, '9***x', 5, '手机都在京东商城网购，一直都在用小米手机，外形设计风格非常好看，屏幕分辨率可以，声音真的好听，拍照也清晰，运行速度最快，；送的手机壳和耳机也可以；', '冰峰黑提', '2023-03-06 12:28:37', 4);
INSERT INTO `data` VALUES (10882, 'l***n', 5, '收货很快，物流流一流，是我想要的东东，\n拍照效果：还可以\n外形外观：轻薄，不沉重，\n用33w充电极其快速\n待机时间：也还不错\n玩游戏可能要多些考虑选择。日常通用没问题。喜爱物廉价美的商家。。。。。', '清凉薄荷', '2023-03-11 18:25:21', 3);
INSERT INTO `data` VALUES (10883, 'j***2', 5, '外形外观：很好\n拍照效果：好。\n总体比较满意。。。。。。。。。。', '清凉薄荷', '2023-02-08 15:35:36', 1);
INSERT INTO `data` VALUES (10884, '境***3', 5, '外形外观：没有猛男能拒绝粉色的手机吧！轻薄程度也很棒\n屏幕音效：作为备用机，性价比很高\n拍照效果：还好，要求高的人也可以凑合用', '樱花蜜粉', '2023-02-21 15:49:56', 2);
INSERT INTO `data` VALUES (10885, '猪***j', 5, '手机很流畅，老人很喜欢。物流服务很满意，就是充电器需要跨去调货比较慢，还好在过年之前到了，刚好带回家。\n整体来说还是比较满意的，喜欢的话可以下手了。', '冰峰黑提', '2023-02-07 22:24:37', 3);
INSERT INTO `data` VALUES (10886, 'j***L', 5, '手机质量很好，做工精细，很漂亮，质量很好，外观大气，送老婆大人的生日礼物，老婆大人很喜欢', '樱花蜜粉', '2023-03-05 11:37:44', 3);
INSERT INTO `data` VALUES (10887, '冷***市', 5, '买来做备用机的，性能足够好，价格很合适。\n拍照效果：一般，一般场景够用\n\n屏幕音效：屏幕实效不错\n\n外形外观：造型很好', '樱花蜜粉', '2022-06-18 12:00:54', 2);
INSERT INTO `data` VALUES (10888, 'j***p', 5, '给老娘买的，一年了，特别辛苦，之前的手机都是三年前的了，手机卡顿，性能也跟不上了，这次买的小米手机，妈妈非常喜欢，还赠送了充电套装，小米还算良心，系统流畅，不错。', '清凉薄荷', '2023-01-22 19:03:29', 3);
INSERT INTO `data` VALUES (10889, 'j***a', 5, '非常不错的手机，轻薄，性能好！！！很好用！去年买了一个青春版，今年就买了两个青春活力板版本！基本是一样的，只是一年多了降了大概200元！！！', '清凉薄荷', '2022-11-10 00:30:41', 3);
INSERT INTO `data` VALUES (10890, 'j***2', 5, '一开始选的其他品牌的，后来又看的红米手机，都不是很满意，最后看到这款，发现很中意，配置也不错，个人感觉够用就好，就刷刷视频看网页，不玩游戏，够用了，最后赞一下京东物流，快', '晴光白雪', '2023-01-19 22:46:28', 2);
INSERT INTO `data` VALUES (10891, '子***兔', 5, '给老妈买的新手机，很漂亮，喜欢粉色的，以前用过小米note粉色的，简直是极品，买手机只选小米，买了好多台了，系统很稳定，从来不更新系统，出厂的就是最好的，更新了就炸了，卡的你怀疑人生', '樱花蜜粉', '2022-10-22 10:15:26', 3);
INSERT INTO `data` VALUES (10892, 'm***0', 5, '给朋友换机，对比了几款选定的这个，功效能耗均衡用足够，颜值也不错，背板玻璃折射的色彩也洋气漂亮，整体很不错。 赶上活动还送了无线耳机，也同样不错，33w充电器手感还挺重，充电挺快的，老年人使用，满足各种应用场景了。 电源键指纹解锁这个用过后感觉非常方便', '冰峰黑提', '2022-05-04 15:21:26', 2);
INSERT INTO `data` VALUES (10893, 'S***3', 5, '外形外观：很漂亮。给妈妈买的。妈妈很喜欢。手感挺好\n屏幕音效：挺清晰的，调成大字模式，很适合老年人使用。\n运行速度：挺快。给老人用的，用起来非常流畅。', '清凉薄荷', '2022-11-20 18:54:35', 2);
INSERT INTO `data` VALUES (10894, '笨***头', 5, '到货就迫不及待打开了，果真没有让我失望，质量特别好，颜值也相当高，满意的一次购物，买给爸爸的，得大内存', '冰峰黑提', '2022-04-30 17:49:48', 5);
INSERT INTO `data` VALUES (10895, '其***好', 5, '手机反应速度很快，很流畅，续航也ok，特别充电速度很快，半小时就能达到80%多', '冰峰黑提', '2023-03-06 21:36:36', 5);
INSERT INTO `data` VALUES (10896, '寒***雪', 5, '从手机到家用电器很多都是小米，从客厅到厨房都是小米，小米的生态链是太强大了，智能家居做的非常的到位，让生活一切都变得简单了！', '清凉薄荷', '2023-03-09 21:26:37', 4);
INSERT INTO `data` VALUES (10897, '静***悔', 3, '手机挺好的，用了好几天了充电器一直不发货', '清凉薄荷', '2022-02-10 22:01:18', 6);
INSERT INTO `data` VALUES (10898, '-***-', 5, '给老婆买的小米10S闲太大，拿给儿子用了，又买了这个，这个大小正合适，重量也轻很多，手感很好，老婆不玩游戏，这个处理器不耗电，待机长正好。', '冰峰黑提', '2022-02-06 18:45:45', 2);
INSERT INTO `data` VALUES (10899, 'w***6', 5, '嘎嘎滴，买给老爸用的，屏幕大，字体大，用了也很流畅，嘎嘎好，处理器是骁龙778g，也是非常不错的处理器，之前的真我Q3s停产了，本来买哪一款，1200左右，处理器也是778  。这款小米11也很不错。', '清凉薄荷', '2023-02-05 21:33:29', 2);
INSERT INTO `data` VALUES (10900, '吾***胸', 4, '物流超快，没有12个小时就到了。真的很轻，大概和苹果mini差不多重，最便宜的778处理器了大概，友商的778差不多翻倍价，性价比超赞。', '樱花蜜粉', '2023-03-07 21:43:51', 5);
INSERT INTO `data` VALUES (10901, '英***爷', 5, '买给家里老人使用的，超级喜欢，手机很轻薄，手感也不错，颜色更好看，对于老人内存足够，运行也很快，待机时间长，电池也耐用！老人日常使用完全没有问题！', '清凉薄荷', '2023-01-07 10:45:16', 3);
INSERT INTO `data` VALUES (10902, 'M***g', 4, '手机总体轻薄，拿在手里手感轻盈，外观好看颜值高，778处理器性能满足日常使用，指纹秒开，拍照清晰，续航不差也不算很好，收到货一点电都没有充十分钟左右才能开机，送的33W充电套装很好。', '冰峰黑提', '2023-03-18 13:13:17', 3);
INSERT INTO `data` VALUES (10903, 'm***o', 5, '手机特别轻薄，买的白色的也很干净漂亮，至于性能，给家里老人买的用两三年是没问题的，送了一个蓝色的手机壳也很好看。很轻薄手感也很好。', '晴光白雪', '2023-01-05 19:28:11', 4);
INSERT INTO `data` VALUES (10904, 'j***T', 5, '手感很好性价比极高很流畅\n外形外观：好看\n屏幕音效：屏幕音效还可以同级别主流\n拍照效果：拍照效果还可以\n运行速度：打王者荣耀很流畅', '冰峰黑提', '2023-03-12 10:04:35', 2);
INSERT INTO `data` VALUES (10905, 'u***5', 5, '外形外观：线性流畅，配色好看\n屏幕音效：屏幕清晰，分辨率高\n运行速度：满足常规使用\n待机时间：充满电后没有使用，6天还有60%', '樱花蜜粉', '2023-03-18 11:13:34', 1);
INSERT INTO `data` VALUES (10906, '七***海', 5, '性价比很高的一款手机，系统使用很流畅，手机拿到手里很轻，很薄，颜色也比较合适，拍照和录像还不错，通话质量也满意。', '清凉薄荷', '2023-02-26 01:17:14', 3);
INSERT INTO `data` VALUES (10907, '想***2', 5, '?是正品，跟商店里买的是一样的，在这网购方便快捷，品质放心，还会光顾！.^?^.\n外形外观：外观很漂亮，大气挺薄的，质量也不重\n屏幕音效：音质还可以\n拍照效果：不错，平常照相够用\n运行速度：挺快的\n其他特色：手机出厂时间有点长，一点点电了，优惠很大，很便宜', '冰峰黑提', '2023-03-12 18:48:36', 2);
INSERT INTO `data` VALUES (10908, '风***9', 5, '自己手机不太好用了，所以就趁着双十一的时候，入手换了这个小米手机，拿到手，手感挺轻的，颜色也是很好看的，还有充电器送的，这样可以使用快充功能。', '晴光白雪', '2022-11-12 09:58:31', 3);
INSERT INTO `data` VALUES (10909, '饭***_', 5, '京东的外包装严实到位，大小合适，外观颜值，轻薄，快捷，手感很棒，颜值够高，设计合理，快充非常给力，屏幕音效非常好，拍照效果非常清晰！运行速度杠杠滴，游戏电视完全不卡顿，不错，物美价廉！总之，小米手机值得推荐购买！', '冰峰黑提', '2022-09-16 01:48:03', 2);
INSERT INTO `data` VALUES (10910, '正***c', 4, '这个手机还真的是挺好的。非常的轻。估计在5G的手机里边已经是最轻的了吧，才150多克。和之前的手机比起来，分量差的不是一星半点。音效也还不错。显示分辨率什么的也都挺好的。小米的手机越做越棒了。', '冰峰黑提', '2022-07-24 20:59:35', 2);
INSERT INTO `data` VALUES (10911, '小***7', 5, '用后感，老妈用的说是不错，手机很漂亮，用起来不错，大小也正合适，换了个手机壳完美！拍照效果也不错，物流也是快', '樱花蜜粉', '2023-01-19 16:01:41', 2);
INSERT INTO `data` VALUES (10912, 'j***5', 5, '手机用了几天，感觉很好，速度快，电池也能用一天多。这款手机很薄，拿在手里都没感觉，这是他最大的优点。', '晴光白雪', '2022-11-10 19:56:15', 3);
INSERT INTO `data` VALUES (10913, 'O***O', 5, '小米11青春版手机轻薄界面美观，运行流畅不发热，极速充\n电，拍照分辨率高清晰，我一直喜欢用小米手机，网买比实\n体店便宜，物美价廉，很满意，五星好评！京东快递,速度快,赞一个!', '樱花蜜粉', '2022-04-21 08:23:21', 3);
INSERT INTO `data` VALUES (10914, 'x***8', 5, '很实用的老人机 还算小巧  携带方便充电速度很快 运行速度也可以  够用了 推荐购买', '冰峰黑提', '2023-03-01 10:54:32', 3);
INSERT INTO `data` VALUES (10915, 'L***1', 5, '不亏米家东西了，真的好，轻巧反应快，灵敏度高，啥都不说了，我根本就是米粉，都是他家东西，力挺小米，包包质感老好了，该有的都有了', '樱花蜜粉', '2022-11-13 17:19:20', 5);
INSERT INTO `data` VALUES (10916, '捌***j', 5, '帮亲戚小孩买的，不怎么会用手机，平时就接打电话，选了几款这个性价比最合适就入手了，\n外形外观：颜色比较好看，拿在手里很轻\n拍照效果：没有使用\n屏幕音效：好', '清凉薄荷', '2023-02-03 09:19:20', 2);
INSERT INTO `data` VALUES (10917, '阿***4', 5, '外形外观：小米11青春版，买的粉色的，适合女生的颜色。\n拍照效果：拍照像素很好，很清晰。\n运行速度：买了285g内存，运行内存8g，速度很快。', '樱花蜜粉', '2022-07-30 13:53:29', 2);
INSERT INTO `data` VALUES (10918, '兔***f', 5, '价格实惠，给妈妈买的，手机不厚，非常轻，非常喜欢，送的手机壳手感非常好。\n外形外观：外观好看，\n屏幕音效：好\n拍照效果：像素很好\n运行速度：速度非常快', '清凉薄荷', '2023-02-18 20:43:46', 2);
INSERT INTO `data` VALUES (10919, '大***5', 5, '手机非常漂亮，给妈妈买的，处理器是778g，运行流畅，家人不玩游戏，这个处理器完全够用。赠送了手机壳，不过自己还是又买了一个手机钢化膜，非常满意！', '樱花蜜粉', '2023-02-14 19:56:57', 2);
INSERT INTO `data` VALUES (10920, '阿***亮', 5, '全五分好评，给老妈买的，性价比高。电池代理时间长，调整成大字模式老年人用很方便，还有页面可以设置好一键呼叫，把常通话的家庭成员都设置好，想打电话的时候点一下就直接呼叫了，对老年人很方便,主要还是LCD屏。当然这个价位不能要求过高，老年人用完全够用', '冰峰黑提', '2023-01-17 12:07:18', 3);
INSERT INTO `data` VALUES (10921, 'S***義', 5, '到货快，手机轻薄，外观精致好看，手感不错。各方面性能均衡，充电速度快，系统运行流畅，可以升级到miui13,性价比很高。', '清凉薄荷', '2022-12-10 09:59:44', 2);
INSERT INTO `data` VALUES (10922, '丝***幻', 5, '外形外观：外形美观，漂亮!\n屏幕音效：声音很大！屏幕清晰！\n拍照效果：拍照效果是没得挑的！\n运行速度：运行速度那是杠杠滴！\n待机时间：待机时间够用了！快充也是很棒的！', '樱花蜜粉', '2022-05-03 23:17:25', 5);
INSERT INTO `data` VALUES (10923, 'j***1', 5, '好喜欢小米手机呀，物流非常快，这个颜色特别好看，玩游戏也特别流畅，试了一下拍照功能，拍了下对面的景物哈哈哈，看得特别清楚，真的太太太强大了，嘻嘻嘻，推荐大家购买，性价比蛮高，冲啊啊啊啊买它！', '樱花蜜粉', '2022-11-27 19:54:31', 2);
INSERT INTO `data` VALUES (10924, '2***i', 5, '手机是给家里老人买的，之前的那个手机用了好几年，这次换的这个用起来真不错，反应速度很快，外观漂亮，屏幕也不错，拍照效果也很好，非常满意。', '樱花蜜粉', '2023-02-23 19:20:32', 3);
INSERT INTO `data` VALUES (10925, '隔***肉', 5, '外形外观：买了三部，外观一直都很喜欢\n屏幕音效：音效这个价位很不错了\n拍照效果：拍照要比之前用的mix好的不是一星半点\n运行速度：运营速度要比之前的mix2快多了\n其他特色：符合大众审美', '樱花蜜粉', '2023-01-28 21:19:05', 2);
INSERT INTO `data` VALUES (10926, '神***g', 5, '外形外观：高端大气上档次\n屏幕音效：很逼真\n拍照效果：专业级水准\n运行速度：很流畅总之就是很满意', '清凉薄荷', '2022-11-17 22:29:50', 3);
INSERT INTO `data` VALUES (10927, 'u***q', 5, '使用了一段时间了，屏幕很大，比之前小米9se大，速度快，而且电池耐用，基本一天一充电，颜色也好看，还送了手机壳，好评！', '樱花蜜粉', '2022-09-03 23:50:31', 3);
INSERT INTO `data` VALUES (10928, 'j***q', 5, '特意用了一个月多月再来评价。没有使用就没有发言权嘛。先来说说使用体验。整体来说来是不错的。屏幕大而且清晰。字体也很大，适合有老花眼的老年人。', '清凉薄荷', '2023-03-05 12:08:17', 2);
INSERT INTO `data` VALUES (10929, 'A***人', 5, '再来亿台?\n外形外观：真的是我最喜欢的小米手机了\n屏幕音效：性价比极高\n拍照效果：不输其他千元机\n运行速度：77G真的也很不错', '清凉薄荷', '2023-02-28 01:42:49', 2);
INSERT INTO `data` VALUES (10930, 'w***i', 5, '比了几款选定的这个，功效能耗均衡，日常使用足够，颜值也在线，背板玻璃折射的色彩也洋气漂亮，整体很不错。', '冰峰黑提', '2022-07-04 20:45:25', 3);
INSERT INTO `data` VALUES (10931, '中***病', 5, '手机很轻便，也很薄，手感不错，外观还可以，系统很简洁，总体很不错，让人满意，没有失望。', '冰峰黑提', '2023-02-16 01:16:20', 2);
INSERT INTO `data` VALUES (10932, 'j***1', 5, '性价比非常不错，小米11青春版778处理器还是很可以的&hellip;给老妈用，足够了，8+128的现在性价比很高，还送耳机和壳子&hellip;很不错！拍照也很清晰&hellip;', '樱花蜜粉', '2023-02-25 22:29:54', 3);
INSERT INTO `data` VALUES (10933, 'j***6', 5, '外形外观：轻薄、握感非常好，靓丽好看！\n拍照效果：拍照效果真的很好！\n运行速度：运行速度还是比较快的，手机也不会发热。', '清凉薄荷', '2022-08-14 13:11:30', 3);
INSERT INTO `data` VALUES (10934, 'H***n', 5, '家人想要轻薄的手机，找了Civi和这款对比，最后选了这款。到手感觉非常轻薄，系统流畅，摄像够用，白色后壳非常好看！在性能过剩的今天，手机完全满足家人的日常需求。', '晴光白雪', '2022-03-25 16:24:50', 5);
INSERT INTO `data` VALUES (10935, '_***猫', 5, '这款手机功能很丰富，支持NFC，公交卡，还可以复制门禁卡，出门都很方便了，只带手机出门就可以，手机很轻薄。', '樱花蜜粉', '2023-03-19 21:28:01', 3);
INSERT INTO `data` VALUES (10936, 'j***翔', 5, '手机很薄很轻便，手感好，买给老妈用的，****功能很好用，数据迁移很快，唯一美中不足的是手机的生产日期是2022年3月份的&hellip;&hellip;', '清凉薄荷', '2023-03-05 19:48:30', 2);
INSERT INTO `data` VALUES (10937, 'j***n', 5, '手机很好很流畅，机身很好看，拍照效果很好很清晰，运行速度很快，待机时间长，使用起来不流畅', '晴光白雪', '2022-07-10 11:37:04', 2);
INSERT INTO `data` VALUES (10938, '迷***刘', 4, '以前用手机一直追旗舰机，但因为喜欢轻薄的都用的华为p系列，上一手机换了3回屏幕价格都赶上整机了，现在发现千元机也挺好，特别这款很合心意，价格便宜，修屏幕也划算，拿在手机质感很好，配置足够用了，虽说换屏便宜也还是希望能减少磕碰，争取用的久一些，个人建议真别戴套，用着手感会差好多。', '冰峰黑提', '2022-11-12 14:29:36', 3);
INSERT INTO `data` VALUES (10939, 'v***i', 5, '给妈妈买的，她很喜欢，质量也很好。\n外形外观：手机大小很合适，屏幕很清晰\n运行速度：运行速度也很快，老人家够用了', '冰峰黑提', '2023-01-01 14:12:03', 1);
INSERT INTO `data` VALUES (10940, 'j***q', 5, '外形外观：外型美观时尚，大气非常喜欢，\n屏幕音效：非常炫彩，一直都是用在小米，\n待机时间：可能是新机待机时间长，\n运行速度：8GB+256GB大容量，不卡机', '樱花蜜粉', '2022-07-09 12:41:57', 2);
INSERT INTO `data` VALUES (10941, 'j***u', 5, '给家里老人换机，对比了几款选定的这个，功效能耗均衡，日常使用足够，颜值也在线，背板玻璃折射的色彩也洋气漂亮，整体很不错。\n赶上活动还送了无线耳机，也同样不错，33w充电器手感还挺重，充电挺快的，老年人使用，满足各种应用场景了。\n电源键指纹解锁这个用过后感觉非常方便，剑走偏锋但不突兀，挺好用的，整体是一部均衡的手机，对性能无太大运行要求的话，可以入。\n京东自营配送，速度无敌，赞赞赞。', '樱花蜜粉', '2022-04-23 22:23:03', 6);
INSERT INTO `data` VALUES (10942, 'h***1', 5, '手机还不错，用了一段时间了，还挺好的，棒棒哒，很轻，这款机子，还是可以推荐的，老人用足够了，价格也便宜，很好很给力。棒棒哒。很好。', '冰峰黑提', '2023-03-10 20:52:29', 2);
INSERT INTO `data` VALUES (10943, 'j***E', 5, '收到宝贝就打开试机，机子是未开封的，一点电都没有，自己充了一会，开机速度杠杠滴，运行流畅，速度很快！机子很薄，手感很好，音质效果好！', '冰峰黑提', '2023-02-23 21:20:04', 2);
INSERT INTO `data` VALUES (10944, '舍***_', 5, '给妈妈用的，她想要轻薄型，选了很多最终选定这款，外观颜色都挺漂亮，而且非常的轻薄手感特好，已经使用一段时间了，没什么问题，她很喜欢，相当满意。', '樱花蜜粉', '2023-03-03 15:21:51', 1);
INSERT INTO `data` VALUES (10945, 'e***4', 5, '机身很薄很轻，屏幕够大。买了256G的，把删了一些里面预装的APP。给孩子用，这价位很合适。小朋友娴熟的撕开包装，设置密码，装了自己要的游戏。运行了2天，速度很快，续航时间大概在2天左右，她几乎用4个小时的情况。还没试过拍照片，选了粉丝的，小朋友非常喜欢。 如果在家长控制方面能和其他品牌手机互通就好了，现在只能每天检查她的使用时间', '樱花蜜粉', '2022-01-21 08:07:26', 2);
INSERT INTO `data` VALUES (10946, 'j***x', 5, '手感轻盈，音质很好声音很大，拍照给力，充电速度很快，运行速度流畅，价格实惠物流很快昨天下单今天就到了这个速度只有京东做得到，', '冰峰黑提', '2022-11-14 01:28:00', 3);
INSERT INTO `data` VALUES (10947, 'm***n', 5, '手机性价比很高，趁双十一特价，赶紧下单整一个，运行流畅，屏幕清晰，日常用品都在京东上采购，价格实惠，送货速度快，赞一个', '冰峰黑提', '2022-12-13 18:02:40', 1);
INSERT INTO `data` VALUES (10948, '华***8', 5, '小米刚出来的时候用过4和5，当时觉得太容易发烫了，所以后面一直都没买过小米的手机了。这次的11给我很大的惊喜，充电速度巨快，而且电量很耐用，而且也不发烫了，喜欢。', '樱花蜜粉', '2022-07-19 15:25:56', 2);
INSERT INTO `data` VALUES (10949, '北***儿', 2, '拍照效果：货收到后就拆开用了，质量很好，东西和官网买的没区别！是理想中的产品，质量不错，物流也很快，值得点赞当时买的时候还在犹豫价格，买来之后一点都不后悔，而且物流还快，可以入手收到啦，很不错，非常喜欢，值得购买，(*^__^*) 嘻嘻&hellip;&hellip;', '清凉薄荷', '2023-03-14 00:48:55', 3);
INSERT INTO `data` VALUES (10950, 'j***t', 5, '在京东买了近二十部手机了，小米手机也买了好几部了，一句话：一如既往的好！\n京东：服务好，物流快速又放心，售后安心又宽心；\n小米：质量好，系统流畅，外观哇塞，照相清晰。\n期间一点小插曲：因为充电器和双肩包未发，售后也给解决了。\n总之物美价廉，体验超棒！\n最后，感谢京东，谢谢小米', '清凉薄荷', '2022-11-21 21:43:29', 2);
INSERT INTO `data` VALUES (10951, '打***子', 5, '很好用，很快，照片很清晰，很喜欢。上一个小米用了五年，这一个也不错，应该可以用好几年了。', '冰峰黑提', '2023-01-10 19:57:36', 3);
INSERT INTO `data` VALUES (10952, '小***公', 5, '好手机，778G用起来很流畅，不像个别@的友商，买来给家里老人用的，很值，屏幕刷新率也好。', '清凉薄荷', '2023-01-11 13:00:11', 2);
INSERT INTO `data` VALUES (10953, 'j***强', 5, '乞丐版&hellip;不，简配版&hellip;错，环保版&hellip;否，是小米11青春版啦，终于在双十一抢到了，其实也就少一充电器，好像现在谁还缺一两个充电器似的，但价格的确是香，手机非常轻薄，家有学生，非常合适。', '樱花蜜粉', '2022-11-17 16:38:24', 3);
INSERT INTO `data` VALUES (10954, '刘***8', 5, '这款手机还是很惊艳的，手感特好，属于超薄系列。屏幕显示依旧的细腻，拍照也不错，很清晰。运行流畅，用起来很顺手', '清凉薄荷', '2023-02-10 18:37:33', 2);
INSERT INTO `data` VALUES (10955, '琳***颜', 5, '昨晚下单，今天中午到，傍晚吃完饭开箱的，弄好了玩了几个小时基本上什么问题都没有，很好。', '樱花蜜粉', '2022-11-22 21:04:23', 5);
INSERT INTO `data` VALUES (10956, 'u***k', 5, '很好用，买给老人用的，操作很简单，跟以前的手机一样，很容易上手，外观也不错。直屏', '樱花蜜粉', '2023-02-24 11:35:21', 2);
INSERT INTO `data` VALUES (10957, 'j***P', 5, '小米手机非常好，性能非常稳定，非常流畅，这是第5次购买了。超级喜欢。物流起级快，', '冰峰黑提', '2022-12-05 21:21:33', 2);
INSERT INTO `data` VALUES (10958, 'j***2', 5, '正品，买的放心，价钱也公道，满意！款式很大方，质量非常好，价钱也很合理质量非常好，客服态度非常非常赞，有问题及时给解决了感觉实物比图片更好看，价格和质量成正比，这次购物非常满意，喜欢的宝宝赶紧下手', '冰峰黑提', '2022-11-03 21:47:07', 4);
INSERT INTO `data` VALUES (10959, 'C***4', 5, '一直用小米手机，这款小米11青春活力版尺寸大小合适，内存也够用，京东自营店发货和物流都很快，上午下单晚上送到，配有原装充电器和硅胶套，价格实惠。', '冰峰黑提', '2022-12-05 20:22:35', 3);
INSERT INTO `data` VALUES (10960, 'E***P', 5, '手机超薄，目前最薄的5G智能手机，手感非常棒！8G内存运行非常流畅，还赠送了无线蓝牙耳机，头一天晚上10点多下单，第二天就送到了', '冰峰黑提', '2021-12-12 13:32:41', 3);
INSERT INTO `data` VALUES (10961, '顾***骏', 5, '618的时候给妈妈买的手机。轻薄，功能够用，整体外观也挺好看的。非常适合给老人做常用机。本身机器已经自带贴膜，这点比较贴心。', '晴光白雪', '2022-07-13 09:23:37', 2);
INSERT INTO `data` VALUES (10962, 'h***6', 5, '非常好 奶奶买的 像素很好 操作流畅 用起来非常奈斯 手感不错 做工细腻', '冰峰黑提', '2023-02-19 00:16:58', 2);
INSERT INTO `data` VALUES (10963, 'j***n', 5, '京东送货非常快，昨天晚上下单，今天早上送到。安装很方便，一会就好了，还赠送了手机壳和充电器，好评。用起来画面不错，只要不安装太多东西，我估计可以的，希望能用久一点', '樱花蜜粉', '2023-02-15 12:07:36', 2);
INSERT INTO `data` VALUES (10964, 'j***w', 4, '手机超级漂亮，轻薄手感完美，电池虽然不大，但用起来也比较耐用，日常使用流畅度和苹果13差距不大，拍照也不错，信号也可以，总体很满意', '清凉薄荷', '2023-02-01 11:33:03', 1);
INSERT INTO `data` VALUES (10965, '娜***你', 5, '性价比高，老妈非常喜欢，很快学会使用，很适合老年人的一款手机，还送了二个手机壳，一次到位，赞。', '冰峰黑提', '2023-01-24 21:08:32', 3);
INSERT INTO `data` VALUES (10966, 'w***6', 5, '手机很薄，运行速度快，满足日常使用，价格便宜，拍照效果不错。', '晴光白雪', '2022-11-14 20:54:28', 4);
INSERT INTO `data` VALUES (10967, '凤***t', 5, '是我想要的轻薄手机，手感很好，顺滑舒服，清晰度很好，颜色漂亮，雅气，包装很好，发送货很快。', '清凉薄荷', '2023-03-16 16:31:45', 2);
INSERT INTO `data` VALUES (10968, 'd***h', 5, '手机颜值很高，运行流畅！MIUI13也到手立马更新整体来说，还是很好的，非常值得再次回购用了觉得很不错，商品质量好，发货也挺快的，总之就是很赞了', '樱花蜜粉', '2022-07-19 17:50:16', 2);
INSERT INTO `data` VALUES (10969, '小***池', 5, '拿到手，充好电就更新了一大把，总体来说还是很不错的，我在用着的几个手机都是小米，多数电器也都是小米，质量还是很不错的，刚更新系统到14还要摸***，不知道我另外两个手机啥时候更新到14', '清凉薄荷', '2023-03-20 11:13:41', 1);
INSERT INTO `data` VALUES (10970, '辉***8', 5, '很满意的一次购物，商家服务好，发货神速，物流也很给力，宝贝收到后非常喜欢，买得放心，用得安心?发货很快，两三天就到了，这个颜色我很喜欢，性价比很高，非常nice物超所值，商品设计完美，外观也很高大上，让人爱不释手。客服更是热情的没话说，这次购物很满意', '清凉薄荷', '2023-03-12 21:24:09', 3);
INSERT INTO `data` VALUES (10971, 'j***1', 5, '买给老人的手机，基本功能非常齐全，操作便捷，使用起来方便。正好趁着活动的时候买，还赠送了充电器和硅胶手机壳，真的是性价比之王！', '冰峰黑提', '2023-01-23 19:55:31', 2);
INSERT INTO `data` VALUES (10972, '云***凡', 5, '拍照非常好看，质感很好颜色鲜艳运转速度快，待机时间长，用起来非常顺手，总体感觉还是蛮不错的', '冰峰黑提', '2023-02-15 14:21:45', 2);
INSERT INTO `data` VALUES (10973, '飞***月', 5, '买给家人的，刚上手觉得真的很漂亮，很轻，心动了，都想自己给自己买一部。整体都很流畅，日常使用不怎么卡顿，过一段时间看看会怎么样。', '清凉薄荷', '2023-02-03 13:20:56', 2);
INSERT INTO `data` VALUES (10974, '正***c', 5, '目前用着还不错，主要是非常的轻，屏幕也挺大的，而且双卡双待，2000多的价位，应该还是性价比很高了。', '樱花蜜粉', '2022-10-06 19:26:52', 2);
INSERT INTO `data` VALUES (10975, 'j***O', 5, '很轻好漂亮，比青春9轻多了，速度快多了，长了约1厘米，价格可以不算太贵，平时用是很好了', '樱花蜜粉', '2022-11-13 09:53:58', 2);
INSERT INTO `data` VALUES (10976, 's***1', 4, '双十一优惠活动，买了一台小米青春版11手机，晴空白雪背板很好看，喜欢?，厚度和大小尺寸跟之前买的红米5plus差不多，更让我心仪?，跟小米有缘，家人用的手机都是小米的。', '晴光白雪', '2022-11-19 16:58:45', 2);
INSERT INTO `data` VALUES (10977, '阿***9', 5, '手机很轻薄，搭载骁龙778G处理器运行流畅，屏幕显示清晰细腻，只有90的高刷，，6400的主摄，拍照还算理想，够用，千元机很好的选择，值得拥有，好评。。', '冰峰黑提', '2023-02-03 13:03:13', 2);
INSERT INTO `data` VALUES (10978, 'H***C', 5, '己是第三个小米手机了，一直在用小米，很好用，不卡，流畅，外型好看，这款小米11青春版颜值很棒，很满意。', '冰峰黑提', '2022-11-30 20:22:04', 2);
INSERT INTO `data` VALUES (10979, 'j***1', 5, '手机质量超级好，外形非常的美观，大小正好，无论是放裤兜还是衣服兜里都非常的方便。', '晴光白雪', '2023-01-25 04:01:22', 2);
INSERT INTO `data` VALUES (10980, '奇***呦', 5, '非常好，给妈妈买的，粉色的很好看，也比较轻薄，还送的手机壳，也很好看，妈妈很喜欢。快递到的非常快。拍照效果也不错，运行速度也够用。', '樱花蜜粉', '2023-03-14 09:53:31', 2);
INSERT INTO `data` VALUES (10981, '谷***辶', 5, '买这款手机是为了他的轻薄，拿到手以后太轻薄了，特别喜欢，另外系统也很好，拿来当备用机合适。', '清凉薄荷', '2023-02-22 08:20:30', 2);
INSERT INTO `data` VALUES (10982, 'z***6', 5, '一直以来都是买小米手机，这款手机很小巧，轻薄，照相清晰度很高，女生用挺合适。发货速度很快', '樱花蜜粉', '2022-10-13 10:38:07', 3);
INSERT INTO `data` VALUES (10983, 'c***1', 5, '给爸爸买的手机  对比了很多款  感觉这款是性价比较高的一款 适合爸爸妈妈用  颜值担当', '清凉薄荷', '2023-02-21 11:07:10', 3);
INSERT INTO `data` VALUES (10984, '就***福', 5, '货已收到，用了几个小时不错很好。还特别的轻，哈哈哈哈，喜欢自营。\n外形外观：漂亮\n运行速度：一般', '冰峰黑提', '2022-01-06 15:57:34', 1);
INSERT INTO `data` VALUES (10985, '我***咔', 4, '手机可以，机身做的很薄，7系列的处理器，性价比很高，买完刚好赶上降价，申请价格保护退了200的差价，不错的购物体验', '冰峰黑提', '2023-01-15 10:21:32', 4);
INSERT INTO `data` VALUES (10986, 'j***x', 5, '这手感没谁了，轻薄的不想一个手机就像个模型一样， 屏幕清晰度很高，音质不错双扬声器声音很大，手机不错很满意，', '冰峰黑提', '2022-11-14 01:30:47', 3);
INSERT INTO `data` VALUES (10987, 'j***h', 3, '使用测试中，还不知道...过段时间再来评论！', '冰峰黑提', '2022-06-28 01:40:19', 9);
INSERT INTO `data` VALUES (10988, 'j***b', 5, '东西收到了，质量很好，京东快递速度非常快，用着还不错吧，颜值也是很高的，小米的东西比较不错，大小也很合适。值得购买哦，下次还会光顾的。', '晴光白雪', '2022-07-08 15:10:16', 3);
INSERT INTO `data` VALUES (10989, 'L***z', 5, '这一回买了两个小米11青春版  买给岳父和岳母的  性能足够他们用了 外观颜值非常不错 他们看都喜欢  屏幕也大 看着不累眼', '清凉薄荷', '2023-02-12 17:11:45', 2);
INSERT INTO `data` VALUES (10990, '开***2', 5, '手机非常漂亮，运行速度快，手感也非常棒，赠送蓝牙耳机和充电器，充电速度也很快，完全能够满足平时的需求。京东发货很快，下单第二天送达，非常方便。', '晴光白雪', '2021-12-18 16:15:30', 2);
INSERT INTO `data` VALUES (10991, 'j***村', 5, '给家人买的，内存够用运行也很快   父母非常喜欢这款手机    充满电能用一天是没有问题的！这款手机性价比很高呢！', '樱花蜜粉', '2023-03-11 20:55:04', 2);
INSERT INTO `data` VALUES (10992, '舞***7', 5, '高端大气上档次，手感很好，颜值很高，速度也很快，人性化设计，拍照效果也棒棒哒，爱了！', '清凉薄荷', '2022-03-06 14:24:52', 3);
INSERT INTO `data` VALUES (10993, 'S***e', 5, '手机轻薄，颜值高，边框窄，性价比极高买小米手机不是一次两次了，这次给家人买的，也是毫不犹豫直奔小米就来了，到手后依旧惊艳，很不错', '冰峰黑提', '2022-09-11 12:25:04', 2);
INSERT INTO `data` VALUES (10994, '蓝***节', 5, '已经收到啦，很不错，还有赠品，性价比太高啦，爱了爱了颜值不错，质量也没有问题，发货超级快，到货超级快，包装很精致，真的是开启了新世界的大门，这个颜色很喜欢，摸起来质感不错，包装也很大气，挺好的，价格适中，东西还是不错的，全五分！奈斯奈斯～', '晴光白雪', '2022-06-10 12:14:17', 5);
INSERT INTO `data` VALUES (10995, 't***n', 5, '外形外观：外观非常好看，而且很薄很轻。\n运行速度：运行速度很快，而且有高刷。\n拍照效果：有3个摄像头，广角非常实用，拍自然景色一定很美，2倍变焦能拍好远的地方', '冰峰黑提', '2021-12-10 23:29:58', 4);
INSERT INTO `data` VALUES (10996, 'j***r', 5, '超出预期，质量很好，做工精细，满意宝贝收到咯??，真的很棒呀！?质量真是没话说，非常满意！?开心开心?宝贝收到了，很惊喜，质量非常好，很满意的一次购物。我会继续回购的，店家值得信赖很精致，质量非常好，很满意的一次购物。谢谢店家！宝贝做工真的非常精细，细节真的棒，爱了爱了', '樱花蜜粉', '2023-02-04 17:54:44', 2);
INSERT INTO `data` VALUES (10997, '夺***胜', 5, '以前给我爸妈换的都是红米系列手机，总感觉红米系列手机用不了几年就开始卡顿，这次给我妈妈换小米11青春版试试看，小米系列怎么样。没用几天，我妈妈就觉得手机流畅、比红米的薄，非常好，拍照也能满足自己的需求。挺好的。', '冰峰黑提', '2022-10-05 18:28:03', 3);
INSERT INTO `data` VALUES (10998, 'o***g', 5, '我是小米10的用户，这台机和小米10比较轻了，薄了。虽然没有无线充电，但是手感非常好，非常轻便。而且有快速充电，这个非常好。现在有活动还送快充充电器，非常贴心。手机自带了一个透明手机套和已贴好手机膜，非常省心。拍照功能也比小米10强了一些。整体感觉这台机是值得推荐购买！第一张图就是这台手机的拍摄效果，有兴趣的朋友可以看看。', '冰峰黑提', '2021-12-19 22:20:16', 5);
INSERT INTO `data` VALUES (10999, 'N***_', 5, '很轻薄，充电速度很快，颜值很高，性价比高，日常使用很顺手，希望能用久一点，好评！', '冰峰黑提', '2023-01-29 10:37:29', 2);
INSERT INTO `data` VALUES (11000, 'j***t', 5, '新手机，一直用小米，新旧机器交替时可以自动同步更新旧手机资料到新手机，续航也不错，性价比超高。', '晴光白雪', '2023-01-15 19:41:57', 2);
INSERT INTO `data` VALUES (11001, '杂***狗', 5, '外形外观：白色很显干净，老太太很喜欢\n屏幕音效：喇叭声音挺好的\n拍照效果：俗话说，扫个码的水平吧\n运行速度：比小米8快，按说那是845，也不知道啥原因\n待机时间：毕竟是新机嘛，一天没问题\n其他特色：256的容量够用了。', '晴光白雪', '2022-02-11 21:13:43', 3);
INSERT INTO `data` VALUES (11002, '宣***a', 5, '帮家里父亲买的手机，还是一如既往的购买小米手机，质量很好，我也是用的小米手机，已经用了好多年了，质量不错，系统流畅不卡，值得推荐。', '清凉薄荷', '2023-01-28 20:45:57', 3);
INSERT INTO `data` VALUES (11003, 'u***u', 5, '外形外观：时尚大气，颜色漂亮\n屏幕音效：清晰大屏\n运行速度：运行流畅', '樱花蜜粉', '2023-02-02 16:08:26', 1);
INSERT INTO `data` VALUES (11004, '低***人', 5, '外形外观：外观很漂亮，白色yyds\n屏幕音效：屏幕素质还是很不错的\n拍照效果：拍照的话，够用了\n运行速度：一代shenu骁龙778g，性价比还是很高的\n\n其他特色：物流很快，元宵优惠很大，还送耳机，总体来说，性价比还是很不错的。', '晴光白雪', '2022-03-06 19:50:59', 3);
INSERT INTO `data` VALUES (11005, '0***豆', 5, '帮老爸买的，用惯了青春版，到手很迅速熟悉机子，大小薄厚合适，手感好，放口袋不显大。目前电池挺耐用，运行流畅。无蓝牙耳机？整体好评！', '冰峰黑提', '2022-10-31 11:18:12', 1);
INSERT INTO `data` VALUES (11006, 'j***u', 5, '京东商城购物方便快捷，小米手机一直都在使用，感觉还不错。充电速度也很快，操作系统也没有问题', '清凉薄荷', '2023-03-04 10:59:41', 2);
INSERT INTO `data` VALUES (11007, '黑***拉', 5, '颜色选的淡蓝色，很好看\n屏幕音效：声音不错\n拍照效果：一般\n运行速度：暂时还不知道\n待机时间：用一天基本可以\n其他特色：超薄手机，真的很轻，很适合女生用，对手机要求不是很高的满足你的颜值控，很漂亮，第一次买小米手机，青春版真的很青春', '清凉薄荷', '2022-02-17 19:20:05', 3);
INSERT INTO `data` VALUES (11008, 'b***j', 5, '屏幕显示色彩艳丽，清晰度高，运行流畅，手感很轻巧，非常适合女生使用，性价比高，值得购买。', '冰峰黑提', '2022-12-14 10:23:43', 2);
INSERT INTO `data` VALUES (11009, 'u***z', 5, '上周给孩子在门店买了一部note12感觉还不错，今天看见有活动自己入手一部小米11青春活力版当做备用机，性价比很高，一切良好，待进一步使用观察。', '冰峰黑提', '2023-03-08 15:30:53', 3);
INSERT INTO `data` VALUES (11010, 'j***w', 5, '外观很好看，使用手感很好，配道很及时，京东自营就是好，包装也不错，值得点赞。\n，', '冰峰黑提', '2022-11-29 19:17:22', 4);
INSERT INTO `data` VALUES (11011, 'a***i', 5, '货真价实，高颜值，高品质，一分钱一分货，材质外观和质量一看就很上档次，非常喜欢???????????', '清凉薄荷', '2023-01-21 13:29:52', 3);
INSERT INTO `data` VALUES (11012, 'j***q', 5, '外形外观：好看，而且很轻，握感极好；\n屏幕音效：不错，在同价位手机里算很棒得了\n拍照效果：要啥自行车，基础的够用了，而且配合MIUI拍文件很方便\n运行速度：蛮快，后续使用使用再看', '冰峰黑提', '2022-02-23 14:54:01', 2);
INSERT INTO `data` VALUES (11013, '大***P', 5, '送了一套充电器， 很良心了\n 非常轻薄，拿着很舒服，颜值很高，拍照很好看。\n如上 看中了挺久的。就是感觉4350mah的电池好像不是那么 经用，可能也是我用的比较多吧，小米还是一如既往的 良心\n是真不错，做的真细心，值得拥有，快递很快', '冰峰黑提', '2022-04-14 19:42:06', 3);
INSERT INTO `data` VALUES (11014, 'l***2', 5, '家里人已经买过一台，老人觉得很好用，正赶双十一，再给家里老人买一个，运转速度快，照相像素高，特别是手感好，很轻薄，小米很不错', '晴光白雪', '2023-01-08 22:37:31', 2);
INSERT INTO `data` VALUES (11015, '学***5', 5, '外形外观：白色的，外观好看，超级薄，拿在手里很舒服。\n屏幕音效：屏幕得益于那个柔性屏，边框很小，没有大下巴，全面屏的很好看。\n拍照效果：一般吧，不爱拍照\n运行速度：速度嗖嗖的\n待机时间：电池就有点小了，好在快充很快', '晴光白雪', '2022-02-09 15:00:12', 2);
INSERT INTO `data` VALUES (11016, '臭***弟', 5, '在京东买的第五个小米手机了，这款是给长辈安排的，内存也足够了，挺流畅的，不卡顿。送货速度非常快，会一直认可小米的。', '清凉薄荷', '2022-12-15 18:49:26', 2);
INSERT INTO `data` VALUES (11017, '泳***_', 5, '手机挺好的，给爸妈买的，充电器充电也很快，背面的颜色做工也很漂亮啦，所以直接戴的透明壳，不要浪费这个好看的设计嘛哈哈哈哈～爸妈用起来也没吐槽什么，挺喜欢的～', '清凉薄荷', '2022-12-17 17:13:20', 2);
INSERT INTO `data` VALUES (11018, 'j***3', 5, '给家里老人买的\n外形外观：虽然几年的产品，还是时尚，手感不错，还轻巧\n屏幕音效：屏幕细腻，音效不错\n运行速度：操作起来也很快，没啥卡顿，对老人很友好\n其他特色：别看33瓦充电器，关键看什么样的协议，门当户对才好，重得很快', '清凉薄荷', '2023-03-22 19:34:38', 8);
INSERT INTO `data` VALUES (11019, '一***四', 5, '他的设计非常酷的感觉，他的功能很强大的感觉，我非常喜欢，下次还要购买！他的设计非常酷的感觉，他的功能很强大的感觉，我非常喜欢，下次还要购买！', '冰峰黑提', '2023-03-10 20:20:59', 5);
INSERT INTO `data` VALUES (11020, 'f***8', 5, '给老妈买的第一个手机，当时就为了找小屏幕和还可以的性能，最后经过各种对比，选择了小米11青春版，拿到手里还是非常惊艳的，系统非常流畅', '冰峰黑提', '2022-10-16 12:12:15', 2);
INSERT INTO `data` VALUES (11021, '问***号', 5, '给朋友推荐的，相当满意，颜值担当，超薄机身，很流畅，朋友非常满意', '晴光白雪', '2022-08-28 20:25:31', 2);
INSERT INTO `data` VALUES (11022, '庄***威', 5, '外形外观：手机手感很好 很轻刚拿上手还以为是模型机\n屏幕音效：屏幕还可以吧\n拍照效果：拍照点赞', '樱花蜜粉', '2023-02-15 10:20:43', 1);
INSERT INTO `data` VALUES (11023, 'j***w', 5, '真的很好用哦这个手机很厉害哦太棒了吧好喜欢外观很好屏幕很好拍照很好 运行也很好 也很热', '樱花蜜粉', '2023-02-24 20:22:36', 2);
INSERT INTO `data` VALUES (11024, 'O***O', 5, '发货速度和物流超快，这小米11青春版手机很时尚，很轻薄，开机的时候电量只有11格了，我充了1个小时竟然有60多格，充电速真超快，运行流畅一点都不卡顿太喜欢了超赞??????', '冰峰黑提', '2022-06-08 19:20:13', 4);
INSERT INTO `data` VALUES (11025, 'j***t', 5, '外形外观：小米11系列同外观，11青春版是直屏，很轻薄。\n屏幕音效：奥魔丽屏很好的色彩，90hz刷新率，流畅省电。\n\n拍照效果：很不错，摄像头基本没啥凸起，拍照效果够用了。\n运行速度：778g 再战3年好吧，毫无问题。', '晴光白雪', '2022-11-07 21:35:05', 1);
INSERT INTO `data` VALUES (11026, 'j***m', 5, '外观很时尚，手握感适宜，屏幕触感良好，安装软件速度非常快，京东活动价1300十购买的，还算不错。京东物流速度超快，上午下单下午就到货，非常方便。', '清凉薄荷', '2023-03-12 08:37:28', 2);
INSERT INTO `data` VALUES (11027, '蟹***厨', 5, '五星好评，非常好！想不到那么快就到了！?收到立马打开看了一下，非常不错，质量超好，颜值又高?，推荐推荐?宝贝收到了，很惊喜，质量非常好，很满意的一次购物。我会继续回购的，店家值得信赖', '清凉薄荷', '2023-02-04 23:27:35', 2);
INSERT INTO `data` VALUES (11028, 'l***s', 5, '拍照效果：宝贝已收到，是我想要的，手感很好，质量也挺好，有问题客服也很快就解决了，态度非常好，一定好评！', '清凉薄荷', '2023-03-13 16:49:08', 2);
INSERT INTO `data` VALUES (11029, 'x***6', 5, '真的非常薄，拿在手里很轻，手感很好，如果屏幕能小一点对手小的人更友好。运行速度也比较满意，对于这个价位的手机来说，性价比不错。', '清凉薄荷', '2022-07-07 10:22:02', 2);
INSERT INTO `data` VALUES (11030, 'b***h', 5, '外形外观：时尚，轻薄，适合女生使用\n屏幕音效：很不错，音响效果特别好，声音大\n拍照效果：够用了\n运行速度：速度很快，CPU也属于中端了\n待机时间：还可以\n其他特色：希望能用住', '清凉薄荷', '2023-03-21 19:28:50', 2);
INSERT INTO `data` VALUES (11031, '股***白', 5, '给妈妈买的，颜值非常高，非常轻巧，运行速度也是相当的快，老妈很喜欢，喜欢的朋友可以入手了', '樱花蜜粉', '2022-07-09 20:02:29', 2);
INSERT INTO `data` VALUES (11032, 'u***g', 5, '一直用的是小米系列的手机 非常好用  这次这款很薄很轻拿在手里手感不错 方方面面都很好 很大气', '冰峰黑提', '2023-01-31 09:51:24', 3);
INSERT INTO `data` VALUES (11033, '樱***月', 5, '一直使用小米。这款手机首先很轻薄，很好用，速度很快，颜值也好，是同价位中性价比很高的一款。', '清凉薄荷', '2023-03-10 19:00:04', 2);
INSERT INTO `data` VALUES (11034, '大***一', 5, '外形外观：帮我老爸买的 很薄很轻很好看 特别大方\n屏幕音效：音效好听\n拍照效果：拍照很清晰 拍过去的老照片 都像实拍\n运行速度：非常快\n待机时间：好几天\n其他特色：支持小米 越来越好', '冰峰黑提', '2023-03-09 00:04:09', 2);
INSERT INTO `data` VALUES (11035, '浙***好', 5, '宝贝不错，手机较薄，手感很好，一般使用足够，值得购买，好评。', '冰峰黑提', '2022-08-15 13:02:23', 4);
INSERT INTO `data` VALUES (11036, '-***-', 5, '小米这款手机还是可以的！打开包装盒手机拿着手感非常舒服，做工精致大气上档次呢！价格优惠哦！', '清凉薄荷', '2023-03-11 20:56:05', 2);
INSERT INTO `data` VALUES (11037, 'j***2', 5, '外形外观：简洁大方，手感一流，时光蓝色很好看。\n屏幕音效：屏幕清晰，色彩饱和度高，音质较好。\n拍照效果：拍照和摄像功能足够用，效果很好。\n运行速度：满足普通功能使用要求，运行流畅。\n待机时间：不玩游戏，只打开一些购物网站，基本上能待机一天。\n其他特色：67W快充，充电速度很快，大约40分钟左右能够充满。', '时光蓝', '2022-12-29 16:57:28', 5);
INSERT INTO `data` VALUES (11038, '星***杨', 5, '外形外观：直屏，6.6屏比6S稍宽一点，长很多，达到了荣耀NOTE8和NOTE10的长度，所以是名符其实的NOTE\n屏幕音效：LCD屏，很清晰，不刺眼，双扬声器\n拍照效果：白天拍照还过得去没有明显失真，室内夜光拍照模糊，失真明显，名符其实的更适合扫码\n运行速度：8G，刚买，应用不多状况下测试，目前运行速度还是很快\n待机时间：67W充电很快，新老手机迁移测试待机时间，40分钟亮屏工作电量大约10%\n其他特色：屏幕是特色，其他还需要时间来检验', '原子银', '2023-02-01 15:50:17', 9);
INSERT INTO `data` VALUES (11039, '波***舍', 5, '性价比高外形外观，笨儿喜欢外形外观，有65%的电，，和note11pro上的A屏各有特色，，屏幕清晰，手握舒适，LCD旗舰直屏，，颜色正，比较快，有质感，边框圆滑过渡，13运行流畅，使用后再评论外形外观，外观硬朗，很好看，联发科天玑8100移动平台，颜色漂亮，具有次旗舰的手机体验，具有令人满意的续航能力，音质很好，有感觉，，体验顺畅无比，第二天就到了，清晰自然，实验实测待机1.5天，高大上，关于手机，视觉效果独树一帜，原色屏，手感极好，商务风范，很清晰，目前可以，操作也很方便，超级流畅，搭配usf3.1+lpddr5内存规格，还是很大错的，年度真香旗舰处理器，可以，立体非对称双扬声器，8100，时尚大气，对比了几个，居中打孔屏幕，金属质感，像素够用了，主流大气，未计算，待机超级长，很快，x轴线性马达，可能因为新机，刚开机，miui，大，手感不错，实惠，颜值高，，音质纯净好听好听，觉得综合这个最好，144hz高刷，，绝对王者，，清晰，性能炸裂，三星gw16400w高清主摄，可以吧，拍照效果不俗，京东很是给力，头天晚上10点多下单，，，充电速度很快，很好，↗', '子夜黑', '2023-01-01 16:06:51', 7);
INSERT INTO `data` VALUES (11040, 'G***2', 5, '外形外观：很美丽，很好看，手感很好。\n屏幕音效：顶级lcd屏幕毫无疑问。\n拍照效果：拍照还可以，平时日常够用了，算不上顶级。\n运行速度：买了8G起步，还可以。\n待机时间：续航很厉害，超大电池，跟我的iPhone 14  Pro Max不相上下。\n其他特色：白色很好看。\n性能好，可以作为安卓备用机。', '奶盐白', '2022-11-04 14:38:18', 9);
INSERT INTO `data` VALUES (11041, '-***干', 5, '外形外观：时尚潮流\n屏幕音效：非常??????????\n拍照效果：6400w高清?\n运行速度：王者荣耀，吃鸡毫无压力\n待机时间：重度使用也能用一天\n其他特色：67w超级快充，大??????????????????????', '奶盐白', '2023-02-21 08:53:53', 4);
INSERT INTO `data` VALUES (11042, 'j***庆', 5, 'Red Mi NOTE 11T pro直屏，67W快充太给力了\n外形外观：外观简洁大方，背板变色炫酷\n拍照效果：MIUI调教，满足日常使用\n待机时间：中度使用一天无压力\n运行速度：旗舰处理器，毫无压力\n值得拥有', '子夜黑', '2022-12-26 10:32:17', 4);
INSERT INTO `data` VALUES (11043, '感***大', 5, '运行畅快续航很好拍照一般性价比高外形外观，喜欢外形外观，有65%的电，，和notel1pro上的A屏各有特色，)屏幕清晰，手握舒适，LCD旗舰直屏，)颜色正，比较快，有质感，边框圆滑过渡，13运行流畅，使用后再评论外形外观外观硬朗；很好看，联发科天玑8100移动平台，颜色 漂亮，具有次旗舰的手机体验，具有令人满意的续航能力)音质很好，有感觉，体验顺畅无比，第二天就到了，清晰自然，实验实测待机1.5天，高大上，关于手机；视觉效果独树一帜，原色屏，手感极好，商务风范，很清晰，目前可以，操作也很方便，超级流畅，搭配usf3.1+Ipddr5内存规格，还是很大错的，年度真香旗舰处理器，可以，立体非对称双扬声器；8100，时尚大气，对比了几个，居中打孔屏幕，金属质感，像素够用了，主流大气，待机超级长，很快，x轴线性马达，可能因为新机，刚开机手感不错，实惠，颜值高：，音质纯净好听好听，觉得综合这个最好，144hz高刷，绝对王者，)清晰，性能炸裂。', '时光蓝', '2023-03-13 16:06:36', 7);
INSERT INTO `data` VALUES (11044, 'j***4', 5, '看到有活动直接拿下，送给老丈人非常棒，因为是LCD屏幕对眼睛很友好 ！\n5080毫安的大电池 加上杜比立体音效 老人用绝对给力\n触控采样率很高 手持操作绝对舒服 这款算是性价比很高的机器了 性能均衡不发热的天玑8100?顶级LCD屏?144hz刷新率 完美送人佳品', '原子银', '2023-03-07 16:31:28', 7);
INSERT INTO `data` VALUES (11045, 'j***5', 5, '一直都是用的红米系列手机，这款手机外观设计时尚好看，运行速度很快，打开软件不卡顿 ，待机时间长，67W充电速度快， 拍照效果很好 ，性价比高，手机握感也不错，处理器很强大，运行流畅，值得推荐 。', '奶盐白', '2023-03-08 06:53:17', 5);
INSERT INTO `data` VALUES (11046, 's***5', 5, '第二次买小米手机了  第一次买还是几年前买的红米note5 给妈妈买的，用了好多年 很稳定  只是内存小了  APP不断升级  现在流畅性不怎么好了，现在买了新款的note11T，在这个价位里反复对比了好几款，还是觉得这个很不错 适合父母用，首先是充电快 续航好，流畅性好  他们不追求极致的相机和屏幕，非常均衡的  天玑8100属于当前很好的CPU 非常稳定 低耗，屏幕也是自动高刷新  配合MIUI 系统流畅 丝滑 用换机助手几分钟就同步了  很方便。', '子夜黑', '2022-11-25 10:31:47', 9);
INSERT INTO `data` VALUES (11047, 'M***谢', 5, '很好很强大，Redmi Note11T Pro+整体采用同色金属Deco+小立边+闪光砂工艺，这次带来了银、蓝、黑三款配色，正脸依旧采用的是居中挖孔屏，配置了LCD材质屏，不仅支持全程DC调光、144HZ七挡变速高刷、270Hz超高触控采样率，还拥有原色屏的专业色准，并且内置高配定制背光灯，做到了硬件级防蓝光。 在性能方面，Redmi Note11T Pro+基本上做到了同价位最好，搭载的是天玑8100处理器，标配了满血版LPDDR5和旗舰级UFS3.1，速率较上一代Note10提升了50%。还配置了超大面积VC+石墨散热系统，实测82万分的成绩也是相当不错。而且，Redmi Note11T Pro+内置有澎湃P 1芯片和4400mAH锂电池，120W神仙秒充最快19分钟就可充满手机。 Redmi Note11T Pro+的影音配置也非常给力。前置1600万像素单摄，后置6400万像素+800万像素超广角镜头+200万像素微距镜头，支持AI智能降噪、视频超级防抖、4 K视频拍摄、720p慢动作视频拍摄、微距延时摄影等功能。值得购买！', '子夜黑', '2023-01-03 19:11:35', 8);
INSERT INTO `data` VALUES (11048, '霏***楓', 4, '京东快递次日达，用差不多了有半个月了，双扬声器，杜比全景声，触感马达，5080毫安大电池，2460x1080分辨率，可升级正式版MIUI14系统，67W充电适配器，充电特快，支持CarWith的车机互联', '子夜黑', '2023-02-11 16:15:41', 5);
INSERT INTO `data` VALUES (11049, '覆***觞', 5, '天玑8100处理器  一代神U  性能强悍   功耗低\n6.6英寸LCD屏  游戏  娱乐  都爽\n侧面 开锁键  指纹   解锁更快\n5000mA大电池  续航持久\n67W快充   超级快\n6400W摄像  配置杠杠的   不到2000的价格  很实在', '子夜黑', '2023-03-14 09:39:09', 4);
INSERT INTO `data` VALUES (11050, 'm***i', 5, '外形外观：外观时尚大气，个人比较喜欢时光蓝。\n屏幕音效：色彩画面和清晰度都很好，音质也不错。\n拍照效果：拍照效果满足一般需求。\n运行速度：得益于天玑8100及8GB的运行内存，操作流畅度很好。\n待机时间：重度使用基本上也能一天一充，67W快充很赞。', '时光蓝', '2023-01-13 10:00:16', 8);
INSERT INTO `data` VALUES (11051, 'N***_', 5, 'Redmi Note11T Pro+整体采用同色金属Deco+小立边+闪光砂工艺，这次带来了银、蓝、黑三款配色，正脸依旧采用的是居中挖孔屏，配置了LCD材质屏，不仅支持全程DC调光、144HZ七挡变速高刷、270Hz超高触控采样率，还拥有原色屏的专业色准，并且内置高配定制背光灯，做到了硬件级防蓝光。\n\n在性能方面，Redmi Note11T Pro+基本上做到了同价位最好，搭载的是天玑8100处理器，标配了满血版LPDDR5和旗舰级UFS3.1，速率较上一代Note10提升了50%。还配置了超大面积VC+石墨散热系统，实测82万分的成绩也是相当不错。而且，Redmi Note11T Pro+内置有澎湃P1芯片和4400mAH锂电池，120W神仙秒充最快19分钟就可充满手机。\n\nRedmi Note11T Pro+的影音配置也非常给力。前置1600万像素单摄，后置6400万像素+800万像素超广角镜头+200万像素微距镜头，支持AI智能降噪、视频超级防抖、4K视频拍摄、720p慢动作视频拍摄、微距延时摄影等功能。内置1012+1216超线性双扬声器，不仅拥有HI-RES认证，还支持杜比全', '子夜黑', '2022-11-14 20:42:14', 8);
INSERT INTO `data` VALUES (11052, '小***9', 5, '外形外观：开箱拿到真机很是惊艳，蓝色超可爱。\n屏幕音效：屏幕很大，单手握持很舒适！\n拍照效果：拍照效果超好，前后相机很出色！\n运行速度：运行很流畅，没有卡顿现象！\n待机时间：大电量，待机时间很好！\n其他特色：京东物流就是快！', '时光蓝', '2022-11-05 21:57:30', 9);
INSERT INTO `data` VALUES (11053, '恶***车', 3, '挺好的，小米还是那个小米', '子夜黑', '2022-12-30 10:04:03', 6);
INSERT INTO `data` VALUES (11054, '葉***聲', 5, '宝贝与描\n外形外观：非常满意，颜值在线，很板正\n屏幕音效：很清晰，音效很好，准备入手蓝牙耳机，配合使用\n拍照效果：拍照也不错，个人觉得很好，\n运行速度：速度嗖嗖滴，用个几年应该没问题，我买的512的，接下来，去慢慢享用', '原子银', '2022-11-14 21:19:59', 8);
INSERT INTO `data` VALUES (11055, '风***之', 5, '外形外观：黑色大气，经久耐看，老人很喜欢\n运行速度：开机运行相当快，8100非常给力\n其他特色：单手握感很不错，长宽比例做的协调，以为单手拿不舒服，比预期的好很多很多。\n屏幕音效：外放声音响亮有质感', '子夜黑', '2022-06-18 10:12:39', 5);
INSERT INTO `data` VALUES (11056, '浪***1', 5, '外形外观：白色，很喜欢，上次买的k40也是白色\n屏幕音效：屏幕分辨率很细腻，\n拍照效果：拍照效果还可以，扫码\n运行速度：天玑8100处理器，响应速度杠杠的\n待机时间：手机刚到，待机时间用用在看\n其他特色：手机手感摸着不错，质感也是可以的', '奶盐白', '2023-01-18 22:12:30', 8);
INSERT INTO `data` VALUES (11057, 'D***G', 5, '给老妈买的，精挑细选看了很多测评选的，老人家用的说很好。\n外形外观：挺时尚的，只是外壳磨砂略无质感。\n屏幕音效：144Hz高刷LCD屏幕是一大亮点，不仅高度护眼，而且斩获多项认证，是目前最好的一块手机LCD屏。\n拍照效果：后置主摄配备大底传感器，影像配置是同价位领先水平，如晒图。\n运行速度：够用了，老人家也没玩啥游戏。\n其他特色：红米note系列新品，搭载中端旗舰芯片天玑8100，性能强且功耗低。同时，5080mAh大电池+67W带来很好的续航，是这价位的真水桶机了！', '原子银', '2022-09-10 19:13:29', 9);
INSERT INTO `data` VALUES (11058, '黎***_', 3, '外形外观：时尚大气，塑料后壳手感不好，毕竟价格在这了\n\n屏幕音效：LCD看着很舒服，不会刺眼\n\n拍照效果：这价格就别指望了\n\n运行速度：8100处理器越来越成熟了，希望能用5年\n\n待机时间：1天，快充很给力\n\n其他特色：这里严重吐槽一下底部设计，麦克风孔和卡槽放一起，取卡的时候很容易插错了孔', '时光蓝', '2023-02-18 14:10:15', 4);
INSERT INTO `data` VALUES (11059, 'g***1', 5, '外形外观：银色的好看。\n屏幕音效：清晰度也很好，上下喇叭相当棒的音效。\n拍照效果：一千多的手机拍照相当满意了。\n运行速度：很流畅，速度也快。\n待机时间：妥妥的一天没问题。\n其他特色：小米推荐购买，性价比超高。', '原子银', '2022-08-25 18:13:55', 4);
INSERT INTO `data` VALUES (11060, 'j***s', 5, '小米Redmi Note 11T Pro 8+256，CPU天玑8100，时光蓝，简洁大方，屏幕清晰，尺寸大小合适，单手握着杠杠的。运行流畅，没有卡顿，电池大，不玩游戏，待机时间还可以有两天，67W的快充，大大缩短了充电速度。', '时光蓝', '2023-02-13 19:49:40', 4);
INSERT INTO `data` VALUES (11061, '落***y', 5, '外形外观：外观很漂亮，渐变色，显得很大气\n拍照效果：拍照效果很好，可能跟处理器的算法有关系\n运行速度：天玑8100，妥妥的旗舰机\n待机时间：刚开始用，不过电池足够大，67瓦的充电速度也很快\n其他特色：性价比高', '时光蓝', '2022-06-04 17:23:49', 7);
INSERT INTO `data` VALUES (11062, '1***国', 2, '?外观颜值：實在，實用性\n?体验感受：網速快，體驗分100%，充電續航力強\n?使用方法：超级满意，拍照清晰，分辨率144hz，信号不好，强，包装精美，还带双系统分身，处理器天机8100，算高配了。\n?功能特点：雙系統分身是我的首先這款手機的理由。', '子夜黑', '2022-09-22 23:37:40', 4);
INSERT INTO `data` VALUES (11063, '龙***颉', 5, '收到手机后非常满意，比预想中的还要好。塑料外壳握起来反而更轻便些，买的67瓦快充版的（67瓦快充的已然非常快了），个人感觉电池大点更实用，更牛的是还有充电保护，充电时手机过热的话会智能降低充电电压已降低危险系数。都说相机拍照效果普通，我个人感觉还不错，当然了跟主打摄影的手机是没法比的，不过对我这种不过分要求手机像素的人来说已经很好了。还有就是系统运行很流畅，天玑8100不愧新一代神u。高素质的LCD屏幕，长时间使用眼睛也不累。3.5mm耳机孔真的是非常人性化啊，简直大爱。还有就是物流很快，毕竟京东配送灰常靠谱，店家服务态度也很好，小米售后也很可靠。总之一句话：闭眼买，没毛病！', '原子银', '2022-07-04 23:38:50', 9);
INSERT INTO `data` VALUES (11064, 'j***m', 5, '外观很漂亮，手感也很好，整体体验了一下挺爽的，游戏方面不用说了杠杠滴！手机发烫也不严重，轻微烫，要比我之前黑鲨手机好多了，黑鲨手机发烫严重不要不要滴！这红米手机越来越好了，性价比高，有老铁喜欢赶紧下手，听我说没用自己体验就明白了。', '原子银', '2022-08-13 14:55:57', 7);
INSERT INTO `data` VALUES (11065, 'y***t', 5, '外形外观：一直信赖小米手机，到货后与网图和实物一直，非常好看，手握感很好。\n屏幕音效：看视频/听音乐，音效特别好。\n拍照效果：拍照效果清晰。\n运行速度：运行速度没得说，很流畅，很快。\n待机时间：待机时间长，最重要是充电速度，这个价钱67w的充电功率牛气了。', '时光蓝', '2022-06-27 18:41:46', 4);
INSERT INTO `data` VALUES (11066, 't***3', 5, '帮家里人买过好几次红米了，这次老妈手机坏了，于是看上了红米note11tpro。凌晨下单当天就到了。包装完好，配件齐全，手机壳和贴膜都有，省得买了。开机试了下，装好软件，运行流畅稳定，有高刷，有nfc，功能齐全。脸部识别和指纹识别都挺敏捷，很方便，价格也不贵，非常适合长辈使用。', '子夜黑', '2022-12-09 23:00:57', 4);
INSERT INTO `data` VALUES (11067, '樊***董', 5, '可以可以\n外形外观：外观精美\n屏幕音效：音效多，声音清\n拍照效果：拍照靓丽\n运行速度：完美不卡顿\n待机时间：超长待机，一天用了20%\n其他特色：外观设计漂亮，内存大，电池容量大。', '时光蓝', '2022-06-24 19:10:08', 8);
INSERT INTO `data` VALUES (11068, '李***昌', 5, '性能小金刚名不虚传，性能这方面没得说比同学旗舰手机进入和平精英还快，天玑8100+加上MIUI13流畅度极强，日常使用一天一充，四十分钟充满电，买手机不就是图方便嘛，这个手机既方便还实惠，自己用，送父母用都是最好的选择，真心爱上MIUI 上次在京东买的米8SE，6+64的手机是在2018年，用了五年的手机 没毛病，就是前一段时间不小心摔碎了屏幕，这才换的手机，相信我买电子产品尽量在官方店铺买在京东买 有保障\n外形外观：白色美观大气\n屏幕音效：屏幕LCD屏护眼省电，杜比全景声双扬声器立体感好\n拍照效果：拍照正好\n运行速度：运行速度：嘎嘎猛，满血8100＋ufs3.1＋R5性能铁三角', '奶盐白', '2022-11-17 09:34:37', 4);
INSERT INTO `data` VALUES (11069, 'w***7', 5, '外形外观：外观设计很好看，喜欢这种直屏\n屏幕音效：屏幕显示可以，音效也ok，就是有点震手\n拍照效果：满足一般拍照需求，夜景拍摄很好\n运行速度：运营速度很快！玩游戏很流畅，昨天玩了4个小时也只是微微发烫\n待机时间：完美！', '子夜黑', '2022-06-03 13:06:59', 6);
INSERT INTO `data` VALUES (11070, '远***等', 5, '外形外观：很好看\n屏幕音效：非常棒\n拍照效果：还可以\n运行速度：还行\n待机时间：一天\n其他特色：有扩展内存', '时光蓝', '2022-08-25 14:14:35', 8);
INSERT INTO `data` VALUES (11071, '1***虾', 1, '刚开始买了华为畅享50，但是新的就感觉有点卡，而且相机是真的不行。后来又重新研究了下发现红米note11Tpro性价比高，处理器性能好，相机拍照颜色真实点，充电速度非常快，20分钟就可以冲50块钱。续航也不错，内存也够用。买来给妈妈用的，她说比之前的华为好用。对了，NFC功能还可以把小区门禁卡和公交卡都绑定进去，确实很方便。还支持红外功能，下午试了一下可以用来开电视和空调。性能挺强大的，居然感觉手机的Iphone.13promax都没那么香了哈哈哈?\n外形外观：漂亮\n屏幕音效：还行\n拍照效果：杠杠的\n运行速度：还行\n待机时间：好\n其他特色：适合妈妈用', '子夜黑', '2022-09-03 18:38:25', 3);
INSERT INTO `data` VALUES (11072, 'j***n', 5, '外形外观：简约大气，色彩明亮，手感扎实\n屏幕音效：屏幕清晰简洁，声音外放清晰，没有杂音\n拍照效果：照效果很好，照片颜色柔和\n运行速度：速度很快\n待机时间：待机时间很长', '原子银', '2023-01-08 19:48:43', 2);
INSERT INTO `data` VALUES (11073, 'y***6', 5, '家里娃一直用小米系列，而且夸赞不停，学生党打游戏，耍酷，这次是给老爸买的。娃强烈推荐这款Redmi Note11T Pro 5G ，说处理器天玑8100又是直屏，适合老人用。并且67W快充，我选了8GB+256GB，大家好评的时光蓝色。老爸很满意，声音也大，拿在手里很有质感，推荐。', '时光蓝', '2023-01-15 19:47:19', 7);
INSERT INTO `data` VALUES (11074, 'j***H', 3, '还可以用的挺舒服的就是没有钢化膜', '子夜黑', '2023-02-07 11:25:39', 1);
INSERT INTO `data` VALUES (11075, 'l***1', 5, '处理器采用的是联发科的天玑8100，性能强悍，功耗低，发热轻，夏季使用体验好，LCD屏幕非常护眼并且耐用，采用5080mAh电池搭配的67W闪充，续航能力和充电速度非常完美，8G运行内存，APP打开速度和运行都十分流畅，千元机价位手机中无可匹敌，性价比很高。', '子夜黑', '2022-06-27 22:10:33', 8);
INSERT INTO `data` VALUES (11076, '春***风', 5, '京东自营送货太快了。早上买的下午就送到家。手机包装特别好。运行速度特别快。快充非常给力。144赫兹高刷真不错。玩什么游戏都不卡。性价比超级高。\n外形外观：非常好看\n屏幕音效：很棒\n拍照效果：很不错\n运行速度：非常快\n待机时间：很满意\n其他特色：性价比超级高。', '子夜黑', '2022-10-03 16:51:49', 4);
INSERT INTO `data` VALUES (11077, '我***0', 5, '系统很快，内存很大，买了多次了，已经，还会光顾，外观很好看，很喜欢，声音很大，拍照效果很好，为家人，也买了多次手机了，快递很快，还会继续光顾，我可是小米的忠实粉丝哦', '时光蓝', '2023-03-11 00:22:51', 4);
INSERT INTO `data` VALUES (11078, '乖***港', 5, '外观：后面好看，正面屏幕大黑边，看着像老年机！哈哈哈哈。\n性能不错：原神高画质确实能跑。1500这个价位很值了。', '奶盐白', '2022-10-23 16:04:58', 6);
INSERT INTO `data` VALUES (11079, '时***K', 5, '外形外观：好看瘦长\n屏幕音效：屏幕亮声音好听\n拍照效果：拍照清晰有点偏红\n运行速度：很快\n待机时间：很好', '原子银', '2023-03-18 00:33:32', 7);
INSERT INTO `data` VALUES (11080, 'f***o', 5, '外形外观：漂亮的外形，后面特别好看，喜欢。\n屏幕音效：还没怎么用，应该很好\n拍照效果：也清晰、漂亮。\n运行速度：快快快快快！\n待机时间：还行\n其他特色：关键是物美价廉。小米就是价格屠夫，京东双11价格给力。', '时光蓝', '2022-11-27 11:41:58', 6);
INSERT INTO `data` VALUES (11081, '淡***点', 5, '手机厚实，带上手机壳以后，手感会好很多！续航很不错，充电大概40来分钟，下载速度也很快，拍照白天还行，很满意！', '子夜黑', '2022-11-09 10:16:34', 8);
INSERT INTO `data` VALUES (11082, 'z***3', 5, '物流速度很快，晚上下单第二天收到，东西是我想要的，配了手机套，看上去漂亮，机器运行速度很快，容量大，日常用足够。活不多说晒图了。?', '时光蓝', '2022-10-06 19:23:21', 4);
INSERT INTO `data` VALUES (11083, 'g***3', 5, '外形外观：外观简洁大方，设计很简约，但是很有气质，非常漂亮\n屏幕音效：屏幕显示清晰，色彩舒适，触感流畅，音效超赞，音域很有层次\n拍照效果：拍照非常清晰，色彩也真实，夜景效果不错，相机可玩性很强\n运行速度：旗舰cpu名不虚传，特意开了好多app，不卡，流畅\n待机时间：新手机一直在鼓捣，也能用满满一天，很满意\n其他特色：充电速度很给力！', '子夜黑', '2022-10-06 17:45:24', 6);
INSERT INTO `data` VALUES (11084, '思***e', 5, '外形外观：这个蓝色真的超赞，很好看，窄机型适合手握\n屏幕音效：屏幕看着也算舒服，刷新率高，效果好清晰\n拍照效果：为了拍视频剪视频买的这款，效果可以，这个配置够用，两千元的价格，绝对性价比超高。\n运行速度：买的高配，现在用起来各方面还都很快，剪视频够用。\n待机时间：充电半小时充满，急速了，现用现充也来得及\n其他特色：红米系列一向讲性价比，配置好，', '时光蓝', '2022-06-27 17:47:07', 3);
INSERT INTO `data` VALUES (11085, 'j***8', 5, '手机外观颜值不错，握持手感很好。摄像头处处理的比较美观。还有3.5耳机孔，完美。屏幕不错，丝滑，亮度挺好，显示效果挺细腻，拍照不错，成像效果很好。体验不错。运行挺快的。新机器感觉非常不错、待机时间也很长，竟5000的大电池的呢！', '子夜黑', '2022-12-04 23:11:59', 5);
INSERT INTO `data` VALUES (11086, 's***g', 5, '不错，喜欢，性价比高，以后会经常光顾东西很满意哦，美观时尚大气，客服超级有耐心，服务细致贴心，大品牌就是不一样商品质量不错，细节、品质、做工都非常好，发货贼快，快递也给力，棒棒哒~???非常值得信赖的品牌，质量有保障，价格还亲民，相当满意真的超级喜欢，质量非常好，与卖家描述的一致！', '时光蓝', '2022-11-14 18:11:37', 8);
INSERT INTO `data` VALUES (11087, '三***界', 5, '818买的，配置很棒，玩游戏流畅不卡顿，神U加持，就是想不一样！外观中规中矩，耐看的那种！护眼LCD，这是我看中的，对眼睛绝对好！', '子夜黑', '2022-08-19 12:49:16', 3);
INSERT INTO `data` VALUES (11088, 'j***q', 5, '屏幕：LCD屏幕观感是真的舒服，pwm确实调光护眼，长时间玩眼睛不酸\n手感颜值：手机轻巧，蓝色的女生用也很搭。\n性能：日常使用很舒服，高刷我只用90HZ就很流程。\n续航：同上90HZ刷新，早上80电出门，下班还有20，很有安全感。', '时光蓝', '2022-08-27 10:09:25', 2);
INSERT INTO `data` VALUES (11089, '孟***2', 5, '外形外观：漂亮\n屏幕音效：很不错，唱歌也很好\n拍照效果：很清晰，就是前置摄像头有点美颜过重的感觉\n运行速度：很快\n待机时间：很长耗电慢', '时光蓝', '2023-02-22 16:55:13', 1);
INSERT INTO `data` VALUES (11090, '嘉***k', 5, '外形外观：握持的手感很不错 背板的感觉很不错 颜色很纯正 很大气\n屏幕音效：屏幕很好 144hz很流畅 推荐购买\n拍照效果：很清晰\n运行速度：运行速度很快\n待机时间：5000ma待机时间很长吧', '原子银', '2023-01-12 19:22:59', 2);
INSERT INTO `data` VALUES (11091, '夜***尽', 5, '外形外观：外观简洁大方，背板变色炫酷。\n拍照效果：miui调教，满足日常使用\n待机时间：中度使用一天无压力，67瓦快充，充电贼快。\n运行速度：天玑旗舰处理器，毫无压力。\n屏幕音效：144hzlcd屏幕，无频闪，眼睛舒服。双扬声器音效避真。', '时光蓝', '2022-10-09 00:58:57', 5);
INSERT INTO `data` VALUES (11092, '奔***8', 5, '买了送人的，很不错，颜值在线，挺薄的，性价比很\n\n高，价位合适，8G+128G运行不卡，原机装了很多\n\nAPP不用的自己就卸载了，设置完成，弄了两个小时手\n\n机也不热，掉电也不快，希望一直这么好用，不打游戏，不追剧，这个手机用着很赞！', '时光蓝', '2022-11-16 20:52:37', 7);
INSERT INTO `data` VALUES (11093, 'h***u', 5, '手机到手立即换卡换机，小米的换机功能还是很实用的，仅仅用了二十分钟就换机完成，简直又方便又省心。512G的内存可以随心所欲了，可以把以前玩过的游戏通通找回来。虽然是天玑国产芯但是运行速度还是很畅快淋漓的。反正完全可以拥有手机的全部功能。', '子夜黑', '2023-02-12 12:17:17', 4);
INSERT INTO `data` VALUES (11094, '网***1', 3, '性能对得起价格，总体上推进', '子夜黑', '2022-12-12 10:49:11', 5);
INSERT INTO `data` VALUES (11095, '周***周', 5, '超级满意，拍照清晰，分辨率144hz，信号强，第一次买小米手机没失望，发货速度极快！包装精美，充满电放了2天，才用8%的电量，还带双系统分身，处理器天机8100，算高配了。', '子夜黑', '2022-09-22 21:41:14', 4);
INSERT INTO `data` VALUES (11096, '小***杨', 5, '外形外观：燃烧器的外观还是很不错的，很漂亮，很精致\n屏幕音效：屏幕很大播放歌曲，音效也很不错\n拍照效果：拍照很清晰，后摄像头的像素很高。\n其他特色：配送速度挺快的。\n价格比较划，也在用小米的手机，这款手机看起来还不错', '时光蓝', '2022-10-04 19:58:46', 6);
INSERT INTO `data` VALUES (11097, '买***了', 5, '在华为，荣耀，红米之间选了好久，最后锁定红米11tpro，同等价位下，tpro11性价比很高，cpu8100,续航也给力，操作屏幕流畅不卡顿，各种app触点灵敏。', '子夜黑', '2022-08-11 11:08:05', 5);
INSERT INTO `data` VALUES (11098, '哈***上', 5, '外形外观：外观漂亮精美，比老的手机窄，银色特别好看\n屏幕音效：屏幕很不错，色彩还原度很高，声音也很大，给父母用正好。\n拍照效果：拍照很清晰，还带微距拍摄，功能很全面。\n运行速度：8g运存很快，手机再也不会卡了', '原子银', '2022-06-27 19:36:53', 5);
INSERT INTO `data` VALUES (11099, '哞***哞', 5, '首先，产品外观不错，磨砂的质感，银色的后屏一闪一闪像星空一样，非常漂亮！\n其次，屏幕清晰舒适，不刺眼，音效清晰无杂音\n第三，像素高，拍照效果不错，适当放大也很清晰，颜色正，不会出现过度曝光或者太暗的情况\n第四，运行速度快，不卡顿，待机时间也很满意\n最后，性价比高，普通家庭较佳选择！', '原子银', '2022-08-05 10:55:23', 2);
INSERT INTO `data` VALUES (11100, '莫***木', 5, '外形外观：直屏面板，屏幕显示效果不错。\n\n拍照效果：可以了，对于千元机来说还不错\n\n待机时间：这个是最满意的基本上两天充一次电，手机用的不多\n运行速度：不错，很少卡顿，给爷爷用肯定可以。', '子夜黑', '2022-11-07 19:39:24', 1);
INSERT INTO `data` VALUES (11101, '玩***价', 5, '外形外观：颜色很棒看着挺有质感\n屏幕音效：木耳听不出来区别，屏幕华星光电的\n拍照效果：和我的米十打的有来回，色准方面准的让我震惊\n运行速度：受制预算6+128好像也还行\n待机时间：目前不错\n其他特色：非常中意颜色', '原子银', '2023-02-10 01:40:17', 2);
INSERT INTO `data` VALUES (11102, '海***t', 5, '以前用过红米系列的手机，总体感觉还不错，性价比很高。这次购买的这款note11t pro手机，手感很舒适，运行速度很快，不论是玩游戏还是刷视频都非常流畅，一点也不卡，而且手机电板续航能力强，充一次电至少可以使用一天半以上，配用67w充电器，充电速度也很快，半个多小时就可以充满电，非常满意的一次购物，综合好评！', '时光蓝', '2022-12-15 08:33:51', 8);
INSERT INTO `data` VALUES (11103, '榴***榴', 5, '送出去的礼物，长辈很喜欢。颜值与实用性并存，40分钟左右可以从45%充满，正常使用可坚持一天半。内存大，喜欢拍照的长辈可以随便造。', '时光蓝', '2023-01-27 19:48:14', 2);
INSERT INTO `data` VALUES (11104, 's***3', 5, '京东快递速度一直快。\n快递外包装很完整，保护很好，无破损\n之前买过一款11，用着挺好的，外观也喜欢。\n摸起来很有质感，屏幕与之前比较大，观影效果拉满，屏幕清晰。\nNFC功能很喜欢，开始体验，开门、乘车简单很多。\n可以体验一把快速充电。\n摸索下一功能。', '子夜黑', '2022-10-17 12:11:47', 5);
INSERT INTO `data` VALUES (11105, 's***8', 5, '这个店虽然是自营的，但发货有点慢了。今天才拿到产品。\n外形外观：打开包装后，手机的外形外观很漂亮，做工也非常的精致。\n屏幕音效：屏幕音效不错的，声音最响，播放音乐也非常的好听。2个杨声器，有立体感的感觉。非常给力呀。\n拍照效果：拍摄的照片很棒哦。\n运行速度：运行速度很快。非常喜欢。', '原子银', '2022-11-19 14:33:03', 2);
INSERT INTO `data` VALUES (11106, '丶***城', 5, '外形外观：外形外观：相当好看，大气上档次低调奢华有内涵！ \n屏幕音效：音效很好，确实很动听\n运行速度：运行速度：8100的加持，速度相当稳，而且省电！ \n待机时间：电池够大，充电够快！\n拍照效果：拍照效果：很清楚，够用了反正！', '原子银', '2023-02-02 18:48:45', 7);
INSERT INTO `data` VALUES (11107, '偏***y', 5, '外观太可以，操作流畅度也不错，充电速度很快，总体还不错。', '子夜黑', '2023-01-20 11:00:48', 9);
INSERT INTO `data` VALUES (11108, 'g***x', 5, '疫情如此严峻的情况下，京东物流依旧正常运转虽然速度不及之前但是也是非常快了！红米note11tpro比pro+好用！买给老年人用的，性价比非常高 性能也好 144hz刷新率啊 纵享丝滑！充电嘎嘎快啊，没一小会就充满了 而且还是5000毫安电池 牛的一批。', '时光蓝', '2022-12-24 14:22:14', 7);
INSERT INTO `data` VALUES (11109, 'D***王', 5, '外形外观：可以，给老人买的，挺喜欢的\n屏幕音效：LCD永不为奴，双扬声器，不错\n拍照效果：满足日常使用\n运行速度：挺快的，MIUI非常好用\n待机时间：刚开始用，还不知道，但是充电很快\n其他特色：性价比很高', '时光蓝', '2023-02-18 20:25:17', 6);
INSERT INTO `data` VALUES (11110, 'K***豆', 5, '外形外观：外观看着很有质感，虽然实际一摸就知道是塑料的，但还是有那种磨砂的高级感\n屏幕音效：屏幕素质很高，现在性能好的lcd手机选择不多了，音效很大声，爸爸很满意\n拍照效果：拍照效果就不强求了，配得上这个价位就够了\n运行速度：8100处理器还是好用的，轻松带的动高刷新率\n待机时间：待机很顶，充电也够快', '原子银', '2022-07-05 20:52:42', 5);
INSERT INTO `data` VALUES (11111, 'R***丶', 5, '外形外观：潮流小立边设计搭配原子银配色简直就是完美\n屏幕音效：超高素质的LCD屏幕，非常棒的音质效果\n拍照效果：拍照清晰特别好看，分辨率高\n运行速度：运行流畅，开启144Hz非常丝滑\n待机时间：67W快充只需半小时即可充满，电池容量大耐用', '原子银', '2022-06-01 22:31:15', 9);
INSERT INTO `data` VALUES (11112, '河***乐', 5, '外观是我喜欢的直边，前相机在中心就很棒，操作系统很方便，屏幕看着很舒服，下载app很快，游戏支持超高帧，运行速度比较快，还有小米耳机，佩戴了快充插头，运输大家途中没有磕磕碰碰，包裹完整，总之，红米11tpro很棒，值得购买', '原子银', '2022-07-01 10:49:15', 9);
INSERT INTO `data` VALUES (11113, '三***界', 5, '白色的，喜欢很久了，今天收到了，非常高兴，开心。\n小米家的产品是相当不错的，家里有许多他家的产品，包罗万象，都很好用。最近买了这台手机，也关注了很久，最在意的就是它的屏幕，护眼，这是最重要的。', '奶盐白', '2022-11-16 15:30:47', 5);
INSERT INTO `data` VALUES (11114, '買***0', 5, '收到之后立马拆包试用了一下 续航很好 很喜欢屏幕的自动调节功能 护眼 很舒适 平时不玩游戏 所以游戏体验不知道 刷视频 打开网页还是很流畅的 拿着不重 没有想象中的那么厚 总体来说还是很满意的 比想象中的好看好用', '原子银', '2022-10-18 08:48:50', 2);
INSERT INTO `data` VALUES (11115, 'j***b', 4, '外形外观：款式简约大气新颖，老爸也很喜欢。\n屏幕音效：音质，性能都不错。\n拍照效果：很清晰，父母要的就是拍得清楚，这个还带的有美颜，可喜欢了。\n运行速度：很流畅，反应很快，轻点一下就能运用自如。\n待机时间：拿回来待机不用都要管几天。\n其他特色：一直担心怕买不到正品，相比实体店，在京东专卖旗舰也不差，而且人家都是质量担保的，特地查了，是正品。整体来说这款手机买来给父母用的，从来没在网上买过这些数码产品之类的，都是犹豫了很久才买的。就是看他的性能，各方面配置都还不错而且是很平价机了，口碑也挺好的，所以才决定下手。没想到没让我失望，很值，老爸很喜欢。喜欢的亲可以入手。', '子夜黑', '2022-11-11 15:18:45', 5);
INSERT INTO `data` VALUES (11116, '夏***8', 5, '外形外观：是方角的 一眼看上去很好看\n屏幕音效：特别清晰\n拍照效果：拍照清晰 自带美颜效果\n运行速度：运行很流畅\n待机时间：充电很快 待你很长', '子夜黑', '2023-01-16 19:11:26', 1);
INSERT INTO `data` VALUES (11117, 'j***y', 5, '颜色很漂亮，外形方正，屏幕很大，音效很好，67W快充，充电速度快，拍照很好，运营杠杠的，打游戏也不烫，大电池待机时间长。京东有保障！', '时光蓝', '2022-11-18 15:05:03', 2);
INSERT INTO `data` VALUES (11118, '大***象', 5, '外形外观：原子银太好看了，第一次买银色的。摄像头头还是太大，有些丑\n屏幕音效：屏幕尺寸可以，，握起来的手感也是不错的LCD屏对我这种近视眼太友好了。杜比景声音效可以\n拍照效果：拍照效果日常使用，没多大的要求\n运行速度：新买的运行速度快啊！天玑8100杠杠滴，虽然8GB也够用了的\n待机时间：5080毫安大电池，充满电中度使用一天没问题。\n其他特色：价格地道，质量好。还有144HZ高刷，你还想要什么自行车', '原子银', '2022-06-18 09:07:10', 2);
INSERT INTO `data` VALUES (11119, '南***e', 5, '144真的很舒服，手机整体有点重，不过电池续航超棒，这个价位8100的机器真的性价比最高，没有之一，手机质感中规中矩，后壳质量不太好，但配置这个价位几乎都是最顶，给父亲买的，就刷刷抖音，**,打打电话，是完全没问题，运行非常流畅，用的很舒服，比之前那个手机好用多了，小米真的用心在做千元机，', '子夜黑', '2023-01-18 11:37:17', 2);
INSERT INTO `data` VALUES (11120, '邹***花', 5, '拍照清晰，音质立体感强，高刷率144hz，显示屏幕清晰，信号强，第一次买小米手机没失望，发货速度极快！包装精美，还带双系统分身，极速处理器天机8100，买的6+128工作机备用，算高配了，性价比高。', '子夜黑', '2022-09-23 01:47:04', 4);
INSERT INTO `data` VALUES (11121, '你***么', 5, '外形外观：好看\n屏幕音效：音效很好\n拍照效果：还可以，很清晰\n运行速度：开始还行，用了一个月开始慢\n待机时间：非常好', '子夜黑', '2022-08-07 12:47:53', 6);
INSERT INTO `data` VALUES (11122, 'j***f', 5, '外观额值不结，据持手感很好。摄像头处处理的比较美观。还有3.5耳机孔，完美。屏幕非常丝滑，亮叠旋好，显示效果旋细腻。拍照不精，成像效黑很好。体验不错。1运行很快。新机器感觉不源。1待机时间：待机时间可人，毕竟5080的大电他。天玑8100真的强。打游戏轻松拿捏', '时光蓝', '2023-03-03 00:30:09', 5);
INSERT INTO `data` VALUES (11123, '_***琪', 5, '总体体验来说这款手机是非常值得入手的，3A游戏原神畅玩。\n外形外观：这个价位这个颜色的颜值我个人觉得没毛病！\n屏幕音效：屏幕不用我多说了lcd yyds。\n拍照效果：ennnnn这个可以忽略不计?相信买这个手机的小伙伴都不是奔着拍照去的吧。\n运行速度：一个字！丝滑?\n待机时间：这个要看你要用这部手机来干嘛啦，我玩的是3A游戏原神，画质开到最高能玩6小时左右吧。\n是真的可以玩原神哦，画质也可以，比我之前魅族的旗舰机好多了，8100真的可以再战一年！\n后续还有追评', '原子银', '2023-01-03 09:50:29', 6);
INSERT INTO `data` VALUES (11124, '啊***吗', 5, '外形外观：白色的颜值很高，非常漂亮\n屏幕音效：LCD的屏幕很护眼，就是奔着LCD屏幕买的，给父母用\n运行速度：MIUI8G刚好够用\n待机时间：大电池?67W快充，续航没焦虑', '奶盐白', '2023-02-06 16:57:36', 4);
INSERT INTO `data` VALUES (11125, 'x***2', 5, '外形外观：很好，大小正好，很有手感\n屏幕音效：护眼，眼不累，led的好屏幕\n拍照效果：很好，效果不错，日常绝对够用\n运行速度：流畅，稳定，刷刷刷', '时光蓝', '2022-06-27 20:34:13', 4);
INSERT INTO `data` VALUES (11126, '罗***X', 5, '给老丈人买的，手感比我的水果13pro轻巧，屏幕效果不错，144刷新率很流畅，LPDDR5的运存，UFS3.1存储，12+256的搭配，1千8出头的价格，挺满意的', '时光蓝', '2022-11-19 18:33:18', 7);
INSERT INTO `data` VALUES (11127, 'h****', 5, '红米手机性价比高，运行系统流畅没有卡顿，电池很耐用，屏幕看着也很舒服，也不怎么热常规使用还是不错的。', '时光蓝', '2022-07-25 16:38:08', 5);
INSERT INTO `data` VALUES (11128, '异***灵', 5, '外形外观：看着很漂亮，银色的比想象中的好看\n屏幕音效：LCD直屏不伤眼，音效也还可以\n拍照效果：同价位的不错了，价位在这里不能跟旗舰机比\n运行速度：运行速度还是挺快的\n待机时间：一天没问题\n其他特色：充电速度快，从0到100大概40分钟，总体不错，这个价位推荐购买', '奶盐白', '2023-01-27 12:16:58', 5);
INSERT INTO `data` VALUES (11129, 'g***s', 5, '外形外观：中规中矩，感觉黑色挺适合男生使用的，握持手感也很好，窄一点长一点\n屏幕音效：LCD屏，是我选择这款机器的主要原因，高刷新率，用起来很爽，上下双扬声器，音效也还不错\n拍照效果：可以忽略\n运行速度：就两个字，流畅，而且发热也不是很严重\n待机时间：大电池，低功耗，待机时间对我来说很够用了', '子夜黑', '2022-08-25 15:20:32', 5);
INSERT INTO `data` VALUES (11130, 'u***n', 5, '五芒星评价?第一次买小米系列手机，这款是red mi。充电很快，尺寸比?大，开机就有各种APP:拼duoduo、bilibili、淘  特、kuai手，不喜欢怀疑是不是自带的等等，京东物流快。客服回复及时态度好，有问必答。下午开得机，手机显示凌晨四点的时间', '奶盐白', '2022-09-03 19:21:41', 4);
INSERT INTO `data` VALUES (11131, '通***杜', 5, '外形外观：非常有质感，突出了现代科技工业品的质感\n屏幕音效：屏幕很好，音效很棒\n拍照效果：虽不是主打拍照，但已经很牛了\n运行速度：不玩游戏，办公足够足够了\n待机时间：一天没问题\n其他特色：性价比第一，我认为是目前性价比最好的机子了', '时光蓝', '2023-03-06 13:19:18', 4);
INSERT INTO `data` VALUES (11132, 'j***w', 5, '是最新款了，\n外形外观：好看，线条流畅，放口袋也问题，轻重刚好\n拍照效果：效果不输苹果?，很清晰，视频拍照都很高清\n运行速度：快，不用等待\n屏幕音效：灵敏，清晰', '时光蓝', '2022-08-25 22:44:57', 4);
INSERT INTO `data` VALUES (11133, '小***饭', 4, '外形外观：外观很漂亮，然后材质很用的很不错，忘记了很舒服。\n屏幕音效：音效还没试试，听说还是不错的，双扬声器用起来还是很好的用的。\n拍照效果：大象是拍照还是不错，在这个价位用起来还是很好用的，主要是6400万像素，影像效果不会太差。\n运行速度： 用的最新的8100的处理器肯定是不错，非常的好，打游戏一点都不卡，拍视频一样很流畅，平常是用一点问题都没有。\n待机时间： 5000毫安大电池，非常的大，一天待机都用不完。', '时光蓝', '2022-11-13 12:48:49', 3);
INSERT INTO `data` VALUES (11134, '庄***4', 5, '性价比很高，手机非常顺畅，打游戏丝滑，听音乐舒服。\n全新靓机，运行流畅。LCD屏幕对眼睛非常友好，续航能力持久，67w快充半个小时多就充满了。很不错，在这个价位，红米还是很香的，派大星服务好，产品颜色挺不错的', '时光蓝', '2022-12-02 16:13:30', 6);
INSERT INTO `data` VALUES (11135, 'Y***n', 5, '手机收到了，速度非常快，不愧是天玑8100处理器，这款手机应该是性价比最高的天玑8100手机了，性能真的是这个级别的天花板了，屏幕我也很喜欢，LCD党果然YYDS,再加上67W快充，不到一个小时就能充满，新机器一天半才冲一次电，除了不玩游戏，基本一直在用，有这个续航能力真的很强了。', '子夜黑', '2023-02-01 21:00:04', 8);
INSERT INTO `data` VALUES (11136, 'S***8', 5, '外形外观：很喜欢，颜色很好看。\n屏幕音效：清晰\n拍照效果：像素高，效果不错。\n运行速度：流畅。\n待机时间：一天使用没有问题。\n其他特色：新机型，各方面表现都不错。', '时光蓝', '2022-07-01 23:04:11', 4);
INSERT INTO `data` VALUES (11137, '取***n', 4, '给妈妈买的，很实用，大电量，而且性能很强。也有67w快充，屏幕大。双扬声器，声音也大。性能强，再用3，4年也没问题，双卡双5G。\n屏幕音效：双扬声器，声音大。\n运行速度：天机8100，性能肯定不差', '奶盐白', '2022-10-05 11:29:54', 4);
INSERT INTO `data` VALUES (11138, 'B***V', 5, '外形外观：简约风，实用至上主义，黑色比较低调内敛\n屏幕音效：LCD久看眼睛疲劳确实没这么严重\n拍照效果：拍照还过得去，能用，手稳一点也能拍的挺不错的\n运行速度：很流畅，天玑8100确实给力\n待机时间：5000+毫安能撑一天，如果不玩游戏的话', '子夜黑', '2022-07-09 19:33:16', 5);
INSERT INTO `data` VALUES (11139, 'j***u', 5, '商品用着很不错  一千五百多元的价格也对得起这个配置了  平时用来打游戏刷视频什么的也是可以满足了  另外一个手机可以当作配用机来用了  颜色也很不错  虽然壳子有点塑料质感 但也行  送的手机壳有仿充电口进尘的好处 非常不错', '奶盐白', '2022-09-22 12:42:51', 3);
INSERT INTO `data` VALUES (11140, 'K***3', 5, '外形外观：喜欢金属质感\n屏幕音效：屏幕比**常用的大\n拍照效果：日常拍照可以的\n运行速度：玩游戏非常流畅\n待机时间：大电池杠杠的\n其他特色：网上测评的神机 玩游戏做备用机都没有任何问题', '原子银', '2023-03-05 10:03:25', 2);
INSERT INTO `data` VALUES (11141, 'D***点', 5, '备用机坏了，正好赶上双11，之前一直看note11t配置可以，双11价格实惠，外观配置完美，机器出了好一点。几乎没有短板，性价比极高', '奶盐白', '2023-01-09 00:31:00', 7);
INSERT INTO `data` VALUES (11142, '小***y', 5, '外形外观：外观看着非常舒服，拿在手里手感也非常棒，质感很好\n屏幕音效：屏幕分辨率也非常好，用着很顺滑，没有卡顿\n拍照效果：6400万像素拍照非常清晰，真实性很高\n运行速度：6+128的配置给家里老人用，这个运行速度非常的好了，天玑8100的高端处理器，这手机用个几年没有问题\n待机时间：5080mAh的超大容量电池待机时间超级久，而且配有67W的高功率充电器，一个小时就能充满，完全不会有电量焦虑\n其他特色：就是双十一价格还是非常棒的，整体的感觉就是物美价廉', '子夜黑', '2022-11-14 22:03:16', 5);
INSERT INTO `data` VALUES (11143, '大***Z', 5, '外形外观：很好看\n屏幕音效：音质好\n拍照效果：很清楚。\n运行速度：极速流畅\n待机时间：久，耐用。\n其他特色：好用，性价比高 流畅度很高。很喜欢。很好很好，物流极速。发货很快！！', '奶盐白', '2022-09-03 11:57:29', 4);
INSERT INTO `data` VALUES (11144, '斌***3', 5, '运行速度：天机8100，不错的处理器。运行主流游戏足够了\n待机时间：待机时间一天足够了，五千多，充电速度实测50分钟充满，前边十几分钟由25%到一半。\n其他特色：摄像头，外观设计可以，苹果造型\n\n外形外观：外观漂亮，略长，适合单手模式', '子夜黑', '2022-09-10 21:30:37', 5);
INSERT INTO `data` VALUES (11145, '梦***l', 4, '外形外观：给朋友买的，听他说还不错，手感很好\n\n屏幕音效：音质也不错，屏幕很清晰，大方\n\n拍照效果：拍照也很清楚，自带美颜功能，朋友非常喜欢\n\n运行速度：运行速度很快，一点都不卡，这一点十分好\n\n待机时间：差不多一天吧，时间很长\n物流很快，第二天就到了，效果不错，好评', '奶盐白', '2022-11-29 13:27:12', 5);
INSERT INTO `data` VALUES (11146, 'j***4', 5, '外形外观：白色款很赞，原厂保护套很厚实\n屏幕音效：奔着LCD才买的，天马屏还可以啊，原厂贴膜用着很顺滑\n拍照效果：扫码机要求不高\n运行速度：8100神U+12g大内存使用不卡顿，12g版建议关掉扩展内存\n待机时间：一天一冲，66w充电器大小合适，携带方便\n其他特色：miui一定要关闭广告，卸载无用预装app，总体上使用体验不错。', '奶盐白', '2022-11-19 20:47:11', 4);
INSERT INTO `data` VALUES (11147, '江***篓', 5, '1：上一个手机红米NOTE7用4年了，这次买新手机还是选择红米NOTE品牌，这个是我喜欢外形外观，\n2：屏幕清晰，手握舒适， LCD 旗舰直屏，\n颜色正，比较快，有质感，边框圆滑过渡，13运行\n流畅，使用后再评论外形外观，外观硬朗，很好看，\n3：联发科8100移动平台，颜色漂亮，具有次旗\n舰的手机体验，具有令人满意的续航能力，音质很\n好，\n4：有感觉体验顺畅无比清晰自\n然，高大上，关于手机，视觉\n效果独树一帜，\n原色屏，手感极好，商务风范，很\n清晰，\n5：目前可以，操作也很方便，超级流畅，\n搭配\nusf3.1+lpddr5内存规格，还是很大错的，年度真香\n旗舰处理器，可以，立体非对称双扬声器，\n6：主流大气，待机超级长，', '时光蓝', '2023-01-10 10:40:13', 3);
INSERT INTO `data` VALUES (11148, '房***晨', 5, '外形外观：送给妈妈的，特意买的白色，觉得十分好看\n屏幕音效：有杜比音效，双扬声器，声音很大\n拍照效果：有防抖，拍照很清晰\n运行速度：买的8G，也不玩游戏，日常就是聊天和看短视频\n待机时间：只用来电话聊天，看看视频，一整天都不用充电', '奶盐白', '2023-02-01 14:05:52', 4);
INSERT INTO `data` VALUES (11149, '宇***6', 5, '年度性价比神机！天玑8100干到1500！\n外形外观：小米家族式设计，没什么好说的，直屏，不割手\n屏幕音效：有高刷就很爽，爸爸刷短视频反正他说很不错\n拍照效果：扫码水平，这个价位还要啥自行车\n运行速度：天玑8100加上稳定miui够用几年了，给爸爸用的，平时就刷刷视频什么的，需求不高，流畅度极佳\n待机时间：很久！5000大电池加66w快充，爸爸够用一天\n其他特色：系统自定义的功能特别多，尤其是升级14后还有很多贴心小功能', '子夜黑', '2023-01-12 15:11:25', 4);
INSERT INTO `data` VALUES (11150, '当***式', 5, '新机用了也有段时间了，感觉很好用，性能强劲，日常使用中没有出现过什么问题，网速也很快，打游戏也不卡，还有一点就是充电真的很快，一会时间就充满了，miui系统也是真的很好用，有些功能我很喜欢，下次可以继续追了。', '子夜黑', '2023-01-12 13:00:41', 5);
INSERT INTO `data` VALUES (11151, 'j***P', 5, '外形外观：亮黑\n屏幕音效：高清大屏\n拍照效果：清晰\n运行速度：非常快\n待机时间：超长\n其他特色：天玑8100，日常游戏 毫无压力', '子夜黑', '2022-12-15 22:08:35', 1);
INSERT INTO `data` VALUES (11152, 'j***2', 5, '外形外观：外观颜值：很好看 材质手感：很好 舒适度：很好 尺码大小：合适。\n拍照效果：拍照不常用，还可以，扫码反应很快。\n运行速度：8G运行内存只剩2到3G左右可用。', '原子银', '2022-10-23 23:04:28', 4);
INSERT INTO `data` VALUES (11153, '遇***l', 5, '给爸爸买的手机，很好用，很流畅，声音大，电池大，充电快，小米老粉了，一直在用小米手机，给爸爸换手机直接闭眼入！！', '时光蓝', '2022-09-01 23:44:33', 7);
INSERT INTO `data` VALUES (11154, '小***市', 1, '512g存储手机，翻遍全网最后选择了这款红米11tp。昨天下单，刚刚收到的，迫不及待的进行了试机。完全个人真实感受，暂评价如下：\n1/手机&ldquo;颜值长相&quot;：完全可以接受！\n2/手机手感：并没有网评那么恶劣，比如说什么塑料中框，后壳等等，本人自认为是比较挑剔一族了，对手机外观用料完全可以接受！\n3/手机拍照：仅就这部手机，再过一百年还是给差评\n    \n因为在网上看过很多拍照评价，因此有一定心理准备。但是收到的实物真的是大跌眼镜，大失所望，一颗心爆成了满天星&hellip;&hellip;    外面阳光灿烂，室内光线充足拍摄照片暗的一p。土豪金的窗帘又暗又变色发青&hellip;&hellip;\n4/手机系统：暂时用着还可以，比较流畅，下载安装软件速度都不错。系统啰嗦太多太多，好多软件都要挨着个的允许通过安全信息。\n5/垃圾app太多：一部手机装了几个浏览器，输入法，各种网上比较广泛的app不管买家用不用，都被一勺烩的预装在手机里，小米是各大app代言人吗&hellip;&hellip;\n\n以上纯属个人感受，希望京东粉和米粉理性选择&hellip;&hellip;', '子夜黑', '2023-03-05 15:38:12', 5);
INSERT INTO `data` VALUES (11155, 'j***j', 5, '给老爸买的，手机上手特别舒服，后盖摸起来也没有那种廉价塑料的感觉，因为后盖是塑料，所以5000mah的电池也不显得很重，天玑8100的处理器用起来特别快，完全不像一个千元机的速度，侧边指纹解锁真的很方便，手去正常握持的时候刚好能把手机解锁，不用刻意去解锁手机了', '子夜黑', '2022-11-09 17:18:26', 2);
INSERT INTO `data` VALUES (11156, 'y***o', 5, '外形外观：带有金属质感的银色十分炫，很显高档\n屏幕音效：屏幕十分高清也润眼，音质是杜比重低音，看视频有像在影院的音效\n拍照效果：拍照效果中规中矩，满足一般曰常需要\n运行速度：运行流畅\n待机时间：待机时间长，充电更是超级快', '原子银', '2022-09-19 20:37:19', 4);
INSERT INTO `data` VALUES (11157, 'c***8', 5, '手机大小合适，手感不错。系统性能不错，运行很流畅，各种程序都不卡，屏幕显示效果很好，512G的存储，暂时不用担心内存有问题了。平民手机，大众选择。', '子夜黑', '2022-11-13 21:24:55', 2);
INSERT INTO `data` VALUES (11158, '爱***冉', 5, '手机特别好反应特别迅速\n外形外观：外形很漂亮 性价比非常高\n屏幕音效：非常顺滑 可以144w\n拍照效果：无敌巨巨巨美丽\n运行速度：很快 库存很大很喜欢\n待机时间：可以支持一天\n其他特色：性价比高吖', '子夜黑', '2022-06-27 17:27:50', 5);
INSERT INTO `data` VALUES (11159, '晓***h', 5, '买来给家里人使用，平常打电话，聊微信，刷抖音，很够用的，屏幕清晰，LCD旗舰直屏，颜色正，有质感，运行流畅，很好看，联发科天玑8100移动平台，令人满意的续航能力，音质很好，很清晰，目前可以，操作也很方便，超级流畅，搭配usf3.1+lpddr5内存规格，双扬声器，居中打孔屏幕，金属质感，像素够用了，x轴线性马达，144hz高刷，京东很是给力，快递很快。', '时光蓝', '2023-01-30 17:09:22', 3);
INSERT INTO `data` VALUES (11160, '灵***风', 5, 'Redmi Note11T Pro5G 天玑8100 速度畅快,天玑800性能小金刚，超级牛掰拍照效果清晰，续航能力很好，无敌战神其他特色，边框直角的，喜欢这个设计，看着有层次感。显示效果，屏幕挺好的,显示细腻清晰，跟以前的nova3比较，清楚，超大机身内存,在配合清楚的拍照能力，nice,电量可以正常使用一天，没得问题', '子夜黑', '2023-01-03 15:24:31', 4);
INSERT INTO `data` VALUES (11161, 'j***6', 5, '老母亲的手机突然垮掉了，赶紧买了这个新款滴！也是同事推荐的，性价比挺高的！无论是运行内存还是存储内存都无可挑剔！老人家也非常满意，运行系统很快就用熟悉了，简单好学！屏幕清晰不卡，声音悦耳动听，总之一级棒！', '原子银', '2022-09-15 10:57:05', 2);
INSERT INTO `data` VALUES (11162, '蝶***1', 5, '通信音质：通话清晰，无杂质。 其他特色：手感超级舒服?，拿着很顺手。 显示效果：屏显舒服不刺眼，画质一流。', '时光蓝', '2022-12-02 17:35:08', 6);
INSERT INTO `data` VALUES (11163, 'b***2', 5, '外形外观：非常有质感，成熟\n屏幕音效：很不错，色彩缤纷，声音浑厚\n拍照效果：还行吧，应付日常够了\n运行速度：就是冲着这个来的\n待机时间：非常给力\n其他特色：性价比巨高的一个手机', '子夜黑', '2022-11-19 19:58:27', 4);
INSERT INTO `data` VALUES (11164, '爱***魚', 4, '极致性价比，lcd+144hz高刷+NFC+超前耳机孔+天机8100\n67W充电，日常完全够用\n外形外观：白色yyds超好看，设计很好\n屏幕音效：屏幕看着不会累\n拍照效果：拍照效果也不错\n运行速度：天机芯片体验不比骁龙差\n待机时间：妥妥一天没问题\n其他特色：客服服务好', '奶盐白', '2022-11-25 23:10:22', 4);
INSERT INTO `data` VALUES (11165, '张***生', 5, '外形外观：很好，平整有度！喜欢的类型。\n屏幕音效：屏幕直面屏（选购的决定性理由）\n拍照效果：尚可，最后一张图可见。\n运行速度：快，反正我够用。\n待机时间：可以，普遍都是在一天。', '奶盐白', '2023-01-15 22:24:30', 7);
INSERT INTO `data` VALUES (11166, '忆***3', 5, '蹲点买的红米note11TPro，给家人买LCD屏更护眼，这款处理器也比新款12性能更好，加上快充、红外、NFC功能，非常适合长辈用了，活动也很给力', '时光蓝', '2022-10-30 12:31:22', 6);
INSERT INTO `data` VALUES (11167, 'l***g', 5, '外形外观：奶白盐非常好看，磨砂的比亮面更高级！\n屏幕音效：清晰明亮，双喇叭音质立体声不错\n拍照效果：拍照不如新出的note12，但是整体够用！\n运行速度：天玑8100，性能强劲，比12的1080好太多，还是11t水桶机??\n待机时间：太耐用了，刷一天视频！游戏也好几个小时\n其他特色：送原装硅胶壳子，67w充电速度已经足够快啦！', '奶盐白', '2022-11-13 15:32:35', 4);
INSERT INTO `data` VALUES (11168, '7***道', 5, '第五次在京东家买手机，质量和速度都非常给力。\n外形外观：时尚好看\n屏幕音效：立体环绕的音质\n拍照效果：拍照效果：清晰和很好看 \n运行速度：8G+128足够日常的实用', '原子银', '2023-01-01 14:22:49', 5);
INSERT INTO `data` VALUES (11169, 'u***h', 5, '外形外观：银色的还是很漂亮的，质感棒棒的\n屏幕音效：lcd屏不伤眼睛\n拍照效果：拍照对的起这个价格了\n运行速度：天玑8100很给力，不卡顿\n待机时间：老年人使用完全不担心待机时间，杠杠的\n其他特色：运行内存在存储内存允许的情况下，竟然可以6+2，真的是意外惊喜！', '原子银', '2022-06-27 20:02:03', 1);
INSERT INTO `data` VALUES (11170, 'j***A', 5, '外形外观：好看，选的白色，白色yyds!\n屏幕音效：Lcd的屏幕，挺好的！\n拍照效果：还可以，这个价位很不错了！\n运行速度：天玑8100，日常使用，轻中度游戏完全够用了！\n待机时间：新手机都挺耐用！\n其他特色：这个价位还能有红外遥控，真的很惊喜！', '奶盐白', '2022-11-11 22:48:07', 4);
INSERT INTO `data` VALUES (11171, 'j***b', 5, '外观非常好看，这个充电器好重跟手机一样重了，整体比预期的要好的多', '奶盐白', '2022-11-06 18:10:34', 6);
INSERT INTO `data` VALUES (11172, 'L***o', 5, '外形外观：漂亮，比note9轻薄了，手感舒服\n屏幕音效：屏幕分辨率达到要求，显示细腻\n拍照效果：拍照可以，很少使用\n运行速度：新机运行速度快，系统流畅，玩和平精英和王者荣耀都没有问题，比上一个note9好多了', '子夜黑', '2022-10-04 16:01:07', 4);
INSERT INTO `data` VALUES (11173, '芒***莓', 5, '很好用的手机，性价比超高。67w的快充，144hz的自适应屏幕刷新率，都让我感到了超值与科技的进步。不到2000都能享受到这样的功能，虽然是塑料后壳，但是一千多块还要啥自行车，爱了爱了。', '子夜黑', '2022-07-15 17:25:37', 2);
INSERT INTO `data` VALUES (11174, 'O***-', 5, '外形外观：方正边框 修长 握持感很足\n屏幕音效：屏幕细腻光滑 有杜比全景音效\n拍照效果：拍照影像模式优化色彩很好\n待机时间：5000毫安大电池  长待机再也没有低电量焦虑了', '奶盐白', '2022-09-16 11:44:59', 4);
INSERT INTO `data` VALUES (11175, '项***6', 5, '省会仓库直接发货的 速度相当快！收到货包装完好，开机有电！手感绝佳，在这个价位颜值无敌！前面买到的手机都不给力果断退货了，小米值得期待，京东值得信任！买电子产品家电都是京东，希望越来越好！加油奥力给?', '原子银', '2022-07-12 18:34:01', 9);
INSERT INTO `data` VALUES (11176, '叹***许', 5, '双十一入手的这款红米，12+256内存够用了，没有下载游戏，所以不知道体验如何。快递员很贴心专门打了电话让去取件。\n刚开始用的几天充电时偶尔会有机身发烫的问题，后来就不会了，运行速度还算灵敏，67w闪充，一个小时就能充饱电，对于我这样整天机不离手的人来说，电量基本够用一天。对于拍照不感冒的我感觉像素还挺清晰，特别值得夸赞的是手电筒是黄色暖光，个人非常喜欢?。', '时光蓝', '2023-01-11 23:08:18', 2);
INSERT INTO `data` VALUES (11177, 'j***6', 5, '手机手感非常好、不易滑落，下单第二天就到了物流非常快\n屏幕音效：屏幕没有频闪非常舒服\n待机时间：续航时间非常长\n运行速度：打开软件速度挺快的', '奶盐白', '2023-01-18 00:51:12', 2);
INSERT INTO `data` VALUES (11178, '岸***豆', 5, '外形外观：外观简洁大方，很好看，很有质感，不同的角度看会呈现不同的颜色，原子银很nice\n屏幕音效：屏幕很清晰，音效也很棒\n拍照效果：拍照效果挺好的，比原图多加了鲜艳的色彩，但这个色彩不会过度，挺好看的。\n运行速度：运行速度对于我不打游戏来说还是可以的，偶尔会出现卡顿或者是闪退的现象。具体原因还不知。\n待机时间：待机时间很长，目前一天多点才充一次，而且充电速度很快，不到一小时，40分钟左右能充满\n其他特色：用惯了小米系统，用着这个手机真的还挺好的。性价比非常高，物流方面很快，京东售后也很给力，保价也有效在有效期内。', '原子银', '2022-11-06 14:28:56', 4);
INSERT INTO `data` VALUES (11179, '漫***華', 5, '外形外观：蓝色很清爽，整体简洁大方，摄像模组排列低调，没有花里胡哨的元素\n屏幕音效：高刷实用，1080P分辨率，双扬声器\n拍照效果：适合静景，够用（能扫码就行）\n运行速度：流畅，关闭系统广告、各种乱七八糟的推送更佳\n待机时间：电池容量大，67W充电功率够用\n其他特色：极其先进的3.5mm耳机口', '时光蓝', '2022-11-24 17:40:57', 3);
INSERT INTO `data` VALUES (11180, '今***啊', 5, '手机非常流畅。没有杀后台现象。只是发现上面喇叭声音很小。应该是个别现象吧。物流很快，质感很好，很漂亮，很喜欢', '子夜黑', '2022-07-04 09:10:34', 2);
INSERT INTO `data` VALUES (11181, 'g***8', 5, '外形外观：大气美观实用\n屏幕音效：好听又好用\n拍照效果：拍照效果真的好\n运行速度：运行速度很不错，用的就是好\n待机时间：待机时间长，充电速度快\n其他特色：物美价廉', '时光蓝', '2022-08-06 23:20:52', 5);
INSERT INTO `data` VALUES (11182, '-***-', 5, '颜值绝对担当，背壳蓝色很漂亮，光线照射着会变色，非常闪耀。指纹集成在右侧的开锁键上，没有屏下指纹方便，但毕竟价格在这儿，也可以理解。', '时光蓝', '2023-03-17 18:51:40', 5);
INSERT INTO `data` VALUES (11183, '风***边', 5, '外观外形：红米Note 11T Pro正面接纳6.6英寸中挖孔屏策划，边框是纯平小立边，而我们拿到手的时间蓝配色带有闪砂渐变成效，完整机器质感很不错\n\n产品质量：屏幕是加分项，LCD材质，144Hz七档变速高刷，画质精细，全程DC调光。摄像方面，后置6400万主摄+800万超广角+200万微距，前置1600万自拍，其他NFC、5G双卡双待、红外遥控、立体声双扬声器、3.5耳机孔，应有尽有。\n\n使用体验：Note 11T Pro是红米家中端新王者，芯片搭载的是天玑8100处理器，配上LPDDR5和UFS3.1的高存储格式，以及VC液冷散热+7层立体石墨的散热体系，今年联发科大显神威，这款8100发热控制让隔壁家汗颜。拍照也不含糊，对比明晰，细节也很到位。内置的是5080mAh容量电池，加载小米自研的磅礴P1充电芯片，67W有线快充，前60%电量只需要10分钟，非常之快。X轴线性马达，在游戏中的震感反馈也很有手感。', '时光蓝', '2022-11-17 18:14:19', 3);
INSERT INTO `data` VALUES (11184, 'j***0', 5, '买的红米T11rou浅蓝色很好看，荧光渐变，非常漂亮，音效也不错，新机速度快，67W快充充电很快，双卡双待的，', '时光蓝', '2022-11-07 15:36:31', 2);
INSERT INTO `data` VALUES (11185, '心***楞', 5, '外包装简洁，感觉不像是手机，有挤压的痕迹，里面有真空填充袋，打开外包装，手机原装盒完好无损，双十二京东也是够忙了，还好里面的手机完好无损，买手机电器家电，首选京东，强大的售后保障，目前手机状态良好，一如既往相信京东，也希望京东继续保持严把质量关，2023一如既往的为京东会员和粉丝们提供优质便捷安心的服务！！！', '子夜黑', '2023-01-01 06:27:17', 9);
INSERT INTO `data` VALUES (11186, 'c***8', 5, '外形外观：外形外观设计精美，颜值比较高。\n屏幕音效：屏幕及音效都很不错，清晰度比较高\n拍照效果：拍照效果还不错，稍后摄像头像素都挺高。\n运行速度：运行速度比较快，512存储空间不错。', '子夜黑', '2023-03-20 14:47:21', 4);
INSERT INTO `data` VALUES (11187, '小***x', 5, '给父母买的，直接买了两部，给老两口一起换了，价格不错，系统很流畅，银色的有拉丝感，很喜欢，黑色的手机也很高级，屏幕效果不错运行速度快，拍照也很清晰！，', '原子银', '2023-01-26 20:26:01', 6);
INSERT INTO `data` VALUES (11188, 'j***Q', 3, '钢化膜根本不是原装但是手机壳是不错的', '时光蓝', '2022-06-13 11:50:55', 5);
INSERT INTO `data` VALUES (11189, '王***6', 5, '外形外观:很漂亮，白色的，很滑，很舒服 \n屏幕音效:屏幕高清晰度。 \n拍照效果:拍照也很好\n 运行速度:运行速度不卡，非常流畅。\n 待机时间:待机，正常使用一天没问题，充电速度怏。', '奶盐白', '2022-11-27 21:49:05', 3);
INSERT INTO `data` VALUES (11190, '刷***0', 5, '正品，买的放心，价钱也公道，满意！真的很好用，对商品非常满意，属于无限回购款，推荐！款式很大方，质量非常好，价钱也很合理快充充电超级超级快！质量也非常不错，的确物有所值', '子夜黑', '2023-03-07 16:26:29', 1);
INSERT INTO `data` VALUES (11191, '周***i', 5, '手机用着不错   专门去小米之家对比了一下   音质超级好  屏幕也大  电池续航没的说   超级大   摄像性能一流 不存在卡顿', '子夜黑', '2023-02-01 13:26:34', 5);
INSERT INTO `data` VALUES (11192, '昨***笑', 5, '总体上还是性价比的首选\n外形外观：外观还是很上大气上档次的\n屏幕音效：LCD的屏幕对老人家还是很友好的\n拍照效果：没有什么要求    但感觉也还不错\n运行速度：很快   联发科耶还是很给力的\n待机时间：够给力的', '子夜黑', '2022-10-03 17:06:59', 4);
INSERT INTO `data` VALUES (11193, '闻***筱', 5, '关注这款手机发市会后，就决定买了，交定金，交尾款，没有想到6月1号就到了，京东快递速度真是快。从芯片天玑8100到LpDDR5内存，67W快充，3.5耳机接孔，NFC都是我想要的。特别是非常喜欢这款手机的LCD屏，对眼睛刺激小。因为给老婆买的，所以选择时光蓝。这样全家人都用红米Note系列(我用红米Note9Por孩子用的红米Note10Por)。还有就是这款手机系统也非常好，价格也亲民。', '时光蓝', '2022-06-01 23:04:39', 8);
INSERT INTO `data` VALUES (11194, 'j***B', 5, '外形外观：很漂亮，各种手机壳带上应该也不错，可以hold住大部分手机壳。\n拍照效果：比我的旧手机拍照要好看一些。\n运行速度：挺快的\n其他特色：充电很快。指纹解锁很方便。就是如果第1次你人脸识别没有识别到的话，他就会给你弹出来让你图案识别或者密码识别。在这种情况下，你想再次人脸识别，你就要点那个图标才能行。我觉得这个有一点的麻烦。', '奶盐白', '2023-01-27 21:08:36', 5);
INSERT INTO `data` VALUES (11195, 'u***p', 5, '自从开始用红米手机，就停不下来了，之前一直用的最低端的，什么note9, note9pro，今年才买的，一千块多一点，出奇的好用。为了备战暗黑破坏神，才准备入手一个高端一点的，跑分七八十万的。比较了很久，突然发现新款上市了。立马入手搞起。不出所料一如既往的好用，真是性价比超高，2000的价格，4000的顺滑。啥游戏都毫无鸭梨，原神直接开最高画质。太绝了。原神只试完了一下就删了，图片是剑侠世界3的截图', '子夜黑', '2022-06-27 17:31:31', 5);
INSERT INTO `data` VALUES (11196, 'd***g', 5, '手机非常棒， 速度很快，外观非常漂亮，拍照非常的清晰，容量大，这次再也不怕容量不够了，红米的手机使用感非常的好，物超所值，价格不贵，够用就行了', '原子银', '2022-08-07 08:06:31', 3);
INSERT INTO `data` VALUES (11197, 'j***3', 4, '外形外观：非常好看。非常的时尚\n屏幕音效：看着非常清晰。非常漂亮\n拍照效果：自带美颜效果。拍照杠杠的。\n运行速度：运行速度非常的快。一点都不差劲\n待机时间：非常强大。很好。', '时光蓝', '2022-11-03 23:11:52', 3);
INSERT INTO `data` VALUES (11198, 'j***b', 5, '待机时间：待机时间长，基本上可以用一天，不过67w快充，充电速度很快\n运行速度：运行速度超级快，不卡，非常好用\n拍照效果：拍照一般，这个价位够用了\n外形外观：外形很好看，我很喜欢', '子夜黑', '2022-12-28 14:20:16', 4);
INSERT INTO `data` VALUES (11199, '浅***7', 4, '新手机就是喜欢，哈哈，一直用小米，这个颜色纠结了好久，因为看详情和网友评价，觉得老是看不清楚色彩，担心有色差。收到很满意这样的浅蓝色。主要内存也够大，适合宝妈给孩子拍很多照片存着。', '时光蓝', '2023-01-18 11:59:24', 6);
INSERT INTO `data` VALUES (11200, '凶***食', 5, '外形外观：不错，这次的塑料质感做的非常好了\n屏幕音效：很好，不闪屏DC调光NICE\n拍照效果：这价格能用就行\n运行速度：挺快的，高刷很流畅\n其他特色：充电快，续航久。正经是第二台了，家人反馈不错，长辈用经济实惠。', '子夜黑', '2023-01-14 23:00:27', 4);
INSERT INTO `data` VALUES (11201, 'j***i', 5, '这次双十二买的，活动力度大，性价比很高，手机外观漂亮，音质也不错，使用起来很流畅，充电特别快，电池续航能力强，整体感觉很满意，颜色很正，赞', '原子银', '2022-12-26 15:16:55', 5);
INSERT INTO `data` VALUES (11202, '麦***善', 5, '充电快，续航强。不会烧屏不发热，游戏表现也好，系统也好，各方面都非常强。非常具有性价比，可以称为小钢炮。', '子夜黑', '2022-07-02 18:08:19', 6);
INSERT INTO `data` VALUES (11203, 'D***诺', 5, '收到啦，很不错，非常喜欢，值得购买，\n外形外观：很满意?，做工很好\n屏幕音效：双扬声器，音质完美\n拍照效果：6400W满足拍照需求，清晰\n运行速度：8+完全够用，运行流畅\n待机时间：五千多大电池?，一天足够使用\n其他特色：总体效果很好，完美完美', '时光蓝', '2023-03-05 12:03:55', 3);
INSERT INTO `data` VALUES (11204, '饭***x', 5, '我太开心了，昨天晚上下单，今天上午九点就送到了，体验感比tb强多了，手机包装好，手感好，很漂亮，使用流畅，续航给力！开心！性能\n小金刚我也拥有了！', '子夜黑', '2023-01-02 13:05:38', 2);
INSERT INTO `data` VALUES (11205, 'M***0', 5, '红米性价比超过的8100芯片手机，正好搞活动果断下手，买了蓝色的非常漂亮，刚拿到手时被惊艳了，用了一段时间之后感觉很不错，速度稳定，温度不高。屏幕的显示也清晰，就是拍照一般般，不过问题不大，总体对这部手机还是很满意的。', '时光蓝', '2022-08-25 14:35:30', 5);
INSERT INTO `data` VALUES (11206, 'u***y', 5, '外形外观：直角边框设计，配色好看有层次感\n屏幕音效：屏幕显示细腻，刷新率高，lcd屏，护眼\n运行速度：天玑8100，运行流畅不卡顿\n待机时间：正常使用一天没问题\n拍照效果：不错，物超所值', '时光蓝', '2023-01-28 11:12:12', 3);
INSERT INTO `data` VALUES (11207, '1***c', 5, '非常好用 ，外观靓丽，手感舒服，这手机的性能很好,MU13加持反应特别跟手,信号也好,网速也快,比天玑1000+好太多了,而且温度也低,充电特别快', '时光蓝', '2022-11-18 22:40:42', 5);
INSERT INTO `data` VALUES (11208, '无***8', 5, '还记得第一次用小米手机是很多年前了，当时好像还需要抢购，买的是一部小米2系列，手机到手后，打开试用了一下，感觉真的很不错，当时那个配置那个价格，好像真的很不错，一直用了好几年，总体那时候感觉小米还不错，现在双十一在京东又买了一部red米not11Pro，性价比很高，目前新机很流畅物有所值吧，希望手机能多用一些时间，总体购物感觉很好，值得推荐！', '时光蓝', '2022-11-16 09:23:23', 4);
INSERT INTO `data` VALUES (11209, 'S***s', 5, '外形外观：千元机的外观质感和水平，胜在白色后盖。整体质感符合价位\n屏幕音效：重点在屏幕，这块定制的LCD屏确实是这个价位最大的卖点，清晰，鲜艳，不伤眼，不伤眼，不伤眼！\n拍照效果：额，不中用\n运行速度：非常快，8100的功耗比很出色。\n待机时间：很长。无游戏需求。一整天不用充电。', '奶盐白', '2022-12-30 17:42:55', 4);
INSERT INTO `data` VALUES (11210, 'C***j', 5, '手机包装特别好，运行速度特别快，快充非常不错，144赫兹高刷真不错。后面圆的好看，外形啊！', '子夜黑', '2023-02-16 20:29:02', 2);
INSERT INTO `data` VALUES (11211, '逍***石', 5, '小米红米Note 11 t Pro，好看真不错，看了好长时间了。性能CPU决定秒杀一切中端机，在千元机里面决定Number one，终于买到满意的商品了，超出期望，非常喜欢，身边的人都问我要链接', '时光蓝', '2023-01-24 18:09:16', 3);
INSERT INTO `data` VALUES (11212, 'h***7', 5, '这回是给老人换手机买了一个大内存的Redmi Note11T Pro 5 G 天玑8100 144HzLCD旗舰直屏 67W快充 8GB+512GB 时光蓝 5 G智能手机 ，屏幕采用居中挖孔前摄设计，中框使用塑料材质，屏幕保护玻璃是康宁第五代大猩猩玻璃，电池盖采用复合板材材质，镜头保护玻璃为康宁第五代大猩猩玻璃，屏幕保护玻璃有疏水疏油镀层。 上下双扬声器，杜比音效 ，后摄6400万，800万超广角，前置1600万，中端拍摄手机，手机搭载天玑8100处理器，安兔兔跑分超83万，同时采用满血版双通道UFS 3.1高速闪存。充电速度很快，67瓦快充，支持充电保护。完全充满电后玩一小时游戏，还有百分之八十左右的电 1其他特色：屏幕20.5:9定制比例，74.29mm宽度手感很棒，潮流小立边。最高144Hz 七档变速 LCD显示刷新率，杜比视界，全程DC调光，true tone真彩显示原色屏幕，硬件级防蓝光。 综上买来给老人用完全没问题，原子灰后盖看着也很好看。', '原子银', '2022-12-26 10:15:17', 3);
INSERT INTO `data` VALUES (11213, '会***来', 5, '使用感不错，触屏灵敏。像素也不错。自带的健康还可以检测睡眠质量 。。充电速度超级快。。剩余20的电还能开启省电模式 还能用个5-6小时??给力   这次我第一次买红米的手机', '奶盐白', '2022-11-16 13:01:16', 5);
INSERT INTO `data` VALUES (11214, 'r***1', 5, '发现红米note11Tpro性价比高，处理器性能好，相机拍照颜色真实点，充电速度非常快，20分钟就可以冲50块钱。续航也不错，内存也够用。买来给妈妈用的，她说比之前的华为好用。对了，NFC功能还可以把小区门禁卡和公交卡都绑定进去，确实很方便。还支持红外功能，下午试了一下可以用来开电视和空调。性能挺强大的，居然感觉手机的Iphone.13promax都没那么香了哈哈哈?', '原子银', '2023-02-03 02:17:08', 4);
INSERT INTO `data` VALUES (11215, 'X***r', 5, '奶盐白很好看，天玑8100性能很强，功耗也控制的不错，LCD屏幕很清晰，144hz很流畅，拍照也够用，买给我妈的，她很喜欢，好！', '奶盐白', '2022-11-06 20:23:46', 2);
INSERT INTO `data` VALUES (11216, '1***儿', 5, '非常满意的一次购物体验，双十一促销时购买，确实比平时更实惠。手机外形美观，电池容量特别大。充电一次不到一小时，可以从容使用两天多。用了十多天一直挺好的，运行流畅无卡顿，小米的系统是我熟悉的更容易上手。总之一切都好很满意。', '子夜黑', '2022-06-27 18:41:49', 6);
INSERT INTO `data` VALUES (11217, '石***人', 4, '物流非常快，第二天就收到手机了。67w的充电速度非常快，半小时就差不多满了。家里用的都是小米手机，换手机很方便。MIUI系统很流畅，用着也方便，老人很满意。', '时光蓝', '2022-11-16 10:12:44', 5);
INSERT INTO `data` VALUES (11218, '谁***啊', 5, '用了，将近两个月了才过来评价，手机很不错，反应速度超级快，而且不怎么发热，最主要双11的性价比很高的，超级喜欢小米系列这款11 notetpro+颜值还是说的过去的，特别推荐购买', '时光蓝', '2023-01-09 18:53:05', 6);
INSERT INTO `data` VALUES (11219, 's***a', 5, '买了note11T pro给爸妈，8+128的配置够用了，外观好看，渐变色炫彩的蓝色，开机流畅，显示为8+3的内存。很不错。。。手感也很好。', '时光蓝', '2023-01-17 21:03:14', 5);
INSERT INTO `data` VALUES (11220, '安***呢', 5, '外形外观：很方正\n屏幕音效：使用正常\n拍照效果：不错\n运行速度：目前使用不卡\n待机时间：还行\n京东物流特别的快，下单两天就送到了，拆开使用后迅速将原来手机的东西倒过来了，很不错', '时光蓝', '2023-02-17 21:21:22', 4);
INSERT INTO `data` VALUES (11221, '稳***的', 5, '手机很适合老人使用，简单，容易操作。处理器和内存日常使用足够，充电快，续航也不错。', '子夜黑', '2022-10-29 20:45:27', 2);
INSERT INTO `data` VALUES (11222, '陈***华', 5, '红米的NOTE系列一直是性价比的最佳选择。买过note3 、4、5、8pro、9、10X。8pro现在还是主力用机。这次双12又买了note 12 Pro+和这部11T pro。买11t Pro为了就是LCD护眼屏，天玑8100性能也是非常不错的。实际使用下来的确达到预期，我的8pro终于可以退役了。', '原子银', '2022-12-20 12:50:04', 4);
INSERT INTO `data` VALUES (11223, 'j***J', 5, '外形外观：很喜欢\n拍照效果：清晰\n待机时间：长\n其他特色：功能多', '时光蓝', '2022-08-14 15:16:18', 7);
INSERT INTO `data` VALUES (11224, 'S***1', 5, '给我家老头子买的手机，我家老头子买用的手机一直是小米品牌的，所以换手机还是在小米红米系列，这里看了多款型号，还是发现这个Note C T Pro的性价比比较高，所以妈妇女节活动期间果断下手，早上上班的时候下单买了，到晚上大概六7:00就送到家了，物流速度相当快。\n说这个手机的性能可谓是相当快，毕竟是个新机，然后RAM 内存6G还有扩展2G的空间，也相当于8G的内存，可以达到这个数量非常好了。\n同时说一下这个手机的包装可，包装也是非常给力，充电器是67W非常大，可以支持快速充电，另外一个给人很意外的是厂家带了手机外壳，透明的手机外壳，这样免去了，我再去买其他的手机外壳', '子夜黑', '2023-03-12 18:58:24', 6);
INSERT INTO `data` VALUES (11225, 'j***e', 5, 'Redmi Note11T Pro 5G 天玑8100 144HzLCD旗舰直屏 67W快充 。旗舰芯片性能强，运行快。大容量电池待机时间长，67w冲电快，LCD屏清晰护眼舒适。外观简约时尚。高像素摄像头拍照清晰。送货速度快，服务态度好。非常满意。好评。', '奶盐白', '2022-12-15 12:44:23', 4);
INSERT INTO `data` VALUES (11226, 'o***p', 5, '8+512才2000出头，这性价比，真是超值。就是冲着小米的红外功能来的，而且还支持NFC，性价比超高，杜比全景声，音质嘎嘎叫。整体感觉很好，平常不玩游戏，8100处理器足够够用，用了两天也没感觉到热，67w快充不慢，半小时就能充满，冲吧，兄弟姊妹们。', '子夜黑', '2022-10-02 13:20:48', 4);
INSERT INTO `data` VALUES (11227, 'j***j', 5, '红米note11T型号手机，外观做工精细，设计简约大方，直屏视觉效果非常好，充电速度也快，系统很流畅，性价比高，值得入手，京东自营购物让人放心省心', '子夜黑', '2022-09-15 21:39:25', 2);
INSERT INTO `data` VALUES (11228, 'm***z', 5, '千挑万选中还是选了这款红米的网红神机。到手后试用了下没有太大的惊喜吧，但是也不会太失望。显示效果还是不错的。细长的机身握持感很好。我买的是6+128的，这个也感觉够用了。发货神速，物流超快，感谢京东！', '原子银', '2022-09-14 11:19:46', 7);
INSERT INTO `data` VALUES (11229, 'j***j', 5, '手机挺不错的，日常使用足够了。LCD的屏幕也比较护眼，刷新率还不错，用起来很流畅，充电速度也很快。大小，重量控制的也不错。虽然是塑料机身，但外观还是很好看的，这个价位把配置搞好更重要。系统很流畅，日常拍照完全够用，充电速度也很快，总之这个价位能给的都给了，很满意。', '时光蓝', '2022-11-11 21:49:39', 5);
INSERT INTO `data` VALUES (11230, 'u***a', 5, '外形外观：外形好看\n屏幕音效：音效好\n拍照效果：像素好很清晰', '时光蓝', '2023-02-11 11:55:43', 3);
INSERT INTO `data` VALUES (11231, '风***2', 5, '外形外观：时光蓝外形大气漂亮，女士很喜欢?\n屏幕音效：6.6寸大屏幕显示清晰，手感刚好。\n拍照效果：一般拍照基本够用，色彩还原满意。\n运行速度：8+256大内存运行速度快，流畅无卡顿。\n待机时间：5080毫安大电池续航能力强劲。\n其他特色：67瓦快充基本40分钟可充满，功能齐全，体验感受很到位，京东购物速度快，质量有保证。购物满意，满分?好评！', '时光蓝', '2023-03-06 21:56:56', 3);
INSERT INTO `data` VALUES (11232, 'h***z', 5, '昨晚付尾款，今天早上就收到了，京东快递非常的给力，\n手机外观一般，天几处理器比校流畅，LCD屏幕不闪，\n下巴宽了一点。拍照，录像都正常。', '时光蓝', '2022-06-01 09:15:37', 6);
INSERT INTO `data` VALUES (11233, '卡***多', 5, '使用感受非常不错。手机有质感。颜色也很漂亮。无论看电影还是玩游戏都非常不错。高刷屏用起来很爽，充电也很快。', '原子银', '2022-12-09 16:17:27', 6);
INSERT INTO `data` VALUES (11234, 'y***m', 5, '价格不贵，性价比很高！\nCPU超快。\n发热量比自己想的还要低。\n屏幕是LCD的，显示效果超级好。\n同时有红外线和NFC。\n总之特别满意！', '子夜黑', '2022-06-03 18:11:55', 5);
INSERT INTO `data` VALUES (11235, 'j***c', 5, '拿在手里手感不错   屏幕很好没有说的边角 打孔暗影，声音效果很好。拍照可以    天玑效果很好  sive3d运行流畅\n充电速度很快', '子夜黑', '2023-02-03 22:17:28', 4);
INSERT INTO `data` VALUES (11236, '紫***武', 5, '性能：发哥853完美组合，游戏稳定，日常应用启动快\n颜值：千元机的标杆 白色是真的好看 后置摄像头排列也非常好\n充电：67W一般都是用到30%左右开始充，30分钟多点就可以充满\n系统：2月份买的 系统已经升到可以MiUi14  稳定好用 \n拍照：一般  真的一般', '奶盐白', '2023-03-16 21:56:53', 3);
INSERT INTO `data` VALUES (11237, '倾***宴', 5, '外形外观：很美观，喜欢，\n屏幕音效：不愧是2k屏幕，非常清晰，不辣眼睛，看着舒服了。\n拍照效果：一亿像素，超清楚，每拍一张照片都是大片来的，超级满意，\n运行速度：大运行内存，开十几个应用都不卡顿，非常好，很流利，\n待机时间：电池很耐用，待机一天半没问题，5000毫安再也不担心电量不够用。\n其他特色：一直都是米粉，k5opro手机，很棒，就是喜欢侧边指纹解锁，反应灵敏，比屏下指纹解锁快很多，机身轻薄，手感好，120w神仙闪充回血一字，快，红米手机值得拥有。', '幽芒', '2022-03-22 20:14:08', 8);
INSERT INTO `data` VALUES (11238, '爱***语', 5, '外形外观：真的很不赖，手感也舒服\n屏幕音效：很不错，听起来不怪就行\n运行速度：很快，比我k30快多了\n待机时间：还可以，充一次用一天\n其他特色：总体感觉不错的\n拍照效果：比旧手机强多了', '墨羽', '2022-03-25 11:40:11', 8);
INSERT INTO `data` VALUES (11239, 'E***n', 5, '屏幕音效：屏幕是真的不错 很清晰 音效也挺好的\n拍照效果：忽略\n待机时间：待机时间挺长的 看视频 玩游戏 一天也够了\n运行速度：运行的也很流畅 \n其他特色：充电是真快啊 \n外形外观：颜值够用 其实白色那个也可以', '墨羽', '2022-08-09 13:21:22', 4);
INSERT INTO `data` VALUES (11240, 'b***v', 5, '外形外观：外观稳重大气，手机后壳的陨石图案非常酷炫。\n屏幕音效： 上下双喇叭看电影放歌曲，声音效果特别棒，音质非常好，屏幕分辨率高，拍照文字图片显示的特别清晰，屏幕的分辨率非常非常非常高。\n拍照效果：拍照清晰细腻，拍照远近切换远近拉伸镜头照片，画面非常好，非常清晰。\n运行速度：运行非常流畅，一点都不卡顿，120W的充电器，充电速度特别的快', '墨羽', '2022-03-24 16:42:11', 8);
INSERT INTO `data` VALUES (11241, 'S***0', 5, '外形外观：整体外观还不错，手感也还行吧\n屏幕音效：双扬声器看视频不错\n拍照效果：一般\n运行速度：天玑9000很强，日常使用很流畅，玩游戏也不错\n待机时间：5000的电池配120W太强了，充电20分钟就能用上一天', '幽芒', '2022-03-26 09:53:25', 7);
INSERT INTO `data` VALUES (11242, '龙****', 5, '这款红米手机发布后一直在关注着！特别信赖小米手机的，是更换手机的首选品牌！就是对小米手机系统信服！这次京东商城活动也对比了好多店铺，还是继续选择小米自营店来下单啦！京东快递次日到达真是值得点赞，打开后慢慢欣赏特别满意，颜色清新脱俗，操作也很得心应手的，小米****功能也是特别好用的！手感也不错！越来越更新换代啦！选择红米手机K50Pro就是物超所值啦！特别要说一下这款幽芒配色也很优雅有商务档次的，一点也不冷艳的，对比了好几个配色还是选这个啦！选对啦！', '幽芒', '2022-06-18 12:51:13', 8);
INSERT INTO `data` VALUES (11243, 'S***e', 5, '外形外观：挺好看的，手感很好\n屏幕音效：顶级屏幕，立体双扬，可惜挖孔\n拍照效果：108涂抹感很强，还是只能扫码\n运行速度：非常快，而且天玑9000还有真DSDS，5G开着都不热\n待机时间：很棒，一晚上不掉电\n其他特色：天玑9000无敌\n只可惜拿到手的有划痕，换了一次还是有，无法接受，而且都是3月生产的货，现在买早期机器真不划算', '幽芒', '2022-06-26 21:06:24', 8);
INSERT INTO `data` VALUES (11244, '嘉***嘉', 5, '朋友推荐的这款手机充电超快，拍照非常满意，朋友也买了，好不容易刷到库存有晴雪，立马下单了，三星2k屏  120瓦闪充 一亿像素摄像头  ，天玑9000，目前为止安卓系的最顶级处理器，侧边指纹解锁很方便', '晴雪', '2022-06-24 09:47:35', 5);
INSERT INTO `data` VALUES (11245, '奕***欢', 5, '三星2K 120Hz直屏，120W充电5000mAh大电池，19分钟左右就能充满，这搭配续航一两天没问题了\n?\n影像：升级了一亿像素和OIS防抖，其实我身边很多朋友也在用K40，日常拍照也还不错的，这个升级的更可以放心了！\n?\n关键芯片是天玑9000，性能逼近骁龙8，但没有骁龙8的发热。游戏功耗真的好很多，而且红米家的保守调度，我用下来 温控表现大好，喜欢玩游戏的可放心[萌萌哒R]\n?\n其他方面，杜比双扬声器、X轴线性马达和DC调光都是有的', '银迹', '2022-08-19 14:39:31', 3);
INSERT INTO `data` VALUES (11246, 'j***明', 5, '这款红米K50PrO首先颜值很高很大气，幽芒颜色看起来很舒服，手机运行非常流畅，不卡顿！下载软件速度也很快！电池容量很大可以玩很久！充电速度超快，真的很方便！真的物超所值！', '幽芒', '2022-07-04 19:05:23', 4);
INSERT INTO `data` VALUES (11247, '八***香', 5, '外形外观：外观漂亮大气，晴雪白女性的首选颜色相当好看。\n屏幕音效：2k的屏幕清晰透亮，看着非常舒适。\n拍照效果：一亿像素那不是盖的，拍照效果超级好，远景，近景一目了然。\n运行速度：没得说，12+3+256,速度跟飞一样，简直不要太快', '晴雪', '2022-10-03 13:56:22', 3);
INSERT INTO `data` VALUES (11248, 'j***m', 5, '外形外观：好看\n屏幕音效：超赞\n拍照效果：还可以\n运行速度：很快\n待机时间：可以\n其他特色：充电很快，还送了耳机，盒子还带一个手机壳', '幽芒', '2023-01-18 22:27:13', 7);
INSERT INTO `data` VALUES (11249, 'L***颜', 5, '细节非常完美，整体来说真的很不错。性价比很高，下载软件的时候 明显温度低很多 运行也比较流畅 120hz高刷自适应屏幕 真心舒服 可以说这次天际9000的功耗调节的非常不错 YYds 不要盲目的跟风 自己好用才是硬道理', '墨羽', '2022-03-22 21:02:11', 7);
INSERT INTO `data` VALUES (11250, 'j***6', 5, '屏幕高清，色彩挺好。音质一\n般，低音不够，偏高音。拍照效果光线强时，很棒，暗\n光一般，防抖很好，色彩还算真实。运行速度很快。充\n电快，充满后待机时间长，玩游戏，不错!赞?，屏幕有\n支架，套上壳好些!目前用着不错!推荐购买。期待一如既往!', '银迹', '2023-01-10 17:36:39', 1);
INSERT INTO `data` VALUES (11251, 't***0', 5, '外形外观：整体设计还不错，手感很好，\n待机时间：配上120W充电快，充满可用一整天\n拍照效果：拍照消晰 效果还行', '幻镜', '2022-09-13 15:50:59', 3);
INSERT INTO `data` VALUES (11252, 'j***t', 5, '外形外观：很好看，手感也很好，颜色也很喜欢。\n屏幕音效：很好\n拍照效果：照片很清晰，颜色也好看，像素很可以。\n运行速度：很快，游戏玩着很顺滑。\n待机时间：很长\n其他特色：使用起来很方便。\n这款手机看中就打算买了，到货也很快，很喜欢，用起来性能也不错。', '银迹', '2022-06-24 17:30:31', 2);
INSERT INTO `data` VALUES (11253, 'j***8', 5, '红米手机真的是性价比超好，外观设计不错，没有硌手的感觉，处理器相当给力，拍照片也清晰，关键还是2K直屏，音质效果非常好，五星好评！', '幽芒', '2022-06-18 15:35:47', 4);
INSERT INTO `data` VALUES (11254, '离***x', 3, '质感一般其他还没发现什么问题', '银迹', '2022-05-19 11:36:17', 5);
INSERT INTO `data` VALUES (11255, 'j***2', 5, '外形外观：喜欢直屏，外观很好看\n\n屏幕音效：2K屏幕120高刷，屏幕看着很舒服，亮度也很好。\n\n拍照效果：拍照还可以。\n运行速度：天玑9000无敌，发热还可以，打游戏很不错，一点也不卡，比K40强太多了', '幽芒', '2022-06-18 09:40:27', 2);
INSERT INTO `data` VALUES (11256, 'j***E', 5, '外形外观：颜值挺高的，手感也舒服\n\n屏幕音效：4k屏特别的清洗，充电音效特别炫\n\n拍照效果：一亿像素，比旧手机强多了\n运行速度：打开app、页面上滑下拉特别的流畅\n待机时间：挺长的，可以用一天\n\n其他特色：整体感觉挺不错的，充电速度快，待机时间长，屏幕清晰', '幽芒', '2022-03-29 10:57:42', 5);
INSERT INTO `data` VALUES (11257, 'b***d', 5, '手机整体还可以，高刷体验不错，120W充电是真的快，5000mAh一不小心就充满了，拍照也还算可以了，比iPhone11稍好一些，JD值得信赖。\n屏幕音效：非常棒，2K屏很舒服。\n拍照效果：这个价位不错就是，说得过去。\n运行速度：快，比888体验好不少。\n待机时间：还可以，主要回血速度快啊', '幽芒', '2022-03-28 22:38:48', 6);
INSERT INTO `data` VALUES (11258, '不***了', 5, '外形外观：挖孔屏，现在主流的造型，这个价位下巴控制的\n也不错\n屏幕音效：2K120很清晰丝滑，音质也ok的，声音可大可\n小，也有杜比音效\n拍照效果：108mp相机还是非常给力的，不知道专业术语，反正就是很牛X，简单对比了一下我的s22感觉比我现用的还好。\n运行速度：天饥9000，8Gb运存，miui13，给我爸用绰绰有余啊，运行非常流畅。\n待机时间：现在智能手机一天一充避免不了的，但是120W快充真的惊掉下巴，放个屁的功夫就充满了，666。\n其他特色：小米换小米手机也绝，用换机助手所有聊天记录什么的都可以转移过去，真的很方便；那个超级壁纸也很厉害，听说隔壁水果ios16也有，但是没有小米这个酷炫；网上吐槽的塑料边框对我来说无所谓，反正要带壳子的，且自带的有一个透明壳（都这种配置这种价格了还要啥自行车）；还有什么红外啥啥的用不上的用的上的它都有。\n\n购买建议：性价比之王，同价位无敌，你是学生还是长辈，打游戏还是日常，都非常值得入手，冲吧铁子们。（', '墨羽', '2022-06-08 10:06:41', 9);
INSERT INTO `data` VALUES (11259, 'j***t', 5, '外形外观：颜值高，绿色?也很清新\n屏幕音效：看视频听音乐很好。\n拍照效果：一亿像素，杠杠的\n运行速度：很快，流畅，玩吃鸡也不卡\n重点是充电的速度很快，外出不需要充电宝，十几分钟就充满了', '幽芒', '2022-03-25 09:04:10', 4);
INSERT INTO `data` VALUES (11260, '翡***面', 5, '外形外观：外形很好看，整机手感很好，也不是很重，拿在手里质感很好，外壳的颜色也很好。\n屏幕音效：屏幕也很出众，很清晰，有高刷新的加持打游戏看文章都很丝滑\n拍照效果：拍照效果很出众，照片质感很强，还原度很好\n运行速度：运行速度很快，打游戏一点都不卡，用着很舒服\n待机时间：大电池和120w快充的加持，待机时间超长，充电时间大大缩短\n我们的客服也很专业，有问题能够及时解答，回复很迅速，解答的很专业！', '幽芒', '2022-10-19 13:54:19', 5);
INSERT INTO `data` VALUES (11261, 't***S', 5, '外形外观：喜欢这个墨羽色  花纹好好看?\n\n屏幕音效：2k屏幕贼清晰   跟双扬声器看剧太搭了\n\n拍照效果：一亿像素果然不是浪得虚名  哈哈哈\n\n运行速度：力挺天玑9000   运行棒棒哒  话不多说   懂得都懂\n其他特色：最喜欢这个120w充电   肉眼可见的速度直线拉升  妈妈再也不担心出门没电了', '墨羽', '2022-04-03 15:33:01', 5);
INSERT INTO `data` VALUES (11262, 'P***钱', 5, '手机真心不错，秒杀苹果13，颜值高，流畅大电池，充电速度杠杠的。\n屏幕音效：屏幕音效反应好\n拍照效果：拍照清晰，对焦快\n运行速度：神速', '幽芒', '2022-06-26 11:00:21', 3);
INSERT INTO `data` VALUES (11263, '亮***忙', 5, '外形外观：大气，漂亮\n屏幕音效：立体环绕强\n拍照效果：完美\n运行速度：快\n待机时间：2天轻度，1天重度使用\n其他特色：高端大气上档次，小米手机性价比高，推荐', '幽芒', '2022-08-17 21:41:29', 3);
INSERT INTO `data` VALUES (11264, 'j***v', 5, '外观：手机外观无任何瑕疵，完美，银色看上去很高大上，手感也很好，主要是三星2K屏幕，很高清&hellip;\n功能：玩游戏还是很顺畅的，拍照也很清晰&hellip;\n优点：因为我是米粉，喜欢小米家的性价比！质量很好！\n今年目标?：想买，小米家的全家桶&hellip;', '银迹', '2022-04-03 17:22:48', 9);
INSERT INTO `data` VALUES (11265, 'C***年', 5, '新买的k50pro，感觉很不错，2k屏幕?120w很给力，主要是电池续航十分给力，手里的iqoo9瞬间不香了，打游戏也还不错，价位精准，难得的好手机！', '银迹', '2022-03-31 18:40:38', 8);
INSERT INTO `data` VALUES (11266, '浪***o', 3, '买了两台，一台我用，一台家人用，这我用的，拍照摄像还不错，比换用的手机是有明显提升的，手机外观虽然网上都说廉价感，但上手感觉还是很精致的，都说塑料边框不好，是没吃过金属边框烫手的苦，精挑细选还是这款黑色，两台同样颜色，我们用外壳区分，上手很舒服，重量和大小都很不错，上个壳和钢化膜手感也比以前的手机好，2k120hz的高素质屏幕加上120w5000毫安的单芯快充，没谁了。打算用两年再换新手机，侧边指纹好顶赞，比屏下指纹好的不是一点半点，是质的提升，蓝牙效果很好，这台会玩游戏，充电发热有一定感知，但相比之前的手机，简直就是清凉，之前用的红米k30u。目前系统是开发版公测，没有什么常驻bug，很不错。', '银迹', '2022-06-13 08:44:55', 9);
INSERT INTO `data` VALUES (11267, '乐***l', 5, '已经用了两个多星期了，感觉还是物超所值，618期间买的，12+256各种券加在一起大概2600块，这个价位能买到天玑9000+2k屏还是一个字香，这是其他品牌给不了的，玩性价比还是得红米啊，加油', '银迹', '2022-06-24 20:18:20', 4);
INSERT INTO `data` VALUES (11268, '杞***室', 5, '性价比高得一批，以后就用联发科方案的红米手机了，发热，续航都调教得很好，还第一时间解锁BL刷了面具装了框架，这手机真香', '墨羽', '2022-04-04 15:06:41', 7);
INSERT INTO `data` VALUES (11269, 'R***b', 5, '外形外观：颜值担当，喜欢黑色的沉稳大气，赞一个\n屏幕音效：清晰可见，操作简单易懂\n拍照效果：很清晰，喜欢\n运行速度：不错哦，很快\n其他特色：玩游戏不错哦\n待机时间：挺长的', '墨羽', '2022-09-01 21:38:05', 4);
INSERT INTO `data` VALUES (11270, 'k***2', 5, '外形外观：外观时尚大气，手机背后的太空陨石图案非常绚丽，看着这个图案，总以为手机摔碎了，呵呵\n屏幕音效：屏幕效果很不错，下面视频可以看出效果\n拍照效果：拍照很清晰，分辨率很高，不错\n运行速度：新手机的运行速度不用说，肯定可以啊\n待机时间：一般情况下可以待机两天\n其他特色：这是一款种草了很久的手机，趁着618活动价入手，价格特别给力，包装物流都不错?', '墨羽', '2022-07-05 22:39:33', 2);
INSERT INTO `data` VALUES (11271, '笨***5', 5, '外形外观：银迹好看。喜欢极了！\n屏幕音效：2k屏，期望。\n拍照效果：很好，清晰。拍照神器。\n运行速度：天玑9000就是不一样。快！\n待机时间：一天够用！', '银迹', '2022-03-25 22:04:18', 4);
INSERT INTO `data` VALUES (11272, '雨***桭', 5, '外形外观：银色超级超级喜欢，小米的品控越来越好。\n运行速度：12G内存，再也不用经常清系统垃圾了。\n屏幕音效：屏幕显示效果惊艳。\n购物平台京东最给力，发布会那天预约的，今天0点付款，下午收到，想想就兴奋，等不及体验看看游戏的速度再来追评！\n出厂的屏幕保护膜是挺好，但是两边没对齐哦。', '银迹', '2022-03-22 20:52:40', 6);
INSERT INTO `data` VALUES (11273, 'W***8', 5, '外形外观：很漂亮，屏幕尺寸大小刚好；\n屏幕音效：音质很棒，上下都安装有喇叭，玩游戏效果很好；\n拍照效果：照片很清晰，画质细腻；\n运行速度：运行速度：刷网页很流畅，玩游戏也不卡顿；', '墨羽', '2022-08-09 12:59:57', 5);
INSERT INTO `data` VALUES (11274, '再***6', 5, '小米的手机质量很好，做工精细，外观时尚大气，操作简单，这个k50pro阿特别的好用，性能够强，手感也不错', '墨羽', '2022-09-03 02:14:45', 3);
INSERT INTO `data` VALUES (11275, 'j***u', 3, '拍照效果不好，其他的还行，', '幻镜', '2022-06-11 18:16:26', 6);
INSERT INTO `data` VALUES (11276, 'd***我', 5, '对这个手机太满意了！相对于骁龙888和GEN1，天玑9000温控和功耗方面控制得非常不错，完全把安卓手机相对苹果的全部优势发挥出来了，充电真的快！每晃神一次电量就涨了百分之二十！几个走神就充满100%了，震动马达也很舒服，是和苹果打字不一样的舒服，拍照不如苹果，但是也足够精细了。背板太好看了，反光很美，舍不得戴硅胶保护壳了。面部解锁非常快。主要还有一个防频闪的功能，整个手机屏幕看着太舒服、太护眼了。12G运存运行非常快，不卡顿！', '晴雪', '2022-08-05 00:03:23', 5);
INSERT INTO `data` VALUES (11277, 'j***b', 5, '外形外观：外观感觉还不错，带壳塑料边框也没什么感觉\n屏幕音效：2K屏是真的清晰，音效也不错\n拍照效果：这个价位还能对拍照有什么要求呢\n运行速度：运行速度很快，很流畅，但是细节还需要打磨，希望越来越好\n待机时间：待机不错，一天一充，120W充的是真快', '银迹', '2022-04-10 20:48:15', 4);
INSERT INTO `data` VALUES (11278, 'j***3', 5, '这次的k50pro 堆料很足，120w快充，120 hz高刷  性价比超高，新一代天机9000处理器，性能强悍，不管拍照，玩游戏都轻松应付，不失旗舰风范', '墨羽', '2022-04-24 12:05:25', 6);
INSERT INTO `data` VALUES (11279, 'j***祖', 5, '外形外观：看起来还是挺好看的，手感也还不错\n屏幕音效：2K屏幕非常清晰\n拍照效果：对拍照没什么要求，总体还是不错的\n运行速度：非常顺畅，\n待机时间：电池耐用', '墨羽', '2022-04-13 21:06:30', 4);
INSERT INTO `data` VALUES (11280, 'j***w', 5, '外形外观：很有特点，像流星散落的感觉\n屏幕音效：也挺可以的，比上不足比下有余\n拍照效果：中规中矩，毕竟不是拍照手机，价位摆在这，不能样样强\n运行速度：特别快，打游戏不卡，作为一台游戏手机我觉得完全够用\n待机时间：电池续航挺久的，很耐用，充电也快，半小时应该都用不上就充满电了！', '墨羽', '2022-07-21 23:29:07', 4);
INSERT INTO `data` VALUES (11281, '只***称', 5, '期待很久的小米13总算出来了，大爱直角边框，总算不用担心太滑摔了屏幕了，颜值给力！后盖是圆弧的，所以也不会很割手，手感好评！拍照终于加上了2 x，很常用，大师镜头也很给力，排出的照片yyds，就是自己的技术还一般，总之手机很满意，**入了！小米加油！13大卖！！', '幽芒', '2023-01-07 21:35:51', 4);
INSERT INTO `data` VALUES (11282, 'j***P', 5, '买的手机，非常好。质量也可以，买电器，手机，选择，京东，挺好的，方便，快捷。下次。购买手机。还是选择京东商城。\n外形外观：外现时尚，自己喜欢的款式。\n屏幕音效：屏幕分辨效果，挺好的。\n拍照效果：拍照清楚，.大牌子，就是不一样。\n\n\n\n运行速度：8GB的运型速度.反应挺快的，没有卡顿。\n待机时间：待机时间挺长的，用了很久，电只是消耗了，一点电。\n其他特色：外观大方，反应又快，照相清楚，值得，买的一款手机。', '墨羽', '2022-03-28 10:49:04', 5);
INSERT INTO `data` VALUES (11283, 'u***2', 5, '外形外观：很有型，墨羽后面镶嵌钻石太好看了\n拍照效果：杠杠滴\n屏幕音效：非常棒\n运行速度：唰唰唰', '墨羽', '2022-03-22 16:35:25', 6);
INSERT INTO `data` VALUES (11284, '润***6', 5, '外形外观：外观设计很不错，颜色看着很舒服。\n屏幕音效：2k高刷屏，观感很不错。\n拍照效果：还可以，拍照感觉不是红米这个系列的强项。\n运行速度：天玑处理器绝对是够用了，选这款就是觉得虽然处理器稍弱，但是屏幕比较好。\n待机时间：充电很快，非常实用！', '银迹', '2023-02-25 23:23:32', 4);
INSERT INTO `data` VALUES (11285, '谭***友', 5, '昨天下的单，今天上午就到了不愧是京东物流真的快。\n这个手机买来是送给老弟的成人礼物，他观察这款手机好久一直心心念念?，现在完愿了。\n手机整体都是非常不错的，配置也很强12+256性价比超级高，外观做工也很精美，也是将近十年的米粉从小米2s开始??，手机很棒。用几天后会追评', '墨羽', '2022-06-18 13:59:15', 5);
INSERT INTO `data` VALUES (11286, 'l***d', 5, '颜值高，选了喜欢的墨羽色，外观看着很细致，看视频画质清晰，声音效果也很好。一亿像素，拍照效果杠杠的，重点是120W快充，充满电速度很快，同京东物流一样快。', '墨羽', '2022-04-05 00:29:10', 5);
INSERT INTO `data` VALUES (11287, 'j***n', 5, '一直都是用这个牌子的手机，我们家人手一部，刚拿到就****，，非常满意。\n屏幕音效：双扬声器打游戏的声音很奈斯\n待机时间：5000的电池配120W的充电器，20分钟就充满了\n运行速度：天玑9000打游戏也很好\n拍照效果：很好\n外形外观：很喜欢的墨羽颜色好看', '墨羽', '2022-04-02 21:45:41', 4);
INSERT INTO `data` VALUES (11288, 'g***8', 5, '货已经收到了，商品与网上介绍的一样，机子外观很漂亮，拍照也清晰。运行速度很快，播放音乐音质很好，我是第一次买小米手机的。物流很快，\n快递员服务态度好，送货上门的。', '墨羽', '2022-11-13 22:16:38', 8);
INSERT INTO `data` VALUES (11289, '玉***7', 5, '外形外观：银色质感好\n屏幕音效：屏幕绝了，非常清晰，对比k20pro\n拍照效果：拍照可以用\n运行速度：运行速度没问题，旗舰水平', '银迹', '2022-03-22 22:00:31', 9);
INSERT INTO `data` VALUES (11290, 'g***g', 5, '这款手机非常好，儿子自己选的，\n外形外观：简单大气，\n屏幕音效：好，\n\n拍照效果：好，\n\n运行速度：快，\n值得购买的一款手机！！', '银迹', '2022-08-25 22:13:15', 2);
INSERT INTO `data` VALUES (11291, 'v***t', 5, '手感非常不错，轻薄，充电快，续航也很好！打王者帧率也非常稳定！拍照也够用！性价比很高！推荐！\n外形外观：靓\n运行速度：快 稳\n待机时间：够长', '幽芒', '2022-09-01 21:03:01', 5);
INSERT INTO `data` VALUES (11292, 'g***5', 5, '外形外观：实在太好看啦\n屏幕音效：外放音乐十分好听\n拍照效果：照片也十分清晰\n运行速度：流畅快快的\n待机时间：基本两天一冲，也快', '晴雪', '2022-09-01 20:41:37', 4);
INSERT INTO `data` VALUES (11293, '我***9', 5, '外形外观：除了12和奥戳以外最好看的机型了，男生也不太在意，颜色是挺好的，摄像模组也还好\n拍照效果：拍照效果有待后期优化，没有火龙处理器的效果好，这个也算众所周知，看后期优化吧\n运行速度：运行速度很快，软件启动切换效果都非常的好，再加上广告跳过软件，体验很不错\n待机时间：待机时间轻松一整天，而且120瓦快充20分钟充满，出门前插一会儿就足够了\n其他特色：三星2K屏自然是没的说，饱和度亮度峰值，再配上高刷，体验非常好', '银迹', '2022-07-23 10:55:02', 6);
INSERT INTO `data` VALUES (11294, '万***8', 5, '红米k50pro手机性价比真的很高，屏幕也比较大，5000毫安的电池很耐用，正常使用2、3天没问题的，而且搭配120w快充，十几二十分钟就把电池充满了，天玑9000处理器，运行速度相当的快，而且屏幕也很清晰，这个价格有这么好的手机真的很不错。', '幻镜', '2022-04-30 09:55:52', 6);
INSERT INTO `data` VALUES (11295, '小***6', 5, '外形外观：线条流畅，手感挺好的\n屏幕音效：颜色有些浅黄，不刺眼\n拍照效果：非常好，清晰不失真\n运行速度：挺快的，以前的用了四年了哈哈，新手机觉得挺快的嘛\n待机时间：可以玩一整天，闪充奥利给！！最喜欢的！！\n其实就是因为王一博买的！！我是百香果，同品类永远偏向博君一肖?', '银迹', '2022-04-09 22:13:10', 4);
INSERT INTO `data` VALUES (11296, 'j***m', 3, '手机耗电有点快，其他感觉都还行。', '幻镜', '2022-06-17 07:07:28', 5);
INSERT INTO `data` VALUES (11297, 'S***1', 5, 'Redmi K50 Pro幽芒色，一个骚气又好看的颜色?特别特别特别的爱不释手。真的，在灯光下照耀的颜色很炫\n天玑9000处理器很流畅，三星2K屏清洗色泽很好，OIS光学防抖的功能很实用，特别是我们这些女孩子很满意，哈哈哈?\n这个手机电池容量也很给力，以后出去拍照也能战斗很久了，好开心，而且包装简洁大气，还很贴心的配送了保护套，买回来都不用着急怕磕碰到了。', '幽芒', '2022-04-04 20:26:15', 9);
INSERT INTO `data` VALUES (11298, '不***Q', 4, '外形外观：真心觉得不错，手感舒适 ，大气稳重，隐隐的有炫酷之感。\n屏幕音效：双向喇叭，看电影，放音乐，声音效果特别好 ，音质也非常棒 ，屏幕分辨率也高 。\n拍照效果：个人感觉拍摄效果清晰细腻，聚焦画面感也特别棒 ，格外清晰。\n运行速度：天机9000 真心不错 ，使用流畅，游戏感也不差。\n待机时间：电池续航特给力 ，确实不错 。\n其他特色：2K屏幕&amp;120w 真心不错 ，值得拥有！', '银迹', '2022-08-14 21:18:12', 4);
INSERT INTO `data` VALUES (11299, 'j***3', 5, '整体来说，相当丝滑。侧边指纹解锁也挺好用，像素与其它方面，整体非常不错。2k屏那是真香。系统用惯了，家里面也是米家生态链。', '墨羽', '2022-03-23 04:01:53', 5);
INSERT INTO `data` VALUES (11300, '蓝***鱼', 5, '外形外观：外形很美观，手持很适合，我很喜欢！\n屏幕音效：不愧是三星2K屏幕，非常清晰，不辣眼睛，看着非常舒服。\n拍照效果：一亿像素，超清楚，成熟的成像方案和CMOS感应原件，每拍一张照片都是大片来的，超级满意！\n运行速度：12+256的大运行内存，开十几个应用都不卡顿，非常好，很流利！安兔兔系统评测轻松过百万，超好！存储测试顺序读和顺序读如此好的成绩，与目共睹！\n待机时间：5000毫安大电池，更优的系统方案，电池真的很耐用，待机一天半没问题，再也不担心电量不够用。\n其他特色：作为12年的米粉，入手K50pro手机，很棒，尤其是喜欢侧边指纹解锁，反应灵敏，比屏下指纹解锁快很多，机身轻薄，手感好，120w神仙闪充回血一字快，红米手机值得拥有。', '银迹', '2022-03-26 12:56:24', 7);
INSERT INTO `data` VALUES (11301, '科***油', 5, '2k屏幕确实很更细腻，作为副机从k40 pro升级购入，性价比太高了，120w充电确实很快，性价比拉满，不打手游，运行速度够快，颜值爆表，摄像头也有提升，附赠透明手机壳，还贴了膜，开箱就能直接用。', '幽芒', '2022-06-18 00:56:34', 4);
INSERT INTO `data` VALUES (11302, 'p***2', 5, '小米的K50POR手机太喜欢了，值得推荐，天玑9000的CPU很香，比k40POR的888快不少，相比上一代手机，照相功能也有了很大提升，小米的MIUI系统也非常好用。2K，120高刷屏幕不是一般的清晰顺畅，充电也贼快，十几分钟就能充满！', '墨羽', '2022-03-27 18:37:12', 5);
INSERT INTO `data` VALUES (11303, 'm***Y', 5, '红米K50pro就是快，比30快多了，屏幕清晰度相当滴满意！音质音也是效杠杠滴！打游戏一点也不卡，澎湃120w快充就是快，二十分钟充满电，牛了个牛啊- ??(?????)手机也不是那么热，反应相当快，待机也可以的！关键是充抵快啦哈哈！相信京东品质！相信京东自营！', '幻镜', '2022-10-06 09:19:08', 5);
INSERT INTO `data` VALUES (11304, '紫***鸽', 5, '外形很美观，手持很适合。\n成熟的成像方案和CMOS感应原件，每拍一张照片 都是大片来的，超级满意!\n12+256的大运行内存，开十几个应用都不卡顿，非常好。\n5000毫安大电池，电池真的很耐用，待机一天半没问题，不担心电量不够用。\n侧边指纹解锁，反应灵敏，比屏下指纹解锁快很多，机身轻薄，手感好。', '幽芒', '2022-04-25 16:20:20', 3);
INSERT INTO `data` VALUES (11305, '作***糕', 5, '外形外观：黑色的很好看很有质感 比图片好看多了\n\n屏幕音效：屏幕很细腻色彩鲜艳\n\n拍照效果：1亿像素 拍照很清晰\n运行速度：运行速度很快 非常棒的手机 \n待机时间：大概可以使用一天。', '墨羽', '2022-04-22 12:38:56', 3);
INSERT INTO `data` VALUES (11306, '净***剂', 5, '老妈的手机是mate3，好多年了，现在打开健康宝实在太慢，于是上京东最终给老妈选中了这款，屏幕大，字就大，待机时间长，处理器性能也高，软件运行都挺流畅，老妈很喜欢', '幽芒', '2022-07-23 15:41:08', 5);
INSERT INTO `data` VALUES (11307, 'Z***6', 5, '外观很美观时尚，符合我的审美，屏幕三星2k直屏显示效果出众，一亿像素拍照无可挑剔，12g内存运行多程序无卡顿，5000毫安电池很耐用，轻度使用两天没问题，天花板级cpu足以应对各种软件，指纹解锁反应快，120w快充极速回血，整机轻薄手感极佳，非常满意', '银迹', '2022-05-07 13:38:38', 8);
INSERT INTO `data` VALUES (11308, 'x***8', 5, '从从小米1，小米4A,小米4，在小米8发布后买了第一批之中的一部，感觉小米手机相当不错。五一期间突发意念购买了这部红米K50 PRO，头天晚上下单第二天上午送到，凸显的京东物流一贯的神速。\n屏幕音效：2k屏幕色彩绚丽，不是1080的屏幕能比的，看着非常舒服。双喇叭立体声，性质很好，听音乐可以听到一些细节，这是单喇叭不能比的。\n\n外形外观：全面屏比起小米8的大刘海确实上了一个大台阶，不会影响通知栏的显示。\n拍照效果：拍照效果也比米8好了很多，一亿像素很清晰。\n运行速度：12G大运行内存和256存储没有任何卡顿。\n待机时间也符合预期，\n充电速度：20分钟充满，简直太快了！', '墨羽', '2022-05-05 18:25:39', 4);
INSERT INTO `data` VALUES (11309, '纯***i', 5, '外形外观：金属质感\n屏幕音效：清晰\n拍照效果：还不错\n运行速度：很快，毕竟配置也算中高端\n待机时间：新手机，待机还可以\n其他特色：总体来说不错，买给妈妈用的，家人喜欢就够了', '银迹', '2023-01-28 15:02:43', 3);
INSERT INTO `data` VALUES (11310, 'j***C', 5, '外形外观：外观美，挺不错\n屏幕音效：不愧是2K屏幕，非常清晰，看着舒服\n拍照效果：一亿像素超清晰，超级满意\n运行速度：非常流畅，打游戏流畅不卡，感觉挺好\n待机时间：电池很耐用，5000毫安电池，待机一天半没问题，再也不用担心电不够用\n其他特色：不错的一次购物，红米手机值得拥有', '墨羽', '2022-04-03 15:17:07', 4);
INSERT INTO `data` VALUES (11311, 'j***B', 5, '使用效果非常好，我非常喜欢。\n屏幕音效：很好，很响亮。\n外形外观：很时尚，很好看。\n拍照效果：正常买小米手机就不要想着拍照了，能扫码就行。', '银迹', '2022-12-10 21:08:26', 4);
INSERT INTO `data` VALUES (11312, 'j***N', 5, '期待已久的k50pro 终于到手了 是真的流畅啊 2K屏看着就是细腻舒服 运行速度也很快 充电就更快了120w 简直了 无敌呀 爱不释手！！！', '幻镜', '2022-09-01 22:23:45', 4);
INSERT INTO `data` VALUES (11313, '乘***浪', 5, '外形外观：手感很好，握持很奈斯\n屏幕音效：声音外放，观看电影效果很好\n拍照效果：这个价位段吊打很多机型\n运行速度：运行速度流畅\n待机时间：轻松使用一天\n其他特色：性价比高', '墨羽', '2022-06-24 15:48:26', 4);
INSERT INTO `data` VALUES (11314, 'j***z', 5, '手机颜值很高，像素很给力，后面两张是实拍图，买到就是赚到。关键充电贼快，价格很不贵才3000多，就能买到 2022年安卓系列最好的处理器了。', '墨羽', '2022-03-24 20:34:31', 4);
INSERT INTO `data` VALUES (11315, '冰***浓', 5, '物美价廉吧！红米主打性价比！超级给力！这个价格了！白菜价！用两年就行了！屏幕很清晰！充电也很快！这个价位了！绝对别挑剔太多了！已经很划算了！自己喜欢就好！我觉得挺赞的啊！', '银迹', '2022-12-22 12:10:58', 5);
INSERT INTO `data` VALUES (11316, 'V***户', 5, '外形外观：样子很好看，红米现在进步很大\n屏幕音效：这个是2k屏幕，显示效果直接无敌\n拍照效果：这个号称1亿像素，自带光学防抖，比我的k40好好太多了\n运行速度：天玑9000这个处理使用个三五年不成问题\n待机时间：待机时间也不错\n其他特色：首先看上这个120w充电速度，不是一般的快，这个手机是给我母亲买的，原来的华为p40手机，用了一年多，卖了给换的这个，另外天玑9000处理绝对够用，另外还有全景声，声音效果不错，自带HIFI，没有几个手机能比，家里三口人终于全部用上了红米，从小米一代一直到现在，已经有了很厚的感情，希望小米公司未来能带给我们更多惊喜', '幽芒', '2022-04-27 18:01:47', 7);
INSERT INTO `data` VALUES (11317, '默***候', 5, '外形外观：好看\n屏幕音效：2k屏幕还是很不错的\n\n运行速度：快\n拍照效果：挺好\n其他特色：充电真快', '墨羽', '2022-04-02 20:59:51', 4);
INSERT INTO `data` VALUES (11318, 'w***j', 5, '外形外观：还不错，比较大\n屏幕音效：音质不错，清晰\n拍照效果：后摄像很清楚，像素很高\n运行速度：能够满足正常需求，有时会偶尔出现点不中的情况，不知道是卡还是什么\n待机时间：这个很好，5000的容量待机时间超长，120w超快充让手机瞬间满电，使用效果很好', '银迹', '2022-06-18 08:24:22', 3);
INSERT INTO `data` VALUES (11319, 'y***w', 5, '1.用了大概两个星期，入手这部机子是冲着天玑9000和2k屏幕来的.\n2.买的8+256G大容量版本，爽爆，视频应用什么的可以随便下了；\n可玩性高\n3.屏幕观感不错，2k确实清楚很多，而且跟iPhone和iqoo9pro比，偏色没那么大；\n天玑9000打游戏好用，温度也适合。\n5、回血快，20分钟左右满了\n1、续航一般般，看视频打游戏掉电挺快的，应该是跟屏幕设置全部调的最高有关\n2、非常偶尔会有卡顿和明显掉帧的情况，具体原因还在调查 \n3、侧边指纹解锁真的不错，妙解，比光学指纹，超声波指纹好多了。\n4、拍照扫码级别。', '幽芒', '2022-04-10 17:30:10', 3);
INSERT INTO `data` VALUES (11320, '幻***舞', 5, '手机到了。\n外形外观：漂亮好看时尚潮流\n屏幕音效：屏幕挺好的，音质很好。\n拍照效果：拍照还行吧，扫码就行了。\n运行速度：新机运行速度肯定很快！\n待机时间：待机时间一般般吧！满性能模式，续航八小时左右。', '幻镜', '2022-07-04 02:51:36', 3);
INSERT INTO `data` VALUES (11321, '此***陷', 5, '外形外观：简约时尚，没有什么太多的花哨设计\n屏幕音效：音效都不错，声音清晰\n拍照效果：拍照效果也很高，照片质量高档\n运行速度：天矶9000处理器运行很好，打开应用反应很快，也不发热\n其他特色：整体性价比很高的一台手机', '墨羽', '2022-04-04 03:43:44', 3);
INSERT INTO `data` VALUES (11322, '白***1', 5, '外形外观：外观很时尚靓丽非常适合年轻人\n屏幕音效：屏幕是高刷，流畅度很高，看起来很舒服\n拍照效果：拍照很清楚，像素很高很清晰\n运行速度：运行速度很快，很流畅', '银迹', '2023-01-10 08:52:00', 3);
INSERT INTO `data` VALUES (11323, 'j***H', 5, '首先，表扬一下京东快递的送货速度，送货速度依旧很快！然后我是帮朋友买的手机的，购买体验感觉也很好，非常棒，表扬一下京东的服务，非常棒！手机运行速度也很快，然后买的是12+256G存储空间的，120W快充，很棒！非常棒！', '晴雪', '2022-09-24 21:18:59', 6);
INSERT INTO `data` VALUES (11324, 'j***I', 5, '外形外观：不错不错，我对这个没有太大的需求，主要看中性能，外观不错，符合我的审美\n屏幕音效：屏幕清晰，杜比音效很舒服\n拍照效果：可圈可点，这个价位拍照性能我要的性能\n运行速度：非常快，丝滑，天玑9000没有让我失望\n待机时间：强，5000毫安大电池可以的\n其他特色：120w充电yyds', '墨羽', '2022-04-05 21:07:18', 2);
INSERT INTO `data` VALUES (11325, '周***铠', 5, '买给家婆的手机，她很喜欢，字体大，声音也很不错\n外形外观：外观也很大气\n拍照效果：拍照应该还可以吧，这个没试', '幽芒', '2022-06-24 12:13:16', 6);
INSERT INTO `data` VALUES (11326, 'b***6', 5, '外观漂亮，手感好。\n屏幕音效：声音清晰， 音乐无杂音。\n拍照效果：手机拍照效果真的好。\n运行速度：运行流畅，游戏不卡，特别好用。\n待机时间：待机时间长，电池耐用。值得推荐。', '幻镜', '2022-09-01 22:21:39', 3);
INSERT INTO `data` VALUES (11327, '缘***a', 5, 'K50 pro 天玑9000真的太给力了，比k40 pro 骁龙888好用，相比上一代拍照真的好了很多，希望miui系统越来越好用，所有应用双开最赞。2k 120HZ高刷屏不是一般的清晰丝滑。续航方面固定120hz，2k分辨率打开，随便用一天，没有焦虑了，充电19分钟充满', '幽芒', '2022-03-25 09:47:41', 7);
INSERT INTO `data` VALUES (11328, '爱***昂', 4, '外形外观：紅米K50 Pro的外觀在背蓋質感较佳，墨羽色 為橄榄陨石紋理，廣著不同角度會有各種折射光，滿特别 的。 中框材質燕塑膠，質感和觸感有明顯的廉價感，這部份满 可惜的，若為鲳镁合金或是不锈鋼材質较有旗艦機的質 感。 SIM卡槽退卡孔與收音孔位置太近，容易混淆，一開始退 卡針還插到收音孔。 屏幕音效：屏幕為三星OLED 2 K屏，顯示效果非常好， 眼睛看起來也舒服，刷新率120Hz也满流暢的，觸控可達 480Hz實際操作起來滿靈敏的；喇叭燕實體雙喇叭（位 置非對穰），有支援Dolby A**os音效，慰起來音質不 錯，聲音大小設定超過中間才會有外放大聲的感覺，整體 音效比我原本的K30至尊紀念版好满多的。 拍照效果：拍照效果不錯，相機鏡頭為三星S5KHM2一億 畫素加上光學防抖，照片的解析度非常高，光學防抖也可 加強拍照成功率；尚未测試夜拍效果，感光元件尺寸大應 該成像效果也不錯 运行速度：系統流暢度较佳，執行程式速度滿快的，游崴 載入速度也非常快；安兔兔跑分燕93萬多分，與發表會 上的100多萬分有差距，期待優化後能蒟更加流暢以及更 高分。 其化特色：手感鞑佳，與我原本的K30', '银迹', '2022-07-27 21:08:47', 2);
INSERT INTO `data` VALUES (11329, 'g***香', 2, '手机是好手机，挺不错的，屏幕清晰，各方面都很优秀，也有几个缺点，优化不好，许多场景都会掉帧，更新系统反向优化，导致我现在只敢锁定13.0.4这个系统一直用，还有就是，开热点的时候手机非常非常非常热，还会自动把我热点关了，非常的烦。其他还好！希望多优化优化', '幻镜', '2022-07-14 23:14:14', 5);
INSERT INTO `data` VALUES (11330, '挊***鬼', 5, '银色质感舒服，手握滋润，系统很流畅，温度控制的很好，120w超快充电，安兔兔跑分92万多，性能都过剩了。目前用起来挺顺手，虽然是右边侧指纹，不过这个也没事，习惯了没密码使用', '银迹', '2022-06-18 00:01:16', 4);
INSERT INTO `data` VALUES (11331, '嘟***香', 5, '运行速度：很快很稳，12g运存，天机9000\n其他特色：性价比高，这价位适合已经把最好的都上了。\n待机时间：很耐用，待机的话一天都不怎么掉电，亮屏使用玩玩游戏刷刷视频也有7小时左右。\n屏幕音效：声音也通透，清晰。屏幕2k 120的屏很爽。', '银迹', '2022-03-31 15:14:19', 3);
INSERT INTO `data` VALUES (11332, 's***忘', 5, '手机手感不错，特别是显示效果非常好。此外，开启WIFI，网速非常快，还支持5G。存储256G足够用几年了，不卡。', '墨羽', '2022-03-28 14:37:28', 9);
INSERT INTO `data` VALUES (11333, '箫***琪', 5, '一直都是小米的购买支持者，不为别的，质量和性价比是我最看中的。手机很清晰，屏幕高水准，电量也很耐用，关键我喜欢侧边指纹解锁，那叫一个快。最欣赏的就是充电了，二十多分钟就吃饱非常好。', '墨羽', '2022-04-01 22:01:45', 4);
INSERT INTO `data` VALUES (11334, 'j***j', 5, '这款手机外观非常炫酷，拿着手感极佳，有5000大电池，超过大部分手机，120w,快充，20分钟可以充满， 12+256超大容量，这个价位值得入手', '幽芒', '2022-08-20 16:18:10', 1);
INSERT INTO `data` VALUES (11335, 'l***9', 4, '外形外观：外观整体上还可以\n屏幕音效：2K屏幕记忆力度比K40要好\n拍照效果：拍照效果比K40好一些\n运行速度：不玩游戏运行速度跟K40差不多，应该稍快一点点\n\nK40用了一年，非常满意，比之前用的华为的小米的四五千的手机用的还顺手的多，之所以换K50pro，是想在照相、续航、屏幕清晰度方面有所提升，这方面K50pro都做到了。', '银迹', '2022-03-23 16:25:38', 8);
INSERT INTO `data` VALUES (11336, '灬***灬', 5, '手机终于收到了！好高兴啊！真的可以说是颜值相当高的一款手机了。配置各方面也很好，搭载了天玑9000芯片，打游戏一点我不卡，非常流畅！像素也是非常高的，拍照片很好看！', '银迹', '2022-06-25 23:47:47', 4);
INSERT INTO `data` VALUES (11337, 'j***q', 4, '真的香，用了几天了，不喜欢清后台，但是也不卡，我男朋友说他苹果都不敢这样开，信号也比之前的vivo手机好，打字触感是真的棒，2k屏幕太清晰了，开了防闪烁模式也是真的有效，因为2k和防闪烁模式都开了，所以续航的话，没有想象中的那么顶，都是也很好了，重度使用，差不多可以六七个小时通信音质:清楚,扬声器声音也大显示效果:无比清楚还有小米主题壁纸里好多免费的超级好看的壁纸簌经真的牛相机后置还挺清楚的,没有网上说的那么夸张,前置确实比较模糊，可以入，用过一段时间后电量和运行再来反馈', '晴雪', '2022-11-14 14:16:36', 4);
INSERT INTO `data` VALUES (11338, 'j***y', 5, '外形外观：摄像头这个组合设计的很漂亮\n屏幕音效：画面显示色彩饱满\n拍照效果：拍照细节到位\n运行速度：运行流畅 大型手游游刃有余\n待机时间：轻松一天没问题', '墨羽', '2022-09-02 08:48:36', 3);
INSERT INTO `data` VALUES (11339, '赵***帅', 4, '这手机壳很好看，颜色很正，手感很好，没有色差，是正品，大内存高运行，玩游戏非常爽，带电旧，120W快充充电特别快，爱了爱了', '墨羽', '2022-07-12 20:33:29', 4);
INSERT INTO `data` VALUES (11340, '小***-', 5, '外形外观：很漂亮，屏占比很高。\n屏幕音效：屏幕素质很好，很清晰。\n拍照效果：拍照很清晰。\n运行速度：运行速度超级快，很不错的。', '幻镜', '2022-12-02 17:33:10', 3);
INSERT INTO `data` VALUES (11341, '安***d', 5, '手机用了几天了，没有出现什么问题，给老公买的，颜色是老公自己选的，外观还挺好看的，待机时间长啊，这个是真的好，运行速度快，还送了透明的手机壳，唯独就是没有送耳机，充电头很大一个，挺重的，没见过这么大的，挺好的。手机质量非常好的', '幻镜', '2022-05-28 20:21:37', 6);
INSERT INTO `data` VALUES (11342, 'j***4', 5, '红米Redmi K50 Pro真心不错的哦，打开包装相当惊艳，无论颜色、外观、屏幕、声音，都非常满意，自带手机保护壳，非常严丝合缝，拿在手里，很有质感，屏幕大，拿着正好合适，银色挺好看的。屏幕也不错，没有坏点，清晰。 拍照效果还可以吧，处理器还是挺不错的，不愧为性价比之王。充电更是没的说，120w得充电器不到半个小时就充满了，以后再也不用担心手机没电了。', '银迹', '2022-09-03 12:49:37', 2);
INSERT INTO `data` VALUES (11343, '一***9', 1, '外形外观：外观太好看了吧，这个绿色真的是太好看了，黑色不行，不好看，外观看上去没绿色好看\n屏幕音效：屏幕很棒，打游戏什么的都特别清晰\n拍照效果：拍照一般般\n运行速度：天机9000真厉害，太牛了！\n待机时间：还行\n其他特色：总得来说还可以！', '幽芒', '2022-06-19 00:16:47', 3);
INSERT INTO `data` VALUES (11344, '简***欢', 5, '0点20多秒下的单，下午3点就到了，这次红米K50Pro在市场上绝对非常有竞争力，可能连对手都没有，简单说一下配置，有澎湃p1自研芯片的加持下手机标配5000mah大电池+120w快充，0到100电量只需19分钟，拍照上采用第二代一亿像素，不是第一代那么拉胯，拍照录像配有ois防抖还有快拍，又快又稳，成像素质肯定和5，6千的旗舰没法比，但同价位也是主流水平，当然，最重要的还是这颗芯，联发科天机9000，联发科的崛起之战，采用台积电4**工艺，GPU性能直追A15，不要说什么性能过剩，你看看网络上手机卖的好的，哪一个不是芯片好的?同时，屏幕素质也是非常的强，这次是有史以来最大的屏幕升级，配备三星2K柔性直屏，相比于曲面屏设计，使用体验会更出色。结合柔性屏幕，下巴超窄，正面的屏占比也是优秀。总之，这块屏真的非常出色，这块屏真的非常出色，这块屏真的非常出色，哈哈，当然我说的是2千到3千这个价位，同档类没有竞争对手，对屏幕要求非常高，价格在2千到3千的，非常推荐这台手机。多功能NFC，双扬声器，红外，WiFi6,x轴马达这些都是标配不多说。发哥，真的站起来了！', '银迹', '2022-03-23 09:04:46', 3);
INSERT INTO `data` VALUES (11345, 'L***4', 5, '选了好久终于决定买了这款，性能强大，性价比高，颜色超喜欢，用了来评价的，感觉还可以，第一次用小米，还担心性能，结果领另我惊喜真的很好', '幽芒', '2022-06-25 20:38:44', 2);
INSERT INTO `data` VALUES (11346, 'j***d', 5, '外观好看，杜比全景声，音效好，高刷很爽，拍照清晰，运行贼快，，，爱了爱了，', '幽芒', '2022-08-11 23:28:25', 5);
INSERT INTO `data` VALUES (11347, 'w***8', 5, '外形外观：好看大气上档次，非常的喜欢这个手机\n屏幕音效：分辨率高，超级清晰\n拍照效果：像素高，清晰\n运行速度：运行速度快，非常好\n待机时间：长', '银迹', '2022-12-23 11:41:45', 2);
INSERT INTO `data` VALUES (11348, 'l***0', 5, 'K40就那个了，感觉放备用机很是牛。性价比高。这k50一出就上了，整体来说真的很不错。性价比很高，游戏体验明显温度低很多运行也比较流畅120hz高刷自适应屏幕真心舒服可以说这次天际9000的功耗调节的非常不错YYds不要盲目的跟风自己好用才是硬道理', '银迹', '2022-03-31 16:17:44', 5);
INSERT INTO `data` VALUES (11349, 'u***b', 5, '非常流畅，手感很好，偶尔打打游戏，没有卡顿现象。充电无敌！\n发热还行，可接受！\n8+256内存绝对够用！', '墨羽', '2022-04-06 08:42:17', 5);
INSERT INTO `data` VALUES (11350, 'c***1', 5, '手机收到了，使用了一段时间了，打电话音量很不错，音质也还可以，屏幕显示也很清晰不刺眼，系统运行流畅，不卡顿，看视频看小说听歌都毫无压力，现在买手机一定要买大内存的，因为现在的app都太大了太占内存！', '墨羽', '2022-07-28 21:34:12', 4);
INSERT INTO `data` VALUES (11351, 'E***t', 5, '外形外观：银色的很酷炫，手感舒适。\n屏幕音效：120hz使用体验丝滑流畅，上下双扬声器音效不错\n拍照效果：拍照图片很清晰。\n运行速度：8+256切换应用很流畅。9000处理器不输高通8\n其他特色：120w快充速度特别快', '银迹', '2022-03-29 13:11:52', 6);
INSERT INTO `data` VALUES (11352, 'j***b', 5, '运行速度：12+256的内存运行杠杠的 很不错\n拍照效果：2k的屏幕很清晰，看视频很爽\n屏幕音效：音质还不错  \n待机时间：平时不怎么打游戏，一天下来还有30左右的电，足够用了。现在活动优惠了不少值得入手', '幽芒', '2022-06-10 15:47:13', 2);
INSERT INTO `data` VALUES (11353, 'w***c', 5, '外形外观：高端大气上档次，低调奢华有内涵，非常时尚\n屏幕音效：屏幕是2k屏幕，清晰度非常棒\n拍照效果：1亿像素很高，拍照效果很好，很清晰\n运行速度：天玑9000处理器，运行流畅无卡顿\n待机时间：一天足够用，120w充电速度。20分钟就能充满，非常满意', '晴雪', '2022-09-18 15:53:50', 2);
INSERT INTO `data` VALUES (11354, '陈***艳', 5, '外形外观：颜色特别好看，看不腻的那种。\n屏幕音效：还不错。\n拍照效果：挺真实的\n待机时间：比较长', '墨羽', '2022-03-31 21:21:57', 4);
INSERT INTO `data` VALUES (11355, 'j***q', 5, '外形外观：真好，手感也舒服，\n屏幕音效：听起来还不错，\n拍照效果：照片可以放很大，很清晰，很好，\n运行速度：很快，\n待机时间：用一天都不用充电\n其他特色：总体使用感觉不错', '墨羽', '2022-03-28 22:08:19', 6);
INSERT INTO `data` VALUES (11356, '不***蚁', 5, 'Redmi K50 Pro采用了6.67英寸三星AMOLED直屏，分辨率为3200&times;1440，支持120Hz的屏幕刷新率。Redmi K50 Pro的屏幕峰值亮度达到了1200nit，支持1.6万级自动亮度，并且支持环境色温感应以及杜比视界。Redmi K50 Pro机身厚度只有8.48mm，非常的薄，但电池容量却达到了5000毫安时，将大电池与纤薄机身完美融合，手机重量为201g，整机手感还是非常出色的。日常使用非常棒的，不压手。\nK50 Pro采用双立体声扬声器，并且保留了3.5mm耳机孔，方便有线耳机使用。同时手机支持蓝牙5.3，也将带来更稳定、省电的无线蓝牙连接体验。实用的时候感觉蓝牙传输速度比我原来的小米8快好多。在《王者荣耀》游戏中，Redmi K50 Pro可以以120帧的帧率运行游戏，经过一局游戏的测试，Redmi K50 Pro运行《王者荣耀》的平均帧率为115.5FPS，在整个游戏过程中画面流畅，可以明显感受到超高帧率带来的游戏体验升级。游戏性能超赞的，超级推荐', '幽芒', '2022-03-30 18:36:08', 7);
INSERT INTO `data` VALUES (11357, 'j***t', 5, '屏幕音效：双扬声器打游戏的声音很奈斯\n待机时间：5000的电池配120W的充电器，20分钟就充满了\n运行速度：天玑9000打游戏也很好\n拍照效果：很好\n外形外观：很喜欢的墨羽颜色好看', '墨羽', '2022-07-09 22:56:39', 3);
INSERT INTO `data` VALUES (11358, '吃***老', 5, '这个手机外观就非常好看了，我好喜欢这种绿色，很淡雅清新的感觉！手机上手玩了一周多了，质感很不错，充电很快，也没有卡顿，玩手游都还OK，会有点发烫，但是影响不大，目前各功能都还不错！', '幽芒', '2022-08-18 19:12:04', 3);
INSERT INTO `data` VALUES (11359, 'z***g', 5, '运行速度：天机9000+12G，2k屏加高刷，非常流畅，细腻\n拍照效果：1亿像素拍照清晰，速度很快\n屏幕音效：双扬声器避免了遮挡\n待机时间：120W秒充，随时可以保证有电', '墨羽', '2022-04-16 18:55:39', 7);
INSERT INTO `data` VALUES (11360, 'c***y', 5, '银色的k50效果非常好，这种银色的贝壳有点那种反光双色效果。非常闪亮。本身这款手机的运行速度就非常快，屏幕的分辨率非常高，显示效果非常的好，尤其是表面在刷新的时候有高刷的效果，运行的话会感觉非常顺畅。', '银迹', '2022-05-03 10:53:08', 7);
INSERT INTO `data` VALUES (11361, '尊***长', 5, '手机很流畅 价格也不是很贵2940元购买。 给老人家用足够了 质量没的说 一直有购买小米的产品。质量放心价格公道 \n美国有苹果 中国??小米 干就完了 欧丽给', '墨羽', '2022-09-21 20:06:39', 6);
INSERT INTO `data` VALUES (11362, 's***a', 4, '各个点都在我的兴趣点上，直屏，大电池，120w快充，miui系统，性能也很够用，起码这号不比火龙差，非常满意。背面这个玻璃反射效果非常漂亮', '墨羽', '2022-03-23 14:23:13', 4);
INSERT INTO `data` VALUES (11363, 'x***c', 5, '不错不错，宝贝收到了，系统流长，外观漂亮，很满意，拍照还有防抖，使用体验非常棒，恨意的一次购物，一直用小米，下次还会在换小米的。', '幽芒', '2022-06-18 16:02:48', 5);
INSERT INTO `data` VALUES (11364, 'j***b', 5, '外形外观：大小合适，这个晴雪配色真的很棒\n屏幕音效：双立体扬声器，体验不错\n拍照效果：一亿像素，日常够用\n运行速度：12+256，游戏嘎嘎爽\n待机时间：5000毫安电池完全够用还有120w快充', '晴雪', '2022-08-20 12:14:16', 2);
INSERT INTO `data` VALUES (11365, '朱***妖', 5, '晚上下的单第二天早上就给送来了，京东没的说。\n新手机到手，老手机数据很快转入，一点也不卡顿，系统很流畅，屏幕清晰，而且充电是真的太快了，不错(*?&acute;╰╯`?)?', '幽芒', '2022-04-20 21:36:02', 4);
INSERT INTO `data` VALUES (11366, '十***熊', 5, '手机真的很漂亮，在实体店看的k50，感觉很不错，朋友都介绍这款手机，还有一亿像素，实在是太棒了，我同学还问我呢，他也准备买一台，我大力推荐哦\n外形外观：墨羽色闪闪发光，\n屏幕音效：显示色彩清晰\n拍照效果：一亿像素，超清感光，夜景更美\n运行速度：顶级处理器\n待机时间：正常手机了，一天4000mah\n其他特色：国产精品', '墨羽', '2022-05-14 22:05:52', 3);
INSERT INTO `data` VALUES (11367, '不***_', 5, '外形外观：非常的酷炫，很喜欢\n屏幕音效：挺好的\n拍照效果：超级好\n运行速度：天玑9000很快，打游戏很爽\n待机时间：挺长的，优化很好\n其他特色：一个字。爽', '银迹', '2022-03-29 00:10:19', 6);
INSERT INTO `data` VALUES (11368, 'j***K', 5, '外形外观：中挖孔屏，银迹色比较好看\n屏幕音效：屏占比高2k屏高清\n拍照效果：一亿像素满足日常生活需要\n运行速度：天玑9000运行杠杠的\n待机时间：用一天足够\n其他特色：120w充电速度快', '银迹', '2022-06-18 10:30:58', 2);
INSERT INTO `data` VALUES (11369, '敏***家', 5, '新手机很漂亮,分辨率很高,天矶9000玩游戏很畅快，运行速度超快。120 W充电20分钟充满，充电太快了,很满意。整体感觉是不错的,和其他手机相比该有的的有,这个充电速度是真的快！', '晴雪', '2022-10-12 21:59:33', 3);
INSERT INTO `data` VALUES (11370, 'j***u', 5, '屏幕音效：还可以\n拍照效果：一般，1亿像素也没有那么好，没有长镜头变焦，最多10倍放大，拍超级月亮都拍不出来\n\n运行速度：还行，不错\n待机时间：电池性能不错，充电很快，电量挺耐用\n外形外观：比官图好看太多，幻境bling bling挺适合女孩子的', '幻镜', '2022-07-21 12:42:23', 2);
INSERT INTO `data` VALUES (11371, '不***行', 5, '外形外观：首先是我喜欢的直面屏 很棒 虽说是塑料中框但不拉夸 后面也好看 我选的是绿色大爱\n屏幕音效：屏幕显示相当细腻 不亏是2K屏 分辨率也高 上下双喇叭看剧很舒服\n拍照效果：我对拍照没多大要求 一亿像素绝对够用效果也不错\n运行速度：天玑9000的性能不是盖的 比火龙系列不逊色 发热控制的很好 流畅度也好 特别丝滑\n待机时间：电池大 充电快 120w20多分钟充满 还在乎待机吗？你以为某果呢 充个电半天用半天\n其他特色：我想跟那些某果的舔苟说 都什么年代了还说国产卡卡卡 中高端机都这么丝滑柔顺 高端机更不用说了', '幽芒', '2022-04-18 11:45:13', 6);
INSERT INTO `data` VALUES (11372, 'd***5', 5, '旧手机有点卡，看了很多购买手机的推荐意见，大家对这款手机的评价还不错，加上之前也用了很多小米的产品，所以对小米的手机也是很信任的。外观简洁大气，手感很棒，机身重量适中，超级快充体验非常棒，基本可以告别电量焦虑，拍照啥的也能达到基本需求，很满意。', '银迹', '2022-10-03 09:44:54', 5);
INSERT INTO `data` VALUES (11373, '9***3', 5, '这部手机很实用，性价比很高，物有所值，系统很流畅，可以入手，推荐大家购买', '幽芒', '2022-03-31 22:12:46', 8);
INSERT INTO `data` VALUES (11374, 'j***7', 5, '性价比高的一款了\n外形外观：时尚还可以了\n屏幕音效：清晰，大声\n拍照效果：清晰\n运行速度：满足日常需求\n其他特色：肉眼可见的充电真快', '晴雪', '2022-08-30 21:14:31', 5);
INSERT INTO `data` VALUES (11375, '小***a', 5, '质量非常好,Redmi K50 Pro搭载天玑9000处理器，采用三星2K直屏，内置5000mAh电池，支持120W秒充 ，采用1亿像素光学防抖相机、VC液冷散热，支持杜比视界全景声，支持蓝牙5.3标准以及LC3音频编码。与卖家描述的完全一致,非常满意,真的很喜欢,完全超出期望值,发货速度非常快,包装非常仔细、严实,物流公司服务态度很好,京东的物流很快,就算邻近仓没货,周边调货也很快,我这儿其他快递不管你在不在家都丢~,,只有京东会联系你,送到你手上,难很满意的一次购物店家很讲信誉,而且很不错哦,在这家店买东东,我很满意', '银迹', '2022-06-27 22:50:11', 1);
INSERT INTO `data` VALUES (11376, 'j***R', 5, '外形外观：很不错 造型美观 女孩子会比较爱\n屏幕音效：屏幕够大 打游戏超爽 拿着也很轻便舒服\n拍照效果：还算ok\n运行速度：赞！赞！！赞！！！真的运行超级可兄弟们\n待机时间：超长待机  前一天的王者 早晨起来还在待机 特别牛\n其他特色：适合游戏党 美化也超好看', '银迹', '2022-06-10 16:18:39', 2);
INSERT INTO `data` VALUES (11377, 'A***K', 5, '材料和做工都特别精致，做工真的非常棒，我觉着我可以推荐给我朋友买。录像水准还是很高的，芯片的水平完全可以吊打 vivo OPPO一类的同等价格手机。处理速度也很快，打游戏几乎不怎么发烫。质量不错，物流也很快，值得点赞！', '幽芒', '2022-09-01 21:14:43', 4);
INSERT INTO `data` VALUES (11378, 'j***浮', 5, '包装完好无损，发货迅速，非常满意，这次红米k50Pro 的屏幕最为惊艳，分辨率极大提高，眼睛看上去很舒服，很细腻，这是最大卖点。还有CPU芯片也是很给力，其他应有尽有【功能】NFC 红外 双扬声器，声音很清晰很大声。指纹识别快速。重量控制的刚刚好 不重哈，还有就是充电器120w的 速度很快20来分钟充满，5000毫安电池也是很给力，使用一天完完全全没问题，总之非常满意。', '银迹', '2022-03-28 19:22:53', 3);
INSERT INTO `data` VALUES (11379, '打***呗', 5, '红米手机大品牌值得信赖，质量保证，大家都喜欢。这个牌子的k50pro墨羽手机，高端大气，天玑9000芯片胜任任何游戏，一亿像素完美成像，120w快充再也不用担心手机没电了，酷酷的，爱了爱了。包装很美观很严实，保存的很好。快递也很速度，第二天就收到了。以后还会继续购买。', '墨羽', '2022-07-30 12:38:09', 6);
INSERT INTO `data` VALUES (11380, 'j***E', 5, '这款手机买的挺满意的，用起来很流畅，外观也比较好看，手感极好，拍照很清晰，充电嘎嘎快，屏幕很清晰，很满意的一次购机。', '幽芒', '2022-04-01 20:37:22', 3);
INSERT INTO `data` VALUES (11381, '心***痕', 5, '一打开充电口那就有个划痕也不知道啥情况非常好，宝贝很高大上，质量很好，看上去就给人一种高级感，价格也合适，这次网购很愉快，大赞?宝贝心仪很久了，趁活动时候买真的太划算了，喜欢的不要犹豫啊好！非常好！质量好，和实体店一样，颜色正，是我喜欢的', '幽芒', '2023-01-21 15:36:11', 5);
INSERT INTO `data` VALUES (11382, 'j***f', 5, '外形外观：整个手机，外观完好无损没有划痕覆盖的碎玻璃设计很有特点\n拍照效果：拍照很快没有延迟\n运行速度：开上2K 120赫兹运行没有丝毫不流畅。\n待机时间：大电池续航很久', '墨羽', '2022-06-14 10:22:22', 3);
INSERT INTO `data` VALUES (11383, 'j***L', 5, '天玑9000给力芯片，高性能，低功耗，硬核给力。VC液冷散热，大电池，打游戏非常给力，很适合我这样的电竞玩家，红米不亏是性价比之王，就是好用，物流也是真给力，凑凑凑的，隔天达，很不错，非常喜欢这部手机。', '银迹', '2023-01-05 20:46:16', 3);
INSERT INTO `data` VALUES (11384, '花***了', 5, '外形外观：外形外观很大气\n屏幕音效：2k的屏幕很清晰\n运行速度：9000处理器很快，玩游戏一点也不卡顿\n待机时间：5000毫安的大电池，120w的充电，只需20分钟充满', '墨羽', '2022-03-23 17:31:20', 7);
INSERT INTO `data` VALUES (11385, 't***m', 5, '手机很好啊，很轻，速度很流畅，玩大型游戏很顺畅！！是有点热，不过还好吧！主要是屏幕有点热，不过也能接受，可以在电风扇下面玩！通风！618活动2600买的很超值了！好评！', '幽芒', '2022-06-30 13:33:32', 4);
INSERT INTO `data` VALUES (11386, 'j***4', 3, '指纹位置是真**尴尬', '幻镜', '2022-05-13 22:44:22', 5);
INSERT INTO `data` VALUES (11387, '时***_', 5, '通信音质:非常清晰明了，没有什么杂音其他特色：使用\n流畅，电池特别抗用，续航在线，充电确实像描述的一样\n快,运行原神没有太大压力,屏幕大小刚好合适,黑色后\n壳在阳光下超级好看！手机后置摄像头像素也够用，光学\n防抖很好用显示效果：显示效果非常好，色彩分明', '墨羽', '2022-04-05 20:47:14', 5);
INSERT INTO `data` VALUES (11388, 'u***d', 5, '续航方面用户表示&ldquo;大电池杠杠的&rdquo;、&ldquo;大电池还是比较耐用&rdquo;，这点认可度也很高。的确5000mAh容量比4500mAh容量可是大了不少，再加上它所标配的120W有线快充，充电速度也不慢，续航确实是一个强有力的保障和后盾，重度用机的朋友完全可以放心。\n      还有，屏幕画质上，2K很细腻、很清晰。这点也是没什么争议的，很多旗舰机都做不到这个2K级别超清分辨率，它能够同时实现2K分辨率、三星E4材质和120Hz高刷，也是诚意满满，把品质尽力做到了最好。', '墨羽', '2022-03-31 17:14:24', 8);
INSERT INTO `data` VALUES (11389, '老***门', 5, '手机\n外形外观：非常好看的颜色！尺寸拿着手感非常舒服！\n屏幕音效：音响音效也非常逼真！\n拍照效果：照片非常清晰！防抖动！\n运行速度：开机很快！打开应用啥的都非常快！', '幻镜', '2022-11-11 16:11:23', 2);
INSERT INTO `data` VALUES (11390, 'j***8', 5, '物流：京东物流很快，隔天就得送达了\n包装：包装精致，里面有泡沫，盒子没有损毁\n外形外观：外观很高级，大气。握感舒服\n屏幕音效：2k屏幕显示细腻，阳光下也很清晰\n拍照效果：拍照很清晰，细节处理很到位\n运行速度：运行流畅，系统也很nice\n待机时间：待机时间超长，充电速度也很快', '银迹', '2022-08-03 10:56:26', 3);
INSERT INTO `data` VALUES (11391, '张***清', 5, '外形外观：经典商务\n屏幕音效：立体音\n拍照效果：很好\n运行速度：运行自如，一点不卡顿。\n待机时间：一天下来可以待机\n其他特色：外观设计很典雅，机背颜色设计的很炫酷', '银迹', '2022-10-21 18:16:34', 2);
INSERT INTO `data` VALUES (11392, '酷***钰', 5, '红米K50PRO确实不错  这次818活动购入价格真的很划算12+256/3000出头\n屏幕音效：不错，2k屏幕\n拍照效果：还可以\n运行速度：很不错\n外形外观：白色版本挺好的  \n天玑9000也是旗舰处理器性能够用很久去了', '晴雪', '2022-08-18 15:23:41', 3);
INSERT INTO `data` VALUES (11393, '琪***光', 4, '外形外观：可以，看剧很可以。\n屏幕音效：素质不错，声音也够大。\n拍照效果：和苹果比有一定差距，总感美颜过。\n运行速度：用了段时间一点也不卡，很好。媳妇当备用机用的。\n待机时间：两三可以，总要是充电够快，根本在乎待机，这点是苹果手机没法比的。', '晴雪', '2022-09-01 17:35:15', 2);
INSERT INTO `data` VALUES (11394, 'w***8', 5, '很好，\n外形外观：不错\n屏幕音效：很好，非常的好啊\n拍照效果：很好，像素清晰啊\n运行速度：很快，非常不错\n待机时间：待机时间挺长，\n其他特色：用的神舒服', '幽芒', '2022-12-23 11:40:46', 2);
INSERT INTO `data` VALUES (11395, 'u***5', 5, '发货速度很快 包装完整无破损  外形图案好看 墨羽 屏幕清晰 拍照给力 远景 近景非常清楚 内存大 充电速度快 音响效果不错  价格优惠   待机时间久 耐用', '墨羽', '2022-06-17 20:27:10', 3);
INSERT INTO `data` VALUES (11396, '赵***昭', 5, '618就宠她\n\n作为忠实米粉，家里很多电子产品和家电都是小米的。前段时间终于抢到了K50，试用一下，体验感蛮好的，小米没让人失望！\n\nK50优点有很多，续航真的很给力。手机信号也非常的好。特别是2K屏看着非常舒服，8100处理器很凉，充电速度很快。在2000多的价位，配置直接拉到顶，满意！', '墨羽', '2022-06-02 13:51:52', 3);
INSERT INTO `data` VALUES (11397, 'v***8', 5, '首发买入，这次送货很快了，次日就到了。用了一段时间，使用感受相当不错，屏幕看起来很舒服，120w快充是真滴快，预装的三方都可以删除，绿色实物比图片感觉好很多，作为不玩游戏的人，这台手机应该可以用很久。', '幽芒', '2022-03-30 09:14:32', 7);
INSERT INTO `data` VALUES (11398, '任***子', 5, '外形外观：造型英朗，适合男孩子，买给弟弟用很不错，游戏性能强悍，他很喜欢，支持高刷，对眼睛很好，手感不错，送货上门很快，给弟弟一个惊喜\n\n屏幕音效：显示效果很棒，高刷很流行\n拍照效果：拍照不错，很清晰', '墨羽', '2022-06-27 15:16:07', 3);
INSERT INTO `data` VALUES (11399, 'g***s', 5, '红米k50pro手机真不错，与卖家描述的一样，是原装正货，红米大牌品质有保证，包装完好无缺，用料扎实，做工细致，挖孔很小的2k屏亮丽，机器功能强大，运行速度快而且稳定，系统操作流畅，机身大小厚薄刚好合适，是非常喜欢的机型。卖家服务好，发货及时，京东自营物流送货快捷迅速，上午下单，下午就收到，点赞加好评的！', '银迹', '2022-04-04 11:13:51', 8);
INSERT INTO `data` VALUES (11400, 'H***1', 5, '通信音质：非常好 其他特色：屏幕大，运行流畅，外观大气 显示效果：色彩好，显示清晰， 正品，价优，购机愉快，店家很好，值得购买。宝贝收到了，质量很不错，包装精致，材质优秀，比想象中好，送礼自用非常合适，下次继续购买', '墨羽', '2022-06-24 18:07:37', 3);
INSERT INTO `data` VALUES (11401, '念***不', 5, '用了几天才来评价，手机很好用，电话铃声大。对方通话声音非常清晰，没有杂音，功能齐全，键盘字体大。样式美观，信号强度大，发货速度快，物流挺快的，服务态度也非常好，最主要东西可以。', '幽芒', '2022-10-16 12:31:56', 3);
INSERT INTO `data` VALUES (11402, '奥***4', 5, '屏幕感官非常好，充电速度非常快\n外形外观：银色最帅，非常推荐\n屏幕音效：音效还是挺不错的，比我的k30s好\n拍照效果：拍照效果的话就不要太抱希望，毕竟是天际\n运行速度：绝对杠杠的', '银迹', '2022-07-05 22:53:52', 3);
INSERT INTO `data` VALUES (11403, 'u***t', 5, '拍照效果:清晰\n\n续航能力:很好\n\n运行速度:畅快\n\n非常不错，玩游戏一点也不卡， 拍照也清楚，就是没有512g有点小失望。客服回答问题有非常快服务好。', '晴雪', '2022-12-19 19:28:02', 3);
INSERT INTO `data` VALUES (11404, '方***-', 5, '外形外观：还可以\n屏幕音效：挺好的\n拍照效果：挺清晰，日常使用足够\n运行速度：杠杠滴\n待机时间：一天下来没问题\n其他特色：充电速度超快，618的价格真香，不到两千九，还要啥自行车', '墨羽', '2022-07-23 19:36:01', 2);
INSERT INTO `data` VALUES (11405, '美***落', 5, '手机到手很惊艳，屏幕完美，杜比立体声也还行。原来时间是华为P30pro.对比一下，拍照确实没有好。说实话。\n运行速度：12\'G大内存运行起来没的说。\n外形外观：银色很不错，带壳塑料边框就无所谓了。', '银迹', '2022-03-31 18:26:54', 7);
INSERT INTO `data` VALUES (11406, 'j***m', 5, '很精致的一款小手机，刚刚收到货还没来得及校正时间日期。试了一下，整体感觉很不错，戒网手机，很适合学生使用，不能上网，不携带任何游戏。学生党可以直接入手小手机做工很精细，机身小巧，很迷你。携带也是非常的方便的。只可以打电话，我是主要买回做备用机的，收短信和打电话用。整体是非常满意的，这种手机不耗电，', '银迹', '2022-09-01 21:01:32', 3);
INSERT INTO `data` VALUES (11407, 'M***r', 5, '外观大气炫酷，音效特别好，拍照也清晰，运行也流畅，不卡顿，充电也不卡顿！', '墨羽', '2022-04-03 22:28:43', 4);
INSERT INTO `data` VALUES (11408, '青***返', 5, '充电超级超级超级快，20分钟左右充满。处理器也是比较过的，运行起来非常流畅，后置像素非常非常非常nice，整体还是非常好的！就是感觉厚重了一些', '幽芒', '2022-12-24 21:50:22', 3);
INSERT INTO `data` VALUES (11409, '网***4', 5, '送货速度好快，第二天收到。好机器，使用流程丝滑，打游戏有一定发热，但是相对于原来机器的发烫已经好很多了。电池容量大，使用一天没问题。外观很中意。五星推荐。', '晴雪', '2022-08-05 12:22:52', 3);
INSERT INTO `data` VALUES (11410, 'j***x', 5, '这手机壳很漂亮，质量很好，做工精细，手感很好，手感不错，满意。速度也挺快就是有点发烫，电池一般没红米9耐用！其余的都还行不错', '银迹', '2022-04-22 09:06:37', 3);
INSERT INTO `data` VALUES (11411, 'X***惢', 5, '直屏幕就是喜欢，超喜欢，操作起来手感很好，很享受。\n屏幕音效：屏幕很清晰，很完美。\n运行速度：运行起来很快，完全感受不不到卡，玩王者不卡，很流畅，很顺畅，就是满意。\n待机时间：充电十来二十分钟就满了 超级快，早上起来刷牙充一遍，晚上洗澡充一遍，就尽情使用。', '墨羽', '2022-05-02 22:27:13', 5);
INSERT INTO `data` VALUES (11412, '傲***阿', 5, '外形外观：外观很好看，尤其是绿色，特别好看\n屏幕音效：2k的屏幕太棒了，用起来特别棒\n拍照效果：拍照一般\n运行速度：天机9000永远的神！\n待机时间：还行\n其他特色：总得来说还可以，这个价格非常不错了', '幽芒', '2022-06-19 00:14:40', 3);
INSERT INTO `data` VALUES (11413, '波***5', 5, '非常满意，送货快，东西好，手机有点压手，很有质感。特别提醒下要用原装的充电器和充电线，充电速度那是真快啊。出乎意料之外的满意。', '墨羽', '2022-07-04 10:18:18', 5);
INSERT INTO `data` VALUES (11414, 'q***8', 5, '完美的机子，尺寸合适手感很好，外观大气上档次，屏幕效果不错，2k屏就是细腻，运行大型游戏无压力！超级快充加持就更显优秀啦', '墨羽', '2022-07-15 11:32:41', 4);
INSERT INTO `data` VALUES (11415, 'W***x', 5, '外形外观：颜值很高，绿色比我想象的好看\n屏幕音效：非常不错\n拍照效果：非常不错\n运行速度：非常快\n待机时间：大电池，待机时间长\n其他特色：给老人买的，经济实惠', '幽芒', '2023-01-17 18:33:36', 2);
INSERT INTO `data` VALUES (11416, '善***人', 5, '很好看，绿色的很好看，屏幕呈现色彩很不错，流畅度很好！整体做工感觉很扎实，120w快充份量很足！侧方位指纹上手体验还不错，解锁很快。集成按钮按起来也很舒服。', '幽芒', '2022-03-23 10:32:52', 3);
INSERT INTO `data` VALUES (11417, 'j***4', 5, '外形外观： 很大气美观，喜欢，2k屏幕,非常nice,音效很不错，听起来很饱满，音色圆润，运行速度很快，拍照超清晰，120W充电速度非常快，一次非常愉快的选择。', '幻镜', '2022-04-05 19:58:02', 3);
INSERT INTO `data` VALUES (11418, 'p***5', 5, '非常流畅，照片清晰，充电无敌快，充一次用一天完全没问题。还送了高端的手机壳。壳子手感很好。买来给孩子用的，自己不舍得放手了，果断自己用了', '晴雪', '2022-10-14 11:58:10', 3);
INSERT INTO `data` VALUES (11419, '番***亨', 4, '618搞活动买的，价格实惠，这款是对比了荣耀，小米12等差不多价位的手机之后选的。这款用了天玑9000处理器，适合刚上大学用的，玩游戏不卡顿，运行速度很快。充电器很大，因为是闪充，因为是新机，目前电量很耐用。机身也很好看，而且是非曲面屏，贴钢化膜也更容易贴合，总体很满意。', '墨羽', '2022-08-02 15:14:54', 3);
INSERT INTO `data` VALUES (11420, 'l***g', 5, '预售，发货比原计划快。电池容量大，120w，手感真的太好了，外壳有质感，屏幕显示效果非常明亮，扬声器很棒。相机拍摄也很好，清晰给力。性价比很高。', '墨羽', '2022-03-26 11:08:58', 4);
INSERT INTO `data` VALUES (11421, 'j***k', 5, '真不错，这处理器性能挺强大的，发热控制的也还行，性价比很高\n外形外观：直屏用着很舒服，不会误触，打游戏很nice\n屏幕音效：2k分辨率很棒\n拍照效果：还行\n运行速度：很快', '幽芒', '2022-07-18 01:42:03', 2);
INSERT INTO `data` VALUES (11422, '绿***茵', 5, '外形外观：还不错，后壳摸着舒服\n屏幕音效：屏幕2k屏幕，很清晰，音质也是很好\n拍照效果：还行吧，这价格还是可以的\n运行速度：9000处理器还是挺不错的，至少短时间不会卡\n其他特色：120w充电很快', '银迹', '2022-08-13 10:40:51', 3);
INSERT INTO `data` VALUES (11423, '我***l', 5, '外形外观：外观大气，尤其是银色的非常喜欢\n屏幕音效：2K屏幕120HZ杠杠的\n拍照效果：一亿像素画质完美，夜景也很不错\n运行速度：非常的流畅，同时打开很多app丝毫不卡\n待机时间：120瓦快充绝对完美，正常20分钟充满，正常可以待机一天', '银迹', '2022-03-29 19:08:34', 5);
INSERT INTO `data` VALUES (11424, '夜***凉', 5, '显示效果:2K屏幕，体验感真的很不错，高清还是高清；\n快充特色:120W充电真的好快，续航能力也很优秀；\n配置方面，天机9000处理器，一个字牛。\n选择这款手机就是冲着天机90002K屏幕120W快充', '墨羽', '2022-06-18 22:25:47', 4);
INSERT INTO `data` VALUES (11425, 'S***u', 5, '手感很好，屏幕清晰\n颜值很高，侧边指纹用着很舒服\n性能很棒，玩游戏时体验非常棒??\n值得入手', '墨羽', '2022-03-26 12:56:08', 4);
INSERT INTO `data` VALUES (11426, 'i***真', 5, '外形外观：感觉不错\n屏幕音效：挺好的\n我觉得很好可以购买\n拍照效果：拍照沟通能力很好\n运行速度：不卡，运行速度比较快，真的不错呀', '银迹', '2022-07-15 22:03:05', 3);
INSERT INTO `data` VALUES (11427, '幸***重', 4, '虽然是我用的第一个塑料中框的手机，买之前还忐忑不安，担心质感做工很差，到手后顾虑完全打消了！质感做工都很棒，大品牌果然靠谱，MIUI13用起来丝滑流畅！天玑9000发热控制的非常好，把玩了3个小时一点也不烫手，120w充电简直不要太快，刷个牙洗个脸的功夫就充好了！不错不错！', '银迹', '2022-03-23 15:31:44', 6);
INSERT INTO `data` VALUES (11428, 'j***7', 5, '这款手机618性价比真的高，2K屏幕很细腻，处理器天机9000真的很顶，用起来非常不错，可以坚持个一两年了', '银迹', '2022-07-12 10:00:08', 5);
INSERT INTO `data` VALUES (11429, 'j***a', 5, '运行速度：快\n屏幕音效：很好\n拍照效果：好\n外形外观：帅\n其他特色：冲电快\n没有3.5耳机转接头', '墨羽', '2022-06-25 12:09:41', 3);
INSERT INTO `data` VALUES (11430, 'h***g', 5, '运行流畅，充电神速，颜值无敌，游戏很丝滑。值得购买，期待红米越来越好。', '墨羽', '2022-03-24 11:02:26', 9);
INSERT INTO `data` VALUES (11431, 't***5', 5, '外形外观：稳中大气\n屏幕音效：流畅清晰\n拍照效果：完美逼真\n运行速度：快速顺畅\n待机时间：超长待机\n其他特色：性价比高\n这款手机买来送孩子的，打游戏特别顺畅，孩子超级喜欢！', '墨羽', '2022-07-08 06:58:31', 2);
INSERT INTO `data` VALUES (11432, '1***2', 5, '外形外观：大气，高颜值，耐看\n屏幕音效：2K屏显示效果非常好，音质效果也好\n拍照效果：拍照成片效果不错，满足自己的需求\n运行速度：快\n待机时间：长', '幽芒', '2022-10-18 23:26:16', 2);
INSERT INTO `data` VALUES (11433, 'p***e', 5, '外形外观：绿色外观大气，磨砂工艺不沾指纹\n屏幕音效：2k分辨率果然不错，2k+直屏，视觉效果很出色\n拍照效果：一亿像素，光学防抖好评！', '幽芒', '2022-03-22 19:43:37', 7);
INSERT INTO `data` VALUES (11434, '毕***华', 5, '外形外观：外观还可以接受，灰色也是比较喜欢的\n屏幕音效：屏幕2K非常清楚，音效也不错\n拍照效果：后置一亿像素拍摄很清楚\n运行速度：很快，不怎么卡顿\n待机时间：普通使用一天时间没问题\n其他特色：性价比很高，值得购买。', '银迹', '2022-12-26 13:40:11', 2);
INSERT INTO `data` VALUES (11435, 'j***q', 5, '特别特别特别的爱不释手。真的，在灯光下照耀的颜色很炫天玑9000处理器很流畅，三星2K屏清洗色泽很好，OIs光学防抖的功能很实用。哈哈哈这个手机电池容量也很给力，以后出去拍照也能战斗很久了，好开心，而且包装简洁大气，还很贴心的配送了保护套，买回来都不用着急怕磕碰到了。', '晴雪', '2022-09-02 09:28:08', 4);
INSERT INTO `data` VALUES (11436, 'q***e', 5, '?先说结论，挺不错的哈哈哈\n1.好看这个绿色超级好看，很有质感。喜欢?\n2.手机比较轻薄，颜值很棒\n3.然后用起来很流畅，不卡不断流不断触，打王者开120帧最高画质不卡。还是很爽的~\n4.充电很快，120q快充，不到20分钟就冲了55%的电??比我之前华为冲的快多了\n5.放歌音质很好。', '幽芒', '2022-03-22 22:29:35', 6);
INSERT INTO `data` VALUES (11437, 'j***D', 5, '手机很不错外观设计都很有创意值得入手', '幻境 8GB+256GB', '2023-02-01 16:45:44', 9);
INSERT INTO `data` VALUES (11438, 'j***Z', 5, '很好用，买给家里长辈', '幻境 8GB+256GB', '2023-03-17 16:54:17', 4);
INSERT INTO `data` VALUES (11439, 'j***I', 5, '终于收货了，整体使用不错。', '幻境 8GB+256GB', '2023-02-03 11:09:35', 3);
INSERT INTO `data` VALUES (11440, 'j***I', 5, '终于到货了，整体不错', '幻境 8GB+256GB', '2023-02-03 10:55:19', 9);
INSERT INTO `data` VALUES (11441, 'j***i', 5, '给父母买的，父母很喜欢，物流很快，用着也没毛病，很好的体验感！运行速度挺快的，拍照也很美', '晴雪 8GB+256GB', '2023-02-13 08:38:02', 9);
INSERT INTO `data` VALUES (11442, 'C***9', 5, '外形外观：很漂亮小米这款的工业设计是天花板级别了\n屏幕音效：画质很细腻满意 音质也很好好评\n拍照效果：这个很真 拍的效果不错 尤其是夜拍很清晰哦\n运行速度：很快超级满意基本直接起飞的感觉\n待机时间：这个就给力了 超级时间长\n其他特色：性价比高很好用满意加好评大品牌值得信赖', '墨羽', '2022-11-06 12:32:10', 8);
INSERT INTO `data` VALUES (11443, '1***哥', 5, '外形外观：很漂亮很满意\n屏幕音效：很好听呢满意好评\n拍照效果：特别牛很好很清晰哦满意\n运行速度：超级快速很好用直接起飞好评满意\n待机时间：这个厉害了俩天能用\n其他特色：机器漂亮做工好', '墨羽', '2022-11-08 21:43:40', 8);
INSERT INTO `data` VALUES (11444, '蓝***心', 5, '三年没换手机，因为没发现性价比满足我需要的。赶上这个双十一，想换一台心仪的手机。看了很多的评测。最后我选择了小米的K50这款机器。之所以选择她它，有三个原因。第一呢？就是内存大。12+256G的这个。内存空间非常大，用起来非常舒服。以前6G,内存的手机，运行点儿程序，非常卡。选择了这个12+256的小米K50以后啊。你可以安很多的程序。想玩就玩，毫无顾忌。这是让人感觉非常畅快的一点。第二，就是他的这个MIUI13，功能非常完善。性能非常全面，人性化交互特点非常突出。第3点呢，就是67w快充、大电量，5000毫安大电池，运营太多的程序啊，他也够用。最让人惊喜的一点呐，他还能安谷歌框架，你有这个爱好呢，选择这一款手机没有错。', '幽芒', '2022-11-07 14:31:30', 8);
INSERT INTO `data` VALUES (11445, '世***转', 5, '新手机收到了，用了两天才来评价。白色的很好看，经典色。\n外形外观：外观简洁经典，大小握在手里正合适。\n屏幕音效：声音超大，早起的闹铃声比以前的大很多。\n\n拍照效果：不错。\n运行速度：还可以。', '晴雪', '2022-10-19 20:49:02', 6);
INSERT INTO `data` VALUES (11446, 'h***r', 3, '外形外观：K50手机外观挺好的，摸起来手感不错，用起来很舒服，2K屏，手感稍重\n屏幕音效：2K屏，因为处理器好，所以120Hz的频率也不卡顿。运行速度快，待机时间超长，声音外放音量挺大，音质也不错，看视频时声音听起来很有质感，小米系统也挺\n运行速度：运行速度快，毕竟处理器要比市场上的780系列高出好几个档次，在缺芯的时候，这个价位的手机处理器很高了\n待机时间：电池容量大，待机时间超长，快充速度快\n拍照效果：拍照可以，因为像素也不是特别高，但对日常的拍照足够了，不好的是感觉自带美颜', '幽芒', '2022-09-03 23:33:57', 6);
INSERT INTO `data` VALUES (11447, '1***哥', 5, '性价比之王哦 真的是一代神机 满意好评 大品牌值得信赖 非常非常值得推荐哦 电池也给力 俩天一冲电吧 勉勉强强够用的 好评满意', '幻镜', '2022-11-15 22:08:41', 8);
INSERT INTO `data` VALUES (11448, 'L***k', 5, '性价比：高，钉子户有希望 运行速度：非常流畅 拍照效果：不怎么拍照，看起来还不错 电池续航：续航很棒，重度游戏一天两充也够了 外观设计：超级好看，有点一块钢板的艺术那种感觉 MIUI系统：新系统精简的非常好，桌面还可以放点花宠', '墨羽', '2022-12-26 19:11:41', 4);
INSERT INTO `data` VALUES (11449, '落***人', 5, '屏幕效果特别好，运行速度很快，外观很漂亮，音效很棒，视频模式自动开启杜比音效，看电影追剧特别爽，2K的屏幕，5500毫安大电池，天机8100，真的待机时间超长，打游戏很舒服，使用起来效果非常完美，强烈推荐购买。', '晴雪', '2022-09-10 10:04:40', 4);
INSERT INTO `data` VALUES (11450, 'j***y', 5, '外形外观：K50的外观设计简约时尚大气，外观挺满意。\n屏幕音效：屏幕显示效果很不错，画质很细腻清晰。\n运行速度：简单的使用运行效果还是挺快的，够用。\n待机时间：5500毫安的大电池，待机时间还是有保证的。\n拍照效果：拍照可以满足日常生活的要求，拍照防抖效果不错。', '墨羽', '2022-10-03 11:39:54', 8);
INSERT INTO `data` VALUES (11451, 'o***a', 5, '外形外观：黑羽很好看 颜色不单调\n屏幕音效：2K分辨率完美 6.67吋大小合适\n拍照效果：4800万完全够用\n运行速度：启动快 多开不卡\n待机时间：充电快 耗电合理\n其他特色：MIUI13好用', '墨羽', '2022-03-31 17:11:20', 7);
INSERT INTO `data` VALUES (11452, '有***点', 5, '屏幕效果：很好 运行速度：很快 外形外观：很漂亮 尺寸大小：刚好。音效:很棒，视频模式自动开启杜比音效，看电影追剧特别爽，5500的大电池，真的待机时间超长，重量，也刚好，不压手，天玑8100，打起游戏很舒服，物流也特别快，性价比很高，很实惠，使用起来感觉很好，非常完美.^?^.', '银迹', '2022-04-19 19:12:30', 7);
INSERT INTO `data` VALUES (11453, 'l***8', 5, '首先充电头越做越小，大小设计合理，比之前我用的米10PRO的还小，\n外观设计很好看，布局是我喜欢的类型，\n前置摄像头在中间，满足平时自拍要求，后置像素完全够用，\n双扬声器声音够大，放歌看电影很舒服。\n电池5500 充电速度很快，充半个小时够一天轻度使用。\n处理器也是中等偏上的，打游戏多应用后台挂载都不卡\n小米系统、小爱同学一如既往的好用！', '幻镜', '2023-02-13 13:04:07', 8);
INSERT INTO `data` VALUES (11454, '是***-', 4, '手机已经用了一周了来评论，第一次用小米手机，看了很多的测评决定买k50，12+256双十一2169入手还送小米充电宝真的很香！一周下来体验感很好，没有卡死的情况，安全下车。处理器真的很流畅，屏幕很大很不错，打游戏超级nice！画质能开最高，运行速度很快，王者吃鸡原神都没问题，打游戏久了还是发热，会有点掉帧，不过比我上个手机的情况好。游戏杀后台感觉还是避免不了，但是不严重，我觉得是ok的。拍照的话确实一般，对于我来说也够用了，不像网上说的扫码级别那么差（最后一张图是k50拍的）。女生推荐入晴雪色，我觉得真的很好看，还是比较有质感的，看上去也不廉价，就是我的摄像头有一丢丢歪，强迫症有点难受&hellip;日常都套壳也不明显。总的来说还是很满意，使用个两三年没得问题，这个价位家人们真的可以直接冲！', '晴雪', '2022-11-10 16:30:56', 4);
INSERT INTO `data` VALUES (11455, '胡***9', 5, '充电很快，自带充电器和卡针，使用流畅，\n拍照效果：一般\n运行速度：快\n外形外观：好\n屏幕音效：清晰\n待机时间：一天\n其他特色：后壳磨砂质感，很新颖，手机挺大的', '幻镜', '2022-08-05 12:24:34', 8);
INSERT INTO `data` VALUES (11456, '黄***默', 5, '总评：性价比很高，很实惠，使用起来感觉很好，作为备用机非常完美。\n分开说。电池：够大，快充给力。不足是 耗电也挺快，可能屏幕和软件多原因，插座上必须多一套充电器了，因为其他冲不动啊。\n显示：效果非常好。玩游戏感觉自带加速 比主力机要好，至少同电话卡 运行更流畅。\n两最大优点：快捷操作特别多 而且非常实用，几乎涵盖所有人不同需求；侧面指纹解锁是真心好用啊！水果要学习学习\n最重要原因，双十一价格真给力。值得入手。', '银迹', '2022-11-17 15:32:16', 5);
INSERT INTO `data` VALUES (11457, 'j***4', 5, '很早就关注这个手机了，今年三八妇女节终于下手了，体验感满满的，颜色很好看，拍照也很赞，续航又久，手机的运行很快，一天就充一次电，用个三4年不是问，感谢京东平台，让我这么优惠价格拿下这部战机^_^^_^', '墨羽', '2023-03-09 11:03:25', 9);
INSERT INTO `data` VALUES (11458, '老***家', 5, '外形外观：时隔多年，红米手机外观还是那么好看\n屏幕音效：音质效果真的超级棒\n运行速度：刚到手玩了一下王者荣耀游戏很流畅\n其他特色：不怎么发烫了', '幻镜', '2023-02-11 22:10:53', 5);
INSERT INTO `data` VALUES (11459, 'u***z', 3, '运行有时卡顿。声效还行。', '墨羽', '2022-06-17 15:49:33', 9);
INSERT INTO `data` VALUES (11460, '删***丿', 5, '外形外观：还不错 拿着也停舒服的\n屏幕音效：2k的屏幕看着 真的舒服\n拍照效果：拍照也挺好的\n运行速度：运行速度特别快\n待机时间：5000ma待机时间也很长', '银迹', '2022-08-28 18:45:42', 5);
INSERT INTO `data` VALUES (11461, 'j***8', 5, '商品收到了，包装得很好，物流非常快，客服专业，有问题及时解答！总体来说非常满意！\n先说下几天使用感受，升级了最新系统，稳定，下了几个游戏试玩一下，运行流畅，温度适中，屏幕2k分辨率显示清晰细腻，这也是本机的一大卖点，很满意，曾经有一个小插曲，就是断网，以为中奖了，没想到尝试其他机器上网也上不去，原来是家里路由器的问题，小米的品质还是值得信赖的。', '幽芒', '2022-11-25 11:46:22', 9);
INSERT INTO `data` VALUES (11462, 'w***境', 5, '外形外观：非常完美，非常漂亮，我非常喜欢\n屏幕音效：简直完爆了，美包包\n拍照效果：非常清晰，简直堪比专业照相机\n运行速度：非常快，简直堪比宇宙飞船一样\n待机时间：一天充一次电，美爆了\n其他特色：非常顺滑，手感特别好棒棒棒', '银迹', '2022-11-03 13:30:09', 3);
INSERT INTO `data` VALUES (11463, '遇***儿', 4, '从苹果xs过度到红米，还在摸索中，整体感觉还行！第一印象不错！透明壳特别服帖，不容易进灰！像素和苹果比还是差一点，毕竟价位在这儿已经很香啦！支持国产，以后就用小米了，性价比高啊！用完一周再来追评！\n尽量多拍几张照片供大家参考！\n买了12+256，应该能用三年吧？！\n哈哈哈哈，期待好用！', '幻镜', '2022-11-04 17:09:02', 8);
INSERT INTO `data` VALUES (11464, 'L***o', 5, 'Redmi K50手机，性价比很高，天玑8100芯片，运行速度很快，2K柔性直屏，视觉效果很好，67W快充 5500mAh大电量，日常需要很放心，墨羽颜色很好看， 8GB+256GB大容量，估计用个几年没问题！', '墨羽', '2022-11-13 20:08:29', 8);
INSERT INTO `data` VALUES (11465, '天***r', 5, '均衡模式安兔兔跑分76万分左右，因为没开性能模 式跑完安免免测试手机就一点温热，可知K50在保证性 能充足的情况下在温控做的很好，打王者和平精英也是 温热的感觉。从k30买到k50，性价比很高，运行流畅，电池容量大，三星2 K屏幕，天玑8100处理器，67W快充，索尼4800万主摄，拍照还有光学防抖，相片清晰，主流配置，握在手里大小重量刚刚好。出厂自带贴膜和手机套，还有快充，到手即用。京东物流很快，不错。这价格应该是无敌的存在了！', '银迹', '2022-11-09 20:52:24', 8);
INSERT INTO `data` VALUES (11466, '宁***道', 5, '手机外观漂亮吸粉，尺寸大小合适，手感很好。屏幕是直屏的，显示效果很棒，果然还是直屏手机好。拍照效果中规中矩。内存8+256，运行流程。手机颜色很骚气。待机时间真的很不错，重度使用一天还可以再撑，毕竟是天玑8100的神U。', '幽芒', '2022-12-25 09:22:16', 7);
INSERT INTO `data` VALUES (11467, 'P***7', 5, '小米手机，从以前到现在，已经用过三款了，每一款都很好用，这款自然也不例外。\n\n真机拿在手上的时候，真的感觉很惊艳！\n\n首先要说的就是2K直屏，像素加倍，清晰加倍，3200*1440的分辨率，不管是看文字、图片还是视频，体验效果都非同凡响。\n\n再来说说大家都很关心的续航问题。\n\n5500mAh的大电量，67W旗舰闪充，充电快，续航久，使用起来，实在太棒！\n\n拍照也是买手机时，会重点考虑的一个方面。\n\n这款Redmi K50，主摄是经典的索尼4800万像素，有OIS光学防抖的加持，升级后，带来了优质的画质，对日常拍照创作都是大大的加分项。\n\n从图片可以看到，小米的这款手机，采用了全新的纳米微晶工艺，质感实在不错！\n\n有五种不同的颜色可供选择，每一款都很漂亮，最后，选择了经典的银色，外观和惊艳。\n\n很喜欢手机的NFC和红外遥控功能，自从换了这款手机后，电风扇基本全是用手机操作开关，真的很方便。\n\n现在已经用了一段时间了，使用很流畅、很快捷，看视频、听音乐效果都很棒，整体感觉十分不错哦！', '银迹', '2022-07-07 11:28:06', 6);
INSERT INTO `data` VALUES (11468, 'M***0', 5, '两千元价位，2k屏，天玑8100，快充大电池，要啥自行车啊，不玩游戏，很少拍照，这配置相当不错了，小米的系统也不错，干净，非常顺手，本想买40来着，一看就**00来块钱，还送充电宝，哈哈，优秀，用段时间追评！', '墨羽', '2023-02-11 17:48:39', 4);
INSERT INTO `data` VALUES (11469, '1***哥', 5, '大品牌值得信赖 国货精品哦 喜欢这个颜色 非常满意 手机速度也快 电池勉勉强强两天一次充电续航还可以吧 京东物流超级给力哦', '幻镜', '2022-11-15 21:04:26', 8);
INSERT INTO `data` VALUES (11470, '士***子', 5, '外形外观：外观大气，有质感\n屏幕音效：屏幕素质不错，2k屏素质很高\n拍照效果：拍照反应很快，成像不错\n运行速度：运行速度跟很快，8100神U加持\n待机时间：待机时间不错，5000毫安时电池不是盖的\n其他特色：都很不错，算是水桶机了，要是价格上能再优惠点就更完美了', '晴雪', '2022-12-28 19:46:33', 7);
INSERT INTO `data` VALUES (11471, '執***0', 5, '相当哇塞的手机，赞一个！\n在K40S和k50间徘徊了很久，终于拿下了，电池诚意满满，耐用。不卡，运行流畅丝滑，吃鸡刷新率高，分辨率清楚，相机十分牛?！\n支持小米，支持国产！支持雷总！', '晴雪', '2022-12-14 11:43:38', 7);
INSERT INTO `data` VALUES (11472, 'h***0', 5, '外形外观：颜色靓丽\n屏幕音效：屏幕清晰，毕竟是2k屏幕\n拍照效果：效果一般，满足日常使用\n运行速度：速度很快，玩的很爽\n待机时间：待机不错，可以玩很久，充电速度也很快了。出门前充个半个小时可以用个一天了', '幽芒', '2022-11-21 22:09:54', 2);
INSERT INTO `data` VALUES (11473, '脱***年', 5, '双十一期间购入，价格触底，犹豫一秒都是对不起自己。\n物流很快，隔天就送到了。整机质感很好，包装精致，配件齐全，全新机无疑。\n2k oled屏真心不错，色彩表现和亮度都非常满意。\n晴雪白上手很惊艳，配上磨砂后盖，雾隐雾现感觉。\n天机8100能耗简直逆天，配上5500大电池，续航真的顶，一天不用充电。自带67w快充，补能效率杠杠的。\n红米手机送壳送膜，这是真对消费者上心。不过还是买了钢化膜和备用壳，原膜是那种软膜，用着有点涩手，所以还是需要贴钢化膜使用。\n缺点可能就是手机边框质感不是金属，一分钱一分货，没有旗舰命不能怪厂家。', '晴雪', '2022-11-02 15:22:39', 9);
INSERT INTO `data` VALUES (11474, '蓝***8', 5, '外形外观：墨羽颜色好看，很沉稳大气\n屏幕音效：2k分辨率还有什么好说的，6.67寸不大不小，满足需要\n拍照效果：我妈一个老太太使用足够了\n运行速度：超级快，之前用的k40就很快了，k50给了更快体验\n待机时间：充电贼快，且前看耗电很合理\n其他特色：性价比真的很高了，老妈满意', '墨羽', '2022-04-16 10:55:33', 8);
INSERT INTO `data` VALUES (11475, 's***w', 5, '双十一最大的收获，观感很好(?▽?)操作丝滑，反应灵敏。运行飞快(●&deg;u&deg;●)?&nbsp;」很满意的一次购物。新一代神机，可以用个好几年(?▽?)。非常划算。拍照清晰。运行寄流畅。屏幕清晰，养眼。', '银迹', '2022-11-18 18:28:50', 8);
INSERT INTO `data` VALUES (11476, '给***铁', 5, '这款小米Redmi K50手机挺好的，做工用料足,老牌子的！小米K50性价比也还可以的。我觉得小米Redmi K50真的好的，外形外观：完全符合高端游戏手机的调性，我拿来做平常工作手机用，完全没有任何违和感。屏幕音效：屏幕没有评测中和视频中说的那么不堪，完全够用拍照效果：实测工作中记录文档等完全没问题，甚至有点超出预期。运行速度：飞快，不管是指纹面部解锁运行速度，都飞快，超出你的想象。待机时间：5500毫安时电池，目前不打游戏可以支撑两天。但是充电发热和玩游戏发热这是游戏手机通病。打游戏需要加个散热器。其他特色：各种针对游戏的优化非常全面，各种配件绝对都是用心思了。总体来说价格还是比较划算的，而且有优惠券的，入手还是可以的哦！！', '墨羽', '2023-01-20 14:46:42', 3);
INSERT INTO `data` VALUES (11477, 'l***_', 5, '外形外观：外观很时尚靓丽，特别是这墨羽色，做的真不错，很有辨识度。\n\n屏幕音效：2k的屏幕，小时效果真的一级棒！\n\n待机时间：拥有5500毫安的大电池，妈妈再也不用担心我手机没电了！\n运行速度：新机很流畅，上手很丝滑很赞。', '墨羽', '2022-03-29 17:17:58', 6);
INSERT INTO `data` VALUES (11478, 'C***9', 5, '很喜欢很满意 京东物流速度超级快 京东服务给力 大品牌值得信赖这个值得推荐 运行速度快到起飞 给力给力好评', '幻镜', '2022-11-12 21:00:27', 8);
INSERT INTO `data` VALUES (11479, 'j***t', 5, '外形外观：外观很不错，高端大气，全新无任何划痕。\n屏幕音效：2k分辨率三星屏，120hz高刷，体验非常不错。\n拍照效果：摄像头没问题，能扫码就行。\n\n运行速度：12g运行内存，随便开软件挂后台不带卡顿的。\n\n待机时间：5500大容量，待机超强!可以刷10小时视频。', '银迹', '2022-11-11 23:55:57', 2);
INSERT INTO `data` VALUES (11480, 'H***R', 3, '给老公买的，应该还可以吧，平时用用', '幽芒', '2022-06-16 23:55:48', 2);
INSERT INTO `data` VALUES (11481, '熟***e', 5, '昨晚下单，今天就到了，物流这方面很赞，打开用了一会使用流畅，值得入手，充电也好', '墨羽', '2023-01-19 20:47:00', 7);
INSERT INTO `data` VALUES (11482, '古***j', 5, '手机用了1个多月了，没有发现问题，使用起来非常流畅，没有卡顿，相机非常不错，67w充电速度快，外观漂亮，性价比很高。买家服务质量好。', '墨羽', '2022-12-22 17:32:28', 8);
INSERT INTO `data` VALUES (11483, '许***亮', 5, '用了机子几天了，感觉很不错，速度很快，?双十一终于对它下手了，颜值是真的没话说?，物美价廉。\n拍照效果：效果不错，很清晰。\n外形外观：比较厚重，沉稳。\n运行速度：运行速度很快，流畅不卡顿。\n屏幕音效：音效很好，杜比音效。', '墨羽', '2022-11-04 14:26:04', 6);
INSERT INTO `data` VALUES (11484, 'j***7', 5, '给老妈买来用的，速度快，屏幕清楚，操作简便，很喜欢！\n外形外观：黑色永远的经典\n屏幕音效：老妈用，声音效果极佳\n拍照效果：老妈出游风景图片颜色很舒适保真\n运行速度：很快，比旧的手机快好多\n其他特色：外观高大上适合老年人用', '墨羽', '2022-12-22 17:55:19', 7);
INSERT INTO `data` VALUES (11485, '从***夭', 5, '外形外观：颜色喜欢\n待机时间：一天是没问题的，最满意的是充电速度很快，大概半小时充满，不用用电焦虑了\n\n这个价位这个配置可以了，对我来说够用了，高性价比', '幻镜', '2022-07-05 18:54:11', 8);
INSERT INTO `data` VALUES (11486, '本***纽', 4, '外形外观：一看到这个配色想都没想就下单了，真的是那种有内涵的美，摄像头星环设计，方形与圆形的对撞设计，辨识度非常高，也很有设计感。手机201g重量适中，配合外形久持也不累，玻璃机身的握感与触感极佳，指纹的位置不会误触，使用方便\n屏幕音效：这块屏幕支持1.6万级自动亮度，环境色温感应、杜比视界、HDR10+、P3色域、色彩很不错。2K屏显示效果真的比1080p的手机细腻很多，峰值亮度1200nit，亮度也够高，日光下完全没问题，高刷浏览文字视频都觉得很流畅\n拍照效果：主摄1亿像素，imx586调教还可以，拍照的时候真的特别清晰，还有光学防抖。前置摄像头也完全不差，自拍照也要美美哒\n运行速度：天玑9000旗舰处理器，高性能低功耗，日常应用速度的提升不是一星半点，VC液冷散热，中度使用都不会觉得热。5G+WIFI6，上网十分流畅\n待机时间：电池容量为5000mAh，中度使用一天一充没问题。单电芯，快充提升至120W，大概30分钟就可以充满，充电够快\n其他特色：其他特色：Dolby A**os立体声双扬声器，音效的感知超强。X轴线性马达和多功能NFC、防水防尘、红外遥控都没有缺席，小功能超级实用。侧边指纹+人脸识别，解锁基本无感。康宁大猩猩的玻璃特别抗划，防摔也', '银迹', '2023-01-08 20:02:07', 6);
INSERT INTO `data` VALUES (11487, 'j***f', 5, '小米k50价格优惠，物美价兼，很实惠的手机，好用实惠。待机时间长，性价比很高\n外形外观：很漂亮\n屏幕音效：很好\n拍照效果：很好\n运行速度：快', '银迹', '2022-11-10 20:18:48', 4);
INSERT INTO `data` VALUES (11488, '耀***2', 5, '外观颜值整体在线，后盖看着很亮 。2K的屏幕，120赫兹的刷新率，显示效果杠杠的!双扬声器音质也不错，音量挺大。支持多种拍照功能，日常使用完全没有问题。运行速度很快很流旸。', '幽芒', '2022-11-10 11:57:41', 2);
INSERT INTO `data` VALUES (11489, 'j***y', 5, '联发科 天玑8100 5**制程处理器，发热量低，三星2K（3200&times;1440） AMOLED屏幕细腻，偏灰一点点。\n给妈妈买的，之前妈妈用我的K20 PRO，我觉得应该给妈妈弄个新手机，大电池，大音量。老人家，拍照，快充不是最重要的\n她很喜欢，待机时间也长呀。我家有好多个小米，红米手机了。', '银迹', '2022-03-31 23:57:32', 6);
INSERT INTO `data` VALUES (11490, 'R***6', 5, '从小米1一直到小米MAX3,用了很多款小米手机，现在手上的max3用了4年多，6+128的组合日常足够，但Redmi K50 天玑8100 2K柔性直屏 OIS光学防抖 67W快充 5500mAh大电量 墨羽 12GB+256GB 这样的配置组合以及双十一活动是在太诱人，换！拿到手里，速度，屏幕，摄像都很满意，不怎么玩烧机游戏，就是日常用，很满意。朋友说日常用，这配置，太奢侈，没办法，喜欢！这几天突然从max3到k50，除了屏幕大小适应一下，别的都是质的飞跃。', '墨羽', '2022-11-03 05:57:03', 9);
INSERT INTO `data` VALUES (11491, '仙***宝', 5, '外形外观：白色后壳是磨砂，减少指纹，配色简洁大方。\n屏幕音效：2k屏体验确实不错，画面色彩细腻，音效很好。\n运行速度：天玑8100的心脏应该不错，买来给妈妈用应该可以多用一点时间。', '晴雪', '2023-01-23 13:07:27', 2);
INSERT INTO `data` VALUES (11492, 'R***1', 5, '外形外观：外观其实还算中规中矩，老年人用，很合适\n屏幕音效：2K屏幕 120Hz 效果是真的很棒，简直就是一大亮点\n拍照效果：对拍照我历来不是很高的要求，能用就行\n运行速度：12Gb 内存还是很快的，不过现在的安卓还是很迟内存，\n待机时间：待机相当棒，多亏这颗8100的CPU\n其他特色：67W的快充也特别棒。特别适合老年人。', '银迹', '2023-01-14 23:58:43', 6);
INSERT INTO `data` VALUES (11493, 'u***1', 5, '外观很漂亮，音质还蛮好的，声音也挺大的，各种操作也灵敏度很高。拍照出来的像素相片看起来还很清楚。运行内存挺快的，开几个应用没有卡顿，大内存存储多。耗电一般吧，也不算快，充电速度快。', '幻镜', '2022-11-30 10:03:14', 6);
INSERT INTO `data` VALUES (11494, '果***福', 5, '外形外观：非常漂亮，手感挺好。\n屏幕音效：双扬声器，音质不错。\n拍照效果：4800万，拍一张照片20m 很高清。\n运行速度：高刷新120   12+3运行完美。\n待机时间：待测试。\n其他特色：最新系统，一点不卡顿。', '墨羽', '2022-06-27 20:43:16', 2);
INSERT INTO `data` VALUES (11495, 'j***w', 5, '?种草官亲测：值得推荐\n??下面种草官通过这段时间的体验通过一份体检报告带你从外观颜值、使用体验、带电时长、芯片表现来直观讲述自己的亲测感受。\n报 告 单\n?姓名：红米K50 \n?颜值：幻境 \n??体重：8G+256G\n?五官：120HZ?2K\n?&zwj;??诊断结果：\n首先从颜值来说，刚打开盒子的时候，背板的颜值直接让我沉醉，和它的名字幻境相辅相成，玻璃材质背板虽然会沾指纹，但是真的很好看\n科室：内科\n?心脏：天玑8100\n?&zwj;??诊断结果：\n处理器用的是天玑8100，在这个价位，这款心脏非常强大，因为手机是给妈妈买的，不打游戏，但是处理办公绝对够用了。\n?我相信你看完这一份体检报告，对于红米K50有了很深的认识。\n??总结：购买手机一定要明白自己的需求，如果只是单纯追求划算，那么你就会买来一堆用不上的数据。在这个价位，这款手机十分抗打，适合母亲的使用环境。', '幻镜', '2022-12-11 22:38:18', 7);
INSERT INTO `data` VALUES (11496, 'j***6', 5, '屏幕高清，色彩挺好。音质一般，低音不够，偏高音。拍照效果光线强时，很棒，暗光一般，防抖很好，色彩还算真实。运行速度很快。充电快，充满后待机时间长，玩游戏，不错!赞?，屏幕有支架，套上壳好些!目前用着不错!推荐购买。期待一如既往!', '银迹', '2023-01-10 17:53:50', 1);
INSERT INTO `data` VALUES (11497, '小***O', 5, '红米手机还是第一次购买，买给家人，屏幕够大，操作方便，安卓手机反应很快，比想象中的要好操作，家人很满意，值得购买。\n外形外观：方方正正，纯全屏。\n屏幕音效：用手机听了qq音乐，音质不错。\n拍照效果：拍照好像没有自带美颜，哈哈哈，但是清晰度较强，像素够用。\n运行速度：运行很快，家人用完全够。\n待机时间：充电超快，很快就能充满。', '幻镜', '2022-12-24 19:06:07', 1);
INSERT INTO `data` VALUES (11498, '淳***哦', 5, '我觉得很好，很轻，自带贴膜和外壳，运行速度很快，拍照可以，声音一般，3000以内性价比很高。颜色我选择白色，白色黑色还是经典，选12+256的，今年这是流行配置了。', '晴雪', '2022-11-19 21:45:08', 6);
INSERT INTO `data` VALUES (11499, '京***官', 5, '在真我和小米中，最终选了K50，到手着实真香啊，屏\n幕1.5K屏，清晰度一流，续航非常好，一次电，两天随便\n用，充电半个钟就充满了，打游戏清晰顺畅。', '墨羽', '2022-11-17 16:05:03', 6);
INSERT INTO `data` VALUES (11500, 'u***d', 3, '速度还好，就是有时候看视频会卡屏', '墨羽', '2022-06-03 12:24:34', 7);
INSERT INTO `data` VALUES (11501, '嘉***巴', 5, '外形外观：6.7英寸大屏，三星2k分辨率，比较大气\n屏幕音效：2k分辨率，显示比较清晰。很不错的一块屏幕\n拍照效果：拍照算得上中规中矩吧，只能说勉强够用吧\n运行速度：比较流畅，很满意的一次购物。', '晴雪', '2023-01-12 20:20:33', 2);
INSERT INTO `data` VALUES (11502, '杨***洋', 5, '拿到手试用了一下，非常流畅，续航能力也很强，以前一直用苹果手机，后来发现还是安卓系统支持的功能多，很多软件在苹果手机不支持，只想说安卓系统yyds。现在国产手机崛起了，做的越来越好，支持国产机！', '墨羽', '2023-01-02 20:39:52', 3);
INSERT INTO `data` VALUES (11503, '一***h', 5, '以前一直以为天机不太行，真正用才发现贼优秀，比高通骁龙处理器用着还流畅，异常丝滑，老米粉了，就想说一下小米的手机助手比华为的难用啊，只有整体备份功能，不像华为的可以直接在电脑上整理手机里的东西，这个真的太方便了。看网上评论说什么塑胶质感的，我觉得银色挺好看，而且膜都给贴好了，还配了透明硅胶手机壳，这个太赞了啊，都不用自己买了。这是一款让我毫不犹豫下单的手机，能兼顾性能的同时还能保持较低的能耗，这一点就非常吸引人了，8100+2K屏+5500大电池，然后2399起步的价格，我只能说，这波红米站在大气层上，简直是无敌的好吗，选的墨羽，但去小米之家看了，感觉墨羽太压抑了，拿到真机后只有一个感觉，选对了！真的超级漂亮！价廉物美，质量挺好，运行速度特快，摄像拍照都很清晰，以前用过各种品牌手机，这次也比较满意的。我家大型电器基本都是京东自营店购买的，京东自营的产品就是好。以后还会继续购买京东自营产品，推荐同事朋友。8100性能很强，吊打高通全家。显示效果也非常好，电池非常大，一整天不充电毫无压力。后盖质感稍逊，整体还算轻薄。很好的购物体验。屏幕和充电比上一代有了很大提升，尤其是屏幕的2K分辨率，比现在很多旗舰手机都要强', '墨羽', '2022-12-07 20:53:57', 9);
INSERT INTO `data` VALUES (11504, 'j***T', 5, '质量很好 手感也不错\n外形外观：顺手\n屏幕音效：三星屏幕杠杠的\n运行速度：处理器很不错的\n待机时间：续航超高 而且充电67w一会就满电了', '幻镜', '2023-02-18 03:34:17', 6);
INSERT INTO `data` VALUES (11505, 'j***t', 5, '收到了，做为礼物?送出的，看起来不错，值得推荐，继续努力，加油吧&hellip;&hellip;\n外形外观：漂亮\n屏幕音效：很好\n拍照效果：精美\n运行速度：快\n待机时间：长', '幻镜', '2023-01-31 18:05:34', 5);
INSERT INTO `data` VALUES (11506, 'L***寒', 5, '外形外观：很好看，虽然是塑料中框但手感还能接受\n屏幕音效：屏幕更清晰！杜比音效很赞\n拍照效果：还不错，没有网上说的那么拉胯\n运行速度：很快\n一直都很喜欢小米的手机，观望了一段时间果断入手，性价比高！镜头没歪，放心入手！推荐！', '幽芒', '2022-07-08 11:12:34', 6);
INSERT INTO `data` VALUES (11507, '我***了', 5, '性价比很高，是正品，很薄，性能好，屏幕很高端，用着很快，相机也很牛，音响效果也很不错，速度很快，很满意，充电快，已经用上了', '墨羽', '2022-10-04 19:37:02', 6);
INSERT INTO `data` VALUES (11508, 'H***0', 4, '小米红米系列性价比特别高，天机8100处理器不比同档次的高通差！而且很省点，发热量特别低！拆开新机后有百分之6电量，用了很久，居然还有百分之30，重度使用用一天半没问题！屏幕高刷120而且是3200的分辨率，特别细腻，6瓦的充电器，两千多，很实惠好用！比肩主流旗舰机的效果，另外侧肩指纹按键特别方便又创意！这次都买了幽茫绿的外观！很时尚！特别满意', '幽芒', '2022-07-28 11:46:13', 6);
INSERT INTO `data` VALUES (11509, '路***尔', 4, '一款不错的备用机，体验感满满，小米值得信赖，使用起来很丝滑，不差于现在手上的主用机器iPhone13，体验感满满，是一次愉快的购物', '幻镜', '2022-11-20 12:35:23', 5);
INSERT INTO `data` VALUES (11510, '小***炮', 5, '找了好久找到这个备用机，双十一活动比较优惠，拆盒之后这个背面的花纹挺惊艳的，特漂亮可惜买了手机壳要被盖上，原机赠了一个透明的壳子，新上手速度挺好的，手小的话，加上手机壳拿着有点笨重，总体这个价位很满意', '墨羽', '2022-11-11 10:18:26', 4);
INSERT INTO `data` VALUES (11511, 'j***a', 5, '外形外观：晴雪配色非常时尚漂亮\n屏幕音效：双扬声器，打游戏看电影都能带来不错的体验\n拍照效果：4800万像素对于我来说够用了\n运行速度：打开多个软件依旧很流畅\n待机时间：67w快充加5500毫安电池续航很不错。', '晴雪', '2022-11-08 16:28:09', 2);
INSERT INTO `data` VALUES (11512, '飞***伶', 5, '用了两天，k50的性价比很高，各方面的硬件配置都对得起这个价格。就是牺牲了外壳材质，所以来到了这个价位。\n把钱堆在性能更好一些的硬件上最实在了。\n屏幕非常清晰，这个分辨率加上高刷，体验是非常不错的，但是常开着耗电问题也比较明显，前面20%电量掉的比较快，不过一天用下来问题也不是很大。8100的芯加上12G也能满足日常大部分需求，还是很流畅的，玩游戏非常爽！米13的系统，对隐私是非常重视了，这点做的挺好的！总体上还是挺满意的，值得拥有！', '墨羽', '2022-11-20 04:03:23', 6);
INSERT INTO `data` VALUES (11513, '娟***儿', 5, '颜色很好看，2K的分辨率真的很清晰，很喜欢，颜色也不单调，4800万像素，特别清晰，完全够用，启动快，开机快，多开应用也不卡，很不错，充电速度也快', '墨羽', '2022-11-22 09:44:09', 3);
INSERT INTO `data` VALUES (11514, '谌***风', 5, '趁着双十一，预定买了号称性价比小钢炮的红米k50，12+256银迹版本，性能来说足以应付各种场景了，手机做工也对的起这个价格，2k屏幕非常的细腻清晰，加上高刷对眼睛也非常友好，5500ma的电池一天一冲，有67w的快充基本能保证手机随时在线，国货当自强，支持小米！', '银迹', '2022-11-29 21:32:15', 8);
INSERT INTO `data` VALUES (11515, '从***干', 5, '外形外观：外观非常喜欢，非常不错\n屏幕音效：双扬声器真的很动听，声音也很大，清晰！\n拍照效果：拍照很棒！成像速度很快！旗舰机水平！\n运行速度：运行很快！\n待机时间：待机很久！', '墨羽', '2022-05-14 18:37:48', 9);
INSERT INTO `data` VALUES (11516, 'd***2', 5, '关注K50很久了，终于在双十一下手了，看中它的高性价比，虽不是最低价，但也是很实惠了！\n外形外观：外观设计很漂亮，简约大方，墨羽配色，看起来很高级\n屏幕音效：双喇叭配置，音效特别好，2K屏看起来很细腻\n拍照效果：比较一般\n运行速度：8100处理器性能强大，运行流畅\n待机时间：待机时间长，重度使用一天一充。', '墨羽', '2022-11-17 00:54:22', 2);
INSERT INTO `data` VALUES (11517, '3***垂', 5, '外形外观：晴雪白色简约时尚\n屏幕音效：6.67/2K屏杜比全景声很震撼\n拍照效果：我不拍照日常扫码4800万够用了\n运行速度：12+256大内存运行流畅\n待机时间：正常水平\n其他特色：冬天游戏不发热不知道夏天怎么样', '晴雪', '2023-01-20 14:47:58', 2);
INSERT INTO `data` VALUES (11518, '凌***咩', 5, '外形外观：中规中矩，镜头存在感略强，侧边指纹解锁无感\n屏幕音效：2k屏效果不错，如果是第一次接触会好感度翻倍\n拍照效果：尚可，日常生活拍照没有特别的感觉\n\n运行速度：作为备用机，日常操作无感\n待机时间：轻度使用，无感\n其他特色：便宜', '银迹', '2022-12-13 21:59:13', 5);
INSERT INTO `data` VALUES (11519, '糖***林', 5, '外形外观：银色比较商务，拿在手里较厚实，质感不错。\n屏幕音效：屏幕很丝滑，显示清晰，可以手动选择高刷和2k高清。\n拍照效果：拍照日常生活够用。\n运行速度：8100处理器运行速度杠杠的。                 总体评价:先表扬一下京东送货速度，十八线小县城隔天就到了手机性价比高，物超所值，满足日常使用，厚度上控制在8mm以内外观上就更优秀了，很满意，nice！', '银迹', '2022-03-23 11:08:11', 6);
INSERT INTO `data` VALUES (11520, '阿***妹', 5, '外形外观：大气上档次\n屏幕音效：质感不错\n拍照效果：效果还可以\n运行速度：这就很强了，游戏一点不卡\n待机时间：超级省电，待机很强\n其他特色：总结，弟弟很喜欢，开心极了。。。', '银迹', '2022-03-27 11:55:40', 4);
INSERT INTO `data` VALUES (11521, 'k***j', 5, '这么便宜的手机，功功能竟然这么全面，性价价比超高，\n不愧是小米，重要的是尽然比官网还要便宜些。挺\n满意的，手感也好，功能强大，反应还是快，找到设\n置，字体换成超大，老妈不会再说字小了，实在不\n行就巨无霸？8弄了ー首家乡美做为铃声，够\n响亮，没破音杂质。微信以后可以和我们视频了\n配置完全够用了', '银迹', '2022-11-06 18:18:04', 2);
INSERT INTO `data` VALUES (11522, 'W***8', 5, '手机外观设计精美，8+256G大内存，上网速度特别快，后配置4800万超清相机，5500毫安大容量电池。已经用过一段时间了，效果不错?，客服服务有耐心，解答详细，整体体验效果非常满意。', '墨羽', '2023-02-26 15:00:33', 6);
INSERT INTO `data` VALUES (11523, 'i***n', 5, '手感很不错，墨羽在阳光下面很漂亮。系统也很丝滑，拿到手就升级了MIUI14.可以删除很多软件。给老爸买2k屏保护眼睛，看得清楚。', '墨羽', '2023-02-26 22:48:32', 6);
INSERT INTO `data` VALUES (11524, '孤***7', 5, '入手三天才过来评论的，使用手感不错，系统非常流畅，屏幕显示效果不错，电池容量挺大，总体来说比较满意，物流也很快，服务态度也很好，看好京东。', '晴雪', '2022-11-07 09:49:57', 5);
INSERT INTO `data` VALUES (11525, 'j***8', 5, '想换个手机，在商场搜了半天，最终确认买了这台小米K50。京东快递很快送达，立即拆箱，手机手感不错，已贴膜，还配送了水晶套。开机后，简单几步注册进入系统，手机的屏幕清晰艳丽，非常漂亮，菜单反应很快，智能手势非常好用。手机内存容量充足，能用很长时间了，摄像头效果也很满意。总体来说，这是一款性价比非常高的手机，值得购买！', '墨羽', '2022-11-04 20:46:12', 6);
INSERT INTO `data` VALUES (11526, 'u***4', 5, '屏幕清淅，反应非常快，音质量很好，但是摄像头上面的喇叭音量大时有点沙沙的杂音，电池非常耐用，最少可以用两天，照相还是很清淅的，赶在618活动时以2559元购得12+256G的，总结这个手机还是非常好的！', '幽芒', '2022-07-19 12:27:50', 7);
INSERT INTO `data` VALUES (11527, '六***沟', 5, '小米手机很好。心仪已久，果断下手，用过之后感觉很不错，是正品，快递也很给力，果然名副其实。宝贝收到了，很惊喜，质量非常好，很满意的一次购物。大品牌值得信赖，大爱，大赞', '幽芒', '2022-12-27 23:54:35', 8);
INSERT INTO `data` VALUES (11528, 'M***粒', 5, '这手机颜值没的说 很漂亮 手感也很棒 这个颜色真的是太爱了 电池容量也够用 内存也够用 电池更是没话说 玩游戏杠杠的', '墨羽', '2023-01-05 22:07:58', 6);
INSERT INTO `data` VALUES (11529, '板***3', 5, '过年给妈妈买了RedmiK50 12+256G新手机，2K OLED直屏，天玑8100超强处理器，5500mAh大电池，67W快充，索尼4800万像素OIS光学防抖，2000出头一点的价格，老人家妥妥的用三年木有问题。Redmi真的是性价比之王，这个价格给到这个配置，诚意满满，向卢伟冰致敬', '晴雪', '2023-02-05 19:49:32', 6);
INSERT INTO `data` VALUES (11530, '小***威', 5, '外形好看，白色的看起来不那么具有塑料感，待机续航杠杠的，重度一天很轻松，充电速度也很快，50分钟就饱了，拍照完全够用，性价比杠杠的，8100速度起飞?', '晴雪', '2022-11-12 21:39:07', 6);
INSERT INTO `data` VALUES (11531, '江***彩', 5, '很喜欢，屏幕很清晰。配色也很好看，中端神U是真的温润。大内存很够用，重回miui久违了老伙计。活动也很给力，而且是11月刚生产出厂的，特别新。五星好评，值得拥有', '晴雪', '2022-11-16 21:01:48', 6);
INSERT INTO `data` VALUES (11532, '邢***2', 5, '外形外观：整体还是可以的，墨羽色还怪好看的\n屏幕音效：屏幕不错，杜比音效都可以\n拍照效果：日常绝对够用\n运行速度：很流畅，自己用着可以\n待机时间：一整天够用\n其他特色：系统还是比较好用的', '墨羽', '2023-02-03 19:24:47', 2);
INSERT INTO `data` VALUES (11533, 'j***q', 5, '外形外观：外形外观：外形漂亮，外观很满意， 非常完美！\n屏幕音效：屏幕音效：非常满意！ 非常喜欢！\n拍照效果：拍照效果：非常清晰！ 非常不错\n运行速度：运行速度：速度快！ 非常满意！\n待机时间：待机时间长，足够用！', '墨羽', '2023-02-26 16:19:44', 5);
INSERT INTO `data` VALUES (11534, 'j***5', 4, '屏幕显示效果真的很好，不过1080p和2k真的看不出来什么差距，可能的上专业设备才能看出来，音效可以，听了两首歌曲感受了一下，开机就提示了更新，有图片为证，家里面有好几台小米手机了，这台k50很惊艳，颜色和外观设计也是纠结了好几台选择了幽芒，拍照效果也没有外界说的那么垃圾真心话，日常使用完全可以了，不能跟4-5千的旗舰机相比，充电速度还没有试，后续再追加评论', '幽芒', '2022-04-01 20:51:09', 6);
INSERT INTO `data` VALUES (11535, '爱***国', 5, '外形外观：时尚潮流，年轻十足\n屏幕音效：屏幕大，音效好\n拍照效果：很清晰，很不错\n运行速度：运行很快，打游戏很6\n待机时间：一天是没有问题的', '幻镜', '2022-11-18 17:34:47', 4);
INSERT INTO `data` VALUES (11536, 'b***1', 5, '包装完整整机流畅，自带磨盒，后壳激活是新机电量正常使用，一天一充没问题，而且是快充，屏幕反应快，清晰性能够优，价格在京东年货节百亿补贴真的是超级划算\n在京东首页搜索?&ldquo;恭喜发财244&rdquo;领800神卷后1499入手', '墨羽', '2023-01-11 09:51:30', 4);
INSERT INTO `data` VALUES (11537, 'j***D', 5, '外形外观：线条流畅\n屏幕音效：听歌音质很好\n拍照效果：清晰\n运行速度：一个字：快\n待机时间：一整天玩手机不用充电', '幽芒', '2023-02-16 07:22:11', 5);
INSERT INTO `data` VALUES (11538, 'j***x', 5, '颜值高，性价比高，喜欢！\n外形外观：沉稳不失档次\n屏幕音效：炫丽，夺目\n拍照效果：好，好，好\n运行速度：牛，牛，牛\n待机时间：待观察\n其他特色：墨羽款真的不一般', '墨羽', '2023-02-02 12:28:43', 4);
INSERT INTO `data` VALUES (11539, '是***吖', 5, '外形外观：方方正正的，边框过渡自然，比小立变手感好。\n续航：67w充电?5500mah的大电池，轻度使用一天没问题。\n屏幕音效：6.67寸2k120hz屏幕，文字显示精细度好，杜比双扬声器听音乐很不错。\n拍照效果：只能扫码的水平。\n其他特色：白色真的是yyds，而且还是磨砂白，简直太棒了！', '晴雪', '2022-11-04 23:04:26', 5);
INSERT INTO `data` VALUES (11540, '般***蜜', 5, '手机还得买小米的，买过华为，买个一加，买过真我，还是小米比较习惯，有些小功能很需要，比较智能，\n这次的k50也超级棒，照片清晰，屏幕清晰，玩起游戏来没有网传的那么烫，那么卡，体验感极高！\n黑色的一点也不单调，特别舒服', '墨羽', '2022-11-16 09:17:13', 5);
INSERT INTO `data` VALUES (11541, '慢***看', 5, '手机618买的，加上支付优惠2420左右到手，到现在用着很好，电池比较给力，本人空闲时间比较多，基本够我一天使用。本来想买K50pro，因本人不玩游戏，对其他功能也没追求，选择了K50 12+256，手机完全够用，比较满意。', '银迹', '2022-08-02 19:03:10', 3);
INSERT INTO `data` VALUES (11542, '卡***通', 5, '流畅，酷炫。外壳做工要求不高！好机，好机！2k价位性价比无敌。miui14优化很好，赞', '墨羽', '2023-02-10 17:55:16', 4);
INSERT INTO `data` VALUES (11543, '罐***-', 5, '使用了一个多星期了，MIUI13的系统非常的流畅丝滑，2K屏非常赞，刷视频打游戏画质都贼高的，天玑8100的处理器打游戏没有之前的骁龙处理器手机烫手了，配色推荐我这款幻境色，非常的nice。', '幻镜', '2022-05-07 16:53:13', 7);
INSERT INTO `data` VALUES (11544, 'j***g', 5, '小米手机非常好用，性价比非常高。双11抢的。优惠很大。性能很好。显示很清楚。反应很快。充电很快。67w快充。电池容量很大。非常满意一款手机。', '墨羽', '2023-01-06 10:43:36', 6);
INSERT INTO `data` VALUES (11545, 'Z***7', 2, '红米K50使用体验 不知不觉这台红米K50已经用了很久了，这么长时间一直作为我的主力机使用。 首先它的这块屏幕我认为是挺不错的，2 K分辨率，在观感上真的比普通的1080P清晰很多。同时还支持DC调光，在夜晚能降低屏幕闪烁。 在这么长的时间里我用它玩游戏、看视频，以及日常使用，它的性能都是很足够的，而且发热量也不大，体验感上是很不错的。 它的续航给我的感受也是相当给力，毕竟电池很大有5500毫安，一整天用下来都没啥压力可以。 最后我来说下不是很满意的拍照。成像效果比较差劲，尤其是光线不好的时候，画质很糊。', '银迹', '2022-10-12 19:24:44', 5);
INSERT INTO `data` VALUES (11546, '锦***鱼', 5, '赞一个，已经使用了半个月回来评价。512版本的好像就618时候发出几天货，而且确实便宜几百，之后的大半个月都处于缺货状态，颜色没得挑，三种配色，哪个有货就买哪个，他库存不定时更新。\n说说使用体验，首先拍照，对我来说够用，扫码很快，没有别人骂的那么拉。\n系统方便很流畅，本人之前使用鸿蒙和ios系统，拿到miui适用了三天，摸索，设置那边每个都去点一下，现在基本完全适用了，总体上，系统挺好用，功能比前面两个系统更丰富，而且还很流畅。\n屏幕素质确实顶，非常ok。\n个人感觉槽点之一就是侧边指纹，好用是好用，解锁速度很快，但是经常误触，手机放在口袋里，伸手进去拿出来的那个过程，经常连续误触，看看如何平衡一下吧。\n整体的手机体验，挺好的，值得购买，特别是8100这个芯片，吹爆。', '墨羽', '2022-07-04 13:12:21', 5);
INSERT INTO `data` VALUES (11547, 'G***龙', 5, '外形外观：棒棒的。\n屏幕音效：效果很好，细腻，\n拍照效果：完全够用。\n运行速度：看中大内存，大存储，高性价比，\n待机时间：一天够用了，快充给力。\n其他特色：总之性价比很高。。。', '银迹', '2022-11-21 08:03:38', 4);
INSERT INTO `data` VALUES (11548, '奥***派', 5, '我买的这台是红米K50 标准版，因为大家都知道，某8系列处理器这两年的表现确实有点不太如意。而刚好这个时候联发科开始发力，天玑1200、天玑9000和天玑8100 在网络上的口碑都很好，作为天玑8100的全球首发机型，那就必须试一试了。\n这个处理器也带来了 85万的高分，而且在高负载情况之下，天玑8100同样可以保持&ldquo;冷静&rdquo;，不会出现太过分的发热。红米也在这款手机上用上了非常大面积的 VC液，冷散热散热面积达到了 3950mm。\n屏幕用的是直屏，显示效果看起来确实不错，在打开2K\n显示之后，文字清晰度有明显提升。同时本身是一块三星的原色屏，所以说在色彩显示和还原上也非常不错。\n刷新率也是有 120Hz的，这也算是如今安卓中高端机的标配。\n电池容量居然做到了 5500 毫安时，这款手机在67瓦的快充加持之下，电池容量还做到了 5500毫安，实在是让人很安心。\n相机方面最大的开级是加入了 OIS 光学防抖，之前我也吐槽过红米没有光学防抖，这次全系都用上了。拍照效果也提升了不少，很容易就能出片。', '银迹', '2022-11-11 14:54:05', 4);
INSERT INTO `data` VALUES (11549, '脸***z', 5, '用了快一个月了，才回来才写评价。。\n外形外观：外观太漂亮了，背面的裂纹处理很巧妙。\n屏幕音效：屏幕清晰流畅，颜色也很饱满。\n运行速度：工作用手机，也不玩游戏，特别快！', '墨羽', '2022-07-19 22:31:15', 2);
INSERT INTO `data` VALUES (11550, 'l***g', 5, '买的12+256，出厂自带贴膜和透明手机壳，有息屏显示功能，侧面指纹解锁也很方便。2K屏幕的效果的确非常赞，各种操作运行非常流畅，打吃鸡无压力。电池很大，一天基本够用，67W快充的速度嗖嗖的，感觉没必要更快了。相机效果还可以吧，平时用的最多的就是扫码，要求不高。总之这个价位的性价比非常高了', '墨羽', '2022-05-06 01:30:25', 9);
INSERT INTO `data` VALUES (11551, 'l***7', 5, '屏幕音效：屏幕很清晰\n运行速度：满足老人使用，没问题\n外形外观：老妈很喜欢', '银迹', '2022-12-26 12:21:41', 3);
INSERT INTO `data` VALUES (11552, '曹***4', 5, '外形外观:很漂亮尺寸大小:刚好。音效:很棒,视频模式自动开启杜比音效，看电影追剧特别爽，5500的大电池，真的待机时间超长，重量，也刚好,不压手，天玑8100,打起游戏很舒服,物流也特别快，性价比很高，很实惠，使用起来感觉很好,非常完美.^J^.', '幻镜', '2022-12-12 21:03:00', 4);
INSERT INTO `data` VALUES (11553, '周***a', 5, '一开始就是冲着k50来的，这个价位的手机，k50简直无敌，屏幕显示效果特别好，2k果然名不虚传，打王者可以开120帧，很流畅，电池也很耐用，充电也很快，系统优化更新速度很快，Bug修复及时，很不错的一款手机，强力推荐！！！', '幻镜', '2022-11-25 20:04:24', 5);
INSERT INTO `data` VALUES (11554, '马***1', 5, '好用！屏幕蛮大的，手机不是很重，手感很好，快充是相当的给力，摄像头是凸出来的，需要好好保护，我想说的是120HZ简直绝绝子，如丝般顺滑，比德芙还要丝滑，电池也很够用，睡前充一波，一整天都不用充。', '墨羽', '2022-07-18 22:14:45', 2);
INSERT INTO `data` VALUES (11555, 'j***m', 4, '首发预定的k50最低版，下午收到货，京东物流很快。手机显示很清晰，天玑8100一点都不热，但好像反应上比天玑9000差一点，毕竟天玑9000单核性能超了40%。。。手机显示很清晰，摄像头够用。安装软件很快，以前的小米8可以作为备用机了!', '幽芒', '2022-03-22 19:14:27', 7);
INSERT INTO `data` VALUES (11556, '树***8', 5, '外形外观：外观非常漂亮，比原来手机轻一些。\n\n屏幕音效：2K屏很nice，DC调光也都有\n拍照效果：还可以吧，有光学防抖，传感器够用\n运行速度：很流畅，不卡，打视频再也不发热了\n待机时间：续航可以的，打一晚上游戏毫无压力。', '银迹', '2022-12-01 21:11:35', 4);
INSERT INTO `data` VALUES (11557, 'l***1', 5, '外观很时尚，很精致。 屏幕高清，色彩稳。拍照效果：很棒，防抖很好，色彩真实。 运行速度：速度很快，8+真心不错。 待机时间：充满后待机时间长，玩游戏，王者一局基本 百分4左右。很不错。 整体来说，质量是很不错的！！！', '墨羽', '2022-11-21 19:39:08', 3);
INSERT INTO `data` VALUES (11558, '无***心', 5, '手机配送非常快，保护得也很好，拆封激**验非常流畅，手握手感也很不错，简单体验了一下系统，非常的流畅，配置这些都还可以，天玑8100的芯片还是很强的，日常使用肯定够够的，性能有溢出，nice', '晴雪', '2022-11-16 18:40:53', 6);
INSERT INTO `data` VALUES (11559, '粉***人', 5, '2k分辨率效果很好，屏幕看着很舒服，手机运行速度很快，拍照防抖照片很清晰，听歌效果也不错，充电速度很快，倒是感觉有些耗电', '幻镜', '2022-12-09 20:09:11', 2);
INSERT INTO `data` VALUES (11560, 'G***e', 5, '小米出品，必属精品，一直用这个牌子，我用过小米note，小米六，红米k30，老婆用过红米note3，红米k30，一直特别好用，这次活动价格很实惠，给老婆换了一个k50，配置很好，相机出片效果很好，大电池，充电快，尤其白色颜值高，性价比很高值得推荐。', '晴雪', '2023-02-22 22:44:35', 2);
INSERT INTO `data` VALUES (11561, '庆***群', 5, '给姑父买的，手机颜值很高，配置也足够用，最重要的是电池容量大，续航时间很给力，而且还能快充，姑父很满意！\n红米K20是当年的钉子户，如今更新迭代到K50了，质量应该也是一如既往的好！', '墨羽', '2023-01-28 00:40:06', 5);
INSERT INTO `data` VALUES (11562, '最***排', 5, '外形外观：外观设计漂亮 手持感觉非常舒适 顺手\n屏幕音效：屏幕显示细腻 双声道 听歌看视频一流\n拍照效果：非常要得\n运行速度：丝滑 顺畅 不卡顿\n待机时间：不玩游戏 平常刷刷视频 看看新闻用一天一充完全没有问题\n其他特色：双十一活动优惠大 还送了个充电宝 性价比非常高 \n总的来说 买对了??????', '银迹', '2022-12-24 19:02:55', 4);
INSERT INTO `data` VALUES (11563, '-***-', 5, '外形外观：墨雨色外观大气漂亮，很个性。\n屏幕音效：2k效果非常棒\n拍照效果：4800w扫码棒棒的。\n运行速度：速度没的说非常快\n待机时间：5500的电池一天没问题。', '墨羽', '2022-03-29 21:25:29', 9);
INSERT INTO `data` VALUES (11564, 'i***x', 5, '外形外观：磨砂玻璃，手感很棒，不容易有指纹\n屏幕音效：屏幕大边框小屏占比高，观感不错\n拍照效果：有光学防抖，非常不错\n运行速度：运行流程，界面顺滑\n待机时间：电池大，待机时间长', '晴雪', '2022-12-27 14:58:51', 3);
INSERT INTO `data` VALUES (11565, '穆***刃', 5, '外形外观：很不错，屏幕清晰，67W待机时间长，快充速度也很快，四十分钟左右就充满了。很厉害，我非常喜欢，操作也非常简单。丝滑流畅，反应特别快', '幻镜', '2022-11-07 20:41:15', 5);
INSERT INTO `data` VALUES (11566, '熊****', 5, '天玑8100+LPDDR5+UFS3.1的性能铁三角和12+256,应该足够我用三四年了。显示效果：三星的2KE4屏没的说，确实精细度很好。为了省电，日常都开1080P。其他特色：5500毫安大电池确实很顶，目前使用体验是妥妥用半天。大电池&gt;&gt;快充。', '晴雪', '2022-11-12 23:38:18', 5);
INSERT INTO `data` VALUES (11567, '啾***子', 5, '外形外观：全黑色的机体，非常好看，拿到手里也非常舒服\n屏幕音效：屏幕不愧是三星的屏幕，非常舒服，色彩辨识度也很不错\n拍照效果：拍照效果也很不错，尤其拍景色，很不错\n运行速度：运行速度可以，12+256，运行速度很快', '墨羽', '2022-10-03 18:45:06', 4);
INSERT INTO `data` VALUES (11568, '小***学', 5, '这简直就是学生党标配啊\n外形外观：外观挺好看的\n屏幕音效：屏幕真的好用，买来玩游戏的，一点不卡\n运行速度：买来玩游戏的一点不卡，\n待机时间：充电贼快，待机时间也长', '墨羽', '2022-11-30 18:55:21', 4);
INSERT INTO `data` VALUES (11569, 'j***d', 5, '屏幕音效：2k的屏幕，看视频非常舒服，打游戏看的也可以\n外形外观：非常好看，适合各种人群\n运行速度：以前一直以为天机不太行，真正用才发现贼优秀，比高通骁龙处理器用着还流畅，异常丝滑\n待机时间：非常长', '墨羽', '2022-04-16 18:29:33', 4);
INSERT INTO `data` VALUES (11570, '涨***饭', 5, '外形外观：炫酷\n屏幕音效：音质不错画面清晰\n拍照效果：很清晰\n运行速度：速度很快，没有卡顿\n待机时间：电池很耐用，用一天下来还能有一半的电量', '幻镜', '2022-11-14 09:16:39', 4);
INSERT INTO `data` VALUES (11571, '若***q', 5, '京东物流速度依然很快。\n外形外观：外观好看，相对于小米其他款来说，这款很是轻巧了。\n屏幕音效：灵动，反应很快，打游戏很畅通，看视频也非常流畅。\n拍照效果：拍照清晰，边框也不会模糊，美颜效果不假面，人像很柔和，风景很秀美。\n运行速度：运行速度快，性价比很高的。\n待机时间：待机时间目前两天是没有问题的。', '墨羽', '2022-07-02 10:05:12', 5);
INSERT INTO `data` VALUES (11572, '梦***夫', 5, '老米粉了，就想说一下小米的手机助手比华为的难用啊，只有整体备份功能，不像华为的可以直接在电脑上整理手机里的东西，这个真的太方便了。看网上评论说什么塑胶质感的，我觉得银色挺好看，而且膜都给贴好了，还配了透明硅胶手机壳，这个太赞了啊，都不用自己买了。', '银迹', '2022-03-22 17:44:28', 5);
INSERT INTO `data` VALUES (11573, 'j***d', 5, '外形外观：黑羽的后盖很漂亮推荐大家购买男女都适用\n屏幕音效：2K屏幕清晰度没得说\n\n拍照效果：超级棒\n运行速度：天玑8100运行非常流畅\n待机时间：大容量电池待机时间超长\n其他特色：送的手机壳和原装膜省了不少钱', '墨羽', '2022-11-13 09:05:01', 6);
INSERT INTO `data` VALUES (11574, '银***1', 5, '非常好，红米note8pro用了三年了，决定换一个新的，父母全是红米也是用了三年了，还是很靠谱。对比了各种型号，还是觉得8100靠谱，不打游戏，微信，新闻，足够用了，买了12G的，多用几年。MIUI系统用习惯了很好，来电自动录音，米家智能，勿扰模式，很实用。这个颜色挺好，黑色因为带斑点，放弃了（纯黑色绝对选纯黑）。性价比高，日常使用足够', '幽芒', '2022-11-03 21:31:32', 4);
INSERT INTO `data` VALUES (11575, 'z***0', 5, '外形外观：6.67寸屏幕，室友喜欢的尺寸，大屏打游戏更舒服。\n屏幕音效：杜比视界·全景声，外放也能享受3D效果。\n拍照效果：ois防抖扫码器，拍照就图一乐。\n运行速度：天玑8100，12G运存，速度挺快，但是小米手机 杀后台严重。\n待机时间：上班用一天，刷刷抖音，打几把游戏，完全没问题。\n其他特色：侧边指纹设计很人性，MIUI13用起来很舒服。', '墨羽', '2022-06-13 10:18:54', 4);
INSERT INTO `data` VALUES (11576, 'J***3', 5, '外形外观：这个银色非常好看，不用角度还能变颜色，nice\n屏幕音效：屏幕和音效也都挺好，香。\n运行速度：给家里人买的8+256，运行速度OK。\n待机时间：5500安的电池，待机也是香啊。\n夏天的时候给爸爸买了一个12+256的k50，用着很好，这次给妈妈也买一个，她之前用的红米k30骁龙7系处理器，其实也还能再用用，但是那个128的内存有点不够了，这次给她换个256的。\n京东物流就是给力，负责我们这片的京东小哥服务也很好，赞!', '银迹', '2022-11-18 16:41:09', 5);
INSERT INTO `data` VALUES (11577, 'j***4', 5, '外形外观：直屏看起来非常舒服2k细腻\n屏幕音效：杜比音效声临其境\n运行速度：miui13系统很流畅', '银迹', '2022-11-27 11:17:45', 3);
INSERT INTO `data` VALUES (11578, '龙***五', 4, '外形外观：墨羽色简直绝绝子，真叫好看了，特别高端\n\n屏幕音效：2k屏幕真是惊艳，比我的米8屏幕素质上了好几个档次，看电视剧效果绝了\n\n拍照效果：拍照日常够用，自拍用美颜相机感觉还行，和米8拍照效果差不多，足够用了\n\n运行速度：运行速度贼快，我买的12+512g的，真棒了，卡顿不存在的，教你们一个用机小技巧，隔一周重启下手机\n\n待机时间：平时一天玩个2～3小时王者，日常工作使用一天，中午刷刷抖音，每天晚上睡觉前还能有33%的电，早上闹钟响了插上充电器，洗漱完吃完饭出门的时候正好充满，哈哈，完美，再也不用一冲一晚上了\n\n其他特色：玩游戏稳得一批，帧率都不带动的，哈哈哈哈哈哈哈哈哈哈哈哈哈哈哈，k50绝了', '墨羽', '2022-07-03 20:05:25', 4);
INSERT INTO `data` VALUES (11579, 'j***R', 5, '外形外观：很好，质感不错\n屏幕音效：效果非常好，高刷2k屏幕，色彩准确\n拍照效果：扫码水平，够用\n运行速度：非常快，且省电，能效比优秀\n待机时间：续航非常顶，妥妥用一天\n其他特色：性价比很高的手机\n\n客服服务优秀，客服服务耐心\n非常满意', '晴雪', '2023-01-11 11:14:00', 4);
INSERT INTO `data` VALUES (11580, 'j***迪', 5, '小米手机值得信赖，买了好几个这样的手机了，非常的不错?????，毕竟买给老人用的手机还可以接受\n外形外观：外观大气，手机自带保护膜，还有手机壳，不用重复购买??\n屏幕音效：屏幕触碰效果好\n拍照效果：拍照像素好，高，清楚的很，自带美颜效果\n运行速度：反应处理速度快\n待机时间：待机时间久，两天没问题\n其他特色：内存还不错，买手机，嘎嘎好', '幽芒', '2022-12-23 15:36:48', 4);
INSERT INTO `data` VALUES (11581, '胖***p', 5, '外形外观：外观轻巧好看 手感很安逸 颜色也很漂亮 非常棒。\n手机运行速度快 打游戏也不卡顿 没有延迟  买的时候有活动 买的也很划算 而且待机时间很长 可以用很久 非常可以', '幽芒', '2022-11-17 17:00:59', 2);
INSERT INTO `data` VALUES (11582, '当***啊', 5, '不错，机子挺好的，2 k分辨率的屏幕看着很舒服，OLED屏幕显示很细腻，色彩丰富。尤其还是2 K直屏，这一点显得难能可贵。67W的快充+5500mAh的大电池，配合天玑8100这颗优秀的处理器，无论是性能还是续航，都很满意。日常使用也蛮流畅。打游戏有着VC液冷的加持，哪怕是原神也能在流畅运行的同时，做到机身不怎么发热?最让我意外的是相机，你敢相信这些照片是用红米K50拍出来的吗，属实惊艳到我了?', '墨羽', '2023-03-15 11:01:25', 5);
INSERT INTO `data` VALUES (11583, 'd***啦', 5, '外形外观：外观好，好漂亮 \n屏幕音效：画质好，屏幕清晰 \n拍照效果：看重的是后置摄像头，好用，照的照片美丽，好摄像头，色彩鲜艳，清晰 \n运行速度：快 \n待机时间：两天多，时间长 \n其他特色：质量轻，物美价廉', '墨羽', '2022-11-14 12:58:25', 3);
INSERT INTO `data` VALUES (11584, 'j***d', 5, '手机收到了，因为前后都是玻璃面板，外观看起来很大气也很漂亮，2K屏幕看视频很舒服，同时支持调光这点很棒，双扬声器听歌看视频如身临其境，运行速度很快，相机拍照效果还可以，要求高的除外，因为刚收到手机，待机时间还不清楚，等用过一段时间再来追评！', '幽芒', '2023-02-04 17:55:02', 6);
INSERT INTO `data` VALUES (11585, '阿***0', 4, '外形外观：好看，非常好看\n屏幕音效：比10s差一点点，不过在这个价位段，无敌\n拍照效果：能用就行，直男不要求很高\n运行速度：12+256无敌了好吧打游戏很舒服\n待机时间：这个还没测试，不过也挺耐用能玩好几局游戏呢\n其他特色：外观好看，充电速度快，推荐购买', '幻镜', '2022-11-25 10:01:12', 4);
INSERT INTO `data` VALUES (11586, 'z***o', 5, '这是一款让我毫不犹豫下单的手机，能兼顾性能的同时还能保持较低的能耗，这一点就非常吸引人了，8100+2K屏+5500大电池，然后2399起步的价格，我只能说，这波红米站在大气层上，简直是无敌的好吗，本来选的墨羽，但去小米之家看了，感觉墨羽太压抑了，毫不犹豫选了幽芒配色，拿到真机后只有一个感觉，选对了！真的超级漂亮！\n外形外观：好\n屏幕音效：好\n拍照效果：好\n运行速度：好\n待机时间：长\n其他特色：无敌是多么寂寞', '幽芒', '2022-03-23 19:56:49', 9);
INSERT INTO `data` VALUES (11587, '念***n', 5, 'K50的外观设计简约大方，很满意。屏幕显示效果很好，画质很清晰细腻。音效很棒，视频模式自动开启杜比音效，看电影追剧特别爽。简单得使用后感觉效果还是挺快的。5500毫安的大电池，待机时间很长。拍照防抖效果不错，可以满足日常需求。', '幽芒', '2023-03-10 14:04:38', 4);
INSERT INTO `data` VALUES (11588, 'H***6', 5, '外形外观：外形时尚好看，非常的简约大气上档次，看起来很好看，特别的喜欢，爱不释手！\n屏幕音效：屏幕清晰，2k的屏幕看起来特别的不错，杜比音效非常的清晰。\n拍照效果：拍照效果一般\n运行速度：运行速度真的很快！', '银迹', '2023-01-10 21:03:50', 6);
INSERT INTO `data` VALUES (11589, 'j***s', 5, '1外观材质：蓝色非常好看，金属材质，手感好，大气。 1屏幕效果：很清晰，屏幕大，还有护眼模式，不刺眼。 1运行速度：运行流畅，很快，一点都不卡。 1轻薄程度：很轻薄，拿在手上很舒适，非常好。另外，声音也好，用它上网课，看视频，电影，听音乐都很好。', '幻镜', '2022-11-13 09:01:44', 3);
INSERT INTO `data` VALUES (11590, 'j***0', 5, '性能刚刚好 很喜欢 日常生活 很舒服 充电也快 屏幕2k 就是拍照拉胯点 其他都完全OK 可以购买 双十一页有优惠 太棒了 啊哈哈', '墨羽', '2022-11-09 19:33:14', 6);
INSERT INTO `data` VALUES (11591, '上***然', 5, '京东物流非常快，前一天晚上下单，第二天就送到了。手机通话、微信、看视频等App都能正常使用。画质更清晰，运行速度更快，内存很大，是一款很不错的手机。', '幻镜', '2023-01-02 11:30:02', 6);
INSERT INTO `data` VALUES (11592, 'j***f', 3, '质量很差但是服务特别好，给个三星吧', '墨羽', '2022-06-13 23:07:21', 1);
INSERT INTO `data` VALUES (11593, '蝶***1', 5, '是正品不是二手机或者翻新机，在官网核实过，也按*#06#h核实对比过，都是相符的。运行速度很快我的是12g运行内存融合15g，屏幕分辨率很高，适合打游戏刷剧，打游戏略发烫，不影响使用。这个价位这个配置很不错。', '幻镜', '2022-12-02 17:37:34', 6);
INSERT INTO `data` VALUES (11594, '呱***2', 5, 'Redmi Note11T Pro 5G 天玑8100 144HzLCD旗舰直屏\n67W快充 12GB+256GB 时光蓝 5G智能手机\n外形外观:屏幕采用居中挖孔前摄设计，中框使用塑胶\n材质，屏幕保护玻璃是康宁第五代大猩猩玻璃，电池盖采用复合板材材质(就是塑料手感),镜头保护玻璃为康\n宁第五代大猩猩玻璃，屏幕保护玻璃有疏水疏油镀层。\n屏幕音效:上下双扬声器，杜比音效\n拍照效果:后摄6400万，800万超广角，前置1600万，\n中端拍摄手机，拍照爱好者不推荐\n运行速度:Redmi Note 11T ProRedmi Note 11T Pro搭\n载天玑8100处理器，安兔兔跑分超83万，同时采用满血版双通道UFS 3.1高速闪存。\n待机时间:充电速度很快，6.7卢快充，支持充电保护。\n完全充满电后玩一小时游戏，还有百分之八十左右的电\n其他特色:屏幕20.5:9定制比例，74.29mm宽度手感很\n棒，潮流小立边。最高144Hz 七档变速LCD显示刷新\n率，杜比视界，全程DC调光，true tone真彩显示原色\n屏幕，硬件级防蓝光。', '墨羽', '2022-12-01 13:43:48', 3);
INSERT INTO `data` VALUES (11595, '冰***浆', 5, '外形外观：外观很惊艳，后盖相当漂亮，非常美丽\n屏幕音效：屏幕显示效果惊艳，色彩明丽，饱和度高，杜比音响真的很震撼，好听\n拍照效果：拍照效果清晰，光学防抖很实用', '墨羽', '2022-07-21 19:12:40', 4);
INSERT INTO `data` VALUES (11596, 'e***u', 5, '外形外观：外形非常时尚手感好\n屏幕音效：2k屏幕非常惊艳，显示效果好\n运行速度：速度挺快的没有什么卡顿\n待机时间：待机时间很长，5500毫安电池很耐用\n其他特色：总体性价比非常不错', '幽芒', '2022-04-05 15:11:37', 5);
INSERT INTO `data` VALUES (11597, 'o***m', 5, '给女儿买的，她的小米8se用了好几年了，这次直接摔坏了屏幕，就直接换新的了，看了多篇文章，都说k50性价比超高，于是入手了标准版12+256，本来想入带p的，无奈预算有限。到手后简单测试一下，各方面都比较满意，真香！', '墨羽', '2022-05-03 12:05:24', 9);
INSERT INTO `data` VALUES (11598, '秋***2', 5, '用了几天感觉还是很不错的，手机很流畅，运行比较快，待机续航蛮可以内存也够大，双十一买的价格优惠，性价比很高。', '墨羽', '2022-11-24 13:45:27', 3);
INSERT INTO `data` VALUES (11599, 't***a', 5, '特意选了黑色这款，背板的裂纹太有个性了，超级喜欢，拿手上第一时间升级系统，各种设置调完后使用得心应手，不愧是粗粮最性价比的手机', '墨羽', '2023-01-25 18:37:20', 3);
INSERT INTO `data` VALUES (11600, '无***盖', 5, '好好看的手机，很好用，好可爱，好喜欢，好不容易抢到。毕业礼物！耶！', '银迹', '2022-06-27 16:32:25', 9);
INSERT INTO `data` VALUES (11601, 'J***丶', 5, '外形外观：手机非常美观，帮朋友买的，自己都想换了，\n屏幕音效：屏幕质感非常爽，三星屏幕很奈斯\n拍照效果：像素很好，自己用足够\n运行速度：一点都不卡，\n待机时间：很长，用了一天来评论的', '晴雪', '2023-01-18 17:24:32', 4);
INSERT INTO `data` VALUES (11602, '棉***E', 5, '左挑右选还是选择了OPPO A36这款，性价比之王。6+128G老人用完全够用。特意选了蓝色，很漂亮，妈妈喜欢。OPPO多年老粉，果然没让我们失望，真的很喜欢，用段时间再来补充评价。', '幻镜', '2022-11-12 22:42:36', 6);
INSERT INTO `data` VALUES (11603, 'A***哥', 5, '外形外观：满意，银色很好看\n屏幕音效：很满意，显示很清晰\n拍照效果：满足普通需要\n运行速度：很流畅，内存大有保障\n待机时间：大电池很不错，重度使用一天\n其他特色：性价比很高', '银迹', '2023-02-06 16:48:56', 3);
INSERT INTO `data` VALUES (11604, 'h***n', 5, '手机外观漂亮，8100的处理器，不卡顿，充电快，电池续航能力很好。原厂膜贴了的还有一个手机壳。', '银迹', '2022-11-14 13:34:36', 6);
INSERT INTO `data` VALUES (11605, '-***_', 5, '手机到的挺快，用了两天还不错，屏幕大，充电快，也不卡，运行也很流畅，屏幕很高清，打了两局王者，画质也不错。 k50电池很大，还不是很厚重，屏幕很好，8100yyds，真的很不错，MIUI就更不用说了，应有尽有，想出手的不用犹豫了，两千块很不错哦,性价比可以，价格也不高，推荐购买。', '银迹', '2022-11-14 14:55:41', 4);
INSERT INTO `data` VALUES (11606, '天***n', 5, '外形外观：外观大气，尺寸正合适，拿在手里有点份量\n屏幕音效：屏幕素质很好，画面流畅，细节也很清晰\n运行速度：速度挺快的，比以前手机快了不少\n拍照效果：只能说够用了，毕竟也不是专业摄影的', '晴雪', '2022-11-18 23:11:20', 4);
INSERT INTO `data` VALUES (11607, '北***g', 5, '外形外观：挺不错的，我买的是晴雪特别不错\n屏幕音效：非常nice\n拍照效果：一般般，毕竟这个价位还要什么自行车\n运行速度：非常流畅\n待机时间：正常使用两天一充\n其他特色：得益于天玑8100的处理器，低能耗，高性能', '晴雪', '2022-12-05 20:55:17', 4);
INSERT INTO `data` VALUES (11608, 'j***b', 5, '提前付的定金，老弟提前看好了这一款，等着5.31号搞活动，便宜了200元，十分实惠的价格，性价比很高，对比了好几天，最终选了这一款，很不错，\n外形外观：很时尚大气\n屏幕音效：很棒\n拍照效果：拍照很清晰，高清镜头，很给力\n运行速度：12+256，运行速度很给力', '墨羽', '2022-06-02 20:18:39', 8);
INSERT INTO `data` VALUES (11609, 'a***蓝', 5, '给家人换手机！新来的让我开机看一下。这个颜色很好看，第一次尝试开机视频，感觉拍的也不错，\n系统整个流畅，内存256，这个价格无敌了\n最后家人很喜欢', '幽芒', '2022-08-09 20:44:28', 2);
INSERT INTO `data` VALUES (11610, '不***告', 5, '外形外观：超舒服，都不想带手机壳了，但是不带又担心摔坏啊啊真的是\n屏幕音效：立体音效哦，打游戏更是一绝\n拍照效果：简直没得说，一点都不亚于那些什么几千亿像素的\n运行速度：充电速度快，运行速度快，不卡顿，很流畅，爱了爱了', '幻镜', '2022-11-10 20:43:59', 4);
INSERT INTO `data` VALUES (11611, '左***4', 5, '快递很快，快递员态度也很好，手机性能没的说，性价比目前最高吧，使用时间还不够长，目前没发现有什么问题，小米还是很稳定发挥的，手机2k屏幕，67w快充，是真的棒，这屏幕，看着太舒服了，很满意，67w快充，其实就是为了2k屏幕，因为屏幕耗电稍高，快充完美弥补', '银迹', '2022-07-25 09:14:29', 5);
INSERT INTO `data` VALUES (11612, 'w***8', 5, '2022.4.4是儿子推荐我在京东自营店下单Redmi K50 天玑8100 2K柔性直屏 OIS光学防抖 67W快充 5500mAh大电量 墨羽 12GB+256GB 5G智能手机 小米红米。价格2799元于本月9日收到小米的手机，价廉物美，质量挺好，运行速度特快，摄像拍照都很清晰，以前用过各种品牌手机，这次也比较满意的。我家大型电器基本都是京东自营店购买的，京东自营的产品就是好。以后还会继续购买京东自营产品，推荐同事朋友。', '墨羽', '2022-04-21 16:13:06', 6);
INSERT INTO `data` VALUES (11613, '杜***肥', 5, '终于等到K50，全线拉满，太帅了！非常不错，银色非 常好看，全熏黑的镜头一体化非常喜欢，2K屏画面明 显饱满很多， 超大电量续航也是一大亮点，之前的手机 一天两充， K50真正实现了一天一充。该有的功能一个 不少，性价比依旧天花板，红米yyds！后期听说会上 120hzdc调光，希望尽快吧，别让米粉等太久，第一台手 机买的就是小米， 很耐用，这台应该也不错， 推荐大家 购买。^O^非常满意', '银迹', '2022-11-20 14:43:09', 4);
INSERT INTO `data` VALUES (11614, 'j***d', 5, '完全满足游戏需求。最值得说的一点是第1次体验如此快速的物流，昨天下午下单，今天早上拿货太开心了，以后还会在京东购物。东西很好，这下不用操心，一台手机电不够了。京东自家的物流真的快，必须好评。！！', '银迹', '2023-01-07 15:13:29', 8);
INSERT INTO `data` VALUES (11615, '苏***洲', 5, '买第一次给老爸买的新手机，希望他会喜欢，大品牌，用起来很放心，质量非常好，赶上活动购买非常的划算,客服真的很不错哦～还是比较喜欢oled屏幕，比较高清！希望后续使用电池不要 太热了。', '幽芒', '2022-11-16 11:18:11', 3);
INSERT INTO `data` VALUES (11616, 'G***o', 5, '东西到手，拆开看的确挺惊艳的，洁白无瑕的感觉，看着就很舒服。67w快充基本40分钟就90+了，大容量电池待机两天都没问题。玩游戏半天去了一般的电左右，还是很耐用的，整体五星', '晴雪', '2022-11-04 16:43:44', 5);
INSERT INTO `data` VALUES (11617, 'l***1', 5, '外形外观：外观非常好看，大气， \n屏幕音效：显示效果很好，非常清晰，音质也不错 \n拍照效果：拍照清晰，只能发放10倍 \n运行速度：运行速度杠杠的，很流畅 \n待机时间：待机时间不错，重要的是充电非常快', '墨羽', '2022-11-09 20:18:58', 4);
INSERT INTO `data` VALUES (11618, 'n***3', 5, '外形外观：外观挺好看的，这个颜色个人比较喜欢。\n屏幕音效：效果不错，看的很舒服。\n拍照效果：效果还可以，日常使用足够了。\n运行速度：运行非常的流畅。\n待机时间：中度使用一天一充。\n其他特色：充电速度很快，一会就充好了，很给力。京东速度很快，第二天就到了。', '银迹', '2022-12-01 16:45:55', 3);
INSERT INTO `data` VALUES (11619, '懒***抽', 5, '外形外观:很漂亮，黑色的，很喜欢，手感不错，很滑，很舒服 屏幕音效:屏幕很清晰，高清晰度。 拍照效果:拍照也很好，很满意，效果不错 运行速度:运行速度杠杠的，也不卡，非常流畅。 待机时间:待机，不打游戏正常使用一天没问题', '墨羽', '2022-11-17 22:57:14', 3);
INSERT INTO `data` VALUES (11620, '爱***书', 5, '手机很好，用了将近半个月才过来评论的，很不错，京东自营物流很快，东西很给力，性价比很高!运行流畅，日常使用完全能胜任，续航方面还是可以的，至于67W充电，确实有点发热的问题但是不影响，测试app长时间运行中，温度适中，游戏的话运行整体表现也不错，正常FPS和正常120Hz下，发热还可以可以接受，总的来说使用体验还不错!确实如网上所说是性价比神机，只有2k预算的话强烈推荐！大电池+快充+好屏幕+高刷，真的很推荐!', '墨羽', '2022-11-21 14:12:34', 5);
INSERT INTO `data` VALUES (11621, '赵***爷', 5, '外形外观：外观选了黑色，高端大气\n屏幕音效：双扬声器，音质超级棒\n拍照效果：索尼4800的像素，光学防抖，夜景模式尤为出众，AI模式智能便捷\n运行速度：天玑8100游戏开黑无延迟，运行多个软件运行很流畅\n待机时间：5500的大电池，使用时间明显提升，搭配67w快充，半个多小时充满', '墨羽', '2022-11-27 17:40:32', 3);
INSERT INTO `data` VALUES (11622, 'j***a', 5, '外观外形：相当漂亮，高端大气，外观做工精细，没有任何瑕疵的精品机，颜色也是我特别喜欢。\n其它特色：2K柔性直屏效果真的是一级棒，67W快充满格40多分钟既充满，5500mAh大电量，还赠送了手机透明皮套，到手就用非常方便，手感还特别好，非常喜欢！', '幽芒', '2022-04-03 13:17:13', 9);
INSERT INTO `data` VALUES (11623, '明***清', 4, '外形外观：本人喜欢黑的，所以就买了墨羽色，后壳太帅！！\n屏幕音效：跟我现有黑鲨差不多。哈啊\n拍照效果：拍照效果，比我手里的黑鲨香。\n运行速度：打个王者，吃鸡啥的还不是，杠杠的。\n待机时间：有个67W快充，自己体会&hellip;', '墨羽', '2022-04-05 11:41:04', 4);
INSERT INTO `data` VALUES (11624, 'T***0', 5, '双十二入手，隔日达。一直用黑色手机，这次选幽芒，惊艳到我了，手感很好，大小合适，孔位设置合理，屏幕细腻，顺滑，全杜比音效，很赞。买的12+256，运行流畅，平时不玩大型游戏，够用一阵子了。拍照效果也不错，夜景还没尝试，不过对于我平时不怎么用摄像头的人来使用已经绰绰有余。待机有保证，充电也快，充电画面还很炫，充的飞快。整体值得购买，物美价廉！', '幽芒', '2022-12-13 16:48:42', 5);
INSERT INTO `data` VALUES (11625, 'c***0', 5, '外形外观：外观好看，很酷炫\n屏幕音效：音质不错，\n拍照效果：拍照效果不错，很高清，夜晚拍的非常清晰\n运行速度：运行速度快到飞起\n待机时间：待机时间很长，可以顶很久', '墨羽', '2023-02-14 19:44:42', 3);
INSERT INTO `data` VALUES (11626, '悠***地', 5, '刚拿到手白色颜值挺不错的，有点像磨砂质感，不沾指纹，手感不错，性能上非常棒，天机8100安兔兔跑分81万，完美高清畅玩原神，属实是被惊艳到了，手机现在用的还挺不错的，暂时没有什么毛病，后续有什么不足的地方，再追评上', '晴雪', '2022-11-06 20:29:30', 6);
INSERT INTO `data` VALUES (11627, '夏***1', 5, '外形外观:非常完美没有一点瑕疵，工业设计水平还是高。虽然继续使用上代外观。总体来说还是一线大厂的水平。手机反复检查了12分钟，视频拍了32分钟。外观成色十分完美。\n屏幕音效:屏幕音效:看视频我用哔哩哔哩 屏幕显\n示HDR视频效果很哇塞，不过对于网速有一定要求。\n杜比音效，非常nice。听音乐看视频，我开一半音量比我原先得手机大的多。\n拍照效果:拍照效果:拍摄效果非常好，对比我原先\n手机有很大提升。但对对比安卓一英寸5000W大底的镜头来说还是逊色一些。但视频拍摄部分是真的稳，开启运动防抖后虽然是2.8K分辨率但拍摄起来非常稳定。\n运行速度:iOS的墓碑机制，启动APP运行速度很\n快。后台保留软件存活情况也好，不会存在从新加载\n的情况。\n待机时间:待机时间是真的长，我中度使用全程\n5G+WiFi使用，可以用一天多7小时(待机+亮屏时间)。\n其他特色:蓝色果然没选错非常好看，充电我测得半\n小时可以充47%(我用华为冰糖40W氮化镓全能充。\n虽然充电时充电头发热严重，但纹波较低，对电油\n手机主板用电设备影响较小，可以延长使用寿命)过完年我会在追评。', '晴雪', '2023-02-14 10:56:19', 2);
INSERT INTO `data` VALUES (11628, '势***A', 5, 'Redmi K50，2 K柔性直屏用着非常丝滑，光学防抖的效果不错，67 W快充的充电速度挺快，5500 mAh电池大电量，非常耐用。幽芒色非常喜欢，12 GB+256 GB足够用了。手机外放音质很好，这款手机性价比很高。赶上有活动抓紧入手吧。', '幽芒', '2022-11-16 22:10:36', 4);
INSERT INTO `data` VALUES (11629, '梁***4', 4, '运行速度：速度很快，用起来很丝滑，指纹解锁特别快，\n屏幕音效：屏幕不错，2k屏绝对给力，音效还行吧，\n拍照效果：拍照我觉得一般，差不多就可以了\n\n\n待机时间：5500毫安电池，绝对给力，充电速度也很快\n外形外观：外观中规中矩，我选的银色的，挺好看的\n其他特色：目前还在研究当中，总体感觉不错，值得拥有', '银迹', '2022-03-29 10:36:03', 4);
INSERT INTO `data` VALUES (11630, 'L***1', 5, '外形外观：简约大方，符合小米一贯的风格，选的雪白色，百搭手机壳。\n屏幕音效：屏幕很大，用起来很舒服，音量大，不过音质一般，这个价位可以接受。\n拍照效果：不在意，没留意。\n运行速度：非常快，飞一般快，很满意。\n待机时间：还不错。\n其他特色：充电非常快。', '晴雪', '2022-12-04 19:23:24', 3);
INSERT INTO `data` VALUES (11631, '歆***n', 5, '外形外观：还可以，不过因为塑料支架的存在，裸机确实有点硌手，后壳白色很好看\n屏幕音效：2k屏幕无敌好吧，很清晰\n\n拍照效果：红米就别太看重拍照了，真想拍点好的，用手动模式或者安装个谷歌相机\n运行速度：特意买了12g版本，MIUI太吃内存了\n待机时间：5500mah很厉害，不过我是中高度用户，早上冲完，可以用到六七点\n其他特色：红外和限行马达很舒服，错过了618，趁着双11入手一波', '晴雪', '2022-11-19 16:47:26', 4);
INSERT INTO `data` VALUES (11632, 'j***9', 5, '用了一段时间来评论，外观很时尚靓丽，特别是这墨羽色,做的真不错，很有辨识度。屏幕音效：2k的屏幕，小时效果真的-级棒！待机时间：拥有5500毫安的大电池，妈妈再也不用担心我手机没电了！运行速度：新机很流畅，上手很丝滑很赞。', '墨羽', '2023-01-15 23:25:31', 4);
INSERT INTO `data` VALUES (11633, 'Z***_', 5, '这活动太给力了，比平时便宜了好几百，而且拿到手，这个颜色比图片看上去更好看，物流也没有因为大促活动受丝毫影响，用了几天才来评价的，这个价格这个品质真是太香了！', '幻镜', '2022-11-17 00:20:32', 9);
INSERT INTO `data` VALUES (11634, 'j***y', 5, '红米k50手机，小米京东自营旗舰店的产品，质量品质令人放心，一直在京东或者小米商城官方购买，安全放心使用，手机价格实惠，联发科8100处理器 CpU，功耗低又省电，处理速度很快，打游戏都能沉着冷静应对，2K直屏120赫兹屏幕刷新率，电池容量大，待机时间长。京东快递物流很快，包装很好无破损。', '墨羽', '2022-11-19 20:07:51', 6);
INSERT INTO `data` VALUES (11635, 'j***D', 5, '手机是正品，物流很快，收到包裹完好无损。手机很好用，性能好，内存大，拍照清楚好看，爱了爱了。喜欢的可以入手。', '晴雪', '2022-11-28 16:36:27', 2);
INSERT INTO `data` VALUES (11636, '过***经', 5, '盯了这款手机好久了，因为预算问题，迟迟没有下手，过程中也对比了很多款同等价位的，最后还是觉得这款更符合自己的心理预期，终于，再一次等到了活动优惠，立马下手了。使用了好几天，总体感觉很好，速度很流畅，性价比很高，不过，玩***上面的小游戏:福气兔，感觉有点掉帧的样子，不知道是咋回事，但是总体来说还是很满意这款手机的！', '墨羽', '2023-01-16 11:01:04', 6);
INSERT INTO `data` VALUES (11637, '阿***力', 5, '第二次购买了，质量很好，系统很流畅，拍照清晰，大电池，续航能力强，处理器天玑8100很厉害，玩游戏一点都不卡，赶上双十一活动，优惠力度很大，性价比很高，值得购买！', '墨羽', '2022-11-03 18:57:20', 2);
INSERT INTO `data` VALUES (11638, 'z***9', 5, '简洁不简单的包装，打开看就是惊喜，很喜欢墨羽，后壳我很好看，买手机就得买旗舰版，很流畅，一点都不卡，2k屏膜很清晰了，大容量再也不用天天删照片啦。', '墨羽', '2022-07-09 13:31:03', 5);
INSERT INTO `data` VALUES (11639, 'j***z', 5, '外形外观：外观很大气，屏幕够大\n屏幕音效：屏幕很灵敏\n拍照效果：拍照效果：照片就是用k50拍的 ，挺清晰的\n运行速度：运行速度：运行很好 \n待机时间：充满电，放一晚大约能掉七八个电\n其他特色：充电很快，大约一小时左右就能充满', '墨羽', '2022-07-09 10:34:31', 4);
INSERT INTO `data` VALUES (11640, 'j***v', 5, '给老爸买的，爸妈一直用的小米手机，这款红米K50屏幕很清晰，待机时间也比较长，内存也很大，老爸前面一款手机用了6年，真的很皮实，老爸喜欢', '墨羽', '2022-12-15 13:16:12', 2);
INSERT INTO `data` VALUES (11641, 'z***8', 5, '红米k50手机很不错，速度很快，漂亮美观，摄像头像素比我这华为p40要好。拍出来效果不错。物流太快了，相信京东自营。', '墨羽', '2022-06-18 13:34:14', 9);
INSERT INTO `data` VALUES (11642, 'w***8', 5, '外形外观：不错外观挺漂亮 很喜欢 黑色比较万能色 男女用都可以 自带壳膜 先用着吧  一直喜欢小米的红外功能 很方便 \n屏幕音效：三星屏质量可靠  音效外放也可以 \n拍照效果：小米的相机优化一直不错 颜色不失真 前摄也比较自然  \n运行速度：12G运存一般够用了 没觉得卡顿 比较流畅\n待机时间：67W充电器很给力 充满半小时左右 一般使用一天没问题 \n价格双十一买的 幺期久久 还算可以', '亮黑', '2023-01-06 15:33:40', 9);
INSERT INTO `data` VALUES (11643, '我***家', 5, '很久就已经加入到购物车了，早就想买了，双十一活动，就下手了。比原来便宜好多！京东自营的，放心，售后也不错，速度也快！\n外形外观：漂亮，好看！\n屏幕音效：屏幕还可以吧！\n拍照效果：一级棒！\n运行速度：买的顶配，绝对够用5年了！', '亮黑', '2022-11-10 12:56:12', 7);
INSERT INTO `data` VALUES (11644, '小***咯', 5, '外形外观：简单大方，很滑溜的\n屏幕音效：清晰明了，真的不错?\n拍照效果：多模式快速拍照，也不错哦?\n运行速度：超级超级的快，简直无敌了\n待机时间：充满能用一整天\n其他特色：小米真的是为发烧而生！', '银迹', '2022-12-25 10:07:15', 7);
INSERT INTO `data` VALUES (11645, '梅***旺', 5, '外形外观：外观非常好看，我买的黑色，非常漂亮\n屏幕音效：音效超棒，\n拍照效果：拍照效果一般，但我不大拍照\n运行速度：运行非常顺畅\n待机时间：待机还行吧', '亮黑', '2023-02-26 21:16:04', 5);
INSERT INTO `data` VALUES (11646, '鹰***底', 5, '小米京东自营旗舰店，售前售后服务周到，从咨询到下单到收货顺利，京东送货服务一如既往，下单第二天收货。小米K40S，是K40升级版，外观更好看，功能更强大，特别是拍照效果升级了，帮家人连续购买了两台，都说好用，搭载高通骁龙870，这个价位这个配置，个人觉得性价比很高。手机流畅，67W充电配置，相当够用，不怕续航问题。质保一年，售后无忧！', '幻镜', '2022-07-25 21:21:52', 7);
INSERT INTO `data` VALUES (11647, '丁***亮', 5, '该款手机性价比很高,同价位手机有NFC和遥控器功\n能的不多,搭载骁龙870处理器和大内存手机运行很流\n畅,照相功能也能应付日常拍照,成功将手机当门禁卡\n使用。好评!\n外形外观：直边框，直屏，孩子特别喜欢', '幻镜', '2022-09-16 12:26:46', 9);
INSERT INTO `data` VALUES (11648, '朋***霍', 5, '隔天到，京东的物流没的说，很快很稳。产品包装完好，密封严实；逐步开箱，手机，充电器，手机保护壳一应俱全，没学某果什么的还得自己买充电器，这点很好；幻境款实机比图片看上去还要漂亮，12+256主流配置，总体满意，作为备用机与我的mate40pro相得益彰，开机之后百分之一的电量，各位老铁入手之后记得先充电。总体满意，值得入手。', '幻镜', '2023-01-15 17:44:49', 9);
INSERT INTO `data` VALUES (11649, '冷***1', 5, '小米的忠实粉丝，非常喜欢小米的手机以及智能家居用品\n。所以，老妈换手机就直接选择了红米K40S，幽芒绿色，很高雅活泼的颜色 老妈非常喜欢。手感出众，比较轻薄，关键是870处理器还是可以的，速度绝对流畅。另外，还有67w快充，ois防抖，以及超级好的影音效果，可以说非常全面，很能打。12G256G不到一千八拿下，很实惠。', '幽芒', '2022-12-14 16:45:17', 9);
INSERT INTO `data` VALUES (11650, 'j***d', 5, '下单第二天天就收到了，打开被这款手机的颜值惊艳到了，超薄的机身，颜色也非常绚丽。870cpu，12+256，反应速度非常快，e4屏幕也很清晰舒适，简直爱不释手。', '幻镜', '2022-12-20 19:40:22', 7);
INSERT INTO `data` VALUES (11651, '不***啊', 5, '外形外观：这款k40在外观上采用了非常经典的方阵设计，握持手感，个人感觉还是很不错的。\n屏幕音效：这款k40的屏幕采用了三星e4材质，显示效果很不错，同时通过了杜比认证。支持HD2显示，在音效上也有杜比认证，双扬声器音量宏大清晰。\n拍照效果：主摄采用了索尼的传感器，同时加入了光学防抖，日常拍照没有问题。\n运行速度：这款是12+256的版本，运行速度非常流畅。\n待机时间：4500毫安的电池可以做到妥妥的一天使用。', '幻镜', '2023-03-11 09:54:24', 9);
INSERT INTO `data` VALUES (11652, '阿***酷', 5, '手感很好 磨砂的外观大气 买给老年人用或者当主力机使用完全没问题 能满足日常需求性能小钢炮 质感很舒服 依然是焊门员屏幕素质 系统流畅度方面都很不错 跟手很快 音效不错 拍照能满足日常很多场景', '晴雪', '2022-11-22 17:19:35', 9);
INSERT INTO `data` VALUES (11653, '我***你', 5, '京东物流很快，到手一个多月，用着很好，很舒服，一直都是米粉，就是喜欢miui没办法。\n手机挺薄的，手感很好，银色简直好看到无敌。870处理器不用说，好就完了。拍照也挺清晰的。安卓确实比苹果用着舒服！', '银迹', '2022-12-27 23:00:34', 5);
INSERT INTO `data` VALUES (11654, 'u***t', 1, '外形外观：大小合适，颜色很好看，手感非常好，选的绿色，不烂大街\n屏幕音效：双喇叭的，效果很好，声音很大很清晰\n拍照效果：不错\n运行速度：简直是绝了，老公做工地的，买贵了怕摔坏可惜，便宜了怕不好用，搜到这款，运行速度是最绝的，超大内存非常实用，吃鸡等游戏体验感也非常好，两千来块简直是性价比超高！喜欢的不要犹豫！', '幽芒', '2022-09-20 20:06:01', 5);
INSERT INTO `data` VALUES (11655, 'j***2', 5, '性价比非常高的一款机子！红米K40S大小合适，身材比较修长。7.7毫米的厚度，195克的重量上手很舒适。整体做工精细，黑色的最漂亮，浑然一体很养眼哦！870的处理器依然强悍，各种APP基本秒开。上下立体声音质洪亮、饱满。屏幕是三星E4发光材质，颜色艳丽，通透。对比其它屏幕目前是前置挖空最小的，看着舒服啊！后置4800万＋800＋200的水桶配置，比上一代增加了光学防抖，成像质量够用了。最满意的就是67W的快充了，38分钟就能充电完成，超赞！小米的系统流畅度、稳定性都可圈可点。这个价位基本没有对手，值得入手啊！', '亮黑', '2022-11-28 02:37:59', 8);
INSERT INTO `data` VALUES (11656, 'A***涯', 5, '收到喽???????\n非常好哦???????\n给个全五星???????\n外形外观：漂亮\n屏幕音效：可以\n拍照效果：清晰\n运行速度：挺溜\n待机时间：不错\n其他特色：感觉挺好的', '亮黑', '2023-01-11 21:27:24', 5);
INSERT INTO `data` VALUES (11657, 'o***1', 5, '京东快递还是很给力的，相当快，手机到手后就迫不及待的拆封开机，这次买的是12+256的版本，整体用起来很流畅，开七八个进程也没一点卡顿迹象，这真称得上性能怪兽了。手机外形尺寸刚刚好,拿起来很舒服,很帅气,屏幕真心给力,色彩显示清晰,变焦功能强大,高通870加持,运行流畅不卡顿,大电池续航长,快充67W相当快，喜欢的一定要入手啊,物超所值,外观不错，整体手感也很轻薄，下载速度很好，游戏体体验在这个价位带算是性价比不错的，4500毫安大电池轻松用一天没有什么问题！', '晴雪', '2022-10-03 16:55:38', 5);
INSERT INTO `data` VALUES (11658, 'E***g', 3, '这价位的手机适合学生党', '亮黑', '2022-05-18 08:12:22', 1);
INSERT INTO `data` VALUES (11659, '孙***强', 5, '运行速度：很快很流畅 拍照效果：还不错，挺好看 电池续航：充电速度很快，手机息屏耗电很少，如果是一直玩，耗电比较快 外观设计：好看，很舒服 性价比：总体不错', '亮黑', '2022-09-01 13:41:16', 4);
INSERT INTO `data` VALUES (11660, 'R***g', 5, '第一次买小米手机，综合对比下来，性价比非常高，准备用来做备用机，首先，性价比，这个确实没什么说，该有的都有，性价比非常高，然后也使用了这个手机蛮久，充电速度杠杠的，玩游戏，像使命召唤这种大型手游蛮不错，整体比预想要好些，但是不妨碍这个手机的缺点，死机了两次（未知原因），鉴于目前良好，我先忍忍接着用用看，充电效果拉满，5g速度还是可以的，大概就这些。', '亮黑', '2022-09-15 22:13:09', 9);
INSERT INTO `data` VALUES (11661, '王***8', 5, '手机摔坏了，急需买新机，预算不高，看了国产品牌的几款机子，同等价位，同等配置只有红米的性价比最高（不喜勿喷），看上2款，一款是k40s，一款是k50，相对来讲，k50还是要好一些，可是价位也高，最后综合评比，选择了这款k40s，毕竟不打游戏，够用了，电池续航一般吧，4500的电池，使用一天没问题，外观很漂亮，手感不错，运行速度嘎嘎快，物流配货很快，第二天上午送货，这速度，真棒！', '亮黑', '2022-10-16 21:38:18', 5);
INSERT INTO `data` VALUES (11662, 'j***n', 5, '发货，快递，给力。疫情向好，物流通畅。包装简约，防撞气垫保安全。前任k30i摔坏了，当然还是小米。****，数据都在。马上新机发布，今年的k40s价格有比较大的优惠，买。双卡，一上一下插口（有点特别）。自带一块普通膜，一个透明手机壳，到手即用。Miui 13，丝滑至极。\n外形外观：丝滑，贴手。\n屏幕音效：三星屏加杜比音效，听音乐，看影剧，打游戏，俱佳。\n拍照效果：三主摄+中部自拍头。完美应对各种需求。\n运行速度：快！870果然牛。12+256配置满分。\n待机时间：还未验证！充电是真快，67瓦闪充，杠杠的。\n     果断购买！比你想象的好太多了。起飞吧，红米！', '亮黑', '2022-12-25 18:47:09', 9);
INSERT INTO `data` VALUES (11663, '紫***业', 5, '发货速度很快，包装精致，外观设计漂亮大气，电话验证是正品，手机重量，厚度，大小都很合适，幻境颜色我非常喜欢，内存够大，速度够快，声音很好，可以说性价比很高，拍照，录像都很好，是一款非常值得购买的手机。', '幻镜', '2023-01-14 19:09:30', 5);
INSERT INTO `data` VALUES (11664, '李***8', 5, '外形外观：媲美苹果旗舰，\n屏幕音效：震撼爽，\n拍照效果：很清晰，拍出大片感觉，\n运行速度：流畅运行，很快很灵敏，\n待机时间：时间长，充电快，\n其他特色：非常给力，性价比超高。', '幻镜', '2022-06-18 09:48:32', 8);
INSERT INTO `data` VALUES (11665, 'm***8', 5, '包装严实合理，物流很快，外观漂亮简洁，手持舒适，使用效果还可以，旋按钮设计合理，一般使用，多开软件，不打游戏够用，入网信息等标注的很清楚！\n外形外观：漂亮\n屏幕音效：可以\n拍照效果：一般\n运行速度：快\n待机时间：一般应用不打游戏68小时左右\n其他特色：性价比高配合各地消费券后的价格很美丽！', '幽芒', '2022-09-14 21:28:49', 4);
INSERT INTO `data` VALUES (11666, '我***-', 4, '告别用了五年的小米8SE  6+128版本，在双十一活动迎来了红米K40S 12+256版本，本人钟爱小屏觉得拿手里方便一开始比较中意于小米12X，后来看了看配置觉得都是870神U和12+256但是价格差一千，思虑再三，考虑到现在口罩大环境影响消费信心受到一定冲击，从&ldquo;报复性消费&rdquo;变成了&ldquo;习惯性省钱&rdquo;，才定下买了K40S\n外形外观：中规中矩，质感比较不错\n屏幕音效：很不错，外放调到最大也不会失真\n拍照效果：这是这个手机最让人吐槽和不满意的地方，扫码肯定没问题\n运行速度：非常快，刚到手换机完成以后80多个软件待更新，几分钟就升级完成\n待机时间：中度玩手机一天一冲完全够用\n其他特色：支持WLAN6，如果家里路由器也有这个功能，网速起飞', '亮黑', '2022-11-16 17:15:29', 9);
INSERT INTO `data` VALUES (11667, 's***迁', 5, '京东物流速度超级的快，就是快递包装盒有点拉胯了有点破损了，好在里面还有一个缓冲气垫膜，手机没有问题。\n在这个价位里这个配置简直无敌，自动入手第一台小米MIX 2S，一直坚信小米一定是米粉心中最酷的手机，要是K60E上870这款处理器那么买的就不是K40S了，K40S去年的机器都吊打现在友商很多新款机，做工没有问题。\n充电速度很快，半个小时基本上能充满，运行速度很快，红外也很好用，外观想买银白色无奈1799无货，一开始不太喜欢这个颜色，但是拿到手上是真香警告，就算不喜欢套个真皮磨砂手机壳也是非常奈斯，换掉老爸六年的老伙计，期待新伙计的给力表现，也希望小米新的一年越做越强，给我们米粉更好的产品更好的性价比!!!', '幻镜', '2023-01-27 09:53:18', 9);
INSERT INTO `data` VALUES (11668, '小***师', 5, '厚度刚好，棱角分明，手感好，有苹果13的赶脚，白色yyds，骁龙870稳如老狗，e4屏幕比e5屏幕对眼睛友好，MIUI流畅不卡顿，给爸妈用太合适了，老妈的note8pro终于可以光荣下岗了', '晴雪', '2022-11-07 16:48:01', 4);
INSERT INTO `data` VALUES (11669, 'j***h', 5, '给父母买的手机，红米的产品还是很好用的，k40系列虽然是去年的产品，但是这个K40s很好的补齐了K50普通版的遗憾，骁龙870和67w快充速度很是喜欢！手机运行速度流畅，拍照也不错，推荐这个青色，简直不要太美了！赞！', '幽芒', '2022-11-30 15:23:40', 6);
INSERT INTO `data` VALUES (11670, 'A***杨', 5, '不怎么用小米，但是这次真的吸引到我了，k50系列确实很香，，但是追求外观，性价比的我选择了这款，手机外观很漂亮，870的性能日常使用足够了，是我喜欢的四四方方的，电池嘛，一天不是问题，功能挺齐全，红外挺不错的，充电也快，个人认为性价比还是不错的，很香。', '银迹', '2022-03-29 18:06:00', 7);
INSERT INTO `data` VALUES (11671, '爱***猫', 4, '收到货，第一时间拆包装，感觉质量是比较好的。与卖家描述的是一致的，查了一下是正品新机！非常满意，发货速度比较快，物流公司服务态度很好，运送速度很快。也没有什么破损，包裹非常完整。很满意，值得购买。续航：打了四局王者荣耀，耗电20 拍照：对于平时用的话足够了 运行：运行自我感觉还不错 骁龙870的处理器差不了', '幻镜', '2023-02-10 20:25:27', 5);
INSERT INTO `data` VALUES (11672, 'j***A', 5, '双十一活动买的，价格太给力了，12+256版本到手1600，这个价钱不比红米note12Pro香吗？而且处理器是一代神U骁龙870，一点不卡顿，流畅无比，也很省电，全程高刷120hz就是爽，用了就回不去了，淘汰掉手里的iPhone 7plus，用了6年多了真心舍不得，作为备用机用吧，iOS有其强大之处，但MIUI 13也有其优势，一直是忠实米粉，从小米一代就买了，喜欢小米这么多年了，愿小米越来越好', '晴雪', '2022-11-14 17:29:48', 4);
INSERT INTO `data` VALUES (11673, '月***6', 5, '给家人买的，充电快，不卡，大屏幕，真的好用，照相也很清楚，还真不错，物流也超级快，好好好，还送了手机壳和手机膜，赞', '亮黑', '2022-12-19 21:31:35', 4);
INSERT INTO `data` VALUES (11674, '-***崔', 5, '外形外观：直角边，白色后壳，不是塑料的，很好看\n屏幕音效：音效非常好，很有质感\n拍照效果：像素比较一般，不过色彩挺好的，我放几张后置拍的照片\n运行速度：很快，丝滑极了\n待机时间：比较久，不玩游戏能撑一天(？  而且充电很快！\n其他特色：物流巨快，头天晚上11点下单，第二天7点就到了，就很喜欢！', '晴雪', '2022-08-04 23:20:11', 8);
INSERT INTO `data` VALUES (11675, '_***_', 5, '运行速度:畅快，手机很好，配件齐全，开机试了一下也很流畅，选择的黑色，很大气，模式也很好，可以设置，内存和处理器感觉很好。物超所值，推荐', '亮黑', '2022-12-13 19:39:46', 4);
INSERT INTO `data` VALUES (11676, '1***哥', 5, '京东服务给力超级放心 肯定是正品满意哦 手机很漂亮 很喜欢 大品牌值得信赖京东物流也快 满意好评 对了 拍照也好很是清晰哦', '晴雪', '2022-11-14 20:48:13', 6);
INSERT INTO `data` VALUES (11677, 'n***L', 5, '一直是小米的忠实粉丝，这次也没让我失望。外观很高端精致，使用感系统很顺滑，电池很持久，充电速度也很迅速。双十一价格很给力，发货如果再及时点就更完美了。\n曾在这款和K50之间徘徊不定，还是选择了高通骁龙系统，感觉千元机红米手机就是天花板了吧，个人感觉不喜勿喷。', '晴雪', '2022-11-22 15:17:34', 5);
INSERT INTO `data` VALUES (11678, 'j***t', 5, '小米k40s外形外观好看，颜色鲜艳，本人好喜欢哦，一眼就看中了。声音够大，也没杂音，屏幕亮度可以。拍照清晰度可以，拍照很清晰，很远就能扫码。12+256大容量，反应快不卡机。待机时间长，一天在使用，到晚上充一次电', '晴雪', '2022-12-17 20:29:35', 2);
INSERT INTO `data` VALUES (11679, '这***0', 5, '外观看起来很规整，没有什么惊艳的样子。67瓦快充很棒。与k30相比，电量跟一样4500mm没有变化。像素低了，重量轻了。整体使用没有太大的变化。', '亮黑', '2022-11-04 21:58:23', 8);
INSERT INTO `data` VALUES (11680, '感***缺', 5, 'Redmi K4oS 幽芒登好看的，直角\n边框很精致~\n最近一直在研究着换手机，却不知道换什么好，后来朋友根据我的预算推荐了红米的 K40S 手机，这台手机我使用了一段时间后发现体验\n感真的不错。\n我选择的是幽芒这个颜色，是一种比较特别的颜色，然后配置的话选择了12GB+256GB 的版本，也是红米K40S 的顶配版本，平时存储\n东西和运行软件根本不用担心内存\n不够用的问题。\n红米K40S 搭载了高通骁龙870处理器，实际跑分测试中能够跑到\n75万分的成绩，并且和 LPDDR5\n以及UFS3.1联合起来形成了&ldquo;性能铁三角&rdquo;的组合。\n另外还加入了大面积的VC 也冷立\n体散热系统，能够快速的释放手机的温度。屏幕方面，使用了 6.67\n英寸的三星E4 发光材质屏幕，分\n辦率达到了高清的标准，并且还支持120Hz刷新率，显示效果极其\n丝滑。\n游戏体验上也很不错，像什么X轴线性马达、NFC、红外運控、双扬\n声器都应有竞有，真的玩游戏能&hellip;', '幽芒', '2022-11-09 19:38:47', 6);
INSERT INTO `data` VALUES (11681, '超***眼', 5, '磨砂质感的后背虽然不如陶瓷般温润如玉，却也展现出良好的握持感，十分贴手。\n6.67寸大屏虽说属于主流屏却只装下一个4500毫安的电池，多少有点容量焦虑，幸好随机配备的是一盒67W快充适配器，打消了一半的焦虑感。\n随机配备的还有一个透明软质手机壳，这是小米优秀的的传统了，适配度极高，同时还能显露出漂亮的后盖设计，我选的绿色特别典雅，绝对要显摆一番的。\nMIUI优秀并且出色的换机功能这点一定要说一说，基本上只有最初两三步匹配机型和挑选传送内容需要点击，剩下的都交给系统吧，换机过程就喝杯咖啡得了，换完之后简直跟旧机一模一样的设置，各种APP也不用再重新登陆了，实实在在做到为用户分忧。\n漂亮的后摄模组设计和排布十分漂亮，比前身K40简直是审美上&ldquo;质&rdquo;的提升。\n性价比上无可挑剔，晓龙870的加持和高刷屏辅助，两千左右价位对手屈指可数而且还是12+256配置呢。', '幽芒', '2022-09-14 17:13:55', 7);
INSERT INTO `data` VALUES (11682, 'u***r', 3, '不知道怎么样，帮别人买的', '亮黑', '2022-06-17 23:22:17', 7);
INSERT INTO `data` VALUES (11683, 'j***v', 5, '外形外观：这款手机的晴雪色确实颜值高，带着清水壳都掩盖不了它的美颜。属于男女老少都能用的款式。\n屏幕音效：屏幕显示清晰通透，实测是双声道扬声器。\n拍照效果：我看评论区很少有人晒实拍样张，我随手拍了几张，菜鸟拍照级别，同时给出了华为P40拍照样张的对比图，供大家参考。个人觉得是可以用的水平。\n运行速度：很流畅，骁龙870处理器+12GB大内存确实有用。\n待机时间：中度使用能坚持一天。', '晴雪', '2023-02-19 14:37:31', 7);
INSERT INTO `data` VALUES (11684, '鱼***舞', 5, '外形外观：机身很薄，屏占比比较高，外观很好看。\n屏幕音效：三星E4屏，1080p分辨率，清晰度完全可以满足，双扬声器声音够大。\n拍照效果：只能说够用，反正不经常拍照，无所谓了。\n运行速度：骁龙870一代神U，配合高刷屏幕，日常使用非常畅快。\n待机时间：刚开始用，续航水平有待检验。\n其他特色：相信小米手机的品质。', '幽芒', '2022-08-11 13:15:54', 2);
INSERT INTO `data` VALUES (11685, 'z***4', 1, '孩子一直要，红米k40s 67w快充很赞，半小时就充满，一晚待电100-99，很牛，系统也还好，就是震感不是很强，比理想的厚度略大，可能是直角机身的缘故，总之非常不错，亮度也很棒，出门在外足够看得清，声音很大很响，。外形外观：外观精美，方方正正，比较立体 屏幕音效：屏幕看着不错，比之前真我x好太多，没有拖影，手感很干脆的感觉 拍照效果：拍照一般般，加了ios也就那样，防抖功能拍出来也是有点模糊。 运行速度：运行快，打王者舒服 其他特色：手感不错，没有耳机孔差评', '幻镜', '2022-11-10 22:12:47', 6);
INSERT INTO `data` VALUES (11686, 'v***7', 5, '运行速度：非常流畅\n外形外观：方方正正的，用不来曲面屏，这种感觉很顺手。\n屏幕音效：显示音效效果也不错，这个我要求不高。随机贴好了保护膜，并附赠手机壳，虽说是透明的，但考虑的非常人性化。快递次日达，元旦放假也照送不误，感谢快递师傅', '亮黑', '2023-01-03 12:56:09', 3);
INSERT INTO `data` VALUES (11687, '曾***2', 5, '外形外观：很漂亮。\n屏幕音效：比我之前用的手机音效增强了不少\n拍照效果：很清晰呢。像素高。\n运行速度：12g运行内存。。足够现在使用呢。\n待机时间：如果玩游戏可以6个钟吧！如果就单纯使用，能一天的。\n这台手机打游戏效果还是不错的。', '幻镜', '2022-11-09 23:41:10', 2);
INSERT INTO `data` VALUES (11688, '梦***9', 5, '京东物流给力，到手一天，简单评价一下，初上手感觉重量很友好，屏幕没什么亮点，边框涂色塑料，可以看我的图片，卡槽一打开就特别掉档次，870劳模SOC，无需多言，摄像头组合比较拉胯，不要期望值太高，作为主力手机应该没问题，特别喜欢拍照的，谨慎入手，充电速度不错，结合价格，K40S没有标榜高大上，实打实作为中等机型给出了诚意，可以入手', '银迹', '2022-04-04 22:11:08', 8);
INSERT INTO `data` VALUES (11689, '狗***灰', 5, '买给老人用的，感觉不错，够用两年了，挺好。\n外形外观：喜欢这种直角边\n屏幕音效：挺好\n拍照效果：很清晰\n运行速度：很快，完全够用', '幽芒', '2022-07-13 08:57:14', 9);
INSERT INTO `data` VALUES (11690, '狂***族', 5, '外形外观：外观方正，简洁大方，银色的很好看。\n屏幕音效：屏幕三星E4材质显示效果很细腻，1080p够用了。2k太费电了。\n拍照效果：拍照没要求有相机能扫码就行。\n运行速度：8+128日常用够够了\n待机时间：不玩游戏，撑一天没问题。\n\n其他特色：性价比很高了', '银迹', '2022-08-06 19:25:41', 2);
INSERT INTO `data` VALUES (11691, 'c***5', 5, '非常好，屏幕很好看，颜色很靓丽。机器比较大，很舒服好用。运行速度也是不错的，然后屏幕声音比较好听，通电话很清晰，很好用。然后整体都非常舒服，唯一就是很多小米自身的app。还不错。比较超值。', '幻镜', '2022-05-04 16:57:04', 7);
INSERT INTO `data` VALUES (11692, '西***5', 5, '红米K40S非常有性价比的一款手机：\n机子采用高通骁龙的870芯片，也算是一代性价比非常高的神U。内存12+3GB，存储内存256G。运行速度快，温控效果好。目前线下已经没有货了。自己用的另一款K40也用了将近两年时间。目前运行的速度依然是杠杠的。\n棋子的边框属于直角边框，稍微有点割手。其他充电速度待机时间都非常不错。', '晴雪', '2022-12-17 09:09:46', 7);
INSERT INTO `data` VALUES (11693, '黄***踪', 5, '手机很好，一直都用小米。40S虽然不是最新的，但性价比高，功能齐全，870很好，性能够用，比note啥的新机还要强悍。外观方正时尚，屏幕出色，运行不卡顿，拍照也不错。', '银迹', '2023-01-03 17:44:09', 4);
INSERT INTO `data` VALUES (11694, '挺***呢', 5, '外形外观：轻薄，有质感，很有档次\n\n屏幕音效：屏幕很清晰，音质很不错\n\n拍照效果：很棒，像素很清晰\n\n运行速度：12+256的运行，能足够满足日常需求和游戏\n\n待机时间：4500毫安大电池，够用。\n其他特色：功能很多，2000左右的价格，值得入手。', '晴雪', '2022-10-13 08:56:44', 5);
INSERT INTO `data` VALUES (11695, '平***漠', 5, '收到手机用了两天才来评价，由于之前用的其它牌子手机，要适应小米的系统还是要点时间，但通用功能已经适应，感觉用起来也是很流畅和顺手的。这次是在小米京东旗舰店上买的K40s，一切都很顺利，手机在户外强光下也能清晰发信息，玩王者游戏也很流畅，很好的一次购物体验。', '银迹', '2022-08-15 23:23:18', 9);
INSERT INTO `data` VALUES (11696, 'j***v', 5, '全家人一直用小米品牌，支持国产，k40s性能不错，外观好看，银色的看着很高档，挺不错的，870的的性能，充电67w快充很快就充满了，手机重量195克，很轻薄拿着很方便的，添加了光学防抖，机身厚度7.7毫米', '银迹', '2022-03-31 22:52:45', 7);
INSERT INTO `data` VALUES (11697, '机***落', 5, '商品收到，性价比很高，打游戏不卡，也没有掉帧的情况，拍照还挺清晰的。\n外形外观：漂亮。\n拍照效果：清晰\n运行速度：流畅', '幽芒', '2023-01-13 11:09:51', 4);
INSERT INTO `data` VALUES (11698, 'j***9', 5, '宝贝收到，包装很好，物流很快，以为还得等几天能到呢？没想到两天就到货了，很快，宝贝很好，手机很好用，包装全新的，未拆封，双11买的物美价廉，以后还来京东买电器。', '亮黑', '2022-11-17 19:23:44', 6);
INSERT INTO `data` VALUES (11699, 'j***b', 5, '双11买的手机，正好也是趁活动给老公换的新手机，颜色很耐看，新手机网速也不错，用老公的手机刷个视频刷个淘宝啥的方便快速多了，比我自己的手机还好用，价格很香，同系列手机换的特别方便，直接一键换新所有资料都传输过来了，很不错，老公很开心', '幽芒', '2022-11-20 20:18:58', 4);
INSERT INTO `data` VALUES (11700, '卡***j', 5, '看了好多红米手机，之前购买的是k20机型，6+128的，这次看中了Redmi K40S 骁龙870 比我那k20好，这个屏是三星E4 AMOLED 120Hz直屏 还有OIS光学防抖， 67W快充，关机很快就充满了。这次果断买了最高配12GB+256GB 还是5G智能手机 小米红米不会让每个米粉失望的，值得推荐购买&hellip;&hellip;。', '银迹', '2022-12-26 21:08:41', 6);
INSERT INTO `data` VALUES (11701, 'u***t', 3, '挺好 ，建议去小米之家体验一番谢谢。', '幻镜', '2022-05-03 08:36:20', 0);
INSERT INTO `data` VALUES (11702, '郭***0', 5, '外观设计挺好看的，枭龙870，12+256运行速度快，功能多，性价比超高，电池电量一天使用刚好，一直玩手机的话只能坚持半天，拍照6400万像素拍照起来效果一般，性价比超高', '亮黑', '2022-12-04 16:07:24', 5);
INSERT INTO `data` VALUES (11703, '记***年', 5, '外形外观：颜值挺高的\n屏幕音效：顺畅\n拍照效果：还可以\n运行速度：王者荣耀，和平精英都没问题\n待机时间：挺长的，出门再也不用揣个充电宝了\n其他特色：这款手机真的很棒，我已经安利家里人买了，不管是游戏党，还是给父母用，都是很不错的选择', '银迹', '2023-01-02 21:42:02', 5);
INSERT INTO `data` VALUES (11704, 'c***q', 5, '外形外观：很漂亮，手感很好。\n屏幕音效：显示清晰，音效立体。\n拍照效果：拍照像素杠杠的，高清哦。\n运行速度：新机子嘛，肯定的了，贼拉快咯。\n待机时间：待机一整天没毛病哦。\n其他特色：主主要的，是充电速度简直呼啦快。吃个午饭的功夫，满了。\n新机子，再好的评价也只能参考。先用它两年再说。不过，小米确实性价比非常高。', '亮黑', '2022-12-11 07:20:21', 6);
INSERT INTO `data` VALUES (11705, 'o***g', 5, '外形外观：非常漂亮的外观。\n屏幕音效：oled的屏幕，清晰护眼。双扬声器听音乐也很震撼。\n拍照效果：流畅无卡顿，效果理想。\n运行速度：12+3=15G的运行内存，流畅。256G的储存也足够用。\n待机时间：一整天妥妥的。\n其他特色：充电非常的快。', '晴雪', '2022-11-05 13:08:47', 6);
INSERT INTO `data` VALUES (11706, 'j***8', 5, '外形外观：外观还不错，蓝色的，看上去挺新颖的\n屏幕音效：屏幕很大，很高清，感官还可以的\n拍照效果：拍照效果也不错，超高像素\n运行速度：骁龙870的处理器，很快的，非常不错的', '幻镜', '2022-03-31 18:33:30', 8);
INSERT INTO `data` VALUES (11707, 'd***6', 5, '打气，漂亮好看！性价比非常高！！！\n外形外观：漂亮\n屏幕音效：不错\n拍照效果：不错\n运行速度：快\n待机时间：够用\n其他特色：手感不错好好！！颜色好看非常不错！！！', '幻镜', '2023-01-30 22:45:11', 6);
INSERT INTO `data` VALUES (11708, 'q***3', 5, '第二天中午收到，是原封，开箱的快乐！屏幕惊艳，丝滑流畅，手感也非常棒，这个颜色也好看，三期免息非常可以，870再加上12 G运存，足够日常使用，性价比很高，不玩游戏，选适合自己的！', '幻镜', '2023-03-19 16:25:08', 6);
INSERT INTO `data` VALUES (11709, '王***祥', 5, '外形外观：外观精致，简洁大方，简洁大方 冷暖效果：制冷效果很好\n屏幕音效：立体感很强，相较于红米K30来说提升的太大\n拍照效果：高清图片，水印相机\n运行速度：运行速度特别快，运存特别大，内存也同种产品配置最佳\n待机时间：续航一天没问题', '幽芒', '2023-01-02 19:09:30', 5);
INSERT INTO `data` VALUES (11710, 'j***c', 5, '手机屏幕非常清晰，使用起来十分流畅，性能十分好不能什么软件都没有问题，性价比比较高，相机效果也不错，还是挺中意的', '幽芒', '2022-12-09 21:08:49', 4);
INSERT INTO `data` VALUES (11711, 'z***3', 5, '京东速度杠杠的，双十一第二天晚上到。开机显示，比k30显示效果好，光线柔和。不打游戏不发热，速度吗，不打游戏，没法说，反正日常用，开几个应用都不卡，本来13系统优化的就比较好。拍照效果啊，要求不高，能用就行。性价比很高。', '银迹', '2022-11-12 00:11:55', 7);
INSERT INTO `data` VALUES (11712, '格***n', 5, '外形外观：真的可以说特别漂亮，摄像头我觉得是小米手机里最好看的（个人观点）\n屏幕音效：屏幕很细腻，看起来也挺舒服，双扬声器外放真不错\n拍照效果：性价比中摄像头也算是不错的了\n运行速度：运行速度没话说毕竟主打这个得\n待机时间：待机时间还算可以，快充也挺快\n其他特色：那就是性价比高，红米系列特色', '晴雪', '2022-11-04 02:23:16', 3);
INSERT INTO `data` VALUES (11713, '雨***t', 5, '外形外观：颜色也是经过再三选择，然后选择了这个银色，颜色非常好看，看着很高端大气。\n拍照效果：拍照效果也是够用的哈\n\n运行速度：我选择的这款是12+256的，运行速度还是蛮快的。价格方面，我是用了优惠券之后买的，所以价格也是很便宜，非常的适合学生党，值得推荐', '银迹', '2022-09-01 00:44:09', 7);
INSERT INTO `data` VALUES (11714, '格***Q', 5, '外观高端大气上档次，相机模组很漂亮，120hz高刷lcd屏，杜比音效杠杠的，6400万高清摄像头，中规中矩，运行速度很快，王者荣耀轻松无压力', '晴雪', '2022-11-03 22:05:17', 3);
INSERT INTO `data` VALUES (11715, 'j***m', 5, '外形外观：在几款手机里面纠结了很久，最后挑了这款，选的幻境，颜色很漂亮，老妈很喜欢\n屏幕音效：声音外放很大，在家跳广场舞都用了\n拍照效果：拍照加了光学防抖功能，比我自己的手机拍照效果更好\n运行速度：经典的骁龙870处理器，选的12+256，可惜没有512G的，用起来很顺畅。希望能多用几年！', '幻镜', '2022-07-25 13:12:08', 2);
INSERT INTO `data` VALUES (11716, '酷***8', 5, '非常划算的一次京东自营购买体验，小米手机性价比超高，大小合适，速度很快，色彩鲜艳，内存大，再也不用担心储存空间不足了，声音好听，双声道立体声效果不错！总的来说很满意！', '银迹', '2022-03-23 11:52:38', 8);
INSERT INTO `data` VALUES (11717, '倪***6', 5, '给妈妈买的，屏幕大，用着很顺手，以前妈妈的手机内存小，老说卡，这次给她换个大的，京东上购物真心方便，晚上下单第二天就到了！', '晴雪', '2022-11-03 17:46:26', 5);
INSERT INTO `data` VALUES (11718, '鬼***5', 5, '外形外观：外形美观\n屏幕音效：屏幕好，音效棒\n拍照效果：拍照清晰\n运行速度：运行速度快\n待机时间：待机时间长\n其他特色：好用\n感谢京东自营，感谢京东快递，物流速度非常快，隔天就到了，品质有保障，用起来很好，非常不错的一款智能手机，\n推荐推荐推荐推荐推荐推荐', '亮黑', '2022-08-11 08:25:12', 7);
INSERT INTO `data` VALUES (11719, '关***哥', 5, '外形外观：绿色真的非常好看哦，外观精致，厚度重量刚刚好。\n屏幕音效：双扬声器，音效特别好。\n运行速度：运行速度非常快，画面清晰，过度动画流畅。\n待机时间：电池还可以，给妈妈用，主要场景是家里，完全够用，而且充电速度快。', '幽芒', '2022-08-13 19:58:03', 5);
INSERT INTO `data` VALUES (11720, '毛***腐', 5, '2000以内拿下活动后顶配已经具备较高的性价比了，一支完全可以满足平常使用场景的手机，作为备用机很值，待机比较出彩在意料之内，毕竟1080的屏还是比较省电的，比较轻巧，这比手上的13香pro轻不少，侧边开关按键集成的的指纹也很灵敏，我不喜欢品下指纹那种，App速度也都挺快，我不玩游戏，足够了，拍照效果一般，但对于随手拍拍的场景也是够用的。', '亮黑', '2022-08-14 16:56:42', 3);
INSERT INTO `data` VALUES (11721, '马***哥', 5, '外形外观：轻薄。唯美。真的不输红米K50。\n屏幕音效：屏幕效果完美，音质非常的棒。\n拍照效果：拍照效果虽然不能跟旗舰比，但是在同价位仍然是佼佼者。\n运行速度：运行速度飞快，值得推荐。我买的是12G运存版本。\n待机时间：正常使用待机一天没有问题。\n其他特色：骁龙处理器在玩很多游戏的时候有优势。', '幻镜', '2022-12-22 06:58:17', 3);
INSERT INTO `data` VALUES (11722, '象***拔', 5, '外形外观：这个外观挺好看的\n屏幕音效：音效挺好听的音量也很大\n拍照效果：效果很不错前置和后置摄像头都好\n运行速度：买的比较配置高 运行挺好的\n买给父母的用了一个月了吧 用着蛮好的 小米手机还是蛮不错的', '幻镜', '2023-02-05 11:42:49', 2);
INSERT INTO `data` VALUES (11723, 'u***r', 5, '运行速度可以了，这CPU对我们这些不打游戏的人来说完完全全够用，也玩过游戏，运行无压力，运行内存也够大，储存内存也够多。屏幕显示效果很好，拍照中规中吧，两个扬声器效果可以，充电速度也很快', '幻镜', '2023-02-05 01:09:21', 3);
INSERT INTO `data` VALUES (11724, '青***子', 4, '一天很快收到货，京东物流配送不是一般的快，这个真的要点赞??，隔壁邻家小朋友要我推荐购买，我先开箱尝新，这个870比我之前用的888一加的运行吃鸡王者要稳定的多，发热明显要好很多，可能这台设计vc散热起到了很好作用，还有防抖也很不错，拍照清晰度质素和3000以上的也不差，后面摄像头的设计很有档次，打游戏扬声器很干净清楚，颜色是我喜欢的，冷银色很有科技感，很cool ，手机手感也很棒，套壳后感觉颜值和手感要差很多，屏幕虽然不是2k的，但是这个价位用三星a4 amoled 120hz高刷也是可以了，游戏和图片效果也是没得说，一般大型游戏或多个app 运行是不会卡顿的，我想小朋友用的话三年应该问题不大，有点遗憾的没有选择12+256的，不应该省这点钱，现在小米的质量我觉得还是有保障的，有点羡慕现在的孩子可以用上这么高大上的手机，想当年我们只能在地里玩泥巴捉泥鳅，哈哈哈，历害了！', '银迹', '2022-09-18 22:26:35', 6);
INSERT INTO `data` VALUES (11725, 'j***9', 5, '给老丈人换的新手机，老手机太卡了，也用了四年了，趁着双十一换一台。选来选去看中了K40S，搞活动顶配只要1669，直接拿下，同品牌换机也很方便，十分钟搞定。老丈人说新手机刷健康通快多了，一下就能把健康码调出来。', '亮黑', '2022-11-24 00:08:31', 9);
INSERT INTO `data` VALUES (11726, 'j***z', 5, '外形外观：美观\n屏幕音效：这个根据个人情况\n拍照效果：高清摄像，\n运行速度：非常划算的一款产品，运行内存12+258G储存内存\n待机时间：超长待机\n其他特色：充电速度非常超级快，不到一小时就满电', '幻镜', '2023-01-16 15:29:35', 5);
INSERT INTO `data` VALUES (11727, '情***8', 5, '外形外观：外观很漂亮，很大气上档次，非常喜欢\n屏幕音效：滴滴滴的声音好听\n拍照效果：拍照效果不错，非常清楚\n运行速度：运行速度快，犹如火箭一般\n待机时间：待机时间长，不用担心电量问题\n其他特色：太多太多特点，特色了，还得各位大佬亲自体验', '晴雪', '2022-12-31 07:31:28', 2);
INSERT INTO `data` VALUES (11728, '为***别', 4, '外形外观：家族设计 不做过多评价 好看的觉得还可以 不喜欢的就会觉得很丑\n屏幕音效：屏幕很不错 现实不比我的11pro差 这方面的堆料还是可以的\n拍照效果：如图我拍的样片 还是很清楚的 还不错 比较好看\n运行速度：刚开始都不错的 但是有点烫手哦玩游戏的话\n其他特色：直屏的我很喜欢 我不喜欢曲屏的 这个我很喜欢', '幻镜', '2022-11-13 09:00:02', 5);
INSERT INTO `data` VALUES (11729, '迪***少', 5, '外形外观：我喜欢的金属外观\n屏幕音效：杜比声很好\n拍照效果：日常绝对够用，不追求太多\n运行速度：非常快', '幻镜', '2022-08-18 21:42:49', 7);
INSERT INTO `data` VALUES (11730, 'l***9', 5, '特地用了一段时间才来评价，上手非常的舒服，速度也非常的快，618买的非常超值，大爱！！！\n外形外观：好看，单手拿着也挺舒服。\n屏幕音效：可以开启杜比全景声，好。\n拍照效果：好，自带美颜。\n运行速度：快，希望能保持两三年\n待机时间：不打游戏，常规使用一天没什么问题。', '亮黑', '2022-07-06 22:02:38', 2);
INSERT INTO `data` VALUES (11731, '天***士', 5, '外形外观：外形设计美观，轻薄，很大气\n屏幕音效：屏幕清晰，看着舒服，音效很不错\n拍照效果：拍照清晰，相机好用\n运行速度：运行速度流畅，不卡顿\n待机时间：待机时间长，用一天没问题\n其他特色：价格实惠，物流快', '幻镜', '2023-03-18 17:42:08', 4);
INSERT INTO `data` VALUES (11732, '3***g', 5, '外形外观：大气\n屏幕音效：显示效果很好，设置的暖色护眼杠杠滴\n拍照效果：焦距清晰，防抖很实用\n运行速度：12+3  速度飞起来\n待机时间：出色', '亮黑', '2022-11-13 23:32:54', 5);
INSERT INTO `data` VALUES (11733, 's***蔡', 5, '外形外观：外观是黑色的，后盖不太容易粘指纹。手机尺寸很合适。声音很大。音质也很好。\n屏幕音效：会震动。\n拍照效果：自带美颜功能。\n运行速度：运行没有问题，很快。\n待机时间：还没有试。', '亮黑', '2022-03-30 14:11:20', 4);
INSERT INTO `data` VALUES (11734, '不***来', 4, '看了几天，还是选择这个K40.各方面配置均衡，用起来流畅，不卡顿，电池充电速度非常快，这个快充果然不是吹的。价格也很合适，处理器不算差，怎么也能用几年，上一部小米还是9SE，小米值得信赖。', '亮黑', '2023-01-05 22:35:32', 3);
INSERT INTO `data` VALUES (11735, 'c***4', 5, '送货速度快，外包装完好。红米K40s也是去年千元级的神机，目前也是性价比很高的一款千元机，充电快，屏幕大，运行内存可达12G，看介绍，机器内部还可增加3G，总共可达15G，所以运行大型软件及多软件运行很流畅，指纹识别也快，是千元机中佼佼者。', '幻镜', '2023-03-08 07:05:12', 3);
INSERT INTO `data` VALUES (11736, 'i***樣', 5, '收到货了，双十一买的，便宜不少，物美价廉，送货速度是真的快！运行流畅，剩下的就是我来挖掘它的潜力了，一代神U高通870真不是盖的！', '晴雪', '2022-11-13 19:05:12', 7);
INSERT INTO `data` VALUES (11737, 'w***6', 5, '外形外观：完美幻境\n屏幕音效：动听动听\n拍照效果：清晰\n运行速度：流畅\n待机时间：够用一天', '幻镜', '2023-01-09 21:59:02', 6);
INSERT INTO `data` VALUES (11738, '乘***0', 5, '运行内存12G+3G,存储空间256G，再也不用担心内存和存储空间不够了，高颜值，高品质，运行速度很快，做工精细，音量音质非常好，一分钱一分货，材质外观和质量一看就很上档次，非常喜欢', '亮黑', '2022-09-22 22:07:16', 6);
INSERT INTO `data` VALUES (11739, 'j***4', 5, '外形外观：很漂亮，简约大气\n屏幕音效：效果细腻，声音清脆，\n拍照效果：像素高，清晰度很高\n运行速度：像做飞机一样的感觉真好啊', '亮黑', '2022-03-30 19:19:52', 5);
INSERT INTO `data` VALUES (11740, '萍***p', 5, '618买的，用了10多天，感觉很好，67w快充，充电很快，\n运行速度：快\n拍照效果：很好\n外形外观：美观大方', '幻镜', '2022-07-08 22:34:22', 2);
INSERT INTO `data` VALUES (11741, 'm***7', 5, '2021年买的K40，非常满意，2022年升级K40S,散热升级到了VC液冷散热，游戏体验更好。充电从33W升级到了67W，添加了OIS光学防抖，机身厚度7.7毫米，机身重量195克，很轻薄，果断入手，确实没有让我失望。也看过朋友的K50,太厚了。', '亮黑', '2022-03-29 10:28:44', 6);
INSERT INTO `data` VALUES (11742, '穆***羔', 5, '给家里老人换的手机。特意买了soc强的。希望能用久一点。小米换机非常方便。充电快。电池大。手感非常好！', '晴雪', '2022-11-06 07:30:02', 9);
INSERT INTO `data` VALUES (11743, 'j***L', 1, '买手机之前先看了评论区，面对50万+的评论区，看到了占比4%的中差评，但是好评底下的跟评贬大于褒，一开始我是比较担心的。可是，今天早上到货之后用了一整天，一切担心都消失了。朋友们尽管放心买，绝对没有毛病。我觉得是完全物美价廉物超所值的，卖2700我都接受，何况我是1774就拿下了（新用户）。手机式样是我自己选的，很好看很喜欢。配套的手机壳和手机切合程度高，手机膜也清晰可见，不太担心手机会摔的问题。刚刚拿到手机时候是42%电量，系统帮我装好了喜马拉雅、番茄免费小说、淘宝、微博、***、快手、今日头条、小红书、拼多多、哔哩哔哩、高德地图、抖音、***、知乎等软件。大部分是在系统自动装的范围，但是也好像有一两个不在其中，存在手机曾经被退货并被前一任购买者安装软件的可能性（不确定）。但是不管它也没有被用过，我用了一天没出现卡机、黑屏、卡屏的情况，也不知道那些人的好多怪诞说法哪来的。我的体验是非常非常非常好，装什么软件卸载什么软件都非常快。最大亮点就是充电和耗电了。反正我开机状态放了接近4小时，电量只少了5%左右。充电那块，一个字:快，两个字:光速。没见过那么快的充电好吧，太让我放心了。顶顶顶！', '幻镜', '2023-01-27 00:40:27', 5);
INSERT INTO `data` VALUES (11744, '丿***森', 5, '屏幕音效：很清晰，音质也不错\n拍照效果：像素很OK\n运行速度：很流畅，打游戏无压力\n待机时间：正常一天一次', '银迹', '2022-11-04 14:46:54', 1);
INSERT INTO `data` VALUES (11745, '上***孩', 4, '外形外观：挺有格调的，很喜欢！\n屏幕音效：屏幕挺好的，音质也挺好的！\n拍照效果：拍照效果挺好，比起旗舰机来差一些，不过对于我来说很满意了！两个手机替换着用很好！\n运行速度：米UI13的加持，特别流畅！12用着很难受，换到13特别棒！\n待机时间：待机时间不错，我不买2k屏，就是这个原因了！\n其他特色：手感很轻薄，亮黑色的也挺好看的！', '亮黑', '2022-03-25 17:39:44', 5);
INSERT INTO `data` VALUES (11746, '饱***生', 1, '为什么买它，性价比超高好吧。买给妈妈使用的。目前使用没啥不好的，非说不行，就是屏幕不太ok。长辈反馈亮度太低会折磨眼镜。870芯片，不要太好。67瓦充电速度杠杠的。12+256顶配版本。不玩游戏，偶尔拍照，这款手机对于父母长辈来说完全够用了。中低端用户，小米做的非常好。考虑很周到。高端用户群体我不评价。希望小米越来越好。更上一层楼。', '幻镜', '2023-02-11 12:45:57', 7);
INSERT INTO `data` VALUES (11747, 'H***6', 5, '手机收到了，质量很好，外观大气，运行速度快一如既往的好品质，非常喜欢的一款产品，非常棒！o(*￣︶￣*)o已经用过一段时间了，效果不错?，客服服务有耐心，解答详细，赞一个质量很过关，品质有保障，相当不错的选择，好多朋友看我用都想买，我都推荐了', '晴雪', '2022-11-13 12:24:04', 3);
INSERT INTO `data` VALUES (11748, 'p***3', 5, '用了快半个月，体验还可以。手机整体很好看，尤其是白色的后盖。屏幕显示效果也可以，可以设置高刷新率的。12+256的配置足够日常使用，疫情期间扫码做核酸，网上学习必备。', '晴雪', '2022-11-23 20:33:24', 4);
INSERT INTO `data` VALUES (11749, '龙***a', 5, '宝贝已收到，谢快递小哥，辛苦了。第二次买K40了,这次k40s,\n外形外观：美观大方。\n屏幕音效：屏幕鲜艳看了舒适。音效很好。\n拍照效果：清晰亮丽。\n运行速度：非常快。\n待机时间：我用一天半左右吧。会推荐给朋友，小米?', '亮黑', '2022-09-22 13:51:07', 2);
INSERT INTO `data` VALUES (11750, '艾***A', 5, '外形外观：方方正正像块砖，哈哈哈\n屏幕音效：屏幕显示非常好，音效2.0简直棒\n拍照效果：很清晰变焦快\n运行速度：还是很快很流畅，开了120hz还是很爽\n\n待机时间：待机时间：一般般，没有快充会很伤。\n手机外观还是很行，k50的模具比40个人觉得好看不少，就是870，唉，三星太拉了。', '银迹', '2022-07-01 18:03:40', 5);
INSERT INTO `data` VALUES (11751, '此***帅', 5, '给妈妈买的，充电速度很快，三四十分钟就可以充满\n续航能力:很好\n拍照效果:清晰，虽然没有其他主打拍照的经验，但13系统的后期插件还是可以弥补的。\n运行速度:畅快\n870的处理器，可以满足日常所有软件\n物流简直神速，第二天就到了，拿在手里感觉很棒，显\n示效果细腻，续航持久，快充给力，水桶机不二之选，这个价位没有对手!\n不足:塑料边框，侧指纹解锁，容易刮花，没有无线充电。', '幻镜', '2022-11-12 19:22:47', 5);
INSERT INTO `data` VALUES (11752, 't***0', 5, '之前给老妈买的红米7有年头了，有点卡，已经跟不上老妈的速度了，年后想着赶紧给换台新机。\n我妈主要的功能需求其实也不多，无非是刷刷抖音，聊聊微信，拍拍视频照片。预算千元机，太高也是性能过剩，主流屏幕，处理器要能跟上节奏，内存打底8G，存储打底128G，另外想着屏幕分辨率要1080打底，并且一定要有护眼功能，毕竟刷抖音的时间太多了，同时想着3年内不用换机，有了明确的目前就好办多了。\n购机前做了不少功课，品牌上无非荣耀、小米、oppo、vivo这几个，其他的不考虑，再按照预算，从配置上做横向对比，最终发现红米的K40S是预算内性价比是最高的，重量手感不错，背壳很绚丽，12+256，高通870，三星+康宁大猩猩屏，1080分辨率，相机还带防抖功能，完全可以媲美其他家3k左右的手机，真心很赞，本来打算入手8+128，不过已经没货了，最终以高性价比的价格拿下了12+256，很开森。\n老妈拿到手机很满意，赶紧研究去了，人脸识别秒开，导致她一度认为手机没有锁屏密码，可爱的老人家?', '幻镜', '2023-02-09 19:18:51', 5);
INSERT INTO `data` VALUES (11753, '蚂***1', 5, '运行速度：12+256运行内存，玩游戏聊天，都丝毫不卡，很好用！\n外形外观：银色的外观，远看如水，近看如雾??，非常好看。\n屏幕音效：音效很棒，立体环绕声效果很好，值得入手！\n拍照效果：拍照效果拉满！很适合年轻人用！', '晴雪', '2022-11-20 13:06:50', 4);
INSERT INTO `data` VALUES (11754, 'f***8', 5, '运行速度：手机很流畅而且打开也很快，小米手机的质量还是可以的，最让我惊喜的是这个K40s额外送3g的运行内存，就是12+3的内存，好意外啊！会一直用小米，希望越做越好，支持小米！', '亮黑', '2022-09-08 21:00:52', 3);
INSERT INTO `data` VALUES (11755, 'j***9', 5, '外形外观：外观其实还可以。只是拍照哪里不是很好看，其他的都很不错\n屏幕音效：很清晰\n拍照效果：拍照效果也不错，满足日常需求\n运行速度：很快，性价比很高', '亮黑', '2022-09-03 19:34:19', 2);
INSERT INTO `data` VALUES (11756, 'a***1', 5, '手机性价比很高，如果把相机再升级一下就好了，使用起来感觉还可以，没啥问题！相比K40升级了充电速度和光学防抖，升级的不多！但是对于这个价格确实是非常不错的啦！！！', '幻镜', '2022-07-24 19:00:10', 7);
INSERT INTO `data` VALUES (11757, '京***飞', 5, '网上做了好多功课，看了好多测评，选择了这款红米手机，使用了一段时间，不玩游戏，正常使用，运行速度很快，电池两天一充，对我这种手机轻度使用者来说，性价比很高，各方面都很满意！', '幽芒', '2022-12-27 11:20:44', 2);
INSERT INTO `data` VALUES (11758, 'x***0', 5, '红米k40s京东快递到货就是快，手机方方正正的很好看，很轻薄，拿在手里很有手感，67w的，充电速度特别快，好用。', '亮黑', '2022-07-23 12:49:07', 4);
INSERT INTO `data` VALUES (11759, '顺***8', 5, '手机收到了，挺好的，用着很流畅，显示分辨率很高，很细，很清晰，下载挺快的，高端大气上档次，不错，希望商家多搞些优惠活动，我下次还在这里买希望可以用5年！！！', '幻镜', '2023-01-22 09:06:43', 7);
INSERT INTO `data` VALUES (11760, 'F***n', 3, '外形外观：外观比红米note 11T pro要好看的多，背板是玻璃的，中框是塑料的，白色很好看\n屏幕音效：屏幕色彩鲜艳，比LCD屏饱和度高的多，看久了并没有不舒服的感觉。音效真的一般般，还没有iPhone 6s的单扬声器效果好，听个响吧全是。\n拍照效果：还凑合，能用，不能说好，也不能说不好。\n运行速度：很快，尤其是网速快，信号好。同样的环境下，无论是5G信号还是WiFi连接速度都比iPhone好的多。\n待机时间：一天一冲，好在67W充电速度特别的快，没有什么电量焦虑，喝口水，上个厕所，随便干点什么，回来一看电池充满了，最满意的一点。\n其他特色：一定要跟着教程关闭广告，并且用一点时间来管理通知和权限，操作完了你会发现这手机好用的很！纯净的很！', '晴雪', '2022-11-16 10:04:11', 4);
INSERT INTO `data` VALUES (11761, '杰***融', 5, '非常舒服的直屏手机，\n外形外观：好看，\n屏幕音效：好\n拍照效果：好\n运行速度：快', '幻镜', '2023-03-14 13:54:09', 2);
INSERT INTO `data` VALUES (11762, '0***0', 5, '物流很快，包装精美完好无损，手机质量好，外观漂亮好看，握着手感好，卖家服务态度好，耐心解说，屏幕色彩靓丽，显示效果很好，，内存运行速度快，网速流畅不会卡，像素高拍照清晰，支持面部和指纹解锁，充电速度快，电池待机久，关键价格很实惠，物超所值。', '亮黑', '2022-11-14 00:08:22', 2);
INSERT INTO `data` VALUES (11763, '那***猪', 5, '红米手机里难得的轻薄机，7.7毫米厚度，195克，握持手感非常棒，不割手，电池4500毫安时日常使用起来绝对够用了，续航还可以，67 W闪充充电速度也很快，摄像也很清晰，屏幕素质也很棒，我愿称之为1800档位最强神机。', '晴雪', '2022-11-12 15:13:26', 2);
INSERT INTO `data` VALUES (11764, '逗***6', 5, '双11活动力度大，主播也卖力，小米红米手机性价比还是比较高的，质量也不错，这次买了个晴雪色的，颜色也耐看，也好看，几款手机最后还是选这款k40s,芯片是骁龙870，也够用了，非常满意。', '晴雪', '2022-11-13 20:01:00', 3);
INSERT INTO `data` VALUES (11765, '云***华', 5, '手机很好用啊，很好用啊，很好用。用红米手机好几台了，给父母也购置了，给老婆也买了，这款手机的性价比是很高的，用起来非常的人性化，各种功能很实用，而且呢价格还不贵，在同样的价格下呢，这款手机使用的是相当的给力，推荐给大家玩游戏，办公娱乐日常应用都很不错，看视频快的不要，不要的空间还大推荐购买。', '幻镜', '2023-02-28 20:00:38', 5);
INSERT INTO `data` VALUES (11766, 'j***l', 5, '京东物流就是快，下单第二天就收到了，67 w快充骁龙870处理器，运行速度很快很流畅，本人不玩游戏足够用，这个价位手机可以了', '亮黑', '2022-08-11 11:53:08', 5);
INSERT INTO `data` VALUES (11767, '2***a', 5, '外形外观：整体看着还行，银色很好看，厚度也可以\n屏幕音效：双扬声器音质不错，屏幕也很清晰，高刷体验好\n拍照效果：不算强，但能接受\n运行速度：大运存和870配合起来很顺畅\n待机时间：电池也很耐用', '银迹', '2022-08-19 17:44:30', 4);
INSERT INTO `data` VALUES (11768, 'j***e', 4, '手机性能：拍照一般 续航很好 运行畅快\n用过几个小米手机了，感觉都不错。这款买来做备用机\n要求不高，1749入手非常划算。AMOLED屏幕显示很好\n看着非常舒服;双扬声器听觉体验加分，看视频啥的会\n自动开启杜比音效：熟悉的MIU系统，\n人性化设计体验\n很好;骁龙870虽然是上上代处理器，不过运行依旧流\n畅，完全能满足日常或基本游戏使用：\n4500毫安电池搭\n配67W快充作为主机使用也完全没问题，联网待机12小\n时掉电3%：\n，拍照方面个人感觉满足日常使用，\n专业摄影\n可以选择更好的\n比起目前使用的两年前手机的40MP似\n平还差一点：\n外观颜值方面是最为喜欢的，非常漂亮\n后盖尤为突出，\n幻境渐变，镜子般的感觉非常nice。\n到\n货至今大半个月\n整体体验很好，这个价真的非常值，推\n荐入手。唯\n不足就是屏幕底部的黑线，咨询茗服说是導\n航方式的原因，希望可以去除，好端端的非加条不小的线\n看着别扭，难不成有什么用吗？好了、到此为止，\n不同\n手机不同使用环境会有细微差别，想入手的可以参者\nFo', '亮黑', '2022-12-25 09:45:12', 4);
INSERT INTO `data` VALUES (11769, 'y***g', 5, '外形外观：很精致 很漂亮\n屏幕音效：屏幕音效效果很好\n拍照效果：很清晰 很漂亮\n运行速度：非常快', '幻镜', '2023-03-15 22:01:28', 5);
INSERT INTO `data` VALUES (11770, '铅***泪', 5, '外形外观：直屏好看，幻境颜色也很好看\n屏幕音效：屏幕显示细腻，e4屏很不错\n\n拍照效果：4800w像素，加防抖，真的够日常用了\n12+256的配置，绝顶，很不错，主力机很强悍了\n一拿到就拿旧手机导数据，很快', '幻镜', '2022-11-10 09:41:31', 4);
INSERT INTO `data` VALUES (11771, 'B***8', 5, '手机用的很好，手机壳很漂亮，手感很好，外观很漂亮\n?宝贝收到了，很惊喜?，设计合理，时尚大方，继续关注，以后会回购的???绝对是最开心的一次购物，店家服务态度很好，售后也是', '银迹', '2022-12-13 18:03:47', 2);
INSERT INTO `data` VALUES (11772, 'z***o', 5, '京东送货超级快，原封正品。870处理器，12+256顶配，一般使用没问题。120hz OLED屏幕，显示非常好。4800万ois光学防抖满足日常拍照记录。4500mAh搭配67W超级快充，中度使用一天还剩下不少电量。杜比视界，x震动马达，红外遥控，全能NFC...日常需要的一样都不少。', '幽芒', '2022-11-17 18:57:01', 5);
INSERT INTO `data` VALUES (11773, '鸣***7', 5, '买来就迫不及待的打开了，各方面都符合我的预期，关键价格还便宜。又得用个好几年。\n外形外观：好看\n屏幕音效：高刷很赞\n运行速度：快\n待机时间：中度使用一天没问题，我不打游戏。', '银迹', '2022-04-19 16:24:23', 5);
INSERT INTO `data` VALUES (11774, '独***9', 5, '手机包装很严密，盒子用薄膜密封，打开手机进入一步步设置画面，从这些细节可以判断是新出厂的。手机设置很容易，也很好用，因为我不玩大游戏，所以感觉速度很快。显示颜色很正。打开手机时显示50%电量，设置安装完软件后基本用完，充电非常快，一个多小时就充满了。', '幻镜', '2023-03-02 19:15:56', 5);
INSERT INTO `data` VALUES (11775, '超***蛋', 5, '用了8个小米红米手机，这个K系列是用的最丝滑的。买的12+256在前两天入手的。手感非常好。是方方正正的外观。系统一如既往地丝滑。再用用会继续再次给大家分享使用的感受。一如既往地支持性价比超高的红米系列。希望能够越做越好。国产之光。', '银迹', '2022-11-10 12:11:20', 4);
INSERT INTO `data` VALUES (11776, '-***-', 5, '外形外观：外观好看，硬朗的线条，手感很好\n屏幕音效：屏幕显示效果很好，色彩鲜艳。立体声很赞\n拍照效果：AI拍照的加持，虚化的过度很不错。光学防抖再也不怕帕金森式的手抖了\n运行速度：12G内存流畅运行，不够可以再加3G虚拟内存\n待机时间：新机待机一天\n其他特色：870神u加上MIUI，最好的事情即将发生', '银迹', '2022-05-12 23:30:05', 8);
INSERT INTO `data` VALUES (11777, 'j***花', 5, '外形外观：外观好看，直板手机看着不错，\n屏幕音效：显示效果很奈斯，很细腻，\n拍照效果：还行，相对于这个价位来说，很超值了，\n运行速度：运行速度很流畅，非常丝滑！\n待机时间：还可以，耐用，\n其他特色：各方面都很可以！', '亮黑', '2022-12-13 13:29:48', 4);
INSERT INTO `data` VALUES (11778, 'j***d', 5, '红米K40s是一款性价比非常好的手机，875高通骁龙旗舰主力机型，大屏幕，电池容量，运行内存大，非常好的购物体验', '幻镜', '2022-12-25 09:01:03', 9);
INSERT INTO `data` VALUES (11779, '耀***2', 5, '手机外形不错，音质非常好，拍照效果也很清晰，运运行速度比较快，非常喜欢，待机时间还好，一天不用充电。看电视剧的效果也非常nice', '幽芒', '2022-11-14 15:11:48', 2);
INSERT INTO `data` VALUES (11780, 'L***o', 5, '新手机收到，对比了40和40s，还是选择买新不买旧的原则，入手了40s，对比了一下拍摄的清晰度，感觉比我之前用的iphone8p清晰不知道多少，运行速度也很快，电池续航跟苹果比就更不用说了！13年用过的米，现在重新入手米感觉不错?', '亮黑', '2022-03-28 15:53:43', 6);
INSERT INTO `data` VALUES (11781, 'h***8', 1, '外观好看，屏幕感觉非常结实，摔了很多次都没事，真心不错的选择，拍照效果特别好，比红米K40好很多，运行速度也特别快，买红米K40S感觉非常满意。红米K40S外观很有档次，对比老款红米，直角线条的设计看起来更高档，屏幕显示特别细腻，120Hz高刷玩游戏很爽，拍照超级棒，拍视频的电影效果赞到不行，运行特别快，同时运行十多个软件都不卡。', '幻镜', '2023-01-14 20:41:25', 5);
INSERT INTO `data` VALUES (11782, '不***告', 5, '外形外观：滑溜溜的，质感超级好\n屏幕音效：立体音效，一点都不亚于其他牌子的手机，打游戏也更带劲了哈哈哈哈哈哈\n拍照效果：一流，都不知道怎么形容了，高清，绝了\n运行速度：不卡哦，运行速度贼快，同时开几个后台都还是很快，还不发烫', '晴雪', '2022-11-10 20:32:43', 5);
INSERT INTO `data` VALUES (11783, '幸***7', 5, '总体感觉不错，双十一下单收到，颜值爆表，运行速度快，电池能用六七 个小时，待机时间长！手机收到后，打开包装一看，感觉非常惊艳，手机做工精细，包装规范，试试功能非常流畅。拍照清晰，运行不发热，极速充电，外观好看，色彩饱和度不错，手感不错，系统流畅，正品，界面美观，屏幕很大，手机很好，分辨率高满意京东品质有保证是正品满意！', '晴雪', '2022-11-24 14:35:20', 6);
INSERT INTO `data` VALUES (11784, '木***风', 5, '外形外观：精致\n屏幕音效：超清，超滑\n拍照效果：杠杠滴\n运行速度：从未见过如此之快的手机', '亮黑', '2022-08-12 22:07:09', 2);
INSERT INTO `data` VALUES (11785, '俺***云', 5, '外形外观：立边不割手，又比机身圆润的要更有手感，拿在手里不会感觉手机会溜走。\n屏幕音效：双扬声器，细节满满，立体声环绕，外放效果在这个价位相当不错了。\n拍照效果：小米的拍照，还有待提高。\n运行速度：骁龙870，12+256，这速度，嗷嗷的。\n待机时间：新机很猛，希望电池不会过早衰退。\n一下子买了2部手机，很喜欢，这个价位的，可以了。', '银迹', '2022-11-14 21:06:28', 5);
INSERT INTO `data` VALUES (11786, '小***急', 5, '外形外观：我选的全黑，还挺好看的\n拍照效果：比之前买的8Pro好点\n运行速度：毕竟处理器好，运行很快\n充电速度特别快，67w的充电器', '亮黑', '2022-04-17 12:32:00', 6);
INSERT INTO `data` VALUES (11787, '只***-', 5, '还是很可以的\n运行速度：没得说，很快\n待机时间：待机时间很不错，耗电速度略快，充电弥补了短板\n屏幕音效：屏幕很清晰很好', '晴雪', '2022-08-08 08:54:05', 1);
INSERT INTO `data` VALUES (11788, '诚***家', 5, '手机新机，反应很快也很灵敏，手感不错，做工也挺好的，重量比之前的机型来说，减轻了很多，拿在手里，，手感很好！', '晴雪', '2022-11-07 14:20:02', 3);
INSERT INTO `data` VALUES (11789, 'j***e', 5, '小米红米K40S手机，三星屏，清晰画面细腻，玻璃后壳，手感滑爽，外观简约大气，漂亮，骁龙870处理器，12g运行，网速快，流畅自然，256G大内存，储量足，非常好用，自营品质，一如既往！', '幻镜', '2022-10-04 21:38:58', 5);
INSERT INTO `data` VALUES (11790, '馥***林', 5, '给我老爸买的手机，配置还挺高的，内存12G，256得存储空间，用起来都很流畅，这款手机目前已经属于清库存的情况了，所以优惠力度特别的大，物超所值，希望质量继续好吧！期待他的表现。', '银迹', '2023-01-30 17:05:58', 7);
INSERT INTO `data` VALUES (11791, '****8', 3, '手机真的很不错，快递嘛，呵呵', '亮黑', '2022-05-31 07:50:47', 7);
INSERT INTO `data` VALUES (11792, 'j***y', 5, '红米K40S幻境 12+256手机，超高性价比游戏手机，比小米商城和小米之家都划算点，高通骁龙870处理器，三星E4AMOLED直屏，最高激发亮度1300尼特，120赫兹高刷，DC调光护眼防闪烁，画质显示细腻清晰，红外万能遥控，NFC，液冷散热，67W快充，主摄OIS光学防抖，功能全面，京东物流速度很快，购物体验很好。', '幻镜', '2023-01-31 00:49:58', 6);
INSERT INTO `data` VALUES (11793, 'j***y', 5, '外形外观：第一次买红米的手机，挑了好久，相中了这款白色的，颜值真的赞?\n屏幕音效：上下都有扬声器?，不错\n拍照效果：拍照就扫码级别啦，反正我也不怎么拍照，当备用机来自\n待机时间：够用，白天上班不怎么玩，有时候两天一充完全没问题，\n运行速度：流畅不卡，我玩LOL手游没压力，\n其他特色：充电真的快，比苹果好太多了；特别喜欢它的充电速度和隐私保护！', '晴雪', '2022-07-06 23:18:22', 5);
INSERT INTO `data` VALUES (11794, '抽***仙', 4, '拍照效果: 一般般，本来也不是冲着拍照去的\n续航能力: 还行，就正常水平差\n运行速度: 畅快，非常流畅，满分\n用过几个小米手机了，感觉都不错。这款买来给老人用的，要求不高，双十一活动价非常划算。 AMOLED屏幕显示色彩没问题，频闪没办法通病； 双扬声器听觉体验加分，看视频啥的会自动开启杜比音效； 老人之前用的也是小米，MIUI人性化设计还行，好用； 骁龙870一代神U运行依旧流畅，完全能满足日常；67W快充不太给力，不过老人用也足够；外观颜值非常漂亮，质感非常好。\n好评', '亮黑', '2023-01-06 09:46:00', 4);
INSERT INTO `data` VALUES (11795, '阳***y', 5, '我非常喜欢我买这个淡淡的颜色，手感也不错，屏幕很清晰，运行很流畅，还有67瓦的充电速度，非常的棒，侧边指纹解锁超级可爱，一下子就解锁了，还可以设置两个以上的面部解锁，非常爱，非常棒，有我想要的那种感觉，质感也很不错，摸起来非常的舒服，不轻不重，大小合适，性价比非常的高，值得入手，各方面都比较满意，谢谢9', '幻镜', '2022-09-15 08:25:41', 6);
INSERT INTO `data` VALUES (11796, 'j***c', 5, '双十一买的，物流还是一如既往的快。\n外形外观：外观棱角分明，重量还可以，手感非常好。\n屏幕音效：屏幕显示挺好，立体声音效非常棒。\n拍照效果：拍照还可以吧，要求不高。\n运行速度：运行速度：运行速度 快，很快。\n待机时间：正常使用一天吧，不过67W的快充很棒，40分钟充满。。', '幻镜', '2022-12-02 23:05:30', 5);
INSERT INTO `data` VALUES (11797, 'Q***o', 5, '服务好、发货快、包装整洁、隔天收货、拆封查看、无指纹、无污垢、全新未拆封产品、京东自营店值得信赖、产品款式很喜欢、出厂屏幕自带贴膜、屏幕清晰、杜比音质、《手机是帮别人购买》很完美。', '亮黑', '2022-09-03 11:13:22', 6);
INSERT INTO `data` VALUES (11798, '九***笑', 5, '外形外观：简洁的设计，挺时髦的设计，很喜欢。\n屏幕音效：非常不错的屏幕，色彩还原的很好，音量够大，也清晰。\n拍照效果：OIS很实用，拍照也够清晰，4800万像素日常用用也够了，扫码反应很快。\n运行速度：刚用一个多月吧，速度很快，很喜欢。', '银迹', '2022-12-28 21:02:50', 4);
INSERT INTO `data` VALUES (11799, 'j***3', 5, '外形外观：有型有样\n屏幕音效：丽音效果\n拍照效果：杠杠滴\n运行速度：快\n待机时间：棒\n其他特色：性价比超高。值得购买！', '幽芒', '2022-12-10 14:55:27', 5);
INSERT INTO `data` VALUES (11800, 'j***g', 5, '京东平台：一如既往的好。自营品质保证。客服专业，价保实诚。物流快速。头晚下单，第二天必须达。\n小米手机：性价比高，设计也越来越棒了。骁龙870性能强，能耗低，冲这个就选了redmi~K40S,当然三星直屏也不错了。67W快充充电速度比官方宣称38分钟实际充满要40多分钟了。不过日常用一天一充是稳妥妥当。不足为塑料中框。当然产品线定位就在哪。往往出乎意料是喜欢满足。。。。\n拍照效果：ois加持\n屏幕音效：亮堂堂\n运行速度：870', '亮黑', '2022-06-24 21:51:43', 3);
INSERT INTO `data` VALUES (11801, 'L***5', 5, '小米手机很多小功能，很实用。广告自己设置可以关闭，很简约，有红外就很实用。点赞京东快递优惠力度大，快递速度快，售后有保障。\n外形外观：晴雪非常好看\n屏幕音效：音质还行\n拍照效果：拍照扫码，够用\n运行速度：运行速度快，骁龙870调教的炉火纯青\n待机时间：待机可以4500电池\n其他特色：性价比非常高的手机，日常使用足够', '晴雪', '2022-11-04 15:46:23', 2);
INSERT INTO `data` VALUES (11802, '老***快', 4, '外形外观：外观好看，我个人比较喜欢\n屏幕音效：音效也不错\n拍照效果：拍照效果够用比特长拍照的肯定差点\n运行速度：运行很快毕竟12G\n待机时间：待机时间都是一天一充超快\n其他特色：整体非常性价比非常高', '晴雪', '2022-11-26 17:16:12', 5);
INSERT INTO `data` VALUES (11803, 'p***x', 5, '晚上下单，第二天早上8点就收到了，京东物流真是快，手机外观好看，后盖颜色很漂亮，屏幕清晰，色彩艳丽，运行速度很快，家人用的都是红米系列，确实好用，很满意。', '幻镜', '2022-08-14 12:04:21', 2);
INSERT INTO `data` VALUES (11804, '衷***盼', 5, '外形外观：好看且美观\n屏幕音效：屏幕用起来也很顺畅\n拍照效果：十分清晰\n运行速度：12+3大内存 \n待机时间：玩的多的话一天充一次 正常待机可以2到3天\n其他特色：用了一个多月才来评论 目前一切都好', '幻镜', '2022-12-15 11:36:50', 4);
INSERT INTO `data` VALUES (11805, 'w***4', 5, '外形外观：大气时尚，握在手上很舒服\n屏幕音效：不错，中音有待加强\n拍照效果：美颜效果杠杠的\n运行速度：还在适应中，后续看看。\n待机时间：一到两天一充，备用机合适。', '亮黑', '2022-11-17 16:26:59', 4);
INSERT INTO `data` VALUES (11806, '时***d', 5, '外形外观：外形外观：最纠结的就是选颜色，最终选择了幻镜。外观大气，看上去简洁大方。喜欢它直立的侧边。玻璃后盖，就像镜子一样。\n屏幕音效：屏幕音效：感觉三星E4屏已经够用了。两个扬声器，杜比全景声，效果不错。\n拍照效果：拍照效果可以。\n运行速度：运行速度：骁龙870的处理器，12+256。完全满足我的使用要求。运行速度很快。\n待机时间：待机时间：还好。 正常使用，一天，还剩30%电量。充电速度快：半小时可以充满。\n其他特色：价格实惠，性价比很高。点赞！', '幻镜', '2023-01-02 17:13:41', 4);
INSERT INTO `data` VALUES (11807, 'a***4', 5, '性能配置很好，67w快充非常棒，全功能nfc！侧连指纹不是太喜欢，相机比note10好，但相机没有小米10pro的效果好。没有无线充电。12+256g存储，870的cpu，散热和稳定性棒棒的！', '亮黑', '2022-11-12 21:01:39', 5);
INSERT INTO `data` VALUES (11808, '网***_', 5, '特意用了三四天再来评论，目前一切完美。收货仔细检查了一下，原封机，去年11月生产的。搭上百亿补贴的尾巴上车，870处理器，运行流畅，充电很快，刚开始有些耗电，升级miui14后续航感觉大大增加，中度使用一天下来还能剩40多个电。打游戏有点发热，不过在接受范围内。这个价位，这个配置，性价比很不错。当备用机用个几年应该没问题。', '亮黑', '2023-03-09 23:45:30', 5);
INSERT INTO `data` VALUES (11809, 'j***9', 5, '67w快充，拍照好，像素高，宽容度也好。很丝滑流畅，2022红米的这个性价比特别高，而且还特别有诚意，支持，有了红米的路由器也有红米的手机，谢谢redmi的慢慢诚意，干饭小米！\n屏幕音效：屏幕亮度高，阳光下没有问题\n外形外观：硬汉圆润的金属质感\n拍照效果：夜景好，宽容度高\n运行速度：速度杠杠的\n待机时间：67w快充不用担心没电\n其他特色：运行内存12G', '晴雪', '2022-11-18 14:00:10', 4);
INSERT INTO `data` VALUES (11810, '边***廷', 5, '红米大品牌，产品质量有保证，质量很好，外观漂亮，给老人用完全够用，非曲屏很好，老人不喜欢曲屏，而且屏幕够大，骁龙870不是吹的，流畅无比，12+7的运存，不会卡机，相机无所谓了，老人不拍照，充电速度超级快，半小时充满，用券比实体店便宜，物美价廉，京东就是好，价格便宜还能用券，虽然疫情，但是没影响效率', '幻镜', '2023-01-26 22:29:00', 4);
INSERT INTO `data` VALUES (11811, 'u***a', 5, '京典的品牌，简洁大方的外观，手感很好，屏幕音效优良，拍照效果稳定优良，运行顺畅，大容量电池待机时间长。', '幻镜', '2022-12-09 11:54:25', 3);
INSERT INTO `data` VALUES (11812, 'j***8', 5, '18号下的单，19号就到了，拿到时包装是完好的，甚至没有褶皱，然后吧，本人是在校大学生，这台手机我觉得是非常值的，不到2000，骁龙870，12+256，颜值也高，我特别喜欢这种直屏，小立边框，总得来说，这台手机虽然比不上现在的顶尖手机，但是平常够用了', '幻镜', '2023-02-24 12:12:15', 5);
INSERT INTO `data` VALUES (11813, '易***亘', 5, '外形外观：挺薄的！也不割手\n屏幕音效：双声道，杜比音效，棒极了\n拍照效果：像素高，清晰度非常满意\n运行速度：太顺畅了，870杠杠的，小米系统国内第一\n待机时间：两三天，67W 超级充电速度\n其他特色：颜色我喜欢，高级有特色', '幽芒', '2022-11-26 23:36:57', 4);
INSERT INTO `data` VALUES (11814, '小***逼', 5, '手机收到了，挺喜欢的。正常使用1天1充充，15分钟充满，或者两天三充。还很不错。拍照:满足所有的需求,非常清晰。外观很时尚，很精致。屏幕高清，色彩稳。拍照效果：很棒，防抖很好，色彩真实。运行速度杠杠的，也不卡，非常流畅。', '亮黑', '2022-11-26 18:15:53', 3);
INSERT INTO `data` VALUES (11815, '一***味', 5, '外形外观：庄严大气，黑色的。亮亮的亮亮的。\n屏幕音效：扬声器调教的还不错。\n拍照效果：拍照对于我来说完全够用的，记录一下生活嘛。\n运行速度：870现在还是很能干，功耗比较低，不会发热，运行也流畅。\n待机时间：这个续航很长啊，而且充电又非常快，基本上一天都不用充电。', '亮黑', '2022-11-24 23:38:55', 4);
INSERT INTO `data` VALUES (11816, 'y***9', 5, '使用了半个多月，我觉得这款产品还是很不错，性价比很高，屏够大，够清晰，使用起来都很流畅，打游戏也很快，颜色还可以，就是这个膜贴上之后亮黑变得有点灰，看看就习惯了。比较轻薄。京东的派送速度绝对绝对神速，一如既往。', '亮黑', '2022-11-22 19:00:08', 1);
INSERT INTO `data` VALUES (11817, 'n***s', 5, '外形外观：整体方正看起来比较商务\n\n屏幕音效：e4的屏幕观感很好，不会辣眼睛\n\n拍照效果：带光学防抖的镜头，比之前有了质的提升，成片率更好\n运行速度：运行速度很快，870一代神u，发热很低', '幽芒', '2022-07-23 15:13:19', 4);
INSERT INTO `data` VALUES (11818, '小***3', 5, '外形外观：外观非常时尚，非常漂亮！适合各个年龄段使用。\n屏幕音效：屏幕非常清晰，分辩率很高，显示细腻。\n拍照效果：拍照效果很棒??！\n运行速度：速度快，打游戏杠杠滴！\n待机时间：待机时间长。\n其他特色：充电很快，67W快充！', '晴雪', '2022-10-20 19:53:35', 4);
INSERT INTO `data` VALUES (11819, 'L***子', 5, '看了很久，最终还是选择了k40s，性价比高，幽芒色很漂亮，喜欢，充电特快67W快充，物流也很给力，上午拍下午就到了，\n外形外观：很靓丽\n屏幕音效：很好\n拍照效果：拍照效果很清晰\n运行速度：运行速度特快，', '幽芒', '2022-04-08 08:32:25', 8);
INSERT INTO `data` VALUES (11820, '顽***弟', 5, '非常喜欢这个小手机呀，特别的棒啊，简直就是爱不释手啊\n拍照效果：好，漂亮啊\n屏幕音效：好\n运行速度：好，真的太喜欢了，快啊', '亮黑', '2022-11-13 14:14:36', 1);
INSERT INTO `data` VALUES (11821, '贝***g', 5, '东西不错，没啥问题，挺好的，屏幕效果看着很不错\n运行速度：速度挺快的\n外形外观：长长的，挺好的\n屏幕音效：看起来很棒', '亮黑', '2022-11-18 19:31:50', 2);
INSERT INTO `data` VALUES (11822, '巡***丶', 5, '外形外观：手机方方正正的，很好看！\n屏幕音效：三星E4的屏幕，虽然是硬屏，但是显示效果还是可以的！\n拍照效果：拍照还行吧，这个价位里的平均水平！\n运行速度：高通骁龙870的处理器，一代神u了，运行速度很流畅，不用担心！\n待机时间：待机时间挺长的，新手机，续航还不错！', '幻镜', '2023-03-08 07:57:24', 4);
INSERT INTO `data` VALUES (11823, '7***m', 5, '外形外观：买的晴雪色很耐看而且菱角分明手感也很好\n\n屏幕音效：之前用的手机单扬声器 Icd 屏这次双扬声器E4屏幕很给力\n\n拍照效果：平时拍些美食绰绰有余\n\n运行速度：搭载870与MIUI12.5也是很流畅待机时间：四千五的电池加快充不打游戏待机很长\n\n 使用感受：半小时就充满，一晚待电100-99，很牛，系统也还好，就是震感不是很强，比理想的厚度略大，可能是直角机身的缘故，总之非常不错，亮度也很棒，出门在外足够看得清，声音很大很响，值得推荐给大家购买！', '晴雪', '2022-11-21 21:05:48', 4);
INSERT INTO `data` VALUES (11824, '凶***湿', 5, '手机很流畅，外观也好看，手感很轻，很适合女生用，充电也快，', '晴雪', '2023-03-12 13:12:04', 3);
INSERT INTO `data` VALUES (11825, 'I***E', 5, '用了一个星期感觉很不错，系统流畅，打游戏也可以，内存256足够用，拍照正常，毕竟价格在那儿，款式超喜欢，颜色也很中意，快递包装能用个泡沫袋包住就更好了。30号晚下单，元旦到货，购物很满意。', '幽芒', '2023-01-07 15:30:16', 6);
INSERT INTO `data` VALUES (11826, 'A***凤', 5, '整体手感还行，买给老妈的，显示细腻清晰，信号可以，性价比高，用着感觉很不错，物流速度也是没得说很快～', '晴雪', '2022-12-20 10:09:42', 7);
INSERT INTO `data` VALUES (11827, '超***阿', 5, '屏幕通透，舒服，散热真的凉爽，跑安兔兔才39度，性能模式，平衡模式只有65万，神U870值得购买的备用机器。\n考虑到性能与信号，选择了红米K40s同时配合京东的活动真不错。值得选择的机器。\n目前主力是13PM\n后续再来。\n12+257跑分性能模式下71万分，无限接近75了。\n谁告诉我75万分怎么跑出来的。\n外形外观：外观很好银色闭眼选择，黑色指纹容易上，戴套手感更好，\n屏幕音效：音质绝对好，\n拍照效果：拍照有防抖，成片也不错。\n待机时间：还没检测。870应该行。', '银迹', '2022-03-18 20:35:25', 4);
INSERT INTO `data` VALUES (11828, 'z***1', 5, '京东送货很快，手机性能够用，充电快，卡槽是双面装卡的，晴雪色很好看，拍照清晰，系统流畅，电池4500感觉有点小啊', '晴雪', '2022-12-17 16:27:21', 5);
INSERT INTO `data` VALUES (11829, 'j***里', 5, '外形外观：外观超级漂亮，家人很喜欢。\n屏幕音效：哈曼卡顿的音效真的超级棒。现在都喜欢外放音乐啦！\n拍照效果：拍照?非常不错，拍人很漂亮，拍景也美丽！\n运行速度：运行速度真的超级棒！', '银迹', '2022-11-27 14:44:43', 4);
INSERT INTO `data` VALUES (11830, 'j***p', 5, '送货速度块，原封未激活正版手机，870处理器非常流畅，充电玩手机不发烫，这款40S性价比非常高绝对物超所值，而且拿在手里的质感非常好，拍照也很清晰，待机时间早上充满电能玩一天，不怎么玩可以好几天不充电', '亮黑', '2022-11-06 22:15:38', 2);
INSERT INTO `data` VALUES (11831, 'j***b', 5, '外形外观：很好看\n屏幕音效：音效清晰\n拍照效果：高清\n运行速度：很快的\n待机时间：能用24个小时\n其他特色：推荐友友们购买哦这个银色不错的', '银迹', '2022-12-27 20:34:44', 1);
INSERT INTO `data` VALUES (11832, '涛***7', 1, '舅舅的上一个手机用了5年了，他说太卡了，电话有时候都卡得来电接不起来，我一看3+32的，已经满了，电池也不行了，看样子必须得换了。\n      昨晚上帮他下单，今天一早刚到公司上班没一会快递小哥电话就到了。这次帮他换一个12+256的，应该能用很长时间了吧。\n      趁着刚好赶上这次双十一，价格比较实惠。他平时最爱用的抖音都是秒开，所有应用都是非常流畅且很丝滑。', '亮黑', '2022-11-11 12:47:27', 4);
INSERT INTO `data` VALUES (11833, '全***公', 5, '外形外观：美观大气，没有廉价感\n屏幕音效：高刷屏，用了回不去\n拍照效果：直男不拍照\n运行速度：杠杠的，性价比最高\n待机时间：一天一充没有问题', '晴雪', '2022-12-05 10:00:52', 4);
INSERT INTO `data` VALUES (11834, '姚***3', 5, '后面的从最早购买的红米Note9pro，到后来的红米k40，到后来的红米Note10pro，到后来的小米充电宝，无线耳机，小米监控。后来购买的红米Note11pro，还给妈妈买过红米Note9。又到这次的K40S。自从我开始使用红米手机以后，家里慢慢慢慢的全都成了红米手机了，K40S是给老婆买的K40升级款礼物。红米手机性价比超高，使用体验特别好，价格实惠，手机好用。妥妥的铁粉', '幽芒', '2022-09-08 22:59:57', 4);
INSERT INTO `data` VALUES (11835, '天***荣', 5, '屏幕音效：屏幕顺滑，不卡顿，音效圆润，声音很大声。\n拍照效果：色彩艳丽。不错。\n运行速度：运行速度非常快。\n待机时间：还没事在看看', '幽芒', '2022-11-13 21:11:11', 4);
INSERT INTO `data` VALUES (11836, '奇***8', 5, '性价比好机看小米，性价比极品看红米，自从红米K40S推出以来，配置骁龙870，12G运行内存，256G储存，大像素防抖后摄+高清前摄，6.67吋高清120赫兹大屏，WIFI蓝牙红外NFC应有尽有，这个两千出头的价格，夫复何求！', '亮黑', '2022-10-03 14:31:59', 6);
INSERT INTO `data` VALUES (11837, '省***钱', 5, '外形外观：外观没得说，对比了好几款手机，这款颜值很棒，沉甸甸的分量，感觉做工也不错，2000左右的手机值得推荐\n屏幕音效：屏幕还挺大的，分辨率也很高，画质很细腻\n拍照效果：拍照肯定跟5000多的手机没法比，平常拍个风景，自拍照还是挺清晰的，完全够用\n运行速度：玩过王者荣耀和英雄联盟手游，一点也不卡', '晴雪', '2023-03-05 18:52:32', 4);
INSERT INTO `data` VALUES (11838, 'j***f', 5, '外形外观：幽芒好看，颜色偏浅，很亮。\n\n拍照效果：要求不高可以\n待机时间：一天没用没充电，\n其他特色：配送很快，第二天就到了，试用两天再说', '幽芒', '2022-11-03 22:58:57', 5);
INSERT INTO `data` VALUES (11839, '西***i', 5, '手机终于心心念念的都买下来了 用了一段时间 感觉也是适应 上手感觉顺 系统是miui的已经习惯了 界面易懂 容量很足够 操作流畅 打电话清晰', '亮黑', '2022-11-13 20:05:32', 1);
INSERT INTO `data` VALUES (11840, 'w***n', 5, '一直想换Redmi K40S，等到双十一价格优惠，果断出手，这款k40s采用 骁龙870 ，发热量控制很好，功耗不大，三星E4 AMOLED 120Hz直屏，日光下分辨清晰，摄像 OIS光学防抖 ，能满足基本摄影需求，但还不够精细，67W快充，速度不错，我选了 幽芒色系，耐看， 12GB+256GB 5G智能手机 满足了我的均衡需求。', '幽芒', '2022-12-04 23:18:46', 4);
INSERT INTO `data` VALUES (11841, 'j***v', 5, '物流速度超快，农村偏远，竞能提前一天送达！！！\n外形外观：高大上，有品位！\n屏幕音效：亮丽环绕，有质感！\n拍照效果：清晰！清晰！清晰！\n运行速度：非常快！不延迟，不卡顿\n京东自营有保障！售后无忧！支持国货，值得拥有！', '亮黑', '2022-11-11 11:15:01', 4);
INSERT INTO `data` VALUES (11842, 'j***F', 2, '不好意思，特意用了几天才来好评，评价晚了！米10已经收货，包装精良，快递为京东快递，保障性强。产品外观良好，没有拆机痕迹，目前使用无问题，基本上为次新机，不仔细看分辨不出来。各种测试、检查手机均为高性能，推荐大家购买，比新机划算太多了。快递给力，卖家服务热情！包装精美！经过多次的对比，怀着忐忑的心终于下手买了米10。毕竟是京东旗下的店铺，值得信赖！收到马上开箱检验，什么99新呀，看外观包括荧屏，那简直就是100%的新机呀！特意用了几天才来好评的。说句实话，米10从各方面来说表现都很出色，本人喜欢听歌，感觉米10就做到了，扬声器，这个可以吹爆，对称式立体双扬声器发挥的淋漓尽致。我也用过其他立体式双扬声器，感觉都比不上米10。总之本人感觉米10很香！用了几天很流畅。充电快的惊人，一会就能充满，大电池大容量，非常赞。打游戏也非常流畅，吃鸡没问题，还有游戏后台加速功能，拍照一亿像素，非常清楚，文档和身份证复印件功能简直是太牛了，现在还有很多功能还没get到，继续研究，支持小米，支持国货。要下手的亲，抓紧购买，毕竟是京东旗下的店铺，值得信赖！值得一提的是机哥耐心解答，不厌其烦，都能一一解答！', '钛银黑『赠40W快充套装』', '2021-12-25 14:36:32', 8);
INSERT INTO `data` VALUES (11843, 'j***x', 5, '机非常满意，客服态度好，非常值得推荐，就是和新的一样', '钛银黑『赠40W快充套装』', '2021-12-28 14:07:38', 7);
INSERT INTO `data` VALUES (11844, 'j***T', 5, '收到后用了几天才来评价，物流很快，京东快递yyds。手机很不错，打游戏很流畅，不卡，手机信号也很好，拍照像素很棒，拿到手机那一刻，感觉跟新的一样，看不出来是二手手机，第一次到在他家买手机，体验很不错，没买之前很担心，看了好久才敢下单，收到手机后，发现自己的担心都是多余的', '钛银黑『赠40W快充套装』', '2021-12-25 10:40:22', 4);
INSERT INTO `data` VALUES (11845, 'j***K', 5, '特意用了一个月才来评价的。首先，99新就是全新呀，太意外太惊艳了，虽然包装换了店家自己的，挺喜庆，挺好看。其次，店家还给贴好了手机膜，对于追求完美的我来说，没气泡没歪斜，没毛病。最后，手机已经升级最新稳定版，开机使用流畅，8+256相比替换的米5s plus简直就是鸟*换炮啊。把自带的不用的程序卸了，又把原机几十个平时常用的软件倒腾过来，可劲儿造也不怕卡顿了。开心', '钛银黑『赠40W快充套装』', '2021-12-27 15:15:20', 4);
INSERT INTO `data` VALUES (11846, 'j***F', 5, '成色确实很不错，基本没有使用痕迹，没有问题，下单时有些忐忑，怕虚标什么的，拿到时没有任何担心的了，几乎就是新的机子了，非常不错。京东旗下的店铺，值得信赖。\n从各方面来说小米10是非常不错的，个人对于小米10手机的外观设计还是比较喜欢的，买的时候在全新K40和二手10之间犹豫过，最后鉴于k40的塑料边框还是选了旧旗舰，做工反正是秒杀现在再用的K30，小米10在综合性能上完全够用，拍照确实是亮点。', '钛银黑『赠40W快充套装』', '2021-12-25 12:22:55', 6);
INSERT INTO `data` VALUES (11847, 'j***v', 5, '犹豫了很久，心想反正有无理由退货，所以还是抱着试试的心态下手了。收到后用了两天来评的。非常满意，手机很新，自己感觉新机几乎一样，用起来完全不会有用着二手的心里疙瘩。特别是最担心的电池耐用性也没让我失望。系统用起来流畅，拍照非常棒！', '钛银黑『赠40W快充套装』', '2021-12-25 15:02:29', 4);
INSERT INTO `data` VALUES (11848, 'j***v', 5, '手机用着很舒服，也很美观，电量确实普通介绍所说，是短版，送小米10快充真的是很奈斯。可以说很让我惊讶和惊喜。非常喜欢，快递也很快。包装也很讲究！服务很周到！非常感谢！！！！！', '钛银黑『赠40W快充套装』', '2021-12-29 09:44:36', 5);
INSERT INTO `data` VALUES (11849, 'j***P', 5, '成色很新，说是二手的其实跟新的没啥区别，这个手机关注很久了，特别喜欢，我媳妇看了说很棒，也想在拍拍二手买一个她自己喜欢的，我推荐给好多朋友了，他们看了也都很喜欢，回头再给我爸爸和妈妈还有媳妇买一部，今后会持续关注', '钛银黑『赠40W快充套装』', '2021-12-25 09:47:04', 4);
INSERT INTO `data` VALUES (11850, 'j***e', 3, '不好意思了,特意用了几天才来好评,评价晚了!快递给力,卖家服务热情!包装精美!经过多次的对比,怀着忐忑的心终于下手买了米10。毕竟是京东旗下的店铺,值得信赖!收到马上开箱检验,什么99新呀,看外观包括荧屏,那简直就是100%的新机呀!特意用了几天才来好评的。说句实话,米10从各方面来说表现都很出色,本人喜欢听歌,感觉米10就做到了,扬声器,这个可以吹爆,对称式立体双扬声器发挥的淋漓尽致。我也用过其他立体式双扬声器,感觉都比不上米10。总之本人感觉米10很香!要下手的亲,抓紧购买,毕竟是京东旗下的旗舰店铺,值得信赖!值得一提的是机哥耐心解答,不厌其烦,都能一一解答!还会推荐同事购买的,总之一句话,很愉快的一次购物!', '钛银黑『赠40W快充套装』', '2021-12-25 15:09:16', 2);
INSERT INTO `data` VALUES (11851, 'j***5', 5, '很好用', '钛银黑', '2023-01-15 10:56:49', 5);
INSERT INTO `data` VALUES (11852, 'j***O', 5, 's小米10手机外观就跟新的一样，非常喜欢，这款手机的屏幕非常漂亮，非常清晰，没有划痕，没有明显磨损，希望能用上几年。', '钛银黑『赠40W快充套装』', '2021-12-27 10:51:05', 2);
INSERT INTO `data` VALUES (11853, '小***切', 5, '手机很好，外观没什么瑕疵，体验也不错，成色漂亮，很满意', '冰海蓝', '2022-09-05 11:53:27', 5);
INSERT INTO `data` VALUES (11854, 'j***k', 5, '手机成色还不错，只有充电口有些许磨损，其他基本完好，使用起来很流畅，很小的发热，手机屏的清晰度非常好。电池也很耐用，看视频一天只充电一次', '钛银黑', '2022-10-24 22:48:44', 6);
INSERT INTO `data` VALUES (11855, 'j***y', 5, '外观很好看，充电也很快，还送手机壳和钢化膜，使用也很流畅，真心不错。', '钛银黑', '2023-01-18 18:32:18', 5);
INSERT INTO `data` VALUES (11856, '5***m', 5, '收到米10了，外观很好99新，之前一直用小米10，内存小了换个大点内存的。机器无故障很满意。', '钛银黑', '2023-01-02 09:22:01', 4);
INSERT INTO `data` VALUES (11857, 'j***y', 5, '宝贝收到了，物美价廉，质量特别好，颜色也很喜欢，卖家态度也很喜欢，以后还会回购的', '钛银黑', '2022-12-24 17:34:45', 4);
INSERT INTO `data` VALUES (11858, 'j***K', 5, '很好99新', '钛银黑', '2022-12-01 12:26:20', 5);
INSERT INTO `data` VALUES (11859, 'j***s', 5, '手机跟新一样，用起来很顺畅，值得购买', '钛银黑', '2022-11-21 18:51:44', 3);
INSERT INTO `data` VALUES (11860, 'j***g', 3, '电量走的有点快，一如既往的发热', '钛银黑【赠3C认证快充】', '2023-03-06 14:00:36', 5);
INSERT INTO `data` VALUES (11861, 'w***7', 5, '好用！物美价廉！值得购买！', '蜜桃金', '2022-11-01 19:52:48', 1);
INSERT INTO `data` VALUES (11862, '-***-', 5, '好看，很新，性价比很高，不过确实比我荣耀烫一点，不过在能接受的范围，这个价格能买到，确实划算，买二手就要买不保值的，哈哈哈哈', '钛银黑', '2022-10-18 18:29:21', 2);
INSERT INTO `data` VALUES (11863, '满***尽', 2, '本来还担心东西不好，到手发现多虑了，五星好评，运气不错，成色99新', '钛银黑', '2022-10-05 16:53:27', 5);
INSERT INTO `data` VALUES (11864, '徐***N', 5, '手机很好，符合实际情况，性价比高，', '钛银黑', '2022-08-29 13:25:42', 1);
INSERT INTO `data` VALUES (11865, 'u***2', 5, '特别好用 屏幕完美 机身完美 性价比很高 送给老妈的 很喜欢', '钛银黑', '2022-08-18 20:04:51', 5);
INSERT INTO `data` VALUES (11866, 'c***童', 5, '物流很快，第二天就收到了，回家第一时间打开检查，外观完美无划痕，基本运行也很流畅，无卡顿，游戏运行画面精准，整体感觉都挺不错，充电稍微有点发热，不过安卓机都一样，可以理解，性价比相当不错了。', '钛银黑', '2022-08-06 14:16:57', 4);
INSERT INTO `data` VALUES (11867, 'j***t', 5, '买家评价：一年之前，每过一个小米10，用的时候感觉非常好，平时不玩游戏，但APP比较多，有几十个，感觉速度超快，比原来的那个手机强多了，所以要建议家人买了第二个，而且价格也便宜很多，好评?', '钛银黑『赠40W快充套装』', '2021-12-31 15:59:57', 3);
INSERT INTO `data` VALUES (11868, 'j***n', 5, '屏幕的流畅度特别好，动态壁纸也超绝，手感也不错，双扬声器棒极了。\n外观很靓，手感很棒，双曲面屏握着手感是很舒适，单手操作完全能够应用自如，屏幕效果很理想，看着比较舒适，音效是非常赞杠，运行速度完美，没有卡顿，特别是APP运行速度很快，拍照效果比以前的小米手机好多了，拍照清晰，1亿像素照片放大了也不失真，待机时间可以两天，电池容量够大，充电更快，而且还支持30W无线充电，非常方便，小米手机用了好几个了希望越做越好', '钛银黑『赠40W快充套装』', '2021-12-29 14:53:37', 4);
INSERT INTO `data` VALUES (11869, 'j***Y', 5, '手机很好，目前没有发现问题，和新的没啥区别，而且送了全兼容的40w快充，客服也相当棒。推荐蜜桃金的，很beautiful。', '钛银黑『赠40W快充套装』', '2021-12-28 11:52:33', 2);
INSERT INTO `data` VALUES (11870, 'j***e', 5, '东西很不错，全新未拆封的，而且比其他地方还要便宜 还送了很多礼品，很满意的一次购物，以后有需要还会来的。', '钛银黑『赠40W快充套装』', '2021-12-26 11:51:21', 4);
INSERT INTO `data` VALUES (11871, '潇***枫', 5, '买给妈妈，很喜欢，质量和速度杠杠的', '蜜桃金『赠40W快充套装』', '2022-01-15 21:21:40', 4);
INSERT INTO `data` VALUES (11872, 'j***B', 5, '买家评价：已经买第二个小米10了，手机确实不错，运行速度很快，拍照清晰。商家服务不错，发货速度很快!服务态度很好!', '钛银黑『赠40W快充套装』', '2021-12-31 15:23:11', 3);
INSERT INTO `data` VALUES (11873, 'j***v', 5, '外形外观：这个颜色很有质感 低调内敛 手里拿着也很大气 屏幕音效：屏幕也很经验 清晰 颜色也正 拍照效果：拍摄有很多模式 基本都很实用 运行速度：运行速度快 无卡顿 很满意 待机时间：待机时间长', '钛银黑『赠40W快充套装』', '2021-12-29 10:25:06', 6);
INSERT INTO `data` VALUES (11874, 'j***E', 5, '收到了，和描述的一样，和全新一样，各方面都很完美，很不错的一款手机。值得购买。', '钛银黑『赠40W快充套装』', '2021-12-28 13:54:34', 2);
INSERT INTO `data` VALUES (11875, 'j***G', 5, '手机符合9.9成新，没有划痕，非常好用性价比高', '钛银黑『赠40W快充套装』', '2021-12-28 13:17:08', 3);
INSERT INTO `data` VALUES (11876, 'j***G', 5, '不错，很新，用起来很流畅。非常满意的一次购物', '钛银黑『赠40W快充套装』', '2021-12-28 12:32:55', 5);
INSERT INTO `data` VALUES (11877, 'j***D', 5, '货已收到，太完美了，没有一点瑕疵，和新的一模一样，做工精细手感好，使用非常流畅，价格也实惠，太喜欢了！', '钛银黑『赠40W快充套装』', '2021-12-28 09:40:31', 4);
INSERT INTO `data` VALUES (11878, 'j***f', 4, '手机是真的不错，物流也很快，发货2天就到了，到货我就拍了几张精美图片，成色和新的差不多，非常新，手机还有6个月保，我真的是太捡漏了，运气爆棚，还送了我原装盒还有原装充电器，真的非常感谢客服，以后买手机的话，真的就这家店了', '钛银黑『赠40W快充套装』', '2021-12-27 10:38:07', 7);
INSERT INTO `data` VALUES (11879, 'j***S', 5, '买用了快一个月了，才来评论 首先手机没有任何问题，系统也是最新的，电池什么的不打游戏基本一天一冲，送的充电器也非常好用，屏幕没有任何划痕，9可以说是全新 放心购买。', '钛银黑『赠40W快充套装』', '2021-12-27 10:29:46', 2);
INSERT INTO `data` VALUES (11880, 'j***z', 5, '颜值高，用起来顺畅，其实没有网上说的那么重，女生也可以接受，拍照效果也不错，音效很好，听歌舒服，运行的很顺，不卡顿，温度也不容易升高，充电是真的快', '钛银黑『赠40W快充套装』', '2021-12-27 10:22:28', 4);
INSERT INTO `data` VALUES (11881, 'a***0', 3, '机身还可以，就是充电的地方哪里磨损多', '蜜桃金', '2023-02-07 23:09:28', 2);
INSERT INTO `data` VALUES (11882, 'j***j', 5, '第好几次买他家手机了，质量相当的好，和新机没啥区别，看不出来一点问题！价格也是给力，让媳妇喜欢不得了的一款手机。也对直播中的帅哥推荐表示感谢！拿都手机一直再玩，巡航也给力，如果再配个原装充电器就更完美了！就是好！', '钛银黑『赠40W快充套装』', '2021-12-25 12:21:19', 2);
INSERT INTO `data` VALUES (11883, 'j***i', 5, '收到第二天 成色非常好，新 这个比较满意 什么时间激活的也看不到 就这一点心里犯嘀咕 有没有拆过也不清楚 反正看着是不错 体验也可以 处理器速度也很快', '钛银黑『赠40W快充套装』', '2021-12-25 10:38:24', 4);
