INSERT INTO `data` VALUES (11961, 'j***H', 5, '快递非常快，用惯了小米质量不错。内存足够大了，这次最起码可以坚持两年。', '钛银黑『赠40W快充套装』', '2021-12-31 15:52:42', 1);
INSERT INTO `data` VALUES (11962, 'j***M', 5, '宝贝收到了用着还行，很满意的一次购物，正好在当天收到的。物流超级快', '钛银黑『赠40W快充套装』', '2021-12-31 15:50:25', 2);
INSERT INTO `data` VALUES (11963, 'j***n', 5, '外形好看，声音音量确实比之前的手机大的很多 ，像素拍照非常非常高 运行速度也特别快  待机时间也很长 是一次不错的购物旅行 推荐大家', '钛银黑『赠40W快充套装』', '2021-12-31 15:01:10', 1);
INSERT INTO `data` VALUES (11964, 'j***R', 5, '东西很喜欢，质量也很好的,第一次买二手手机,惊艳到我了,确实可以,瑕疵几乎看不到!点赞', '钛银黑『赠40W快充套装』', '2021-12-30 15:00:00', 2);
INSERT INTO `data` VALUES (11965, 'j***z', 5, '第一次买二手手机，一直纠结犹豫，收到货用了几天才来评价，真的很赞，无论运行速度，手机外观和新机几乎没有区别，爱了。', '钛银黑『赠40W快充套装』', '2021-12-30 14:40:06', 2);
INSERT INTO `data` VALUES (11966, 'j***g', 5, '质量很好，速度很快，简直物超所值，太香了。', '钛银黑『赠40W快充套装』', '2021-12-30 14:14:46', 2);
INSERT INTO `data` VALUES (11967, 'j***t', 4, '速度很快，第一天拍，第二天中午收到货！跟新的差不多，很好的体验！', '钛银黑『赠40W快充套装』', '2021-12-30 13:40:45', 2);
INSERT INTO `data` VALUES (11968, 'j***O', 5, '客服态度很好，发货速度快及时，手机外观设计很好，系统流畅！', '钛银黑『赠40W快充套装』', '2021-12-30 12:29:56', 2);
INSERT INTO `data` VALUES (11969, 'j***h', 5, '手机用了几天后才来评价不错超乎我的想象 ，肯本不像是二手手机反应很快，给五星是当之无愧的。再买手机就来你们家，以后没必要买新手机。', '钛银黑『赠40W快充套装』', '2021-12-30 12:20:19', 2);
INSERT INTO `data` VALUES (11970, 'j***Q', 5, '非常符合我的预测，跟新手机一样！收到了马上就安装app了，没有任何不良', '钛银黑『赠40W快充套装』', '2021-12-30 11:37:24', 2);
INSERT INTO `data` VALUES (11971, 'j***n', 5, '手机物流很快，二天就到了，收到手机后感觉跟新的一模一样，很不错，好评', '钛银黑『赠40W快充套装』', '2021-12-30 11:23:48', 2);
INSERT INTO `data` VALUES (11972, 'j***C', 5, '手机到了，非常棒，运行速度非常流畅，，使用手感非常好，好评', '钛银黑『赠40W快充套装』', '2021-12-30 11:25:18', 3);
INSERT INTO `data` VALUES (11973, 'j***r', 5, '新的一样，而且送好多东西，很不错', '钛银黑『赠40W快充套装』', '2021-12-30 10:23:40', 3);
INSERT INTO `data` VALUES (11974, 'j***G', 5, '小米10早收到了，外观很好看，手感也不错，拍照也很清晰，感觉续航还行，不过充电是真的快，不到一个钟就充满了，其他功能还在研究', '钛银黑『赠40W快充套装』', '2021-12-29 16:50:20', 2);
INSERT INTO `data` VALUES (11975, 'j***p', 5, '非常的不错 手感很棒 分辨率很高 刷新率好 很流畅 还要再买啊', '钛银黑『赠40W快充套装』', '2021-12-29 15:22:04', 2);
INSERT INTO `data` VALUES (11976, 'j***J', 5, '小米的真爱粉，用的所有的手机都是小米的，流畅度很好，玩游戏也顺畅，挺好的', '钛银黑『赠40W快充套装』', '2021-12-29 15:15:02', 2);
INSERT INTO `data` VALUES (11977, 'j***W', 5, '发货很快，拍照效果清晰效果很好，运行快可以装很多软件了都，画面感很好看时间久了都没问题，很喜欢！', '钛银黑『赠40W快充套装』', '2021-12-29 12:25:40', 2);
INSERT INTO `data` VALUES (11978, 'j***J', 3, '这款手机给我最大的感受就是&amp;ldquo;很流畅&amp;rdquo;它的屏幕显示素质的确是杠杠的?配合骁龙865和90Hz玩吃鸡一点都不卡顿，我也算是一个米粉吧，从小米6开始接触小米，真的，我用过小米之后我就不想再用其他品牌的手机了，我很喜欢小米这人性化的系统，很快捷很方便。至于网上那么多喷小米的，我想，仁者见仁智者见智吧。要做一个理智的粉丝，有缺点提缺点，如果非要把小米和其他品牌的手机做比较来突出小米的不好，我觉得完全没必要，手机嘛，自己觉得好用就行了', '钛银黑『赠40W快充套装』', '2021-12-29 12:17:40', 3);
INSERT INTO `data` VALUES (11979, 'j***y', 5, '外形外观：漂亮\n屏幕音效：色彩艳丽立体声音效很棒\n拍照效果：很好\n运行速度：快\n待机时间：满意\n其他特色：拍照特别漂亮清晰', '钛银黑『赠40W快充套装』', '2021-12-29 11:00:19', 2);
INSERT INTO `data` VALUES (11980, 'j***e', 5, '总体上还是很满意的。发的快递很快，有保障，物流也很快，手机不错，活动价，性价比很高，配置也不错，够用了，还送了好多东西，充电器，膜，基本上不需要买东西了，对了，还有质保，这样用起来比较放心了。服务也不错，好评。！', '钛银黑『赠40W快充套装』', '2021-12-28 15:40:01', 3);
INSERT INTO `data` VALUES (11981, 'j***C', 5, '手机用的不错，想买一台给老婆用，拍照非常好看', '钛银黑『赠40W快充套装』', '2021-12-28 14:07:52', 2);
INSERT INTO `data` VALUES (11982, 'j***y', 5, '手机完美，性能也好跑了60多万分，和新的一样，买到了一个我自己挑了几次都没挑中的颜色。五星', '钛银黑『赠40W快充套装』', '2021-12-27 15:12:11', 2);
INSERT INTO `data` VALUES (11983, 'j***w', 5, '手机用起来没有问题，购物体验很好，还送了手机壳和卡针', '钛银黑『赠40W快充套装』', '2021-12-27 14:56:30', 3);
INSERT INTO `data` VALUES (11984, 'j***G', 5, '手机很好，刚拿到手机，没有划痕，感觉就像全新机', '钛银黑『赠40W快充套装』', '2021-12-27 14:15:46', 2);
INSERT INTO `data` VALUES (11985, 'j***s', 5, '手机成色很新，运行速度流畅，电池也还耐用，这个价位可以接受。', '钛银黑『赠40W快充套装』', '2021-12-27 14:14:27', 2);
INSERT INTO `data` VALUES (11986, 'j***l', 5, '用起来非常流畅，服务好！手机整体还真是漂亮，超值！但有一些瑕疵，这是难免的。尺寸比想象中的要好很多。总体上还不错！东西收到之后呢，我也是很满意的！京东平台真的是超级好的卖家，解答疑问不厌其烦，细致认真，关键是东西好，而且货物发得超快，包装仔细，又很好看，值得信赖！机型的做工精细，对我个人而言觉得好看，发货速度快，是物有所值的。很好的卖家。谢谢喽，我的同学们看到我用的这款小米10都很喜欢呢。下次再来哦！老客户了啊，希望以后有更多', '钛银黑『赠40W快充套装』', '2021-12-27 12:34:57', 3);
INSERT INTO `data` VALUES (11987, 'j***x', 5, '运行速度：运行速度，小米就是永远的神，性价比超高，推荐大家购买\n拍照效果：拍照效果不用说，直接上图，非常清晰，满足日常需求不是问题\n屏幕音效：屏幕大气上档次，看着舒服，舒畅\n外形外观：外观一个字，爽，就是好看', '钛银黑『赠40W快充套装』', '2021-12-27 11:31:27', 3);
INSERT INTO `data` VALUES (11988, 'j***O', 5, '手机很不错，看起来很新，用几天看看性能什么的怎么样', '钛银黑『赠40W快充套装』', '2021-12-27 11:08:29', 2);
INSERT INTO `data` VALUES (11989, 'j***Q', 5, '看了很多品牌，找了很多家店，但是这个店铺比较实惠，相对于别的店铺，不仅仅少钱，还送很多小东西，所以选择了小米，选择了小米10，因为价格比较实惠学生买得起，因为学ps所以选择了10，拍照效果真的非常棒，性能也好，用起来很流畅，畅玩王者吃鸡lol手游。', '钛银黑『赠40W快充套装』', '2021-12-26 11:22:37', 3);
INSERT INTO `data` VALUES (11990, '海***味', 5, '用了好久来评价，非常好，像新的一样，没有任何缺点，', '钛银黑【赠3C认证快充】', '2023-03-22 20:50:48', 6);
