INSERT INTO `data` VALUES (12040, 'j***o', 5, '手机收到半个多月了，很喜欢，作备用也很顺手。', '钛银黑', '2022-11-17 20:38:56', 3);
INSERT INTO `data` VALUES (12041, '狐***丫', 5, '非常的好', '钛银黑', '2022-11-16 19:28:59', 7);
INSERT INTO `data` VALUES (12042, 'j***r', 5, '这个宝贝6到飞起！很轻，拍摄效果很好，配置也很高，配件齐全，就是转机的时候比原来红米note8pro的旧手机烫一点，充电非常快不是很烫。打游戏还没有测试。主要是外观设计太好看了(??&omega;??)??很好(?▽?)建议购买！???', '小白裙', '2022-10-19 12:06:21', 5);
INSERT INTO `data` VALUES (12043, 'y***6', 5, '关注小米手机很久了，看到这一款外形很漂亮，尤其是背壳手感特别好，优惠活动赠送吹风机和镜子，价格很实惠。立刻下单购买，使用起来手感不错，拍照效果很好。正常使用带电一天，充电67w很快就充满了。充电过程以及使用过程热度不高，整体感觉很不错。', '小白裙', '2023-02-21 07:14:25', 9);
INSERT INTO `data` VALUES (12044, '火***8', 5, '第一次首发买手机，给老婆买的结婚周年礼物，手机很漂亮，拍照很清晰，手机很轻，小白裙还有褶皱，随机就是曲屏说心里话有点不喜欢，个人偏爱纯平手机，不知道为什么现在主流手机都是曲屏，后续使用好了再来评价，现在总体满意，小米性价比还是挺高的，不得不说京东大上海速度还是棒棒哒！\n拍照效果：很清晰', '小白裙', '2022-09-28 09:17:42', 5);
INSERT INTO `data` VALUES (12045, '松***乏', 5, '外形外观：小白裙颜色非常好看，我一男的都非常喜欢?\n屏幕音效：单扬声器有点遗憾\n拍照效果：像素没得说，前置眼球追踪，后置进光量很足\n运行速度：8G运存对于我这种不玩游戏的刚好适合\n待机时间：正常吧，主要是功耗还得看后续体验\n其他特色：67W全新版本充电器很快，9分钟可冲入30%电量，非常棒!', '小白裙', '2022-10-18 13:05:40', 6);
INSERT INTO `data` VALUES (12046, '落***h', 5, '拍照效果：还好还好哈\n外形外观：美\n屏幕音效：好好\n运行速度：快\n待机时间：长\n其他特色：粉色最好看', '怦怦粉', '2022-11-11 00:42:42', 6);
INSERT INTO `data` VALUES (12047, 'X***y', 5, '小米手机越来越好看了 买了送女朋友 很是喜欢 看看这颜值 屏幕都是可以的 定制的主题 还有变色的图案 合适值得推荐 我会一直陪着你的', '潮流色', '2023-02-15 22:39:32', 7);
INSERT INTO `data` VALUES (12048, 'm***e', 5, '京东发货和配送无懈可击地好，包装很好，结实，HELLO Kitty版作为给老婆生日礼物不错，CIVI2系列手机定位也是女性为主力目标，机身轻巧，裸机175左右，很薄，好久没有拿过这么轻手机在手上了。背后kitty猫图案和主题很可爱，最关键是拍照能力非常好，尤其自拍，美颜效果一流！虽然轻薄但还是有67w超级快充，电池容量也足够大，正常使用一整天没有问题！虽然cpu不是最顶尖，但日常使用，社交软件，视频端等都比较流畅，实在是很适合女性定位的一部手机！\n外形外观：可爱\n拍照效果：非常好', '潮流色', '2023-02-13 00:08:53', 5);
INSERT INTO `data` VALUES (12049, 'b***l', 5, '我买的冰蓝色 非常漂亮 很轻 照相非常好看。小米civi主打拍照 给女朋友买非常适合。外表漂亮，性能稳定 重量轻盈 拍照贼好看！\n拍照效果：小米里最好的 。\n外形外观：轻盈飘逸\n运行速度：顺畅最新系统\n屏幕音效：曲面屏 高端大气', '冰冰蓝', '2023-03-03 20:22:58', 4);
INSERT INTO `data` VALUES (12050, '寿***味', 5, '平时用惯小米了，所以换手机首选还是小米，\n外形外观：瘦长型\n屏幕音效：音量响 屏幕显示漂亮\n拍照效果：清晰\n运行速度：目前新的很快，时间长了就不晓得了\n待机时间：新手机待机肯定长', '冰冰蓝', '2022-10-20 11:36:14', 5);
INSERT INTO `data` VALUES (12051, 's***荩', 5, '小白裙的背板挺特别的，光泽很好看，手感还不错。手机很轻薄，握感很好，适合女生，初步使用下来觉得没毛病。', '小白裙', '2022-10-02 09:26:43', 3);
INSERT INTO `data` VALUES (12052, '风***归', 5, '待机时间：续航方面，使用5G网络在线播放1080p电视剧，从100%电量开始播放，总共播放了393分钟，续航时间为6.5小时。不过，因为是5G网络，且手机保持最大亮度和音量，并不符合日常使用的逻辑，正常情况下，大部分时间在室内连接Wi-Fi，保持自动亮度和低音量，基本能够维持一整天的使用。\n拍照效果：采用120Hz高刷OLED屏，5000万后置三摄，背面采用大文理工艺，摸上去坑坑洼洼的感觉，防滑方面良好。处理器使用晓龙7gen1，综合性能较高，前置摄像头包含一枚3200万超清专业主摄，一枚3200万超清超广角主摄，并且前置多色温四柔光灯，在夜晚也可以更好的自拍。', '怦怦粉', '2022-10-14 20:49:11', 4);
INSERT INTO `data` VALUES (12053, '莫***图', 5, '外形外观：小白裙时尚靓丽，屏幕占比规整大气。\n运行速度：选的12G运存，程序启动速度比我的K40超大杯快。给母亲用边看直播边玩小游戏或看小说完全无压力。\n拍照效果：不会调参数，但自动模式已经比我的K40和母亲上一台note9的好太多了。\n待机时间：新机到手，上述母亲的用法一小时耗电10%，足够用。', '小白裙', '2023-03-14 19:00:48', 4);
INSERT INTO `data` VALUES (12054, '执***士', 5, '外形外观：非常小巧，贴手，轻巧\n屏幕音效：微曲面屏，视觉好，音效还行\n拍照效果：效果绝佳，自拍效果特别好，视频通话也美颜\n运行速度：新机不卡，运行流畅，\n待机时间：待机时间长，快充很快充满', '怦怦粉', '2022-11-10 22:32:36', 3);
INSERT INTO `data` VALUES (12055, '农***台', 5, '外形外观：很漂亮，曲面屏，拿着很舒服。\n屏幕音效：屏幕分辨率很高，很清晰，看着很舒服。\n拍照效果：拍照效果很好，专业拍照手机。\n运行速度：运行速度很快。\n待机时间：还可以，充电速度很快。\n其他特色：京东自营小米品牌值得信赖。', '朦朦黑', '2023-01-26 19:13:41', 4);
INSERT INTO `data` VALUES (12056, '挥***珑', 5, '外形外观：kitty加成很漂亮，手机壳也很美\n\n屏幕音效：屏幕很好\n拍照效果：刚刚的，特别适合自拍\n待机时间：无敌，civi系列的强项', '潮流色', '2023-02-18 10:58:01', 4);
INSERT INTO `data` VALUES (12057, 'C***7', 5, '外形外观：怦怦粉超级好看，很适合女孩子用\n屏幕音效：音效很好\n拍照效果：拍照效果非常好，前置后置都非常?\n运行速度：非常快\n待机时间：一天一充\n其他特色：手机很轻薄\n就是寄过来的时候包装很脏，其他都可', '怦怦粉', '2022-10-18 10:43:50', 4);
INSERT INTO `data` VALUES (12058, '紫***月', 5, '外形外观：外形好看，美观大方，颜值很高，适合女生使用，拿着重量也很轻，一点都不累手\n屏幕音效：高分辨率屏幕，特别清晰，还有屏幕指纹，音效也很好\n拍照效果：照相好看，自拍功能很强大，美颜滤镜也很美\n运行速度：使用运行流畅，速度快\n待机时间：重度使用一天不成问题\n其他特色：前置双摄像头，后置摄像头的设计显得很大，很漂亮，后盖带有褶皱的纹路很好看！', '小白裙', '2023-03-13 23:14:02', 3);
INSERT INTO `data` VALUES (12059, 'j***w', 3, '这个手机看着还行吧\n拍照效果：一般', '怦怦粉', '2023-01-26 20:16:45', 6);
INSERT INTO `data` VALUES (12060, 'Y***望', 5, '前置自拍太优秀了\n，2颗 32MP前置摄像头，广角+超大广角，这样合拍也能挤进去更多人了。自拍有「经典」「质感」两种模式。经典模式整体偏白，比较软妹；我更喜欢质感模式，更真实不吃妆。最诱人的是皮肤质感的处理，完全不会有涂抹感！能保留肤质本身的纹理，对瑕疵的处理也不是那种无脑磨皮，会保留一些无伤大雅的小瑕疵来提升照片的真实度，更耐看。\n暗光拍摄神器&mdash;&mdash;柔光灯！可以调节冷暖光，氛围感和情绪拿捏的死死的！感觉这个功能很实用，因为有的妆面只有在暖光下才好看。\n轻薄好看，只有7毫米薄，官方参数是7.23mm，171.8g。真的很轻了，握感确实非常出众！白色这款表面还有波浪纹理，很特别。屏幕稳定发挥，足够细腻，AMOLED屏幕，支持高频PWM调光，妈妈再也不担心我躲在被窝里玩手机了！\n这么薄，电池4500mAh，这个电量对于这么轻薄的手机来说确实挺挺大的，不知道实际体验怎么样，等它真正投入使用之后再来更新。67W快充试了，二十多分钟就能充满啦！个人觉得充电效率远远比巨大的电池更重要。', '小白裙', '2022-11-02 12:38:18', 3);
INSERT INTO `data` VALUES (12061, 'W***十', 5, '外形外观：双曲面屏幕\n屏幕音效：显示清晰，细腻。\n拍照效果：拍照效果很好\n运行速度：运行速度快\n待机时间：一天不成问题\n其他特色：蓝牙，红外，NFC，', '小白裙', '2023-02-22 17:26:54', 3);
INSERT INTO `data` VALUES (12062, 'j***g', 5, '一看就看中了这个手机，颜值非常高，拍照效果很好，是女生都会爱上它的。\n外形外观：太美了\n拍照效果：非常棒\n运行速度：很可以\n待机时间：一天没问题', '怦怦粉', '2022-10-16 09:06:05', 4);
INSERT INTO `data` VALUES (12063, 'j***m', 5, '拿到手机，感觉很轻，手感也刚刚好，性价比超高，真的值得购买哈，背面玻璃材质，感觉很有档次，简洁的白色设计，很喜欢，看看这手机后面使用情况如何，但相信小米出品，必是好品，赞赞赞；物流是使用京东物流，物流速度很快，值得赞，包邮也很好，赞赞赞。', '小白裙', '2023-01-30 12:25:36', 2);
INSERT INTO `data` VALUES (12064, 'B***g', 5, '外形外观：非常漂亮，手感很好，重量也控制的很棒。\n屏幕音效：显示效果细腻，刷新率够高。\n拍照效果：足够满足使用还能拍出非常不错的照片\n运行速度：不卡顿，很流畅。\n待机时间：轻度使用一天一充没问题\n其他特色：非常漂亮，后盖颜色很不错。', '怦怦粉', '2023-02-02 17:50:27', 3);
INSERT INTO `data` VALUES (12065, 'j***t', 4, '外形外观：买的淡粉色，外观非常好看，很薄很精致时尚，握感很舒服\n屏幕音效：无色差，很细腻，声音很清晰\n拍照效果：镜头给力，拍照清晰\n运行速度：快\n待机时间：一天够用\n其他特色：充电很快', '怦怦粉', '2022-10-16 09:39:53', 3);
INSERT INTO `data` VALUES (12066, '林***3', 5, '手感真好，大波浪手感，无敌了。 头一次用这个手感，保护壳我都不用了，用坏还买这个。', '小白裙', '2022-10-13 18:29:38', 2);
INSERT INTO `data` VALUES (12067, 'd***o', 5, '1.手机比civi偏重一点，可以接受\n2.适合女生，我是给妈妈买的，非常实用\n3.电池充电非常快，比之前的redmi9快了好几倍，出门在外不再着急了', '冰冰蓝', '2022-10-10 11:50:14', 2);
INSERT INTO `data` VALUES (12068, '自***c', 5, '看了好久，还是忍不住入手，用起来很哇塞的感觉，小米发烧友，无论从手感，质感，流畅感来说都足够强大了。', '怦怦粉', '2023-02-17 11:32:01', 6);
INSERT INTO `data` VALUES (12069, '子***曰', 5, '外形外观：给老婆买的，外观挺好，轻薄手感不错。\n屏幕音效：音效可以的。\n拍照效果：拍照效果很好，尤其是前置摄像头，还带广角，满足日常自拍?\n待机时间：待机时间有待使用观察，目前还不确定。\n其他特色：双十一买的，先用着，后面看效果。', '怦怦粉', '2022-11-11 22:30:47', 3);
INSERT INTO `data` VALUES (12070, 'f***崽', 5, '外形外观：漂亮\n屏幕音效：清晰\n拍照效果：自然\n运行速度：超速\n待机时间：整天\n其他特色：都好\n延伸评价：买吧', '朦朦黑', '2022-10-15 11:14:03', 4);
INSERT INTO `data` VALUES (12071, 'g***g', 5, '手机轻薄，微曲屏样子好看，运行速度快，拍照清晰，自拍广角足，美颜修饰自然，很不错的一款手机', '小白裙', '2022-11-13 13:46:13', 5);
INSERT INTO `data` VALUES (12072, '李***-', 5, '颜值爆表，手感特别好，不累手（照片拍不出真机的感觉，实物特别漂亮）\n拍照效果：自拍好看又自然\n外形外观：曲面屏手感太好了，手感温润又细腻\n待机时间：续航时间很不错，搭配67w快充，十分钟就能从个位数充到百分之三十多\n其他特色：背部应该是某种特殊的类肤玻璃，很舒服', '怦怦粉', '2022-10-15 13:32:10', 3);
INSERT INTO `data` VALUES (12073, 'u***4', 5, '速度响应很快，已经开始用了，从cc9pro直接过度到civi2。很适合女性使用。京东速度一如既往的快，第二天就到。\n外形外观：好看\n屏幕音效：靓丽\n拍照效果：漂亮\n运行速度：快\n待机时间：长\n其他特色：价格合适', '小白裙', '2022-10-19 17:47:16', 3);
INSERT INTO `data` VALUES (12074, 'j***1', 5, '老婆之前的那个华为手机用了多年虽说仍是好的但到了该淘汰的时候了，看到小米新出的这款civi2，外观靓丽，特别是这款怦怦粉，犹如一位青春活泼又不失优雅的大眼少女，令我这个大男人看了都怦然心动！机子到手，老婆爱不释手，初试了一下，屏幕清晰艳丽，系统顺畅，前置摄像头自拍是亮点，买的最大内存版本这下应该够用很长一段时间了，至于性能参数也不太懂，实用之后再慢慢体验了', '怦怦粉', '2022-10-19 09:35:30', 5);
INSERT INTO `data` VALUES (12075, 'g***4', 5, '外形外观：轻薄程度：很薄，很轻，很舒服\n拍照效果：手抖也不怕，个人觉得比12好\n待机时间：2日一充\n运行速度：不打游戏，普通够用\n屏幕音效：可以', '小白裙', '2023-02-05 23:16:43', 3);
INSERT INTO `data` VALUES (12076, '是***-', 5, '手机很好，性价比特别高，父母用着很合适，小爱语音功能我感觉不错，父母年纪大很多东西找不到，小爱都可以帮助解决，避免了很多麻烦。', '怦怦粉', '2023-03-03 11:32:45', 2);
INSERT INTO `data` VALUES (12077, 'n***2', 5, '小米CV 2小白糖，手感超级的棒，贝壳这样的一种触感，非常的轻薄，适合女孩子，特别要赞的是它的拍照功能，无敌的适合少女&bull;', '小白裙', '2023-01-05 09:24:52', 4);
INSERT INTO `data` VALUES (12078, 's***7', 5, '手机已经用了好些天才上来评价的。首先这款小米civi2样式很好看?，全面屏虽不新颖却不失它的独特。轻薄款式也是civi2的优势之一。机身原装软件比较多，幸好是可以随意删去多余或不需要的。这些天我用的功能还不多，所以觉得很好用哦。期待后面还会一如既往好用。', '小白裙', '2023-01-25 11:39:46', 4);
INSERT INTO `data` VALUES (12079, '水***U', 5, '一直用小米，系统很人性化，旧手机两年了还在用，这次换个新手机，相机非常强大，拍照效果优化的很好，质感也很好，官方配的壳膜很贴心，67瓦快充实测不到一小时内充满，背后的小屏幕是惊喜，总之很满意国画之光，支持小米。无线充非常棒！', '小白裙', '2022-11-14 19:25:23', 4);
INSERT INTO `data` VALUES (12080, 'j***f', 5, '买来当备用机的，发货第二天就到了，让我立刻拿到了新手机\n外形外观：颜值和外观?没得说，特别好看，也很轻薄可爱，如果是男朋友送我这么可爱的手机我会高兴死\n屏幕音效：单扬声器，但是声音很大，??杜比全景声\n拍照效果：前置的补光灯很有创意，虽然自拍还是没有水果手机好看，但是我觉得挺不错的\n待机时间：这个待机时间我有话说！4500毫安?快充，但是充得快用的也快，打一把王者会消耗百分之十以上，续航时间不长。', '潮流色', '2023-02-14 01:03:14', 3);
INSERT INTO `data` VALUES (12081, '桃***e', 3, '耗电快，有点卡，但拍照清晰，外观好看。', '怦怦粉', '2023-01-10 01:20:35', 8);
INSERT INTO `data` VALUES (12082, 'j***g', 5, '小米civi2,外观特别漂亮，轻薄，手感非常好 前后镜头拍照功能强大，续航能力强。', '怦怦粉', '2022-10-02 14:59:26', 6);
INSERT INTO `data` VALUES (12083, 'l***x', 5, '这手机太可爱太漂亮了！收到以后马上打开，心情瞬间明亮了起来！爱了爱了！??????拿在手里手感非常好，各方面功能也很棒，赠品也非常精致，很满意！支持小米手机！支持国产！????????????', '潮流色', '2023-02-10 09:43:56', 6);
INSERT INTO `data` VALUES (12084, '陶***茂', 5, '非常nice的一款手机，首先是外观非常好看，尤其是粉色的，后壳伯陵柏岭的，其次续航没得说收到第一天充满，到现在已经是第三天了，还有百分之50的电。照相真的好看，自带的美颜效果确实不错。而且打视频电话也有美颜功能。真的非常好，很喜欢这款手机。', '怦怦粉', '2023-02-02 11:25:23', 4);
INSERT INTO `data` VALUES (12085, '尽***民', 5, '外形外观：微弧面屏，设计合理，手感舒适。\n屏幕音效：声音清晰，音量大小合适。\n拍照效果：后5000万，前3200万+美颜，拍照真实，清晰。\n运行速度：骁龙7系列，满足日常所需，杆杆得。\n待机时间：一次充饱，日常中度使用（刷抖音，微信，听歌），可以用一天。\n其他特色：自拍很强大。', '怦怦粉', '2022-10-16 16:26:50', 2);
INSERT INTO `data` VALUES (12086, 'j***2', 5, '外形外观：很轻薄，很漂亮\n屏幕音效：屏幕很清晰细腻，阳光下也能清楚显示\n拍照效果：还原效果很赞\n运行速度：流畅又丝滑\n待机时间：中度使用一天一冲', '冰冰蓝', '2023-01-22 16:36:44', 2);
INSERT INTO `data` VALUES (12087, 'r***n', 5, '轻薄好看，只有7毫米薄，骁龙7处理器没毛病，响应很快，日常用足够了，拍照效果很好，尤其是前置摄像头，还带广角，电池4500mAh，这个电量对于这么轻薄的手机来说确实挺挺大的，足够用了。', '冰冰蓝', '2023-01-01 10:36:52', 2);
INSERT INTO `data` VALUES (12088, '伱***诺', 2, '外形外观：外观很轻薄，手感也合适\n屏幕音效：之前买的直屏手机贴膜就不好贴，安卓手机要用曲屏的，虽然没有双扬声器，声音还是挺大的\n拍照效果：拍照也很清晰，微距镜头也可以拍清楚\n运行速度：速度够，玩游戏一点不卡', '朦朦黑', '2023-02-17 09:00:41', 3);
INSERT INTO `data` VALUES (12089, 'j***g', 5, '外形外观：超级好看，还很轻薄，适合女生单手操作\n\n拍照效果：逆天。前后摄像头拍照都很美，后置摄像头可以拍很远的距离，依旧清晰。\n屏幕音效：很好，可圈可点\n运行速度：尚可\n此外，功能还很好，推荐女生采购。', '怦怦粉', '2023-01-07 18:12:27', 2);
INSERT INTO `data` VALUES (12090, '过***活', 5, '外形外观：外观粉色，边角圆润，手感很好！\n屏幕音效：明目效果很好，老人看着很清晰！\n拍照效果：老人用刚刚好！\n运行速度：杠杠的！\n待机时间：超长待机！\n其他特色：充电速度很快！', '怦怦粉', '2023-02-15 22:25:03', 2);
INSERT INTO `data` VALUES (12091, 'j***w', 5, '手机大小适中，也不重，而且充电是真的快，基本使用耗电是不快的（目前还没有用它刷视频 追剧啥的），拍照自拍的时候屏幕上方，左右各一个补光灯，真的很适合爱拍照的小姐姐', '怦怦粉', '2022-10-14 18:15:34', 3);
INSERT INTO `data` VALUES (12092, '战***0', 5, '到货就迫不及待打开了，果真没有让我失望，质量特别好，颜值也相当高，满意的一次购物正品，棒棒哒，价格很优惠，总而言之挺好的，还会再买产品包装精致美观大气，目前用着非常不错，真实评价，希望可以帮到集美们这个颜色很喜欢，摸起来质感不错，百搭～包装也很大气，用来送人的话也是不错的选择一次很好的购物体验，服务周到，物流快速，配送也很周到，态度也很好，好评！', '朦朦黑', '2022-11-12 14:34:58', 6);
INSERT INTO `data` VALUES (12093, '落***n', 5, '用了两天再来评价，外观好看非常薄，屏幕效果不错，拍照效果非常好，适合爱拍照的，都不用修图，充电速度非常快啊，耗电还好，一天没有问题，。运行速度一般般，内存够大，适合我这不玩游戏的。。还送了吹风机镜子非常好。', '怦怦粉', '2023-03-05 15:46:38', 3);
INSERT INTO `data` VALUES (12094, 'S***s', 5, '在京东自营旗舰店买的小米civi2，今年9月底上市的。收到手机，很漂亮，轻薄，手感也很不错。使用流畅，拍照效果也很棒。', '朦朦黑', '2022-10-10 14:23:48', 4);
INSERT INTO `data` VALUES (12095, 'j***9', 5, '发货很快，昨天晚上20:10下单今天上午九点多就到了，手机颜值很高，跟本人178拿在手里大小很合适，其他没啥没啥可说的，小米品质值得信赖，而且这个价位正常使用没问题！', '冰冰蓝', '2023-02-10 21:35:17', 3);
INSERT INTO `data` VALUES (12096, '神***色', 5, '首要是外观，背面在充足光线下，不同的角度反射不同的光泽，很闪很亮眼。手机很轻薄，很适合女生使用，背面的弧度非常贴合手的握感。最主要的还是拍照效果，背面的还算不错，比不过旗舰，但是前面的镜头就非常好了，直接集成美颜优化，跟后置镜头一个水平了。可惜就是音效弱很多，明显杂音很多。', '冰冰蓝', '2022-11-19 21:46:08', 3);
INSERT INTO `data` VALUES (12097, '有***肆', 5, '外形外观：颜值很高，很漂亮的蓝色，曲面屏幕，很轻薄，但是塑料中框\n屏幕音效：听音乐音质不错，屏幕色彩也很nice，很清晰\n拍照效果：还算不错，前置yyds\n其他特色：没有耳机孔了&hellip;', '冰冰蓝', '2022-10-31 16:00:32', 2);
INSERT INTO `data` VALUES (12098, 'm***文', 5, '外形外观：轻薄好看\n屏幕音效：一般 声音大有杂音\n拍照效果：非常好 拍照很好看\n运行速度：运行速度一般\n待机时间：待机时间：有点 短     \n赠品很好看', '怦怦粉', '2022-12-03 15:53:22', 2);
INSERT INTO `data` VALUES (12099, '南***s', 5, '好漂亮的kitty谁懂啊！！！好好看！！男朋友送的，好喜欢呜呜呜，摸起来手感很好，送的壳也好漂亮，暂时没有太阳，等出太阳了回来追评。\n拍照效果：挺好的\n外形外观：超好看', '潮流色', '2023-02-09 21:47:03', 4);
INSERT INTO `data` VALUES (12100, 's***阳', 3, '自拍确实不错，但其他方面我只能讲不值这个价', '怦怦粉', '2022-10-16 18:25:58', 9);
INSERT INTO `data` VALUES (12101, '秋***m', 5, '小米新出的手机，特别适合女孩子用，刚好闺女要换手机了给她安排一个，给她选了个粉色的。直接寄她学校去的，拿到手非常惊喜，前置摄像头拍照特别好看，真的特别喜欢 ，还带补光灯，电池续航一天一充，送了个镜子各梳子的礼盒也很不错&hellip;&hellip;', '怦怦粉', '2023-01-03 20:30:04', 3);
INSERT INTO `data` VALUES (12102, '顾***顾', 5, '用了一段时间了再过来评价，非常适合女孩子使用，自拍的柔光灯拍出来效果非常的好，出厂就自带的贴膜，省去了贴膜的过程。机器运行的速度也非常的快，拍照浏览网页，使用起来没有任何卡顿，非常棒~', '冰冰蓝', '2022-12-27 15:57:11', 4);
INSERT INTO `data` VALUES (12103, 'S***s', 5, '在京东自营旗舰店买的小米civi2，今年9月底上市。包装漂亮，手机外表很漂亮，手感轻薄，拍照效果也不错，新手机很流畅。', '冰冰蓝', '2022-10-10 14:26:36', 4);
INSERT INTO `data` VALUES (12104, '大***香', 5, '确实不错，很惊讶能做这么好，颜值担当，轻薄单手操作不费劲。运行速度挺快的，拍照对我而言也是够用的。价格略高了一点。', '朦朦黑', '2022-12-01 21:09:49', 4);
INSERT INTO `data` VALUES (12105, '遥***1', 5, '小米的灵动岛给我女儿买的，她很喜欢，手机非常流畅，用的也蛮好，就是那个赠品镜子和梳子明明显示一起发的，结果手机都到了，赠品才刚出库，', '怦怦粉', '2022-11-02 19:29:36', 6);
INSERT INTO `data` VALUES (12106, 'j***e', 5, '外观颜值：颜值很高，颜值很高；\n\n?商品收到了，包装得很好，物流非常快，客服态度很积极，有问题及时解答！总体来说非常满意！', '怦怦粉', '2023-02-04 00:03:19', 6);
INSERT INTO `data` VALUES (12107, '爱***爸', 5, '这款手机真的是为女生量身定做的，首先外观十分漂亮，颜色是女生喜欢的那种，手感很轻，十分容易上手！另外拍照功能十分强大，值得关注的是自拍都非常强大！所以买给老婆作为礼物是无可挑剔的！', '怦怦粉', '2022-10-03 10:03:32', 3);
INSERT INTO `data` VALUES (12108, 'j***0', 1, '颜值和手感并存的女性专用手机，性价比非常高，拍照很牛，前置甚至比很多手机的后置效果都好。手机很薄，本以为电池不行，但用了几天发现待机还不错，比想象中好了很多。不玩游戏，骁龙7已经够用了。', '朦朦黑', '2022-11-07 17:58:56', 3);
INSERT INTO `data` VALUES (12109, 'k***7', 5, '当时在小米这一款和K20至尊版已经纠结了很久。后来发现这款是主打年轻美颜所用的，外壳和背部的结构也很别致。主要是前自拍镜头还带补光灯，很适合用来给年轻女生做自拍。', '小白裙', '2022-11-28 12:02:33', 4);
INSERT INTO `data` VALUES (12110, 'z***5', 5, '外形外观：很轻薄，手感确实很不错\n屏幕音效：音效不错\n拍照效果：前置摄像头是亮点，很特别\n运行速度：运行的软件多了有点卡\n待机时间：待机时间还行', '怦怦粉', '2022-12-25 11:24:38', 2);
INSERT INTO `data` VALUES (12111, '怎***0', 5, '8+3+256还是够用了，128现在感觉不咋够用了，还是直接买个内存大一点的好，玩游戏啥的也没问题，手感是真的不错，录屏很薄，重量也恰到好处，手感无敌', '怦怦粉', '2023-01-12 10:44:32', 2);
INSERT INTO `data` VALUES (12112, '不***1', 5, '机身轻薄，用起来很舒服\n屏幕音效：屏幕清透，看起来很舒服\n拍照效果：自拍无敌，就为了前置相机才买的，很满意', '冰冰蓝', '2023-03-10 20:43:04', 2);
INSERT INTO `data` VALUES (12113, '我***l', 5, '如果简单概括，可以说本次小米Civi 2最大的升级亮点就在其拍照功能上，无论是后置还是前置都有了相当大的提升。在后置上，小米Civi 2采用的是三摄像头的配备，其中主摄为5000万像素的索尼IMX766 CMOS，对于这颗主摄相信大家都不会陌生，它也是如今众多旗舰机型的选择，因为其良好的调教以及1/1.56英寸的大底，成为了不会出错的选择，在小米Civi 2使用这颗摄像头也使得整体的拍摄质感获得了极大的提升。\n\n同时在镜头上，小米Civi 2也首次采用了1G+6P的玻塑混合镜头组合，它拥有ED超低色散光学玻璃镜片以及2.0&mu;m融合大像素，这也让我们在夜景拍摄时可以获得更纯净的色彩和光源捕捉。', '小白裙', '2022-11-25 13:28:28', 3);
INSERT INTO `data` VALUES (12114, '嗨***人', 5, '外观很漂亮，收到测试了一下，操作很流畅。很好的手机，会推荐朋友买。', '朦朦黑', '2022-10-28 16:44:22', 2);
INSERT INTO `data` VALUES (12115, 'D***图', 5, '外形外观：非常漂亮比图片上的好看\n屏幕音效：屏幕很清晰，扬声器效果不错\n拍照效果：前摄像头简直拍照神了\n运行速度：不错比想象的要快\n待机时间：电池比较耐用', '怦怦粉', '2022-10-10 08:18:49', 2);
INSERT INTO `data` VALUES (12116, '笑***团', 5, '外形外观：轻薄\n屏幕音效：很好\n拍照效果：真的不错\n运行速度：很快\n待机时间：很久\n其他特色：就是好看', '小白裙', '2023-03-13 10:23:39', 2);
INSERT INTO `data` VALUES (12117, '不***律', 5, '外形外观：外观好看，手感也不错！\n拍照效果：拍照效果很强，功能很齐全，纹理的处理也很细节！\n运行速度：处理器的话，正常使用没啥问题，相对流畅！', '朦朦黑', '2022-10-19 22:15:22', 1);
INSERT INTO `data` VALUES (12118, '大***地', 5, '外形外观：颜值绝绝子，小白裙背面的条纹很好看\n\n拍照效果：自拍前摄有两盏补光灯\n\n运行速度：7GEN1速度还是杠杠滴\n其他特色：充电速度贼快', '小白裙', '2022-10-15 19:32:12', 3);
INSERT INTO `data` VALUES (12119, 'f***L', 5, '一直用小米手机，性能一如既往的不错，外观设计越来越时尚，颜值超高，手感柔软很轻薄，拍照技能更是非常强大，强烈推荐，支持小米。', '怦怦粉', '2022-11-29 16:05:43', 4);
INSERT INTO `data` VALUES (12120, '黎***y', 5, '还不错 手机外观很漂亮。\n拍照效果：拍照很nice\n运行速度：稍有卡顿\n待机时间：很不错 充一次电 可以用一整天', '冰冰蓝', '2022-12-16 12:45:32', 2);
INSERT INTO `data` VALUES (12121, 'L***呀', 5, '手机很不错呀 妈妈很喜欢 以后就选小米啦\n外形外观：好看\n屏幕音效：还可以\n拍照效果：美颜强大\n运行速度：暂时感觉不错\n待机时间：续航还行\n其他特色：有待观察', '冰冰蓝', '2022-10-26 08:55:26', 1);
INSERT INTO `data` VALUES (12122, 'p***6', 5, '外形外观：比较轻薄，单手能操作\n屏幕音效：质感很好，显示细腻\n运行速度：目前还可以，不玩游戏完全够用', '朦朦黑', '2023-03-16 08:53:11', 3);
INSERT INTO `data` VALUES (12123, 'j***I', 5, '外形外观：颜值高，很适合大学生\n拍照效果：美颜很好，非常适合自拍\n运行速度：很流畅\n其他特色：可以跟小米电脑互传，效率很高，有助于学习', '冰冰蓝', '2022-10-14 20:54:26', 1);
INSERT INTO `data` VALUES (12124, 'K***a', 5, '运行速度：快\n\n拍照效果：好\n\n屏幕音效：好\n\n外形外观：好\n\n待机时间：长\n其他特色：好\n非常好的一款手机', '怦怦粉', '2022-10-28 09:43:48', 2);
INSERT INTO `data` VALUES (12125, '小***i', 5, '太喜欢这手机了颜值高，很薄，而且像素还不错。\n充电很快，三四十分钟就充满了，日常使用用一天没得问题。\n对比了很多款手机，最后选择了这一款，性价比很高', '冰冰蓝', '2022-10-17 18:28:15', 2);
INSERT INTO `data` VALUES (12126, 's***o', 5, '外形外观：白色，小白裙。\n屏幕音效：画面细腻。\n拍照效果：5000w还是厉害。\n运行速度：新机，运行速度很快。\n待机时间：一天还是可以的。\n其他特色：带充电器，比一代好。', '小白裙', '2023-02-04 16:29:05', 2);
INSERT INTO `data` VALUES (12127, 't***e', 5, '快递很快，手机实用性和颜值都非常的赞，买给老婆的，她很喜欢，她说这手机拍照效果很好，手机也很轻薄，小仙女必备。一直用的小米手机，质量值得信赖。', '小白裙', '2022-12-30 22:22:01', 3);
INSERT INTO `data` VALUES (12128, 's***宝', 5, '作为小米的忠实粉，之前的手机是小米CC9，不足2K居然用了3年之久，更换的原因为卡槽松，电池不耐用，刚好推出了小米Civi2手机，毫不犹豫的下手，已用半月有余，暂未发现任何异常，充电器充电速度非常快，非常满意。', '冰冰蓝', '2022-10-15 14:07:34', 2);
INSERT INTO `data` VALUES (12129, '持***话', 5, '性价比高，物流速度很快，手机外形美观，屏幕音效好，拍照也很清晰，以前用的就是小米的牌子，一直很好用，手拿着不大不小，刚刚好，质量有保证，比实体店便宜', '朦朦黑', '2023-02-09 14:04:05', 2);
INSERT INTO `data` VALUES (12130, 'c***0', 5, '外形外观：非常好看，方方正正，感觉挺干练的，而且机身也薄，拿在手上很舒适，非常不错的一台机，直接推荐。', '小白裙', '2022-10-27 17:31:42', 3);
INSERT INTO `data` VALUES (12131, 's***n', 5, '手感轻薄，颜色漂亮，曲面屏用起来也很顺滑，尤其是自拍镜效果非常好，果然是有涂层的，在逆光环境下有效果。五星好评，老婆大人很满意。', '怦怦粉', '2022-11-19 13:02:13', 2);
INSERT INTO `data` VALUES (12132, 'j***z', 5, '外形外观：非常漂亮，看见就爱了\n屏幕音效：很不错的。\n拍照效果：非常强大\n运行速度：一个字，快', '小白裙', '2022-10-15 20:59:44', 2);
INSERT INTO `data` VALUES (12133, 'j***c', 5, '小米手机已收到，包装完好无损，手机外观颜值很高，运行速度很快，触控灵敏，反应快。京东昨天下的单，今天中午就收到了。', '朦朦黑', '2022-11-10 16:30:22', 4);
INSERT INTO `data` VALUES (12134, 'j***A', 4, '颜值高分，流畅，用了一周，流畅无比和苹果13差不多，相机拍照效果很好，夜景效果很突出。2000左右性价比最高的了。京东送货快，价格比小米之家便宜50还多了赠品。', '冰冰蓝', '2023-02-14 19:36:48', 2);
INSERT INTO `data` VALUES (12135, '清***心', 5, '外形外观：不错很好，外观好看\n屏幕音效：显示很好，虽然单扬声器但是效果不错\n拍照效果：自拍很好看，后置还可以\n\n待机时间：待机很好', '冰冰蓝', '2022-10-02 07:07:06', 2);
INSERT INTO `data` VALUES (12136, 'j***s', 5, '京东物流快。包装好。买的黑色。显大气。时尚。手感不错。很薄。握着舒服。像素不错。图片清晰。很喜欢。推荐购买。', '朦朦黑', '2022-10-20 14:33:04', 2);
INSERT INTO `data` VALUES (12137, 'b***o', 5, '这手机很轻薄，手感很好，续航不错，67w的充电速度也足够快，拍照效果非常好，nice！！！\n京东的物流没得说，本地仓有货，上午拍，下午到。\n京东金融也赞，还能免息分期。', '冰冰蓝', '2022-10-14 21:54:23', 3);
INSERT INTO `data` VALUES (12138, '约***G', 5, '手机是真的很好看\n很轻薄，手感很好，限定版真的很独特，配色和外观绝绝子，手机壳阳光下变色也是非常独特了，点赞\n充电67w很快，屏幕也很清晰，处理器虽然不是最新的，但是上一代的也完全够用\n京东快递也要点赞一个', '潮流色', '2023-02-19 09:21:50', 2);
INSERT INTO `data` VALUES (12139, 'j***z', 5, '充电非常快，出外玩的时候，一会儿就充满。\nHELLO KITTY在阳光下会变粉红，创意十足。\n限量版值得拥有！真的喜欢，希望多出主题，可以出情侣款，可以再大屏一些男友也能用，小米有创意。', '潮流色', '2023-02-19 02:51:29', 3);
INSERT INTO `data` VALUES (12140, '饭***1', 5, '第一眼接触它我就打消了买iPhone14pro max的念头，真的手感太棒了，圆边，后壳小白裙设计，超薄，手感超一流，之前用过6.3mm的手机，这个虽然7.多mm厚，但是手感真的太棒了！！', '小白裙', '2022-11-29 23:32:55', 2);
INSERT INTO `data` VALUES (12141, 'j***y', 5, '手机特别轻薄，屏幕也大，用完某果之后，感觉国产手机功能真的强大，拍照还自带美颜，终于又爱上自拍了！赠品也很完美，感觉这款手机专为女生定制的。', '小白裙', '2022-10-15 17:16:00', 2);
INSERT INTO `data` VALUES (12142, '抽***我', 5, '挺好用的，很灵敏，性价比高，手感很好，很漂亮，我很喜欢，好适合女孩子啊！拍照也很好看。\n下面的图片就是用手机在台灯下拍的。', '小白裙', '2022-12-03 21:53:54', 2);
INSERT INTO `data` VALUES (12143, 'A***o', 5, '一直用的都是小米的手机，这款手机手感特别好，充电速度快，屏幕清晰，尤其是拍照自带美颜功能，特别喜欢。', '小白裙', '2023-03-16 10:26:54', 3);
INSERT INTO `data` VALUES (12144, 'w***n', 5, '很好！不错！分辨率也是很不错！外观挺漂亮！\n外形外观：好看\n屏幕音效：好\n拍照效果：效果不错！', '小白裙', '2023-03-12 12:25:22', 1);
INSERT INTO `data` VALUES (12145, '兰***貅', 5, '颜值很高，适合女生用，也很轻，主打拍照功能很好，美颜很自然，速度也够日常使用了，。', '怦怦粉', '2023-03-12 20:16:55', 2);
INSERT INTO `data` VALUES (12146, '千***0', 5, '小米civi2设计依然非常漂亮，质感非常好，去年买了小米civi，用了一年感觉非常好用，今年继续小米civi2，拍照功能也非常好，轻薄漂亮。', '冰冰蓝', '2022-10-29 13:56:59', 4);
INSERT INTO `data` VALUES (12147, '韩***典', 5, '收到了。。。第一时间拆开包装，与卖家描述一致，完全超出我的期望值，包装也很给力，还赠送了手机壳和手机自带模，总的来说又是一次满意的购物体验&hellip;', '朦朦黑', '2022-12-04 06:29:36', 5);
INSERT INTO `data` VALUES (12148, 'u***o', 5, '外形外观：很好看，年轻人第一个灵动岛。\n屏幕音效：屏幕色彩完美不愧是三星屏幕\n拍照效果：自拍太清晰了，美颜也好用\n运行速度：很快', '怦怦粉', '2022-10-03 12:12:28', 2);
INSERT INTO `data` VALUES (12149, '帅***帅', 5, '收到货后就迫不及待的打开，是小米的忠粉了，这是第N个手机。\n外形外观：外观非常的小清新，手感轻巧舒适。\n屏幕音效：屏幕色彩很鲜艳，音响效果不错\n运行速度：8+256运行速度很快，多开应用不卡顿。', '小白裙', '2022-11-02 23:20:31', 4);
INSERT INTO `data` VALUES (12150, '金***鑫', 5, '这是第二个小米手机了，之前的用了好几年，觉得还可以。这款颜值特别好看，尤其是这个粉粉的，清新又时尚。基本功能都可以，我用着也很流畅，当然我不玩游戏，也试不出来什么。最后想说，拍照真的很好。适合女生用。', '怦怦粉', '2023-01-18 19:45:51', 3);
INSERT INTO `data` VALUES (12151, 'w***a', 5, '颜色超级漂亮，而且非常轻薄，服务也太好了，连手机膜都给贴好了，还送了手机保护套，非常的满意！', '冰冰蓝', '2022-12-02 18:44:39', 3);
INSERT INTO `data` VALUES (12152, '摩***飛', 4, '手机用了几天 效果不错  轻薄 反应速度也快  拍照很不错&hellip;为独音质差些&hellip;物流快&hellip;满意～', '怦怦粉', '2022-10-22 06:41:31', 3);
INSERT INTO `data` VALUES (12153, 'j***g', 5, '小米手机收到了，非常满意，外观很好看，外观很漂亮！\n小米civi2待机续航能力比较不错，玩时间长也不会发热，价格比较实惠！', '小白裙', '2022-11-06 17:29:52', 4);
INSERT INTO `data` VALUES (12154, '三***0', 5, '手机确实拿起来很轻，手感太好了，对于小手女生来说，很友好。手机也很好看，很nice。自拍太绝了，打遍机圈无敌手的存在，很好。', '冰冰蓝', '2022-11-13 09:07:52', 2);
INSERT INTO `data` VALUES (12155, 'j***t', 5, '买的以前款升级版。同步数据后感觉两只手机无缝衔接，速度刷刷地快，昨晚收到就用上了，摄像头很棒，小米手机电池超级好，耐用，旧手机都舍不得扔了', '小白裙', '2023-01-11 09:57:41', 3);
INSERT INTO `data` VALUES (12156, 'x***1', 4, '给家里老人买的，非常好用，系统运转很快，操作便捷，使用起来不比苹果华为差啊。性价比可以，颜色也喜欢。老人觉得用起来很不错！', '怦怦粉', '2022-11-26 15:22:44', 2);
INSERT INTO `data` VALUES (12157, 'H***E', 5, '?超级好用！还很美观！墙裂推荐！有需要再回购！\n拍照效果：发货很快，包装的很好，价格也特别实惠，还有这么多功效也是不错了，值得购买', '冰冰蓝', '2022-10-29 18:36:09', 3);
INSERT INTO `data` VALUES (12158, 'j***f', 5, '之前金东上买过k40, 很多错！这次这个机器同样的优秀，轻薄，黑色光滑细腻，照相效果也很好！值得推荐！', '朦朦黑', '2023-02-12 23:53:57', 3);
INSERT INTO `data` VALUES (12159, 'j***h', 5, '不得不夸一下这款的外形，特别是白色的小白裙，颜值担当。另外尺寸重量，女性用都非常合适。市面上为数不多的专为女性设计的手机。性能配置中上，加上专为女性优化的拍照功能，推荐购买。', '小白裙', '2022-12-14 14:43:31', 2);
INSERT INTO `data` VALUES (12160, 'j***昕', 5, '昨晚下单，今日送达，物流很快。手机外观好看，拍照效果好，运行速度快，待机时间长', '怦怦粉', '2022-11-12 17:42:30', 4);
INSERT INTO `data` VALUES (12161, 'j***c', 5, '宝贝特别喜欢，颜值高质量好，中看又中用，有需要的朋友不要犹豫了，最后祝商家生意兴隆！东西很满意哦，美观时尚大气，客服超级有耐心，服务细致贴心，大品牌就是不一样', '潮流色', '2023-02-14 15:59:35', 4);
INSERT INTO `data` VALUES (12162, '焚***_', 5, '外形外观：外观非常好看，大小适中，手感非常好。\n屏幕音效：屏幕适中，音效银好。\n拍照效果：像素好，拍照非常清晰。\n精细运行速度：反应快，看视频没有卡顿现象，平时看看视频，浏览网页，拍照足够了。\n待机时间：充满电用一天没有问题。\n其他特色：充电速度非常快，不会发热发烫。', '时光蓝', '2023-01-16 11:42:03', 5);
INSERT INTO `data` VALUES (12163, '冷***家', 5, '京东超级给力，头天晚上下单物流第二天上午就到了，手机屏幕大，120Hz高刷很流畅，MIUI13系统不卡，反应很灵敏，手机已贴膜，有一个清水套，配有一个33w快充头，充电速度快，千元机有着高端机的质感，性价比超级高，值得购买', '子夜黑', '2023-02-11 20:25:12', 9);
INSERT INTO `data` VALUES (12164, 'm***8', 5, '外形外观：好看漂亮，好看漂亮\n屏幕音效：好\n拍照效果：清晰，红米千元机不失所望\n运行速度：快没得说。\n待机时间：长，好用特别好\n其他特色：红米手机值得信赖', '子夜黑', '2023-01-18 19:21:44', 4);
INSERT INTO `data` VALUES (12165, '静***方', 5, '外形外观：这款手机颜值很高哦，我买的黑色款，挺耐看的。\n\n屏幕音效：屏幕很大，看着很舒服。\n拍照效果：像素清晰，拍照也很灵敏。\n运行速度：运行起来也很流畅，不卡机。\n待机时间：充满之后，可以待机一整天。\n这款手机是买来送爸爸的，很适合老人用，声音也很大。', '子夜黑', '2023-01-26 22:21:52', 3);
INSERT INTO `data` VALUES (12166, 'Y***2', 5, '外形外观：手握刚刚好。不大不小。\n屏幕音效：音效很清晰，\n拍照效果：这个价位算这样了，要求不高。\n运行速度：目前来看很顺畅，就是系统予装的程序感觉很多。\n待机时间：新手机，待机时间还可以。', '镜瓷白', '2023-03-13 20:22:28', 3);
INSERT INTO `data` VALUES (12167, 'q***2', 5, '挺不错的手机，六吉内存很够用了，颜值也不错，感觉做工各方面都满意，性价比还是红米系列更好呀！MIUI系统很长时间不接触了，试试好用不', '子夜黑', '2023-01-17 17:03:33', 9);
INSERT INTO `data` VALUES (12168, 'j***幽', 5, '前不久买了一台红米note12，用起来非常顺手，红米手机的品质越来越好了，这次趁着活动合适，再买一台给老爸用，手机用着非常顺畅，没有一点卡顿的现象，无论是拍照还是***，配置都是过剩的，日常使用没有任何问题，充电速度也很快，真的很不错的一款手机。', '时光蓝', '2023-02-09 19:33:34', 8);
INSERT INTO `data` VALUES (12169, 'q***1', 5, '送货很快，今天下单，明天就到了。包装很好。很好用，很流畅。已经贴好了手机膜。还送了手机壳。是快充。屏幕很大。用起来超级丝滑。很满意。', '镜瓷白', '2022-12-23 13:46:59', 4);
INSERT INTO `data` VALUES (12170, 's***k', 5, '外形外观：老人很喜欢 轻巧\n屏幕音效：效果不错\n拍照效果：效果很好哦\n运行速度：很快能用几年\n待机时间：待机时间很长\n给老人买的，都很喜欢，miui用习惯了', '时光蓝', '2023-01-02 20:54:59', 6);
INSERT INTO `data` VALUES (12171, 'y***0', 5, '昨晚付的尾款，第二天中午就收到了，简直是极限快，拿回家联网试了试，手机非常流畅，拍照也很清晰，重量的话拿在手里正好，总之非常不错！忠实米粉一枚！希望越来越好！', '子夜黑', '2022-11-03 21:12:11', 4);
INSERT INTO `data` VALUES (12172, 'x***m', 5, '外形外观：大小合适，手感很好\n拍照效果：清晰，最后一张就是本机拍照，可比较\n运行速度：下载软件速度超快\n待机时间：第一次充电，用完再补充评价', '镜瓷白', '2022-11-04 22:50:58', 3);
INSERT INTO `data` VALUES (12173, 'c***2', 5, '手机非常的好用，如丝滑一般的小米系统，外观也是设计的非常棒，非常的好，而且价格也非常的合适，作为备用机，也是非常的不错，主机用于处理非常重要的事情，备用机用来玩，也是不错的，而且电量大，体积刚好合适，真的是不错。', '子夜黑', '2023-02-19 18:13:01', 2);
INSERT INTO `data` VALUES (12174, '太***子', 5, '外形外观：大气。6.67屏幕。视频打游戏，绝顶\n屏幕音效：声音洪亮。\n拍照效果：千元里面数一数二\n运行速度：很快，多软件运行，还算流畅。\n千元机里面性价比最好得了。国产小米值得信赖。第三款小米手机了。', '子夜黑', '2023-02-09 21:39:38', 2);
INSERT INTO `data` VALUES (12175, 'g***g', 4, '外观超级豪华大气，手感不错特别是对于充电速度那是相当满意一会就充电满了，值得推荐的一款小米手机，手机送了一个手机壳带上后如裸机的感觉效果很满意，爱说说后面的摄像头很大和水果的感觉差不多了，这一次是双十一的活动但是提前十天就开始了活动内容，京东的会员送了一张3000-300的卷算下来真的很实惠！　天玑8100，运行速度很快，性能模式安兔兔跑84万分，均衡模式跑77万分。128g内存不用担心存储问题了。屏幕显示效果很好，没有瑕疵。67瓦快充充电很快，但5080毫安电池，感觉掉电还是有点快，中度用，一天一充。后置主摄像头4合一6400万像素，光圈f1.89拍照效果一般，照相颜色稍微暗淡，没有老手机(viv0z5)4合一4800万像素的鲜亮。前置1600万像素，光圈f2.45效果也一般吧。广角摄像头玻璃下有点杂质，抖动一下掉里面去了，希望不要再出来。总体还不是比较满意，喜欢天玑8100和512大内存，对照相要求不高的可以入手，性价比很高。对于在1500以内的选择这款手机当仁不让，特别是它的cpu绝对秒杀新出来的note12，老一辈讲穿衣靠家当，这款手机足矣让你在日常使用和玩手游中淋漓尽致的玩耍', '镜瓷白', '2022-11-13 15:58:51', 5);
INSERT INTO `data` VALUES (12176, 's***k', 5, '外形外观：很时尚 也适合老人使用\n屏幕音效：声音很大，不错\n拍照效果：效果很清晰老人很满意\n运行速度：速度很快，刷视频不卡\n待机时间：时间很长，足够用', '子夜黑', '2022-12-31 21:59:10', 6);
INSERT INTO `data` VALUES (12177, '小***安', 5, '这个手机相当的不错吧！虽然买了，但是现在还没有接触摸到手机到底是个什么样的感觉，从图片外观上看颜值很高，看着很大气，1000多点的手机也相当不错的啦！希望能再来奋战个三年。', '子夜黑', '2022-12-25 13:56:28', 7);
INSERT INTO `data` VALUES (12178, '刮***宇', 5, '小米手机很好用，拍照效果很好，手机屏幕也很漂亮，外观设计风格非常独特，小米手机玩游戏也不卡，充电速度很快，质量很好，发货速度非常快。', '镜瓷白', '2023-02-01 17:24:25', 9);
INSERT INTO `data` VALUES (12179, '阿***7', 5, '外形外观：买来给婆婆用的，外观简洁大方，操作方便\n待机时间：老人用，一天冲一次电，待机时间非常好，婆婆很喜欢\n运行速度：一般用来看看视频，拍照，开机速度快。\n拍照效果：喜欢拍照，效果非常好，色彩饱满', '子夜黑', '2023-01-09 11:10:20', 4);
INSERT INTO `data` VALUES (12180, '活***儿', 3, '送话器容易损坏，其它还好', '时光蓝', '2022-12-26 13:36:36', 2);
INSERT INTO `data` VALUES (12181, 'j***h', 5, '外形外观：手感很好，也很漂亮\n屏幕音效：120hz oled不是盖的，屏幕细腻，非常流畅\n拍照效果：还可以\n运行速度：非常好，没有卡顿', '子夜黑', '2022-11-03 11:39:47', 5);
INSERT INTO `data` VALUES (12182, '想***子', 5, '外形外观：颜值真的太高了，很好看，简洁大方\n屏幕音效：屏幕很清楚，滑动起来很流畅，效果很好\n拍照效果：拍照不错，自带美颜，挺棒的\n运行速度：运行速度流畅，还不错\n待机时间：待机时间还可以，具体没有去测\n其他特色：给家里老人买的，屏幕大，用起来很方便', '子夜黑', '2023-01-26 09:12:05', 4);
INSERT INTO `data` VALUES (12183, 'd***o', 5, '外形外观：天蓝色很漂亮，外形大气，男生用大小挺合适。\n屏幕音效：清晰度不错，基本没有颗粒感。色彩也比较丰富。\n拍照效果：很清晰，对焦比较快。\n运行速度：很流畅，没有卡顿。没玩游戏，不知道玩游戏卡不卡。\n待机时间：新手机续航一天没问题。', '时光蓝', '2022-11-07 11:05:42', 4);
INSERT INTO `data` VALUES (12184, 'l***1', 5, '外观时尚，白色的特别好看 1屏幕音效：屏幕清晰，音效很好 1拍照效果：拍照清晰，防抖效果不错 1运行速度：运行速度很快，操作流程，骁龙4gen cpu不错 1待机时间：待机时间长，电池耐用', '镜瓷白', '2022-11-09 20:12:09', 4);
INSERT INTO `data` VALUES (12185, 'j***h', 5, '一直用的小米，很多智能设备都是小米的，这手机颜值高，买给母亲用的，性价比高，非常好看 120hz高刷', '镜瓷白', '2022-11-04 12:39:54', 4);
INSERT INTO `data` VALUES (12186, 'j***g', 5, '手机收到了包装很严实。试用了一下真的很好运行内存空间大很流畅。用到现在还没有充电哦续航还不错??????????', '时光蓝', '2022-11-19 18:46:47', 9);
INSERT INTO `data` VALUES (12187, '哈***T', 5, '很好很好，非常值，这个价位应有的颜值和性能，千元机做成这样非常不错\n拍照效果：扫码水平\n待机时间：手机续航非常棒，用一天没压力', '镜瓷白', '2022-11-06 15:37:56', 6);
INSERT INTO `data` VALUES (12188, 'h***h', 5, '外形外观：轻巧轻薄手感很棒\n屏幕音效：屏幕清晰，打王者没问题，妥妥的\n拍照效果：拍照要求不高，完全胜任\n运行速度：开始超级棒\n待机时间：白天8小时没问题的\n其他特色：性价比很高的', '镜瓷白', '2022-11-14 22:23:31', 6);
INSERT INTO `data` VALUES (12189, '林***7', 5, '外形外观：外观精美，握感良好，大小也刚刚好！\n屏幕音效：屏幕很棒，色彩很漂亮。音质不错，刷剧非常爽。\n拍照效果：拍照还可以，就是防抖比较一般，还需要优化。\n运行速度：速度很快，希望可以一直这么快吧！\n待机时间：一天一充，充电速度很快，满足需求了。', '子夜黑', '2023-01-29 19:25:20', 4);
INSERT INTO `data` VALUES (12190, 'j***M', 5, '手机很轻薄，屏幕也很大，侧边指纹解锁方便好用。高刷屏打游戏很赞，操作不会断触，流畅度非常高。运行速度很满意，玩王者、吃鸡这种都还可以，而且电池大、充电快，续航很踏实。整体来说，性价比非常高。', '子夜黑', '2023-03-03 13:17:48', 4);
INSERT INTO `data` VALUES (12191, '巴***匠', 5, '外形外观：美观轻薄，手感特别好。\n屏幕音效：声音也比较大，给妈妈买的，很满意。\n拍照效果：拍照完全够用，不是很惊艳，对得起这个价位。\n运行速度：不玩游戏，感觉不到卡顿，6G日常使用足够了', '镜瓷白', '2023-03-19 22:27:42', 4);
INSERT INTO `data` VALUES (12192, 'S***6', 5, '双十一搞活动买的，隔天就到了，速度杠杠滴，包装也非常的好，没有破损，质量也是没得说，棒?\n外形外观：很可爱\n屏幕音效：挺好\n拍照效果：千元机里面还是不错的\n运行速度：可以\n待机时间：长\n其他特色：MIUI还是挺好用的', '时光蓝', '2022-11-01 19:42:51', 6);
INSERT INTO `data` VALUES (12193, '冻***1', 5, '外形外观：白瓷色很好看\n屏幕音效：屏幕真的不错，音效也好\n拍照效果：挺不错的\n运行速度：可以的\n待机时间：很耐用\n其他特色：系统很好，充电也很快', '镜瓷白', '2023-02-25 19:51:52', 4);
INSERT INTO `data` VALUES (12194, 'z***0', 5, '作为老年机很适合，重量轻，电池大，屏幕大，带3.5mm耳机插孔，带红外，33w快充也够用了，与手机后壳同色摄像头低座很赞，比小米13黑色好看多了！手机套带防尘塞点赞，不但防尘还不硌手，总之很好的一部老年学生手机', '镜瓷白', '2023-01-08 23:11:34', 4);
INSERT INTO `data` VALUES (12195, 'z***7', 5, '我特意选了蓝色，没有让我失望。试用了一下速度流畅。屏幕升级成OLED屏幕确实比我以前的红米10要清晰很多。系统不卡顿。送货很快', '时光蓝', '2022-11-06 12:09:33', 3);
INSERT INTO `data` VALUES (12196, '南***李', 5, '买的白色超级好看，拍照?功能也很强大！像素?真的超级清晰，拍风景照特别好看！续航不打游戏上班够用? ??? ? ，12性能提升一大截，机子运行流畅?安全性也很高，电池?一天一充足以。对得起这个价位，使用感受不错 (-^O^-)', '镜瓷白', '2022-12-13 14:24:45', 4);
INSERT INTO `data` VALUES (12197, '风***-', 5, '为家里老人挑选一款经济实用型的手机，最终选择了红米note12，红米Note12机型的价格虽然最低，起价仅1199元，但它配备了性能不错的骁龙4 Gen1芯片，并且还配备了更大的6.67英寸OLED显示屏，以及5000mAh大电池，能够给用户带来非常好的体验相比之下，红米Note12看起来更加简约。我选择了白色版本，相机模块的颜色与背面一致，看起来非常漂亮。手机机身厚度约7.98mm，重量约188g，这样的机身厚度和重量，在这个水桶机盛行的年代，十分罕见，手机拿在手上极为轻便，不会有一丝一毫的厚重感。屏幕显示方面，OLED显示面板提供了比较好的色彩和对比度。1200尼特的峰值亮度，在户外能见度和观看体验上，仍然不错。红米Note12搭载骁龙4 Gen1芯片，并且支持5G。同时，这款手机还提供8GB运行内存和256GB存储空间，足以处理日常任务，如通话、网页浏览、看视频和轻度游戏。红米Note12保留了与其前身相同的电池容量和充电速度，这就意味着，红米Note12继续配备了5000mAh电池和33W充电器。续航倒是没有问题，电池电量一整天都用不完。', '镜瓷白', '2023-02-15 08:34:59', 4);
INSERT INTO `data` VALUES (12198, 'P***o', 5, '记得第一部小米手机是米2，从那之后就没有使用小米手机，这部手机是买给父母用的，首先看中的是性价比，8+128G内存，大屏大容量电池够用的功能！\n屏幕音效：屏幕是oled的，很好用，也很清晰，这个价格真心难得\n拍照效果：拍照清晰，够用\n运行速度：骁龙处理器，中低端的，对于这个价格真心够用了\n最后8+128G内存组合配合骁龙处理器，日常使用非常流畅的', '子夜黑', '2023-03-05 21:59:05', 5);
INSERT INTO `data` VALUES (12199, 'j***y', 3, '还行吧，刚试用了两三天', '时光蓝', '2023-02-14 17:20:28', 8);
INSERT INTO `data` VALUES (12200, '何***可', 5, '已经收到货了，商品和描述的相符，质量没问题，关键价格也合适，小米老粉。非常值得信赖的品牌，质量有保障，价格还亲民，相当满意\n外形外观：外观简洁大方，颜色很漂亮\n屏幕音效：音质也很好，听歌音质很好。显示很清晰，90hz高刷不错\n拍照效果：拍照效果非常清晰', '时光蓝', '2022-11-10 23:07:45', 4);
INSERT INTO `data` VALUES (12201, 'j***u', 5, '手机挺好的，外观硬朗，直屏好贴膜。6G内存，各种功能都能高速运行，屏幕尺寸大看视频很震撼。续航时间长，大电池33W充电很快。', '镜瓷白', '2022-11-10 20:06:22', 5);
INSERT INTO `data` VALUES (12202, 'j***o', 5, '手机到货速度很快，用了好几天，感觉挺不错的，婆婆用的很习惯，简单易学，不会那么复杂，手机网络什么都很快，很不错，续航挺久的，很喜欢', '子夜黑', '2023-02-02 09:40:42', 4);
INSERT INTO `data` VALUES (12203, 'v***o', 5, '外形外观：分量适中，太小合适，一个手操作没问题\n屏幕音效：屏幕精细，声音清澈\n拍照效果：很好，画面干净流畅，精细\n运行速度：玩英雄联盟一点不卡\n待机时间：反正用一天足够了\n其他特色：手感不错啊，比较薄，背面还是磨砂质感。', '子夜黑', '2022-11-14 16:06:59', 3);
INSERT INTO `data` VALUES (12204, 'j***z', 5, '父母没那么多使用需求，使用这个手机性价比很高。\n外形外观：外形不会出什么错，手机重量适中，拿在手上不累。\n屏幕音效：屏幕刷新率可以到120，看视频非常流畅\n\n参加了以旧换新的活动，旧机给的价格也是这些平台里最高的。', '时光蓝', '2022-11-03 23:09:14', 5);
INSERT INTO `data` VALUES (12205, 'd***6', 5, '拍照清晰，运行畅快，续航很好\n通信音质:通信音质挺好的，听起来非常清晰，用起来的感觉也挺好的!感觉真不戳! 其他特色:MIUI永远的神，运行非常流畅，感觉整挺好的，到手就是MIUI稳定版，很久没用了。MIUI还是一如既往地流畅，真好。显示效果:显示效果也挺不错的，感觉整挺好。爱了爱了!文字很清晰，屏幕，&quot;不会泛黄。看起来真不错。', '时光蓝', '2023-01-04 15:34:30', 3);
INSERT INTO `data` VALUES (12206, 'h***h', 5, '外形外观：家人很喜欢机器的外形，轻薄有手感，配合自带的手机壳，完美\n屏幕音效：画质清晰，刷屏嘎嘎快\n拍照效果：拍月全食妥妥的\n运行速度：目前速度超快，无所不能，吃鸡荣耀不在话下\n待机时间：还没测评\n其他特色：性价比极高！', '时光蓝', '2022-11-11 17:40:28', 4);
INSERT INTO `data` VALUES (12207, 'B***3', 5, '买给家里老人使用的，同等价位也对比了其他品牌，应该说红米这款有它的过人之处，老人使用，也不需要什么太过于强大的功能，看看视频打打电话这款足够了，值得推荐，做工也很不错，手感也挺好', '镜瓷白', '2023-01-19 16:31:43', 2);
INSERT INTO `data` VALUES (12208, '星***i', 5, '真不错，体验很棒??\n手机很流畅，值得推荐购买，\n屏幕很清晰手感棒，玩游戏也不卡，用一天没问题\n拍照效果：很清晰\n运行速度：很快\n待机时间：很长\n屏幕音效：声音好听\n外形外观：好看', '子夜黑', '2022-11-06 20:34:20', 3);
INSERT INTO `data` VALUES (12209, 'j***7', 5, '收到货了，很神速，赞??！！！\n外形外观：外观简洁大方\n屏幕音效：还不错\n拍照效果：够用就行\n运行速度：甩我以前的机子一条街', '子夜黑', '2022-11-13 16:20:43', 1);
INSERT INTO `data` VALUES (12210, 'c***q', 5, '外形外观：薄啊，比我之前的note 8 pro薄多了，也轻多了\n屏幕音效：外放声音比米10s小，屏幕显示效果比note 8的好\n拍照效果：挺好的，老人家用也可以了，如果要追求卓越也不会买这台啦\n运行速度：8+256的配置，用个几年也没有问题，喜欢玩游戏的也不会买这台吧\n待机时间：我设置了120帧的显示速率，可能会稍耗电，但清晰啊。哈哈哈\n其他特色：如果不需要双卡双待的话，可以插tf卡扩展，这个很人性化哦。', '时光蓝', '2022-11-03 21:25:29', 3);
INSERT INTO `data` VALUES (12211, '我***跑', 5, '手机还是不错的，上手以后看看喜欢了，有点喜欢上国产手机了，很不错呢，挺喜欢的呢。很不错的感觉，喜欢手机的功能和流畅度，很不错的。', '子夜黑', '2022-12-12 11:34:55', 5);
INSERT INTO `data` VALUES (12212, 'u***x', 5, '外形外观：外观很漂亮\n屏幕音效：屏幕很大，音效不错\n拍照效果：拍照效果很好，清晰，像素高\n运行速度：运行速度很快\n做活动买的，价格也很合适、里面自带膜和手机壳', '时光蓝', '2023-01-21 16:56:18', 3);
INSERT INTO `data` VALUES (12213, 's***8', 5, '外形外观：非常精致批量\n屏幕音效：这个价格没有对手oled 超高清\n拍照效果：夜视拍照也很清晰\n运行速度：6+128g 运行杠杠的\n红米超高性价比，从note9更换新换代到nteo12从没失望过，确实好用，直接拥有', '子夜黑', '2022-11-18 08:49:57', 4);
INSERT INTO `data` VALUES (12214, 'W***8', 5, '外形外观：很喜欢！简洁大方，样式很好看\n拍照效果：挺好的，不太重视这方面\n运行速度：速度嘎嘎快，玩游戏毫无压力\n待机时间：还行，续航不错', '镜瓷白', '2023-02-12 10:57:59', 3);
INSERT INTO `data` VALUES (12215, 'j***f', 5, '使用起来很顺畅，看视频网络好就不卡，使用久也不发热，当然我没打游戏，拍照也挺清晰的，总体是满意的性价比在那。', '镜瓷白', '2023-02-05 14:35:22', 4);
INSERT INTO `data` VALUES (12216, 'R***9', 5, '外形外观：简约大气\n屏幕音效：显示效果好\n拍照效果：拍照清晰颜色真实\n运行速度：很快\n待机时间：很好\n其他特色：买来送老人三八礼物。运行速度快，内存大，操作简单，老人很喜欢。京东物流快，价格全网最实惠', '镜瓷白', '2023-03-08 00:34:47', 2);
INSERT INTO `data` VALUES (12217, 'S***n', 5, '通信音质：好 其他特色：外观好看 显示效果：清晰 给父母买的，父母很喜欢，续航能力可以，充电速度快，屏幕显示清晰，给老人用绝对没问题。', '镜瓷白', '2023-02-11 12:28:29', 3);
INSERT INTO `data` VALUES (12218, 'j***0', 5, '物流速度快，包装防磕碰非常到位，快递员专业，手机性价比很高，实用方便，充电速度快，外观颜值高，值得拥有。', '镜瓷白', '2023-02-28 08:45:47', 7);
INSERT INTO `data` VALUES (12219, 'j***D', 3, '商家服务不好；手机看还可以；就是没耳机及手机壳', '时光蓝', '2022-12-27 10:17:04', 7);
INSERT INTO `data` VALUES (12220, 's***k', 5, '红米N12/5G，续航能力: 很好 拍照效果: 清晰 运行速度: 畅快 通信音质：清晰，没有其他杂音。 显示效果：三星的显示屏，显示清晰！ 宝贝收到了，太惊喜了，质量非常好，性价比很高，真是出乎意料！手机不错，运行流畅无卡顿，还有优惠，可以放心省钱购买，不要犹豫了很好。做工很不错，没发现什么瑕疵，个人感觉大小也挺合适，找了很久选的这款。小米大品牌值得信赖，实用性和颜值 都非常的赞，我很喜欢。', '子夜黑', '2022-11-18 13:27:10', 3);
INSERT INTO `data` VALUES (12221, 'j***a', 5, '1.手机颜色好看，大气，拿在手上手感好，使用起来，速度挺快，大电量不用天天充电挺好。照相效果也挺好，带广角的，有景深感。买的高配，性价比高，电池续航：快速充电，一般性充满电可用二天左右； 通信音质：很好的，音质不错的； 运行速度：很快的，不卡顿；', '镜瓷白', '2023-01-19 16:46:50', 2);
INSERT INTO `data` VALUES (12222, '静***方', 5, '手机非常的有颜值，看着也很大气，我是买来送老丈人的，老丈人很开心，这款手机声音很大，通话声音也很大，之前用的手机，就是声音太小了，终于把这个问题解决了，红米手机值得信赖，性价比很高。充电器是33W的，充电速度很快。', '子夜黑', '2023-01-26 22:27:05', 4);
INSERT INTO `data` VALUES (12223, 'f***3', 5, '外形外观：漂亮\n屏幕音效：屏幕音效：声音效果很好，给家里人用的 \n拍照效果：拍照效果还可以，家里人用还可以\n运行速度：运行速度，新机都还可以\n待机时间：待机时间挺长，5000ma大电池', '子夜黑', '2023-01-27 15:21:30', 3);
INSERT INTO `data` VALUES (12224, '鲁***男', 5, '外形外观：外观时尚颜色也很正很好看\n\n屏幕音效：屏幕清晰度很高\n拍照效果：拍照很好，千元机很不错了\n运行速度：运行速度很快，习惯了用小米手机\n待机时间：轻度使用可以用两天，看抖音看腾讯视频一天一冲', '镜瓷白', '2023-02-07 22:31:00', 3);
INSERT INTO `data` VALUES (12225, 'j***情', 5, '质量很好！\n外形外观：外观大气，上档次！\n屏幕音效：屏幕大，音响效果杠杠的！\n拍照效果：满足平时的要求，够用！\n运行速度：够用！\n待机时间：大容量电池！', '子夜黑', '2023-01-19 13:20:16', 2);
INSERT INTO `data` VALUES (12226, '温***y', 5, '一直用的都是小米手机，这个双十一一口气买了两部这个款式的手机，配置完全一样，只是颜色不一样，情侣机。这款手机很大气，颜值很高，尤其是蓝色手机壳的。手机屏幕挺大，适合的大，屏幕看着眼睛觉得很舒服。拍照也非常清晰。', '时光蓝', '2022-11-17 20:28:45', 4);
INSERT INTO `data` VALUES (12227, '飞***8', 5, '外形外观：手机很好看，十分轻薄\n屏幕音效：三星屏幕显示效果很好，高刷就是流畅舒服\n运行速度：系统很流畅，很满意\n待机时间：5000大电池，用一天没问题', '时光蓝', '2022-11-03 20:50:25', 3);
INSERT INTO `data` VALUES (12228, 'j***t', 5, '外形外观：外形非常好看，手感很好，拿起来很薄\n屏幕音效：屏幕显示不错，高刷新率非常流畅\n拍照效果：还可以，满足日常需求\n运行速度：可以满足日常需求\n待机时间：大电池待机时间长', '子夜黑', '2023-03-06 18:53:32', 2);
INSERT INTO `data` VALUES (12229, 'a***6', 5, '很漂亮，配置也够出色，性价比还是红米系列更好呀！千元机里很不错的了，运行速度很快，人脸识别快捷灵敏，视频效果不错，用起来的感觉也挺好的！感觉真不戳！超级给力，给父母买的，用起来超级丝滑，这款手机很大气，续航时间***人很喜欢，大小也刚刚好！使用久也不发热，速度杠杠滴', '时光蓝', '2023-03-13 23:52:58', 3);
INSERT INTO `data` VALUES (12230, 'p***u', 5, '手机质量不错，流畅度很好，正品，发货速度，第二天就到了，便捷，老板服务周到热情，物美价廉', '子夜黑', '2023-01-30 18:31:28', 8);
INSERT INTO `data` VALUES (12231, '憂***殇', 5, '外形外观：外观对比之前几代有改进。\n屏幕音效：屏幕清晰，音效不错。\n拍照效果：很清晰。方便上手。\n运行速度：运行速度快。\n待机时间：待机时间挺长，30w充电也很快。快递员的态度非常好。', '镜瓷白', '2023-03-06 11:31:31', 2);
INSERT INTO `data` VALUES (12232, 'l***0', 5, '给母亲买的，在网上选了好多款，最后朋友推荐这款，当天下午五点下单第二天中午收货，发货速度非常快，包装非常仔细、严实，试机效果不错，颜值高，操作流畅，屏幕色彩饱满，母亲很满意', '镜瓷白', '2023-03-06 06:40:44', 8);
INSERT INTO `data` VALUES (12233, '老***9', 5, '给亲戚家孩子买的，虽然配送到农村，但是速度实在是快。孩子用上以后很开心，告诉我待机时间完全没问题，足够学习用了，很值得很高兴。容量绝对够用。信任京东！一级棒！', '子夜黑', '2023-01-18 17:15:26', 1);
INSERT INTO `data` VALUES (12234, '今***7', 5, '通信音质挺好的，听起来非常清晰，用起来的感觉也挺好的！感觉真不戳！ 其他特色：MIUI 永远的神，运行非常流畅，感觉整挺好的，到手就是MIUI 稳定版，很久没用了。MIUI 还是一如既往地流畅，真好。 显示效果：显示效果也挺不错的，感觉整挺好。爱了爱了！文字很清晰，屏幕?不会泛黄。看起来真不错。', '镜瓷白', '2023-01-11 16:44:56', 3);
INSERT INTO `data` VALUES (12235, 'y***5', 5, '货收到了，质量好，物美价廉，超值划算，千元旗舰只有米机用的LED屏幕。这么好的配置，试用了一下速度快，外观漂亮，做工精细，，充电速度快，在京东买了好多产品，真心不错，头一天拍的，第二天快递小哥送到家里，物流很快啊，客服小妹服务态度好，以后还会购买的喔??????', '子夜黑', '2023-01-08 18:03:03', 4);
INSERT INTO `data` VALUES (12236, 'j***t', 5, '外形外观：外观时尚，白色的特别好看\n屏幕音效：屏幕清晰，音效很好\n拍照效果：拍照清晰，防抖效果不错\n运行速度：运行速度很快，操作流程，骁龙4gen cpu不错\n待机时间：待机时间长，电池耐用', '镜瓷白', '2022-11-02 23:05:06', 2);
INSERT INTO `data` VALUES (12237, 'F***o', 5, '外形外观：可以的。符合一般审美要求。\n屏幕音效：很清晰，不刺耳。\n拍照效果：有很多种拍摄模式，还有智能模式。\n运行速度：没有装太多的软件，运营速度很快！', '镜瓷白', '2023-03-17 11:01:56', 2);
INSERT INTO `data` VALUES (12238, '子***族', 5, '外形外观：很好看\n\n运行速度：父母很满意，也不卡\n\n待机时间：待机时间也够久\n\n拍照效果：拍照要求不高，符合预期，也不错，和父母视频效果不错', '子夜黑', '2023-01-22 11:22:01', 2);
INSERT INTO `data` VALUES (12239, 'j***W', 5, '外形外观：好看\n拍照效果：非常清晰\n待机时间：待机长\n运行速度：运行速度非常快\n其他特色：跟实体店一模一样', '镜瓷白', '2023-02-05 21:16:56', 3);
INSERT INTO `data` VALUES (12240, 'p***y', 5, '几年前买过一部红米的手机，感觉使用起来还是不错的，电池续航挺好，也比较耐用，这次给老妈换手机，又想到了红米，到手机实体店也体验了一下，觉得红米手机的品质也越来越好了，这次趁着活动就买一台给老妈用，手机用着顺畅，没有一点卡顿现象，对于年纪大的人来说日常使用也没有任何问题，充电速度也很快，外观颜色适中好看，大小手感也挺好。 日常使用足够，值得入手。 京东物流送货又快又省心，购物体验不错。', '时光蓝', '2023-03-04 14:46:55', 6);
INSERT INTO `data` VALUES (12241, '志***卫', 5, '手机很不错，摄像头很好！买了个大内存的，父母很喜欢！拍照效果也很好很清晰！电池容量5000ma超级大，再也不用担心电量不够了！小米系统一如既往的好用！直接满分好评！', '子夜黑', '2023-03-04 13:58:12', 4);
INSERT INTO `data` VALUES (12242, '波***装', 5, '给爸爸买的，感觉还不错。\n外形外观：黑色的玻璃背板，手感和颜色都很好。\n屏幕音效：120HZ高刷屏，使用起来效果非常好。\n拍照效果：双摄够用，拍照效果很不错。\n运行速度：有时候会卡，但是价位摆在这里，也够用了。\n待机时间：电量足够用。', '子夜黑', '2023-01-28 22:17:51', 2);
INSERT INTO `data` VALUES (12243, '一***殇', 5, '外形外观：外观设计很好看，淡淡的天蓝色。\n\n屏幕音效：屏幕清晰，音效很好。音量挺大。\n拍照效果：拍照很清楚。像素高。\n运行速度：网不卡。很好用。\n待机时间：待机时间很长。充电也快。', '时光蓝', '2023-01-30 19:21:22', 2);
INSERT INTO `data` VALUES (12244, '杜***b', 5, '外形外观：时尚大气上档次、很好看！\n屏幕音效：音质效果非常棒声音大、显示细腻光滑清晰、\n拍照效果：拍照清晰人像真实立体\n运行速度：极致顺滑、\n待机时间：大续航里程大电池容量超长待机王\n其他特色：完美、', '子夜黑', '2022-12-27 17:48:22', 3);
INSERT INTO `data` VALUES (12245, 'b***5', 4, '外形外观：很轻很薄，手感超好，白色背很好看。\n屏幕音效：屏幕显示很漂亮，音效不比两千多的手机差\n拍照效果：拍照快，颜色比之前的10好多了(刚用这台新的淘汰旧的)\n运行速度：不算很快，但老人家用刚刚好，不会卡\n待机时间：刚用，应该没问题。\n其他特色：屏幕够大，字可以调大而不影响阅读，老人用超合适。', '镜瓷白', '2023-02-04 22:13:55', 2);
INSERT INTO `data` VALUES (12246, '楠***3', 5, '手机外观，手感都很好，屏幕无瑕疵，浏览视觉效果出众，配置也够出色，想我不完游戏，用起来很流畅。', '镜瓷白', '2022-11-07 19:28:25', 5);
INSERT INTO `data` VALUES (12247, '1***8', 5, '外形外观：非常漂亮好看，手感很好\n屏幕音效：像素很好，声音很大声，声音也很清晰\n拍照效果：拍照很高清，夜景也很好看，美颜效果也很好。\n运行速度：手机反应很快，切换app也很快，刷视频也很快。\n待机时间：充一次电能用一个星期，电池非常耐用，充电也很快，插上充电60秒一分钟就充满。\n\n其他特色：红米手机就是好，永远支持红米，性价比也很高，京东上也经常也有***，京东快递发货也快60分钟一个小时就送到', '时光蓝', '2022-12-14 21:31:39', 3);
INSERT INTO `data` VALUES (12248, '流***丶', 5, '配置还是可以的，拍照清晰，运行起来也很流畅。总体还行，性价比也不错，对得起这个价钱。充电的速度也很快，总体比较满意。', '时光蓝', '2022-11-10 23:51:37', 5);
INSERT INTO `data` VALUES (12249, '先***姓', 5, '老爹手机丢了，急用，赶紧下单了一个，快递挺快的，质量也还可以，老爹用习惯小米了，就没给他换其他的，登录上他的账号以后，所有的软件都在，很方便，大赞', '时光蓝', '2023-01-04 19:39:37', 5);
INSERT INTO `data` VALUES (12250, 'H***拉', 5, '外形外观：外观好看，瓷白色真漂亮，手感也很舒适\n屏幕音效：屏幕分辨率出色，音质效果好\n拍照效果：拍摄清晰，防抖做得好\n运行速度：运行流畅不卡顿', '镜瓷白', '2023-02-14 13:50:12', 2);
INSERT INTO `data` VALUES (12251, '流***汉', 3, '给父母买的，很好用，一直用这个牌子的，老人说很好用。\n外形外观：简洁大气上档次，低调奢华有内涵。\n屏幕音效：屏幕大，老人眼睛不好，可以字体很大。\n拍照效果：两个摄像头，不错。\n运行速度：挺快的', '镜瓷白', '2023-01-29 09:43:35', 3);
INSERT INTO `data` VALUES (12252, 's***5', 5, '屏幕音效：屏幕显示优秀，长时间看了也不伤眼睛，老人很满意。\n待机时间：一般使用的话，基本上早上出门晚上回来都够了，一天一充，方便\n运行速度：运行速度极快，没有延迟，程序秒开。', '子夜黑', '2023-01-20 10:22:47', 2);
INSERT INTO `data` VALUES (12253, 'b***8', 5, '手机挺好用的，速度也挺快，声音也很大。因为是新机，肯定没毛病。6.67寸的屏幕很大。刷屏速度也比较快。', '镜瓷白', '2023-02-03 16:28:02', 5);
INSERT INTO `data` VALUES (12254, '大***咭', 5, '京东快递特别快，前天下的单没想到现在这种情况就能收到，看了好久还是觉得这个手机不错，内存也够用，给家里大人用，很实惠', '子夜黑', '2022-12-26 10:30:49', 2);
INSERT INTO `data` VALUES (12255, '狄***章', 5, '手机其实选了很久，主要是做备用机，又需要支持广电卡，感觉很不错，最起码用起来还是很合适的，运行速度也不错，屏幕比想象中的大！整体效果还是可以的！', '子夜黑', '2022-12-25 20:36:26', 3);
INSERT INTO `data` VALUES (12256, '温***你', 5, '手机性能：续航很好 拍照清晰 运行畅快\n物流非常快，画面很清晰，操作很顺畅，拍照效果还可以，后摄比前摄好，运行速度快，充电也特别快，基本上半个小时左右就充好也。通话声音音质也还好，手机屏幕\n底下有白条操纵，代替以前的返回退出三图标，同样大的\n屏幕显得更大，用电源健做指纹识别使手机看起来更简洁。做为千元手机，性价比还是不错的。', '镜瓷白', '2022-12-03 12:20:05', 3);
INSERT INTO `data` VALUES (12257, 'j***g', 5, '外形外观：比较大的屏幕 看起来很舒服\n屏幕音效：丝滑流畅\n拍照效果：只能说还不错 算不算多好\n运行速度：记得买高配的 系统运行还是比较迟内存\n待机时间：33W快充 正常情况下很棒', '子夜黑', '2023-02-12 17:27:04', 2);
INSERT INTO `data` VALUES (12258, 'G***1', 5, '外形外观：简单实用，没有过多花里胡哨的东西，经久耐看\n屏幕音效：屏幕主流水平，这个价位正常水平\n拍照效果：够用了，要追求完美的可以绕过了\n运行速度：运行很流畅，几乎没有卡顿', '子夜黑', '2023-02-17 15:58:44', 3);
INSERT INTO `data` VALUES (12259, 'b***6', 5, '给爸妈各买了一个手机\n外形外观：好看，玻璃背面\n屏幕音效：挺好的，清晰有质感\n拍照效果：好着呢，很好的效果\n运行速度：快，很快，老人用没问题', '子夜黑', '2023-01-14 20:19:27', 3);
INSERT INTO `data` VALUES (12260, '向***妮', 5, '一直期待这款note12！这蓝色太好看了！是给妈妈买的，老年人用足够了！颜值漂亮！运行速度快！电池容量大！不枉我等了这么久！以前看评论说这款手机如何如何低配之类的，咱毕竟价钱在这呢！但是我觉得无论颜值还是性能和运行速度都相当不错了，性价比高！我都喜欢上这个手机了！真的特别好！', '时光蓝', '2022-11-01 23:00:30', 4);
INSERT INTO `data` VALUES (12261, 'g***g', 5, '给老人换机买的，用了三周了，很好很适合，颜色好看做工细致，千元机还提供了高科技的红外遥控功能和3.5耳机接口，真的意外之喜。老人用得比较满意，美中不足说是最大听筒音量比以前的小声点', '镜瓷白', '2023-02-26 17:59:18', 4);
INSERT INTO `data` VALUES (12262, '铁***徒', 5, '小米的产品质量很好，做工精细，外观时尚大气，操作简单\n特别特别满意，超级好看，客服很有礼貌，很客气，良心商家，支持！', '子夜黑', '2023-01-02 23:09:16', 4);
INSERT INTO `data` VALUES (12263, 'p***u', 5, '给老妈买的，老妈很喜欢，白的很漂亮，手感也不错，服务周到，画质清晰，系统流畅，很满意', '镜瓷白', '2023-01-30 18:33:50', 5);
INSERT INTO `data` VALUES (12264, 'j***5', 5, '外形外观：外观很有质感，黑色大气。 屏幕大，显示效果不错，\n屏幕音效：音效不错，分辨率清晰，\n拍照效果：像素好，图片清晰，不失真，拍照模式多，简单易操作\n运行速度：新机运行速度快，不跳页，不卡，浏览网页速度很快，截频方便。 \n发货速度快，包装精致，充电速度快，待机时间长。', '子夜黑', '2023-02-13 09:30:50', 2);
INSERT INTO `data` VALUES (12265, '小***光', 5, '想不到那么快就到了！收到货后试了一下，很不错，质量很好，值得拥有！五星好评！\n外形外观：很好看！\n屏幕音效：屏幕很大，口袋装不下！\n拍照效果：像素妥妥的够用！\n运行速度：很快，很流畅！\n待机时间：超长，可能是新机的原因吧！', '子夜黑', '2023-03-08 20:49:01', 2);
INSERT INTO `data` VALUES (12266, 'j***j', 5, '手机流畅，外观漂亮，待机时间长，物流很快，值得入手，还送了耳机，喜欢的米粉赶紧入手吧，，，，，，新品上市双十一巨划算，，，，，，，，，，，，，，', '时光蓝', '2022-11-04 20:41:13', 3);
INSERT INTO `data` VALUES (12267, 'l***1', 5, '小米手机很好用，这款给家人买的，特别适合，样式好看，屏幕分辨率很高，拍照效果不错，很适合家里的人使用，性价比高，快递小哥非常有速度，京东商城买的比较放心安心，质量有保证。', '镜瓷白', '2022-11-09 19:51:48', 5);
INSERT INTO `data` VALUES (12268, 'j***v', 2, '外形外观：外观简单大气，颜值方面很能打\n屏幕音效：音效不错，屏幕色彩鲜艳，没有卡顿现象\n拍照效果：拍照清晰，分辨率高\n运行速度：运行速度快\n待机时间：待机时间长，适合任何年龄使用\n其他特色：字体可以调大，这个手机性价比特别高\n\n这个手机是买给父亲的，父亲很开心，老年人使用特别方便，没有卡顿的情况，字体大小对老年人很友好，性价比高，色彩搭配很好，不会很刺眼，手机自己可以调节亮度，而且操作简单，方便，很好上手，父亲眼睛不好，打字不方便，手写也特别流畅，对手机特别满意', '子夜黑', '2023-02-01 18:37:02', 2);
INSERT INTO `data` VALUES (12269, '一***生', 4, '发货快，包装严实，各方面都没破损，颜值很高，耐看，打开网页丝滑顺畅，游戏不掉帧，分辨率高，功能很齐全，比note9好多了许多，人脸识别快捷灵敏，，黑暗拍照清晰无差异，音质清脆，待机时间超长，一天重度七八个小时，一天一冲，耐用性大大提高，爱了爱了', '时光蓝', '2022-12-03 21:09:25', 2);
INSERT INTO `data` VALUES (12270, 'j***0', 5, '红米note12手机，仔细体验发现，边框小立边真的会让手机更好看呢，另外，红米note12系列中每款颜色都特别棒，看起来都很好看。相机，766就是不一样，还有那个2亿像素镜头。\n外形外观：好\n拍照效果：额非常棒，\n运行速度：快？', '时光蓝', '2022-12-27 16:14:37', 3);
INSERT INTO `data` VALUES (12271, '三***p', 5, '手机好看，超乎想象，趁着便宜买的，家里人用的，配置够了。性价比极高', '镜瓷白', '2023-03-11 19:00:07', 5);
INSERT INTO `data` VALUES (12272, 'j***R', 5, '外形外观：美观好看\n\n屏幕音效：音质很清晰\n\n拍照效果：像素很高\n\n运行速度：快 流畅\n\n待机时间：充一次电可以用2天\n其他特色：物流很快 次日达', '镜瓷白', '2022-11-19 14:37:06', 2);
INSERT INTO `data` VALUES (12273, '2***哥', 5, '这款手机外观设计好看，性价比较实在，电池耐用，屏幕适中，音效好，运行快，值得信赖，给个五星好评！', '子夜黑', '2023-02-06 10:34:06', 5);
INSERT INTO `data` VALUES (12274, 'j***0', 5, '性价比超高的一款红米手机，非常适合家里的老人使用。\n外形外观：蓝色的很大气，周边完好无损！\n屏幕音效：显示细腻，色彩饱和度高！\n拍照效果：中规中矩，没什么问题。\n待机时间：基本上可以两天一充。\n运行速度：反正不打游戏的?', '时光蓝', '2023-02-11 10:20:15', 2);
INSERT INTO `data` VALUES (12275, '斌***然', 5, '手机给老人买的，红米在这个价位还是非常值得选择，大电池长续航，就这点很管用，老人也很喜欢', '时光蓝', '2023-02-16 12:12:37', 2);
INSERT INTO `data` VALUES (12276, 'f***8', 5, 'Redmi12是真的好，材料和做工都特别精致，做工真的非常棒，我觉着我可以推荐给我朋友买。\n拍照也很清楚，续航也不错，充电很快，一天一充。满足日常使用，给老人用很好，性价比超高！', '子夜黑', '2023-01-19 19:34:47', 3);
INSERT INTO `data` VALUES (12277, '好***好', 5, '外形外观：红米12外观设计赞美\n屏幕音效：这个手机主要是屏幕比较好，相对于价格来说！\n拍照效果：拍照也清晰！\n运行速度：大内存\n待机时间：电池容量也大\n其他特色：千元机里面有该有都有，性价比很高！', '时光蓝', '2023-02-11 12:41:21', 2);
INSERT INTO `data` VALUES (12278, 'J***张', 5, '红米收到了，用了大半天，体验不错，跟大家分享一下各方面的使用感觉，外观设计风格很好看，好评！屏幕也很好，音效也不错，拍照效果很好，运行速度很快，很流畅，待机时间很长，两亿像素真的很厉害，满电的情况下，一天够用。总体来说，这款红米note12pro的手机还是很不错，性价 比很高。期待红米越做越好', '子夜黑', '2022-11-20 23:08:21', 2);
INSERT INTO `data` VALUES (12279, 't***n', 5, '非常性价比高的手机，屏幕大小合适，清晰度高，有120的高刷，输出流畅，mimu13也合适，自带的软件可以删除，按照自己的习惯使用，整体机器外观好看，包装精美，还有33w快充，非常合适，价格也不贵', '时光蓝', '2022-12-17 21:59:29', 3);
INSERT INTO `data` VALUES (12280, 'S***2', 5, '外形外观：符合我的要求\n屏幕音效：非常棒\n拍照效果：有待提高\n运行速度：快的\n待机时间：非常的长\n其他特色：充电速度很快，还附赠了一个透明手机壳，小米同系列转移数据方便', '时光蓝', '2022-12-20 18:39:40', 2);
INSERT INTO `data` VALUES (12281, '会***熊', 5, '外形外观：手感很好，屏幕大小合适。\n拍照效果：拍照小金刚。\n运行速度：不玩游戏指定没事。\n待机时间：不玩游戏，正常使用，一天两充。', '时光蓝', '2023-01-11 17:32:17', 2);
INSERT INTO `data` VALUES (12282, '三***顺', 5, '外形外观：设计不错，屏幕大小也合适，握在手里挺好的\n屏幕音效：显示清晰，音效也还可以的\n拍照效果：拍照很清晰\n运行速度：8G运行很快', '子夜黑', '2023-03-06 20:41:34', 2);
INSERT INTO `data` VALUES (12283, '流***汉', 5, '给父母买的，一次买了两个，一个人一个，一个人用了一个，很方便。\n外形外观：高端大气上档次低调奢华有内涵，不错。\n屏幕音效：真心喜欢，颜色、款式都非常棒！\n拍照效果：不错，两个摄像头。\n运行速度：快快快，不错啊', '时光蓝', '2023-01-29 09:41:59', 3);
INSERT INTO `data` VALUES (12284, '清***r', 5, '一直以来，红米手机给人的印象就是性价比很高，这次新出的note 12系列更是把价格做到了千元机价位，并且在性能配置上也有了很大提升。这款手机是红米note12系列中的一款，价格亲民，性价比高。外观外形：手机的正面采用了居中挖孔设计，摄像头隐藏在挖孔内，配合高屏占比后盖，看上去特别震撼。使用体验：手机正面采用了6.67英FHD+挖孔屏，支持120 Hz高刷新率、480 Hz触控采样率；背部采用了双摄模组，加入了全新的 AG磨砂工艺；搭载天玑310芯片，支持8GB+256 GB存储组合。', '镜瓷白', '2023-03-09 13:52:38', 3);
INSERT INTO `data` VALUES (12285, 'l***l', 5, '外形外观：外观大气，白色很好看，让人爱不释手\n拍照效果：拍照效果很好，清晰颜色正\n运行速度：相当不错，几乎没有延迟', '镜瓷白', '2023-01-12 09:09:34', 3);
INSERT INTO `data` VALUES (12286, 'c***q', 5, '物流很快，?产品很快就收到了，比想象中还好，不错不错！希望能耐用，总体不错，到货超级快，运行速度可以，不打游戏完全够用，拍照效果也比之前有提升，性价比很高的一款，(?&bull;??&bull;?)??价格超优惠，性能也非常棒，完美的一次购物。没有廉价的感觉，很高端，特别棒！', '镜瓷白', '2022-11-10 22:42:24', 4);
INSERT INTO `data` VALUES (12287, '一***才', 5, '外形外观：小米手机外形很好看。手感非常棒。\n屏幕音效：屏幕120高刷，千元机，配置很良心的。\n拍照效果：拍照效果很棒。\n运行速度：6+128，运行速度快。切换app很流畅。', '时光蓝', '2022-12-16 20:25:45', 2);
INSERT INTO `data` VALUES (12288, '流***汉', 5, '价格实惠，质量杠杠的，非常好的一次购物。一次购买了四台，挺好的。\n外形外观：不错，父母很喜欢。\n屏幕音效：屏幕大，音效好。\n拍照效果：双摄像头不错。\n运行速度：快，父母用绰绰有余了。', '时光蓝', '2023-01-29 09:40:03', 3);
INSERT INTO `data` VALUES (12289, '小***o', 5, '手机收到了，质量很好，外观大气，性价比很高，京东买放心，爸妈很喜欢，流畅度很好。红米手机的质量这几年确实大幅提升了，太赞了。', '时光蓝', '2023-01-18 19:16:48', 4);
INSERT INTO `data` VALUES (12290, 'j***X', 5, '已经用了一段时间了，性能外观啥的都很满意，运行速度也很快！拍照功能一般，不算很好，全屏下面黑边框比较多，不是很满意，其他都挺好，尤其是这个优惠后感觉很划算', '子夜黑', '2023-02-12 10:26:29', 3);
INSERT INTO `data` VALUES (12291, '井***木', 5, '外形外观：质感很好，6.67，尺寸很大，观感很好。\n\n屏幕音效：高刷屏幕120HZ，非常清晰，OLED屏，视觉效果比以前好太多了。\n\n运行速度：新手机，运行速度非常棒，以后用完了追评。', '子夜黑', '2023-01-20 19:56:19', 3);
INSERT INTO `data` VALUES (12292, '巅***6', 5, '外形外观：非常好看\n屏幕音效：特别有感觉\n拍照效果：还不错\n运行速度：十分流畅\n待机时间：适合用两天没有问题，不打游戏的话\n其他特色：支持小米的产品，性价比高', '子夜黑', '2023-02-01 22:31:53', 2);
INSERT INTO `data` VALUES (12293, 'j***f', 5, '手机很好用，特别喜欢，外观好看，轻便，很适合卖给家人做为礼物。\n外形外观：外观颜值很高\n屏幕音效：音效特别好 会回购', '镜瓷白', '2023-01-08 23:30:38', 2);
INSERT INTO `data` VALUES (12294, 'j***a', 5, '手机质量很好，给老人买的，性价比很高\n外形外观：模型挺好的，就是下面的黑边有点难受\n运行速度：只能说物有所值吧，给老人买的，可以凑合用\n待机时间：5000毫安的大电池，用起来也是非常舒服的，非常耐用', '镜瓷白', '2023-02-12 14:42:53', 2);
INSERT INTO `data` VALUES (12295, 'c***7', 5, '外形外观：美观大方，很薄很赞，线条不错\n屏幕音效：音质很好，画质清晰\n拍照效果：拍照清晰，拍照不错\n运行速度：速度挺快，运行挺好，不卡顿\n待机时间：待机时间长，充电速度快，一个一个小时充满', '子夜黑', '2023-01-05 22:40:36', 2);
INSERT INTO `data` VALUES (12296, '二***人', 5, '外形外观：外观非常好看，颜值超高！\n屏幕音效：屏幕分辨率显示屏非常好！\n拍照效果：拍照效果非常好，各种模式都有，很好看拍的。\n运行速度：运行速度快！', '子夜黑', '2023-02-09 09:58:56', 3);
INSERT INTO `data` VALUES (12297, '蓝***色', 5, '性价比很高的一款手机，工作时候用，速度很快，手感较好，比原来手机薄一些，各项功能满足日常要求。京东快递速度很快，下单第二天就到了，送到家门口，为京东快递点赞！', '时光蓝', '2023-01-27 12:44:56', 5);
INSERT INTO `data` VALUES (12298, '杜***b', 5, '外形外观：简约大气设计很实用\n屏幕音效：千元机里的佼佼者了\n拍照效果：父母用足够了\n运行速度：运行流畅\n待机时间：电池续航可以说是一大亮点了、5000毫安时大电池', '子夜黑', '2022-12-21 01:00:27', 3);
INSERT INTO `data` VALUES (12299, '乃***e', 5, '外形外观：挺漂亮精致\n屏幕音效：屏幕挺好，看着挺细腻\n运行速度：还好\n待机时间：非常好', '时光蓝', '2022-12-30 12:16:52', 3);
INSERT INTO `data` VALUES (12300, '小***3', 5, '屏幕音效：好用，触控也很灵敏\n拍照效果：清楚 ，拍照不失真\n待机时间：可以用一天呢，待机时间长\n运行速度：6+128的够用了，性价比还是好的', '子夜黑', '2023-01-20 10:28:22', 2);
INSERT INTO `data` VALUES (12301, 'j***P', 5, '很喜欢，价格优惠，性价比超高，发货速度那不用说，杠杠的，满意，充电速度很快很快，流畅，喜欢喜欢，一次满意的购物体验', '子夜黑', '2022-11-26 21:52:53', 4);
INSERT INTO `data` VALUES (12302, 'c***q', 5, '总体不错，到货超级快，运行速度可以，不打游戏完全够用，拍照效果也比之前有提升，性价比很高的一款，(?&bull;??&bull;?)??价格超优惠，性能也非常棒，完美的一次购物很满意?，做工很好，物流快，客服很棒，点赞物流速度真的是没话说，就是一个字：快。商品从外包装来看非常高档，小米的品质在提升呀。', '时光蓝', '2022-11-10 22:40:56', 4);
INSERT INTO `data` VALUES (12303, 'u***5', 5, '外形外观：很赞，很喜欢，拿在手上很有手感。\n屏幕音效：声音很棒。\n拍照效果：拍照像素也很高。\n运行速度：安装了好多软件也不卡。强烈推荐。', '时光蓝', '2023-03-08 21:29:16', 3);
INSERT INTO `data` VALUES (12304, 'j***见', 4, '现在全家都是红米，物美价廉，我的已经用了两年了，很不错，不比原来三千的差，现在老公换手机，果断推荐了红米note12，新款，内存大，完美。', '子夜黑', '2023-01-17 10:35:38', 1);
INSERT INTO `data` VALUES (12305, 'H***8', 5, '提前一周预约，10月31日晚上付款，第二天就到货啦！颜值高，手感很好，显示效果也很Nice，不亏千元级Oled屏。使用三天功能正常，不玩大型游戏，6G完全够用！', '镜瓷白', '2022-11-04 15:57:25', 3);
INSERT INTO `data` VALUES (12306, 'N***诺', 5, '外形外观：新潮时尚，简约大气\n屏幕音效：立体音效，大屏幕\n拍照效果：还行吧，性价比很高\n运行速度：很流畅，8G运存很给力\n待机时间：基本一天一充\n其他特色：性价比超高', '子夜黑', '2023-01-02 10:15:39', 2);
INSERT INTO `data` VALUES (12307, 'o***o', 5, '很好推荐购买实物如图细节棒棒哒！\n外形外观：很喜欢如图\n屏幕音效：很好适合老年人用推荐购买\n拍照效果：可以在千元机中不错的说\n运行速度：挺流畅作为老年机够用了\n待机时间：挺好的电池续航可以棒棒哒！', '子夜黑', '2023-03-14 10:24:00', 4);
INSERT INTO `data` VALUES (12308, 'j***g', 5, '外形外观：握持手感很不错 流畅\n屏幕音效：声音太 也没有破音\n拍照效果：这个价格真的不要太高要求\n运行速度：几代人买大内存的咯。方便以后运行不掉速度', '镜瓷白', '2023-02-12 17:28:32', 2);
INSERT INTO `data` VALUES (12309, 'j***9', 5, '外形外观：黑色大气，手感不错\n屏幕音效：比苹果12要大一点，色彩绚丽\n待机时间：出厂充了65%，待机24小时，仅耗电10%\n其他特色：上午下单下午送达，宇宙速度，超赞', '子夜黑', '2023-02-08 14:42:56', 2);
INSERT INTO `data` VALUES (12310, 'j***W', 3, '一般般 雷军的产品 始终口号大于产品力', '镜瓷白', '2022-12-28 19:04:00', 3);
INSERT INTO `data` VALUES (12311, '潘***4', 5, '手机很好，值得购买，外观好看，手感不错，老妈用着很喜欢，一次很好的购物，京东服务周到，物流也很快，配送也很周到，非常喜欢！！！！！！', '时光蓝', '2022-11-15 18:02:29', 2);
INSERT INTO `data` VALUES (12312, 'j***6', 5, '待机时间真的很长，日常使用﹣﹣天一次都用不完，这款新出的苹果手机质量很好，系统流畅，信号稳定，手感很好， 幕分辨率比较高拍照清楚显示艳丽，外观新颖，质量可靠，很快就收到了。手机太完美了，而且屏幕很清晰，色彩洋艳，运行速度也很快', '时光蓝', '2022-12-28 23:22:00', 2);
INSERT INTO `data` VALUES (12313, '我***山', 5, '外形外观：买给老婆做备用机，老婆选的外观，十分满意\n屏幕音效：这个价位够用了，性价比很高\n运行速度：性价比足够了\n待机时间：这个要特别讲讲，作为备用机主要就是要长期回****，续航基本能撑一天，非常不错。', '镜瓷白', '2023-03-18 11:00:23', 2);
INSERT INTO `data` VALUES (12314, 'b***2', 5, '买给妈妈用的。之前用的是红米note8，用习惯这个系列了，所以这次还是买的note系列。\n外形外观：外观蛮好看的，比较薄。\n拍照效果：拍照像素挺高的，很清晰。\n运行速度：新手机速度杠杠的。', '镜瓷白', '2023-02-02 16:09:24', 3);
INSERT INTO `data` VALUES (12315, 'W***过', 5, '第n次买了，一如既往的好！\n外形外观：给老妈用的，买的白色，很干净！\n屏幕音效：屏幕清晰！声音很大，音质很好！\n拍照效果：拍照清晰，真的很好！\n运行速度：运行速度非常快！', '镜瓷白', '2023-01-05 20:59:02', 3);
INSERT INTO `data` VALUES (12316, 'j***e', 5, '非常喜欢，款式好看，系统流畅，照相清晰，电池也耐用。性价比非常高。值得购买。', '镜瓷白', '2022-12-17 18:06:49', 1);
INSERT INTO `data` VALUES (12317, 'j***e', 5, '这款手机外观很好，功能也很多，能满足常用须求，三星屏幕，效果很好，性价比很高，推荐使用。', '时光蓝', '2023-02-19 09:46:20', 2);
INSERT INTO `data` VALUES (12318, '落***昏', 5, '很好，物流很快，东西很给力，性价比很高！是理想中的产品，质量不错，物流也很快，值得点赞宝贝真不错，做的真细心，值得拥有，快递很快收到啦，很不错，非常喜欢，值得购买，(*^__^*) 嘻嘻&hellip;&hellip;大无语事件家人们！咱就是说，太好用了，狠狠的爱住了！上次买到这么好用的东西还是上次！特别特别特别好，没有任何破损的地方，外观也好看，好评！已经用过一段时间了，效果不错?，客服服务有耐心，解答详细，赞一个是正品，而且价格不贵，用着也很大气，一直在用，很好??价格很实惠，性价比很高，算是平价好物，会回购的', '子夜黑', '2023-01-20 17:02:26', 4);
INSERT INTO `data` VALUES (12319, '佐***城', 5, '手机很好，给老妈买的，适合父母用。\n外形外观：大气\n屏幕音效：不错\n拍照效果：挺好\n运行速度：很快\n待机时间：很久', '子夜黑', '2023-01-17 13:12:02', 2);
INSERT INTO `data` VALUES (12320, '幕***尘', 5, '手机外观豪华、大气！特别是对充电速度那是相当满意一会就充电满了，值得推荐的一款品牌手机，手机送了一个手机壳带上后如裸机的感觉，后面的摄像很大。天玑8100，运行速度很快。屏幕清晰，音效很好！总体来说，这款红米note12的手机还是很不错，性价 比很高。期待红米越做越好', '时光蓝', '2023-01-13 09:55:54', 3);
INSERT INTO `data` VALUES (12321, 'j***n', 5, '红米一直主打性价比，感觉很适合，赶着活动入手一台，\n外形外观：很薄，看图片可以比较出来，也不大，拿在手里正合适\n运行速度：很快，8加128够用了', '子夜黑', '2022-11-17 19:07:21', 3);
INSERT INTO `data` VALUES (12322, '遗***1', 5, '外观好看，显示清晰，运行速度很快，自带保护壳和膜，双喇叭音效很好，拍摄效果满足日常需要。', '子夜黑', '2023-01-11 23:01:28', 4);
INSERT INTO `data` VALUES (12323, 'j***b', 5, '宝贝收到了，和描述一样，很喜欢宝贝收到了，很惊喜，质量非常好，很满意的一次购物。我会继续回购的，店家值得信赖趁着活动入手划算，发货快，包装得好，非常不错，全新体验，赞赞赞！', '时光蓝', '2023-01-21 18:47:17', 1);
INSERT INTO `data` VALUES (12324, '我***上', 5, '外形外观：非常时尚漂亮，非常赞，送给妈妈的礼物\n屏幕音效：屏幕很大，实用很友好，超级赞\n拍照效果：很棒\n运行速度：很流畅，6g的内存足够长辈使用\n待机时间：很好！\n其他特色：家人很喜欢，超级赞，日常使用聊天刷抖音没有任何问题！', '镜瓷白', '2023-01-08 15:48:54', 2);
INSERT INTO `data` VALUES (12325, 'j***0', 5, '外形外观：很新颖，很轻拿着很舒服，款式非常棒\n屏幕音效：声音很不错\n拍照效果：拍照很好\n运行速度：很快的，\n待机时间：很长，很耐用，导航一天都不用充电，用过待机最长的手机，我买了3台了，推荐', '子夜黑', '2023-03-18 08:46:20', 1);
INSERT INTO `data` VALUES (12326, 'u***k', 5, '手机屏幕大小刚好，很适合老人用！屏显效果也不错。之前用小米手机，可以直接移机，老人也不需要再适应！系统运行速度快，日常使用完全够用！京东物流非常快，隔天就到货了！', '子夜黑', '2022-11-04 17:27:51', 3);
INSERT INTO `data` VALUES (12327, 'j***4', 5, '许多图片都存在小米网盘里，后摄比前摄好，看起来真不错，配置和性能也还说得过去！以后换机还选小米品牌！还是一如既往地流畅，就只用安装，显示效果也挺不错的，再也不要随身带充电宝了，也完全够用，款式也很好看', '子夜黑', '2023-01-16 09:48:25', 2);
INSERT INTO `data` VALUES (12328, '噻***柒', 5, '给奶奶买的，手机很好用！手机包装很好无破损，物流也快，手机外观漂亮，款式好看，质量很好，正品，做工精致，屏幕细腻够大很清晰，色彩饱和度很不错，照相不错，很漂亮，音质也很棒，系统功能强大，运行速度很快，看\n电影听音乐都很给力，非常享受，操作简单，内存也足够，性价比蛮高的，而且价格还实惠便宜，很划算，支持，超喜欢。\n手机屏幕够大，感觉不错，老公刚拿到就试了试，很流畅。家里老爸老妈都是这个，又给老公买了一部，真心感觉这个\n牌子的手机用着不错，送的手机壳也很好用，价格也实惠，玩游戏也很流畅。强烈推荐', '时光蓝', '2022-11-13 17:56:53', 3);
INSERT INTO `data` VALUES (12329, '灯***子', 5, '手机很棒，性价比超高，忠实的米粉，小米加油！还记得那句口号吗？为发烧而生。?\n外形外观：屏幕很整洁，没有大刘海\n拍照效果：拍照效果确实满足需求，很清晰，色彩丰富\n运行速度：非常流畅，丝毫不卡顿', '子夜黑', '2022-11-03 20:38:30', 4);
INSERT INTO `data` VALUES (12330, '七***鬼', 5, '儿子外公外婆的手机都不太好用了，于是没和他们老人家说就直接下单了，都是小米，黑色的先到，蓝色的过了五天后到，都很快速，现在两个老人家都用上了，通话清晰使用也非常满意，不求能用多久，只能能用上两年就值了。', '子夜黑', '2022-12-01 21:29:04', 3);
INSERT INTO `data` VALUES (12331, '彪***吧', 5, '外形外观：外观大气上档次\n屏幕音效：音效清晰明亮\n拍照效果：拍照清晰，确实不错\n运行速度：运行速度也不错\n待机时间：待机时间一天杠杠的', '时光蓝', '2023-01-10 22:03:24', 2);
INSERT INTO `data` VALUES (12332, 'j***P', 5, '给妈妈买的，性价比超高，磨砂的很有质感，用起来挺顺手的，简单大方，续航能力强，满意', '子夜黑', '2022-11-26 21:44:36', 4);
INSERT INTO `data` VALUES (12333, '马***1', 5, '外形外观：外观造型时尚，大方，握持很顺手\n屏幕音效：屏幕质感清晰，亮度适中\n拍照效果：拍照效果细腻，照片清晰\n运行速度：运行速度很快，用起来不卡顿', '时光蓝', '2023-01-26 07:45:54', 2);
INSERT INTO `data` VALUES (12334, '为***长', 5, '屏幕音效：高颜值，高品质，非常好，一分钱一分货，材质外观和质量一看就很上档次，非常喜欢\n外形外观：外观可人\n拍照效果：拍照效果优秀', '镜瓷白', '2023-01-04 12:03:17', 3);
INSERT INTO `data` VALUES (12335, 'w***z', 5, '外形外观：外形外观很高端大气上档次，做工不错，\n屏幕音效：屏幕显示效果很艳丽，屏幕很大，音质也不错，\n拍照效果：拍照一般\n运行速度：运行速度很快，配的上这个价格，值得入手。', '子夜黑', '2023-01-16 20:55:21', 2);
INSERT INTO `data` VALUES (12336, '一***-', 5, '商品评价:白色颜值很高 o( ??? )o，机身很轻薄，触摸屏灵敏，日常使用游刃有余，跟闺蜜拍照?也是轻松拿捏，像素挺高的，同等价位系列的天花板！支持国货??！小米yyds！太赞了，而且电池很强?，再也不要随身带充电宝了(≧&forall;≦)ゞ', '时光蓝', '2023-01-07 20:37:08', 3);
INSERT INTO `data` VALUES (12337, '叫***力', 5, '首先包装严实看得出正品，隔天到，速度非常快，大赞！蓝色确实不错，挺清新，挺薄的，摄像头放中间也习惯了；手机确实全新，激活信息里面，当天看不来激活日期，隔天能看来，很久没用小米手机了，这个功能确实不错，能看来是否二手机，系统是安卓12，8＋128够用了，屏幕60和120hz频率可以自己调节很棒，相当的流畅，出厂自带贴膜和送的透明保护套，很不错，摄像方面确实一般，够用嗯，很多丰富功能慢慢发现，同价位确实值得推荐', '时光蓝', '2023-03-11 02:14:23', 2);
INSERT INTO `data` VALUES (12338, 'N***诺', 5, '外形外观：白色的很好看，比之前用的红米7稍微大一点\n屏幕音效：还不错，屏幕看上去也很舒适\n拍照效果：清晰、魅力\n待机时间：超长待机\n运行速度：流畅度还不错', '镜瓷白', '2022-12-03 21:24:34', 2);
INSERT INTO `data` VALUES (12339, 'i***e', 5, '京东物流速度很快，物品完整无缺，一直都信赖此品牌，整体做工很好，屏幕大，机身薄，电池容量高，运行速度很快，性价比高，本人很满意，全给满分，值得推荐购买', '时光蓝', '2023-01-13 12:03:43', 3);
INSERT INTO `data` VALUES (12340, '巴***5', 5, '质量很好，包装很用心，平时不玩游戏用的很流\n畅，特别是尺寸，小刚合适，物流挺快的，客服\n回复也挺及时，手机给老人买的，用的挺顺手。\n显示，拍照都还挺好的，老人对这些方面要求不\n高，平时只是看个时间，看看天气预报什么的，\n电话都很少打。给好评！', '时光蓝', '2023-03-16 11:27:33', 2);
INSERT INTO `data` VALUES (12341, '不***啊', 5, '外形外观：大小合适，颜色很正\n屏幕音效：中规中矩，老妈用了\n拍照效果：还可以，够用就行\n运行速度：反应速度很快\n待机时间：正常使用，快充三十分钟满电', '镜瓷白', '2023-01-29 16:08:44', 2);
INSERT INTO `data` VALUES (12342, 'j***t', 5, '运行流畅！待机时间长！非常好用！外形大气！拍照效果好！满足常规使用，大游戏也没压力！', '时光蓝', '2023-01-30 20:06:28', 4);
INSERT INTO `data` VALUES (12343, '-***T', 5, '小米的手机很好用，物美价廉         用的也方便    像素高      颜值不错         好看耐用', '时光蓝', '2023-01-03 20:28:25', 4);
INSERT INTO `data` VALUES (12344, '一***o', 5, '这个手机性价比很高，主要是屏幕和处理器够给力，千元机能买到高通处理器和oled屏幕，可以了。我买的是8+128版本，用起来很丝滑流畅，电池也够用，给父母用配置绝对够用！', '时光蓝', '2023-01-27 17:53:10', 4);
INSERT INTO `data` VALUES (12345, 'l***g', 5, '习惯性好评 充电器不错 看起来大大的 试了一下 充电很快 手机手感不错 比较好 换机功能方便 旧手机上的都传过来了', '时光蓝', '2023-01-20 15:06:55', 4);
INSERT INTO `data` VALUES (12346, '五***6', 5, '白色的真是好看，有磨砂的质感，给加人的备用机很合适，128g 足够了，算了一下这已经是买的第14只小米手机了，希望系统能优化一下网络偶尔断流的事儿，其他用着都还不错，新旧文件迁移很方便，总体感觉不错', '镜瓷白', '2023-01-22 21:09:32', 4);
INSERT INTO `data` VALUES (12347, '爱***a', 5, '手机包装很好无破损，物流也快，手机外观漂亮，款式好看，质量很好，正品，做工精致，屏幕细腻够大很清晰，色彩饱和度很不错，照相不错，很漂亮，音质也很棒，系统功能强大，运行速度很快，看电影听音乐都很给力， 非常享受，操作简单，内存也足够，性价比蛮高的，而且价格还实惠便宜，很划算，支持，超喜欢。', '时光蓝', '2022-11-30 07:30:30', 2);
INSERT INTO `data` VALUES (12348, '远***2', 5, '颜值相当不错，骁龙处理器，手感很好，对于一千多块钱来说，还是算对得上了', '时光蓝', '2022-11-22 19:31:43', 5);
INSERT INTO `data` VALUES (12349, 'j***幽', 5, '红米的note12手机无论材质还是做工都超出了预期，超值，红米手机还是性价比最高的手机，品质优良，用起来非常顺滑不卡顿，大内存的手机用起来就是好，再也不用担心内存不够了，手机采用了直板设计，用起来非常顺手，屏幕显示很好。京东物流超快，第二天就收到了，非常满意，值得购买。', '子夜黑', '2023-02-28 21:05:53', 4);
INSERT INTO `data` VALUES (12350, 'u***6', 5, '手机非常漂亮，速度很快，刚刚拿到手机，建议大家，试一下这一款', '子夜黑', '2023-03-20 10:33:02', 2);
INSERT INTO `data` VALUES (12351, 'l***q', 5, '外形外观：红米12外观设计赞美，非常漂亮好看，手感很好\n屏幕音效：这个手机主要是屏幕比较好，像素很好，声音很大声，声音也很清晰\n拍照效果：拍照很高清，夜景也很好看，美颜效果也很好。\n运行速度：手机反应很快，切换app也很快，刷视频也很快。\n待机时间：充一次电能用一个星期，电池容量也大，电池非常耐用，充电也很快，插上充电60秒一分钟就充满。\n其他特色：红米手机就是好，永远支持红米，性价比也很高，京东上也经常也有活动，京东快递发货也快', '时光蓝', '2023-02-21 16:17:06', 3);
INSERT INTO `data` VALUES (12352, 'P***b', 5, '外形外观：外形是一如既往的note手感\n屏幕音效：屏幕很流畅 观感也说的过去\n运行速度：目前没有出现卡顿现象\n待机时间：电池很大 续航非常给力 好评！', '镜瓷白', '2023-01-07 18:26:00', 2);
INSERT INTO `data` VALUES (12353, '哈***_', 5, '运行速度：运行速度飞快\n待机时间：待机时间很足\n外形外观：外观设计风格非常好看，很时尚\n屏幕音效：屏幕质量物有所值\n拍照效果：拍照效果好看', '时光蓝', '2023-01-14 20:26:19', 2);
INSERT INTO `data` VALUES (12354, '婷***呢', 5, '外形外观：外观简洁大方，白色颜值很高，适合女生使用。\n屏幕音效：听音乐很棒，打电话声音也很好。\n拍照效果：拍照效果很满意。\n运行速度：快，打开网页app什么的都很顺滑。', '镜瓷白', '2022-12-07 16:39:33', 2);
INSERT INTO `data` VALUES (12355, '必***者', 5, '屏幕音效：屏幕提升明显，通透不少\n运行速度：运行很快\n待机时间：待机时间长，充电快\n外形外观：好看多了', '子夜黑', '2022-11-03 20:04:34', 2);
INSERT INTO `data` VALUES (12356, 'j***d', 5, '外观大气漂亮，设计感很强，运行速度也快，屏幕够大，拍照清晰，色感十足，关键还有大容量电池，待机时间长，性价比很高的一款手机。', '子夜黑', '2023-02-05 17:32:30', 3);
INSERT INTO `data` VALUES (12357, 'o***o', 5, '小米的包装一直都是简单环保实用。手机屏幕够大，显示清晰，60hz无频闪。外壳颜色多样可选，总有一款适合你。8G内存运行流畅无卡涩。京东物流超快安全有保障。服务态度一流。', '时光蓝', '2023-01-25 23:21:05', 3);
INSERT INTO `data` VALUES (12358, 'j***o', 5, '看了很多评测，最后还是选了这款，主要给家里人用，拿到手的第一感觉是轻，另外屏幕大对老人非常友好，屏幕也非常清晰，和我自己lcd屏幕相比更加通透，反应速度也挺流畅，家人用着挺好', '时光蓝', '2022-12-31 16:08:26', 2);
INSERT INTO `data` VALUES (12359, 'j***3', 5, '外形外观：简约大气 上档次 手感舒适\n屏幕音效：很清晰 没有任何杂音\n拍照效果：很清晰 画质不模糊\n运行速度：玩游戏什么的也不卡顿赞', '镜瓷白', '2023-01-05 15:28:12', 2);
INSERT INTO `data` VALUES (12360, 'u***1', 5, '外形外观：白色的外观，是真的耐看，很棒\n\n屏幕音效：120hz的刷新率，感觉很流畅\n运行速度：新手机，运行速度可以', '镜瓷白', '2023-01-16 13:08:36', 2);
INSERT INTO `data` VALUES (12361, '土***堂', 5, '非常好长辈很喜欢，整体手感非常轻，建议大家选择黑色我觉得显档次，系统自带的小米换机app也很给力，新旧手机数据完美转移，电池表现也不错刷刷视频看看微信非常耐用，另外开机键比音量键低是正常的，因为有指纹解锁问过客服了！整体非常满意！', '子夜黑', '2022-11-13 19:42:41', 2);
INSERT INTO `data` VALUES (12362, 'j***V', 5, '成色非常新，手机也很流畅，还送了快充手机壳钢化膜物超所值', '太空灰', '2022-11-09 15:47:57', 1);
INSERT INTO `data` VALUES (12363, 'A***e', 5, '不错，值得信赖的二手商家，在他家买手机放心，已经是第二次购买了，强烈推荐给大家。', '月幕白', '2022-01-02 16:31:51', 7);
INSERT INTO `data` VALUES (12364, 'w***y', 5, '手机就是全新，没有一点瑕疵，系统运行流畅，特别是变焦镜头，效果非常好，还送了快充。下次还会光顾的。', '星环紫', '2021-04-04 21:26:41', 4);
INSERT INTO `data` VALUES (12365, '_***_', 5, '外观设计漂亮，尺寸大小合适，包装仔细完整，宝贝手感不错，感觉很好，发货速度快，服务态度一流，给力！5星好评！货真价实！老板很豪爽！', '太空灰+小米65W原装快充', '2021-01-14 20:23:31', 5);
INSERT INTO `data` VALUES (12366, 'j***O', 5, '手机收到玩了两天这个处理器真的超级喜欢，玩起来超级流畅，拍照也特别清楚，手机电池挺耐用的，玩了那么久还没出现过卡顿，5G网速也超级快，个人挺喜欢这款手机的，对比了其他家的小米手机这家店铺总体来说经济实惠好用不贵！', '太空灰', '2021-03-28 08:34:08', 3);
INSERT INTO `data` VALUES (12367, 'j***7', 5, '外观没什么划痕，手机功能齐全，电池续航久没得说非常不错，而且客服小哥很给力。手机手感舒适。', '月幕白', '2021-06-08 17:21:17', 5);
INSERT INTO `data` VALUES (12368, '丶***A', 5, '没有特别明显的划痕，很值了', '天际蓝', '2021-05-24 11:41:45', 6);
INSERT INTO `data` VALUES (12369, 'j***m', 5, '用了几天才来评价的，865用着就是快，和平精英完美运行，安兔兔跑分59万+，客服态度也很好，手机基本就是新的，很满意的一次购物。', '太空灰+小米65W原装快充', '2021-01-30 12:44:30', 5);
INSERT INTO `data` VALUES (12370, '你***达', 5, '手机运行非常快，也很漂亮，上档次，尤其摄像头看着非常质感，加上优美的声音旋律，简直完美。在视频时，像素稳定性也非常好', '星环紫+小米65W原装快充', '2020-12-29 08:59:10', 8);
INSERT INTO `data` VALUES (12371, 'j***c', 5, '之前在评测视频里看到了这款手机，非常符合我的要求。真全面屏，升降式摄像头，骁龙865的处理器，4700的电池非常够用，真的不错的好手机。这家的品质也不错，给我发的95新实际几乎没有划痕，非常新，小米账户正常登陆，是正规的手机，真的很真不错。但是这家三天都没给我发货真的想有蚂蚁在我身上爬，从付款到到货有进七天的时间，真的很难受。', '太空灰', '2022-06-26 12:38:36', 3);
INSERT INTO `data` VALUES (12372, 'l***0', 5, '跟新的一样，很流畅，值得信赖', '太空灰', '2022-10-03 10:13:17', 1);
