INSERT INTO `data` VALUES (12376, '梦***1', 3, '买的是天际蓝送到的是水色天光，充电器很一般，一般到不敢用。屏幕上有水印，也就**成新，和宣传的九五成新有段距离。后续再追评。', '天际蓝', '2022-09-29 11:12:25', 8);
