INSERT INTO `data` VALUES (12394, '恨***妹', 5, '手机到了超级好用的打游戏不卡不发热手机运行快手感也特别好，还有就是店家服务特别好。下次我需要在买手机的话还会选择这个店家。', '太空灰+小米65W原装快充', '2020-12-30 16:19:46', 1);
INSERT INTO `data` VALUES (12395, 'j***j', 5, '外观很新，用起来也很流畅，非常不错。现在的手机都是打孔屏，非常不喜欢，只能买以前的手机了，好在各方面都没落后，很好', '太空灰', '2022-12-18 02:56:04', 6);
INSERT INTO `data` VALUES (12396, '红***红', 5, '听说评价超过一百个字有送积分，基本上每个星期都会光顾，统一评论，京东实在是太方便了，根本停不下来，从此后买生活用品第一个想到的就是京东，都是正品，一开始还担心，现在都习惯了，真心不错的，现在还要多多给优惠呦，下次还会再来的，都逛上了，哈啊哈哈哈哈。还是很不错的宝贝真心不错，物超所值，很满意的一次网购。', '月幕白', '2023-03-20 11:47:45', 9);
