INSERT INTO `data` VALUES (12421, '翱***S', 3, '手机质量成色都很好就是店家不诚信没有白色货还卖。买的白色但是收到个蓝色，挺麻烦的不退了。小米手机系统bug比较多常遇到奇怪的问题', '月幕白', '2021-08-04 22:52:22', 1);
INSERT INTO `data` VALUES (12422, 'j***t', 5, '给老爸买的，收到货快一周了，才给他弄好，教会使用。这次满意购物，收到货后简直惊喜，跟新的一毛一样。比我自用了一年多的还新，哈哈，我的摔过。珠光白的后盖非常好看，老爸很喜欢。比我在小米商城抢的紫色后盖更好看。非常棒哈！以后还来光顾', '月幕白', '2021-08-26 17:29:46', 7);
