INSERT INTO `data` VALUES (12425, 'j***A', 5, '特地用了几天才来评价。商品完全看不出是旧的。用起来流畅无比。我也不玩游戏，但听小说中多开几个别的网页。基本不卡顿。比我以前用了五年的手机，真是一个天上一个地下。至于照相嘛，没有特别感觉好。也许是我用的少，不会用。总之，这次购物感觉很好，以后会介绍别人再来。', '星环紫', '2021-06-22 06:03:51', 3);
