INSERT INTO `data` VALUES (12478, 'j***j', 5, '手机收到了第一时间赶来评论，给要入手这款手机的小伙伴一个参考，之前也对比过其它商家的产品，最后选择了凯旋通，收到手机后发现我的选择是对的，手机很满意，绝对99新，不仔细看的话，几乎没有划痕，功能正常，唯一美中不足的地方是手机摄像头附近，听筒附近有一些灰尘，不过问题不大，自己动手清理一下就OK了，照片是清理过后拍的，总体还算满意，值得入手', '太空灰', '2021-07-19 16:05:28', 8);
