INSERT INTO `data` VALUES (12486, 'K***P', 5, '本体成色挺新的，磨损基本在中框，充电口严重些，现在在用拍不了机身。送了18W充电器，Type - C数据线，钢化膜，气囊保护壳。机身体验挺好的，刚拿到手是MIUI12.5.5，后面自己更到12.5.7。', '月幕白', '2021-12-14 23:06:59', 1);
