INSERT INTO `data` VALUES (12488, '杰***-', 5, '还是不错的，服务也很到位，客服比较有耐心，有问必答，发货也认真对待，有问题及时沟通。快递也挺快的。买来给爸爸用着挺好，还算满意，就是电池有点不抗用，影响不大', '太空灰', '2021-03-11 02:11:36', 2);
INSERT INTO `data` VALUES (12489, '神***丰', 5, '卖家发货快。3天到货。包装完整。手机外观很新。性能跑分达到59.9万。看网页，看视频，打游戏。打电话。拍照，录视频。全部都能使用。值得买。点赞！', '月幕白+小米65W原装快充', '2021-02-01 10:44:15', 2);
INSERT INTO `data` VALUES (12490, 'j***l', 5, '在收货之前收到工作人员电话告诉我我订的白色款质检没有通过，询问我要不要换成紫色款。我说紫色会不会太炫了?，他说不满意可以随时退换，哈哈。很感谢工作人员负责任的态度！现在到手了，各个方面都比较满意，确实是95新，有轻微使用痕迹，但总体外观无刮痕、使用流畅，紫色也是好看的~先用一段时间再来评论~??', '月幕白', '2021-06-02 14:59:14', 2);
INSERT INTO `data` VALUES (12491, '时***享', 5, '和想象的一模一样，惊艳呀', '星环紫', '2021-05-20 21:23:12', 0);
