INSERT INTO `data` VALUES (12786, 'P***s', 5, '外形外观：简洁大方，远山蓝很好看\n屏幕音效：屏幕显示效果极佳，音效不错\n拍照效果：杠杠的，长焦也很清晰\n运行速度：很流畅\n待机时间：不得而知\n其他特色：旗舰机处理器内存闪存', '远山蓝', '2022-12-15 14:03:35', 7);
INSERT INTO `data` VALUES (12787, 'l***6', 5, '京东的配送速度很快，点赞非常快非常好。经常在京东购买商品，配送速度保证时效，商品保质保量。\n外形外观：外形小巧灵动很好。\n屏幕音效：屏幕效果很好，音效也很好。6.36英寸E6直屏\n拍照效果：徕卡专业影像配备了徕卡光学镜头，后置5400万像素主镜头，1200万像素超广角镜头，1000万像素长焦镜头，前置3200万像素摄像头。\n运行速度：使用了最新的高通骁龙8第二代八核处理器，应用程序打开速度快。\n待机时间：待机时间长，搭载了4500毫安的大容量电池。充电速度快，支持无线充电。\n其他特色：支持IP68等级的防水防护。小米13是2023最期待最惊喜的旗舰手机，首先看了网络数码博主的测评，其次在线下体验了小米13手机，觉得手机的手感很好，是一款不错的直屏手机旗舰。手机整体的性能也很不错，跑分水平很高，电池容量大，续航时间长。小米13搭载了全新的MIUI14系统，不仅精简了系统的存储空间，而且可以对预装的系统程序有更好的可调节性。小米13是国货手机之光。', '黑色', '2023-01-03 14:54:21', 7);
INSERT INTO `data` VALUES (12788, '凡***购', 5, '外形外观：非常漂亮，买它是外观吸引了我\n屏幕音效：显示清晰，肉眼并看不到颗粒感，\n拍照效果：莱卡加持的相机果然不错，拍的照片很真实，特别是夜景，你肉眼看到什么样，拍出来就是什么样，非常奈斯！\n运行速度：运行速度非常流畅，一点都不卡顿。\n待机时间：待机时间中度使用一天，完全没有任何压力\n其他特色：手感好，重量轻，做工精，这是所有小米手机当中颜值最高的一款。', '黑色', '2022-12-15 21:01:40', 7);
INSERT INTO `data` VALUES (12789, '刘***c', 5, '目前到手感觉还行，可以冲一手兄弟们。性价比高，手感也很好！这款手机采用了骁龙8+性能铁三角组合，搭配12+256 GB的超大内存和MIUI13系统 使用是非常流畅的。另外该机还采用了120W+5000毫安的 续航套装，不仅续航表现出色，而且充电速度是非常快的。除此之外，该机还采用了一亿像素光学防抖后 置主摄和1.5K旗舰直屏等配置，外观方面，手机尺寸为6.67英寸，机身重202g.厚度为8.48mm。采用1.5K定制直屏（2712&times;1220），支持120Hz刷新率446PPi，观感接近2K屏幕，功耗却与1080P屏幕相近，且采用硬件 级低蓝光。超窄边框，2.4mm超小下巴。配置方面，搭 载高通骁龙8+处理器，CPU与GPU性能相比上 代都有 很大的提升。散 热方面，采用电竞级VC散热，覆盖面 积3725mm，12层堆叠。散热能力大幅度提升。续航方面，5000mAh大电量电池搭配120W闪充。拍摄方面，后置摄像头采用1亿像素主摄，支持OIS光学防 抖；8MP超广角摄像头;2MP微距摄像头。前置摄像头则采用20MP摄像头。屏下指纹重新回归，支持心率 监测、暗光解 锁   后续会追评！', '白色', '2023-01-02 17:37:33', 6);
INSERT INTO `data` VALUES (12790, '会***子', 5, '外形外观：白色太漂亮了，握感觉舒服。\n屏幕音效：终于有小屏旗舰了，米10太重了，13刚刚好。\n拍照效果：拍照杠杠滴。\n运行速度：运行速度很快\n其他特色：家里的1000m光纤终于可以跑满了。\n其他的慢慢体验。', '白色', '2022-12-16 13:03:02', 6);
INSERT INTO `data` VALUES (12791, '晩***榆', 5, '外形外观：手感不错，不愧是小屏旗舰，外观设计优雅大气\n屏幕音效：屏幕显示清晰，屏幕边框完美，音效逼真，还原真实\n拍照效果：拍摄清晰，莱卡联名，夜景很好，前置也很棒，随手出大片\n运行速度：骁龙8gen2，运行速度快，游戏毫无压力，旗舰处理器完美运行\n待机时间：待机时间长，小屏旗舰的优势\n其他特色：很喜欢这款手机，希望小米越来越好', '旷野绿', '2022-12-17 17:16:34', 5);
INSERT INTO `data` VALUES (12792, 'j***Y', 5, '外形外观：东西已经收到！手感不错！用料扎实！质量很好！平常用基本没有问题！\n屏幕音效：清晰，很好\n运行速度：反应灵敏\n拍照效果：成片效果好速度快', '旷野绿', '2023-03-10 11:06:29', 9);
INSERT INTO `data` VALUES (12793, 'V***箭', 5, '首发入手，还是很超值的，比水果机流畅，试了传说中的原神最高画质，一小时都不发热，帧数很高，稳定流畅，爽歪歪！水果机就不一样，要发烫的哦！小米13，冲！五星好评！', '远山蓝', '2022-12-17 09:23:11', 7);
INSERT INTO `data` VALUES (12794, 'L***e', 5, '这一代小米 13感觉特别好，用习惯了苹果转过来的，手机电池耗电挺耐用，省电还是可以的，发热情况很好，玩游戏绝对不会卡，基本不发热，手机手感绝佳，机壳颜色也很不错，徕卡拍照一流，抵得过半个好相机。', '白色', '2023-01-18 01:49:59', 6);
INSERT INTO `data` VALUES (12795, 'l***8', 5, '外形外观：就两个字:漂亮，握持手感很棒。\n屏幕音效：显示清晰，声音爆满，音效很好。\n拍照效果：莱卡加持，拍照有保障。\n运行速度：骁龙满血8gen2快的一匹。\n待机时间：刚拿到，需要用几天才知道，貌似续航还是很不错的。\n其他特色：手感绝佳，拍照清晰，声音好听，通话质量很好。', '远山蓝', '2023-02-08 18:37:02', 7);
INSERT INTO `data` VALUES (12796, 'c***p', 5, '外形外观：非常好看，颜值高，小巧，便于携带\n屏幕音效：细腻美观，大小合适\n拍照效果：非常不错，比我的k30u好很多\n运行速度：12g非常快，很满意\n待机时间：还没用，试过后来评价\n其他特色：非常美观的直屏小手机，手感好，外观美', '黑色', '2022-12-17 20:46:57', 9);
INSERT INTO `data` VALUES (12797, 'u***a', 5, '外形外观：非常好看，质感很好\n屏幕音效：屏幕亮度好，显示细腻\n拍照效果：莱卡双摄，拍照清晰\n运行速度：非常流畅，****，省心省力\n待机时间：一天半左右，67w快充，不算太快，够用了', '黑色', '2023-01-20 09:52:13', 4);
INSERT INTO `data` VALUES (12798, 'j***d', 5, '不愧是是史上口碑最好的小米旗舰！用过索尼、三星、苹果、华为，综合感受最好的还是小米，对比iPhone14Pro也不遑多让！\n核心配置上，小米13采用6.36英寸四窄边直屏，搭载高通第二代骁龙8，后置5000万徕卡主摄、徕卡75mm长焦和徕卡超广角，电池为4500mAh，支持67W有线、50W无线闪充。\n我选择的是旷旷野绿外表，温和淡雅很喜欢！\n下单后显示排单到1月5号，结果12月27就送到了，比预定早了一个周！好评！', '旷野绿', '2023-01-05 19:03:03', 6);
INSERT INTO `data` VALUES (12799, '小***咪', 5, '外形外观：非常好看，摸起来非常舒服，还是不带壳舒服\n屏幕音效：很不错哦，加上环绕立体声感觉更棒，很赞\n拍照效果：很好，很喜欢，不过我自己用的不多\n运行速度：很快，非常喜欢\n待机时间：刚用，具体还不太知道，不过用了一两个小时，没掉多少电\n其他特色：用起来真的很舒服', '黑色', '2023-01-12 19:33:52', 4);
INSERT INTO `data` VALUES (12800, 'f***锋', 5, '外形外观：漂亮，手感极好\n屏幕音效：极好，护眼\n拍照效果：极好，焦距充足\n运行速度：极快\n待机时间：可以\n其他特色：轻便，屏幕漂亮\n京东速度，当天达，2023开年礼物，极好的小米手机\n小米换苹果多年，现在换回来。\n体验做技术，总在进步的小米手机，永远在路上', '远山蓝', '2023-01-02 08:28:44', 9);
INSERT INTO `data` VALUES (12801, 'C***7', 5, '外形外观：直边框太爽了，6.36尺寸握感很好，小尺寸真香\n屏幕音效：屏幕是1080p，但是不妨碍看4k?，双扬声器马马虎虎吧\n拍照效果：有莱卡的加持拍照真的上了还几个档次，很好看\n运行速度：我的是12+512，运行速度很快\n待机时间：本来很好的，不小心更新14.0.11版本结果耗电有点快，98的电看个短视频10分钟就掉1%电，双十一买的k50u更新14.0.10都没有掉这么快\n其他特色：莱卡拍照很好', '远山蓝', '2023-01-10 18:46:36', 8);
INSERT INTO `data` VALUES (12802, 'j***p', 3, '正在使用，但随机软件太多', '旷野绿', '2023-03-08 14:42:00', 6);
INSERT INTO `data` VALUES (12803, '是***胖', 5, '从米2一直用到了13运行速度: 畅快 拍照效果: 清晰 续航能力: 很好 小米13是我最满意的一块手机，特别这个尺寸手感特别好，单手操作很舒服，外观颜色炫酷，直角边框，是我最喜欢的！运行流畅，像素清晰，电池很给力，小米13集优点于一身，真的给我惊喜，物有所值，喜欢的不要犹豫了！', '旷野绿', '2023-01-17 23:19:31', 5);
INSERT INTO `data` VALUES (12804, '全***5', 5, '从小米8一直到如今的13，始终没有让我失望过。蜜柚14改进不少，运行速度有了大幅度的提升。电池的续航能力非常棒，用了一天还有50%的电量。拍照效果也是较之前的旗舰机有了大幅度的提升。推荐购买12GB的运行内存，性价比颇高。', '远山蓝', '2023-02-11 00:52:38', 6);
INSERT INTO `data` VALUES (12805, 'f***s', 5, '外形外观：13真香，比苹果14手感好很多，淡淡绿色很好看\n屏幕音效：屏幕看着很舒服，双扬声器声音大很动听\n拍照效果：徕卡镜头拍照很有效果，但是长焦和微距像素有点差\n运行速度：12+256加上MIUI14的系统非常流畅\n待机时间：大电池就是爽，67W充电快快快', '旷野绿', '2023-01-11 23:55:19', 5);
INSERT INTO `data` VALUES (12806, '阿***y', 5, '外形外观：美，窄边美\n屏幕音效：很棒\n拍照效果：夜景也不错，很大提升\n运行速度：很快\n待机时间：还正常', '远山蓝', '2023-02-11 11:19:59', 8);
INSERT INTO `data` VALUES (12807, '蓝***7', 5, '小米13这次真的很惊艳，顶级的性能，还有符合我审美的远山蓝外观，加上直屏和直边框，拿在手里手感真的是绝了，还有纳米皮，摸起来是真舒服啊，用惯了玻璃后盖再用这种纳米皮，舒服。另外徕卡相机拍照效果也很棒，收到手机第一时间拍开箱照，加个水印防盗图。\n最后，满分好评！', '远山蓝', '2022-12-22 16:29:08', 9);
INSERT INTO `data` VALUES (12808, '楼***意', 5, '小米13这款手机质量非常好，又是直屏的非常喜欢，我特别喜欢直屏的手机。最讨厌曲面屏的手机，等了好几代刚好小米13出了一个直屏，真的太喜欢了，无论是手机外观，还是手机性能，拍照功能都完全符合卖方的描述。我真的很喜欢。这完全超出了预期。交货速度非常快。包装非常仔细和紧密。物流公司有良好的服务态度，交货速度非常快。令人满意的购物质量非常好。我希望更多的朋友能信任它。京东的态度很好，以获得赞扬。交货很快，态度很好，我很满意！好，好！网上购物是如此快。我没想到京东的服务这么好，商品质量好，价格低，而且卖家非常热情。下次我会有机会再找你购物。找到你心中的宝贝是一件非常开心的事。', '白色', '2023-03-03 13:52:46', 7);
INSERT INTO `data` VALUES (12809, 's***d', 5, '很早以前曾经是小米CC9用户，家里也是全套小米智能设备&hellip;&hellip;这次突然看到小米13，突然有一种&ldquo;惊为天人&rdquo;感觉，手感更加一流，于是毫不犹豫马上买了。这个边框+屏幕的感觉，简直绝绝子。必须好评！\n\n虽然没有送无线充，但兼容50W小米无线充，正好有一个，完美适配。\n\n最意外的惊喜是徕卡，非常浓郁，很喜欢，跟之前的华为徕卡差不多，无缝连接了。\n\n总体是惊喜，价格能接受。\n\n吐槽也是有的，官方清水壳无法保护镜头盖，担心耐久性。', '远山蓝', '2023-01-07 15:26:15', 9);
INSERT INTO `data` VALUES (12810, '莫***剑', 5, '这次的小米13外形真的好，尺寸把握，手感，配置及拍照等方面可以媲美某果。该有的配置都有，CPU内存配置顶级，玩游戏毫无压力，拍照速度秒拍，徕卡成像也满足需求，可玩性高。搭配miui14操作流畅，特别是电池省电，不管玩游戏还是看视频，手机发热也低，小米13稳了。用个3年应该可以吧。', '黑色', '2023-03-16 10:58:56', 8);
INSERT INTO `data` VALUES (12811, '我***坏', 5, '外形外观：外观真的超级好看，直屏手机爱好者的最爱，棱角分明，后背是陶瓷的，很是舒服\n屏幕音效：屏幕120赫兹高刷，很舒服\n拍照效果：莱卡镜头，真的很值\n运行速度：骁龙888第二代处理器，加上米柚系统14很流畅\n待机时间：待机几小时还是100%\n其他特色：整体来说很满意，感觉是下一批钉子户', '白色', '2023-02-05 16:59:37', 8);
INSERT INTO `data` VALUES (12812, 'H***儿', 5, '来了来了，米13不错 黑色大气低调！ 今天的旷野绿也到手了，真的好看。还在犹豫的小伙伴直接上图给大家看效果！暗光下有点水泥灰的意思，强光也微绿的好看！ 很不错的一款手机，质感很好，配置够用！ 老伙计可以下岗了！哈哈', '旷野绿', '2023-01-23 22:42:05', 9);
INSERT INTO `data` VALUES (12813, '颜***丶', 5, '外形外观：手感极佳，外观非常好看漂亮，棱角分明，是我钟意的直屏款！\n屏幕音效：屏幕真是没话说，分辨率高，非常高清，给人一种非常舒适的观感！\n拍照效果：不愧是搭配徕卡的相机，像素非常棒，拍照流畅！\n运行速度：运行速度是我最看中的东西了，第二代骁龙8+处理器不是吹出来的，流畅度，反应速度简直神了！\n待机时间：充满电不管怎么玩都能用一天，不玩游戏日常使用时间更长，最起码能用12小时以上！\n其他特色：各方面都满足我对小米13的幻想，值了！', '黑色', '2023-01-05 16:42:07', 8);
INSERT INTO `data` VALUES (12814, '思***儿', 5, '外形外观：小巧机身配合圆润直边铝合金边框显得是那么和谐，后壳玻璃材质，温润有质感，散热好\n屏幕音效：全景杜比音效，双扬声器震撼场面音随心动\n拍照效果：莱卡镜头完美呈现，长焦镜头 高像素等\n运行速度：第二代骁龙处理器完美赶超水果机\n待机时间：能抗住深度使用七八个小时没问题，正常用，充满一天没问题 心动的小伙伴买它吧！', '旷野绿', '2023-02-11 01:32:28', 9);
INSERT INTO `data` VALUES (12815, '_***鑫', 5, '外形外观：外观好看，难得的直屏机\n屏幕音效：音响够用\n拍照效果：拍照好看，徕卡加成的镜头确实好看\n运行速度：推荐购买12G版本，12G的用起来很爽\n待机时间：待机时间早上出门充满电，晚上下班回家还能有一点电，很强', '白色', '2023-01-16 18:46:59', 7);
INSERT INTO `data` VALUES (12816, '龙***5', 5, '东东收到了，京东自营的商品，发货速度一向都是很快滴，快递小哥更是相当的给力。商品包装严密无破损，实物与店家所提供的图片信息一般无二。大年三十儿，晚上下单的，正月初一下午我就收到了货。商品不错，新机运行的速度挺快滴。新旧机置换方便、快捷，总体满意。', '黑色', '2023-01-22 21:29:02', 8);
INSERT INTO `data` VALUES (12817, 'j***q', 5, '外形外观：大小合适，白色的很漂亮，手感很好\n屏幕音效：显示清晰，边框很漂亮，音效逼真\n拍照效果：比小米11清晰很多，莱卡就是给力，拍的照片很真实\n运行速度：运行速度流畅，游戏无卡顿，长时间运行也不怎么热\n其他特色：白色的真的很漂亮，手感超级好，颜值很高', '白色', '2023-02-16 23:16:46', 3);
INSERT INTO `data` VALUES (12818, '摇***喵', 5, '手感非常的好，小巧也不是很重，总体非常好\n外形外观：漂亮。很喜欢，，手感真的很好，自带贴膜。哦哦哦\n屏幕音效：很好\n拍照效果：非常好，很喜欢。拍的美美的\n运行速度：棒，没有卡顿刚刚。顺滑\n物流也快。一直在京东购买', '白色', '2022-12-15 20:14:18', 3);
INSERT INTO `data` VALUES (12819, '杰***麦', 5, '昨天去店里体验了一下手感，然后昨晚直播间下单的，24期免息，送保温杯，小音箱，小台灯。\n买来做备用手机，平时自用水果11PM。之前的备用机是华为nova，2017年买的。\n不得不说小米13的手感很好，直框直屏，黑色和白色都非常好看，因为工作环境，只能选耐脏的黑色了。个人喜欢裸奔，所以原机的贴膜也撕了，套也不带了。\n到手就更新系统，删一些不要的应用，关闭扩展内存，关闭广告，开高刷，目前还没怎么使用，过段时间追平再说说续航、丝滑程度等等的感觉&hellip;&hellip;\n目前发现的就是用外放听歌的话，音质实在是邋遢极了&hellip;&hellip;', '黑色', '2023-02-02 22:08:53', 8);
INSERT INTO `data` VALUES (12820, 'x***8', 5, '使用后非常好，尤其是屏幕，感觉上了一个档次，非常清晰，质感也很好，用着非常顺手，颜色也很漂亮，买给老公的，大小也很合适。全家都是小米手机，忠实粉丝。', '旷野绿', '2022-12-26 20:55:34', 9);
INSERT INTO `data` VALUES (12821, '上***使', 5, '一直想换手机，但是比较纠结选择哪一款。\n原来手机是因为内存不够用，经常卡顿，这次换手机的目的很明确，大内存512。\n换新手机颜值也很重要，不光好用。\n原来远去锁定在小米身上，符合颜值加内存两方面的需求。\n颜色是儿子帮忙选的，相信年轻人的眼光，选的蓝色。\n到手后确实经验到我了，外观漂亮。\n系统丝滑，好用。拍照效果特棒。\n在官方直播间买的，还送了三件套礼物，不错。\n值得推荐', '远山蓝', '2023-02-05 21:15:42', 9);
INSERT INTO `data` VALUES (12822, 'g***9', 5, '外形外观：说实话，这次的外观彻底&plusmn;我了\n屏幕音效：杜比全景声身临其境太爽了\n拍照效果：相比于苹果小米13杠杠的，我手里的苹果13 pro Max都想扔了\n运行速度：运行速度快，完全不卡\n待机时间：待机时间长一天一充', '黑色', '2023-02-01 21:18:19', 3);
INSERT INTO `data` VALUES (12823, 'M***泷', 3, '好家伙 第二天就遇到问题，开免提对面听不到声音', '宝石蓝', '2023-03-10 16:26:23', 8);
INSERT INTO `data` VALUES (12824, 'S***r', 5, '1外观很精致，很漂亮。系统运行流畅快。不玩游戏，所以游戏性能就不评价。\n2/拍照效果非常好，对焦很快，比我的三星s10效果要好。\n3/外放声音不错，比我三年前的三星s10好多了。\n4/大小，看网上评测都把他称为小屏手机。但跟我的6.1寸的三星s10比起来明显更大/更厚/更沉。仅从外观精致/小巧这方面来看三星s10甩小米几条街。\n5/屏幕很好，买之前还在担心1080p的分辨率太低，8bit的色深是否影响显示效果，用了好几天感觉完全不影响，显示效果不比三星s10的2k屏差。', '旷野绿', '2023-02-09 16:42:22', 3);
INSERT INTO `data` VALUES (12825, '田***猫', 5, '外形外观：大方帅气\n屏幕音效：屏幕大小合适，音效很不错\n拍照效果：拍照效果绝了，清晰度高\n运行速度：顺滑\n待机时间：待机时间很久，平时一天玩手机，一天充一次电', '黑色', '2023-01-07 22:06:33', 3);
INSERT INTO `data` VALUES (12826, '西***哒', 5, '手感太棒了，等了好多年，终于出了，这一刻泪流满面，玻璃的手感久违了，用了好几年素皮快崩溃了，miui14非常流畅，也不热，打游戏稳稳的！', '旷野绿', '2022-12-30 15:41:50', 5);
INSERT INTO `data` VALUES (12827, '花***r', 5, '外形外观：非常漂亮，绝对是直屏第一\n屏幕音效：屏幕也很出色，没有发黄\n拍照效果：拍照算是不错的，虽然和12s ultra有距离\n运行速度：高通的大龙2，终于不是火龙了', '白色', '2022-12-17 13:46:23', 4);
INSERT INTO `data` VALUES (12828, '你***春', 5, '小巧的外形，玻璃的背板，我很喜欢。买的是256的内存，都说13是新的钉子户，我来试试水。虽然没有了哈曼卡顿，但是音质还是不错的，音量也很足，拍照方面简单的试了下，并没有感觉很大的变化，徕卡加持的感觉不是很明显，放大到最高倍数画面很是模糊，不经常拍照也不太懂这些东西，游戏方面的话就不给予评价了，因为玩游戏用的平板，毕竟mini6才是玩游戏首选，充电速度很快，67W的快充，我从百分之％20 到百分之％80用了大约15分钟左右，这个速度我很满意，待机方面的话还没有做测试，但是网上有评测视频，大家可以看一下。人脸识别速度很快，刷一下就开了。重点说一下这个震动反馈，手感很好，和苹果有的一拼！', '黑色', '2023-01-06 19:34:08', 3);
INSERT INTO `data` VALUES (12829, '6***4', 5, '觉得有用运行速度：畅快\n拍照效果：清晰\n续航能力：很好\n超窄边框直屏确实很惊艳，屏占比与颜值均有上佳表现；小尺寸机身＋两侧边缘弧形过渡，不仅单手操作颇为方便，手感也很舒适；骁龙8Gen2处理器搭配全新的MIUI14系统，性能与流畅度均为行业顶级水平，用户体验较为优秀；徕卡相机组合不容小觑，拍照实力在线。', '黑色', '2023-01-18 13:00:12', 3);
INSERT INTO `data` VALUES (12830, 'j***4', 5, '米6用到现在，看到米13的大小非常不错，大小在现在的手机里是一股清流，配置也很完美，加上8g2解决了功耗问题，成功让我有了换机冲动，上手后手感还是比原来的米6厚重不少，还需要适应一下，速度没得说顶级配置很丝滑，续航也很不错，电池比较耐用，充电速度满意，希望也能用5年', '黑色', '2023-01-05 09:09:50', 4);
INSERT INTO `data` VALUES (12831, 'j***z', 5, '小米13，12+256，真香，白色手机颜值很高，边框极窄，MIUI14系统丝滑，手感很棒，6.36寸的屏幕大小刚刚好，适合单手操控，莱卡认证的相机，拍照也超级棒。已经用了4款小米手机了，做的确实越来越好，小米mix2手感最棒，小米13性能最好，红米k50性价比最高，最开始用的小米note2曲面屏！家人以前也是用的水果手机，现在只用新国货小米手机！加油，希望小米手机越来越好！', '白色', '2023-02-07 10:46:20', 9);
INSERT INTO `data` VALUES (12832, 'j***y', 5, '外形外观：屏幕边框很细，看起来非常舒服，外观方正。\n屏幕音效：显示效果好，虽说是1080P的屏幕，但日常看起来区别不大。不仔细靠近看没区别\n拍照效果：拍照效果喜欢。夜间效果好。招牌字都看的清晰\n运行速度：使用了几天未见有卡顿现象，非常丝滑\n待机时间：日常使用一天没问题。67W快充不到40分钟充满。', '黑色', '2023-02-15 16:48:16', 6);
INSERT INTO `data` VALUES (12833, '林***天', 5, '非常不错的手机，手感好，用着舒服，好久没有用纯平手机了，安卓一股清流！只喜欢！小米确认不错，买就是了！各方面做得挺好的，快递一流！', '白色', '2023-03-08 23:57:30', 9);
INSERT INTO `data` VALUES (12834, '一***钙', 5, '老米粉很满意！小米8可以退休了。米13非常漂亮的手机 超薄 关键反应还挺快 屏幕也很完美 比想象中要好得多 到小米之家试了试  回家看了一下就下单了 第二天送到 值得推荐 这次相比以前型号提升很多 奈斯了啊小米 爱不释手了这次 大小也合适。手感方面不错，不愧是小屏旗舰，外观设计优雅，屏幕显示清晰，屏幕边框完美，音效逼真，还原真实，拍摄清晰，莱卡联名，夜景很好，前置也很棒，运行速度快，游戏毫无压力，待机时间长，很喜欢这款手机，还是挺不错的！', '黑色', '2023-01-05 21:33:17', 6);
INSERT INTO `data` VALUES (12835, 'D***n', 5, '外形外观：直边就很喜欢，金属边框很好看，\n拍照效果：画质清晰，照片还原度很高\n运行速度：很流畅，稳定，小米13yyds\n待机时间：明显提升了很多，一天一充完全没问题', '白色', '2022-12-19 22:55:13', 6);
INSERT INTO `data` VALUES (12836, 'X***_', 5, '连续三年的高端之作，手感真好。屏幕第一眼看上去感觉很棒。边框所有手机里面最窄的。我在手里面的感觉不大不小，刚刚好。单手操作很方便。性能也非常棒，玩起来的感觉散热也很好。', '远山蓝', '2022-12-23 10:42:18', 3);
INSERT INTO `data` VALUES (12837, '克***斯', 5, '外形外观：很好看，我比较喜欢蓝色，科技纳米皮很耐脏\n屏幕音效：屏幕很合适，小屏幕用起来很舒服\n拍照效果：很好，毕竟有莱卡\n运行速度：很快，很丝滑\n待机时间：很久，一天一充', '远山蓝', '2023-01-02 09:02:46', 5);
INSERT INTO `data` VALUES (12838, 'c***o', 5, '第一次用小米手机，买了这款小米13，个人感觉很不错，给我的感觉是用起来很&ldquo;柔软&rdquo;的感觉，很流畅。由于第一次使用小米系列，很多功能还不知道，用了之后再来追评。', '黑色', '2023-02-22 00:10:18', 4);
INSERT INTO `data` VALUES (12839, 'Y***x', 5, '外形外观：真的巨好看！买的时候还在纠结摄像头大小不一样会很丑  目前看来还是我多虑了  手机那一圈金属边看着真的很高级！真的很好看！谁懂啊！\n拍照效果：拍照效果目前还没发现有啥特别之处哈哈哈哈哈哈哈哈   但也还不错\n\n待机时间：待机可以用很久很久！过年在家基本上一整天都是在玩手机的  一天差不多充一次电  充电速度很快  剩余20的电量半个小时就可以充满', '白色', '2023-02-10 17:39:49', 3);
INSERT INTO `data` VALUES (12840, 'M***i', 5, '外形外观：个人感觉外观比宣传图还好看\n屏幕音效：杜比全景音效很棒\n拍照效果：拍照效果非常好\n运行速度：动画很流畅\n待机时间：中规中矩吧\n\n总体的使用感觉还是很好的（第一部小米手机）', '远山蓝', '2022-12-20 20:11:18', 3);
INSERT INTO `data` VALUES (12841, '朱***-', 5, '外形外观：外观很大气，黑色很有质感。\n拍照效果：拍照效果很好，尤其是徕卡拍出来的照片很出片\n运行速度：很好，很流畅，没有卡顿。\n待机时间：待机时间长，一般情况下使用一天一充。', '黑色', '2023-02-05 10:05:51', 2);
INSERT INTO `data` VALUES (12842, '柠***儿', 5, '外形外观：直角边框精致，一体型好，质感好，非常适合女孩子\n屏幕音效：可视角好，如果加上2k屏幕更完美\n拍照效果：徕卡相机照相非常棒，长焦也非常清楚，\n运行速度：速度非常快\n待机时间：待机时间也很长 \n整体来说小米13非常好，手机小巧玲珑，重量也轻，莱卡相机照相也非常完美，特别适合女孩子用', '旷野绿', '2022-12-27 11:17:56', 2);
INSERT INTO `data` VALUES (12843, '牧***z', 5, '使用四五天左右，个人感觉这一代成了，撼动了我这个米6钉子户，一直盼着出个小直屏，这不就来了，因为米6用的太久，这个跨度换过来给我的体验舒适度和新鲜感都比较满，总而言之对这代很满意，希望小米秉承小直屏做下去，我后面接着换。', '白色', '2022-12-29 17:30:21', 8);
INSERT INTO `data` VALUES (12844, '云***儿', 5, '比较轻巧，运行流畅，外形美观，各方面体验都不错，很均衡很满意的一款手机。', '白色', '2023-03-03 21:28:05', 9);
INSERT INTO `data` VALUES (12845, 'R***e', 3, '三星，双扬声器拉胯，', '黑色', '2023-02-01 15:06:52', 5);
INSERT INTO `data` VALUES (12846, 'S***V', 5, '外形外观：握持手感很好，不愧是小屏旗舰，大小刚合适。\n拍照效果：徕卡加持，随手出大片，特别是黑白风格，以及负一屏的快捷键，好用且好看。\n运行速度：高通2代处理器，运行速度流畅', '黑色', '2023-03-06 17:02:41', 6);
INSERT INTO `data` VALUES (12847, '浅***瓜', 5, '外形外观：我买的是蓝色的素皮的，手机确实挺轻，可以长时间握持，从米10换过来的，还是喜欢直角平。\n\n屏幕音效：屏幕很棒，感觉很清晰，很亮，防闪烁直接打开。\n拍照效果：快速，清晰，莱卡还得在摸索摸索摸索看下具体照片效果。\n\n运行速度：机器运行速度，超级流畅。\n待机时间：我觉得待机时间挺长的，耗电控制的很好。\n其他特色：充电速度，我很满意。机器重量也挺惊喜。总之好处＞瑕疵。', '远山蓝', '2023-01-12 16:21:16', 2);
INSERT INTO `data` VALUES (12848, 'j***a', 5, '以旧换新换掉了之前的iPhone12pro。手感很棒、很轻。小米13用的骁龙8gen2处理器，使用起来也非常流畅，不卡顿。充电速度完爆苹果手机，30分钟就能完全充满，待机时间也很长，下班回家还有36左右的电量。拍照的莱卡出片也很棒，景深有层次感，远景也很清晰。音效也不错，看爱奇艺视频。完全满足我对手机的要求。', '远山蓝', '2023-01-05 19:22:22', 3);
INSERT INTO `data` VALUES (12849, '米***-', 5, '小米13直屏屏幕很喜欢，不喜欢曲面屏，手感不错，摄像头好看，拍照也很好，续航不错，充电也快，MIUI系统用着也习惯，骁龙8 Gen2处理器，YYDS，选的是12GB+512GB黑色的，还能24期免息很给力！', '黑色', '2023-01-04 01:08:32', 3);
INSERT INTO `data` VALUES (12850, 'r***9', 5, '外形外观：经典直板，和手上的13pro很像很像&hellip;\n屏幕音效：显示中规中矩\n拍照效果：人像模式很赞\n运行速度：还行吧\n待机时间：不错，充电也快\n其他特色：小屏直板，手感极佳。', '黑色', '2023-03-18 19:44:04', 5);
INSERT INTO `data` VALUES (12851, 'j***e', 5, '外形外观：最喜欢这个，给10分\n\n运行速度：骁龙8gen2很牛的，不会卡顿\n\n拍照效果：莱卡相机很喜欢\n\n别处都有礼品，我买的没有，很难受，找客服没补发', '远山蓝', '2023-03-19 13:54:23', 8);
INSERT INTO `data` VALUES (12852, '泽***宇', 5, '收到了，苹果换回来的，还是选择了小米。手感非常不错，是心目中的小屏旗舰，外观设计中规中矩，屏幕边框很完美，显示清晰，音效逼真，拍摄清晰，莱卡联名，运行速度还不错，玩游戏无压力，待机时间很长。心中完美小屏直屏旗舰机。', '黑色', '2023-01-14 08:14:17', 7);
INSERT INTO `data` VALUES (12853, '小***2', 5, '一直关注小米手机，闺女也很喜欢，拍照效果好，内存大，分辨率也很高，反应快，非常不错，方方正正手感很好，皮质很有质感！', '远山蓝', '2022-12-31 20:37:05', 4);
INSERT INTO `data` VALUES (12854, 'j***8', 5, '外形外观：非常喜欢\n拍照效果：非常可以\n屏幕音效：非常好听\n运行速度：可以，就是连wifi有卡死\n待机时间：待机可以，但是在使用过程中掉电特快???', '远山蓝', '2022-12-20 00:17:10', 7);
INSERT INTO `data` VALUES (12855, 'c***u', 5, '收到了收到了，京东物流杠杠滴！隔天就到了。收货就迫不及待打开了，大小合适，?分量，做工精细手感特别棒。小米真的很给力。直角屏幕和曲面屏做了比较，曲面屏好看，但是手机外壳包不住侧边，?用袋子形状的东西，不然，放包里，很容易被压坏的。', '旷野绿', '2023-03-07 22:56:32', 9);
INSERT INTO `data` VALUES (12856, '隐***9', 5, '包装保护：全方位保护\n外形外观：轻薄，金属质感，拉丝面\n画面品质：高清，色彩逼真\n运行速度：秒开，即点即出\n游戏效果：全效开放，无压力\n晚上下单，隔天上午就到货，物流配送相当迅速！机器配置高，外观完美，运行流畅，一次完美购物体验！', '轻薄电竞R9000X', '2022-08-17 18:33:58', 5);
INSERT INTO `data` VALUES (12857, 's***y', 5, '包装很结实，两层的，外面有京东的包装盒。联想的包装盒外有联想密封贴，防止遇到二手机。电脑做工很精致，全金属机身，外观含蓄不张扬，我是买来工作用的，一点儿不违和，很满意！屏幕画质好，亮度高，演示公司的三维程序很出彩！性能释放强，满意！就是适配器太沉了，没办法，为了性能释放只能忍了！总体很满意，很推荐！', '专业电竞R9000P', '2022-08-18 09:11:43', 9);
INSERT INTO `data` VALUES (12858, '黑***z', 5, '游戏本收到了，京东就是快，第二天就到了。质量感觉很不错，喜欢双面的金属设计，摸上去手感很好，键盘按起来也很赞，运行操作很流畅，屏幕显示很清晰，分辨率很高，看起来很舒服，总体很不错，推荐大家购买！', '【销量先锋】专业电竞R9000P', '2023-01-05 16:02:07', 5);
INSERT INTO `data` VALUES (12859, 'j***4', 5, '电脑很好，快递很给力，电脑运行没得说的，非常可以，是全新的，配置可以，可以冲\n画面品质：可以可以，2k\n运行速度：666\n游戏效果：无敌\n外形外观：很帅，特别是后面灯，爱了', '【销量先锋】专业电竞R9000P', '2022-11-10 22:20:59', 4);
INSERT INTO `data` VALUES (12860, '也***然', 5, '质感很好，走起来流畅，系统也很好使，自带的软件也很方便\n外形外观：很漂亮\n包装保护：很到位\n运行速度：很快\n游戏效果：待测', '专业电竞R9000P', '2022-08-11 08:15:39', 9);
INSERT INTO `data` VALUES (12861, 'j***8', 5, '包装保护：包装很给力，包的很严实，有泡沫保护着，很赞\n外形外观：做工很精细，外观还是很漂亮的，\n画面品质：画面清晰，色彩丰富，整体很可以\n运行速度：开机速度快，打游戏运行起来很流畅，\n游戏效果：游戏页面看着很清晰，色彩鲜艳，运行起来没有卡顿的现象，\n这次选购还是很喜欢的，大件都在京东买，昨天晚上下的单，上午送到，这效率真是无敌??有需要还会在回购', '【销量先锋】专业电竞R9000P', '2022-11-11 16:01:45', 6);
INSERT INTO `data` VALUES (12862, 'M***e', 5, '第一次买笔记本电脑 去年就一直关注R9000P了 我这边三月三加清明节放三天假 索性就就入手了 4月2日购买到4月3日到货 京东yyds 到货马上验机 生产日期3月21日的 屏幕无坏点完美屏 三星内存 海力士固态 验完机立马自己加装1T固态 用了3天没什么问题\n包装保护：无破损完美\n外形外观：精致 简洁大方 手感好\n画面品质：2.5K屏看起来很舒服很细腻\n跑分评测：没跑分 就是Win11用不是很习惯 慢慢摸索吧\n运行速度：很快 秒开\n游戏效果：我很少玩3A游戏 2.5K 165hz高刷完美适配各种网游', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-04-05 10:49:56', 8);
INSERT INTO `data` VALUES (12863, '大***酷', 5, '包装保护：包装很好\n外形外观：我网上看没有太大感觉 实物真的惊艳到我了\n画面品质：不说了 有了电脑不看手机了\n跑分评测：绝了 只能说这两个人字\n运行速度：冲 冲 冲 感觉真的舒服 大型游戏随便玩', '【销量先锋】专业电竞R9000P', '2023-03-15 22:16:18', 8);
INSERT INTO `data` VALUES (12864, '布***9', 5, '包装很结实，产品很给力，更新了好半天。\n速度很快，开机秒开，应用秒开。\n外观给力，帅气金属机身。\n重量还行，比游戏本稍微轻点。\n屏幕给力，显示效果非常好。', '轻薄电竞R9000X', '2022-11-02 14:21:45', 9);
INSERT INTO `data` VALUES (12865, '彳***-', 5, '第一次买电脑，很棒，看图，（18岁小屁孩的手，给你们做屏幕参考）\n包装保护：完美无破损\n外形外观：无划痕\n画面品质：画面品质：2K 165赫兹高刷很畅快\n跑分评测：AMD5800H的3060跑分还彳亍，评测视频B站很多\n运行速度：流畅，开机5,6秒就好\n游戏效果：网游无压力，3A也还可以', '专业电竞R9000P', '2022-08-09 22:22:32', 3);
INSERT INTO `data` VALUES (12866, 'y***朱', 5, '综合考虑选择了这款，没有失望，很不错，性能也很不错，运行游戏也不卡，开机很快，色彩也不错。看视频也是不错的！外观也很赞，轻薄。整机包装保护不错，送货速度也是超快！目前是用了几天后才评价的。游戏和视频也开了好几次了，声音效果还可以。检查过，是正品\n包装保护：很好\n外形外观：很好\n画面品质：不错\n跑分评测：不错\n运行速度：不错\n游戏效果：不错', '轻薄电竞R9000X', '2022-12-12 19:58:33', 8);
INSERT INTO `data` VALUES (12867, 'h***0', 5, '曾经买过第一代拯救者，7年来我用过4台笔记本，现在又回到了拯救者。如今拯救者的外观真好看，R9000X外观大气质感好又轻薄，是我喜欢的外观。这是我第一次用双A平台的笔记本，试了几个游戏，在2k分辨率下都很流畅，我的主力电脑是台式机，这台笔记本已经能满足我偶尔出差、旅游用途了。对了这台机器屏幕表现不错，看评测NTSC是74%，实际观感更出色。\n拿到后我加了一条联想16g内存，固态盘换成了1t，系统还是选择了win10，换下的原装固态装了硬盘盒用。', '轻薄电竞R9000X', '2023-01-25 19:38:42', 9);
INSERT INTO `data` VALUES (12868, 'x***o', 5, '包装保护：京东快递很快。早上就送到了。\n外形外观：外形很好看 ，很轻薄。就是有点重。屏幕很大，窄边框，视觉效果很好。\n画面品质：很好，亮度500。\n跑分评测：跑分很高，运行速度很快，不卡顿。6800h很快，cpuz单核560多核5600。鲁大师130w。其他跑分软件暂时没跑。\n运行速度：很快，工业软件运行很流畅。\n游戏效果：很好，3a很流畅，网游那些肯定没问题。6800s 8g 显存，3a可以开高画质。\n 下次继续买联想，这次购物很满意。', '轻薄电竞R9000X', '2022-11-02 11:17:44', 7);
INSERT INTO `data` VALUES (12869, '飞***鹅', 5, '包装保护：高端大气上档次\n外形外观：霸气奈斯\n画面品质：高分屏good\n跑分评测：120w\n运行速度：gta5特效全开无压力\n游戏效果：8G显存不是盖的', '轻薄电竞R9000X', '2022-11-10 23:19:30', 8);
INSERT INTO `data` VALUES (12870, 'K***少', 5, '中午接近12点下单，下午不到6点多就送到了，快递小哥送货速度无敌！\n\n新电脑比想象中要好多了，屏幕和机壳比我的y9000x好上几个档次，把娃照片做屏保和开机画面让人爱不释手哈。\n\n和老鸡对比，重量增加不算多，屏幕大了一圈。\n\n性能暂时没有游戏可测试&hellip;应该不会让我失望！', '【新品】旗舰电竞R9000K', '2022-08-26 16:54:21', 6);
INSERT INTO `data` VALUES (12871, '买***丶', 5, '性价比很高，性能强劲，主要看中了性能，买过来制图，比公司的台式机好多了，基本上不玩游戏了，不过看到这个电脑还是会手痒?\n包装保护：寄过来的时候包装很完整，里面有很多泡沫棉\n外形外观：真的帅啊，金属面板质感很好\n运行速度：运行速度没得说，起飞，3d建模再也不卡了', '【销量先锋】专业电竞R9000P', '2022-11-17 18:44:54', 8);
INSERT INTO `data` VALUES (12872, 'w***7', 5, '非常不错，处理器：6800h完全够用，配上显卡6800s也是非常不错，2.5k100%RGB色彩，屏幕素质可以，再加上键盘手感也非常好，外观还是喜欢21款的外观，当然现在这个外观也不错，值得推荐', '轻薄电竞R9000X', '2023-02-04 22:35:27', 4);
INSERT INTO `data` VALUES (12873, 'q***8', 3, '电脑是送到学校的，具体不清楚，购物再评', NULL, '2021-11-10 23:11:11', 8);
INSERT INTO `data` VALUES (12874, '_***_', 5, '买的入门款，使用感受很不不错，没有发现什么问题。屏幕给我观感特别好，音质也没啥问题。游戏的话没怎么试，看后续体验。目前总体比较满意。', '轻薄电竞R9000X', '2023-02-13 20:50:14', 4);
INSERT INTO `data` VALUES (12875, 'j***h', 5, '包装保护：包装很好\n外形外观：很漂亮，有质感。电池很重很大\n画面品质：屏幕素质很高\n跑分评测：玩大众游戏轻轻松松\n运行速度：非常快，秒开机\n游戏效果：运行速度很快，配置够用了，目前的市场上性价比很高的款型', '【销量先锋】专业电竞R9000P', '2022-11-12 19:21:28', 7);
INSERT INTO `data` VALUES (12876, '席***生', 5, '包装保护：京东物流一直都可以信赖没啥说的包装完好，打开物流箱里面是机器包装箱，封口完好没有磕碰。\n外形外观：是我喜欢的样子，大写Y很时尚很nice\n画面品质：2.5k果然好，比以前的老机器1080好太多，刷新率也高，没看到啥缺点，屏幕京东方的没有啥问题。\n跑分评测：来红灯（野兽模式）136万鲁大师跑分，满意了。\n运行速度：跑分就说明一切\n游戏效果：还没完，目前不知道如何，不过配置在这的应该不会差。\n总体满意，用用看。', '专业电竞R9000P', '2023-01-06 18:10:44', 7);
INSERT INTO `data` VALUES (12877, 'e***a', 5, '首次网上购买笔记本，京东包装加原封泡沫垫妥妥的，拯救者本本外观工艺确实阔以，全金属机身质感大赞，沉稳的灰黑色调满意。全方位检查没有一丝划痕，屏幕色彩显示清晰高大上，LOGO和键盘灯格调不错。适配器&hellip;.咱能优化轻便点嘛&hellip;. 首次开次耐心等待，二次开机十秒，运行流畅无卡顿，武汉调货的八月下旬产的本本，大师验机，AMD配双三星配京东方配海力士闪存，可以冲啦~', '【销量先锋】专业电竞R9000P', '2023-03-14 08:53:12', 9);
INSERT INTO `data` VALUES (12878, '就***了', 5, '包装保护：包装挺厚实的，机子无磕碰划痕\n外形外观：全铝的轻薄本，办公很实用\n画面品质：屏幕分辨率高，特别棒\n运行速度：打开office和其他软件操作反应挺快的\n游戏效果：基本上steam游戏都能玩\n我是A粉，3A平台性价比很高。买！', '轻薄电竞R9000X', '2022-12-16 11:14:38', 7);
INSERT INTO `data` VALUES (12879, '园***8', 5, '太帅了真的\n包装保护：快递包装的很好 很大气 根本不用担心出什么问题\n外形外观：拯救者大气的外观 不用多讲\n画面品质：顶级！玩游戏真的舒服 平时办公用着2.5k的屏幕也是很爽 看多了都有点不太习惯手机屏幕了哈哈哈\n运行速度：很快 不管是游戏 还是工业软件 真的超级快', '【销量先锋】专业电竞R9000P', '2023-02-18 12:09:42', 3);
INSERT INTO `data` VALUES (12880, '慕***n', 5, '电脑收到了，打开箱子一整个惊艳住，电脑很赞，安全下车！外观非常漂亮，大小和厚度也很适合女生，和游戏本相比算是方便携带的。激活流程也很方便。迫不及待打了一把lol，很流畅，fps稳定在140-170之间，画质非常好。这款性价比真的超高，冲啊！', '轻薄电竞R9000X', '2022-11-14 15:10:02', 2);
INSERT INTO `data` VALUES (12881, '小***卜', 5, '笔记本刚到手，金属质感很好，信仰灯很炫，键盘灯也很好看，屏幕分辨率很好，整体外观大气整洁，值得拥有！', '专业电竞R9000P', '2022-11-22 12:51:45', 8);
INSERT INTO `data` VALUES (12882, 'j***b', 5, 'r9000p非常nice，上班的时候用了同事的，触感，反应，屏幕都很舒服，所以买了个同款。\n芯片是amd的，固态买了个1t的的三星970pro（还是980pro？），下午去安。电脑自带的，都当系统盘使用。插机械硬盘反应也很快，不愧是拯救者，以后妥妥够用了。\n2022款听说比21款散热好些，用的时候风扇呼呼的吹，搭配一个支架就很nice了。不关机的话，拯救者大标一直都很炫亮。\n总体下来很满意，还在与新电脑磨合阶段，鲁大师跑分13000多，还是可以啦。', '【销量先锋】专业电竞R9000P', '2023-03-19 10:33:24', 4);
INSERT INTO `data` VALUES (12883, '秋***候', 5, '包装保护：京东快递很给力，包装完好并且送货上门，当面签收\n外形外观：外观很帅气，大Y简直太酷了\n跑分评测：跑分125万\n画面品质：游戏画质很棒，体验感十足', '【销量先锋】专业电竞R9000P', '2023-03-08 09:28:15', 3);
INSERT INTO `data` VALUES (12884, 'j***w', 5, '游戏本收到了，京东就是快，早上下单，下午就到了\n质量很不错，喜欢双面的金属设计，手感超级棒，键盘按着很赞，运行操作很流畅，屏幕显示很清晰，分辨率很高，看起来很不错，值得大家入手', '【销量先锋】专业电竞R9000P', '2023-03-14 22:58:29', 2);
INSERT INTO `data` VALUES (12885, '磕***拉', 5, '包装保护：包装很好 很牢固 运输无磕碰\n外形外观：金属外壳很好看比之前的旧拯救者好看了很多 真的很轻薄\n画面品质：画面不错 很流畅\n运行速度：打了两局永劫无间 和 老头环 最高画质无压力', '轻薄电竞R9000X', '2023-01-11 20:40:27', 6);
INSERT INTO `data` VALUES (12886, 'm***o', 5, '非常好，值得入手！屏幕无坏点，金属外观，还不重，有质感！尺寸不大不小，刚刚好，符合我的要求！可工作，可游戏。', '轻薄电竞R9000X', '2023-01-17 18:17:42', 4);
INSERT INTO `data` VALUES (12887, '你***人', 5, '外形外观：非常美观，摸起来很冰冷的。\n画面品质：默认设置是高画质，很不错的，十分舒适，还是16:10尺寸令人期待。\n游戏效果：没有瑕疵，正常运行，似乎没有发现微小的卡顿。\n\n目前没有准备近年内的新游戏，现在玩到csgo，崩坏3，欧陆风云4，命运石之门精英版，运行很不错，画面效果很好，下次要用到了ps，sia等等绘画软件，我希望这款笔电可以继续带来令人惊喜的成果。\n运行速度：运行速度：调整系统设置稍有卡顿了，偶尔反应慢拍。', '【销量先锋】专业电竞R9000P', '2022-12-10 10:46:32', 6);
INSERT INTO `data` VALUES (12888, 'f***o', 5, '联想拯救者R9000X终于入手了，整机金属质感，颜值爆表。敲击键盘手感相当舒服。165Hz 10bit高色域屏，无论办公还是游戏，色彩还原度非常高，眼睛也不疲劳。更有AMD RX6800S独立显卡加持，性能完全能媲美台式机。', '轻薄电竞R9000X', '2022-11-21 12:15:01', 6);
INSERT INTO `data` VALUES (12889, '8***3', 5, '很薄，正常游戏本重量，全金属面，质感非常好，屏幕质量也可以，外观没有瑕疵，白色键盘灯有两个档位。amd 功耗低，性能和3060一样，但是功耗更低。是一款精致的游戏本。', '轻薄电竞R9000X', '2023-01-25 14:41:56', 2);
INSERT INTO `data` VALUES (12890, 'T***8', 5, '包装保护：没问题，京东自营就好品质好。\n外形外观：轻薄，拉丝工艺，金属质感无敌了\n画面品质：高刷2.5k屏爱了爱了。\n运行速度：联盟原神cf无压力，嘎嘎丝滑。平时用运行速度很快。', '轻薄电竞R9000X', '2022-12-04 14:15:08', 6);
INSERT INTO `data` VALUES (12891, 'j***r', 5, '三星内存，三星固态镁光显存，京东方屏幕，11月29号生产，到手很新，用了十多天了，没有任何问题，完美机子，元旦入手，打游戏很流畅，屏幕无坏点，京东物流很赞，几个小时就到手了，性价比高，非常好看的logo,包装保护的很好，京东自营购机很有保障???', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-14 15:09:11', 8);
INSERT INTO `data` VALUES (12892, 'j***7', 5, '当天就到了，使用了近一周分享一下体验：\n外形外观：AD面金属，质感很好，C面塑料，有类金属感。整体外观突出但不张扬，相比其他游戏本更低调。\n\n画面品质：2.5K 16寸屏幕，相当于外置显示屏的4K效果，太清楚了。我的漏光很少，也无坏点。\n\n运行速度：5800H + RTX3060 6G 了，运行大部分游戏都无压力。\n\n游戏效果：如下图奥德赛帧率测试。在无超频、野兽模式下，2K全最高画质，混合模式56帧，独立显卡61帧。\n就一周使用来看，我的这台无大问题。小问题是风扇不转时有电流声，通病无解。总而言之，香！', 'R9000P', '2021-04-14 09:56:13', 8);
INSERT INTO `data` VALUES (12893, 'j***7', 5, '16：10的屏幕真的非常大非常舒服，2.5K屏也是观感无敌，到手验机只通电了3小时确实不错，硬盘是三星的，拯救者r9000p确实是一款非常不错的游戏本，几乎没有缺陷，玩apex2.5k可以160帧，奥德赛高画质关抗锯齿有70帧左右', '【销量先锋】专业电竞R9000P', '2023-02-25 01:54:30', 6);
INSERT INTO `data` VALUES (12894, 'j***U', 3, '买了一个月  音响滋啦啦响  糟心', NULL, '2021-11-08 22:38:57', 8);
INSERT INTO `data` VALUES (12895, 'B***Z', 5, '买来用了一小段时间了从开箱验机，到日常使用没有任何问题，就是打游戏最好开野兽模式或者一键超频，普通的均衡我有过一次闪退，开野兽模式从来没有过，日复一日依旧对京东自营店有着十分信赖，也希望越来越好，整机不错\n包装保护：完好无损\n外形外观：金属感拉满，帅！！！\n画面品质：刷新贼快，画质拉满，流畅的起飞！！！\n跑分评测：120多万\n运行速度：无卡顿，超流畅运行\n游戏效果：画质拉满，稳定不掉帧', '【销量先锋】专业电竞R9000P', '2023-02-09 14:40:11', 2);
INSERT INTO `data` VALUES (12896, '简***夜', 5, '包装保护：非常厚实，保护的很好。\n外形外观：厚薄适中，做工精美，材质真实。\n运行速度：不卡顿，非常流程，同时运行多个应用都可以！', '轻薄电竞R9000X', '2022-12-21 07:20:19', 6);
INSERT INTO `data` VALUES (12897, '苇***s', 5, '全金属，超薄，对男生来说这点重量不算什么，质感确实好，非常漂亮，性能也好，我很喜欢\n京东快递发货很快，包装好，点赞', '轻薄电竞R9000X', '2022-11-05 00:39:01', 7);
INSERT INTO `data` VALUES (12898, '似***帅', 5, '做工不错\n包装保护：很好\n外形外观：不错，要是银色就更好了\n画面品质：不错\n跑分评测：不错\n运行速度：很流畅\n游戏效果：不错', '专业电竞R9000P', '2023-02-12 09:14:57', 6);
INSERT INTO `data` VALUES (12899, '夜***嗔', 5, '外形外观：好看 好看 好看！\n包装保护：包装很完好 生产日期是今年的10月份 很新\n跑分评测：鲁大师跑了一百一十多万\n游戏效果：游戏还没试过 完事再过来评价\n机子暂时整体是很过关的.', '【销量先锋】专业电竞R9000P', '2022-12-03 16:40:15', 3);
INSERT INTO `data` VALUES (12900, '爱***霖', 5, '挺好的，拿到手特意录了开箱视频。忙得顾不上仔细查看。联想官方自营，还是令人放心的。关键是价格 现在的价格真的是很好， 比老款的都便宜，但是性能3060+6800  这个可以说比一般的都好的多，够用够用。做工也可满足', '【销量先锋】专业电竞R9000P', '2023-03-09 13:22:30', 9);
INSERT INTO `data` VALUES (12901, '售***人', 5, '想买个笔记本很久了，关注了不少品牌的机型，最后还是选择了R9000X2022，外观全金属质感很好，键盘手感舒适，屏幕不必多说，完美！双A平台性能强劲，完全满足了我的需求，甚至在未来的相当一段时间内都可以满足我的需求，很满意这款产品。', '轻薄电竞R9000X', '2022-11-19 19:40:26', 5);
INSERT INTO `data` VALUES (12902, 'C***_', 5, '电脑的内外包装对电脑的保护做得不错，开箱过程简直是一种享受，非常nice。\n机器外观比图片上看起来更漂亮一些，两面金属材质质感很好。键盘触感也相当不错，打字反馈很好，屏幕清晰度也很好，2.5k屏yyds，打游戏也很好，办公娱乐第一首先', '【销量先锋】专业电竞R9000P', '2022-11-28 10:05:38', 3);
INSERT INTO `data` VALUES (12903, '碧***g', 5, '外观很漂亮，金属的，质感不错\n\n性能不多说，跟台式差不多\n\n屏幕顶级，不多说\n\n续航，办公5个小时，还行\n\n重量，5斤比15.6的轻薄本重1斤，完美\n\n总结:可以代替商务本的游戏本，无论是外观还是性能, GTA5稳定流畅运行没毛病', 'R9000P', '2021-04-12 10:34:37', 7);
INSERT INTO `data` VALUES (12904, '殷***苂', 5, '包装 保护：付款到收货只用半天时间，上午下单 下午就收货了，京东自营真的很棒。包装严实安全，不松散。全新机器未拆封。\n外形外观：外观造型非常帅气，重量能接受，主要是很喜欢。A面大Y  logo很美，键盘灯很棒。键程舒适而且最重要的是外接口很多。\n运行速度：r5 5800h配新3060显卡日常游戏使用盈余，性能足够强大。运行处理很流畅。\n游戏效果：日常使用很安静，特效全开无呼啸。还能更改模式。很棒很值得哦。', '专业电竞R9000P', '2022-06-10 22:13:27', 6);
INSERT INTO `data` VALUES (12905, 'j***h', 5, '联想拯救者R9000P，拿到手后，第一时间开箱。做工相当好，A壳金属手感一流，奔驰灯颜值高，外观真是太惊艳了。2K屏大爱，显示细腻，无论游戏办公，效果杠杠的。键盘布局合理，手感一流。独立显卡给力，这是一个五星水桶机，没有短板，给联想大大的赞。', 'R9000P', '2021-04-07 20:34:17', 8);
INSERT INTO `data` VALUES (12906, '白***哦', 5, '包装保护：三层保护，完全没问题\n外形外观：真的很好看\n画面品质：2.5k没问题\n跑分评测：7位数的跑分\n运行速度：贼快\n游戏效果：没问题的', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-25 12:44:20', 5);
INSERT INTO `data` VALUES (12907, '消***8', 5, '一直相信的品牌，包装好，送货快。款式简洁大方，颜色雅致，金属质感很好，高端大气，尤其电脑外壳图标超级喜欢。使用一段时间了，运行内存都很满意，用起很上手，很满意，望后期的售后也跟上。', '【销量先锋】专业电竞R9000P', '2023-01-14 09:50:01', 6);
INSERT INTO `data` VALUES (12908, 'j***k', 5, '外观很漂亮，机身轻薄，手感做工都很不错，运行流畅，多屏协同真的很方便，屏幕也很清楚，比上一代提升了不少，而且有联想自带的控制中心，对于学生来说很合适。联想笔记本一如既往让人觉得好用，运行十分流畅，配置也很高。购买的时候对比了好几家，最后还是选择了这家，感觉性价比好高，而且显示屏大小也刚刚好，这个价格很公道，开机也就快，安装了几款主流游戏很顺畅，一边下载，一边玩游戏，一边听音乐也不卡顿，朋友都说不错，问我要了链接也要买呢，物美价廉感觉很满意。', '【销量先锋】专业电竞R9000P', '2023-03-16 23:32:11', 7);
INSERT INTO `data` VALUES (12909, '谨***8', 5, '大Y灯非常帅气，AD两面金属很有质感，16:10的屏幕观感非常的好，显示细腻无坏点无漏光，显卡野兽模式单烤130w，性能释放没问题，温度也控制的不错，是一台各方面比较均衡的水桶机', '【销量先锋】专业电竞R9000P', '2022-12-23 10:26:03', 6);
INSERT INTO `data` VALUES (12910, 'j***5', 5, '趁着双11活动好近下单，物流很快，隔天就收到了\n包装保护：包装蛮精致蛮用心的，有泡沫条保护，防止碰撞损坏\n外形外观：质感很棒，尤其键盘音箱小细节处理的很棒，整体外观比图片体验感\n画面品质：屏幕画质啥的没的说，就是蛮好的\n跑分评测：没啥跑分的，系统用习惯就好了\n总结：整体还是不错的，性价比高，趁着活动入手划算', '轻薄电竞R9000X', '2022-11-04 10:43:50', 6);
INSERT INTO `data` VALUES (12911, 'T***代', 5, '外观真的很棒，金属质感，跑分一般，运行起来建筑制图软件还行，比较顺畅，保护措施很到位，应该可以使用四年左右，之后继续换联想的旗舰游戏本', '专业电竞R9000P', '2022-08-18 17:29:53', 6);
INSERT INTO `data` VALUES (12912, 'j***s', 5, '10.31号买的，11.2号就到了，包装完好，2022/10/17号生产的，拆开外观完美，造型很漂亮，画质很好，使用起来看着很舒服，运行速度很快，秒开，打游戏的感受很棒，画质清晰流畅效果很好.\n开学的时候就想买了一直等双十一看到活动果断下单', '【销量先锋】专业电竞R9000P', '2022-11-13 18:06:55', 7);
INSERT INTO `data` VALUES (12913, '庞***豪', 5, '包装保护：包装挺好，包了好几层。\n外形外观：非常大气，大奔驰标也很哇塞。\n画面品质：挺好的，打游戏用的，挺好。\n跑分评测：可以了\n运行速度：挺快的，没有卡顿，\n游戏效果：挺好，快速。游戏体验杠杠的。', '专业电竞R9000P', '2023-01-16 16:05:33', 5);
INSERT INTO `data` VALUES (12914, '原***尘', 3, '割韭菜了，线下拿货已经8800了！', 'R9000P/RTX3060/R7/165Hz 2.5k屏', '2021-09-25 19:52:59', 9);
INSERT INTO `data` VALUES (12915, 'j***6', 5, '外形外观：这个拯救者的外观是真的帅\n画面品质：16寸的2.5k屏显示相当奈斯\n跑分评测：新版鲁大师分数正常\n游戏效果：3060可以2k高画质玩3a,体验相当不错', '专业电竞R9000P', '2022-08-18 18:07:57', 2);
INSERT INTO `data` VALUES (12916, 'j***K', 5, '满意的一次购物  用两周了  体验感不错\n包装保护：完整\n外形外观：耐看 质感很好\n画面品质：清晰', '轻薄电竞R9000X', '2023-02-17 16:04:00', 6);
INSERT INTO `data` VALUES (12917, '酸***1', 5, '不错，外观大气，小新我很喜欢，颜色无色差。开机很快，运行一天，没有大噪音。画质清晰，音效也很ok。买来学习ps剪辑视频制作再也不担心卡了质感很好，摸起来很丝滑，使用起来也不错，以为16寸会很大，但也还好，掉电也比较慢。', '专业电竞R9000P', '2022-08-07 10:53:07', 6);
INSERT INTO `data` VALUES (12918, '久***n', 5, '第一次在网上买电脑，一以前的联想电脑因为太旧了，实在是不想继续用了。测评如下：\n包装保护：非常好，产品完好无损\n外形外观：金属磨砂外壳，防指纹\n画面品质：2.5k超高分辨率屏幕，看着十分舒服\n跑分评测：110w分，也算很高了\n运行速度：非常快，没有卡顿\n体验非常好', '轻薄电竞R9000X', '2022-12-12 21:50:50', 5);
INSERT INTO `data` VALUES (12919, '疯***9', 5, '包装保护：真的很严实，内盒一点没刮蹭。\n画面品质：不愧为2.5K屏，看着是真的很舒服。眼睛不累。因为不玩游戏，也用不着跑分看成绩。要的就是屏幕舒服。\n运行速度：开机速度还行，安装软件时有提示会影响开机速度。\n外形外观：最喜欢这个Y，标志代表了一切。就是这个适配器大了，比之前的大很多，沉很多。\n总体来说，非常满意。', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-21 11:48:34', 5);
INSERT INTO `data` VALUES (12920, 'z***l', 5, '电脑速度不错，也很薄，显示也很清晰哈哈，机器也很漂亮，不错哈哈很好的体验／', '轻薄电竞R9000X', '2023-01-24 15:18:17', 4);
INSERT INTO `data` VALUES (12921, 'r***0', 5, 'Y9000P作为一款专业的电竞游戏笔记本，R7-6800H+RTX3060，性能确实十分强悍，完全满足目前主流网游和3A大作要求。特别是在外观颜值方面更是满足了一切颜王的要求，机身AD双面金属机身设计，还有一个专属的大&ldquo;Y&rdquo;灯，B格满满。联想作为国内知名品牌，专业电脑供应商，拯救者作为联想笔记本旗下的明星产品，产品品质和品控绝对有保证，再加上京东自营售后服务做保障，安全感满满。目前使用，流畅丝滑，体验感非常棒。', '【销量先锋】专业电竞R9000P', '2023-03-15 16:28:21', 6);
INSERT INTO `data` VALUES (12922, 'j***5', 5, '哈哈，买的第二天就到手了，外观非常漂亮，质感非常好，高大上档次。预装的win11系统，非常流畅屏幕清晰好看，特别值的一款电脑', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-02-13 19:03:05', 8);
INSERT INTO `data` VALUES (12923, '山***风', 5, '电脑很好，打游戏很流畅，拯救者很好用，第一次买电脑买到这么好的真的很惊艳，拯救者名副虚传！\n包装保护：包装很完整\n外形外观：外观没有磕碰之类的\n画面品质：2.5k165hz真的很爽\n跑分评测：娱乐大师跑分稳120w以上\n运行速度：开机很快不到7秒\n游戏效果：游戏很流畅', '专业电竞R9000P', '2022-09-22 17:38:15', 5);
INSERT INTO `data` VALUES (12924, '1***7', 5, '到底就是拯救者哈，灯效满满，散热满满，小键盘也是好评，太喜欢了~', '【销量先锋】专业电竞R9000P', '2023-03-15 14:36:42', 9);
INSERT INTO `data` VALUES (12925, 'j***c', 5, '人生的第一台游戏笔记本电脑，找了很长时间，最终选择这款电脑入手，隔天到达，速度很快，现在到手上满满的激动，外观非常帅气，键盘手感也很好，充电器是300w的，贼6，哈哈，后续好用继续评价。', '【销量先锋】专业电竞R9000P', '2023-03-09 18:09:39', 7);
INSERT INTO `data` VALUES (12926, 'j***L', 5, '包装保护：外包装没有明显损伤\n外形外观：奔驰标很帅\n画面品质：165hz刷新率很流畅\n跑分评测：120w+和期待中一样满意\n运行速度：平时不玩3a 普通游戏完美运行\n游戏效果：不卡帧，高刷，', '专业电竞R9000P', '2022-10-21 12:15:30', 5);
INSERT INTO `data` VALUES (12927, 'j***f', 5, '外观材质：外观很漂亮富有科技感，拯救者信仰大Y灯， 大logo灯，背光键盘，屏幕显示效果也很棒。\n电脑性能：电脑gaga快，开机很快，5800H的AMD CPU完全够用。高刷高色域护眼电竞屏，加上多核心处理器。流畅运行各种游戏。\n显卡效果：满血版显卡，功耗大性能强，游戏画面流畅，3060的显卡玩市面上大多数游戏都能驾驭。', '专业电竞R9000P', '2022-10-10 22:00:42', 6);
INSERT INTO `data` VALUES (12928, 'l***e', 5, '包装保护：大包套小包，踏实没毛病\n外形外观：外观真的帅啊！大Y灯YYDS\n画面品质：高分屏，高素质\n运行速度：6800+3060完全够用\n游戏效果：对于只玩联盟的来说够了，偶尔3A也没毛病', '【销量先锋】专业电竞R9000P', '2023-03-15 20:28:16', 4);
INSERT INTO `data` VALUES (12929, '牛***丶', 5, '人生中第一个本子，想着对自己好点，上个好一点的本子，没让我失望，外观很简洁，Y字灯很漂亮很有辨识度，打游戏也嘎嘎香，出厂日期也挺新，总的来说很棒。', '【销量先锋】专业电竞R9000P', '2023-02-23 14:20:12', 7);
INSERT INTO `data` VALUES (12930, 'D***y', 5, '7月25日出厂的，全新未拆封，用了将近一周了，没有别的可以说的！我只能用三个字形容：艺术品！\n平时不用的时候盯着这块2.5k屏发呆，不禁会感叹怎会有如此完美的设计，美感与性能的结合#(滑稽)\nps：买后得了电子YW，买前打游戏，买后刷批站\n包装保护：全新未拆封\n外形外观：不得不说确实漂亮\n画面品质：测试无漏光，无坏点，显示效果好\n跑分评测：看娱乐大师吧\n运行速度：快\n游戏效果：还不错', '专业电竞R9000P', '2022-08-10 20:45:58', 5);
INSERT INTO `data` VALUES (12931, 'h***9', 5, '外观很漂亮，全金属材质，白色背光键盘，雷电/网口接口齐全，USB接口也不少，还带摄像头屏蔽按键，很好', '【销量先锋】专业电竞R9000P', '2023-03-09 16:27:24', 6);
INSERT INTO `data` VALUES (12932, '小***q', 5, '用了几天了，感觉这台电脑很不错，机身外观个人觉得很好看也很耐看，特别喜欢这个小键盘和方向键，开机键的一圈亮光不同颜色对应不同的性能模式，我用平衡模式，日常办公基本没有听到风扇声。在更新系统时风扇会响，不过也还可以接受，没有电流声，屏幕也没有曲面屏。特别推荐做工程类的购买这个，目前这个性价比觉得很可以了。', '轻薄电竞R9000X', '2022-12-01 23:45:45', 6);
INSERT INTO `data` VALUES (12933, 'O***好', 5, '包装保护：很不错\n外形外观：很好看\n画面品质：超级清晰\n跑分评测：115万左右\n运行速度：开机十几秒', '【销量先锋】专业电竞R9000P', '2022-11-14 11:35:27', 6);
INSERT INTO `data` VALUES (12934, 'j***p', 5, '综合考虑选择了这款，没有失望，非常好，性能也很不错，运行流畅，2.5k屏幕色彩很棒，声音效果很好，包装很到位，大Y灯超酷，一线大牌值得拥有，晚上下单，隔天就到，物流很快，百亿补贴性价比超高，冲?', '【销量先锋】专业电竞R9000P', '2023-03-15 21:31:27', 3);
INSERT INTO `data` VALUES (12935, 'w***s', 5, '笔记本非常实用！\n包装保护：保护很到位 外形外观：很好 运行速度：很快 游戏效果：很好 评分检测。\n画面品质：2.5K IPS屏非常清晰\n外形外观：很满意，自己加装了一根1T的固态硬盘，非常方便，里面自带了固定螺丝', '【销量先锋】专业电竞R9000P', '2023-03-11 17:58:13', 5);
INSERT INTO `data` VALUES (12936, '刘***雨', 5, '包装保护：包装完好无损，京东快递非常快。\n外形外观：轻薄简约，质感很好。\n画面品质：10bit。2.5k165hz。清晰流畅。\n运行速度：运行流畅。\n跑分评测：均衡模式独显直连。娱乐大师125w。完美哈。\n游戏效果：画质非常细腻，坦克世界完美运行。6800s显卡功耗90w，3060显卡功耗140w。低功耗高性能。真的强?。', '轻薄电竞R9000X', '2022-11-24 14:18:11', 4);
INSERT INTO `data` VALUES (12937, '思***i', 5, '心心念的电脑终于到货了 使用了一段时间才来评价 体验感十足 性能完全ok 甚至对于我而言有些过剩 选择模式是最最最最爽的 根据使用环境选择性能模式 打游戏的时候即使打开野兽模式声音也不是很大 安静模式真的是一点声音没有！ 重量还好 我感觉没有适配器沉 哈哈哈 屏幕已经很薄了 16比10的屏幕是真爽！！！', '【销量先锋】专业电竞R9000P', '2022-11-14 23:52:41', 6);
INSERT INTO `data` VALUES (12938, 'j***8', 5, '包装保护：快递包装完美\n外形外观：r9kp外形真的爱了，棱角分明，ad好像都是金属\n画面品质：2.5k屏幕，165hz高刷新率，玩游戏不要太爽\n跑分评测：鲁大师接近130w的样子，记得开野兽模式\n运行速度：相当流畅。', '【销量先锋】专业电竞R9000P', '2022-12-25 10:47:46', 5);
INSERT INTO `data` VALUES (12939, 'J***7', 5, '送货很准时，机子也保护的比较好，应该是全新机，目前正在使用，还没玩游戏，希望不会失望！机子仔细看了很多人反应的左下角缝隙的问题，我的没看到，今天仔细看了机器发现背面左下角有一点点划痕，算了，不影响使用，总体感觉机器屏幕很好，声音也不错，反应快，刚好收到货第二天小孩子就停课了拿去上网课，效果杠杠滴！', '轻薄电竞R9000X', '2022-11-09 12:59:16', 6);
INSERT INTO `data` VALUES (12940, 'j***e', 5, '包装保护：包装精美安全可靠\n外形外观：外形漂亮\n画面品质：画质很好\n跑分评测：跑分满意很高\n运行速度：速度特别快\n游戏效果：效果好，就是买来打游戏的。', '【销量先锋】专业电竞R9000P', '2023-03-07 15:40:25', 4);
INSERT INTO `data` VALUES (12941, '咱***砍', 5, '科研利器，有了拯救者跑代码，绘图再也不卡了，独立显卡还是很棒的，16寸的屏幕也足够用了，外观也很好看，金属材质，很有科幻感，总之很香！', '【销量先锋】专业电竞R9000P', '2023-02-22 13:21:59', 5);
INSERT INTO `data` VALUES (12942, 'j***7', 5, '包装保护：保护的非常的不错\n外形外观：非常的好看logo很好看！！还能发光！！\n画面品质：还是很清晰的，很好看\n跑分评测：比同等位英特尔处理器的跑分高。\n运行速度：非常的流畅，很喜欢！\n游戏效果：还没有玩游戏，应该也不错呢！', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-01 16:13:35', 9);
INSERT INTO `data` VALUES (12943, 'j***e', 5, '到手后使用了一段时间，整体使用体验非常号 A面是金属的，2K屏的观感非常棒，5800H的CPU，日常使用体验非常流程，3060的显卡，玩3A也很流程，爱了爱了！', 'R9000P', '2021-04-18 15:52:21', 8);
INSERT INTO `data` VALUES (12944, '杯***人', 5, '?发货很快，两三天就到了，这个颜色我很喜欢，配置很高，非常nice，靓机一枚，玩了几局，FPS就没低过，其他单机游戏还在下载，什么Steam，EA，Uplay通通下起来，不然就浪费了这个配置', '【销量先锋】专业电竞R9000P', '2023-03-10 09:16:44', 7);
INSERT INTO `data` VALUES (12945, 'w***t', 5, '这个游戏本把我惊艳到了，一次完美无语论比的体验，太爱这个本本了，钱掏的值\n包装保护：真棒\n外形外观：完美\n画面品质：超凡\n跑分评测：惊人，超3060\n运行速度：快的像神一样\n游戏效果：棒的呱呱叫', '轻薄电竞R9000X', '2022-12-28 13:12:32', 6);
INSERT INTO `data` VALUES (12946, 'j***H', 5, '包装保护：包装十分妥帖，防震系数高\n外形外观：大气且不易脏，方便，而且不是很重说实话\n画面品质：好，无坏点，客服很有耐心，帮忙解决了很多问题\n跑分评测：可以\n运行速度：快\n游戏效果：感觉还是很流畅的，达到了预期要求', '【销量先锋】专业电竞R9000P', '2022-11-03 15:00:36', 4);
INSERT INTO `data` VALUES (12947, '永***芳', 5, '非常精致的一款产品，处理器和显卡都很强，双十一降价到7499，就让这款产品的性价比更高了，用起来非常的流畅，续航也可以，比轻薄本还要强。', '轻薄电竞R9000X', '2022-11-27 21:22:02', 7);
INSERT INTO `data` VALUES (12948, 'Y***y', 5, '外形外观：全金属面板触感和质感都非常出色\n画面品质：2K屏在rx6800s加持下能应付大部分的需求', '轻薄电竞R9000X', '2022-11-25 21:57:57', 4);
INSERT INTO `data` VALUES (12949, 'j***c', 5, '包装保护：包装很高大尚，有两层的保护，里面有一个袋子装着电脑，然后还有海绵隔着，不怕磕碰\n外形外观：外观很好看的，银色的外观很，键盘用起来也很顺手\n画面品质：完了一下永劫无间，画质也非常好，不卡顿，性能也够用了', '【震撼新品】专业电竞R9000P', '2022-09-16 23:37:24', 5);
INSERT INTO `data` VALUES (12950, 'j***e', 5, '京东真的牛?，凌晨12点付的尾款，中午就送到了。这机器抢到了不容易啊，黄niu太多了。机器质感很好。我的老微星gs60可以下岗了。比gs60重，厚。屏幕是真的爽，我都不想外接显示器了。金属的a面确实舒服。性能还没体验。5800加3060，相信大多数的游戏不开2k都没问题。好了就这么多了，我要打游戏，哈哈', 'R9000P', '2021-04-07 16:57:25', 8);
INSERT INTO `data` VALUES (12951, '桐***X', 5, '外形外观：超级帅 好喜欢\n画面品质：不错 杠杠的\n跑分评测：没有跑过 没那么重要\n运行速度：开机速度超级快\n游戏效果：还没开始打游戏 应该不错吧\n包装保护：有点磕磕碰碰 但是还是保护很好', '专业电竞R9000P', '2022-10-21 22:18:31', 5);
INSERT INTO `data` VALUES (12952, '冯***9', 5, '机器开机速度很快，散热效果也不错，玩起游戏来，一点也不卡顿，等用一段时间后，看看效果怎么样', '【销量先锋】专业电竞R9000P', '2023-03-15 21:58:09', 6);
INSERT INTO `data` VALUES (12953, 'c***r', 5, '非常不错，这款 r9000p 2022 款玩游戏很流畅，对于我这种普通玩家来说已经够用了。fn+q 快捷切换三种模式也很便利。目前我给它配了个 拯救者 135w 氮化镓快充，但是玩大型游戏的话还是建议使用自带的 300w 充电器。 据说马上要新出一款 300w 氮化镓，希望能缩小体积减轻重量。还是很期待的。', '【销量先锋】专业电竞R9000P', '2023-03-07 14:16:25', 6);
INSERT INTO `data` VALUES (12954, 'r***6', 5, '到手时外包装有破损，但是还好里面没事，保护得很好。第一次开机要40多秒，但之后开机都很快，13秒左右。目前跑各种游戏完全无压力，都是最高特效。2.5k显示屏效果很好，沉浸感强，音箱效果也非常不错，加上整体的做工和低噪音的散热，堪称完美。', '轻薄电竞R9000X', '2022-11-14 21:43:30', 2);
INSERT INTO `data` VALUES (12955, 'q***6', 5, '宝贝描述和实物一样样滴，注册登录后运行速度极快。整体外观时尚潮流，轻薄小巧，整体配置较为，黑色版显示屏细节清晰盈亮，对于我 办公商务绰绰有余，黑色版更显高端大气，全尺寸键盘独树一帜，方便我平时出差进行移 动网站优化等需求操作。', '【销量先锋】专业电竞R9000P', '2022-11-11 20:47:05', 1);
INSERT INTO `data` VALUES (12956, '泡***锅', 5, '包装保护：非常好 \n跑分评测：一百三十多万\n运行速度：挺快的\n游戏效果：下了一个QQ飞车，不知道为什么玩不了，窗口模式，不能大屏?然后我就卸了（实在不知道玩什么游戏....）\n外形外观：非常好，画面分辨率高，我直接没验货，让我妈取回来的，安全下车！', '专业电竞R9000P', '2022-11-14 06:59:19', 6);
INSERT INTO `data` VALUES (12957, '西***溅', 5, '画面品质：2.5k屏幕很清晰。16:10屏幕上下边都很窄，视觉效果满分！\n跑分评测：amd。yes！跑分很高。8g显卡搭配高分屏幕很爽！\n游戏效果：游戏效果很好！各种游戏都不卡，但是amd驱动现在有一个bug，设置成独显之后跑分会降低，混合模式效果才是最大化！', '轻薄电竞R9000X', '2022-12-08 20:09:42', 4);
INSERT INTO `data` VALUES (12958, '皮***虎', 5, '只需不到八千元 即可拥有rtx3060 2.直连模式和hdr 2.5k屏幕 配置上很丰富 性能也很好\n本子厚度要远比游匣好很多， 之前买的g15蛮厚的。\n重量没有想象中沉。\n性能稳定 玩xbox 的 xgpu游戏 没问题 ori， forza horizon 都支持hdr模式 ， horizon默认评级配置是超高模式 \n看hdr视频 色彩也很好', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-02-22 08:56:35', 8);
INSERT INTO `data` VALUES (12959, '清***h', 5, '包装保护：无破损\n外形外观：很薄\n画面品质：分辨率很高很清晰\n跑分评测：还行\n运行速度：还可以\n游戏效果：一般', '轻薄电竞R9000X', '2023-01-28 12:58:03', 4);
INSERT INTO `data` VALUES (12960, 'c***a', 5, '首先，这个价位还可以，其次，联想是个老牌子，值得信赖，再者上手质感很好，金属外观，好看，还有，背部的大灯晚上看着不错，另运行游戏也还可以，apex稳定100多帧，最后，屏幕色好', '【销量先锋】专业电竞R9000P', '2022-12-26 11:20:04', 5);
INSERT INTO `data` VALUES (12961, '飞***6', 5, '笔记本质感非常好，屏幕又大又清晰，九十瓦的6800s对标3060，打游戏完全够我用了，古墓丽影最高画质在2.5k分辨率下，有六十多帧。换成windows10系统后完美。', '轻薄电竞R9000X', '2022-11-26 15:25:39', 5);
INSERT INTO `data` VALUES (12962, '晼***儿', 5, '联想拯救者R9000X，高刷电竞，真不错，手感非常舒适，速度很快，还是超薄，在游戏本领域，能承受轻薄本的称号。我最怕重的本本了，但是真心说比之前用的笔记本舒适到那去了，外观颜值\n很漂亮，耐用。', '轻薄电竞R9000X', '2022-12-26 14:30:19', 6);
INSERT INTO `data` VALUES (12963, 'j***b', 5, '外形外观：帅的很！\n画面品质：画质清晰\n运行速度：快\n游戏效果：游戏效果：原神60帧没有任何压力， 3A游戏暂时没有下载。\n自己买的第一台笔记本电脑，使用了一个星期，用来玩玩游戏，做做设计都很不错。而且在管家那里可以人工客服回答电脑上遇到的问题。', '专业电竞R9000P', '2022-10-19 01:41:50', 2);
INSERT INTO `data` VALUES (12964, '倔***肉', 5, '电脑发货很及时到货很快，电脑配置很高，日常办公打游戏速度贼快 很流畅 屏幕尺寸很好 视野很宽广 很不错', '专业电竞R9000P', '2022-11-23 19:53:45', 3);
INSERT INTO `data` VALUES (12965, '叮***妍', 5, '包装保护：实话外包装很简陋，但是都是实用的设计 当电脑拿出来的时候这些都不重要了?\n外形外观：低调大方的外形，很耐看，看视频不以为充电器大小，拿到实物的时候我靠 真的大 跟板砖?一样哈哈哈哈\n画面品质：2看电影玩游戏体验不错\n跑分评测：还没跑\n运行速度：相当的流畅\n游戏效果：开三极致 玩了一天吃鸡 奈斯嚯嚯嚯', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-05-01 20:01:59', 4);
INSERT INTO `data` VALUES (12966, 'j***绵', 5, '非常不错的产品，AD金属面很舒服，超级赞的。包装严实，京东物流好评。16个框框看着舒服，满血的3060赞。充电器是真的大。整体重量比我之前的thinkpad要重。尺寸差不多。我现在就是把它装到我的tp包里。首发买到性价比是真的高。三星内存显存。730的固态。屏幕真舒服比我以前的舒服太多了。', 'R9000P', '2021-04-09 14:53:00', 8);
INSERT INTO `data` VALUES (12967, 'j***h', 5, '包装很结实，两层的，外面有京东的包装金。联想的包装金外有联想密封贴，防止遇到二手机。电脑做工很精致，全金属机身，外观含蓄不张扬，我是买来学习用的，一点儿不违和，很满意！屏幕画质好，亮度高，性能释放强，满意！就是适配器太沉了，没办法，为了性能释放只能忍了！总体很满意，很推荐！', '【销量先锋】专业电竞R9000P', '2023-03-14 13:45:42', 4);
INSERT INTO `data` VALUES (12968, 'w***3', 5, '包装保护：包装没有问题，保护的很到位，纸箱保护没有任何损失，\n快递服务：前一天晚上下单，第二天中午就到了，服务态度也很好，\n外观设计：金属质感很帅气，整体看起来也很高端大气，背面拯救者的logo也很不错\n产品质量：作为21年性价比最高的一款游戏本，搭载了满血版3060显卡，\n用户体验：运行速度很快，基本能带动现在世面上的所有3A大作，平常办公作业也完全是没有问题，2.5k电竞屏加上16：10的比例，玩起来是真的爽，\n买的内存是金士顿，两根8G显存，硬盘是海力士，512G，屏幕是京东方，网卡是intel的，也算是很不错的了', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-22 15:52:39', 9);
INSERT INTO `data` VALUES (12969, 'j***a', 5, '包装保护：包装盒特别好看，而且是我喜欢类型，收到时候满满欢喜。\n外形外观：电脑外观，我连上电脑，大Y亮起来，非常酷，电脑手感很好。\n画面品质：非常清晰，没有一点模糊，特别游戏，用最高画质，那种感觉就是爽。\n运行速度：速度上，搭载今年最新的锐龙处理器和最新的3060显卡，没有半点卡顿。\n游戏效果：游戏体验这个更爽，因为，可以直接调到狂野模式，这个玩起来，真爽。\n所以我选择拯救者笔记本，是对的。', 'R9000P', '2021-06-13 00:03:46', 7);
INSERT INTO `data` VALUES (12970, 'j***f', 5, '包装保护：完好无损\n外形外观：双面金属机身超跑排气管出风口专属可控大Y灯\n画面品质：16寸大屏2.5k超高清分辨率 占比92.3%，硬件级防蓝光+DC调光，减少了屏幕光幕中的有害蓝光\n游戏效果：三模显示切换，支持实时光线追踪，模拟真实光线路径，游戏体验更惊艳', '【震撼新品】专业电竞R9000P', '2022-09-18 16:50:13', 4);
INSERT INTO `data` VALUES (12971, '胖***黝', 5, '包装保护：包装干净整洁，两层包装非常好\n外形外观：外观时尚，很酷，大Y的logo可以开关灯，漂亮\n画面品质：画质清晰2.5K分辨率 完美\n跑分评测：鲁大师测试跑分 轻轻松松150万 厉害?\n运行速度：开机7秒，打开软件的速度合适非常快\n游戏效果：测试了几款大型三A游戏 效果真棒 游戏帧数非常高！', '【震撼新品】专业电竞R9000P', '2022-06-24 10:49:47', 4);
INSERT INTO `data` VALUES (12972, '小***8', 5, '联想拯救者R9000P值得拥有，运行速度快，游戏本的首推，有条件的可以上更高配置，屏幕 音效 运行 系统等都很厉害。', '【销量先锋】专业电竞R9000P', '2023-03-12 13:37:38', 2);
INSERT INTO `data` VALUES (12973, 'j***q', 5, '画面品质：换了新屏幕，真的色泽比之前用了七八年的电脑好太多了\n包装保护：抢到了首发，7999，3060够了\n外形外观：外形很骚气，还有科幻的奔驰logo，还可以控制，有点骚气\n游戏效果：独显的效果真的很棒，无论游戏办公，都足够用了', 'R9000P', '2021-04-19 23:32:06', 8);
INSERT INTO `data` VALUES (12974, '黛***惑', 5, '包装保护：双层包装盒，机器外侧还是有缓冲泡沫架保护。\n外形外观：ACD面金属，框架金属，质感拉满。\n画面品质：屏幕素质很高，显示细腻，色彩不错。\n跑分评测：画图用，specviewperf结果很不错，图一乐。', '轻薄电竞R9000X', '2022-11-14 10:38:17', 4);
INSERT INTO `data` VALUES (12975, 'D***u', 5, '外形外观：质感不错，背面线条挺有设计感的，Y字形大背灯挺酷的\n画面品质：屏幕分辨率很高，画质比前一台电脑好多了，看着很舒服\n运行速度：运行速度很快，打开游戏没有卡顿。PS之类考验配置的软件使用也很流畅\n总体来说不介意电脑重量的话，买这台电脑性价比真的不错', '【销量先锋】专业电竞R9000P', '2023-03-20 16:36:10', 4);
INSERT INTO `data` VALUES (12976, 'Y***t', 5, '机器收到后，马上就开机激活了，系统预装正版WIN11，开机速度7秒左右，散热做的也不错，吃鸡全特效拉满，帧数未定在120左右，好电脑害的选联想啊兄弟们', '【销量先锋】专业电竞R9000P', '2023-01-08 16:39:19', 7);
INSERT INTO `data` VALUES (12977, '守***时', 5, '包装保护：保护很严实，一点都不怕运输受损。\n外形外观：高端大气，金属外壳，看着很舒服，摸起来手感也不错。\n画面品质：画面很清晰，还有多种画质可调节。\n运行速度：运行很快，很流畅，开机快的超乎想象。\n游戏效果：游戏很流畅，画质让人感到身临其境，玩游戏很舒服，很畅快。', '专业电竞R9000P', '2022-10-13 23:18:14', 3);
INSERT INTO `data` VALUES (12978, '孤***人', 5, '外形外观：手感非常好 很喜欢\n画面品质：画面也非常清晰细腻\n运行速度：玩3a无压力\n游戏效果：玩游戏非常好', '【销量先锋】专业电竞R9000P', '2023-03-19 19:20:22', 4);
INSERT INTO `data` VALUES (12979, 'j***g', 5, '第一次买联想拯救者系列，在打开的那一刻真的非常非常惊艳！！！！！\n包装保护：快递小哥很耐心的等我验过外包装后才离开，外包装完美无破损无划痕。\n包装箱质感很好，有很厚重的感觉，对机体的泡沫保护也很有安全感。\n外形外观：从防尘布拿出电脑的那一刻，真的真的很超值啊，外观绝杀！完美达到我画图所需的性能而又不失轻薄！酷酷的黑色又很典雅的感觉，妥妥的西装**！！！\n画面品质：整张屏幕给我带来的感觉很震撼，清晰、色彩饱和度高，追剧必备良品呐简直，第一血必须给黄石第五季！！！\n\n运行速度：运行速度很流畅，很轻盈的感觉，顿感超值的体验！', '轻薄电竞R9000X', '2023-01-04 20:09:25', 6);
INSERT INTO `data` VALUES (12980, 'j***7', 5, '非常好? ikun 必买.性能稳定 输出猛.\n奔驰大标快绝版了，百亿补贴 非常划算.\nAmd锐龙7处理器 加3060显卡 玩3a大作足够了\n大家闭眼入', '【销量先锋】专业电竞R9000P', '2023-03-18 14:39:39', 5);
INSERT INTO `data` VALUES (12981, 'w***刷', 5, '包装保护：赞！\n外形外观：很好！\n画面品质：很高清！\n运行速度：很流程！\n游戏效果：非常好！\n       第一次在网上买电子产品，很好没有翻车。比我想象中的要好很多，很喜欢！', '【销量先锋】专业电竞R9000P', '2023-03-13 17:33:01', 4);
INSERT INTO `data` VALUES (12982, 'G***E', 5, '挺好的笔记本电脑，包装很严实，表面没有划痕，预装正版的Win11系统和Office2021办公套装。这款笔记本电脑做工精致，接口齐全，屏幕是雾面屏，防炫光，2.5 K分辨率，165Hz刷新率，用起来顺滑流畅。处理器是锐龙7-5800H，显卡是RTX3060 6GB显存，16GB 3200Mhz第四代双通道内存，512GB固态硬盘，持续读取速度每秒3000多兆。该配置可以运行目前市面上主流的游戏和办公生产力软件。很满意的一次购物。', '专业电竞R9000P', '2023-03-13 22:07:15', 4);
INSERT INTO `data` VALUES (12983, '小***位', 5, '屏幕很清晰，键盘用起来也很舒服。rx6000s对于我来说够用了，现在遇到的游戏都能玩。续航很好，就是重了点', '轻薄电竞R9000X', '2022-11-17 21:46:18', 6);
INSERT INTO `data` VALUES (12984, 'a***0', 5, '外形外观：型男必备\n画面品质：非常清晰，色彩鲜艳\n跑分评测：1158096\n运行速度：快\n游戏效果：游戏已经玩上，嗖嗖嘚\n包装保护：严实', '专业电竞R9000P', '2022-10-23 16:54:16', 4);
INSERT INTO `data` VALUES (12985, '凹***伤', 5, '包装保护：包装得很好，没有瑕疵情况\n游戏效果：3A大作，运行流畅\n用了也很长一段时间才评价的，这款轻薄工作办公很方便，同样也丝毫不影响下班后的游戏体验。', '轻薄电竞R9000X', '2023-01-15 11:49:18', 5);
INSERT INTO `data` VALUES (12986, '向***洋', 5, '年度最香3060笔记本，全功率输出3060显卡，4bg三星内存，散热优秀，玩游戏爽到爆，拯救者2021年度入门旗舰机，良心配置，能抢到很幸运，退吧战五年。', 'R9000P', '2021-04-12 14:20:38', 8);
INSERT INTO `data` VALUES (12987, 'm***c', 5, '包装保护：保护的非常好，内胆防摔\n外形外观：是我横向比较了几乎所有电竞本后，觉得最漂亮时尚、有质感，大气的造型\n画面品质：屏幕非常清晰，大屏配高刷，很带劲', '轻薄电竞R9000X', '2022-11-28 19:36:02', 4);
INSERT INTO `data` VALUES (12988, '邹***9', 5, '外观真的没得讲，设计师YYDS，玩游戏爽的一批，打开网页很快，总而言之言而总之就是性能外观都是牛的一批！', '【销量先锋】专业电竞R9000P', '2023-03-06 20:40:59', 6);
INSERT INTO `data` VALUES (12989, '枫***雪', 5, '包装保护：非常不错\n外形外观：高端大气上档次\n\n画面品质：非常清晰\n\n跑分评测：非常高\n\n运行速度：非常快\n游戏效果：非常快\n电脑中大大奔，拯救者R9000P\n采用满血版3060处理器，比3050快不少\n16G内存，最大可扩展64G\n外观采用铝合金材质，看起来高端大气上档次\n游戏随便玩，挖矿随便挖', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2021-11-20 19:40:02', 9);
INSERT INTO `data` VALUES (12990, 'h***o', 5, '包装很赞，满满的仪式感，用了十年苹果，跳出来发现win系统也不错，机器也很精致。很不错的购物体验，有这个秒杀的价格，谁还买上代的二手机器去，完美体验，加了六年延保，暂时不准备换机器了。', '轻薄电竞R9000X', '2023-02-26 22:43:32', 5);
INSERT INTO `data` VALUES (12991, 'j***x', 5, '电脑不错哦 轻薄本 打游戏顺畅 最喜欢他的触摸板 是我用过最丝滑的 看视频也非常清晰', '轻薄电竞R9000X', '2023-01-07 11:10:00', 3);
INSERT INTO `data` VALUES (12992, '鳄***-', 5, '1、物流特别给力 两天就到了 颜色特别好看 颜值超级给力 然后就是手感 磨砂质感 估计不沾灰 屏幕一级棒 特别是那个 90屏占率 瑞龙5 小游戏偶尔玩一下完全没问题 csgo无压力 办公用途完美无任何压力 十分流畅 预装了win10系统 上手概10分钟就可以开始使用 十分方便 这款商务用途绝对是首选\n\n2、因为装的东西不多，十几秒就开机了，电池续航时间约只有3小时就自动关机了。用鲁师检测领先全国11%的用户。总共就开机几次，时间很短，目前没发现什么异常，因为本人不玩游戏，不知道玩游戏的情况会怎样，只是办公用估计没问题吧，如果以后有什么再追评。先好评\n\n3、电脑很好用，外观气小清新！操控性能也很好！电脑整体看起来很精致，键盘看着也超级舒服，朋友都说我会买东西，说我有眼光！比官方旗舰店实惠，价格也有优势！就是自己是电脑**，很多小问题不会操作，客服这边也很耐心！愉快的一次购物体验！给店家一百个赞！忽略**手机的像素\n\n4、看了好久的电脑，很喜欢粉色，终于让我找到了，然后就立马下了单，为了等这个电脑，真是日思夜想，都等的失眠了收到之后耳机也是粉嫩粉嫩的，真是少女心泛滥了，然后刚开始不知道怎么', '轻薄电竞R9000X', '2022-12-21 09:07:11', 3);
INSERT INTO `data` VALUES (12993, '一***c', 5, '包装保护：收到的时候外包装有一个小小的口子，但是内里完好无损，里面还有海绵保护层，很用心了\n画面品质：画面非常清晰，视觉得到很大的满足\n运行速度：运行速度也很nice呀，一点也不卡顿，用起来非一般的感觉，太开心了\n外形外观：外观真的有点炫酷的，买之前还担心会不会看上去特别笨重，但是结合科技的外观，看上去精致了很多', '【销量先锋】专业电竞R9000P', '2022-11-22 10:30:55', 4);
INSERT INTO `data` VALUES (12994, 'u***8', 5, '专业电竞R9000P，标压R7...包装保护：包装很给力，包的很严实，有泡沫保护着，很赞\n外形外观：做工很精细，外观还是很漂亮的，\n画面品质：画面清晰，色彩丰富，整体很可以\n运行速度：开机速度快，打游戏运行起来很流畅，\n游戏效果：游戏页面看着很清晰，色彩鲜艳，运行起来\n没有卡顿的现象\n这次选购还是很喜欢的，大件都在京东买，物流也非常的快', '【销量先锋】专业电竞R9000P', '2023-03-13 14:03:06', 4);
INSERT INTO `data` VALUES (12995, 'u***e', 5, '1买过最贵的电脑买完有点心疼钱hhhh。\n\n2性能释放和散热都很优秀，A系新款。\n\n3质感良好，重量适中。\n\n4屏幕很舒服，自带色彩管理。\n\n5外观很商务，整体也蛮心动，颜值控大爱。\n\n6再想想\n\n7带独显的轻薄游戏本，因为看模型+打游戏需要独显，独显对工科三维结构模型的渲染速度提高很多。', '轻薄电竞R9000X', '2022-11-12 14:10:50', 4);
INSERT INTO `data` VALUES (12996, '洋***爱', 5, '性能释放非常棒，做工细节完美，感觉很完美，这就是我想要的笔记本，9000 系列比 7000 系列有更好的散热和做工细节,如果你不是那么在乎性能，而是想要一个好屏幕，好散热的游戏本，3060 版本的 R9000P 将会是值得考虑的选择。', 'R9000P', '2021-04-07 23:27:23', 8);
INSERT INTO `data` VALUES (12997, '黄***-', 5, '非常好，很漂亮，老弟很喜欢，响应速度，外观，性能都很不错，除了是板载内存，硬盘不能自己加外，都挺不错的，但这两个缺点是真的隔应，后续看看质量吧', '轻薄电竞R9000X', '2023-01-18 11:13:39', 4);
INSERT INTO `data` VALUES (12998, 'L***光', 5, '超值&rdquo;游戏利器&mdash;&mdash;搭载AMD锐龙7 5800H以及RTX 3060显卡、16GB双通道内存、512GB SSD，拥有2.5K分辨率、165Hz刷新率16英寸屏幕的联想拯救者R9000P外观简约干练，硬朗冷酷\n\n　　联想拯救者R9000P的外观有浓厚的家族基因&mdash;&mdash;简约干练，却透露着硬朗冷酷的味道。\n\nA面中间为可控&ldquo;Y&rdquo;灯，很有辨识度。两侧对称的腰线增加了A面的层次感。此外，该机A面与D面均为金属材质，细腻的表面手感和质感都让人印象深刻，可以说一上手就能感受到扎实的做工。\n当然超高屏占比还可以提升视觉代入感，不过联想拯救者R9000P屏幕的优点还不止于此。这块16英寸屏幕拥有2560X1600高分辨率、165Hz高刷新率、100%sRGB高色域、3ms个高速响应时间、G-Sync与FreeSync双料防撕裂等特性，可以带来更细腻、逼真且顺畅的游戏画面。', 'R9000P/RTX3060/R7/165Hz 2.5k屏', '2021-09-22 10:21:38', 9);
INSERT INTO `data` VALUES (12999, 'w***G', 5, '包装保护：外面一个京东快递的包装，里面是联想的包装，保护的很好，产品毫发无损\n跑分评测：挺好的，120多万的跑分\n运行速度：很快，一点不卡\n外形外观：很好看的外观设计，尤其那个大Y灯真的好看\n游戏效果：还没试\n画面品质：挺好的，我感觉', '【销量先锋】专业电竞R9000P', '2022-11-04 18:16:34', 4);
INSERT INTO `data` VALUES (13000, '天***影', 5, '外形外观：精致简洁轻薄电竞感金属感强。\n包装保护：无损保护完好\n画面品质：2.5k很细腻很色彩\n跑分评测：核显都能跑92万多分\n运行速度：很快秒开\n游戏效果：主流游戏都流畅\n此型号联想笔记本电脑性价比高，外观好看便携，amd6800的续航强，游戏核显独显都很强，强力推荐。', '轻薄电竞R9000X', '2023-01-27 20:02:30', 4);
INSERT INTO `data` VALUES (13001, 'j***E', 5, '提高生产力，就得靠它了，爱不释手，妈妈送的新年礼物，我太爱了，每天用它听网课，做笔记。心情美美哒。各种美图天天都在朋友圈里秀。真的老铁，用一件趁手的兵器,武功都会变高呢！', '【销量先锋】专业电竞R9000P', '2023-01-22 18:53:55', 4);
INSERT INTO `data` VALUES (13002, 'j***w', 5, '包装仔细，没有破损，京东快递送货上门，16英寸超高屏，专属可控大Y灯，4出风口强大散热，超跑排气管出风设计，原感键盘，便携快充大容量电池，告别续航焦虑，推荐购买', '【震撼新品】专业电竞R9000P', '2022-07-20 20:14:55', 5);
INSERT INTO `data` VALUES (13003, 'j***2', 5, '一直都在用联想的电脑，这是第二款拯救者，质量都很好。\n包装:很精致\n画面:玩游戏，看电影，办公都能完美匹配。\n跑分:120+万，还可以\n运行速度:非常棒\n系统:W11系统用着不太习惯', '轻薄电竞R9000X', '2023-01-17 08:28:52', 4);
INSERT INTO `data` VALUES (13004, '张***国', 5, '包装保护：很好完美包装\n外形外观：漂亮炫酷十足\n画面品质：清新脱俗\n跑分评测：刚刚的，可以\n运行速度：非常快。激情澎湃', '【销量先锋】专业电竞R9000P', '2023-01-18 14:41:17', 5);
INSERT INTO `data` VALUES (13005, 'j***g', 5, '外形外观：做工简洁，机器质感优秀，手感很好，AD金属面非常上档次！！\n画面品质：这块屏幕就是彻彻底底的加分项，效果太好了！细腻清晰，颜色也好！！\n跑分评测：跑分也是一众同等配置机型中的佼佼者，数一数二的性能发挥！！！\n运行速度：速度很快很流畅！！！\n\n买之前也对此了很多竞品机型，有机械的钛钽plus，微星GP76，最终选择了R9000p，非常满意！！！', 'R9000P', '2021-04-08 14:20:07', 8);
INSERT INTO `data` VALUES (13006, 'j***z', 5, '包装保护：非常好\n外形外观：包装完好，快递也很快，机子用着也很快很流畅，以前需要装半天的软件很快就装好了，下载和传输速率也很快。游戏还没有玩，等到时候来追评谈感受。\n画面品质：2k屏的感觉确实很棒', '【销量先锋】专业电竞R9000P', '2022-12-10 11:05:46', 6);
INSERT INTO `data` VALUES (13007, 'j***U', 3, '打游戏也可以说是非常不错了', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2021-11-07 21:15:25', 9);
INSERT INTO `data` VALUES (13008, '旺***呀', 5, '外观：设计新颖，好看\n系统：系统流畅，反应迅速，指纹识别很快\n画面：特别特别清晰\n运行速度：超级快\n包装：很密实', '轻薄电竞R9000X', '2023-02-09 13:22:43', 4);
INSERT INTO `data` VALUES (13009, 'j***o', 5, '包装很好，有京东快递的盒子，盒子没有破损，内部电脑箱子上有联想的封条，都是没有破损的全新机器，快递很快，次日达，电脑真是惊艳到我了，很薄全金属机身，双A平台的贴纸在B面上俨然这台机器就是一台&ldquo;西装**&rdquo;啊。R7-6800H处理器真的性能很高，我这台配的是6600S的显卡，对标RTX3060，暴打3050的一块卡啊，我相信A卡战未来！所以一定要支持AMD。用了这么久也没有什么问题，价格也很合理，AMD品质联想品质点个赞！', '轻薄电竞R9000X', '2023-02-09 10:50:55', 6);
INSERT INTO `data` VALUES (13010, 'w***9', 5, '这款笔记本拯救者r9000p运行速度非常快，很清晰，颜色绚丽，收到拆开箱子就非常喜欢，看着就高大尚，键盘手感也很棒，非常顺畅。', '专业电竞R9000P', '2022-10-18 22:20:03', 5);
INSERT INTO `data` VALUES (13011, 'j***y', 5, '电脑很好用，模拟器多开玩手游岗岗的一点不卡，系统很好，很纯净，满意的一次购物。以后就看耐用性了', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-25 13:41:55', 6);
INSERT INTO `data` VALUES (13012, '袅***y', 5, '好看，很炫酷听歌真的很好听，音效像耳机\n包装保护：很完整，最外面的纸盒也保护的很好\n外形外观：就很炫酷，冰冰凉凉的全金属机身\n画面品质：永远滴神，打游戏巨清晰\n跑分评测：不知道，挺好的吧，我不太懂\n运行速度：不知道\n游戏效果：超赞，非常好', '【销量先锋】专业电竞R9000P', '2022-11-07 17:51:24', 4);
INSERT INTO `data` VALUES (13013, 's***n', 5, 'A面低调，屏幕很好，够大够亮。最主要的是大电池，就算是我用不上，也喜欢大数字。', '轻薄电竞R9000X', '2022-12-26 11:55:05', 3);
INSERT INTO `data` VALUES (13014, 'j***e', 5, '包装保护：用了两层包装盒很结实，收到货盒子没有破损情况！\n外形外观：电脑很美观，有质感，科技感很足\n画面品质：画面很清晰，4K播放很完美\n运行速度：处理速度很快，开机也快，下载需要的软件后开机只要7秒', '【销量先锋】专业电竞R9000P', '2022-11-16 12:49:14', 5);
INSERT INTO `data` VALUES (13015, 'j***v', 5, '电脑很棒，外壳很有质感，键盘也不错，屏幕细腻，运行速度更是没得说！能用好多年了，总体来说非常满意！', '【销量先锋】专业电竞R9000P', '2022-11-11 20:25:14', 5);
INSERT INTO `data` VALUES (13016, '北***宝', 5, '头天下单第二天上午送到，还是一如既往的快捷给力！\n这款电脑造型充满机械感，见棱见角，典型直男风格。\n开机速度很快，对得起在CPU上花的大洋。\n键盘、屏幕、外壳做工精良。\n电脑本身重量在接受范围之内。\n不错的电脑。', '【销量先锋】专业电竞R9000P', '2023-03-15 21:12:12', 4);
INSERT INTO `data` VALUES (13017, '马***胜', 5, '本本做工不错，金属质感很强，屏幕开阔，看电影音效满足学生党。宿舍打游戏超频空间挺大，秒开机，迅速抵达战场。同学看了都说好。', '轻薄电竞R9000X', '2023-02-28 12:58:22', 6);
INSERT INTO `data` VALUES (13018, '东***东', 5, '双十二之前活动价买的，基本是这个价位最高的性价比了，屏幕素质很好，机器全新，没有坏点，娱乐大师跑分133万分，机身三面金属，质感很好，接口少的问题可以几十块钱买个扩展坞解决，除了板载内存外没有明显的缺点了，现在有刚性需求的小伙伴们可以无脑入，双A配置也可以起飞！！！', '轻薄电竞R9000X', '2022-12-14 22:24:44', 7);
INSERT INTO `data` VALUES (13019, '赫***启', 5, '包装保护：非常棒，纸壳厚度防止磕碰，笔记本的外观非常时尚漂亮，画质清晰分辨率高，正好淘汰自己用的本也换个好的感觉一下，显卡性能还是很强悍的，运行速度没得说，不太会玩游戏显卡没问题够自己用，联想LoGo也很漂亮，非常满意', '专业电竞R9000P', '2022-09-17 13:29:42', 5);
INSERT INTO `data` VALUES (13020, 'u***l', 5, '刚收到电脑，开箱检验一下，没有磕破，完美！配置高，开游戏全开，流畅，太给力了！值得推荐', '【销量先锋】专业电竞R9000P', '2023-03-13 19:21:11', 5);
INSERT INTO `data` VALUES (13021, '小***c', 5, '包装保护：京东物流没的说，下单的第二天就送到了。包装很严实，好评！\n外形外观：R9000P的外观最经典，A面的Y形灯点亮非常好看且有质感。\n运行速度：运行速度真的是杠杠的，锐龙7系处理器真的很强！搭配RTX显卡一起，网游和大型3A单机游戏运行起来也是毫无压力！\n画面品质：2.5k分辨率的屏幕无需多言，冲就完事了！', '专业电竞R9000P', '2023-02-02 18:51:54', 4);
INSERT INTO `data` VALUES (13022, '哈***清', 5, '外形外观：非常满意，金属外壳，很有质感\n跑分评测：跑分120w\n\n画面品质：画质也很清晰\n运行速度：运行也很快', '轻薄电竞R9000X', '2023-02-08 20:58:22', 4);
INSERT INTO `data` VALUES (13023, '角***湛', 5, '外观：很商务，很有范儿\n性能：满足个人的所有需求，运行速度也很不错\n屏幕：2.5k，高刷新率，高色域，显示效果很好很好', '轻薄电竞R9000X', '2023-02-10 22:34:22', 4);
INSERT INTO `data` VALUES (13024, '王***8', 5, '非常喜欢这款拯救者r7000p 性能爆炸颜值超高\n外形外观：外形时尚美观\n画面品质：高清份倍率高刷新率\n游戏效果：世面游戏随便玩\n包装保护：包装非常好没有磕碰\n运行速度：开机速度非常快也就几秒', '专业电竞R9000P', '2022-08-13 11:45:28', 4);
INSERT INTO `data` VALUES (13025, '影***夏', 5, '第二天游戏本就收到了 京东就是快。质量很不错 喜欢双面的金属设计 摸上去手感很好 键盘按起来也很棒 运行操作很流畅 屏幕显示很清晰 分辨率很高 看起来舒服 总体很不错', '【销量先锋】专业电竞R9000P', '2023-03-10 15:07:22', 4);
INSERT INTO `data` VALUES (13026, 'j***W', 5, '性能满足要求，时隔多年之后重回A卡阵营，双A平台功耗低，待机时间长，R9000X是一台日常办公和游戏都能兼顾的笔电，轻度游戏还是很不错的，重量控制的很好。配合固态的移动硬盘512G的存储也没什么问题。', '轻薄电竞R9000X', '2023-03-02 08:36:41', 5);
INSERT INTO `data` VALUES (13027, '我***5', 5, '外甥读大学了，送给外甥的礼物，他很喜欢，配置OK，外观也非常大气，性能OK，绝对够用了，用来画图，平常游戏也杠杠的', '专业电竞R9000P', '2022-08-28 20:07:03', 2);
INSERT INTO `data` VALUES (13028, 'M***8', 5, '收到笔记本半个月了，使用感受很好，开机速度非常快，运行速度也很快，散热非常棒，日常都用不到野兽模式，静音模式办公足以！机器包装的很仔细，是全新的机器，7月25日生产的，硬盘和内存都是三星的，品控也很到位，是非常满意的一次购物！', '轻薄电竞R9000X', '2022-11-14 15:18:27', 4);
INSERT INTO `data` VALUES (13029, '零***c', 5, '包装保护：包装的很好，两层材质包装，防止破损；\n外形外观：简约大气，16寸的屏幕看着舒服，不累眼睛?；\n画面品质：画质清晰，2.5K的屏幕；\n跑分评测：还没有跑分，应该很高。\n运行速度：速度流畅；\n游戏效果：还没开始玩游戏。', '【销量先锋】专业电竞R9000P', '2022-11-16 17:08:17', 3);
INSERT INTO `data` VALUES (13030, 'j***m', 5, '外观非常棒，大标很张扬很喜欢，手感很棒，冷天不冻手，性能也超强！总之非常喜欢！就挺棒！很满意', 'R9000P', '2021-04-09 12:18:44', 7);
INSERT INTO `data` VALUES (13031, '夏***6', 5, '入手十几天了，整体使用起来也可以，古墓丽影开全特效也能流畅玩儿。很不错', '轻薄电竞R9000X', '2022-12-26 11:57:48', 4);
INSERT INTO `data` VALUES (13032, '小***爸', 5, '包装保护：很有仪式感的包装很喜欢\n外形外观：93%的屏占比看着很爽\n画面品质：色彩还不错\n运行速度：还挺流畅的', '轻薄电竞R9000X', '2022-11-16 12:15:46', 1);
INSERT INTO `data` VALUES (13033, '贺***璋', 5, '包装保护：外表无破损,非常好\n外形外观：很好看\n画面品质：还可以\n跑分评测：跑分的非常给力,居然能跑到12万分以上\n运行速度：运行速度非常快,超出了我的想象,直接爱了\n游戏效果：非常流畅非常好,无压力畅玩各种3A大作', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2021-11-03 01:55:46', 9);
INSERT INTO `data` VALUES (13034, 'j***6', 5, '这质感太好了，全金属就是感觉好看一点，我这台9月份产的，品控感觉挺好的，没有任何瑕疵，第一次用大屏感觉好大，2.5k16:10还不错，用着非常舒服。', '轻薄电竞R9000X', '2023-01-10 10:37:30', 6);
INSERT INTO `data` VALUES (13035, 'j***z', 5, '包装保护：全方位保护\n画面品质：高清色彩逼真\n运行速度：秒开当天下单下午\n游戏效果：效果拉满\n\n物流很快，晚上下单，第二天中午就到', '【销量先锋】专业电竞R9000P', '2023-03-08 18:19:25', 2);
INSERT INTO `data` VALUES (13036, 'w***3', 5, '包装保护：包装很完美。保护的也很好，有两层保护\n外形外观：没有破损之类的问题\n画面品质：2.5k还行，就是可能还没习惯。\n跑分评测：115左右，挺好的！\n运行速度：开机很快，打开软件速度也很快\n游戏效果：终于可以完美的完apex了，小针一扎，不是白给就是', '专业电竞R9000P', '2022-09-11 20:45:12', 3);
INSERT INTO `data` VALUES (13037, 'l***6', 5, '画面品质：画质超级棒，清晰，细腻，色彩靓丽。看世界杯享受。\n外观也够吸引眼球。\n配置更是相当可以，运行绘图软件顺畅。', '【销量先锋】专业电竞R9000P', '2022-11-27 17:04:04', 4);
INSERT INTO `data` VALUES (13038, 'j***u', 5, '电脑收到了，安全下车，我这电脑买转了，三星的固态，华星屏幕，物流也很快哟，晚上下单，第二天下午就到了，\n运行速度：运行速度非常快，想要入手，电脑的铁子剁手剁手快剁手。', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-03-05 20:36:09', 6);
INSERT INTO `data` VALUES (13039, 't***贝', 5, '非常好电脑性能：非常好快递收到了，感谢店家；电脑收到了，用了几天感觉很好用，内存很大，屏幕清晰， CPU 运行顺畅，值得拥有，推荐给大家更显高端大气，全尺寸键盘独树一帜，方便我出差进行移动网站优化等需求操作。', '【销量先锋】专业电竞R9000P', '2023-01-22 18:59:43', 4);
INSERT INTO `data` VALUES (13040, '-***1', 5, '电脑很好，开机速度很快，值得入手，现在购买性价比很高，真是一台非常不错的电脑，推荐大家入手。\n外形外观：非常酷炫\n画面品质：高清，看视频很好', '【销量先锋】专业电竞R9000P', '2023-03-14 22:12:11', 4);
INSERT INTO `data` VALUES (13041, '山***i', 5, '用了有半个月了，感觉非常棒。笔记本整体外观时尚潮流，轻薄小巧，方便携带，整体配置较为不错，显示屏细节清晰盈亮，对于我办公商务绰绰有余，银色版更显高端大气，全尺寸键盘独树一帜，方便我平时出差进行移动网站优化等需求操作。', '轻薄电竞R9000X', '2022-11-21 11:04:45', 4);
INSERT INTO `data` VALUES (13042, 'j***Z', 5, '包装保护：包装很严实，防伪贴还在，跳联网后安全下车，不过好像是四等奖=.=\n跑分评测：鲁大师两次都是118w分\n\n运行速度：玩了原神，画质不错', '【销量先锋】专业电竞R9000P', '2022-11-02 23:57:26', 6);
INSERT INTO `data` VALUES (13043, 'T***J', 5, '今年的新一代神机！7999运气好抢到了！配置可以说是完美了！2k屏幕出厂带校色软件，颜色比2020款的r7000p好看很多！500尼特高亮度！完美屏！5800+3060   面对目前主流游戏都没什么问题！经典版鲁大师跑分近60w！玩地平线4最高特效2k分辨率，平均126帧也是棒棒哒！', 'R9000P', '2021-04-09 21:49:58', 8);
INSERT INTO `data` VALUES (13044, '泣***情', 5, '比预期的要好好多，本来就是一眼看中，实体更是漂亮的没话说，还有散热器软件运行流畅，屏幕清晰，而且手感很不错，电池也耐用，机身很薄没有笨重感反正是很值得入手的一款。客服还是非常不错的，耐心解答，完美！', '轻薄电竞R9000X', '2023-01-20 22:32:25', 4);
INSERT INTO `data` VALUES (13045, '9***贝', 5, '心心念的电脑终于买到啦，拿到第一感觉特别棒，比之前的电脑质感好太多，检查了键盘，屏幕，散热都很完美，6800h加6800s完美搭配，不管是工作还是适度游戏都完美胜任，是我心目中的那台电脑～从发布就一直关注，过年了终于换上了新电脑，整理心情快乐出发！！！', '轻薄电竞R9000X', '2023-01-24 12:21:31', 5);
INSERT INTO `data` VALUES (13046, 'j***d', 5, '给小孩上大学用的，外包装有一点受损 好在机器完好无损，这款性能还是很好的 品控非常优秀', '【震撼新品】专业电竞R9000P', '2022-08-17 12:19:26', 4);
INSERT INTO `data` VALUES (13047, 'S***8', 5, '媳妇平时做点小设计，剪辑下视频，做做平面图之类的，没想买游戏本，出于有点私信，左挑右选，选择了联想拯救者R9000，各项配置完全够用，游戏很流畅，开启野兽那是杠杠的！外观大气，大Y标超级显眼，R7-6800H/RTX3060运行流畅，画质完美，游戏效果棒！京东物流依旧给力，外包装无破损，机器完美！', '【销量先锋】专业电竞R9000P', '2023-03-17 16:24:35', 3);
INSERT INTO `data` VALUES (13048, 'j***f', 5, '朋友推荐买的，收到货很喜欢，尤其是外面的大Logo，特意用了一段时间来评价的，无论是玩游戏，还是刷剧一点都不卡顿，而且它是2.5k的屏，看起来特别清晰，总之一句话，挺喜欢，个人还是比较推荐这一款', '专业电竞R9000P', '2022-08-22 10:16:32', 5);
INSERT INTO `data` VALUES (13049, 'j***n', 5, '包装保护：包装紧密严实，盒子整体设计简洁区明\n外形外观：模具整体设计和谐流畅，金属机身更显高端大气，键盘、标志灯光明亮素实\n\n画面品质：2·5k分辨率搭配15.6寸屏幕尺寸完美比例，极致清晰，高色域覆盖明媚鲜艳\n运行速度：秒开应用，游戏加载不超十秒，无需等待立即享受\n游戏效果：针对性优化，比同价位电脑性能更上一层楼，光线追踪技术真实', '专业电竞R9000P', '2022-06-12 14:11:11', 4);
INSERT INTO `data` VALUES (13050, '千***防', 5, '外形外观：外形漂亮质感很好，大小合适，金属表面，灯的颜色可调，背光键盘细节好评\n画面品质：屏幕细腻显示舒服非常好，2k分辨率看电影不错\n跑分评测：跑分中上满足日常需求，性能强劲，水桶机，办公娱乐都能满足，性能释放好\n包装保护：两层包装保护到位，完美无磕碰', 'R9000P', '2021-04-12 14:39:49', 6);
INSERT INTO `data` VALUES (13051, 'j***P', 5, '包装保护：有些破损，但总体不影响\n外形外观：很好\n画面品质：没有瑕疵很不错\n跑分评测：CPU烤鸡没有掉线的\n运行速度：很棒\n游戏效果：不错不错', '专业电竞R9000P', '2022-08-20 17:41:03', 4);
INSERT INTO `data` VALUES (13052, '烟***斯', 5, '包装保护：还是挺严实的\n外形外观：真的很帅，全金属\n画面品质：很强\n跑分评测：挺高\n运行速度：非常快\n游戏效果：3A大作稍微有点卡', '轻薄电竞R9000X', '2022-12-28 16:59:04', 3);
INSERT INTO `data` VALUES (13053, 's***g', 5, '外观全金属感觉非常不错，用起来挺好的，win11还需要适应下，暂时用途主要是办公，游戏体验后续更新', '轻薄电竞R9000X', '2022-11-16 20:15:25', 6);
INSERT INTO `data` VALUES (13054, '迦***开', 5, '笔记本包装的很好，京东送货很快，外形是金属质地，我很喜欢，AMD的CPU挺好的，屏幕够大，笔记本有一定的分量，总体来说还不错吧', '轻薄电竞R9000X', '2022-12-28 08:47:58', 4);
INSERT INTO `data` VALUES (13055, 'j***d', 5, '打算买了回家过年上午买下午到论速度还是很快的！！\n检查一下午确实没什么问题自营店的品控还是可以的！还有2k玩游戏太清楚了比我1080p主机清晰太多了！\n画面品质：强的', '【销量先锋】专业电竞R9000P', '2023-01-01 21:57:58', 7);
INSERT INTO `data` VALUES (13056, 'u***l', 5, '续航能力强，比较有质感，运行速度满意，性价比比较高，有朋友万需要会推荐该本本的。\n\n电脑非常流畅，性价比很高。客服飞飞也很热心，凌晨都还在，回答问题特别耐心\n\n很酷的笔记本哦。鼠标触屏特别灵敏，运行流畅，英雄联盟无延迟，屏幕看起来很舒服尺寸合适用，\n\n外观材质：特别好看，虽然是游戏本但是一点不笨拙 电脑性能：吃鸡没问题 运行特别流畅\n\n发货很快，电脑轻薄，系统速度很快，用着不错。感谢客服高达提供的耐心服务', '16G内存 512G固态 标配版', '2023-03-09 17:23:56', 8);
INSERT INTO `data` VALUES (13057, 'j***t', 5, '画面品质：超清，亮丽，色彩很美\n跑分评测：103W?\n游戏效果：流畅 舒适 享受\n运行速度：快 开机只需6秒\n包装保护：非常好 没有破损\n外形外观：非常完美', '16G内存 1TB固态 升级版', '2023-03-03 23:19:52', 7);
INSERT INTO `data` VALUES (13058, 'j***i', 5, '显卡效果非常棒！对于打游戏的人来说，太香了！物流也快，没几天就到了，服务态度也很好！画质高清，看起来很舒服，没有卡顿，完美！物流速度很快，东西收到特别满意，机身颇有设计感，满满的高级感很喜欢，运行也不错，客服人员也特别好回应很快，总而言之，产品很好，这台拯救者电脑真的外观非常漂亮！质感也很好！买来做设计的，配置也够高！开机速度也很快！最主要是太拉风了 外观材质：外观属实惊艳到我 特别酷帅到炸 电脑性能：电脑开机很快  我专业是数字媒体。', '16G内存 512G固态 标配版', '2022-10-21 09:36:43', 8);
INSERT INTO `data` VALUES (13059, 'c***曦', 5, '联想拯救者r7000 真的很不错，独立直显，打游戏非常通畅，一点都不会卡頓，真的很棒，开机不到8秒，双十一期间不到六千块，真的很实惠，物有所值，键盘自带光线，还会赠送鼠标，鼠标垫，清洁刷，背包，体积不重，续航很棒，堪称\n3050 天花板', '16G内存 512G固态 标配版', '2022-11-12 18:42:50', 7);
INSERT INTO `data` VALUES (13060, 'j***i', 5, '包装保护：两层纸箱，中间还有厚厚的海绵，保护的很好。\n外形外观：外观简洁大方，适合年轻人用。\n画面品质：画面清晰，没有问题\n运行速度：速度超快，开机几秒钟。\n游戏效果：非常流畅，适合游戏。\n跑分评测：分数挺高的，感觉挺好。。', '16G内存 512G固态 标配版', '2023-02-26 09:58:44', 5);
INSERT INTO `data` VALUES (13061, 'd***2', 5, '包装保护：包装很好，完好无破损，两层纸箱\n外形外观：中规中矩的设计，工业感很强\n画面品质：非常细腻的画面，屏幕分辨率很高\n跑分评测：没有亲子测试，看了网上测评，物有所值\n运行速度：目前开机10秒以内，反应迅速\n游戏效果：主要用来处理图形软件，满足需求', '32G内存 512G固态 升级版', '2023-02-15 16:07:58', 9);
INSERT INTO `data` VALUES (13062, 'j***l', 5, '电脑外观是我喜欢的类型，键盘背光可调节，A面小奔驰标可调节。显卡满血达到了95W。鲁大师跑分100W+，目前开箱试用感觉很流畅，反应迅速，还额外赠送了鼠标和鼠标垫，好评！', '16G内存 512G固态 标配版', '2022-10-21 21:51:45', 7);
INSERT INTO `data` VALUES (13063, 'j***3', 5, '买来看剧，追剧真不错，独立显卡，运行速度也很快，外观比较高级，包装也很精致，还赠送了鼠标和鼠标垫，键盘很炫酷，屏幕15.6英寸刚刚好，看剧打游戏都很奈斯', '16G内存 512G固态 标配版', '2023-02-13 22:40:14', 6);
