INSERT INTO `data` VALUES (13065, 'j***m', 5, '外观好看漂亮\n性能特别流畅，玩游戏不卡，比如CF， 等大型\n游戏，玩起来不卡顿，\n键盘手感也很舒适，电池容量也很大，使用时间\n超长。屏幕大，追剧很爽。', '16G内存 512G固态 标配版', '2023-02-16 12:05:49', 5);
