INSERT INTO `data` VALUES (13074, 'j***e', 5, '包装保护：非常满意的一次购物体验，包装很严密，很严格\n外形外观：外形外观美丽大方，高贵典雅，质量不错，高贵黑，黑色给人一种高级的感觉，提升了一个档次\n画面品质：60hz高清画质，超轻刷新率，非常满意，看电影非常舒服，非常满意\n跑分评测：amd处理器跑分非常高，好几十万的评分，电脑秒开机，打起游戏来非常快，非常迅速，很舒服。\n运行速度：速度也是很快，软件点一下就可以打开，秒开软件，加载速度也是很快，非常厉害的感觉\n游戏效果：打起游戏来非常厉害，非常厉害，非常迅速，非常舒服', '16G内存 512G固态 标配版', '2022-11-20 10:21:16', 5);
INSERT INTO `data` VALUES (13075, 'u***a', 5, '开机很快，性能非常不错，打一般游戏很流畅，屏幕效果很不错。键盘打字非常舒服，还赠送双肩包携带更方便，续航能力强，比较有质感，运行速度满意，性价比比较高，有朋友需要会推荐该本本的。', '16G内存 512G固态 标配版', '2023-02-21 17:33:00', 5);
INSERT INTO `data` VALUES (13076, 'j***s', 5, '包装保护：包装的很好，没有划痕\n外形外观：外形也是非常的美观、大气\n画面品质：画面也不错呀我直接上图\n跑分评测：完全OK的\n运行速度：废话不多说直接上图\n游戏效果：同上直接上图效果不错的', '16G内存 512G固态 标配版', '2022-10-17 16:22:20', 5);
INSERT INTO `data` VALUES (13077, 'j***h', 5, '包装挺严实的，完好无损。外观很好看，看上去很高贵时尚。电脑很不错，开机很快，打游戏完全没有卡顿出现，很满意的一次购物。', '16G内存 512G固态 标配版', '2023-01-30 11:36:26', 6);
INSERT INTO `data` VALUES (13078, 'j***u', 5, 'LEGION\n联想拯救者R7000 p图设计师电\n只\n竞游戏笔记本电脑y RTX3050独..\n显卡效果非常棒!对于打游戏的人来说，太香了!物流也快，没几天就到了，服务态度也很好!画质高清，看起来很舒服，没有卡顿，完美!物流速度很快，东西收到特别满意，机身颇有设计感，满满的高级感很喜欢，运行也不错，客服人员也特别好回应很快，总而言之，产品很好，这台拯救者电脑真的外观非常漂亮!质感也很好!买来做设计的，配置也够高!开机速度也很快!', '32G内存 1TB固态 升级版', '2023-02-06 19:05:01', 5);
INSERT INTO `data` VALUES (13079, 'j***u', 5, '了些天，还是很好用的。第二次买电脑了，这个价格不贵，应速度也很快，第一个买的那个华硕的电脑，4千左右吧，可是开机太慢啦。应迟钝，我气的卖啦。这次因为工作出差需要，看上这款电脑很轻薄，携带起来很方便，买了用用，办公表格啥的还是很好用的，运行挺流畅的，看看电视，电影画质也很高清。游戏的话，我个人建议你得卖个高配的哈。我用处不。也就表格简单的用下，看电视剧用用的，上网查阅资料比较，续航时间够长，10多个小时没问题，客服服务态度也很友好，发货速度很快，包装很严实。\n用了一段时间，总体上是不错的一台电脑。各方面都不错。价格一般，价格再便宜点就更好了。期待华硕的电脑做的越来越好吧。总之，电脑还是值得买的。非常好，值得信任，也不用验证了，正祈不了！！跟愉快的一次购物！老板人超好！物流必须给个赞，昨天下午下的单子，今天上午就到货了！好评！过几天之后再过来做追评吧！', '16G内存 512G固态 标配版', '2022-10-30 12:51:51', 6);
INSERT INTO `data` VALUES (13080, 'w***0', 5, '物流快，包装盒没有破。打游戏很流畅，追剧的时候简直不要太好了?满意。好评 很喜欢。\n包装保护：没有破损\n画面品质：可以的', '16G内存 512G固态 标配版', '2023-01-12 21:11:41', 6);
INSERT INTO `data` VALUES (13081, 'j***0', 5, '赠品有很多，电脑质量非常不错，重量也没有想象中的那么重，携带方便。散热系统很好玩了一小时游戏也没有发热就像是刚刚开机一样，开机时间也很短，总之各方面都不错，很喜欢。', '16G内存 512G固态 标配版', '2023-03-03 21:25:35', 6);
INSERT INTO `data` VALUES (13082, 'j***n', 5, '包装保护：包装挺严实的，完好无损，外观很好看，看上去挺高贵时尚，整体电脑很不错，开机速度很快，试下网游游戏，速度很快，不会很卡，很满意的一次购物\n外形外观：外观非常喜欢，电脑性能也很稳定反应很快触摸也很灵敏，开机时间短也没有发热的情况，核心温度维持在668度左右，总体很不错，很满意\n画面品质：简直就是完美之作，无论是是显示还是音效，都是高品味，作为一个程序员角度来看，处理器不错，总之很不错，主要是是我懒得打字', '16G内存 512G固态 标配版', '2023-02-26 20:06:50', 5);
INSERT INTO `data` VALUES (13083, '货***8', 5, '16G内存 1TB固态 幻夜黑  \n产品真不错，物流也很快，客服态度好，收到电脑后，外表面也没有损坏，包装很严实，保护的很好，收到后用了一段时间，感觉很满意，外形美观，性能强悍，用着没什么问题，散热也不错，值得信赖！', '16G内存 1TB固态 升级版', '2022-09-10 16:57:26', 5);
INSERT INTO `data` VALUES (13084, 'j***R', 5, '包装保护：包装保护：好有纸壳，还有防撞膜 \n外形外观：外观很好，大气\n画面品质：画质几个流畅\n跑分评测：可以入手', '16G内存 512G固态 标配版', '2022-08-22 17:15:28', 6);
INSERT INTO `data` VALUES (13085, 'j***d', 5, '电脑外观很好，内存也很大，用着也很流畅，物流很快，一天就收到了，画质清晰，外观特别酷特别帅，开机也很快，运行也不错，一点都不卡顿，完美，显卡效果也非常得棒，总体来说就是很喜欢，以后就认准他家了??', '16G内存 512G固态 标配版', '2023-02-22 12:58:55', 5);
INSERT INTO `data` VALUES (13086, 'j***s', 5, '包装保护：包装挺好的，没有破损\n外形外观：外观靓丽，很好看，挺满意的\n画面品质：画面挺好的，没问题\n跑分评测：跑分跑了一下，分数挺高的', '16G内存 512G固态 标配版', '2023-02-16 15:02:39', 6);
INSERT INTO `data` VALUES (13087, 'j***w', 5, '包装保护：包装的非常严实，没有任何磕碰，打包的非常好，送了一些赠品，背包质量不错。\n外形外观：外观无敌，太帅了，比一般的游戏本要薄一点，全金属的质感，非常漂亮。\n画面品质：画质非常好，2.5k非常清楚。\n运行速度：12代i5, 3050Ti, 完全能满足我的需求，一般游戏也都能玩。', '16G内存 512G固态 标配版', '2023-01-29 18:44:39', 5);
INSERT INTO `data` VALUES (13088, 'j***e', 5, '电脑到了，非常好用，速度也非常快，性价比感觉也非常高，外观也非常好看非常喜欢', '16G内存 1TB固态 升级版', '2022-12-29 11:38:46', 8);
INSERT INTO `data` VALUES (13089, 'j***8', 5, '电脑外观是我喜欢的类型，键盘背光也是可以调节的，独立显卡，运行速度也很快，包装很精致，还赠送鼠标和鼠标垫，屏幕15.6英寸刚刚好，追剧玩游戏都很奈斯。', '16G内存 512G固态 标配版', '2023-03-17 20:26:29', 5);
INSERT INTO `data` VALUES (13090, 'j***h', 5, '当我打开这个包装的时候，是感觉是十分好的，里面的保护措施也是更好，电脑本身也很好，反应很快，也送了很多东西1、笔记本整体外观时尚潮流，轻薄小巧，方便携带，整体配置较为不错，显示屏细节清晰盈亮，对于我办公商务绰绰有余，银色版更显高端大气，全尺寸键盘独树一帜，方便我平时出差进行移动网站优化等需求操作。\n2、宝贝两天就到了，捯饬了一下午，觉得很满意，电脑的外观很漂亮，运行速度和内存都还蛮好的，适合我这种简单办公的需要。最后点赞客服，有问必答，服务态度很好，非常周到。满意的购物。\n3、宝贝不错，运行流畅，无卡顿，毕竟和高端笔记本一样的处理器，这价位，这配置知足了，办公，处理下文档，很不错！而且是这价位边框最窄的了，便携，美观，于一身的，对比了很多家！客服很好！不错，满意！\n4、首先要说的是这款笔记本电脑的外观是我非常非常喜欢的，其次要说的是这款笔记本电脑的性能还是非常非常不错的，屏幕色彩也是非常清晰 这款笔记本电脑开机的速度是7-8秒，装完软件是12秒，还是非常符合我的要求的。再次要说的就是这款笔记本电脑的耐用性，是我很期待的。总而言之，这个电脑是非常不错，这外观也很不错，也很耐用，我很喜欢这', '32G内存 1TB固态 升级版', '2022-12-22 10:50:35', 7);
INSERT INTO `data` VALUES (13091, 'j***s', 5, '设计美观，功能强悍，十秒以内开机完成，散热也很快，很有重量感，商家很贴心，还赠送了背包，出行携带很方便，特意用了几天再来评价，整体很满意.', '16G内存 512G固态 标配版', '2022-08-23 12:37:09', 6);
INSERT INTO `data` VALUES (13092, 'j***0', 5, '这款游戏本很棒，也是听别人推荐来的，玩lol特别流畅，运行大部分3a大作都没问题，平时游戏打的也不多，主要用来编程和cad作图，运行起来十分流畅，感觉不到卡顿，外观也特别帅气，开机很快，没有出现一丝卡顿', '16G内存 512G固态 标配版', '2022-12-15 17:33:23', 5);
INSERT INTO `data` VALUES (13093, 'g***r', 3, '英雄联盟偶尔卡顿一下', '16G内存 512G固态 标配版', '2022-11-08 16:51:20', 1);
INSERT INTO `data` VALUES (13094, 'Y***B', 5, '包装保护：包装非常严密，服务很好\n外形外观：外观非常漂亮，质感非常好\n画面品质：画质高清，60hz满足日常需求\n运行速度：运行速度：开机速度很快， 运行速度非常快', '16G内存 512G固态 标配版', '2023-02-17 17:14:44', 5);
INSERT INTO `data` VALUES (13095, 'w***8', 5, '电脑很漂亮，用起来也非常流畅。物流也很快，客服态度好，收到电脑后看了一下,配置一样，是正品，没有产品异样，外表面也没有损坏，包装很严实，保护的很好，非常的喜欢。', '16G内存 512G固态 标配版', '2023-02-01 17:35:59', 6);
INSERT INTO `data` VALUES (13096, 'j***b', 5, '包装保护：外面封的很好没有磕碰\n外形外观：跟照片一样\n画面品质：1080分辨率也是非常棒\n跑分评测：鲁大师检测评分也很高哦\n运行速度：3050的显卡也是可以的哦\n游戏效果：这一点是非常的棒的，运行不卡顿的。\n值得拥有哦?', '16G内存 512G固态 标配版', '2022-11-03 13:33:44', 4);
INSERT INTO `data` VALUES (13097, '买***定', 5, '当天下单第二天就到了，物流神速。开机仔细验过了，无划痕，不插电开不了机，配置也没问题，硬盘和内存的品牌都不错，小三角灯闷骚，我喜欢，用起来很不错', '16G内存 512G固态 标配版', '2023-02-07 21:36:17', 5);
INSERT INTO `data` VALUES (13098, 'j***e', 5, '非常好用呀  买来就使用了  很流畅  手感也很好   喜欢的宝子可以安心饿下单了\n包装保护：好\n外形外观：符合我的审美\n画面品质：高\n运行速度：快', '16G内存 512G固态 标配版', '2023-03-04 18:18:49', 5);
