INSERT INTO `data` VALUES (13105, 'j***2', 5, '测了，是全新的，品质一级棒，包装也不错，物流很快，而且价格合理，很实惠，很喜欢 。东西还不错。\n包装保护：还行\n\n外形外观：可以\n画面品质：一般般\n跑分评测：一万多\n运行速度：还好吧\n游戏效果：就玩了英雄联盟，还好吧操作挺流畅的', '16G内存 512G固态 标配版', '2022-10-30 18:00:32', 4);
