INSERT INTO `data` VALUES (13107, 'u***o', 5, '各方面都很不错的电脑，放心闭眼入，福利多多，很棒很棒，买之前看了好多，幸好没有踩坑，奥力给哈哈哈 ，冲啊！冲', '16G内存 512G固态 标配版', '2023-01-02 15:24:32', 5);
