INSERT INTO `data` VALUES (13109, 'j***5', 5, '这款电脑确实可以，独立显卡，打游戏很棒，开机几秒就可以，屏幕也够用，开学季买的不到6000，还赠送鼠标和垫，还有清洁屏幕的工具，续航也可以，很值。', '16G内存 512G固态 标配版', '2023-02-16 19:59:47', 5);
INSERT INTO `data` VALUES (13110, 'u***l', 5, '很好，产品用的不错，\n包装保护：很严实\n外形外观：很炫酷\n画面品质：不错\n跑分评测：不错\n运行速度：快\n游戏效果：不错不错', '16G内存 512G固态 标配版', '2023-02-19 15:15:33', 5);
