INSERT INTO `data` VALUES (13204, 'j***z', 5, '外形外观非常漂亮，电脑也非常薄，这个价位比实体店优惠多了，值得购买。试用了两天，在家办公完全合适了，运行速度也很快，和商家描述的一样，整体电脑性价比还是可以的，合适正常办公看电视，开好几个软件都不卡.公说买这个电脑值了，喜欢的朋友可以考虑哦。', '16G内存 1TB固态 升级版', '2023-01-19 11:31:43', 4);
