INSERT INTO `data` VALUES (13206, 'j***v', 5, '很好，配置适合游戏，还可以选择模式，功能齐全，外观没。快递包装好，音效好', '16G内存 512G固态 标配版', '2023-01-11 18:08:55', 4);
