INSERT INTO `data` VALUES (13220, 'j***c', 5, '电脑还是选联想，很nice一点都不卡，我用来学室内设计画图完全绰绰有余，包装很好快递也很快，很好非常喜欢', '16G内存 512G固态 标配版', '2022-11-25 13:58:45', 5);
