INSERT INTO `data` VALUES (13225, 'j***H', 5, '包装保护：包装的很严实，没有一点划痕\n外形外观：外形很酷炫\n画面品质：画面也很有感觉\n运行速度：没有一点卡顿现象，什么游戏都可以运行的了\n游戏效果：游戏也很流畅', '16G内存 512G固态 标配版', '2022-10-30 13:15:06', 4);
INSERT INTO `data` VALUES (13226, 'u***a', 5, '产品物流速度快，颜值外观高端大气！散热效果不错，噪音小。电脑大小合适，运行速度很快，屏幕显示效果好，色彩很好', '16G内存 512G固态 标配版', '2022-11-14 18:11:51', 3);
INSERT INTO `data` VALUES (13227, 'j***y', 5, '本本很漂亮，比想象中还要轻薄。屏幕看着挺舒服。电池满电提示能够使用接近六小时，实际工作时间有待测试验证。客服要特别赞一下，电脑很大气，买来给学生用的，配件很齐全，评价晚了，试用了下不错，准备工作用，用用office软件,性价比很高，总体满意.本本很不错，手感很好，很流畅', '16G内存 512G固态 标配版', '2023-02-28 14:31:03', 3);
INSERT INTO `data` VALUES (13228, 'j***d', 5, '包装保护：非常nice\n外形外观：很帅气，高端\n运行速度：游戏顺畅\n物流很快，客服服务态度很好，包装全新没有指纹，开机十分流畅，大学生办公十分好用，无聊时打打游戏也很顺畅，游戏开最高画质十分舒服', '16G内存 512G固态 标配版', '2022-11-13 11:46:28', 6);
INSERT INTO `data` VALUES (13229, 'j***o', 5, '非常好的一款电脑 值得购买 对于设计专业的软件也能带动 散热非常好 渲染没问题 外观也好看 心动的快点下手吧 双十一的活动也很优惠 电脑对于女生可能有点小重不过是游戏本可以理解 目前使用啦几天没啥问题 电脑也很舒畅\n包装保护：好\n外形外观：好\n画面品质：好', '16G内存 512G固态 标配版', '2022-11-13 14:06:37', 3);
INSERT INTO `data` VALUES (13230, 'j***易', 5, '这款笔记本电脑确实不错，手感好，散热也很好，反应速度很快，颜值高，续航也可以，屏幕显示效果也很好，运行速度很流畅，另外物流也很快，太赞了，值得推荐！特别是运行大型游戏，非常流畅。安装的设计软件也能快捷运行。成为工作和生活中的好帮手。客服耐心讲解。一次不错的购买体验。', '16G内存 512G固态 标配版', '2022-11-09 17:07:07', 3);
