INSERT INTO `data` VALUES (13235, 'u***k', 5, '里面有泡棉保护，外包装轻微破损\n包装保护：还可以\n外形外观：帅\n画面品质：很清晰\n跑分评测：百万跑分很轻松\n运行速度：蛮快的\n游戏效果：插电一点问题没有，非常流畅', '16G内存 512G固态 标配版', '2023-02-02 20:01:31', 5);
INSERT INTO `data` VALUES (13236, '-***吖', 5, '真的很可以 我看这款电脑看了一个月 最后决定买他了 回来很激动 打开看看和图片一模一样 和我心里的一模一样 良心商家', '16G内存 512G固态 标配版', '2022-10-28 17:33:30', 4);
INSERT INTO `data` VALUES (13237, 'j***b', 5, '第一次买电脑 选了好久选的这个 看样子是不错的\n包装保护：双层纸盒 胶带缠得很严实\n\n外形外观：完好无损 没有破损地方 \n\n运行速度：开机很快', '16G内存 512G固态 标配版', '2023-03-11 17:45:36', 2);
INSERT INTO `data` VALUES (13238, 'j***e', 5, '电脑不错 发货也很快，用起来很流畅，打游戏也很舒服?还免费送一些小配件 鼠标 鼠标垫 电脑包还有其他的', '16G内存 512G固态 标配版', '2022-12-05 14:42:56', 5);
INSERT INTO `data` VALUES (13239, 'j***1', 5, '包装保护：保护的非常好\n外形外观：很帅\n画面品质：高帧率很牛\n运行速度：很快\n游戏效果：很多游戏都带的动，画质也很清晰', '16G内存 512G固态 幻夜黑 升级版', '2022-02-21 18:56:48', 6);
INSERT INTO `data` VALUES (13240, '安***评', 5, '包装保护：保护的特别好，拿过来包装一点没瑕疵\n外形外观：特别好看，有质感有手感\n画面品质：观看特别舒服，顺畅\n运行速度：运行速度很快，不卡', '16G内存 512G固态 标配版', '2023-02-02 20:32:55', 5);
INSERT INTO `data` VALUES (13241, 'j***N', 5, '联想大品牌，值得信赖，电脑用起来很舒服，打游戏一点也不卡，是22年的新款，性能没话说，而且物流也很快，送货到家，客服服务也很好，不懂的客服都耐性解答，非常满意', '16G内存 512G固态 标配版', '2022-12-04 17:45:18', 5);
INSERT INTO `data` VALUES (13242, 'j***c', 5, '我买的是联想拯救者R7000 5800H，质量很过关，品质有保障，相当不错的选择，好多朋友看我用都想买，我都推荐了', '16G内存 1TB固态 升级版', '2022-09-05 15:57:37', 5);
INSERT INTO `data` VALUES (13243, '猫***卅', 5, '电脑不错，运行流畅，不卡顿。价格合适，\n跑分评测：117W分，还行吧。\n包装保护：包装结实，无损坏，\n物流也很快，\n外形外观：还行，符合我的审美条件。\n游戏效果：打游戏稳定流畅，不卡顿！', '16G内存 1TB固态 升级版', '2022-11-07 16:41:56', 5);
INSERT INTO `data` VALUES (13244, 'j***i', 5, '包装保护：还不错\n外形外观：好看\n画面品质：不错\n跑分评测：很好快递很快\n游戏效果：很好\n真的很不错 快递速度很快 很喜欢', '16G内存 512G固态 标配版', '2022-11-25 19:33:12', 6);
INSERT INTO `data` VALUES (13245, 'j***g', 5, '包装保护：包装非常好，快递一点破损都没有\n外形外观：外观很满意！很好看，很简约，也很帅\n画面品质：画质目前感受良好\n运行速度：运行速度毕竟是新电脑，感受非常好\n总体来说，电脑很不错', '16G内存 512G固态 标配版', '2023-02-12 17:56:49', 5);
INSERT INTO `data` VALUES (13246, 'j***O', 5, '电脑很好 ， 配送很快，电脑质量很好，性价比高，还送了电脑包鼠标等实用东西，个人比较满意 ，五星好评。', '16G内存 512G固态 标配版', '2022-10-10 17:47:55', 6);
INSERT INTO `data` VALUES (13247, 'j***2', 5, '电脑很好，用着也很舒服，等了很久到货迫不及待就拆箱了，完美无瑕疵，嘎嘎好用\n运行速度：嘎嘎快\n外形外观：很好\n包装保护：很严实\n画面品质：嘎嘎清楚\n游戏效果：直接起飞老铁', '16G内存 512G固态 标配版', '2022-11-17 21:55:50', 5);
INSERT INTO `data` VALUES (13248, '槐***9', 5, '包装保护：很安全\n外形外观：非常的喜欢\n跑分评测：杠杠的\n运行速度：飞快\n游戏效果：非常的流畅\n画面品质：很不错\n商家还送了鼠标垫，背包，客服态度也很好', '16G内存 512G固态 标配版', '2022-12-18 09:43:42', 5);
INSERT INTO `data` VALUES (13249, 'j***z', 5, '包装保护：包装得很严实拿回来的时候拆了半天 纸箱很完整 没有破损\n外形外观：非常时尚 很符合现在年轻人的审美 轻便\n画面品质：画面很清晰流畅 没有杂质\n游戏效果：游戏过程中非常流畅 没有出现任何卡顿现象 很满意 非常适合游戏的一款笔记本很推荐给大家', '16G内存 512G固态 标配版', '2023-01-30 18:20:04', 2);
INSERT INTO `data` VALUES (13250, 'j***c', 5, '电脑包装非常到位，包装非常的大气，高端。电脑细节做的非常到位，性能也非常的好，打游戏也不卡，性价比高，非常推荐买。', '16G内存 512G固态 标配版', '2022-10-17 06:58:55', 4);
INSERT INTO `data` VALUES (13251, '小***U', 5, '包装保护：包装很好，没有损坏\n外形外观：很好看  很酷\n画面品质：不错 自我感觉满意\n运行速度：还可以  用一段时间后再来反馈\n游戏效果：效果不错 可以满足需求\n电脑很不错  是正品  大家放心入  价格也是划算的', '16G内存 512G固态 标配版', '2023-01-05 20:31:34', 5);
INSERT INTO `data` VALUES (13252, '王***欣', 5, '包装保护：包裹得很好\n外形外观：超级好看\n游戏效果：没得说嘞非常安逸\n运行速度：超级快  开机5秒', '16G内存 1TB固态 升级版', '2023-02-20 17:18:48', 2);
INSERT INTO `data` VALUES (13253, 'j***c', 5, '嘎嘎不错，一点都不卡顿，\n画面品质：画质很不错\n外形外观：本来想买银色，但是黑色也很不错，很高级\n游戏效果：不打游戏，但是做PPT还不错，看电视也很高清', '16G内存 512G固态 标配版', '2022-11-14 14:03:46', 3);
INSERT INTO `data` VALUES (13254, '张***之', 5, '这款电脑很棒，玩只狼**流畅，运行大部分3a大作都没问题，散热效果不错，客服沟通方便，整体满意，运行十分流畅，几乎感觉不到明显的卡顿。 外观也漂亮，是喜欢的类型 ，和期望值一样，很好用的一款游戏笔记本，物流很快，当天定第二天中午就到了。', '16G内存 512G固态 标配版', '2023-02-26 11:58:36', 6);
INSERT INTO `data` VALUES (13255, 'j***e', 5, '运行速度：快快快，一点都不卡\n\n画面品质：清晰，亮丽，色彩很好\n外形外观：高端大气，颜色好看\n包装保护：包装坚固，完整，快递速度也很快', '16G内存 512G固态 标配版', '2023-02-03 18:56:32', 5);
INSERT INTO `data` VALUES (13256, '隐***9', 5, '包装保护：全方位保护\n外形外观：轻薄，金属质感，拉丝面\n画面品质：高清，色彩逼真\n运行速度：秒开，即点即出\n游戏效果：全效开放，无压力\n晚上下单，隔天上午就到货，物流配送相当迅速！机器配置高，外观完美，运行流畅，一次完美购物体验！', '轻薄电竞R9000X', '2022-08-17 18:33:58', 5);
INSERT INTO `data` VALUES (13257, 's***y', 5, '包装很结实，两层的，外面有京东的包装盒。联想的包装盒外有联想密封贴，防止遇到二手机。电脑做工很精致，全金属机身，外观含蓄不张扬，我是买来工作用的，一点儿不违和，很满意！屏幕画质好，亮度高，演示公司的三维程序很出彩！性能释放强，满意！就是适配器太沉了，没办法，为了性能释放只能忍了！总体很满意，很推荐！', '专业电竞R9000P', '2022-08-18 09:11:43', 9);
INSERT INTO `data` VALUES (13258, '黑***z', 5, '游戏本收到了，京东就是快，第二天就到了。质量感觉很不错，喜欢双面的金属设计，摸上去手感很好，键盘按起来也很赞，运行操作很流畅，屏幕显示很清晰，分辨率很高，看起来很舒服，总体很不错，推荐大家购买！', '【销量先锋】专业电竞R9000P', '2023-01-05 16:02:07', 5);
INSERT INTO `data` VALUES (13259, 'j***4', 5, '电脑很好，快递很给力，电脑运行没得说的，非常可以，是全新的，配置可以，可以冲\n画面品质：可以可以，2k\n运行速度：666\n游戏效果：无敌\n外形外观：很帅，特别是后面灯，爱了', '【销量先锋】专业电竞R9000P', '2022-11-10 22:20:59', 4);
INSERT INTO `data` VALUES (13260, '也***然', 5, '质感很好，走起来流畅，系统也很好使，自带的软件也很方便\n外形外观：很漂亮\n包装保护：很到位\n运行速度：很快\n游戏效果：待测', '专业电竞R9000P', '2022-08-11 08:15:39', 9);
INSERT INTO `data` VALUES (13261, 'j***8', 5, '包装保护：包装很给力，包的很严实，有泡沫保护着，很赞\n外形外观：做工很精细，外观还是很漂亮的，\n画面品质：画面清晰，色彩丰富，整体很可以\n运行速度：开机速度快，打游戏运行起来很流畅，\n游戏效果：游戏页面看着很清晰，色彩鲜艳，运行起来没有卡顿的现象，\n这次选购还是很喜欢的，大件都在京东买，昨天晚上下的单，上午送到，这效率真是无敌??有需要还会在回购', '【销量先锋】专业电竞R9000P', '2022-11-11 16:01:45', 6);
INSERT INTO `data` VALUES (13262, 'M***e', 5, '第一次买笔记本电脑 去年就一直关注R9000P了 我这边三月三加清明节放三天假 索性就就入手了 4月2日购买到4月3日到货 京东yyds 到货马上验机 生产日期3月21日的 屏幕无坏点完美屏 三星内存 海力士固态 验完机立马自己加装1T固态 用了3天没什么问题\n包装保护：无破损完美\n外形外观：精致 简洁大方 手感好\n画面品质：2.5K屏看起来很舒服很细腻\n跑分评测：没跑分 就是Win11用不是很习惯 慢慢摸索吧\n运行速度：很快 秒开\n游戏效果：我很少玩3A游戏 2.5K 165hz高刷完美适配各种网游', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-04-05 10:49:56', 8);
INSERT INTO `data` VALUES (13263, '大***酷', 5, '包装保护：包装很好\n外形外观：我网上看没有太大感觉 实物真的惊艳到我了\n画面品质：不说了 有了电脑不看手机了\n跑分评测：绝了 只能说这两个人字\n运行速度：冲 冲 冲 感觉真的舒服 大型游戏随便玩', '【销量先锋】专业电竞R9000P', '2023-03-15 22:16:18', 8);
INSERT INTO `data` VALUES (13264, '布***9', 5, '包装很结实，产品很给力，更新了好半天。\n速度很快，开机秒开，应用秒开。\n外观给力，帅气金属机身。\n重量还行，比游戏本稍微轻点。\n屏幕给力，显示效果非常好。', '轻薄电竞R9000X', '2022-11-02 14:21:45', 9);
INSERT INTO `data` VALUES (13265, '彳***-', 5, '第一次买电脑，很棒，看图，（18岁小屁孩的手，给你们做屏幕参考）\n包装保护：完美无破损\n外形外观：无划痕\n画面品质：画面品质：2K 165赫兹高刷很畅快\n跑分评测：AMD5800H的3060跑分还彳亍，评测视频B站很多\n运行速度：流畅，开机5,6秒就好\n游戏效果：网游无压力，3A也还可以', '专业电竞R9000P', '2022-08-09 22:22:32', 3);
INSERT INTO `data` VALUES (13266, 'y***朱', 5, '综合考虑选择了这款，没有失望，很不错，性能也很不错，运行游戏也不卡，开机很快，色彩也不错。看视频也是不错的！外观也很赞，轻薄。整机包装保护不错，送货速度也是超快！目前是用了几天后才评价的。游戏和视频也开了好几次了，声音效果还可以。检查过，是正品\n包装保护：很好\n外形外观：很好\n画面品质：不错\n跑分评测：不错\n运行速度：不错\n游戏效果：不错', '轻薄电竞R9000X', '2022-12-12 19:58:33', 8);
INSERT INTO `data` VALUES (13267, 'h***0', 5, '曾经买过第一代拯救者，7年来我用过4台笔记本，现在又回到了拯救者。如今拯救者的外观真好看，R9000X外观大气质感好又轻薄，是我喜欢的外观。这是我第一次用双A平台的笔记本，试了几个游戏，在2k分辨率下都很流畅，我的主力电脑是台式机，这台笔记本已经能满足我偶尔出差、旅游用途了。对了这台机器屏幕表现不错，看评测NTSC是74%，实际观感更出色。\n拿到后我加了一条联想16g内存，固态盘换成了1t，系统还是选择了win10，换下的原装固态装了硬盘盒用。', '轻薄电竞R9000X', '2023-01-25 19:38:42', 9);
INSERT INTO `data` VALUES (13268, 'x***o', 5, '包装保护：京东快递很快。早上就送到了。\n外形外观：外形很好看 ，很轻薄。就是有点重。屏幕很大，窄边框，视觉效果很好。\n画面品质：很好，亮度500。\n跑分评测：跑分很高，运行速度很快，不卡顿。6800h很快，cpuz单核560多核5600。鲁大师130w。其他跑分软件暂时没跑。\n运行速度：很快，工业软件运行很流畅。\n游戏效果：很好，3a很流畅，网游那些肯定没问题。6800s 8g 显存，3a可以开高画质。\n 下次继续买联想，这次购物很满意。', '轻薄电竞R9000X', '2022-11-02 11:17:44', 7);
INSERT INTO `data` VALUES (13269, '飞***鹅', 5, '包装保护：高端大气上档次\n外形外观：霸气奈斯\n画面品质：高分屏good\n跑分评测：120w\n运行速度：gta5特效全开无压力\n游戏效果：8G显存不是盖的', '轻薄电竞R9000X', '2022-11-10 23:19:30', 8);
INSERT INTO `data` VALUES (13270, 'K***少', 5, '中午接近12点下单，下午不到6点多就送到了，快递小哥送货速度无敌！\n\n新电脑比想象中要好多了，屏幕和机壳比我的y9000x好上几个档次，把娃照片做屏保和开机画面让人爱不释手哈。\n\n和老鸡对比，重量增加不算多，屏幕大了一圈。\n\n性能暂时没有游戏可测试&hellip;应该不会让我失望！', '【新品】旗舰电竞R9000K', '2022-08-26 16:54:21', 6);
INSERT INTO `data` VALUES (13271, '买***丶', 5, '性价比很高，性能强劲，主要看中了性能，买过来制图，比公司的台式机好多了，基本上不玩游戏了，不过看到这个电脑还是会手痒?\n包装保护：寄过来的时候包装很完整，里面有很多泡沫棉\n外形外观：真的帅啊，金属面板质感很好\n运行速度：运行速度没得说，起飞，3d建模再也不卡了', '【销量先锋】专业电竞R9000P', '2022-11-17 18:44:54', 8);
INSERT INTO `data` VALUES (13272, 'w***7', 5, '非常不错，处理器：6800h完全够用，配上显卡6800s也是非常不错，2.5k100%RGB色彩，屏幕素质可以，再加上键盘手感也非常好，外观还是喜欢21款的外观，当然现在这个外观也不错，值得推荐', '轻薄电竞R9000X', '2023-02-04 22:35:27', 4);
INSERT INTO `data` VALUES (13273, 'q***8', 3, '电脑是送到学校的，具体不清楚，购物再评', NULL, '2021-11-10 23:11:11', 4);
INSERT INTO `data` VALUES (13274, '_***_', 5, '买的入门款，使用感受很不不错，没有发现什么问题。屏幕给我观感特别好，音质也没啥问题。游戏的话没怎么试，看后续体验。目前总体比较满意。', '轻薄电竞R9000X', '2023-02-13 20:50:14', 4);
INSERT INTO `data` VALUES (13275, 'j***h', 5, '包装保护：包装很好\n外形外观：很漂亮，有质感。电池很重很大\n画面品质：屏幕素质很高\n跑分评测：玩大众游戏轻轻松松\n运行速度：非常快，秒开机\n游戏效果：运行速度很快，配置够用了，目前的市场上性价比很高的款型', '【销量先锋】专业电竞R9000P', '2022-11-12 19:21:28', 7);
INSERT INTO `data` VALUES (13276, '席***生', 5, '包装保护：京东物流一直都可以信赖没啥说的包装完好，打开物流箱里面是机器包装箱，封口完好没有磕碰。\n外形外观：是我喜欢的样子，大写Y很时尚很nice\n画面品质：2.5k果然好，比以前的老机器1080好太多，刷新率也高，没看到啥缺点，屏幕京东方的没有啥问题。\n跑分评测：来红灯（野兽模式）136万鲁大师跑分，满意了。\n运行速度：跑分就说明一切\n游戏效果：还没完，目前不知道如何，不过配置在这的应该不会差。\n总体满意，用用看。', '专业电竞R9000P', '2023-01-06 18:10:44', 7);
INSERT INTO `data` VALUES (13277, 'e***a', 5, '首次网上购买笔记本，京东包装加原封泡沫垫妥妥的，拯救者本本外观工艺确实阔以，全金属机身质感大赞，沉稳的灰黑色调满意。全方位检查没有一丝划痕，屏幕色彩显示清晰高大上，LOGO和键盘灯格调不错。适配器&hellip;.咱能优化轻便点嘛&hellip;. 首次开次耐心等待，二次开机十秒，运行流畅无卡顿，武汉调货的八月下旬产的本本，大师验机，AMD配双三星配京东方配海力士闪存，可以冲啦~', '【销量先锋】专业电竞R9000P', '2023-03-14 08:53:12', 9);
INSERT INTO `data` VALUES (13278, '就***了', 5, '包装保护：包装挺厚实的，机子无磕碰划痕\n外形外观：全铝的轻薄本，办公很实用\n画面品质：屏幕分辨率高，特别棒\n运行速度：打开office和其他软件操作反应挺快的\n游戏效果：基本上steam游戏都能玩\n我是A粉，3A平台性价比很高。买！', '轻薄电竞R9000X', '2022-12-16 11:14:38', 7);
INSERT INTO `data` VALUES (13279, '园***8', 5, '太帅了真的\n包装保护：快递包装的很好 很大气 根本不用担心出什么问题\n外形外观：拯救者大气的外观 不用多讲\n画面品质：顶级！玩游戏真的舒服 平时办公用着2.5k的屏幕也是很爽 看多了都有点不太习惯手机屏幕了哈哈哈\n运行速度：很快 不管是游戏 还是工业软件 真的超级快', '【销量先锋】专业电竞R9000P', '2023-02-18 12:09:42', 3);
INSERT INTO `data` VALUES (13280, '慕***n', 5, '电脑收到了，打开箱子一整个惊艳住，电脑很赞，安全下车！外观非常漂亮，大小和厚度也很适合女生，和游戏本相比算是方便携带的。激活流程也很方便。迫不及待打了一把lol，很流畅，fps稳定在140-170之间，画质非常好。这款性价比真的超高，冲啊！', '轻薄电竞R9000X', '2022-11-14 15:10:02', 2);
INSERT INTO `data` VALUES (13281, '小***卜', 5, '笔记本刚到手，金属质感很好，信仰灯很炫，键盘灯也很好看，屏幕分辨率很好，整体外观大气整洁，值得拥有！', '专业电竞R9000P', '2022-11-22 12:51:45', 8);
INSERT INTO `data` VALUES (13282, 'j***b', 5, 'r9000p非常nice，上班的时候用了同事的，触感，反应，屏幕都很舒服，所以买了个同款。\n芯片是amd的，固态买了个1t的的三星970pro（还是980pro？），下午去安。电脑自带的，都当系统盘使用。插机械硬盘反应也很快，不愧是拯救者，以后妥妥够用了。\n2022款听说比21款散热好些，用的时候风扇呼呼的吹，搭配一个支架就很nice了。不关机的话，拯救者大标一直都很炫亮。\n总体下来很满意，还在与新电脑磨合阶段，鲁大师跑分13000多，还是可以啦。', '【销量先锋】专业电竞R9000P', '2023-03-19 10:33:24', 4);
INSERT INTO `data` VALUES (13283, '秋***候', 5, '包装保护：京东快递很给力，包装完好并且送货上门，当面签收\n外形外观：外观很帅气，大Y简直太酷了\n跑分评测：跑分125万\n画面品质：游戏画质很棒，体验感十足', '【销量先锋】专业电竞R9000P', '2023-03-08 09:28:15', 3);
INSERT INTO `data` VALUES (13284, 'j***w', 5, '游戏本收到了，京东就是快，早上下单，下午就到了\n质量很不错，喜欢双面的金属设计，手感超级棒，键盘按着很赞，运行操作很流畅，屏幕显示很清晰，分辨率很高，看起来很不错，值得大家入手', '【销量先锋】专业电竞R9000P', '2023-03-14 22:58:29', 2);
INSERT INTO `data` VALUES (13285, '磕***拉', 5, '包装保护：包装很好 很牢固 运输无磕碰\n外形外观：金属外壳很好看比之前的旧拯救者好看了很多 真的很轻薄\n画面品质：画面不错 很流畅\n运行速度：打了两局永劫无间 和 老头环 最高画质无压力', '轻薄电竞R9000X', '2023-01-11 20:40:27', 6);
INSERT INTO `data` VALUES (13286, 'm***o', 5, '非常好，值得入手！屏幕无坏点，金属外观，还不重，有质感！尺寸不大不小，刚刚好，符合我的要求！可工作，可游戏。', '轻薄电竞R9000X', '2023-01-17 18:17:42', 4);
INSERT INTO `data` VALUES (13287, '你***人', 5, '外形外观：非常美观，摸起来很冰冷的。\n画面品质：默认设置是高画质，很不错的，十分舒适，还是16:10尺寸令人期待。\n游戏效果：没有瑕疵，正常运行，似乎没有发现微小的卡顿。\n\n目前没有准备近年内的新游戏，现在玩到csgo，崩坏3，欧陆风云4，命运石之门精英版，运行很不错，画面效果很好，下次要用到了ps，sia等等绘画软件，我希望这款笔电可以继续带来令人惊喜的成果。\n运行速度：运行速度：调整系统设置稍有卡顿了，偶尔反应慢拍。', '【销量先锋】专业电竞R9000P', '2022-12-10 10:46:32', 6);
INSERT INTO `data` VALUES (13288, 'f***o', 5, '联想拯救者R9000X终于入手了，整机金属质感，颜值爆表。敲击键盘手感相当舒服。165Hz 10bit高色域屏，无论办公还是游戏，色彩还原度非常高，眼睛也不疲劳。更有AMD RX6800S独立显卡加持，性能完全能媲美台式机。', '轻薄电竞R9000X', '2022-11-21 12:15:01', 6);
INSERT INTO `data` VALUES (13289, '8***3', 5, '很薄，正常游戏本重量，全金属面，质感非常好，屏幕质量也可以，外观没有瑕疵，白色键盘灯有两个档位。amd 功耗低，性能和3060一样，但是功耗更低。是一款精致的游戏本。', '轻薄电竞R9000X', '2023-01-25 14:41:56', 2);
INSERT INTO `data` VALUES (13290, 'T***8', 5, '包装保护：没问题，京东自营就好品质好。\n外形外观：轻薄，拉丝工艺，金属质感无敌了\n画面品质：高刷2.5k屏爱了爱了。\n运行速度：联盟原神cf无压力，嘎嘎丝滑。平时用运行速度很快。', '轻薄电竞R9000X', '2022-12-04 14:15:08', 6);
INSERT INTO `data` VALUES (13291, 'j***r', 5, '三星内存，三星固态镁光显存，京东方屏幕，11月29号生产，到手很新，用了十多天了，没有任何问题，完美机子，元旦入手，打游戏很流畅，屏幕无坏点，京东物流很赞，几个小时就到手了，性价比高，非常好看的logo,包装保护的很好，京东自营购机很有保障???', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-14 15:09:11', 8);
INSERT INTO `data` VALUES (13292, 'j***7', 5, '当天就到了，使用了近一周分享一下体验：\n外形外观：AD面金属，质感很好，C面塑料，有类金属感。整体外观突出但不张扬，相比其他游戏本更低调。\n\n画面品质：2.5K 16寸屏幕，相当于外置显示屏的4K效果，太清楚了。我的漏光很少，也无坏点。\n\n运行速度：5800H + RTX3060 6G 了，运行大部分游戏都无压力。\n\n游戏效果：如下图奥德赛帧率测试。在无超频、野兽模式下，2K全最高画质，混合模式56帧，独立显卡61帧。\n就一周使用来看，我的这台无大问题。小问题是风扇不转时有电流声，通病无解。总而言之，香！', 'R9000P', '2021-04-14 09:56:13', 8);
INSERT INTO `data` VALUES (13293, 'j***7', 5, '16：10的屏幕真的非常大非常舒服，2.5K屏也是观感无敌，到手验机只通电了3小时确实不错，硬盘是三星的，拯救者r9000p确实是一款非常不错的游戏本，几乎没有缺陷，玩apex2.5k可以160帧，奥德赛高画质关抗锯齿有70帧左右', '【销量先锋】专业电竞R9000P', '2023-02-25 01:54:30', 6);
INSERT INTO `data` VALUES (13294, 'j***U', 3, '买了一个月  音响滋啦啦响  糟心', NULL, '2021-11-08 22:38:57', 7);
INSERT INTO `data` VALUES (13295, 'B***Z', 5, '买来用了一小段时间了从开箱验机，到日常使用没有任何问题，就是打游戏最好开野兽模式或者一键超频，普通的均衡我有过一次闪退，开野兽模式从来没有过，日复一日依旧对京东自营店有着十分信赖，也希望越来越好，整机不错\n包装保护：完好无损\n外形外观：金属感拉满，帅！！！\n画面品质：刷新贼快，画质拉满，流畅的起飞！！！\n跑分评测：120多万\n运行速度：无卡顿，超流畅运行\n游戏效果：画质拉满，稳定不掉帧', '【销量先锋】专业电竞R9000P', '2023-02-09 14:40:11', 2);
INSERT INTO `data` VALUES (13296, '简***夜', 5, '包装保护：非常厚实，保护的很好。\n外形外观：厚薄适中，做工精美，材质真实。\n运行速度：不卡顿，非常流程，同时运行多个应用都可以！', '轻薄电竞R9000X', '2022-12-21 07:20:19', 6);
INSERT INTO `data` VALUES (13297, '苇***s', 5, '全金属，超薄，对男生来说这点重量不算什么，质感确实好，非常漂亮，性能也好，我很喜欢\n京东快递发货很快，包装好，点赞', '轻薄电竞R9000X', '2022-11-05 00:39:01', 7);
INSERT INTO `data` VALUES (13298, '似***帅', 5, '做工不错\n包装保护：很好\n外形外观：不错，要是银色就更好了\n画面品质：不错\n跑分评测：不错\n运行速度：很流畅\n游戏效果：不错', '专业电竞R9000P', '2023-02-12 09:14:57', 6);
INSERT INTO `data` VALUES (13299, '夜***嗔', 5, '外形外观：好看 好看 好看！\n包装保护：包装很完好 生产日期是今年的10月份 很新\n跑分评测：鲁大师跑了一百一十多万\n游戏效果：游戏还没试过 完事再过来评价\n机子暂时整体是很过关的.', '【销量先锋】专业电竞R9000P', '2022-12-03 16:40:15', 3);
INSERT INTO `data` VALUES (13300, '爱***霖', 5, '挺好的，拿到手特意录了开箱视频。忙得顾不上仔细查看。联想官方自营，还是令人放心的。关键是价格 现在的价格真的是很好， 比老款的都便宜，但是性能3060+6800  这个可以说比一般的都好的多，够用够用。做工也可满足', '【销量先锋】专业电竞R9000P', '2023-03-09 13:22:30', 9);
INSERT INTO `data` VALUES (13301, '售***人', 5, '想买个笔记本很久了，关注了不少品牌的机型，最后还是选择了R9000X2022，外观全金属质感很好，键盘手感舒适，屏幕不必多说，完美！双A平台性能强劲，完全满足了我的需求，甚至在未来的相当一段时间内都可以满足我的需求，很满意这款产品。', '轻薄电竞R9000X', '2022-11-19 19:40:26', 5);
INSERT INTO `data` VALUES (13302, 'C***_', 5, '电脑的内外包装对电脑的保护做得不错，开箱过程简直是一种享受，非常nice。\n机器外观比图片上看起来更漂亮一些，两面金属材质质感很好。键盘触感也相当不错，打字反馈很好，屏幕清晰度也很好，2.5k屏yyds，打游戏也很好，办公娱乐第一首先', '【销量先锋】专业电竞R9000P', '2022-11-28 10:05:38', 3);
INSERT INTO `data` VALUES (13303, '碧***g', 5, '外观很漂亮，金属的，质感不错\n\n性能不多说，跟台式差不多\n\n屏幕顶级，不多说\n\n续航，办公5个小时，还行\n\n重量，5斤比15.6的轻薄本重1斤，完美\n\n总结:可以代替商务本的游戏本，无论是外观还是性能, GTA5稳定流畅运行没毛病', 'R9000P', '2021-04-12 10:34:37', 7);
INSERT INTO `data` VALUES (13304, '殷***苂', 5, '包装 保护：付款到收货只用半天时间，上午下单 下午就收货了，京东自营真的很棒。包装严实安全，不松散。全新机器未拆封。\n外形外观：外观造型非常帅气，重量能接受，主要是很喜欢。A面大Y  logo很美，键盘灯很棒。键程舒适而且最重要的是外接口很多。\n运行速度：r5 5800h配新3060显卡日常游戏使用盈余，性能足够强大。运行处理很流畅。\n游戏效果：日常使用很安静，特效全开无呼啸。还能更改模式。很棒很值得哦。', '专业电竞R9000P', '2022-06-10 22:13:27', 6);
INSERT INTO `data` VALUES (13305, 'j***h', 5, '联想拯救者R9000P，拿到手后，第一时间开箱。做工相当好，A壳金属手感一流，奔驰灯颜值高，外观真是太惊艳了。2K屏大爱，显示细腻，无论游戏办公，效果杠杠的。键盘布局合理，手感一流。独立显卡给力，这是一个五星水桶机，没有短板，给联想大大的赞。', 'R9000P', '2021-04-07 20:34:17', 8);
INSERT INTO `data` VALUES (13306, '白***哦', 5, '包装保护：三层保护，完全没问题\n外形外观：真的很好看\n画面品质：2.5k没问题\n跑分评测：7位数的跑分\n运行速度：贼快\n游戏效果：没问题的', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-25 12:44:20', 5);
INSERT INTO `data` VALUES (13307, '消***8', 5, '一直相信的品牌，包装好，送货快。款式简洁大方，颜色雅致，金属质感很好，高端大气，尤其电脑外壳图标超级喜欢。使用一段时间了，运行内存都很满意，用起很上手，很满意，望后期的售后也跟上。', '【销量先锋】专业电竞R9000P', '2023-01-14 09:50:01', 6);
INSERT INTO `data` VALUES (13308, 'j***k', 5, '外观很漂亮，机身轻薄，手感做工都很不错，运行流畅，多屏协同真的很方便，屏幕也很清楚，比上一代提升了不少，而且有联想自带的控制中心，对于学生来说很合适。联想笔记本一如既往让人觉得好用，运行十分流畅，配置也很高。购买的时候对比了好几家，最后还是选择了这家，感觉性价比好高，而且显示屏大小也刚刚好，这个价格很公道，开机也就快，安装了几款主流游戏很顺畅，一边下载，一边玩游戏，一边听音乐也不卡顿，朋友都说不错，问我要了链接也要买呢，物美价廉感觉很满意。', '【销量先锋】专业电竞R9000P', '2023-03-16 23:32:11', 7);
INSERT INTO `data` VALUES (13309, '谨***8', 5, '大Y灯非常帅气，AD两面金属很有质感，16:10的屏幕观感非常的好，显示细腻无坏点无漏光，显卡野兽模式单烤130w，性能释放没问题，温度也控制的不错，是一台各方面比较均衡的水桶机', '【销量先锋】专业电竞R9000P', '2022-12-23 10:26:03', 6);
INSERT INTO `data` VALUES (13310, 'j***5', 5, '趁着双11活动好近下单，物流很快，隔天就收到了\n包装保护：包装蛮精致蛮用心的，有泡沫条保护，防止碰撞损坏\n外形外观：质感很棒，尤其键盘音箱小细节处理的很棒，整体外观比图片体验感\n画面品质：屏幕画质啥的没的说，就是蛮好的\n跑分评测：没啥跑分的，系统用习惯就好了\n总结：整体还是不错的，性价比高，趁着活动入手划算', '轻薄电竞R9000X', '2022-11-04 10:43:50', 6);
INSERT INTO `data` VALUES (13311, 'T***代', 5, '外观真的很棒，金属质感，跑分一般，运行起来建筑制图软件还行，比较顺畅，保护措施很到位，应该可以使用四年左右，之后继续换联想的旗舰游戏本', '专业电竞R9000P', '2022-08-18 17:29:53', 6);
INSERT INTO `data` VALUES (13312, 'j***s', 5, '10.31号买的，11.2号就到了，包装完好，2022/10/17号生产的，拆开外观完美，造型很漂亮，画质很好，使用起来看着很舒服，运行速度很快，秒开，打游戏的感受很棒，画质清晰流畅效果很好.\n开学的时候就想买了一直等双十一看到活动果断下单', '【销量先锋】专业电竞R9000P', '2022-11-13 18:06:55', 7);
INSERT INTO `data` VALUES (13313, '庞***豪', 5, '包装保护：包装挺好，包了好几层。\n外形外观：非常大气，大奔驰标也很哇塞。\n画面品质：挺好的，打游戏用的，挺好。\n跑分评测：可以了\n运行速度：挺快的，没有卡顿，\n游戏效果：挺好，快速。游戏体验杠杠的。', '专业电竞R9000P', '2023-01-16 16:05:33', 5);
INSERT INTO `data` VALUES (13314, '原***尘', 3, '割韭菜了，线下拿货已经8800了！', 'R9000P/RTX3060/R7/165Hz 2.5k屏', '2021-09-25 19:52:59', 2);
INSERT INTO `data` VALUES (13315, 'j***6', 5, '外形外观：这个拯救者的外观是真的帅\n画面品质：16寸的2.5k屏显示相当奈斯\n跑分评测：新版鲁大师分数正常\n游戏效果：3060可以2k高画质玩3a,体验相当不错', '专业电竞R9000P', '2022-08-18 18:07:57', 2);
INSERT INTO `data` VALUES (13316, 'j***K', 5, '满意的一次购物  用两周了  体验感不错\n包装保护：完整\n外形外观：耐看 质感很好\n画面品质：清晰', '轻薄电竞R9000X', '2023-02-17 16:04:00', 6);
INSERT INTO `data` VALUES (13317, '酸***1', 5, '不错，外观大气，小新我很喜欢，颜色无色差。开机很快，运行一天，没有大噪音。画质清晰，音效也很ok。买来学习ps剪辑视频制作再也不担心卡了质感很好，摸起来很丝滑，使用起来也不错，以为16寸会很大，但也还好，掉电也比较慢。', '专业电竞R9000P', '2022-08-07 10:53:07', 6);
INSERT INTO `data` VALUES (13318, '久***n', 5, '第一次在网上买电脑，一以前的联想电脑因为太旧了，实在是不想继续用了。测评如下：\n包装保护：非常好，产品完好无损\n外形外观：金属磨砂外壳，防指纹\n画面品质：2.5k超高分辨率屏幕，看着十分舒服\n跑分评测：110w分，也算很高了\n运行速度：非常快，没有卡顿\n体验非常好', '轻薄电竞R9000X', '2022-12-12 21:50:50', 5);
INSERT INTO `data` VALUES (13319, '疯***9', 5, '包装保护：真的很严实，内盒一点没刮蹭。\n画面品质：不愧为2.5K屏，看着是真的很舒服。眼睛不累。因为不玩游戏，也用不着跑分看成绩。要的就是屏幕舒服。\n运行速度：开机速度还行，安装软件时有提示会影响开机速度。\n外形外观：最喜欢这个Y，标志代表了一切。就是这个适配器大了，比之前的大很多，沉很多。\n总体来说，非常满意。', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-21 11:48:34', 5);
INSERT INTO `data` VALUES (13320, 'z***l', 5, '电脑速度不错，也很薄，显示也很清晰哈哈，机器也很漂亮，不错哈哈很好的体验／', '轻薄电竞R9000X', '2023-01-24 15:18:17', 4);
INSERT INTO `data` VALUES (13321, 'r***0', 5, 'Y9000P作为一款专业的电竞游戏笔记本，R7-6800H+RTX3060，性能确实十分强悍，完全满足目前主流网游和3A大作要求。特别是在外观颜值方面更是满足了一切颜王的要求，机身AD双面金属机身设计，还有一个专属的大&ldquo;Y&rdquo;灯，B格满满。联想作为国内知名品牌，专业电脑供应商，拯救者作为联想笔记本旗下的明星产品，产品品质和品控绝对有保证，再加上京东自营售后服务做保障，安全感满满。目前使用，流畅丝滑，体验感非常棒。', '【销量先锋】专业电竞R9000P', '2023-03-15 16:28:21', 6);
INSERT INTO `data` VALUES (13322, 'j***5', 5, '哈哈，买的第二天就到手了，外观非常漂亮，质感非常好，高大上档次。预装的win11系统，非常流畅屏幕清晰好看，特别值的一款电脑', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-02-13 19:03:05', 8);
INSERT INTO `data` VALUES (13323, '山***风', 5, '电脑很好，打游戏很流畅，拯救者很好用，第一次买电脑买到这么好的真的很惊艳，拯救者名副虚传！\n包装保护：包装很完整\n外形外观：外观没有磕碰之类的\n画面品质：2.5k165hz真的很爽\n跑分评测：娱乐大师跑分稳120w以上\n运行速度：开机很快不到7秒\n游戏效果：游戏很流畅', '专业电竞R9000P', '2022-09-22 17:38:15', 5);
INSERT INTO `data` VALUES (13324, '1***7', 5, '到底就是拯救者哈，灯效满满，散热满满，小键盘也是好评，太喜欢了~', '【销量先锋】专业电竞R9000P', '2023-03-15 14:36:42', 9);
INSERT INTO `data` VALUES (13325, 'j***c', 5, '人生的第一台游戏笔记本电脑，找了很长时间，最终选择这款电脑入手，隔天到达，速度很快，现在到手上满满的激动，外观非常帅气，键盘手感也很好，充电器是300w的，贼6，哈哈，后续好用继续评价。', '【销量先锋】专业电竞R9000P', '2023-03-09 18:09:39', 7);
INSERT INTO `data` VALUES (13326, 'j***L', 5, '包装保护：外包装没有明显损伤\n外形外观：奔驰标很帅\n画面品质：165hz刷新率很流畅\n跑分评测：120w+和期待中一样满意\n运行速度：平时不玩3a 普通游戏完美运行\n游戏效果：不卡帧，高刷，', '专业电竞R9000P', '2022-10-21 12:15:30', 5);
INSERT INTO `data` VALUES (13327, 'j***f', 5, '外观材质：外观很漂亮富有科技感，拯救者信仰大Y灯， 大logo灯，背光键盘，屏幕显示效果也很棒。\n电脑性能：电脑gaga快，开机很快，5800H的AMD CPU完全够用。高刷高色域护眼电竞屏，加上多核心处理器。流畅运行各种游戏。\n显卡效果：满血版显卡，功耗大性能强，游戏画面流畅，3060的显卡玩市面上大多数游戏都能驾驭。', '专业电竞R9000P', '2022-10-10 22:00:42', 6);
INSERT INTO `data` VALUES (13328, 'l***e', 5, '包装保护：大包套小包，踏实没毛病\n外形外观：外观真的帅啊！大Y灯YYDS\n画面品质：高分屏，高素质\n运行速度：6800+3060完全够用\n游戏效果：对于只玩联盟的来说够了，偶尔3A也没毛病', '【销量先锋】专业电竞R9000P', '2023-03-15 20:28:16', 4);
INSERT INTO `data` VALUES (13329, '牛***丶', 5, '人生中第一个本子，想着对自己好点，上个好一点的本子，没让我失望，外观很简洁，Y字灯很漂亮很有辨识度，打游戏也嘎嘎香，出厂日期也挺新，总的来说很棒。', '【销量先锋】专业电竞R9000P', '2023-02-23 14:20:12', 7);
INSERT INTO `data` VALUES (13330, 'D***y', 5, '7月25日出厂的，全新未拆封，用了将近一周了，没有别的可以说的！我只能用三个字形容：艺术品！\n平时不用的时候盯着这块2.5k屏发呆，不禁会感叹怎会有如此完美的设计，美感与性能的结合#(滑稽)\nps：买后得了电子YW，买前打游戏，买后刷批站\n包装保护：全新未拆封\n外形外观：不得不说确实漂亮\n画面品质：测试无漏光，无坏点，显示效果好\n跑分评测：看娱乐大师吧\n运行速度：快\n游戏效果：还不错', '专业电竞R9000P', '2022-08-10 20:45:58', 5);
INSERT INTO `data` VALUES (13331, 'h***9', 5, '外观很漂亮，全金属材质，白色背光键盘，雷电/网口接口齐全，USB接口也不少，还带摄像头屏蔽按键，很好', '【销量先锋】专业电竞R9000P', '2023-03-09 16:27:24', 6);
INSERT INTO `data` VALUES (13332, '小***q', 5, '用了几天了，感觉这台电脑很不错，机身外观个人觉得很好看也很耐看，特别喜欢这个小键盘和方向键，开机键的一圈亮光不同颜色对应不同的性能模式，我用平衡模式，日常办公基本没有听到风扇声。在更新系统时风扇会响，不过也还可以接受，没有电流声，屏幕也没有曲面屏。特别推荐做工程类的购买这个，目前这个性价比觉得很可以了。', '轻薄电竞R9000X', '2022-12-01 23:45:45', 6);
INSERT INTO `data` VALUES (13333, 'O***好', 5, '包装保护：很不错\n外形外观：很好看\n画面品质：超级清晰\n跑分评测：115万左右\n运行速度：开机十几秒', '【销量先锋】专业电竞R9000P', '2022-11-14 11:35:27', 6);
INSERT INTO `data` VALUES (13334, 'j***p', 5, '综合考虑选择了这款，没有失望，非常好，性能也很不错，运行流畅，2.5k屏幕色彩很棒，声音效果很好，包装很到位，大Y灯超酷，一线大牌值得拥有，晚上下单，隔天就到，物流很快，百亿补贴性价比超高，冲?', '【销量先锋】专业电竞R9000P', '2023-03-15 21:31:27', 3);
INSERT INTO `data` VALUES (13335, 'w***s', 5, '笔记本非常实用！\n包装保护：保护很到位 外形外观：很好 运行速度：很快 游戏效果：很好 评分检测。\n画面品质：2.5K IPS屏非常清晰\n外形外观：很满意，自己加装了一根1T的固态硬盘，非常方便，里面自带了固定螺丝', '【销量先锋】专业电竞R9000P', '2023-03-11 17:58:13', 5);
INSERT INTO `data` VALUES (13336, '刘***雨', 5, '包装保护：包装完好无损，京东快递非常快。\n外形外观：轻薄简约，质感很好。\n画面品质：10bit。2.5k165hz。清晰流畅。\n运行速度：运行流畅。\n跑分评测：均衡模式独显直连。娱乐大师125w。完美哈。\n游戏效果：画质非常细腻，坦克世界完美运行。6800s显卡功耗90w，3060显卡功耗140w。低功耗高性能。真的强?。', '轻薄电竞R9000X', '2022-11-24 14:18:11', 4);
INSERT INTO `data` VALUES (13337, '思***i', 5, '心心念的电脑终于到货了 使用了一段时间才来评价 体验感十足 性能完全ok 甚至对于我而言有些过剩 选择模式是最最最最爽的 根据使用环境选择性能模式 打游戏的时候即使打开野兽模式声音也不是很大 安静模式真的是一点声音没有！ 重量还好 我感觉没有适配器沉 哈哈哈 屏幕已经很薄了 16比10的屏幕是真爽！！！', '【销量先锋】专业电竞R9000P', '2022-11-14 23:52:41', 6);
INSERT INTO `data` VALUES (13338, 'j***8', 5, '包装保护：快递包装完美\n外形外观：r9kp外形真的爱了，棱角分明，ad好像都是金属\n画面品质：2.5k屏幕，165hz高刷新率，玩游戏不要太爽\n跑分评测：鲁大师接近130w的样子，记得开野兽模式\n运行速度：相当流畅。', '【销量先锋】专业电竞R9000P', '2022-12-25 10:47:46', 5);
INSERT INTO `data` VALUES (13339, 'J***7', 5, '送货很准时，机子也保护的比较好，应该是全新机，目前正在使用，还没玩游戏，希望不会失望！机子仔细看了很多人反应的左下角缝隙的问题，我的没看到，今天仔细看了机器发现背面左下角有一点点划痕，算了，不影响使用，总体感觉机器屏幕很好，声音也不错，反应快，刚好收到货第二天小孩子就停课了拿去上网课，效果杠杠滴！', '轻薄电竞R9000X', '2022-11-09 12:59:16', 6);
INSERT INTO `data` VALUES (13340, 'j***e', 5, '包装保护：包装精美安全可靠\n外形外观：外形漂亮\n画面品质：画质很好\n跑分评测：跑分满意很高\n运行速度：速度特别快\n游戏效果：效果好，就是买来打游戏的。', '【销量先锋】专业电竞R9000P', '2023-03-07 15:40:25', 4);
INSERT INTO `data` VALUES (13341, '咱***砍', 5, '科研利器，有了拯救者跑代码，绘图再也不卡了，独立显卡还是很棒的，16寸的屏幕也足够用了，外观也很好看，金属材质，很有科幻感，总之很香！', '【销量先锋】专业电竞R9000P', '2023-02-22 13:21:59', 5);
INSERT INTO `data` VALUES (13342, 'j***7', 5, '包装保护：保护的非常的不错\n外形外观：非常的好看logo很好看！！还能发光！！\n画面品质：还是很清晰的，很好看\n跑分评测：比同等位英特尔处理器的跑分高。\n运行速度：非常的流畅，很喜欢！\n游戏效果：还没有玩游戏，应该也不错呢！', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-01 16:13:35', 9);
INSERT INTO `data` VALUES (13343, 'j***e', 5, '到手后使用了一段时间，整体使用体验非常号 A面是金属的，2K屏的观感非常棒，5800H的CPU，日常使用体验非常流程，3060的显卡，玩3A也很流程，爱了爱了！', 'R9000P', '2021-04-18 15:52:21', 8);
INSERT INTO `data` VALUES (13344, '杯***人', 5, '?发货很快，两三天就到了，这个颜色我很喜欢，配置很高，非常nice，靓机一枚，玩了几局，FPS就没低过，其他单机游戏还在下载，什么Steam，EA，Uplay通通下起来，不然就浪费了这个配置', '【销量先锋】专业电竞R9000P', '2023-03-10 09:16:44', 7);
INSERT INTO `data` VALUES (13345, 'w***t', 5, '这个游戏本把我惊艳到了，一次完美无语论比的体验，太爱这个本本了，钱掏的值\n包装保护：真棒\n外形外观：完美\n画面品质：超凡\n跑分评测：惊人，超3060\n运行速度：快的像神一样\n游戏效果：棒的呱呱叫', '轻薄电竞R9000X', '2022-12-28 13:12:32', 6);
INSERT INTO `data` VALUES (13346, 'j***H', 5, '包装保护：包装十分妥帖，防震系数高\n外形外观：大气且不易脏，方便，而且不是很重说实话\n画面品质：好，无坏点，客服很有耐心，帮忙解决了很多问题\n跑分评测：可以\n运行速度：快\n游戏效果：感觉还是很流畅的，达到了预期要求', '【销量先锋】专业电竞R9000P', '2022-11-03 15:00:36', 4);
INSERT INTO `data` VALUES (13347, '永***芳', 5, '非常精致的一款产品，处理器和显卡都很强，双十一降价到7499，就让这款产品的性价比更高了，用起来非常的流畅，续航也可以，比轻薄本还要强。', '轻薄电竞R9000X', '2022-11-27 21:22:02', 7);
INSERT INTO `data` VALUES (13348, 'Y***y', 5, '外形外观：全金属面板触感和质感都非常出色\n画面品质：2K屏在rx6800s加持下能应付大部分的需求', '轻薄电竞R9000X', '2022-11-25 21:57:57', 4);
INSERT INTO `data` VALUES (13349, 'j***c', 5, '包装保护：包装很高大尚，有两层的保护，里面有一个袋子装着电脑，然后还有海绵隔着，不怕磕碰\n外形外观：外观很好看的，银色的外观很，键盘用起来也很顺手\n画面品质：完了一下永劫无间，画质也非常好，不卡顿，性能也够用了', '【震撼新品】专业电竞R9000P', '2022-09-16 23:37:24', 5);
INSERT INTO `data` VALUES (13350, 'j***e', 5, '京东真的牛?，凌晨12点付的尾款，中午就送到了。这机器抢到了不容易啊，黄niu太多了。机器质感很好。我的老微星gs60可以下岗了。比gs60重，厚。屏幕是真的爽，我都不想外接显示器了。金属的a面确实舒服。性能还没体验。5800加3060，相信大多数的游戏不开2k都没问题。好了就这么多了，我要打游戏，哈哈', 'R9000P', '2021-04-07 16:57:25', 8);
INSERT INTO `data` VALUES (13351, '桐***X', 5, '外形外观：超级帅 好喜欢\n画面品质：不错 杠杠的\n跑分评测：没有跑过 没那么重要\n运行速度：开机速度超级快\n游戏效果：还没开始打游戏 应该不错吧\n包装保护：有点磕磕碰碰 但是还是保护很好', '专业电竞R9000P', '2022-10-21 22:18:31', 5);
INSERT INTO `data` VALUES (13352, '冯***9', 5, '机器开机速度很快，散热效果也不错，玩起游戏来，一点也不卡顿，等用一段时间后，看看效果怎么样', '【销量先锋】专业电竞R9000P', '2023-03-15 21:58:09', 6);
INSERT INTO `data` VALUES (13353, 'c***r', 5, '非常不错，这款 r9000p 2022 款玩游戏很流畅，对于我这种普通玩家来说已经够用了。fn+q 快捷切换三种模式也很便利。目前我给它配了个 拯救者 135w 氮化镓快充，但是玩大型游戏的话还是建议使用自带的 300w 充电器。 据说马上要新出一款 300w 氮化镓，希望能缩小体积减轻重量。还是很期待的。', '【销量先锋】专业电竞R9000P', '2023-03-07 14:16:25', 6);
INSERT INTO `data` VALUES (13354, 'r***6', 5, '到手时外包装有破损，但是还好里面没事，保护得很好。第一次开机要40多秒，但之后开机都很快，13秒左右。目前跑各种游戏完全无压力，都是最高特效。2.5k显示屏效果很好，沉浸感强，音箱效果也非常不错，加上整体的做工和低噪音的散热，堪称完美。', '轻薄电竞R9000X', '2022-11-14 21:43:30', 2);
INSERT INTO `data` VALUES (13355, 'q***6', 5, '宝贝描述和实物一样样滴，注册登录后运行速度极快。整体外观时尚潮流，轻薄小巧，整体配置较为，黑色版显示屏细节清晰盈亮，对于我 办公商务绰绰有余，黑色版更显高端大气，全尺寸键盘独树一帜，方便我平时出差进行移 动网站优化等需求操作。', '【销量先锋】专业电竞R9000P', '2022-11-11 20:47:05', 1);
INSERT INTO `data` VALUES (13356, '泡***锅', 5, '包装保护：非常好 \n跑分评测：一百三十多万\n运行速度：挺快的\n游戏效果：下了一个QQ飞车，不知道为什么玩不了，窗口模式，不能大屏?然后我就卸了（实在不知道玩什么游戏....）\n外形外观：非常好，画面分辨率高，我直接没验货，让我妈取回来的，安全下车！', '专业电竞R9000P', '2022-11-14 06:59:19', 6);
INSERT INTO `data` VALUES (13357, '西***溅', 5, '画面品质：2.5k屏幕很清晰。16:10屏幕上下边都很窄，视觉效果满分！\n跑分评测：amd。yes！跑分很高。8g显卡搭配高分屏幕很爽！\n游戏效果：游戏效果很好！各种游戏都不卡，但是amd驱动现在有一个bug，设置成独显之后跑分会降低，混合模式效果才是最大化！', '轻薄电竞R9000X', '2022-12-08 20:09:42', 4);
INSERT INTO `data` VALUES (13358, '皮***虎', 5, '只需不到八千元 即可拥有rtx3060 2.直连模式和hdr 2.5k屏幕 配置上很丰富 性能也很好\n本子厚度要远比游匣好很多， 之前买的g15蛮厚的。\n重量没有想象中沉。\n性能稳定 玩xbox 的 xgpu游戏 没问题 ori， forza horizon 都支持hdr模式 ， horizon默认评级配置是超高模式 \n看hdr视频 色彩也很好', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-02-22 08:56:35', 8);
INSERT INTO `data` VALUES (13359, '清***h', 5, '包装保护：无破损\n外形外观：很薄\n画面品质：分辨率很高很清晰\n跑分评测：还行\n运行速度：还可以\n游戏效果：一般', '轻薄电竞R9000X', '2023-01-28 12:58:03', 4);
INSERT INTO `data` VALUES (13360, 'c***a', 5, '首先，这个价位还可以，其次，联想是个老牌子，值得信赖，再者上手质感很好，金属外观，好看，还有，背部的大灯晚上看着不错，另运行游戏也还可以，apex稳定100多帧，最后，屏幕色好', '【销量先锋】专业电竞R9000P', '2022-12-26 11:20:04', 5);
INSERT INTO `data` VALUES (13361, '飞***6', 5, '笔记本质感非常好，屏幕又大又清晰，九十瓦的6800s对标3060，打游戏完全够我用了，古墓丽影最高画质在2.5k分辨率下，有六十多帧。换成windows10系统后完美。', '轻薄电竞R9000X', '2022-11-26 15:25:39', 5);
INSERT INTO `data` VALUES (13362, '晼***儿', 5, '联想拯救者R9000X，高刷电竞，真不错，手感非常舒适，速度很快，还是超薄，在游戏本领域，能承受轻薄本的称号。我最怕重的本本了，但是真心说比之前用的笔记本舒适到那去了，外观颜值\n很漂亮，耐用。', '轻薄电竞R9000X', '2022-12-26 14:30:19', 6);
INSERT INTO `data` VALUES (13363, 'j***b', 5, '外形外观：帅的很！\n画面品质：画质清晰\n运行速度：快\n游戏效果：游戏效果：原神60帧没有任何压力， 3A游戏暂时没有下载。\n自己买的第一台笔记本电脑，使用了一个星期，用来玩玩游戏，做做设计都很不错。而且在管家那里可以人工客服回答电脑上遇到的问题。', '专业电竞R9000P', '2022-10-19 01:41:50', 2);
INSERT INTO `data` VALUES (13364, '倔***肉', 5, '电脑发货很及时到货很快，电脑配置很高，日常办公打游戏速度贼快 很流畅 屏幕尺寸很好 视野很宽广 很不错', '专业电竞R9000P', '2022-11-23 19:53:45', 3);
INSERT INTO `data` VALUES (13365, '叮***妍', 5, '包装保护：实话外包装很简陋，但是都是实用的设计 当电脑拿出来的时候这些都不重要了?\n外形外观：低调大方的外形，很耐看，看视频不以为充电器大小，拿到实物的时候我靠 真的大 跟板砖?一样哈哈哈哈\n画面品质：2看电影玩游戏体验不错\n跑分评测：还没跑\n运行速度：相当的流畅\n游戏效果：开三极致 玩了一天吃鸡 奈斯嚯嚯嚯', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-05-01 20:01:59', 4);
INSERT INTO `data` VALUES (13366, 'j***绵', 5, '非常不错的产品，AD金属面很舒服，超级赞的。包装严实，京东物流好评。16个框框看着舒服，满血的3060赞。充电器是真的大。整体重量比我之前的thinkpad要重。尺寸差不多。我现在就是把它装到我的tp包里。首发买到性价比是真的高。三星内存显存。730的固态。屏幕真舒服比我以前的舒服太多了。', 'R9000P', '2021-04-09 14:53:00', 8);
INSERT INTO `data` VALUES (13367, 'j***h', 5, '包装很结实，两层的，外面有京东的包装金。联想的包装金外有联想密封贴，防止遇到二手机。电脑做工很精致，全金属机身，外观含蓄不张扬，我是买来学习用的，一点儿不违和，很满意！屏幕画质好，亮度高，性能释放强，满意！就是适配器太沉了，没办法，为了性能释放只能忍了！总体很满意，很推荐！', '【销量先锋】专业电竞R9000P', '2023-03-14 13:45:42', 4);
INSERT INTO `data` VALUES (13368, 'w***3', 5, '包装保护：包装没有问题，保护的很到位，纸箱保护没有任何损失，\n快递服务：前一天晚上下单，第二天中午就到了，服务态度也很好，\n外观设计：金属质感很帅气，整体看起来也很高端大气，背面拯救者的logo也很不错\n产品质量：作为21年性价比最高的一款游戏本，搭载了满血版3060显卡，\n用户体验：运行速度很快，基本能带动现在世面上的所有3A大作，平常办公作业也完全是没有问题，2.5k电竞屏加上16：10的比例，玩起来是真的爽，\n买的内存是金士顿，两根8G显存，硬盘是海力士，512G，屏幕是京东方，网卡是intel的，也算是很不错的了', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-22 15:52:39', 9);
INSERT INTO `data` VALUES (13369, 'j***a', 5, '包装保护：包装盒特别好看，而且是我喜欢类型，收到时候满满欢喜。\n外形外观：电脑外观，我连上电脑，大Y亮起来，非常酷，电脑手感很好。\n画面品质：非常清晰，没有一点模糊，特别游戏，用最高画质，那种感觉就是爽。\n运行速度：速度上，搭载今年最新的锐龙处理器和最新的3060显卡，没有半点卡顿。\n游戏效果：游戏体验这个更爽，因为，可以直接调到狂野模式，这个玩起来，真爽。\n所以我选择拯救者笔记本，是对的。', 'R9000P', '2021-06-13 00:03:46', 7);
INSERT INTO `data` VALUES (13370, 'j***f', 5, '包装保护：完好无损\n外形外观：双面金属机身超跑排气管出风口专属可控大Y灯\n画面品质：16寸大屏2.5k超高清分辨率 占比92.3%，硬件级防蓝光+DC调光，减少了屏幕光幕中的有害蓝光\n游戏效果：三模显示切换，支持实时光线追踪，模拟真实光线路径，游戏体验更惊艳', '【震撼新品】专业电竞R9000P', '2022-09-18 16:50:13', 4);
INSERT INTO `data` VALUES (13371, '胖***黝', 5, '包装保护：包装干净整洁，两层包装非常好\n外形外观：外观时尚，很酷，大Y的logo可以开关灯，漂亮\n画面品质：画质清晰2.5K分辨率 完美\n跑分评测：鲁大师测试跑分 轻轻松松150万 厉害?\n运行速度：开机7秒，打开软件的速度合适非常快\n游戏效果：测试了几款大型三A游戏 效果真棒 游戏帧数非常高！', '【震撼新品】专业电竞R9000P', '2022-06-24 10:49:47', 4);
INSERT INTO `data` VALUES (13372, '小***8', 5, '联想拯救者R9000P值得拥有，运行速度快，游戏本的首推，有条件的可以上更高配置，屏幕 音效 运行 系统等都很厉害。', '【销量先锋】专业电竞R9000P', '2023-03-12 13:37:38', 2);
INSERT INTO `data` VALUES (13373, 'j***q', 5, '画面品质：换了新屏幕，真的色泽比之前用了七八年的电脑好太多了\n包装保护：抢到了首发，7999，3060够了\n外形外观：外形很骚气，还有科幻的奔驰logo，还可以控制，有点骚气\n游戏效果：独显的效果真的很棒，无论游戏办公，都足够用了', 'R9000P', '2021-04-19 23:32:06', 8);
INSERT INTO `data` VALUES (13374, '黛***惑', 5, '包装保护：双层包装盒，机器外侧还是有缓冲泡沫架保护。\n外形外观：ACD面金属，框架金属，质感拉满。\n画面品质：屏幕素质很高，显示细腻，色彩不错。\n跑分评测：画图用，specviewperf结果很不错，图一乐。', '轻薄电竞R9000X', '2022-11-14 10:38:17', 4);
INSERT INTO `data` VALUES (13375, 'D***u', 5, '外形外观：质感不错，背面线条挺有设计感的，Y字形大背灯挺酷的\n画面品质：屏幕分辨率很高，画质比前一台电脑好多了，看着很舒服\n运行速度：运行速度很快，打开游戏没有卡顿。PS之类考验配置的软件使用也很流畅\n总体来说不介意电脑重量的话，买这台电脑性价比真的不错', '【销量先锋】专业电竞R9000P', '2023-03-20 16:36:10', 4);
INSERT INTO `data` VALUES (13376, 'Y***t', 5, '机器收到后，马上就开机激活了，系统预装正版WIN11，开机速度7秒左右，散热做的也不错，吃鸡全特效拉满，帧数未定在120左右，好电脑害的选联想啊兄弟们', '【销量先锋】专业电竞R9000P', '2023-01-08 16:39:19', 7);
INSERT INTO `data` VALUES (13377, '守***时', 5, '包装保护：保护很严实，一点都不怕运输受损。\n外形外观：高端大气，金属外壳，看着很舒服，摸起来手感也不错。\n画面品质：画面很清晰，还有多种画质可调节。\n运行速度：运行很快，很流畅，开机快的超乎想象。\n游戏效果：游戏很流畅，画质让人感到身临其境，玩游戏很舒服，很畅快。', '专业电竞R9000P', '2022-10-13 23:18:14', 3);
INSERT INTO `data` VALUES (13378, '孤***人', 5, '外形外观：手感非常好 很喜欢\n画面品质：画面也非常清晰细腻\n运行速度：玩3a无压力\n游戏效果：玩游戏非常好', '【销量先锋】专业电竞R9000P', '2023-03-19 19:20:22', 4);
INSERT INTO `data` VALUES (13379, 'j***g', 5, '第一次买联想拯救者系列，在打开的那一刻真的非常非常惊艳！！！！！\n包装保护：快递小哥很耐心的等我验过外包装后才离开，外包装完美无破损无划痕。\n包装箱质感很好，有很厚重的感觉，对机体的泡沫保护也很有安全感。\n外形外观：从防尘布拿出电脑的那一刻，真的真的很超值啊，外观绝杀！完美达到我画图所需的性能而又不失轻薄！酷酷的黑色又很典雅的感觉，妥妥的西装**！！！\n画面品质：整张屏幕给我带来的感觉很震撼，清晰、色彩饱和度高，追剧必备良品呐简直，第一血必须给黄石第五季！！！\n\n运行速度：运行速度很流畅，很轻盈的感觉，顿感超值的体验！', '轻薄电竞R9000X', '2023-01-04 20:09:25', 6);
INSERT INTO `data` VALUES (13380, 'j***7', 5, '非常好? ikun 必买.性能稳定 输出猛.\n奔驰大标快绝版了，百亿补贴 非常划算.\nAmd锐龙7处理器 加3060显卡 玩3a大作足够了\n大家闭眼入', '【销量先锋】专业电竞R9000P', '2023-03-18 14:39:39', 5);
INSERT INTO `data` VALUES (13381, 'w***刷', 5, '包装保护：赞！\n外形外观：很好！\n画面品质：很高清！\n运行速度：很流程！\n游戏效果：非常好！\n       第一次在网上买电子产品，很好没有翻车。比我想象中的要好很多，很喜欢！', '【销量先锋】专业电竞R9000P', '2023-03-13 17:33:01', 4);
INSERT INTO `data` VALUES (13382, 'G***E', 5, '挺好的笔记本电脑，包装很严实，表面没有划痕，预装正版的Win11系统和Office2021办公套装。这款笔记本电脑做工精致，接口齐全，屏幕是雾面屏，防炫光，2.5 K分辨率，165Hz刷新率，用起来顺滑流畅。处理器是锐龙7-5800H，显卡是RTX3060 6GB显存，16GB 3200Mhz第四代双通道内存，512GB固态硬盘，持续读取速度每秒3000多兆。该配置可以运行目前市面上主流的游戏和办公生产力软件。很满意的一次购物。', '专业电竞R9000P', '2023-03-13 22:07:15', 4);
INSERT INTO `data` VALUES (13383, '小***位', 5, '屏幕很清晰，键盘用起来也很舒服。rx6000s对于我来说够用了，现在遇到的游戏都能玩。续航很好，就是重了点', '轻薄电竞R9000X', '2022-11-17 21:46:18', 6);
INSERT INTO `data` VALUES (13384, 'a***0', 5, '外形外观：型男必备\n画面品质：非常清晰，色彩鲜艳\n跑分评测：1158096\n运行速度：快\n游戏效果：游戏已经玩上，嗖嗖嘚\n包装保护：严实', '专业电竞R9000P', '2022-10-23 16:54:16', 4);
INSERT INTO `data` VALUES (13385, '凹***伤', 5, '包装保护：包装得很好，没有瑕疵情况\n游戏效果：3A大作，运行流畅\n用了也很长一段时间才评价的，这款轻薄工作办公很方便，同样也丝毫不影响下班后的游戏体验。', '轻薄电竞R9000X', '2023-01-15 11:49:18', 5);
INSERT INTO `data` VALUES (13386, '向***洋', 5, '年度最香3060笔记本，全功率输出3060显卡，4bg三星内存，散热优秀，玩游戏爽到爆，拯救者2021年度入门旗舰机，良心配置，能抢到很幸运，退吧战五年。', 'R9000P', '2021-04-12 14:20:38', 8);
INSERT INTO `data` VALUES (13387, 'm***c', 5, '包装保护：保护的非常好，内胆防摔\n外形外观：是我横向比较了几乎所有电竞本后，觉得最漂亮时尚、有质感，大气的造型\n画面品质：屏幕非常清晰，大屏配高刷，很带劲', '轻薄电竞R9000X', '2022-11-28 19:36:02', 4);
INSERT INTO `data` VALUES (13388, '邹***9', 5, '外观真的没得讲，设计师YYDS，玩游戏爽的一批，打开网页很快，总而言之言而总之就是性能外观都是牛的一批！', '【销量先锋】专业电竞R9000P', '2023-03-06 20:40:59', 6);
INSERT INTO `data` VALUES (13389, '枫***雪', 5, '包装保护：非常不错\n外形外观：高端大气上档次\n\n画面品质：非常清晰\n\n跑分评测：非常高\n\n运行速度：非常快\n游戏效果：非常快\n电脑中大大奔，拯救者R9000P\n采用满血版3060处理器，比3050快不少\n16G内存，最大可扩展64G\n外观采用铝合金材质，看起来高端大气上档次\n游戏随便玩，挖矿随便挖', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2021-11-20 19:40:02', 9);
INSERT INTO `data` VALUES (13390, 'h***o', 5, '包装很赞，满满的仪式感，用了十年苹果，跳出来发现win系统也不错，机器也很精致。很不错的购物体验，有这个秒杀的价格，谁还买上代的二手机器去，完美体验，加了六年延保，暂时不准备换机器了。', '轻薄电竞R9000X', '2023-02-26 22:43:32', 5);
INSERT INTO `data` VALUES (13391, 'j***x', 5, '电脑不错哦 轻薄本 打游戏顺畅 最喜欢他的触摸板 是我用过最丝滑的 看视频也非常清晰', '轻薄电竞R9000X', '2023-01-07 11:10:00', 3);
INSERT INTO `data` VALUES (13392, '鳄***-', 5, '1、物流特别给力 两天就到了 颜色特别好看 颜值超级给力 然后就是手感 磨砂质感 估计不沾灰 屏幕一级棒 特别是那个 90屏占率 瑞龙5 小游戏偶尔玩一下完全没问题 csgo无压力 办公用途完美无任何压力 十分流畅 预装了win10系统 上手概10分钟就可以开始使用 十分方便 这款商务用途绝对是首选\n\n2、因为装的东西不多，十几秒就开机了，电池续航时间约只有3小时就自动关机了。用鲁师检测领先全国11%的用户。总共就开机几次，时间很短，目前没发现什么异常，因为本人不玩游戏，不知道玩游戏的情况会怎样，只是办公用估计没问题吧，如果以后有什么再追评。先好评\n\n3、电脑很好用，外观气小清新！操控性能也很好！电脑整体看起来很精致，键盘看着也超级舒服，朋友都说我会买东西，说我有眼光！比官方旗舰店实惠，价格也有优势！就是自己是电脑**，很多小问题不会操作，客服这边也很耐心！愉快的一次购物体验！给店家一百个赞！忽略**手机的像素\n\n4、看了好久的电脑，很喜欢粉色，终于让我找到了，然后就立马下了单，为了等这个电脑，真是日思夜想，都等的失眠了收到之后耳机也是粉嫩粉嫩的，真是少女心泛滥了，然后刚开始不知道怎么', '轻薄电竞R9000X', '2022-12-21 09:07:11', 3);
INSERT INTO `data` VALUES (13393, '一***c', 5, '包装保护：收到的时候外包装有一个小小的口子，但是内里完好无损，里面还有海绵保护层，很用心了\n画面品质：画面非常清晰，视觉得到很大的满足\n运行速度：运行速度也很nice呀，一点也不卡顿，用起来非一般的感觉，太开心了\n外形外观：外观真的有点炫酷的，买之前还担心会不会看上去特别笨重，但是结合科技的外观，看上去精致了很多', '【销量先锋】专业电竞R9000P', '2022-11-22 10:30:55', 4);
INSERT INTO `data` VALUES (13394, 'u***8', 5, '专业电竞R9000P，标压R7...包装保护：包装很给力，包的很严实，有泡沫保护着，很赞\n外形外观：做工很精细，外观还是很漂亮的，\n画面品质：画面清晰，色彩丰富，整体很可以\n运行速度：开机速度快，打游戏运行起来很流畅，\n游戏效果：游戏页面看着很清晰，色彩鲜艳，运行起来\n没有卡顿的现象\n这次选购还是很喜欢的，大件都在京东买，物流也非常的快', '【销量先锋】专业电竞R9000P', '2023-03-13 14:03:06', 4);
INSERT INTO `data` VALUES (13395, 'u***e', 5, '1买过最贵的电脑买完有点心疼钱hhhh。\n\n2性能释放和散热都很优秀，A系新款。\n\n3质感良好，重量适中。\n\n4屏幕很舒服，自带色彩管理。\n\n5外观很商务，整体也蛮心动，颜值控大爱。\n\n6再想想\n\n7带独显的轻薄游戏本，因为看模型+打游戏需要独显，独显对工科三维结构模型的渲染速度提高很多。', '轻薄电竞R9000X', '2022-11-12 14:10:50', 4);
INSERT INTO `data` VALUES (13396, '洋***爱', 5, '性能释放非常棒，做工细节完美，感觉很完美，这就是我想要的笔记本，9000 系列比 7000 系列有更好的散热和做工细节,如果你不是那么在乎性能，而是想要一个好屏幕，好散热的游戏本，3060 版本的 R9000P 将会是值得考虑的选择。', 'R9000P', '2021-04-07 23:27:23', 8);
INSERT INTO `data` VALUES (13397, '黄***-', 5, '非常好，很漂亮，老弟很喜欢，响应速度，外观，性能都很不错，除了是板载内存，硬盘不能自己加外，都挺不错的，但这两个缺点是真的隔应，后续看看质量吧', '轻薄电竞R9000X', '2023-01-18 11:13:39', 4);
INSERT INTO `data` VALUES (13398, 'L***光', 5, '超值&rdquo;游戏利器&mdash;&mdash;搭载AMD锐龙7 5800H以及RTX 3060显卡、16GB双通道内存、512GB SSD，拥有2.5K分辨率、165Hz刷新率16英寸屏幕的联想拯救者R9000P外观简约干练，硬朗冷酷\n\n　　联想拯救者R9000P的外观有浓厚的家族基因&mdash;&mdash;简约干练，却透露着硬朗冷酷的味道。\n\nA面中间为可控&ldquo;Y&rdquo;灯，很有辨识度。两侧对称的腰线增加了A面的层次感。此外，该机A面与D面均为金属材质，细腻的表面手感和质感都让人印象深刻，可以说一上手就能感受到扎实的做工。\n当然超高屏占比还可以提升视觉代入感，不过联想拯救者R9000P屏幕的优点还不止于此。这块16英寸屏幕拥有2560X1600高分辨率、165Hz高刷新率、100%sRGB高色域、3ms个高速响应时间、G-Sync与FreeSync双料防撕裂等特性，可以带来更细腻、逼真且顺畅的游戏画面。', 'R9000P/RTX3060/R7/165Hz 2.5k屏', '2021-09-22 10:21:38', 9);
INSERT INTO `data` VALUES (13399, 'w***G', 5, '包装保护：外面一个京东快递的包装，里面是联想的包装，保护的很好，产品毫发无损\n跑分评测：挺好的，120多万的跑分\n运行速度：很快，一点不卡\n外形外观：很好看的外观设计，尤其那个大Y灯真的好看\n游戏效果：还没试\n画面品质：挺好的，我感觉', '【销量先锋】专业电竞R9000P', '2022-11-04 18:16:34', 4);
INSERT INTO `data` VALUES (13400, '天***影', 5, '外形外观：精致简洁轻薄电竞感金属感强。\n包装保护：无损保护完好\n画面品质：2.5k很细腻很色彩\n跑分评测：核显都能跑92万多分\n运行速度：很快秒开\n游戏效果：主流游戏都流畅\n此型号联想笔记本电脑性价比高，外观好看便携，amd6800的续航强，游戏核显独显都很强，强力推荐。', '轻薄电竞R9000X', '2023-01-27 20:02:30', 4);
INSERT INTO `data` VALUES (13401, 'j***E', 5, '提高生产力，就得靠它了，爱不释手，妈妈送的新年礼物，我太爱了，每天用它听网课，做笔记。心情美美哒。各种美图天天都在朋友圈里秀。真的老铁，用一件趁手的兵器,武功都会变高呢！', '【销量先锋】专业电竞R9000P', '2023-01-22 18:53:55', 4);
INSERT INTO `data` VALUES (13402, 'j***w', 5, '包装仔细，没有破损，京东快递送货上门，16英寸超高屏，专属可控大Y灯，4出风口强大散热，超跑排气管出风设计，原感键盘，便携快充大容量电池，告别续航焦虑，推荐购买', '【震撼新品】专业电竞R9000P', '2022-07-20 20:14:55', 5);
INSERT INTO `data` VALUES (13403, 'j***2', 5, '一直都在用联想的电脑，这是第二款拯救者，质量都很好。\n包装:很精致\n画面:玩游戏，看电影，办公都能完美匹配。\n跑分:120+万，还可以\n运行速度:非常棒\n系统:W11系统用着不太习惯', '轻薄电竞R9000X', '2023-01-17 08:28:52', 4);
INSERT INTO `data` VALUES (13404, '张***国', 5, '包装保护：很好完美包装\n外形外观：漂亮炫酷十足\n画面品质：清新脱俗\n跑分评测：刚刚的，可以\n运行速度：非常快。激情澎湃', '【销量先锋】专业电竞R9000P', '2023-01-18 14:41:17', 5);
INSERT INTO `data` VALUES (13405, 'j***g', 5, '外形外观：做工简洁，机器质感优秀，手感很好，AD金属面非常上档次！！\n画面品质：这块屏幕就是彻彻底底的加分项，效果太好了！细腻清晰，颜色也好！！\n跑分评测：跑分也是一众同等配置机型中的佼佼者，数一数二的性能发挥！！！\n运行速度：速度很快很流畅！！！\n\n买之前也对此了很多竞品机型，有机械的钛钽plus，微星GP76，最终选择了R9000p，非常满意！！！', 'R9000P', '2021-04-08 14:20:07', 8);
INSERT INTO `data` VALUES (13406, 'j***z', 5, '包装保护：非常好\n外形外观：包装完好，快递也很快，机子用着也很快很流畅，以前需要装半天的软件很快就装好了，下载和传输速率也很快。游戏还没有玩，等到时候来追评谈感受。\n画面品质：2k屏的感觉确实很棒', '【销量先锋】专业电竞R9000P', '2022-12-10 11:05:46', 6);
INSERT INTO `data` VALUES (13407, 'j***U', 3, '打游戏也可以说是非常不错了', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2021-11-07 21:15:25', 5);
INSERT INTO `data` VALUES (13408, '旺***呀', 5, '外观：设计新颖，好看\n系统：系统流畅，反应迅速，指纹识别很快\n画面：特别特别清晰\n运行速度：超级快\n包装：很密实', '轻薄电竞R9000X', '2023-02-09 13:22:43', 4);
INSERT INTO `data` VALUES (13409, 'j***o', 5, '包装很好，有京东快递的盒子，盒子没有破损，内部电脑箱子上有联想的封条，都是没有破损的全新机器，快递很快，次日达，电脑真是惊艳到我了，很薄全金属机身，双A平台的贴纸在B面上俨然这台机器就是一台&ldquo;西装**&rdquo;啊。R7-6800H处理器真的性能很高，我这台配的是6600S的显卡，对标RTX3060，暴打3050的一块卡啊，我相信A卡战未来！所以一定要支持AMD。用了这么久也没有什么问题，价格也很合理，AMD品质联想品质点个赞！', '轻薄电竞R9000X', '2023-02-09 10:50:55', 6);
INSERT INTO `data` VALUES (13410, 'w***9', 5, '这款笔记本拯救者r9000p运行速度非常快，很清晰，颜色绚丽，收到拆开箱子就非常喜欢，看着就高大尚，键盘手感也很棒，非常顺畅。', '专业电竞R9000P', '2022-10-18 22:20:03', 5);
INSERT INTO `data` VALUES (13411, 'j***y', 5, '电脑很好用，模拟器多开玩手游岗岗的一点不卡，系统很好，很纯净，满意的一次购物。以后就看耐用性了', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-01-25 13:41:55', 6);
INSERT INTO `data` VALUES (13412, '袅***y', 5, '好看，很炫酷听歌真的很好听，音效像耳机\n包装保护：很完整，最外面的纸盒也保护的很好\n外形外观：就很炫酷，冰冰凉凉的全金属机身\n画面品质：永远滴神，打游戏巨清晰\n跑分评测：不知道，挺好的吧，我不太懂\n运行速度：不知道\n游戏效果：超赞，非常好', '【销量先锋】专业电竞R9000P', '2022-11-07 17:51:24', 4);
INSERT INTO `data` VALUES (13413, 's***n', 5, 'A面低调，屏幕很好，够大够亮。最主要的是大电池，就算是我用不上，也喜欢大数字。', '轻薄电竞R9000X', '2022-12-26 11:55:05', 3);
INSERT INTO `data` VALUES (13414, 'j***e', 5, '包装保护：用了两层包装盒很结实，收到货盒子没有破损情况！\n外形外观：电脑很美观，有质感，科技感很足\n画面品质：画面很清晰，4K播放很完美\n运行速度：处理速度很快，开机也快，下载需要的软件后开机只要7秒', '【销量先锋】专业电竞R9000P', '2022-11-16 12:49:14', 5);
INSERT INTO `data` VALUES (13415, 'j***v', 5, '电脑很棒，外壳很有质感，键盘也不错，屏幕细腻，运行速度更是没得说！能用好多年了，总体来说非常满意！', '【销量先锋】专业电竞R9000P', '2022-11-11 20:25:14', 5);
INSERT INTO `data` VALUES (13416, '北***宝', 5, '头天下单第二天上午送到，还是一如既往的快捷给力！\n这款电脑造型充满机械感，见棱见角，典型直男风格。\n开机速度很快，对得起在CPU上花的大洋。\n键盘、屏幕、外壳做工精良。\n电脑本身重量在接受范围之内。\n不错的电脑。', '【销量先锋】专业电竞R9000P', '2023-03-15 21:12:12', 4);
INSERT INTO `data` VALUES (13417, '马***胜', 5, '本本做工不错，金属质感很强，屏幕开阔，看电影音效满足学生党。宿舍打游戏超频空间挺大，秒开机，迅速抵达战场。同学看了都说好。', '轻薄电竞R9000X', '2023-02-28 12:58:22', 6);
INSERT INTO `data` VALUES (13418, '东***东', 5, '双十二之前活动价买的，基本是这个价位最高的性价比了，屏幕素质很好，机器全新，没有坏点，娱乐大师跑分133万分，机身三面金属，质感很好，接口少的问题可以几十块钱买个扩展坞解决，除了板载内存外没有明显的缺点了，现在有刚性需求的小伙伴们可以无脑入，双A配置也可以起飞！！！', '轻薄电竞R9000X', '2022-12-14 22:24:44', 7);
INSERT INTO `data` VALUES (13419, '赫***启', 5, '包装保护：非常棒，纸壳厚度防止磕碰，笔记本的外观非常时尚漂亮，画质清晰分辨率高，正好淘汰自己用的本也换个好的感觉一下，显卡性能还是很强悍的，运行速度没得说，不太会玩游戏显卡没问题够自己用，联想LoGo也很漂亮，非常满意', '专业电竞R9000P', '2022-09-17 13:29:42', 5);
INSERT INTO `data` VALUES (13420, 'u***l', 5, '刚收到电脑，开箱检验一下，没有磕破，完美！配置高，开游戏全开，流畅，太给力了！值得推荐', '【销量先锋】专业电竞R9000P', '2023-03-13 19:21:11', 5);
INSERT INTO `data` VALUES (13421, '小***c', 5, '包装保护：京东物流没的说，下单的第二天就送到了。包装很严实，好评！\n外形外观：R9000P的外观最经典，A面的Y形灯点亮非常好看且有质感。\n运行速度：运行速度真的是杠杠的，锐龙7系处理器真的很强！搭配RTX显卡一起，网游和大型3A单机游戏运行起来也是毫无压力！\n画面品质：2.5k分辨率的屏幕无需多言，冲就完事了！', '专业电竞R9000P', '2023-02-02 18:51:54', 4);
INSERT INTO `data` VALUES (13422, '哈***清', 5, '外形外观：非常满意，金属外壳，很有质感\n跑分评测：跑分120w\n\n画面品质：画质也很清晰\n运行速度：运行也很快', '轻薄电竞R9000X', '2023-02-08 20:58:22', 4);
INSERT INTO `data` VALUES (13423, '角***湛', 5, '外观：很商务，很有范儿\n性能：满足个人的所有需求，运行速度也很不错\n屏幕：2.5k，高刷新率，高色域，显示效果很好很好', '轻薄电竞R9000X', '2023-02-10 22:34:22', 4);
INSERT INTO `data` VALUES (13424, '王***8', 5, '非常喜欢这款拯救者r7000p 性能爆炸颜值超高\n外形外观：外形时尚美观\n画面品质：高清份倍率高刷新率\n游戏效果：世面游戏随便玩\n包装保护：包装非常好没有磕碰\n运行速度：开机速度非常快也就几秒', '专业电竞R9000P', '2022-08-13 11:45:28', 4);
INSERT INTO `data` VALUES (13425, '影***夏', 5, '第二天游戏本就收到了 京东就是快。质量很不错 喜欢双面的金属设计 摸上去手感很好 键盘按起来也很棒 运行操作很流畅 屏幕显示很清晰 分辨率很高 看起来舒服 总体很不错', '【销量先锋】专业电竞R9000P', '2023-03-10 15:07:22', 4);
INSERT INTO `data` VALUES (13426, 'j***W', 5, '性能满足要求，时隔多年之后重回A卡阵营，双A平台功耗低，待机时间长，R9000X是一台日常办公和游戏都能兼顾的笔电，轻度游戏还是很不错的，重量控制的很好。配合固态的移动硬盘512G的存储也没什么问题。', '轻薄电竞R9000X', '2023-03-02 08:36:41', 5);
INSERT INTO `data` VALUES (13427, '我***5', 5, '外甥读大学了，送给外甥的礼物，他很喜欢，配置OK，外观也非常大气，性能OK，绝对够用了，用来画图，平常游戏也杠杠的', '专业电竞R9000P', '2022-08-28 20:07:03', 2);
INSERT INTO `data` VALUES (13428, 'M***8', 5, '收到笔记本半个月了，使用感受很好，开机速度非常快，运行速度也很快，散热非常棒，日常都用不到野兽模式，静音模式办公足以！机器包装的很仔细，是全新的机器，7月25日生产的，硬盘和内存都是三星的，品控也很到位，是非常满意的一次购物！', '轻薄电竞R9000X', '2022-11-14 15:18:27', 4);
INSERT INTO `data` VALUES (13429, '零***c', 5, '包装保护：包装的很好，两层材质包装，防止破损；\n外形外观：简约大气，16寸的屏幕看着舒服，不累眼睛?；\n画面品质：画质清晰，2.5K的屏幕；\n跑分评测：还没有跑分，应该很高。\n运行速度：速度流畅；\n游戏效果：还没开始玩游戏。', '【销量先锋】专业电竞R9000P', '2022-11-16 17:08:17', 3);
INSERT INTO `data` VALUES (13430, 'j***m', 5, '外观非常棒，大标很张扬很喜欢，手感很棒，冷天不冻手，性能也超强！总之非常喜欢！就挺棒！很满意', 'R9000P', '2021-04-09 12:18:44', 7);
INSERT INTO `data` VALUES (13431, '夏***6', 5, '入手十几天了，整体使用起来也可以，古墓丽影开全特效也能流畅玩儿。很不错', '轻薄电竞R9000X', '2022-12-26 11:57:48', 4);
INSERT INTO `data` VALUES (13432, '小***爸', 5, '包装保护：很有仪式感的包装很喜欢\n外形外观：93%的屏占比看着很爽\n画面品质：色彩还不错\n运行速度：还挺流畅的', '轻薄电竞R9000X', '2022-11-16 12:15:46', 1);
INSERT INTO `data` VALUES (13433, '贺***璋', 5, '包装保护：外表无破损,非常好\n外形外观：很好看\n画面品质：还可以\n跑分评测：跑分的非常给力,居然能跑到12万分以上\n运行速度：运行速度非常快,超出了我的想象,直接爱了\n游戏效果：非常流畅非常好,无压力畅玩各种3A大作', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2021-11-03 01:55:46', 9);
INSERT INTO `data` VALUES (13434, 'j***6', 5, '这质感太好了，全金属就是感觉好看一点，我这台9月份产的，品控感觉挺好的，没有任何瑕疵，第一次用大屏感觉好大，2.5k16:10还不错，用着非常舒服。', '轻薄电竞R9000X', '2023-01-10 10:37:30', 6);
INSERT INTO `data` VALUES (13435, 'j***z', 5, '包装保护：全方位保护\n画面品质：高清色彩逼真\n运行速度：秒开当天下单下午\n游戏效果：效果拉满\n\n物流很快，晚上下单，第二天中午就到', '【销量先锋】专业电竞R9000P', '2023-03-08 18:19:25', 2);
INSERT INTO `data` VALUES (13436, 'w***3', 5, '包装保护：包装很完美。保护的也很好，有两层保护\n外形外观：没有破损之类的问题\n画面品质：2.5k还行，就是可能还没习惯。\n跑分评测：115左右，挺好的！\n运行速度：开机很快，打开软件速度也很快\n游戏效果：终于可以完美的完apex了，小针一扎，不是白给就是', '专业电竞R9000P', '2022-09-11 20:45:12', 3);
INSERT INTO `data` VALUES (13437, 'l***6', 5, '画面品质：画质超级棒，清晰，细腻，色彩靓丽。看世界杯享受。\n外观也够吸引眼球。\n配置更是相当可以，运行绘图软件顺畅。', '【销量先锋】专业电竞R9000P', '2022-11-27 17:04:04', 4);
INSERT INTO `data` VALUES (13438, 'j***u', 5, '电脑收到了，安全下车，我这电脑买转了，三星的固态，华星屏幕，物流也很快哟，晚上下单，第二天下午就到了，\n运行速度：运行速度非常快，想要入手，电脑的铁子剁手剁手快剁手。', 'R9000P/RTX3060/R7/165Hz 2.5K新', '2022-03-05 20:36:09', 6);
INSERT INTO `data` VALUES (13439, 't***贝', 5, '非常好电脑性能：非常好快递收到了，感谢店家；电脑收到了，用了几天感觉很好用，内存很大，屏幕清晰， CPU 运行顺畅，值得拥有，推荐给大家更显高端大气，全尺寸键盘独树一帜，方便我出差进行移动网站优化等需求操作。', '【销量先锋】专业电竞R9000P', '2023-01-22 18:59:43', 4);
INSERT INTO `data` VALUES (13440, '-***1', 5, '电脑很好，开机速度很快，值得入手，现在购买性价比很高，真是一台非常不错的电脑，推荐大家入手。\n外形外观：非常酷炫\n画面品质：高清，看视频很好', '【销量先锋】专业电竞R9000P', '2023-03-14 22:12:11', 4);
INSERT INTO `data` VALUES (13441, '山***i', 5, '用了有半个月了，感觉非常棒。笔记本整体外观时尚潮流，轻薄小巧，方便携带，整体配置较为不错，显示屏细节清晰盈亮，对于我办公商务绰绰有余，银色版更显高端大气，全尺寸键盘独树一帜，方便我平时出差进行移动网站优化等需求操作。', '轻薄电竞R9000X', '2022-11-21 11:04:45', 4);
INSERT INTO `data` VALUES (13442, 'j***Z', 5, '包装保护：包装很严实，防伪贴还在，跳联网后安全下车，不过好像是四等奖=.=\n跑分评测：鲁大师两次都是118w分\n\n运行速度：玩了原神，画质不错', '【销量先锋】专业电竞R9000P', '2022-11-02 23:57:26', 6);
INSERT INTO `data` VALUES (13443, 'T***J', 5, '今年的新一代神机！7999运气好抢到了！配置可以说是完美了！2k屏幕出厂带校色软件，颜色比2020款的r7000p好看很多！500尼特高亮度！完美屏！5800+3060   面对目前主流游戏都没什么问题！经典版鲁大师跑分近60w！玩地平线4最高特效2k分辨率，平均126帧也是棒棒哒！', 'R9000P', '2021-04-09 21:49:58', 8);
INSERT INTO `data` VALUES (13444, '泣***情', 5, '比预期的要好好多，本来就是一眼看中，实体更是漂亮的没话说，还有散热器软件运行流畅，屏幕清晰，而且手感很不错，电池也耐用，机身很薄没有笨重感反正是很值得入手的一款。客服还是非常不错的，耐心解答，完美！', '轻薄电竞R9000X', '2023-01-20 22:32:25', 4);
INSERT INTO `data` VALUES (13445, '9***贝', 5, '心心念的电脑终于买到啦，拿到第一感觉特别棒，比之前的电脑质感好太多，检查了键盘，屏幕，散热都很完美，6800h加6800s完美搭配，不管是工作还是适度游戏都完美胜任，是我心目中的那台电脑～从发布就一直关注，过年了终于换上了新电脑，整理心情快乐出发！！！', '轻薄电竞R9000X', '2023-01-24 12:21:31', 5);
INSERT INTO `data` VALUES (13446, 'j***d', 5, '给小孩上大学用的，外包装有一点受损 好在机器完好无损，这款性能还是很好的 品控非常优秀', '【震撼新品】专业电竞R9000P', '2022-08-17 12:19:26', 4);
INSERT INTO `data` VALUES (13447, 'S***8', 5, '媳妇平时做点小设计，剪辑下视频，做做平面图之类的，没想买游戏本，出于有点私信，左挑右选，选择了联想拯救者R9000，各项配置完全够用，游戏很流畅，开启野兽那是杠杠的！外观大气，大Y标超级显眼，R7-6800H/RTX3060运行流畅，画质完美，游戏效果棒！京东物流依旧给力，外包装无破损，机器完美！', '【销量先锋】专业电竞R9000P', '2023-03-17 16:24:35', 3);
INSERT INTO `data` VALUES (13448, 'j***f', 5, '朋友推荐买的，收到货很喜欢，尤其是外面的大Logo，特意用了一段时间来评价的，无论是玩游戏，还是刷剧一点都不卡顿，而且它是2.5k的屏，看起来特别清晰，总之一句话，挺喜欢，个人还是比较推荐这一款', '专业电竞R9000P', '2022-08-22 10:16:32', 5);
INSERT INTO `data` VALUES (13449, 'j***n', 5, '包装保护：包装紧密严实，盒子整体设计简洁区明\n外形外观：模具整体设计和谐流畅，金属机身更显高端大气，键盘、标志灯光明亮素实\n\n画面品质：2·5k分辨率搭配15.6寸屏幕尺寸完美比例，极致清晰，高色域覆盖明媚鲜艳\n运行速度：秒开应用，游戏加载不超十秒，无需等待立即享受\n游戏效果：针对性优化，比同价位电脑性能更上一层楼，光线追踪技术真实', '专业电竞R9000P', '2022-06-12 14:11:11', 4);
INSERT INTO `data` VALUES (13450, '千***防', 5, '外形外观：外形漂亮质感很好，大小合适，金属表面，灯的颜色可调，背光键盘细节好评\n画面品质：屏幕细腻显示舒服非常好，2k分辨率看电影不错\n跑分评测：跑分中上满足日常需求，性能强劲，水桶机，办公娱乐都能满足，性能释放好\n包装保护：两层包装保护到位，完美无磕碰', 'R9000P', '2021-04-12 14:39:49', 6);
INSERT INTO `data` VALUES (13451, 'j***P', 5, '包装保护：有些破损，但总体不影响\n外形外观：很好\n画面品质：没有瑕疵很不错\n跑分评测：CPU烤鸡没有掉线的\n运行速度：很棒\n游戏效果：不错不错', '专业电竞R9000P', '2022-08-20 17:41:03', 4);
INSERT INTO `data` VALUES (13452, '烟***斯', 5, '包装保护：还是挺严实的\n外形外观：真的很帅，全金属\n画面品质：很强\n跑分评测：挺高\n运行速度：非常快\n游戏效果：3A大作稍微有点卡', '轻薄电竞R9000X', '2022-12-28 16:59:04', 3);
INSERT INTO `data` VALUES (13453, 's***g', 5, '外观全金属感觉非常不错，用起来挺好的，win11还需要适应下，暂时用途主要是办公，游戏体验后续更新', '轻薄电竞R9000X', '2022-11-16 20:15:25', 6);
INSERT INTO `data` VALUES (13454, '迦***开', 5, '笔记本包装的很好，京东送货很快，外形是金属质地，我很喜欢，AMD的CPU挺好的，屏幕够大，笔记本有一定的分量，总体来说还不错吧', '轻薄电竞R9000X', '2022-12-28 08:47:58', 4);
INSERT INTO `data` VALUES (13455, 'j***d', 5, '打算买了回家过年上午买下午到论速度还是很快的！！\n检查一下午确实没什么问题自营店的品控还是可以的！还有2k玩游戏太清楚了比我1080p主机清晰太多了！\n画面品质：强的', '【销量先锋】专业电竞R9000P', '2023-01-01 21:57:58', 7);
INSERT INTO `data` VALUES (13456, 'j***r', 5, '发货速度快，当时我考虑华为笔记本和小米笔记本荣耀笔记本这三个机型，三天时间我把这三款都研究一遍，最终选择小米红米2022版锐龙版R7-6800-16-512固态硬盘+3.2k屏幕这款性价比最高值得推荐\n运行速度：刚收到电脑必须插电源才能开机，运气速度很好，静音不错\n屏幕效果：15寸屏幕，耐看型屏幕，非常不错\n散热性能：电脑运作非常好，用4-5小时机身一点不发热\n外形外观：漂亮???\n轻薄程度：我个人觉得非常不错\n其他特色：屏幕3.2k 办公非常不错\n散热能力：非常好\n运行速度：非常好，性价比很高', '新Redmi Pro 15英寸 3.2K屏', '2022-12-03 23:56:40', 8);
INSERT INTO `data` VALUES (13457, 'j***7', 5, '电脑总体很可以，性能挺好的，外观也可以，运行速度也很快，屏幕也很清晰透彻，颜色也挺不错，看电视用它的话，我觉得也很可以，音质也很nice。\n散热能力：挺不错的只是声音有点小大，但是过会儿就没有声音了散热挺快的。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-18 23:04:35', 6);
INSERT INTO `data` VALUES (13458, '花***动', 5, '运行速度:很好。\n屏幕效果:非常棒，显示效果很细腻。\n散热性能:看底部的散热孔，散热应该很棒。\n轻薄程度:这个厚度，我很喜欢。\n外观:非常喜欢这个外观，很时尚。\n总结:价格合适，最强核显，工作之余玩游戏也是可以的。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-03 21:55:49', 5);
INSERT INTO `data` VALUES (13459, '燕***斌', 5, '运行速度：刚使用两天，运行速度还比较快，后期追评反馈，主要是win11用着也很舒服\n屏幕效果：屏幕显示细腻，不愧是高清显示屏\n散热性能：散热还可以，目前还没玩大型游戏\n外形外观：外观非常简约，看着高端大气\n轻薄程度：很轻很薄，携带方便\n其他特色：小米手机传输文件方便，比较友好，其他还在摸索中，后期追评。', '锐龙R5六核|2.5K高色域屏', '2022-06-24 17:45:05', 9);
INSERT INTO `data` VALUES (13460, 'J***9', 5, '运行速度：新机器运行速度棒\n屏幕效果：显示屏显示效果清晰\n散热性能：散热性能很好\n外形外观：外观设计非常时尚\n其他特色：小米的产品一直都很棒\n轻薄程度：很轻薄，出门携带方便\n散热能力：使用一晚上感觉很好', '新Redmi Pro 14英寸 2.5K屏', '2023-01-12 11:13:46', 6);
INSERT INTO `data` VALUES (13461, '手***刀', 5, '10年米粉，对小米系产品一直青睐有加。这款笔记本电脑同样没让我失望。做工精细，手感舒适，金属质感十足，整体轻薄有加。系统运行流畅，电量持久，中度使用，2天一充，很有安全感。屏幕显示细腻鲜艳。这款小米 Redmi BookPro 15 2022太超值了！力荐！', '新Redmi Pro 15英寸 3.2K屏', '2022-08-29 13:56:45', 9);
INSERT INTO `data` VALUES (13462, 'j***a', 5, '已经用了redmibook pro15 2022锐龙版r7-6800h两周的时间了，来说一下使用体验。\n首先是电脑屏幕特别好，3.2k，用来看视频很舒服很清晰，我看4k现场版演唱会视频真的是一种享受。90hz高刷，打游戏真的画面很流畅。\n其次是做工，cnc一体工艺，因为我之前用的是macbook air，所以我特别喜欢这种一体金属外壳，这也是我选择这款的一部分原因。同时金属外壳被动散热效果也挺好的，开启高性能模式运行大程序的时候，能够感觉得到不会过热。\n说到散热，双风扇，散热性能不错，同时风扇声音不会像游戏本声音那么大，没有啸叫的情况，离开半米就不怎么听得到了。\n性能方面，数据都看得到，这颗集显，真的6，我就直接说使用情况。打守望先锋开高质量画面，3.2k90hz分辨率，除了风扇转打游戏无压力，原神高质量画面同样流畅，lol、csgo、cf等等更不用说一样无压力，基础网络游戏都没问题。\n售后上，我直接去小米售后，免费检测咨询之类的，给你当场解答，挺满意的。\n其他一些细节就不多赘述了。指纹解锁，100w氮化镓快充还很便捷携带，京东自营服务不错跨区域调货提前一天到，小米客服也很好有不懂的也', '新Redmi Pro 15英寸 3.2K屏', '2022-11-17 23:42:52', 8);
INSERT INTO `data` VALUES (13463, '大***葭', 5, '看了挺久才选的这个轻薄本，之前的老游戏本很重而且充电器很大一点儿都方便，这个笔记本的充电器很方便，办公和轻度娱乐完全够，一只手就能开合，平时日常办公完全没有风扇音，锐龙的处理器平时使用电脑没有热感，这个价位非常值得入手！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-10 23:09:14', 6);
INSERT INTO `data` VALUES (13464, '安***w', 5, '这一代的redmibookpro质感很好，使用起来也很流畅，惊艳的是屏幕，亮度提升了，3k屏幕整体的感官很好，清晰度杠杠的，90的刷新率日常使用能感觉到一点区别，界面动画要流畅些，感官不错！整体造型非常好看，CNC的机身刚性很好，适合出差携带，不用担心机身变形。音质还不错，立体声，推荐！', '新锐龙标压R7|3.2K高色域大屏', '2022-07-23 16:37:32', 4);
INSERT INTO `data` VALUES (13465, '机***哥', 5, '运行速度：超级顺滑，锐龙R7 6800H CPU杠杠的\n屏幕效果：显示效果更好，屏幕比较细腻\n散热性能：良好\n外形外观：简洁美观\n轻薄程度：比较轻薄\n其他特色：相比上一代，核心显卡提升很大，比得上MX550的独立显卡了', '新Redmi Pro 15英寸 3.2K屏', '2022-08-29 23:07:02', 7);
INSERT INTO `data` VALUES (13466, '张***呀', 5, '运行速度：AMD yes,优化可以，速度杠杠的。\n屏幕效果：这个屏幕在这个价位无敌。\n散热性能：两个风扇吹，还是可以的。\n外形外观：质感很好，一流水平。\n轻薄程度：很适合学生党，携带方便。', '新锐龙标压R5|3.2K大屏-RTX独显', '2022-06-02 17:34:31', 8);
INSERT INTO `data` VALUES (13467, '辉***6', 5, '运行速度：非常快。\n屏幕效果：屏幕效果：屏占比高，显示效果好。\n外形外观：金属机身，高端大气。\n轻薄程度：很薄很轻，方便随身携带。\n\n满意，五星好评。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-03 17:11:07', 4);
INSERT INTO `data` VALUES (13468, 'j***l', 5, '笔记本工艺精致，手感舒服，质量和手机一样棒，速度杠杠的，鲁大师评分100多万分，画质精细，正版office 2021,可以玩原神游戏，其他网络游戏不在话下！', '新Redmi Pro 15英寸 3.2K屏', '2023-01-17 22:37:16', 9);
INSERT INTO `data` VALUES (13469, 'u***h', 5, '给妹妹买的礼物，她的第一台电脑。物流相当快！外观完美配置也非常不错性价比很高！关键是屏幕也非常好特别细腻颜色出众，小米的产品一直都是很让人放心的家里的生态也基本都是小米的了。', 'Redmi Pro 14英寸 2.5K屏', '2022-12-13 15:28:22', 8);
INSERT INTO `data` VALUES (13470, '爱***瑾', 5, '运行速度：运行很快，满意。\n屏幕效果：显示细腻，满意。\n散热性能：散热很好，满意。\n外形外观：金属感强，满意。\n轻薄程度：轻薄刚刚好。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-11 19:49:06', 4);
INSERT INTO `data` VALUES (13471, 's***o', 5, '物流非常快，京东速度无敌。电脑质感很棒，颜色款式都很好，屏幕单手开合，充电器和接口好评，可以和小米手机互用。屏幕素质无敌，3.2的视网膜屏幕显示细腻，颜色亮度也很好。正在学习新系统，上手中。', '新锐龙标压R7|3.2K高色域大屏', '2022-06-12 16:01:18', 8);
INSERT INTO `data` VALUES (13473, '静***儿', 5, '第二次购买，指纹识别很快，指纹识别很灵敏，识别率很高，识别率高，小朋友的就稍微差点，屏幕不错，主要用来上网课，屏幕比较重要。想买的别犹豫哇！没有廉价的感觉，很高端，特别棒！已经收到啦，很不错，性价比太高啦，爱了爱了', '新Redmi Pro 15英寸 3.2K屏', '2022-12-11 19:09:45', 4);
INSERT INTO `data` VALUES (13474, 'j***g', 5, '电脑很不错，开机很快，外观也很精致，很喜欢，本来想买联想Pro 16 最后买了，这个很惊喜，感觉比联想要好 屏幕素质很好，充电器很小巧出差的话，只带这个小充电器就可以了，没有很大的适配器这点我很喜欢缺点的话就是插口少了一两只有一个插口需要配合扩展屋使用。  总体来说很棒，我很喜欢这次购物很满意', '新Redmi Pro 15英寸 3.2K屏', '2022-11-20 20:31:03', 9);
INSERT INTO `data` VALUES (13475, 'j***s', 5, '运行速度：开机很快，就跟唤醒屏幕一样，一下就开了。\n散热性能：不会很热，就正常的温度。\n外形外观：外形外观：看了网上的测评说会割手，实际使用感受并没有，放心入。\n轻薄程度：很轻薄，很满意。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-19 22:32:05', 7);
INSERT INTO `data` VALUES (13476, 'c***m', 5, '运行速度：AMD YES！速度快，开机只需8秒\n屏幕效果：2.5K屏幕色彩炫丽明亮\n散热性能：散热良好，也比较静音\n外形外观：没的说，CNC一体化铝制，近乎完美\n拿到手开箱就惊艳了！轻薄机身，CNC一体化铝制外壳，拿在手上颇有某果的手感，开机速度不是盖的，8秒开机。运行程序流畅，散热良好静音，16GB+512，2.5K屏幕，堪称性价比之王，非常值得入手。', 'Redmi Pro 14英寸 2.5K屏', '2022-08-22 11:58:12', 9);
INSERT INTO `data` VALUES (13477, '猫***y', 5, '双十一买的，第一次买小米的产品，抢到过，雷子良心啦。活动价4999买的。就这配置我觉得办公室办公，完全够用啦，pp图剪业余做做设计类的，很OK，主要是颜值高，没有接口方面，没有太多需求，完全够用，使用了半个月，目前没有任何问题。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-14 10:54:55', 8);
INSERT INTO `data` VALUES (13478, 'j***a', 5, '送货很快，配送及时，电脑外观很精致，屏幕显示很清晰，色彩画面很好，运行配置很实用，学习，娱乐很方便，运行很快，很好的一次购物体验。', 'Redmi Pro 14英寸 2.5K屏', '2022-10-20 12:47:51', 5);
INSERT INTO `data` VALUES (13479, 'j***0', 5, '屏幕效果：非常nice，绝对满足日常需要\n运行速度：相当之流畅，再也不用等了\n散热性能：风扇工作声音很小，几乎不影响心情\n外形外观：手感十足，金属材质质感直接拉满，且键盘回弹也很柔和', '新Redmi Pro 15英寸 3.2K屏', '2022-08-27 01:35:34', 3);
INSERT INTO `data` VALUES (13480, '绝***意', 5, '运行速度：非常流畅，大型网游毫无压力\n屏幕效果：很好\n散热性能：风扇声音很小，散热良好\n外形外观：CNC工艺，铝合金材质，很有质感\n轻薄程度：简约时尚，轻薄便携\n散热能力：双风扇\n运行速度：开机速度飞快，运行流畅，不卡顿', '新Redmi Pro 15英寸 3.2K屏', '2022-11-09 14:07:17', 6);
INSERT INTO `data` VALUES (13481, '久***寿', 5, '是正，和实体店一样，价格还优惠，果断转粉质量非常好，完全超出期望值，发货速度非常快，包装非常仔细、严实，很满意的一次购物很好看，制作工艺很精美，材质也很好！给个赞！', 'Redmi Pro 14英寸 2.5K屏', '2022-11-20 10:15:24', 9);
INSERT INTO `data` VALUES (13482, '你***哦', 5, '轻薄程度：带着去教室很方便，比较轻\n外形外观：颜值很高，很喜欢\n散热性能：玩GTA5温度不是特别高，可以接受\n屏幕效果：用了之后就再也不想用以前的电脑了\n运行速度：用了十几天，运行速度很快', '新Redmi Pro 15英寸 3.2K屏', '2022-11-17 08:06:13', 6);
INSERT INTO `data` VALUES (13483, 'h***0', 5, '我买的是 Redmi Book Pro 15 2022锐龙版。它传承了Redmi产品高性价比、高品质的一贯特点。这台机器的外观设计精湛，金属顶盖加上CNC工艺提升了整体质感，为颜值加分。高性能的 AMD 锐龙7 6800H处理器和RDNA 2架构的集成显卡则令它性能十分强悍，无论高负载办公还是游戏娱乐，都能轻松应对。特别是强劲的图形性能，让用户能够在1080p高画质下畅玩大多数热门网游，推荐！', '新Redmi Pro 15英寸 3.2K屏', '2023-03-05 14:02:41', 7);
INSERT INTO `data` VALUES (13484, '了***8', 5, '外观灰色非常高大上，开合阻尼感也做的刚刚好，屏占比很高2.5k高色域90hz的屏幕效果也更好，6800h的u不光可以办公，还能玩3a?', '新Redmi Pro 15英寸 3.2K屏', '2022-11-03 19:44:13', 4);
INSERT INTO `data` VALUES (13485, 'a***傲', 5, '首先这个物流很快，然后是说下外观做工吧，还是非常惊喜的，一如既往地小米高品质高颜值，再有这大促价位，?分妥妥的；配置性能非常赞，但是不玩游戏的话，学生用也足够了，这价格放到几年前只能买傻大黑粗的学霸本，时代变了，为小米点赞！对了，适配器也非常赞哦，非常小巧，而且还很美观，还可以为手机充电，出差只带一个充电器，美滋滋！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-11 20:05:05', 7);
INSERT INTO `data` VALUES (13486, 'j***3', 5, '电脑用了一个月感觉不错，一般般的游戏也可以玩，用着特别流畅，不卡。cad也带的动。电池容量也不错，开机速度也特别快。客服服务特别好，也特别专业。小米有这么牛的专业客服真的很厉害，有问题解决问题。比较推荐大家购买也较为划算', '新Redmi Pro 15英寸 3.2K屏', '2023-03-19 18:06:34', 4);
INSERT INTO `data` VALUES (13487, '遍***了', 5, '特意用了几天才来评价，非常不错，小米不愧为性价比之王，笔记本轻薄，待机时间也不错，平常用来处理文档，不看剧，不打游戏，打印文档，偶尔用ps处理一下图片，绰绰有余', '锐龙R5六核|2.5K高色域屏', '2022-07-12 12:19:34', 4);
INSERT INTO `data` VALUES (13488, '大***梨', 5, '外形外观：在网上对比了很多台电脑，CNC工艺的电脑外形看起来就是高端味，有质感，摸起来很舒适\n轻薄程度：比起以前我旧笔记本好太多了，上手第一感觉就是纤细，轻薄到接口都少\n屏幕效果：看重它是LCD屏幕，而且3.2K,观感细腻，色彩鲜艳，看得很舒服\n运行速度：AMD6系列处理器，强，功耗小，主要这代的核显性能强很多，基本可以玩市面游戏。', '新Redmi Pro 15英寸 3.2K屏', '2022-09-12 22:50:28', 6);
INSERT INTO `data` VALUES (13489, 'j***t', 5, '这款小米Redmi BookPro 14款，它是2022年锐龙版，4K多点价位，配置也是挺好的了，能满足很多想要性价比配置又好的朋友需求了，买来给媳妇上研，颜值高有便携，锐龙核显看剧完全没有压力，但是，除了电脑和充电器，没有任何配件，', '新锐龙标压R5|2.5K高色域屏', '2022-06-27 19:27:59', 4);
INSERT INTO `data` VALUES (13490, '萌***7', 5, '非常不错的轻薄本，值得购买！五千多的电脑能有这个水平，无疑是超值的。电脑性能非常，有三种模式选择，可以适合各种场景，从办公到轻度游戏，都非常给力。用料上乘，屏幕素质高。携带比较方便，电池续航能力超级优秀。100瓦的氮化镓充电器也非常不错，可以给各种小米红米的装备充电。', '新Redmi Pro 15英寸 3.2K屏', '2022-09-19 14:24:30', 7);
INSERT INTO `data` VALUES (13491, '素***尚', 5, '不错不错，这电脑 CNC一体工艺很好看，不会卡顿，客服很专业，有很多疑惑都帮我解答了，很推荐大家购买，电脑外观真心好看，摸上去手感很丝滑，值得购买!', '新Redmi Pro 15英寸 3.2K屏', '2022-11-25 20:34:55', 8);
INSERT INTO `data` VALUES (13492, 'j***X', 5, '我这是第一次买电脑，很不错，那块3.2k屏幕是是真的刚，看剧是挺舒服的，一体机身是很有质感的\n运行速度：速度很可以的\n轻薄程度：还是比较薄，不会觉得厚', '新Redmi Pro 15英寸 3.2K屏', '2022-11-11 23:48:09', 3);
INSERT INTO `data` VALUES (13493, 'h***丶', 5, '老电脑要退休了，看了一圈决定买这款，发货速度快，一拿到手开机就爱上了他。外形外观:银灰色很时尚，运行速度:开机很快，大概10几秒没细数，运行速度也好屏幕效果:很清晰，色彩也不错，亮度挺好散热性能:玩NBA2k最高画质，玩一会键盘中心区域会较热，但不是夸张的热，能接受轻薄程度:较轻薄，挺好的，算是全能本了其他特色:有待时间挖掘', '新锐龙标压R7|3.2K高色域大屏', '2022-07-23 10:44:43', 3);
INSERT INTO `data` VALUES (13494, '绿***8', 5, '运行速度：这个没得说，挺快的。\n屏幕效果：像素好，画面感很强。\n散热性能：配一个笔记本底座使用，效果非常好。\n外形外观：是我喜欢的类型。\n轻薄程度：超薄，方便携带。\n散热能力：很好，没有因此罢工。', 'Redmi Pro 14英寸 2.5K屏', '2022-08-25 17:19:20', 2);
INSERT INTO `data` VALUES (13495, '京***安', 5, '笔记本用的，很好用，买了一个，也是用来办公用的笔记本的质量不错，物流也很快\n运行速度：快\n外形外观：好看\n轻薄程度：轻巧\n运行速度：流畅', '新Redmi Pro 15英寸 3.2K屏', '2022-11-11 15:53:44', 7);
INSERT INTO `data` VALUES (13497, '拌***面', 5, '总体来说，Redmibook给我的感觉很不错，外观设计简洁，轻便之余还兼顾了性能，AMD,YES！日常办公娱乐使用是没问题的，游戏的话，平时只玩原神，只能说勉强能玩呢。总得来说，学习办公，没问题的，而且还有货。', '新锐龙标压R7|2.5K高色域屏', '2022-06-18 09:18:22', 3);
INSERT INTO `data` VALUES (13498, 'l***p', 5, '电脑很好，做工手感都不错，充电器也不算大。机器性能强劲功耗也不错，屏幕出场色温低了点，手动调到7500k就很舒服了。目前为止很满意。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-06 20:56:25', 7);
INSERT INTO `data` VALUES (13499, 'y***2', 5, '电脑很棒，开机秒开，3.2k的屏幕很清晰，屏幕色彩也很好，雾面屏不反光。6600h处理器性能强悍，运行速度很快，估计能用七八年，键盘手感也很舒服，这个价位真的超值', '新锐龙标压R5|3.2K高色域大屏', '2022-06-25 00:33:00', 7);
INSERT INTO `data` VALUES (13500, '漫***龙', 5, '运行速度：新本，运行一点都不卡\n屏幕效果：2.5K屏很优秀，色彩靓丽\n散热性能：散热不错，声音很小\n外形外观：外观很亮眼，轻薄优秀', 'Redmi Pro 14英寸 2.5K屏', '2022-08-17 16:15:21', 7);
INSERT INTO `data` VALUES (13501, 'u***8', 5, '主要看中性价比，整体感觉不错，散热很好，续航八小时以上，办公追剧选择它不会错。', '新Redmi Pro 15英寸 3.2K屏', '2023-01-24 17:07:21', 9);
INSERT INTO `data` VALUES (13502, '小***丶', 5, '【优点】\n①续航真的很给力，开个Fn+k换成冷静模式，日常做个ppt，追个剧可以干到6h亮屏时间续航，再精心调教一下我认为多出1-2h亮屏时间问题不大（冲击7-8h续航）。\n②性价比是真高，4999到手的6800H版本，香死了好不好！！ 核显挺强的，不用担心一般的大型游戏流畅度。\n③充电速度个人认为挺快的，100w 氮化稼充电器，体积控制的可以说很好了，双typ-c设计盲插到底，可以给手机充电，这个是真的方便！！！\n④MIUI+挺方便的，还有小爱同学按键，随时呼唤\n⑤赠了一年WPS会员我要爽死了。记得打开wps领取，点一下就领到了，还好没错过！\n⑥金属机身是真的高级（有mac那味儿了），1.8kg放在背包里很方便，不重。\n⑦指纹解锁很方便，可以录好几个哈哈哈。哪个手指方便用哪个。\n  【总评】总体来说体验还是可以的，主要爽在性价比高，续航，便捷性好~ 在轻薄本里可以说是不错的选择。\n毕竟，4999冲到的R7-6800H，你还想要什么自行车。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-18 18:52:14', 1);
INSERT INTO `data` VALUES (13503, 'S***S', 5, '晚上下单早上就收到货了，新电脑就是好用，运行速度很快，为了稳定专门选的标压版本的，设置也比较简单，期待后面也系统稳定，先给好评，\n运行速度：快，\n屏幕效果：还可以，\n散热性能：没感觉到热，\n外形外观：金属外观，手感和视觉都很好，\n轻薄程度：挺薄的，不算厚。\n散热能力：很好。', '新Redmi Pro 15英寸 3.2K屏', '2022-09-11 13:18:50', 2);
INSERT INTO `data` VALUES (13504, 'F***飞', 5, '发货速度很快！晚上10点下单早上就收到了！绝绝子！\n包装很好，外观很精美！AMD的处理器是极具性价比的！很棒！\n16g内存很够用！家用办公看剧，完全够了！\n512g硬盘，快速响应！好样的！如果需要肯定喜欢还会购买！', '锐龙R5六核|2.5K高色域屏', '2022-08-12 17:40:15', 9);
INSERT INTO `data` VALUES (13505, '0***-', 5, '真的是惊艳到了。拿到手的第一感觉就是精致，cnc一体精雕工艺真不是盖的，甚至有种macbook的感觉。到手开合轻而易举。屏幕很好，3.2k，看着就舒服。锐龙r76800h，速度确实快，跑分100万，接口不算特别丰富，也不算特别少，刚刚好，平时会用的都有。值得推荐', '新Redmi Pro 15英寸 3.2K屏', '2022-11-22 18:40:07', 6);
INSERT INTO `data` VALUES (13506, '谭***樂', 5, '笔记本使用了一段时间还是比较可以的，像玩一些彩虹6号呀，然后一些英雄联盟原神都是带得动，普通的办公用起来也是非常的舒服，而且像有任何问题联系客服，的话都是非常专业的，我自己的手机啊，还有一些耳机，什么用品都是买的小米的，小米还是非常，用心用起来还是比较舒服，后续的话有任何问题都可以联系小米，感觉也是非常的售后比较舒服', '新Redmi Pro 15英寸 3.2K屏', '2023-01-03 17:51:29', 5);
INSERT INTO `data` VALUES (13507, '皓***7', 5, '笔记本很好，6800h日常运行无压力，还有完整的方向键，屏幕很高清，平时用来看剧什么的刚刚好\n屏幕效果：很优秀\n外形外观：cnc一体性，外观很好看\n散热性能：还行吧，玩游戏风扇也不会很吵\n轻薄程度：轻薄本偏重，但不会很厚', '新Redmi Pro 15英寸 3.2K屏', '2022-11-24 21:29:38', 5);
INSERT INTO `data` VALUES (13508, 'j***z', 5, '质感很好，允许速度真快，屏幕效果杠杠强，散热性能真好，外形外观超高颜值，特别轻薄，携带真方便，适合广大学生与商务办公', '新Redmi Pro 15英寸 3.2K屏', '2022-11-17 07:42:43', 7);
INSERT INTO `data` VALUES (13509, 'j***d', 5, '屏幕效果：要的就是这高分屏，色彩单人够用了\n外形外观：全金属，很有质感\n轻薄程度：很轻薄，刚好便携\n运行速度：新机，一点不卡，', '新Redmi Pro 15英寸 3.2K屏', '2023-02-20 02:19:39', 6);
INSERT INTO `data` VALUES (13510, '叶***扬', 5, '京东自营真是YYDS！隔日达没毛病！收到很及时。\n运行速度：很流畅，开机只要10秒不到。平时商务参公用为主，网页、办公软件、网盘、聊天软件用的多，一点不卡，程序全开，cpu最高时占比也才60%多，在可接受范围\n屏幕效果：很清晰，看着舒服润眼不难受\n散热性能：用了大半个月没有发现散热不好的情况\n外形外观：外形很精致，全金属外壳，科技感满满\n轻薄程度：厚度适中，不是最薄的但也不算重，出门携带很方便\n其他特色：大小很合我心意，另外买了一个内胆包，出门携带就方便了。喜欢用裸机，不贴膜，用着爽。价格3799，16G运行内存，500G固态硬盘，很划算了！', 'Redmi Pro 14英寸 2.5K屏', '2022-11-28 15:00:25', 5);
INSERT INTO `data` VALUES (13511, '坠***雨', 5, '非常漂亮的笔记本，非常好用，性价比高，值得购买。这处理器用来办公，玩网络游戏绰绰有余了。屏幕素质非常高，颜色显示很正，没有偏差，屏幕亮度也好。键盘打字非常舒服，完美。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-14 21:33:08', 6);
INSERT INTO `data` VALUES (13512, 'K***W', 5, '之前买了两台红米笔记本，拿去公司办公用。挺好用这次买小米自己用。当天下单当天到。收到马上激活。外观和屏幕绝对是顶级的。键盘手感舒服，比之前的红米好很多，配的100W氮化镓充电器超赞。', '新小米Pro 14英寸 2.8K屏', '2022-08-16 22:12:31', 7);
INSERT INTO `data` VALUES (13513, '昵***t', 5, '水桶机，屏幕细腻，刷新率也不错，尤其是金属质感真的超出了这个价位很多，颜值担当，音质也比想象中的好多了，性能不错，出差带着偶尔玩玩dota2。舒舒服服啊哈哈', '新Redmi Pro 15英寸 3.2K屏', '2023-02-16 21:18:29', 2);
INSERT INTO `data` VALUES (13514, 'j***0', 5, '这款电脑的做工非常精美，外观颜值也很高，系统流畅，显示屏的效果非常好。总体来说物超所值吧！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-13 00:31:38', 5);
INSERT INTO `data` VALUES (13515, '3***吟', 5, '轻巧便携，手感嘎嘎好，屏幕色彩饱满，很快完成激活，电脑是20号下单的，21号到的，快递速度还是很快的，电脑包装完整，无破损损，开机速度，运行速度还可以，R7 6800h处理器，屏幕15.6寸的很适合玩游戏，看电影，体验非常不错！', '新锐龙标压R7|3.2K高色域大屏', '2022-08-09 10:53:33', 6);
INSERT INTO `data` VALUES (13516, 'j***o', 5, '运行速度：不错\n屏幕效果：清晰，色彩鲜艳\n外形外观：轻薄，银灰色颜色大气，高档\n轻薄程度：非常轻薄，轻\n其他特色：相信小米家，相信国产\n \n给妹妹买的电脑，她收到后非常喜欢，笔记本轻盈，质感好，', '新Redmi Pro 15英寸 3.2K屏', '2022-12-31 09:40:10', 5);
INSERT INTO `data` VALUES (13517, 'j***j', 3, '快递快是快，包装属实一般。', 'RedmiBook Pro14锐龙', '2021-10-28 00:32:52', 4);
INSERT INTO `data` VALUES (13518, 'f***5', 5, '购买全程顺利。至目前，无发热、噪音等问题。\n运行速度：快，这个价位的这个做工，值得推荐\n屏幕效果：2.5K的屏果然不一样，显示细腻\n散热性能：刚刚拿到手，还没有烤机，全金属的散热应该很好。\n外形外观：漂亮，简约\n轻薄程度：轻薄易带，真心不错', '锐龙R5六核|2.5K高色域屏', '2022-08-15 10:09:54', 6);
INSERT INTO `data` VALUES (13519, 'v***大', 5, '很不错的笔记本，双十一活动还是不如618早知道不等了，总体来说很满意。\n屏幕效果：很好\n运行速度：快的\n散热性能：ok\n外形外观：质感很不错\n轻薄程度：有点重OMG啊\n散热能力：应该还可以吧\n运行速度：可以。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-13 10:17:57', 6);
INSERT INTO `data` VALUES (13520, '芴***枫', 5, '运行速度：很好\n屏幕效果：显示效果很细腻\n散热性能：轻薄本就那样吧，能用就行\n外形外观：做工很好，CNC一体加工很nice。\n轻薄程度：重量合适，移动很方便。\n其他特色：适配器小巧方便，非常好。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-04 21:01:52', 5);
INSERT INTO `data` VALUES (13521, 'j***R', 5, '运行速度：运行速度非常快，非常流畅不卡顿\n屏幕效果：屏幕是3.2K屏，看起来非常养眼，非常舒服的视觉体验\n散热性能：散热也很好，有多个风扇散热非常好\n轻薄程度：高性能轻薄本，适合随身携带，适合各种场景使用！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-06 22:04:05', 5);
INSERT INTO `data` VALUES (13522, '单***望', 5, '外观颜值：非常漂亮 \n材质手感：非常好 \n容量空间：空间很大 做工细。\n第一次买红米的笔记本，颜值很惊艳，系统流畅，散热很不错，15寸的尺寸正好可以放到书包里，希望价格能保持住', '新Redmi Pro 15英寸 3.2K屏', '2022-08-25 11:14:28', 2);
INSERT INTO `data` VALUES (13523, '端***喝', 5, '做工精细，颜值很高。屏幕清晰度很棒，散热日常办公基本听不到风扇声音。很薄也不枉轻薄本的称呼。打字键盘手感不错。就是没有数字键盘浪费了大空间。A口就一个有点不够用得买拓展。插拔手感还可以。充电线好评。运行速度很快。最后吐槽下注册微软账号激活office真费劲。微软真的恶心。各种登录错误。', '新Redmi Pro 15英寸 3.2K屏', '2022-12-10 09:31:52', 6);
INSERT INTO `data` VALUES (13524, '存***定', 5, '机器整体机身强度很好，全CNC 一体式的UNIBODY机身，和苹果的macbook 是一个工艺，这个价格买这个产品非常的良心，性能调教上便轻薄本，性能释放适中。机器内部两个大风扇很良心。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-11 15:18:25', 7);
INSERT INTO `data` VALUES (13525, 'u***j', 5, '电脑质感很棒，屏幕分辨率很高，色彩很出色，外出携带开会也很方便，锐龙的核显也能玩一些游戏，作为轻薄本很不错的选择.', '新Redmi Pro 15英寸 3.2K屏', '2022-09-16 21:25:38', 3);
INSERT INTO `data` VALUES (13526, '王***格', 5, '收到之后立马拆开了，打开之后真的很惊艳，做工精致，外观漂亮。深灰色显得稳重成熟。运行速度很快，屏幕色彩鲜艳，很清晰！基本不玩游戏，这配置足够了！风扇声音很安静，自己买了一个小米的鼠标，很满意。', '新小米Pro 14英寸 2.8K屏', '2022-08-29 21:04:40', 5);
INSERT INTO `data` VALUES (13527, 'j***n', 5, '外观：全cnc一体化的机器确实很漂亮 、质感优秀\n屏幕：高分辨率高色域高刷新率 同价位屏幕可以说第一\n性能；搭配amd6800h 性能一流 核显吊打1050笔记本独显\n充电：续航优秀 充电很快很快 满意\n总结 值得推荐', '新锐龙标压R7|2.5K高色域屏', '2022-07-28 12:42:38', 1);
INSERT INTO `data` VALUES (13528, '忍***咩', 5, '运行速度：6800H非常不错，速度很快。\n屏幕效果：显示效果很好，检查无亮点暗点等问题\n散热性能：散热还好，跑了一下wow，温度还行\n外形外观：外观是我喜欢的的，很有质感\n轻薄程度：15.6寸能做这么轻薄确实不错', '新锐龙标压R7|3.2K高色域大屏', '2022-08-09 09:58:37', 5);
INSERT INTO `data` VALUES (13529, '稚***5', 5, '外观无敌好看，简洁大方，屏占比很大，显示比较细腻，整机很轻薄，方便携带，键盘手感很好，性能很好运行很快，平时办公用，散热不错，个人非常满意', '新Redmi Pro 15英寸 3.2K屏', '2022-12-12 11:45:05', 5);
INSERT INTO `data` VALUES (13530, '_***路', 5, '运行速度：很快很流畅\n屏幕效果：毕竟新款 比几年前的老电脑看着舒服多了\n散热性能：不玩游戏的话 声音不大\n外形外观：非常舒服 像个手机一样舒服\n轻薄程度：拿着很舒服\n其他特色：不重', 'Redmi Pro 14英寸 2.5K屏', '2023-03-20 14:01:40', 5);
INSERT INTO `data` VALUES (13531, '发***8', 5, '这是一款性价比很高的笔记本电脑?！\n运行速度：运行速度也很快，\n屏幕效果：屏幕效果超级棒??????????????????????\n散热性能：散热风扇，玩了一天也不热?\n外形外观：外观漂亮！手感不错！\n轻薄程度：薄厚程度适中，这是我最喜欢的了！', '新Redmi Pro 15英寸 3.2K屏', '2022-12-21 19:30:53', 2);
INSERT INTO `data` VALUES (13532, 'y***8', 5, '电脑很好，搭配的amd r7 6800h无论是办公还是游戏都能轻松应对，键盘打字很舒服，百瓦充电不用续航焦虑，3.2k显示屏无论色彩还是清晰度都很惊艳，cnc一体精雕，可以说是笔记本质感天花板，miui+搭配自己的小米手机。效率可以翻倍。想买来办公游戏的朋友可以考虑购入哦。', '新Redmi Pro 15英寸 3.2K屏', '2022-12-26 12:25:49', 6);
INSERT INTO `data` VALUES (13533, 'j***p', 5, '电脑散热很不错，质感也还可以，6800H算是笔记本最强核显了，烤机温度不超过80&deg;，打原神和英雄联盟够用了。\n散热性能：很好\n外形外观：质感不错\n运行速度：很流畅\n屏幕效果：很清晰，体验感堪比4k', '新Redmi Pro 15英寸 3.2K屏', '2022-08-27 12:22:50', 5);
INSERT INTO `data` VALUES (13534, 'j***a', 5, '经过大量比较，选择了这款笔记本。拿到手之后也没有令我失望，从外形设计到内在性能，还有屏幕素质都是很不错的。6.18的促销幅度很大，使它成为极具性价比的产品。还有就是第一次购买AMD CPU的产品，第一次体验Windows 11系统，感觉特别新鲜。', '新锐龙标压R7|3.2K大屏-RTX独显', '2022-06-18 23:40:04', 8);
INSERT INTO `data` VALUES (13535, 'Y***8', 5, '颜色很好看，运行速度可以，跟小米手机，配合，完美。家里大部分都是小米产品，不错。', 'Redmi Pro 14英寸 2.5K屏', '2022-10-29 14:26:03', 4);
INSERT INTO `data` VALUES (13536, 'j***H', 5, '运行速度：宝贝当天就收到了，很喜欢很满意。运行速度很快。\n屏幕效果：屏幕效果很好。\n散热性能：散热效果不错，\n外形外观：外形外观很漂亮，\n轻薄程度：超轻博类型的\n其他特色：颜色好看是我喜欢的类型样子', 'Redmi Pro 14英寸 2.5K屏', '2023-01-30 21:03:44', 1);
INSERT INTO `data` VALUES (13537, 'j***3', 5, '笔记本买了几天才来评价，效果特别好用，软件也是不卡，性价比高，而且薄厚特别舒服特别好看。客服服务态度也很好，每次问什么问题，他也会速度的回答你，下次还会来的！京东还是很靠谱的，', 'Redmi Pro 14英寸 2.5K屏', '2022-08-25 17:21:37', 9);
INSERT INTO `data` VALUES (13538, '白***霞', 5, '物流超快，包装精致，打开包装第一眼看到电脑外观很漂亮，又很轻巧，方便携带，选择同配置其它品牌没有这样的完美，还有指纹开启，太棒了，续航和宣传的一样，超值，很满意', '新Redmi Pro 14英寸 2.5K屏', '2023-01-10 13:29:37', 7);
INSERT INTO `data` VALUES (13539, 'p***7', 5, '运行速度：开机三四秒就好了，响应挺快的，只是办公和看剧，正常运行。\n屏幕效果：分辨率很高，开个会员看剧美得很，B站的高清资源看着过瘾。\n外形外观：灰色很有高级感，轻薄小巧\n其他特色：指纹识别很方便\n\n总体来说满足我的需求，外观也不错。这个价格也还合适。用了半个月才来评价，暂时没出现什么问题。', 'Redmi Pro 14英寸 2.5K屏', '2022-11-17 18:44:14', 5);
INSERT INTO `data` VALUES (13540, 'j***r', 5, '整体做工精致，颜值高，100W快充很给力，屏幕显示舒适，运行性能快，几本没什么可挑剔的，只觉得触板还可以再改进一下', '新锐龙标压R7|3.2K高色域大屏', '2022-08-15 12:54:52', 7);
INSERT INTO `data` VALUES (13541, 'j***f', 5, '笔记本全新 物流非常快 电脑开机非常快 屏幕显示非常棒 办公软件运行流畅 魔兽怀旧无压力 非常愉快的购物体验', '新Redmi Pro 15英寸 3.2K屏', '2022-12-19 09:23:52', 7);
INSERT INTO `data` VALUES (13542, 'c***6', 5, '看了很多款，最后还是选择了红米，大小符合预期，很薄很有质感，反应速度也很快，对平时工作和学习用的话应该是绰绰有余，颜色也是喜欢的那款，十分满意', 'Redmi Pro 14英寸 2.5K屏', '2023-03-08 18:00:42', 2);
INSERT INTO `data` VALUES (13543, '落***6', 5, '这款电脑总体很喜欢，屏幕2.5K全面屏，待机时间很长，双usb-c口，关键本本又轻回老家随身携带方便，值得购买。头条晚上下单，第二天中午就送到配送太给力', 'Redmi Pro 14英寸 2.5K屏', '2023-01-03 14:49:10', 3);
INSERT INTO `data` VALUES (13544, '七***叁', 5, '红米redmiBook 15 2022 锐龙 6800H集显版本\n反应速度非常快，很轻薄，很美观\n锐龙处理器6800h核显非常厉害\n没有必要去买独显版本，反而会降低续航时间和续航\n而且6800h的核显已经媲美老版本1050ti\n15.6的屏幕还有3.2k的屏幕分辨率\n都说红米品控不好，顺便买了京东六年整机延保\n还别说做工真是非常棒，cnc制造工艺而，很轻薄\n比联想的小新16pro 2022锐龙版本好看\n性价比比较高，来第一波吃瓜！', '新锐龙标压R7|3.2K高色域大屏', '2022-06-10 16:03:29', 9);
INSERT INTO `data` VALUES (13545, '提***1', 5, '商品评价:外观材质：很时尚 手感也不错 显卡效果：挺清晰的 看电影很给力 电脑性能：性能也够用 AMD六核12线程可以了 小米品质值得信赖', 'Redmi Pro 14英寸 2.5K屏', '2022-11-13 12:22:24', 5);
INSERT INTO `data` VALUES (13546, 'j***E', 5, '运行速度：运行速度快\n屏幕效果：自带护眼黑夜集中模式\n散热性能：自带散热性能好\n外形外观：简单大方还美观\n轻薄程度：很好，方便携带，可单手打开\n其他特色：耗电慢，可持续运作时间长，主要是自带office excel等方便使用', '新Redmi Pro 15英寸 3.2K屏', '2023-01-17 19:07:28', 4);
INSERT INTO `data` VALUES (13547, 'j***x', 5, '外形外观：外观很好看，颜色很喜欢，轻薄，充电气和手机充电器一样，一点不占地方。\n屏幕效果：屏幕很大，分辨率高很清晰。\n散热性能：很好，散热声音不大。\n运行速度：很快，网页看视频也不卡顿。', '新Redmi Pro 15英寸 3.2K屏', '2023-02-02 21:25:21', 4);
INSERT INTO `data` VALUES (13548, '一***酱', 5, '屏幕效果：3.2k显示细腻 莱斯滴很   色彩惊艳\n运行速度：6800h比其他人分数低 不知咋回事 \n散热性能：单压cpu 没问题\n外形外观：很像苹果  精致 满满细节\n轻薄程度：超薄 满意', '新Redmi Pro 15英寸 3.2K屏', '2022-09-10 18:47:36', 4);
INSERT INTO `data` VALUES (13549, '微***倘', 5, '觉得还不错，用起来很丝滑，办公无敌，对于我这种不打游戏来说，简直是最合适不过的了\n屏幕效果：显示完美\n运行速度：流畅丝滑\n外形外观：这颜值无敌好吧', '新Redmi Pro 15英寸 3.2K屏', '2022-11-22 13:43:56', 5);
INSERT INTO `data` VALUES (13550, '半***港', 5, '性能够我用了，屏幕素质很好，小米的妙享中心很给力。外观也很好看，重量控制的很好。a面摸起来很爽，键盘手感也不错，散热表现很好', '新Redmi Pro 15英寸 3.2K屏', '2022-11-03 22:58:15', 2);
INSERT INTO `data` VALUES (13551, 'j***c', 5, '笔记本看起来很薄，摸起来很舒服，优质的舒适感。一体的CNC工艺，质感瞬间就上来了。新快的6800处理器，速度很快，屏幕为3.2K屏，非常清晰，很细腻，非常适合我使用。\n运行速度：很快\n屏幕效果：很清晰\n散热性能：很不错\n外形外观：好看，质感好\n轻薄程度：舒适', '新锐龙标压R7|3.2K高色域大屏', '2022-07-14 20:58:36', 4);
INSERT INTO `data` VALUES (13552, '喆***z', 5, '运行速度：超级快，指纹解锁很nice\n屏幕效果：看着很舒服，每天办公至少8小时也不累眼睛\n轻薄程度：很轻薄，办公开会很好拿，女孩子也可以单手拿嘿嘿\n就是说非常的爱～性价比很好，欢喜～', '新Redmi Pro 15英寸 3.2K屏', '2022-11-17 17:14:31', 3);
INSERT INTO `data` VALUES (13553, '施***学', 5, '给力给力给力，重要的事情一定要说三遍。工艺真的很棒，做工特别的精致，运行速度也是很快，屏幕有点大，散热也是杠杠的。作为办公本来说，出了内存太小了，真的找不出什么吐槽点，非常推荐购买的一款产品', '新Redmi Pro 15英寸 3.2K屏', '2022-11-16 08:45:54', 4);
INSERT INTO `data` VALUES (13554, 'n***0', 5, '外面很好看，做工精细，有点重，\n运行速度：速度很快。注册很麻烦。\n屏幕效果：三K屏幕非常细腻，\n散热性能：很好。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-03 11:39:54', 7);
INSERT INTO `data` VALUES (13555, '可***条', 5, '性价比很高，果然是王炸品牌，老公手机也是小米，算半个小米粉丝，家里老电脑快要下岗了，赶紧买了这个笔记本，平时办公用完全足够了，希望用久一点！', 'Redmi Pro 14英寸 2.5K屏', '2022-09-02 13:45:06', 5);
INSERT INTO `data` VALUES (13556, '熊***9', 5, '京东下单物流真的快，头天下单第二天笔记本都到货了。开机检查外观真的惊艳，做工扎实，开机后登录账号尝试注册成功，使用几天效果非常不错，红米笔记本不比其他品牌差！支持国货！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-16 14:58:37', 8);
INSERT INTO `data` VALUES (13557, '月***辉', 5, '发货很快，次日就送达\n产品质感很好，一体cnc非常高级\n屏幕特别好，3200分辨率高，颜色准，反应快\n性能足够，功耗控制也不错\n不得不说第一次买小米笔记本感觉还是比较惊喜的', '新Redmi Pro 15英寸 3.2K屏', '2023-01-10 11:59:19', 5);
INSERT INTO `data` VALUES (13558, '伤***7', 5, '运行速度：自己平时很少玩游戏，性能对我来说很够用。\n屏幕效果：屏幕显示细腻，\n散热性能：感觉散热还可以。\n外形外观：机器看起来摸起来比较有质感。', '新Redmi Pro 15英寸 3.2K屏', '2022-08-23 21:45:09', 5);
INSERT INTO `data` VALUES (13559, 'S***S', 5, '买笔记本主要是为了办公方便，选择了这款笔记本，轻薄，尤其是屏幕非常棒，并且cpu用来跑程序也是完全够用的，出差的话续航也是完全满足需求的，非常适合我，特别满意。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-24 14:35:19', 6);
INSERT INTO `data` VALUES (13560, 'j***9', 5, '首先说Redmibook这款笔记本是挺不错的，这个价位的电脑再配上锐龙R7，3.2K高刷屏幕CNC工艺机身，还有PD充电器（外出携带不占用空间，颜值也高），还有什么可以挑剔的。日常使用场景绝对够用，音质不错，续航也可以，性价比很高', '新锐龙标压R7|3.2K高色域大屏', '2022-07-11 12:51:57', 7);
INSERT INTO `data` VALUES (13561, 'm***h', 5, '先说优点：\n1.外观确实好看，工艺很好，我有一台yoga14，工艺不相上下，棒！\n2.指纹集成开锁相当方便，比我那台yoga14人脸更方便，更灵敏！\n3.运行速度快，没出现过卡顿\n4.屏幕一绝，清晰，透亮，而且亮度高，太阳下也看得清楚\n5.散热不错，我基本看视频做文档，偶尔玩玩lol，文明，非常满意，平时用听不到风扇的声音\n6.type-c接口一边一个，都可以充电，太方便了！比我那个联想好多了\n再说缺点：\n1.不是全键盘，可惜了这大的尺寸\n2.只有一个usb口，我的被鼠标接收器占用，再接设备就要用转接器了', '新Redmi Pro 15英寸 3.2K屏', '2023-01-17 09:02:16', 4);
INSERT INTO `data` VALUES (13562, '诗***风', 5, '屏幕效果：非常好，显示分辨率高，色彩细腻！\n散热性能：手接触部位基本感受不到热度，体验非常好。\n外形外观：外观非常惊艳，简单大气！\n运行速度：性比价比非常高，cpu性能好，内存配置高！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-12 16:18:48', 5);
INSERT INTO `data` VALUES (13563, '韩***白', 5, '月初买的，送货特别快，隔天就到了。当时还联系快递小哥自己上门去取了。\n看了笔吧评测和中正测评决定的买的。\n虽然不是游戏本，反正我不是臭打游戏的，哈哈。完全符合我的要求，性能够用，屏幕好，而且cnc机身很有质感。\n收到检查了外观无瑕疵，屏幕完美，3.2k真的很细腻，就是有点暖，自己调了下色温到7500k看着很舒服一些。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-13 10:50:50', 5);
INSERT INTO `data` VALUES (13564, '不***出', 5, '电脑使用起来很快，屏幕颜色很细腻，看着眼睛没有不舒服的感觉，整体很轻薄，发热量低，使用了半小时几乎没有感觉到发热，整体使用感觉很好。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-26 21:19:33', 6);
INSERT INTO `data` VALUES (13565, 'D***D', 5, '运行速度：很快很快很快\n屏幕效果：这块屏幕真的不错，有些便宜点笔记本用的还是低色域的，这个良心\n散热性能：散热是要长时间用后才能体现出来，这个很难模拟测试，所以日后追评\n外形外观：家族式设计，还不错', 'Redmi Pro 14英寸 2.5K屏', '2022-10-05 12:13:36', 6);
INSERT INTO `data` VALUES (13566, '子***8', 5, '我是唯性能者，所以毫不犹豫拿下6800H本，回家没有立刻评论，\n今天各种测试，室温28度，笔记本散热完全没问题，没有降频。\nCNC工艺真香！全金属外壳的光泽和手感非常舒服。\n关注过好几代红米笔记本，品质是越做越好！性价比也是超高！！！\n强烈推荐14寸的，适宜各种场合。', '新锐龙标压R7|2.5K高色域屏', '2022-06-04 11:32:56', 5);
INSERT INTO `data` VALUES (13567, 'j***-', 5, '运行速度：很顺畅\n屏幕效果：显示效果满分\n外形外观：简约大气\n轻薄程度：适中\n其他特色：使用了十天，感觉很不错，win11丝滑流畅，屏幕够大显示效果很好，键盘手感很好，键够大也没有很紧凑，锐龙处理器完全够用。', '新Redmi Pro 15英寸 3.2K屏', '2022-08-26 21:57:44', 4);
INSERT INTO `data` VALUES (13568, '番***米', 5, '米粉。安全下车。如图，很薄，很有质感，带得动简单游戏。已经下载了人类一败涂地、双人成行。喜欢~\n最主要还是用来办公的，经常同时打开好几个程序，完全没得问题。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-27 11:45:40', 5);
INSERT INTO `data` VALUES (13569, '酷***鱼', 5, '本本很漂亮，轻巧，外观金属质感，大气，键盘灯很人性，办公绝对够用，一般游戏也可以拿下，同档次的办公本它游戏性能也是出众的！总体来说很满意的一次购物！', '新Redmi Pro 15英寸 3.2K屏', '2022-12-09 09:06:24', 5);
INSERT INTO `data` VALUES (13570, 't***3', 5, '第一次用红米的电脑，上手感觉很好，非常的轻盈，整体非常精致，开机特别快，还预装了win11系统，赶紧体验一下', '新Redmi Pro 15英寸 3.2K屏', '2022-09-12 15:48:54', 7);
INSERT INTO `data` VALUES (13571, '我***亮', 5, '趁着双十一活动赶快下单了，可以说是今年最值得买的笔记本了，屏幕素质超级高，硬盘读写快，风扇的声音也可以接受，主要是和我的小米手机完美匹配，平时背着也不会觉得沉，可以说是满足了一切需求，补充一句：京东快递真给力?', '新Redmi Pro 15英寸 3.2K屏', '2022-11-16 14:29:21', 6);
INSERT INTO `data` VALUES (13572, '我***此', 5, '电脑挺好的  双十一价格不到5000 前几个月就关注想买了，确实实惠了不少。外出办公非常便携。 电池续航虽然没有10宣传的10几个小时。 能用个4-5小时吧  屏幕完美 看电影3.2k很爽。 完美', '新Redmi Pro 15英寸 3.2K屏', '2022-11-19 07:47:23', 5);
INSERT INTO `data` VALUES (13573, 'A***s', 5, '用起来很不错，键盘手感挺不错的，机身全金属外壳用起来有质感，有指纹识别，识别速度快，电池充满电办公学习可以用很久，机身不热', '锐龙R5六核|2.5K高色域屏', '2022-08-07 21:57:24', 2);
INSERT INTO `data` VALUES (13574, 'j***U', 5, '运行速度：非常快，可以满足\n屏幕效果：细腻舒适\n散热性能：没有噪音\n外形外观：潮流时尚', '新Redmi Pro 15英寸 3.2K屏', '2022-08-26 08:39:13', 2);
INSERT INTO `data` VALUES (13575, 'L***恋', 5, 'A，C，D面都是cnc金属一体成型，质感和手感都很优秀，这才5000出头，有这个做工已经是相当优秀了。 屏幕：15.6寸的准3 k雾面屏，超窄边框，16：10的黄金比例，比大多数的16：9屏幕更加震撼，显示效果极为优秀，刷新率有90hz，略可惜，边框很可惜不是玻璃一体的屏幕，为了控制成本，这其实可以理解。 处理器6800 H. 8 c16t，7**工艺，日常使用功耗性能都极为出色。全新的核显，性能提升很大，基本可以通杀所有网游了，性能和笔记本的1050ti基本相当，配合6400的高频内存，整体配置很强悍。 刚使用没多久，续航没怎么测试，但是充电得题一嘴，很快，而且送的GAN 100w pd头，C 2 C 接口， 小巧精致。 外放效果优秀。', '新Redmi Pro 15英寸 3.2K屏', '2022-09-11 17:06:08', 4);
INSERT INTO `data` VALUES (13576, '希***宝', 5, '第一次买小米的笔记本，本来还很担心，但是用起来真的不错，同等价位，比之前买的宏碁好多了。无论是屏幕，还是运行速度，都非常快，散热性能，目前来看还是不错的，外形也很漂亮，总之，相信京东，相信小米！！！！！', '新Redmi Pro 15英寸 3.2K屏', '2022-08-25 18:14:48', 2);
INSERT INTO `data` VALUES (13577, '老***7', 5, '买来奖励外甥高考后上大学的，外观真的不错，不管游戏体验还是看视频都是杠杠的，外甥非常开心。\n运行速度：非常快流畅。\n屏幕效果：真的好，比我单位配的电脑屏幕真是不要好太多。\n散热性能：总体OK\n外形外观：CNC工艺提升了档次。\n总的来说目前没有问题，满意。', '新锐龙标压R7|3.2K高色域大屏', '2022-06-10 10:53:49', 4);
INSERT INTO `data` VALUES (13578, 'f***5', 5, '包装保护：很结实，保护的挺好。严实卡扣\n外形外观：很有质感，上手不错，如果把删除键搞大一点，就更好了\n画面品质：小米画质很好，显示效果不错\n跑分评测：跑分没跑，应该很多\n运行速度：速度不错，比普通办公电脑速度快，对比过win10和11两个版本的，win10操作更流程。\n游戏效果：还没有试，回头追评再告诉你们', 'Redmi Pro 14英寸 2.5K屏', '2022-08-26 08:21:15', 5);
INSERT INTO `data` VALUES (13579, '费***鼠', 5, '屏幕效果：屏幕非常好！15.6寸是最好的尺寸，边框控制的很美观，颜色显示很准，适合做对色彩要求高的鸿运，比如网页设计，图片视频处理等。\n散热性能：散热很强悍，风扇声音也小\n外形外观：很薄很轻，便于携带，电源适配器也不大，电池容量72Wh 中规中矩，毕竟是轻薄本\n其他特色：内存是16GB LDDR5 6400MHz，硬盘是PCle4.0 可用容量是477GB 非常快的组合，支持Wifi6\n运行速度：CPU是R7 6800H，中规中矩，但是自带的核显很强悍，比MX450强太多了，查了一下已经摸到差不多GTX1650的水平了，实测英雄联盟120-140fps，打一些常见的游戏性能是足够的，跑大型的代码库完全没问题\n\n总体是很满意的，用了三天，还没发现什么问题，声卡网卡都正常，自带的windows11也很流畅，之前死活不想升级11，结果发现还真不错(≧&nabla;≦*)', '新锐龙标压R7|3.2K高色域大屏', '2022-07-28 14:48:48', 4);
INSERT INTO `data` VALUES (13580, 'j***7', 5, '屏幕效果：色彩标准，看上去很舒服。外形外观：虽说是15.6以为很大，但是它还是很方便携带的，屏幕大长时间看屏幕也不会不舒服。外观很好看，质感很棒。 散热性能：\n没有温度，低温运行可以满足我的各种办公需求。运行速度：6800H这颗CPU性能的确很足 轻薄程度：薄，对于男生来说一点都不重。 其他特色：好看，优雅！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-15 00:31:05', 4);
INSERT INTO `data` VALUES (13581, 'j***d', 5, '非常不错的笔记本电脑，cpu和显卡性能都很不错，做工也很好，没有发现什么问题', '新Redmi Pro 15英寸 3.2K屏', '2022-11-16 15:26:54', 4);
INSERT INTO `data` VALUES (13582, 'j***0', 5, '外观非常有质感，颜值高，性能超快，散热良好，没感觉到烫手发热，非常静音', '新Redmi Pro 15英寸 3.2K屏', '2022-09-11 20:29:35', 3);
INSERT INTO `data` VALUES (13583, '洋***咩', 5, '第一次购买小米的笔记本电脑，看起来不错，运行速度很快，屏幕大效果好，散热性能很好，轻薄型的，出差使用很方便，而且是全面屏，很喜欢！', '新Redmi Pro 15英寸 3.2K屏', '2023-03-16 11:33:12', 5);
INSERT INTO `data` VALUES (13584, '网***强', 5, '京东送货这个速度太满意了，6月1号一大早就收到了，试用一天了谈谈感受。\n运行速度：锐龙6800H，办公兼顾轻游戏的首选，核显对标入门独显YYDS，关键功耗控制喜人啊，不打游戏的情况下，用了4个小时，剩余电量59%?\n屏幕效果：一直想买oled的显示屏本本，弊端懂的都懂，结果到手我感觉我满意了，屏幕素质绝对是一流的，特别是亮度，感觉不只400nit，分辨率就不说了，足够细腻。\n散热性能：没感觉到怎么发热，用了一天都是温温的 ，大游戏没试过，风扇声音也没听见。\n外形外观：之前定的友商的16.1 ，就是因为在线下店看了上一代15pro，转定的这个，cnc一体手感细节绝了，满意?\n其他特色：锐龙15pro2022五星好评，基本无短板的办公学习轻游戏本，推荐！', '新锐龙标压R7|3.2K高色域大屏', '2022-06-01 20:11:52', 4);
INSERT INTO `data` VALUES (13585, 'g***3', 5, '京东物流超级给力，快递小哥送货上门，服务超赞，小米忠实粉丝，家里很多小米的产品，小米的产品性价比高，质量也可以保证，笔记本买的8核，运行速度很快，颜值也很高，大爱', 'Redmi Pro 14英寸 2.5K屏', '2022-11-13 12:04:32', 7);
INSERT INTO `data` VALUES (13586, 'j***O', 5, '红米的这款手提电脑运行速度快，屏幕清晰，散热性能好，外型轻薄，但上手却挺沉实，手感好，小孩上网课用非常适合，下午落单，第二天早上就到了，京东的物流非常棒，电器it商品还是信赖京东自营！', 'Redmi Pro 14英寸 2.5K屏', '2022-12-03 14:10:12', 2);
INSERT INTO `data` VALUES (13587, 'j***o', 5, '全金属cnc一体机身 手感塑料没法比 正常办公没问题 游戏我打打csgo 只要网络没问题 性能绝对够用\n风扇问题声音其实可以接受 性价比很高', '新Redmi Pro 15英寸 3.2K屏', '2022-11-12 12:07:35', 2);
INSERT INTO `data` VALUES (13588, 'm***o', 5, '孩子上网课用，非常好的体验，屏幕惊艳，边框很窄，机身颜色当下流行，触感不错，触摸板宽大，触感良好，手势操作方便。小米的MIUI?和小米手机有很多可以互动的，很方便。总体来说使用体验很好，性价比不错，有小米其他设备的更加方便。', '新Redmi Pro 15英寸 3.2K屏', '2023-01-04 13:11:57', 5);
INSERT INTO `data` VALUES (13589, '_***_', 5, '包装很完整很结实，没有损坏\n电脑外观简约利落，很漂亮\n屏幕素质很好，很清晰，分辨率不错\n系统是win11，处理器稍弱一些，但日常使用足够', 'Redmi Pro 14英寸 2.5K屏', '2022-11-12 22:53:47', 5);
INSERT INTO `data` VALUES (13590, '我***t', 5, '外形外观：精致，商务非常有高级感\n屏幕效果：90hz3.5k屏，看得到的流畅和精细感\n运行速度：非常快，目前仅做办公用，打开应用速度飞起\n散热性能：基本办公的时候风扇转动声音并不大，不贴近几乎不能听到\n总的来说非常满意，15.6寸重量也还合适', '新Redmi Pro 15英寸 3.2K屏', '2022-08-20 17:48:15', 4);
INSERT INTO `data` VALUES (13591, '胖***丁', 5, '非常好，开机流畅，颜值特别高，小爱同学超级方便，太喜欢啦，哈哈哈', 'Redmi Pro 14英寸 2.5K屏', '2022-08-25 13:37:42', 3);
INSERT INTO `data` VALUES (13592, 'b***3', 5, '看这款电脑看了很久，一直犹豫不决，本打算买R5的，对比来对比去，还是买了R7，不玩游戏，就是平时办公之类，买了后没有后悔，真的很好，性价比很高，14寸，大小也合适，值得入手。', 'Redmi Pro 14英寸 2.5K屏', '2023-01-05 08:37:07', 3);
INSERT INTO `data` VALUES (13593, 'l***1', 5, '京东非常快，昨晚下单今下午就送达了。电脑很满意，屏幕是我想要的大小，并且也不刺眼，整个电脑用起来很流畅很舒服，外观也很漂亮，充电器这么便携出乎意料。\n非常棒，不漏电，触摸板很好用，键盘很大很舒服', '新锐龙标压R7|3.2K高色域大屏', '2022-06-01 18:04:15', 9);
INSERT INTO `data` VALUES (13594, '5***啦', 5, '拿到快递包裹，打开包装的瞬间，就觉得本次选择的正确性。开机速度很快，很安静，运行顺畅。\n目前目前已经使用了5天，除了系统office还未成功激活在，其他都很满意！', 'RedmiBook Pro14锐龙', '2021-06-11 10:27:41', 8);
INSERT INTO `data` VALUES (13595, '菲***狗', 5, '从13换到15.6，屏幕感觉很爽，笔记本质感非常好，也非常爆，其他还要慢慢体验\n运行速度：非常快\n屏幕效果：清晰，屏幕大，16:10舒适\n散热性能：风扇声很小\n外形外观：造型简单，质感好', '新锐龙标压R7|3.2K高色域大屏', '2022-06-18 22:44:01', 4);
INSERT INTO `data` VALUES (13596, '启***7', 5, '趁着双十一有活动下的单，收到货以后打开包装第一眼就很惊艳，做工质感都很好，屏幕也不错，风扇声音不大，小米手机和电脑互传文件也很方便，总之很满意\n正好这两天疫情严重，全城静默，儿子在家上网课派上用场了。客服很专业?', '新Redmi Pro 15英寸 3.2K屏', '2022-11-28 22:14:00', 6);
INSERT INTO `data` VALUES (13597, 'j***o', 5, '第一次尝试小米牌子的笔记本，结果很惊艳，性价比极高，到手后使用半个月了，没有发生过任何问题，离电使用能到十个小时，屏幕很清晰，充电很快，运行速度很快，看着很舒服，整体颜值特别高，特别喜欢，客服态度也很好，以后买电脑还买小米，整挺好???', '新Redmi Pro 15英寸 3.2K屏', '2022-11-16 15:09:32', 6);
INSERT INTO `data` VALUES (13598, 'j***6', 5, '满心期待有惊喜，笔记本做工好，打开使用开机很快，色彩显示高清，不错，很喜欢！\n运行速度：很快，开机几秒。\n屏幕效果：鲜艳高清。\n外形外观：金属感很强。', '锐龙R5六核|2.5K高色域屏', '2022-08-14 20:49:53', 4);
INSERT INTO `data` VALUES (13599, '芊***谦', 5, '机器整体很有质感，按键舒服，分量适中，运行快捷&mdash;&mdash;机器整体很满意。', '新锐龙标压R7|3.2K高色域大屏', '2022-06-02 20:33:00', 7);
INSERT INTO `data` VALUES (13600, '天***子', 5, '千呼万唤始出来，终于等到疫情有所好转收到双十一下的订单了。这款笔记本当时对比再三，看了不少测评，性价比真的很多，对于我这基本用于办公来说，这款用起来还是很流畅的，作工也很好，手感不错，颜值也高，画质很赞，不怎么玩游戏所以也没有测评的，总得来说，笔记本很满意。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-24 01:45:14', 3);
INSERT INTO `data` VALUES (13601, 'B***仔', 5, '电脑非常得好，屏幕非常的顶级有pro的样子了，目前没发现毛病运行速度也非常快，散热还算可以。外观非常的漂亮也很轻薄，很值得这个价钱，非常得不错！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-06 22:18:59', 2);
INSERT INTO `data` VALUES (13602, 'j***i', 5, '电脑运行流畅，手感一级棒，真的超级舒适，送了office软件，真的大赞。外观高级舒适 很喜欢很喜欢。目前并没有发现什么产品质量问题。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-21 16:30:50', 3);
INSERT INTO `data` VALUES (13603, 'H***7', 5, '性价比之王，质感很棒??，R5-6600办公对于我来说已经完全足够了，高清2.5K画质比之前的鸿基好很多了，一体成型手感很nice.给满分！', '新锐龙标压R5|2.5K高色域屏', '2022-06-23 18:15:50', 8);
INSERT INTO `data` VALUES (13604, 'j***X', 5, '收到很惊喜，是我想要的那种感觉。办公日常使用都可，颜色很高级，细节之处做的也很好。指纹解锁，爱了爱了。', '锐龙R5六核|2.5K高色域屏', '2022-08-11 18:26:13', 6);
INSERT INTO `data` VALUES (13605, 'u***f', 5, '外观质感特棒颜值很高，性能也不错，日常办公运行ps软件很流畅，用了10来天没啥问题。续航方面个人中重度使用ps办公有5、6个小时以上。16:10的高刷雾面屏幕办公看电影都很爽', '新Redmi Pro 15英寸 3.2K屏', '2022-11-19 11:03:06', 5);
INSERT INTO `data` VALUES (13606, '鱼***饼', 3, '东西挺不错的，但是过完30天保价就降价啥意思？', 'RedmiBook Pro14锐龙', '2021-12-13 17:36:07', 9);
INSERT INTO `data` VALUES (13607, '麦***0', 5, '618活动期间将近比对了十款笔记本，最终还是确实红米Pro15，性价比极高，入手三面金属，手感很棒，屏幕看着很舒服，长时间看眼睛不痛。携带轻便，win11系统新颖有趣，gis用着很流畅，不卡顿，运算很快，我班男生跟我买了一样的，玩游戏也贼强。另外还能实现和我小米手机的联动，舒服了！', '新锐龙标压R7|3.2K高色域大屏', '2022-07-02 14:23:38', 2);
INSERT INTO `data` VALUES (13608, '如***媚', 5, '电脑收到了，比预想的还要乐观，屏幕看起来很舒服，电脑整体轻便，还有正版的系统，可能刚开始使用微软系统，需要磨合一下，整体来说，很是满意', '新Redmi Pro 15英寸 3.2K屏', '2022-12-26 17:23:35', 1);
INSERT INTO `data` VALUES (13609, '珊***7', 5, '笔记本很轻薄，方便携带，外观漂亮，做工很好?，系统用起来也很流畅，风扇噪音很小，续航时间挺长，出差用很方便，给办公室同事购买，已购第二台了，推荐推荐', 'Redmi Pro 14英寸 2.5K屏', '2022-09-18 00:51:17', 5);
INSERT INTO `data` VALUES (13610, 'j***5', 5, '东西很精致，做工很好。操作起来也很细腻，手感不错。主要是纯金属的明显比塑料的要高端一些。家里老婆和小孩都很开心，明天一个上课和另外一个上网课都已经预定了。自信满满的一次购物。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-13 23:58:00', 6);
INSERT INTO `data` VALUES (13611, '流***6', 5, '运行速度：速度顺滑，满意\n屏幕效果：屏幕华丽，色彩鲜艳亮丽\n散热性能：风扇声音小，开启大型软件声音稍大\n外形外观：样子最为喜欢，颜色也喜欢', '新锐龙标压R5|3.2K大屏-RTX独显', '2022-06-27 19:18:32', 4);
INSERT INTO `data` VALUES (13612, '半***7', 5, '之前买的联想小新air14plus2022锐龙版R76800Hs，无奈做工太差劲了，合起来上下对不齐，转轴两边不对等，屏幕右下角也有点漏光，用了四个月机身还有点掉漆和小变形，没摔没碰的，我都不知道怎么弄得。\n然后看到小米的CNC一体切割工艺做工不错，就买了这款红米的Redmibook14pro2022锐龙版R76800H（主要为了接口丰富和便携性，所以选的红米）\n感觉终于找到理想中的笔记本，尤其是机身强度和做工，简直秒杀联想。在这一点上我要为小米打Call，为小米点赞！总之这次购物非常满意！！！\n运行速度：非常快\n屏幕效果：看着很舒服，温润如玉\n散热性能：给力，有一点点电流声，不过无伤大雅\n外形外观：做工精细，机身很有质感。我挑剔的眼光几乎看不到任何瑕疵。\n轻薄程度：1.45Kg 重量，两脚插头?100wPD快充，小巧玲珑，便携性好！\n其他特色：性价比很高，同价位最优选择，没有之一。做工很精致。R76800H核显强劲，理想中的笔记本电脑，希望小米越来越好！！！', '新Redmi Pro 14英寸 2.5K屏', '2022-12-15 10:46:39', 3);
INSERT INTO `data` VALUES (13613, '爱***菜', 5, 'CNC一体切割质感爆棚，做工应该算这价位里最好的超薄本了，屏幕细腻程度非常高，配合90hz刷新率真是纵享丝滑的感觉，6800H性能不用多说，目前市面最强核显没有之一，双11活动价格也很给力，主要用来办公+影音娱乐用的，这配置战三年没压力，要是usb-A口能多两个就更好了，总体来说性价比超值。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-12 14:20:47', 6);
INSERT INTO `data` VALUES (13614, '龙***儿', 5, '京东快递飞速，当天就到了。\n屏幕视觉效果优越，键盘还算舒服，做工一流。\n屏幕和cnc是最大亮点。平时工作用，看看视频，很少打游戏，新出的锐龙6800H绝对够用，而且完全有余地。不打游戏，所以噪音很小。', '新锐龙标压R7|3.2K高色域大屏', '2022-06-18 16:50:11', 4);
INSERT INTO `data` VALUES (13615, 'x***a', 5, '作为一名资深米粉，第一次购买红米系笔记本，做工很精致，电脑运行也很流畅，amd的核显很强，亲测娱乐大师102万，游戏实测大表哥2可以在1080p稳定在接近40帧，gta5稳定在90帧附近，轻薄本加100瓦氮化镓充电器的配置，可以玩3a大作，确实超出了预期。离电播剧实测可以达到七八个小时左右，续航也很顶，真的很不错，米粉可以入，其他品牌的海军也别来杠，没工夫搭理！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-24 09:26:02', 7);
INSERT INTO `data` VALUES (13616, 'j***9', 5, '笔记本做工很好，质感不错，6800H cpu性能很强，核显也能畅玩游戏，屏幕也很清晰', '新Redmi Pro 15英寸 3.2K屏', '2022-11-14 15:31:08', 7);
INSERT INTO `data` VALUES (13617, 'b***e', 5, '外形外观：采用cnc果然工艺果然好看，比我想象中轻薄，非常nice\n运行速度：6800h的性能毋庸置疑，大部分游戏都勉强能玩\n屏幕效果：120Hz很流畅，分辨率高很清晰\n散热性能：不玩游戏、只看视频的情况下出风口温度很低，风扇声音很小，键盘中间靠近屏幕处有点点温热\n其他特色：跟红米手机互联，传输文件很方便\n使用一段时间后我会再来追评，第一次用红米的电脑，需要时间来感受', '新Redmi Pro 14英寸 2.5K屏', '2022-08-25 12:29:35', 4);
INSERT INTO `data` VALUES (13618, '音***旅', 5, '运行速度：自带win11，非常流畅\n屏幕效果：2.5k屏，显示色彩非常细腻\n散热性能：风扇相当安静，有三种模式可调\n外形外观：比起我的小米13.3好太多了，这款已经购买了两部了', 'Redmi Pro 14英寸 2.5K屏', '2022-08-23 15:03:58', 6);
INSERT INTO `data` VALUES (13619, '为***1', 5, '看了一个星期，做了各种攻略，最终选择了这款，性价比是真的高，外观也是非常好看，做工很细腻，性能也没的说，非常喜欢', '新Redmi Pro 15英寸 3.2K屏', '2022-11-11 09:46:05', 6);
INSERT INTO `data` VALUES (13620, '德***生', 5, '1.质感真的很好很好，摸着很舒服，看着很高级。\n2.目前用来十多天，没有问题，运行迅速，反应灵敏。\n3.屏幕素质真的很高，看了再去看其他屏幕能感受到差距。\n4.办公用完全够用了，暂时还没有尝试过游戏。\n5.发货迅速，包装完好。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-15 00:01:48', 4);
INSERT INTO `data` VALUES (13621, 'z***9', 5, '因为之前的笔记本硬盘坏了，经常开不开机，趁双十一买的新笔记本。考虑手机是红米的，电视也是小米的，很不错，就选了这款。据说R7 6800h是比较好的处理器。电脑很大气，很精致，很有商业气息。第一次买轻薄本，比之前买的笔记本薄了很多，很便携。充电器只比手机的大一点，也很便携。使用感受，很方便，很流畅，除了仙剑奇侠传七运行起来有时候卡顿以外，暗黑和帝国时代能稳定运行。有三挡可调。最大的问题可能是散热不大好，运行游戏一会儿键盘左边就很烫，开最大档会好一些。总体很不错的笔记本电脑。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-17 01:34:21', 4);
INSERT INTO `data` VALUES (13622, 'E***o', 5, '运行速度：速度快，很流畅\n屏幕效果：高分高刷，屏幕细腻，亮度也不错\n散热性能：双风扇确实比之前好\n外形外观：很不错，cnc一体，质感好\n轻薄程度：整体轻薄还是比较方便携带的', '新锐龙标压R7|3.2K高色域大屏', '2022-08-08 21:47:47', 4);
INSERT INTO `data` VALUES (13623, '醉***迎', 5, '小米这个笔记本外观设计非常简洁大气，很有质感，性能也很强，日常使用很流畅，外出办公携带很方便，屏幕也很清晰，非常不错?', '新Redmi Pro 15英寸 3.2K屏', '2022-11-13 21:12:26', 5);
INSERT INTO `data` VALUES (13624, 'j***c', 5, '运行速度：AMD的5500u芯片，是六核心12线程，用来给办公本很合适，多开网页，多开Word文档，都没有问题，自带的核显也能够播放4k视频\n屏幕效果：高分辨率看起来很细腻，色彩也很丰富，高刷新也适合用来看一些4k电影，\n散热性能：办公本嘛发热也不大，散热还可以\n外形外观：非常的润，然后摸起来也很舒服\n轻薄程度：比较轻薄，单一个笔记本差不多1.4千克\n其他特色：性价比也很高', '锐龙R5六核|2.5K高色域屏', '2022-06-18 15:29:50', 4);
INSERT INTO `data` VALUES (13625, '九***刃', 5, '笔记本性能不错，屏幕非常清晰，运行安静。还能和手机协同，很方便。大屏办公也很好。触控板很大，很好用。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-07 13:29:24', 5);
INSERT INTO `data` VALUES (13626, 's***u', 5, '运行速度：打开应用很流畅，使用过程中没有卡顿现象，对于我这种不打游戏的来说够用了，续航还没体验，等过段时间再来评论。\n屏幕效果：屏幕效果很不错，看电影画面挺清晰。\n轻薄程度：机身很薄，A、B面触感很好。', '新锐龙标压R7|3.2K高色域大屏', '2022-06-03 23:05:09', 4);
INSERT INTO `data` VALUES (13627, '飞***g', 5, '电脑非常好用！当天买当天就到了。\n屏幕效果：120嘎嘎棒，2.5k显示效果也很好\n散热性能：轻薄本性能就不大OK了，但散热还是可以的。风扇也很安静\n外形外观：学苹果总不会错，很有质感', '新Redmi Pro 14英寸 2.5K屏', '2023-01-15 09:36:28', 4);
INSERT INTO `data` VALUES (13628, '在***呀', 5, '以前就经常买小米和红米的产品，第一次买红米的笔记本电脑，到手后无论是从好质感、性能、还是颜值上都十分满意，这台电脑会陪我度过整个大学生涯！', '新Redmi Pro 15英寸 3.2K屏', '2022-11-20 18:04:51', 6);
INSERT INTO `data` VALUES (13629, '辰***晨', 5, '运行速度：非常快\n屏幕效果：看上去很舒服\n散热性能：好好好\n外形外观：小米产品 值得信赖 一如既往的喜欢！赞赞赞赞赞赞', '新Redmi Pro 15英寸 3.2K屏', '2022-11-27 00:18:54', 6);
INSERT INTO `data` VALUES (13630, '星***4', 5, '配送速度很快，电脑很精致，金属的框架很时尚商务，特别喜欢，一收到就迫不及待地打开了，家人也很满意。', '新Redmi Pro 15英寸 3.2K屏', '2022-08-30 14:43:36', 9);
INSERT INTO `data` VALUES (13631, 'j***a', 5, 'cnc外壳加上喷砂工艺确实不错，很有质感，铠侠的硬盘，天马的屏，16寸还是用2.5K分辨率好，现在3.5k的屏幕显示的字会变的很小。不打游戏风扇没听到转过，说明散热不错。拿来办公，看电影，玩连连看，没问题。', '新Redmi Pro 15英寸 3.2K屏', '2022-11-09 20:29:26', 4);
INSERT INTO `data` VALUES (13632, 'I***N', 5, '上大学买的电脑是小米ProGTX，用的还不错，现在给朋友推荐买的。这款电脑果然没让我失望，运行速度快，屏幕，散热，性能都不错。附赠的充电器也很不错。', '新Redmi Pro 15英寸 3.2K屏', '2022-12-09 16:57:44', 5);
INSERT INTO `data` VALUES (13633, 'Z***6', 5, '今天收到啦，手感不错，颜值很在线，比较喜欢\n外形外观：很漂亮\n轻薄程度：比较薄\n屏幕效果：还不错', 'Redmi Pro 14英寸 2.5K屏', '2023-01-06 23:16:25', 2);
INSERT INTO `data` VALUES (13634, '咁***子', 5, '今年的红米bookpro15可谓是性能怪兽了！锐龙r7-6800h直接拉满，直呼AMD yes！\n这款笔记本外观做工依旧是CNC工艺，满满的艺术感，屏幕特别大且清晰，键盘的敲击感十足，而且插口也是特别齐全，这点特别好评！而且送的充电头也比较便携，windows系统和office都是免费预装好的，开机激活就可以使用。\n希望小米能继续给我们带来这样的好产品吧！！加油！', '新Redmi Pro 15英寸 3.2K屏', '2022-08-26 18:05:44', 4);
INSERT INTO `data` VALUES (13635, 'j***B', 5, '运行速度：R76800H速度很流畅很快，\n屏幕效果：3.2k屏幕很不错\n散热性能：散热效果绝了\n外形外观：颜值杠杠的\n轻薄程度：非常的轻薄拿手里很舒服', '新Redmi Pro 15英寸 3.2K屏', '2022-11-11 16:23:21', 4);
INSERT INTO `data` VALUES (13636, 'j***z', 5, '电脑收到好几天了。用过才评价。CNC一体外观真的好看。运行很快。开机几秒钟。屏幕色彩清晰。平时办公。追剧轻松搞定。支持小米。准备手机也换小米', '新Redmi Pro 15英寸 3.2K屏', '2022-11-16 07:16:49', 5);
INSERT INTO `data` VALUES (13637, 'u***u', 5, '屏幕素质一流，显示清晰，3.2k屏幕，第一眼就被惊艳！系统反应速度快，铝合金cnc一体工艺，手感舒适。\nc口充电方便，读取速度快。各个软件的响应速度非常快。', '新锐龙标压R7|3.2K高色域大屏', '2022-06-12 12:49:01', 4);
INSERT INTO `data` VALUES (13638, '弓***孝', 5, '运行速度：开机速度很快\n屏幕效果：清晰度很高\n散热性能：不错\n外形外观：大气\n轻薄程度：正好', '新Redmi Pro 15英寸 3.2K屏', '2023-02-04 15:10:16', 4);
INSERT INTO `data` VALUES (13639, 'j***s', 5, '在认真对比了半个月后，同价位的电脑里，当下几乎无\n出其右啦。今年红米pro15的精心调教，配上AMD最新\n处理器在核显能力上的大幅提升，综合成品配合几乎是\n目前轻薄本里的顶级性能释放。外观上，红米延误了\nCNC一体化制造的超好切合，严丝合缝，质感十足，\n在视觉上甚至媲美苹果的颜值。手感上，内外细磨砂手\n感，温润如玉，恰到好处。屏幕，性能，做工品控，这\n次红米确实是一次巨大的飞越。加上自己小米的生态产\n品，生活办公娱乐的质量，获得了非常高效的提前。具\n体产品的深度体验，续航的实际情况等，在一段时间的\n使用后,再来详细追评。\n其他特色：指纹解锁方便，快速，电脑小巧轻薄方便携\n带外观材质：外观简洁大方，好看，灰银色很好看显卡\n效果：独立显卡，MX550，运行很流畅电脑性能：第\n12代智能英特尔酷睿移动式处理器i7-12650H，性能很\n强，本人目前是硬件工程师，平时使用cadence，运行\n流畅，也不怎么发烫，使用感优秀。', 'Redmi Pro 14英寸 2.5K屏', '2022-08-17 20:44:18', 3);
INSERT INTO `data` VALUES (13640, 'L***6', 5, '做工完美，屏幕清晰，系统超快！跑分近90万，LOL180-140之间，我奔着锐龙R7的，14寸2K，cnc，120刷新买的！办公加很很很轻度游戏。就这几个参数，难道还有性价比超过它的吗！放心买！', '新锐龙标压R7|2.5K高色域屏', '2022-06-18 09:32:50', 1);
INSERT INTO `data` VALUES (13641, 'c***t', 5, '运行速度：AMD Yes！\n屏幕效果：相当不错，色彩鲜艳\n散热性能：办公不错\n外形外观：相当不错，手感一流\n轻薄程度：轻便\n其他特色：AMD核显给力！\n运行速度：刚刚的', '新小米Pro 14英寸 2.8K屏', '2022-08-19 00:31:21', 4);
INSERT INTO `data` VALUES (13642, 'I***限', 5, '给外甥女买的学习用的笔记本，她不玩游戏，有这配置是完全足够了！\n运行速度：Amd次代的R7Cpu，能满足所有的工作学习场景。\n屏幕效果：屏幕是3.2k，超高分辨率，看起来就是舒服。\n散热性能：全金属外壳，散热效能杠杠的！', '新Redmi Pro 15英寸 3.2K屏', '2023-01-14 14:45:01', 4);
INSERT INTO `data` VALUES (13643, 'j***9', 5, '运行速度：十分流畅\n屏幕效果：很好，比之前的笔记本强很多。\n散热性能：风扇声音不大\n外形外观：很漂亮，比小新好看很多\n轻薄程度：很薄，因为以前用14寸刚换15.6觉得稍稍有些重\n其他特色：和小米手机互联效果很好～', '新锐龙标压R7|3.2K高色域大屏', '2022-06-14 12:42:19', 3);
INSERT INTO `data` VALUES (13644, 'k***1', 5, '运行速度：蛮快的，嗖嗖的\n屏幕效果：清晰，看电影很好\n\n散热性能：不错，没有很烫的感觉\n外形外观：非常漂亮，金属的感觉很好，棱角分明\n轻薄程度：蛮轻薄的，拿起来不费劲，一只手就可以拿起来', '新Redmi Pro 15英寸 3.2K屏', '2023-01-12 10:14:58', 3);
INSERT INTO `data` VALUES (13645, '陈***梓', 5, '终于可以淘汰t520了  性能很好 体验丝滑顺畅，机身材质全铝合金深得我心，机器尺寸看起来只有以前14寸大 真的很小巧   哈哈哈哈哈，屏幕也很满意  终于没有看不清晰字的问题了，总之总体来说很满意，但是也有不足，没有电脑包， 键盘没独立数字键盘，接口实在少啊  我买了扩展坞', '新锐龙标压R7|3.2K高色域大屏', '2022-08-15 17:22:52', 5);
INSERT INTO `data` VALUES (13646, '神***良', 5, '轻薄好用，外观满分，办公神奇。\n运行速度：非常快，办公和屏幕游戏都不错。\n屏幕效果：雾面屏，效果不错。\n散热性能：还不错基本感觉不到很热。\n外形外观：这点满分，超过预期。', '新Redmi Pro 14英寸 2.5K屏', '2023-01-09 07:18:24', 3);
INSERT INTO `data` VALUES (13647, 'j***d', 5, '比较了好久，最终选了这款，小米品质果然没让我失望，性价比高，开机速度超级快，画质清晰，运行流畅，内存大，无发热噪声等问题，买了一台后又买一台给儿子上课用', '新Redmi Pro 15英寸 3.2K屏', '2023-01-06 20:37:10', 6);
INSERT INTO `data` VALUES (13648, '七***雪', 5, '帮高考完的妹妹买的，对比了好多个，妹妹一眼就相中了这个，就决定是它了！到手果然没失望，轻薄好看，颜值高，屏幕素质好，CNC工艺精致机身，r5用来打打小游戏也够了', '新Redmi Pro 14英寸 2.5K屏', '2022-08-31 22:27:23', 5);
INSERT INTO `data` VALUES (13649, '啸***月', 5, '新一代A处理器效果很好，屏幕素质不错，长时间办公也没有多大压力，做工工艺没话说，在小米产品上居然能感受到一丝精致感，屏幕大小很合适，适合我们这样的中老年人。', '新Redmi Pro 15英寸 3.2K屏', '2022-08-18 13:15:24', 5);
INSERT INTO `data` VALUES (13650, 'u***v', 5, 'R7 6800H的处理器简直不要太好 相比12代i5还是瑞龙更强一些 性价比也是超级高 目前使用无任何问题\n散热性能：散热超级不错了 以前的电脑稍微一使用就烫手 这个完全没有\n外形外观：15.6英寸的也没感觉超级大感觉很合适\n屏幕效果：3.2K高分辨率爱了爱了\n轻薄程度：很轻薄', '新Redmi Pro 15英寸 3.2K屏', '2022-11-11 17:20:03', 4);
INSERT INTO `data` VALUES (13651, '日***鱼', 5, '全金属cnc机身 拿在手里有点份量 质感和做工非常棒\n键盘键程比较长 打字手感很好\n屏幕显示效果很棒\n性能释放不错 待机基本没声音 满载声音也不大', '新Redmi Pro 15英寸 3.2K屏', '2022-09-18 15:18:05', 4);
INSERT INTO `data` VALUES (13652, '慧***A', 5, '触摸手感不错 颜色设计也是我很喜欢的黑金 对于我来说挺轻薄的，携带起来方便 启动也可以 这款是这次蓝牙的，连接键盘和手机都方便哦。客服态度专业可以 响应及时', 'Redmi Pro 14英寸 2.5K屏', '2023-03-06 10:17:28', 5);
INSERT INTO `data` VALUES (13653, '一***间', 5, '京东物流送货超快，整机的质感很好，cnc工艺确实好，边沿顺滑，屏幕显示效果很棒，15.6的尺寸也合适，不到2公斤的重量，出门携带也算方便，处理器是AMD最新的R7-6800，应该是当下最强集显了，游戏还没试，看网上评论效果很好，改天试试。使用期间死过一次机，开不了机，打电话给售后很快解决了，整体来说还是不错的，4999元6期白条免息性价比还是挺高的。', '新Redmi Pro 15英寸 3.2K屏', '2023-01-31 14:16:54', 4);
INSERT INTO `data` VALUES (13654, '止***头', 5, '外形外观：很漂亮 磨砂材质手感很好，做工很细。\n容量空间：16G再也不用担心内存不够了。\n屏幕效果：2.5K屏真的很清晰，以前电脑1080p的，对比一下红米这个真的很惊艳。\n很满意的一款电脑。', '锐龙R5六核|2.5K高色域屏', '2022-07-24 13:11:26', 5);
INSERT INTO `data` VALUES (13655, '知***伟', 5, '屏幕效果：效果棒棒哒，就是为了屏幕和cnc买的这台机子\n散热性能：性能释放非常好，长时间使用不卡顿\n外形外观：外观精致，机器也很薄\n其他特色：和手机联动功能很好用', '新Redmi Pro 15英寸 3.2K屏', '2022-09-02 14:43:05', 4);
INSERT INTO `data` VALUES (13656, '是***呢', 5, '这款小米小米笔记本还蛮满意的哈，做工还真挺讲究的，精美的外观设计风格，我自己也是才入手没多久的，小米电脑外观简洁大气，我买了银色的，质感有点磨砂，低调奢华，运行速度很快，我平时不怎么玩游戏，办公使用速度很快，屏幕清晰，颜色正，电脑也不厚，重量合适，放在双肩背包里面刚刚合适，散热也很好，总之这次比较满意。', 'Redmi G 2.5K 165hz电竞屏', '2023-02-25 12:59:28', 8);
INSERT INTO `data` VALUES (13657, '罓***沙', 5, '包装保护：快递包装结实，京东快递快，无破损\n外形外观：外观时尚简约，美观大方，符合年轻审美，接口丰富，满足日常需求\n画面品质：画质清晰，2.5k，165hz屏，玩游戏流畅丝滑\n运行速度：16g大内存配合win11，系统运行流畅度快的不要不要\n游戏效果：游戏运行高帧流畅，画面展现生动细腻，风扇噪音小，散热赞', 'Redmi G 2.5K 165hz电竞屏', '2022-09-16 21:37:11', 5);
INSERT INTO `data` VALUES (13658, 'h***8', 5, '包装保护：包装好，占空间不大，保护不错\n外形外观：外形很酷\n画面品质：画面挺好，还有防蓝光护眼模式\n运行速度：速度没问题，很流畅\n游戏效果：不卡顿，整体流畅\n\n家里现在一系列小米的生态产品。这笔记本的miui+程序，直接联动手机，直接不用数据线电脑操作手机，相当于投屏，很方便', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-12 10:22:25', 4);
INSERT INTO `data` VALUES (13659, 'L***4', 5, '我是退掉拯救者Y7000P转过来买REDMI G 2022的，配置几乎一模一样，价格要高出1300元，还是红米靠谱，整体设计非常大气！发货速度特别快，晚上8点下单，第二天中午就收到了，京东给力！满意的一次购物满意的电脑', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-25 12:41:17', 6);
INSERT INTO `data` VALUES (13660, 'j***m', 5, '性能很强劲，金属模具提升了质量和散热水平。电池比标准版更大！要是和标准版一样提供两个硬盘扩展就更让人满意了！加油Redmi G', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-28 08:48:27', 9);
INSERT INTO `data` VALUES (13661, '李***6', 5, '包装保护：包装很好，颜值不错，质量也没有问\n外形外观：外观大气上档次！LOGO简约有品质\n画面品质：显示细腻。色彩丰富。\n运行速度：进行速度杠杠的。\n性价比超级高的一款电脑。会再体验一段时间后再来追评。', 'Redmi G 2.5K 165hz电竞屏', '2023-01-26 16:54:28', 7);
INSERT INTO `data` VALUES (13662, '不***_', 5, '很满意?，做工很好，物流快，客服很棒，点赞材质结实，手感好，很得劲，物流也快，性价比很高，值得购买?大品牌！值得信赖！效果超级好！贵有贵的道理！很棒的商品！跟实体店没有区别，还便宜，喜欢！当时买的时候还在犹豫价格，买来之后一点都不后悔，而且物流还快，可以入手?终于对它下手了，颜值是真的没话说?，材质很好，物美价廉，趁活动赶紧囤起来', 'Redmi G 2.5K 165hz电竞屏', '2022-11-18 23:09:16', 9);
INSERT INTO `data` VALUES (13663, 'j***v', 5, '包装保护：放了多个海绵垫，保护完美\n外形外观：高端大气上档次\n画面品质：屏幕清晰，240的刷新频率\n跑分评测：1583038的跑分，在游戏本里很能打\n运行速度：很便捷\n游戏效果：流畅', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-01 18:41:57', 6);
INSERT INTO `data` VALUES (13664, 'z***E', 5, '包装保护：有很多泡沫保护\n外形外观：个人很喜欢。\n画面品质：个人很喜欢，看图\n跑分评测：不会，不是天天用\n运行速度：开的安静模式，\n游戏效果：还行吧，有很强针对性的可以问客服，更专业。\n第二台小米笔记本，', '12代I5|RTX3050|2.5K高刷屏', '2022-08-09 21:09:43', 7);
INSERT INTO `data` VALUES (13665, 'j***v', 5, '包装的很好，没有出现破坏，\n外形外观：漂亮的\n跑分评测：138万\n游戏效果：很好\n运行速度：很好', 'Redmi G Pro 2.5K 240hz电竞屏', '2023-01-09 20:37:54', 8);
INSERT INTO `data` VALUES (13666, '炖***肉', 5, '包装保护：保护很到位。\n画面品质：清晰锐利，验机没有坏点。\n跑分评测：单核700多分，二级缓存8m够用。\n运行速度：Wi-Fi6网卡，网络流畅。\n游戏效果：网游低画质跑满165hz刷新率。\n外形外观：有数字小健盘，和一个小爱按钮，好评。', '12代I5|RTX3050|2.5K高刷屏', '2022-08-09 15:02:14', 6);
INSERT INTO `data` VALUES (13667, 'c***0', 5, '包装完好，电脑?拆封后完美无瑕疵，屏幕很亮很清晰，喜欢小米的工艺设计，很用心，很有质感，满意！', 'Redmi G 2.5K 165hz电竞屏', '2022-12-24 00:13:00', 8);
INSERT INTO `data` VALUES (13668, '1***p', 5, '配置高，价格实惠，使用感受赏心悦目。看8k 60帧HDR的视频超棒。极力推荐哦。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-14 16:19:40', 5);
INSERT INTO `data` VALUES (13669, '天***色', 5, '包装保护：包装结实安全感满满\n外形外观：和上一代相比看起来高端大气上档次\n画面品质：清晰可见\n运行速度：快到飞起来\n游戏效果：还没玩过 应该没问题', '12代I7|RTX3050Ti|2.5K高刷屏', '2022-08-03 18:25:34', 3);
INSERT INTO `data` VALUES (13670, 'j***1', 5, '运行速度快，电脑外形漂亮，有个性，能和手机互联，很满意，期待后续持续给力\n包装保护：完好无损\n外形外观：漂亮，有质感\n画面品质：2.5K很清晰\n\n运行速度：一个字快\n游戏效果：不玩游戏，没有测试', '12代I7|RTX3050Ti|2.5K高刷屏', '2022-07-28 22:18:03', 5);
INSERT INTO `data` VALUES (13671, '假***麟', 3, '感觉还可以，整体看上去没有大问题', 'Redmi G 2.5K 165hz电竞屏', '2023-02-28 13:59:51', 2);
INSERT INTO `data` VALUES (13672, '半***港', 5, '可以，外观非常nice，高刷屏看起来很舒服。性能释放不错，虽然只打打网游，控制中心好评，非常友好。屏幕素质不错，重量还行，总体OK。', 'Redmi G 2.5K 165hz电竞屏', '2022-10-04 23:30:49', 2);
INSERT INTO `data` VALUES (13673, '大***辽', 5, '外形外观：电脑很好看，很有质感\n画面品质：画面特别舒服\n包装保护：包装保护结实\n京东物流很快，机器挺有分量，性能也不错，充电器也好看', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-25 19:31:54', 5);
INSERT INTO `data` VALUES (13674, '小***哒', 5, '包装保护：很有安全感\n外形外观：比上一代好了看很多，全金属外壳\n画面品质：高刷屏幕玩游戏非常爽\n跑分评测：没测过，应该不会低\n游戏效果：LOL最高画质没压力', 'Redmi G 2.5K 165hz电竞屏', '2022-11-11 20:12:46', 5);
INSERT INTO `data` VALUES (13675, 'l***8', 5, '价格低，性比价高物美价廉，相信国产品牌，比想象中的好很多，物流特别快满意，看得出来商家很用心。宝贝真心不错，美观又大方，非常好看 大方 ，东西比我想象中的还要完美，外观比较好看，总的来说完美，准时。服务态度好，用了感觉不错宝贝收到后很满意，东西总体不错给个好评，我很喜欢，推荐推荐', 'Redmi G 2.5K 165hz电竞屏', '2023-01-23 17:19:19', 3);
INSERT INTO `data` VALUES (13676, 'J***g', 5, '笔记本内部做工非常不错如下图。我自带的铠侠512g硬盘，不太够用自己更换了国产致钛1TB，并且加了1TB游戏盘，重装了系统，而且加上了散热铜片。\n重置装好之后试了原神，稳定流畅，i5+3050，玩玩原神，上网课什么还是很不错的。\n屏幕是华星光电的2.5k屏幕，观感很不错，显示效果也很不错。', 'Redmi G 2.5K 165hz电竞屏', '2022-09-19 15:44:59', 5);
INSERT INTO `data` VALUES (13677, '晴***u', 5, '电脑外观挺不错的，手感很棒，屏幕分辨率也挺高的，安装了一些软件和游戏，很流畅，噪音不大，还算安静', 'Redmi G 2.5K 165hz电竞屏', '2022-09-10 13:34:11', 6);
INSERT INTO `data` VALUES (13678, 'j***v', 5, '包装保护：外包装和内包装完好无损\n外形外观：高大上，很有质感！\n画面品质：清晰流畅！\n跑分评测：非常优秀！\n运行速度：非常快，感觉不到停顿！\n游戏效果：流畅而大气，大游戏也是轻松流畅而无任何卡顿现象！', '12代I5|RTX3050|2.5K高刷屏', '2022-07-28 16:59:03', 5);
INSERT INTO `data` VALUES (13679, '鑫***4', 5, '非常好的电脑，很有质感，有种高端的感觉。\n日常使用应该没有问题，还没有试游戏。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-10-14 09:14:35', 7);
INSERT INTO `data` VALUES (13680, '爱***柏', 5, '包装保护：装太垃圾了 最外面一层已经散架了\n画面品质：不错 \n游戏效果：容易卡退，才用了一天就因为游戏卡了出来卡关机了 \n运行速度：很不错', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-24 21:22:14', 1);
INSERT INTO `data` VALUES (13681, 'j***6', 5, '包装保护：送过来的时候烂了一个大洞\n外形外观：很漂亮，质感也很好\n画面品质：画质清晰，看着很舒服\n跑分评测：正常的跑分\n用鲁大师验机，各项都正常。\n游戏效果：玩原神很舒服，其他游戏也很棒，音质音效也很不错', 'Redmi G 2.5K 165hz电竞屏', '2022-12-20 22:21:18', 4);
INSERT INTO `data` VALUES (13682, 'u***8', 5, '包装保护：包装保护：完好无损，保护的很好，没有损坏。\n外形外观：外观精致，有质感\n画面品质：屏幕很棒，很清晰\n跑分评测：性价比很高', 'Redmi G 2.5K 165hz电竞屏', '2022-09-10 14:53:34', 1);
INSERT INTO `data` VALUES (13683, '丞***g', 5, '包装保护：很好，全新包装，超大一个包裹有很多空气保护防爆膜\n外形外观：全金属机身，很有质感\n画面品质：超级好', 'Redmi G 2.5K 165hz电竞屏', '2022-09-14 14:07:01', 6);
INSERT INTO `data` VALUES (13684, '喵***9', 5, '物流快第二天就到了。包装完好整齐精致，外形好看，黑色很酷，画面品质一流，超级清晰，跑分很高，运行速度很快，到手玩了游戏体验感非常好，游戏很流畅，不卡顿，也不是很热，风扇声音也不大，总之很满意。', 'Redmi G 2.5K 165hz电竞屏', '2022-12-29 10:41:49', 4);
INSERT INTO `data` VALUES (13685, '萌***略', 5, '电脑很好吃，很满意，物流也很快  没事黑个屏  卡个顿  但是客服都会教给你解决方法的  售后说下午五六点就来邮寄回去   一晚上都没来  给打了电话说让我自己去邮寄就行了  我很满意希望你们今后一直保持', 'Redmi G 2.5K 165hz电竞屏', '2022-09-11 14:01:10', 3);
INSERT INTO `data` VALUES (13686, 'e***0', 5, '很好，性价比很高。\n\n当初选择6000元左右的电脑，做了好多功课，这样那样各种比对，最后还是选择了性价比之王的redmi G。\n包装保护：还可以把，来了一个小箱子，里面只有电脑和电源适配器，美中不足的是，不赠送鼠标，没有电脑包。\n外形外观：游戏本我不喜欢那种造型特别夸张的，这款还算低调。\n画面品质：可以说非常棒了，专业级显示器，正好我也是办公用。\n跑分评测：暂时没跑，看评测挺高的\n运行速度：嘎嘎快，多程序运行也毫无压力。3A游戏目前还没测试过，不玩那个，哈哈。\n游戏效果：以后再评。', 'Redmi G 2.5K 165hz电竞屏', '2022-09-15 07:47:20', 4);
INSERT INTO `data` VALUES (13687, 'u***w', 5, '英特尔最新酷睿Redmi G 2.5K 165hz 电竞屏；12代15标。\nRedmi G Pro 2.5K 240hz电竞屏；新锐龙&hellip;\n包装保护：用硬质纸板防护，京东快递很给力，没有出现破损\n外形外观：比上一代进步多了，A面金属，很有质感，标志简单美观，一眼看上去就很时尚。接口非常丰富，USB， HDMI2.1，网口，全功能type c可以满足全方位需求\n画面品质：高色域 250hz的屏幕真的非常亮\n眼，颜色正，输出效果好，而且这次屏幕*的\n下巴处理的很好，屏占比很高，看着很舒服\n运行速度：旗舰级配置，运行稳定流畅，暂时没有发现系统和驱动方面的问题\n游戏效果：独显直连，输出效果很棒，开光追\n和不开的区别非常大(具体看图）\n缺点：电源适配器真的又大又重，好在全功能\ntypec支\n持充电，临时外出不玩游戏的情况可以应付；\n风扇声真的大，玩游戏时候风扇跑起来有点吵\n结论，机子性能，外观，配置都很棒，预留了\n第二个硬盘口', 'Redmi G 2.5K 165hz电竞屏', '2023-01-02 11:20:20', 2);
INSERT INTO `data` VALUES (13688, 'j***w', 5, '产品真的超级棒，下次还会买的，愿越做越好，非常好的购物体验是正品很好用，价格便宜了很多，性价比超高，真的特别划算，包装也很高端大气上档次，值得购买\n包装保护：保护的很好，外面用了个很大的箱子保护\n外形外观：是正品新品\n画面品质：很清晰gtx3050就是不一样\n跑分评测：很高\n运行速度：非常快', 'Redmi G 2.5K 165hz电竞屏', '2022-12-09 20:54:34', 6);
INSERT INTO `data` VALUES (13689, '河***h', 5, '电脑还不错，性价比很高，配置高，使用起来流畅不卡顿，特别舒适，可以打游戏，办公无压力。除了比较重，没啥缺点，不过游戏本都这样，使用起来整体感受很棒。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-10-13 11:24:28', 4);
INSERT INTO `data` VALUES (13690, '茨***少', 5, '性價比很高，屏幕的高刷新率，很清晰色彩調和清晰，獨立顯卡很到機器有很大的前途和可塑性，機器在操作上很順暢，安裝純淨版的WIN11，很方便，運行速度也很快和順暢，機器外觀很好看，顏值也很高，各種各樣的外掛設備端口應有盡有，在散熱方面很效率很高，機器運行溫度都在40-50℃左右，鍵盤為全面盤，還有獨立數字區，很讚??機器再用多一段時間過追評！', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-11 17:44:40', 2);
INSERT INTO `data` VALUES (13691, 'T***z', 5, '电脑非常不错，小米的东西注重性价比，同配置里价位最低的就是小米了。\n使用体验来说的话，除了风扇声音比较大之外，一切都非常不错。外观也比较酷炫。还有独显直连功能，非常适合打游戏！', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-18 08:05:13', 1);
INSERT INTO `data` VALUES (13692, '缘***哦', 5, '很好很不错，快递速度很快，隔天就到了！玩永劫无间游戏很流畅，一点都不卡', 'Redmi G 2.5K 165hz电竞屏', '2023-01-31 13:42:41', 7);
INSERT INTO `data` VALUES (13693, 'j***k', 5, '电脑很好\n包装保护：没问题，保护的超级好\n外形外观：漂亮，超级漂亮！！！！\n画面品质：画质超级好，顶级屏幕\n跑分评测：没有跑，主要检查了没问题，\n运行速度：超级快！！！！！\n游戏效果：玩了糖豆人哈哈哈哈哈哈', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-29 12:16:34', 3);
INSERT INTO `data` VALUES (13694, 'u***o', 3, '配置不错，就是没有硬盘扩展位，', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-29 11:36:56', 9);
INSERT INTO `data` VALUES (13695, 'j***p', 5, '包装保护：外面还专门套了个箱子，可以的\n外形外观：很有档次感\n画面品质：屏幕很不错\n跑分评测：跑分感觉可以的\n运行速度：可以的\n游戏效果：还没试', '12代I5|RTX3050|2.5K高刷屏', '2022-08-11 13:09:57', 4);
INSERT INTO `data` VALUES (13696, '半***港', 5, '整体外观相比上一代进步很大，屏幕素质很棒很棒，a面摸起来很爽。机身重量控制的很好，键盘手感也很不错。散热表现非常好，性价比很高。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-03 23:00:10', 1);
INSERT INTO `data` VALUES (13697, '景***少', 5, '金属手感贼好，屏幕真的细腻啊，流畅得很！感觉物超所值啊\n包装保护：包装完好无损！\n外形外观：金属质感，摸着很舒服！\n画面品质：165刷新率真的是丝滑流畅啊！\n游戏效果：游戏很流畅，3050给力！', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-26 12:06:19', 5);
INSERT INTO `data` VALUES (13698, 'j***1', 5, '京东平台选购笔记本电脑非常方便，我选的小米笔记本是游戏本，游戏版本体验很好啊，而且是最新款的，在京东下单，随后送货的京东小哥送货也非常及时，京东的购物体验是不错的。同时，小米笔记本里面颜值、性能非常好的。再有后期服务值得期待。', '12代I5|RTX3050|2.5K高刷屏', '2022-07-28 11:58:09', 3);
INSERT INTO `data` VALUES (13699, '心***心', 5, '大学生首选电脑，质优价廉，运行内存快，使用下面常，散热好，速度快，打游戏一流。质量非常好，完全超出期望值，发货速度非常快，包装非常仔细、严实，很满意的一次购物物超所值，商品设计完美，外观也很高大上，让人爱不释手。客服更是热情的没话说，这次购物很满意', 'Redmi G 2.5K 165hz电竞屏', '2022-12-04 09:00:11', 4);
INSERT INTO `data` VALUES (13700, 'j***X', 5, '外形外观：朴素并不失科技感，金属a面很有质感\n包装保护：套了两层纸盒，保护得很好\n画面品质：不愧是2.5k屏，画面很细腻，赶得上手机了\n跑分评测：到手就下了鲁大师，能跑到17w+,超过98%\n运行速度：开机大概3秒左右，对得起他的配置\n游戏效果：还没下，应该3a大作高画质都毫无压力', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-03 08:40:22', 3);
INSERT INTO `data` VALUES (13701, '讨***天', 5, '非常快，一个晚上就送到了。外面多套了个纸箱，有点儿瘪，当面打开，里面的箱子完好无损。第一次开机需要连接电源，开机就一路设置激活，期间不能关机，所以没准备好的话，不要开机。设置好以后试了试，都很好，没发现问题，连接小米手机也很方便。', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-26 19:29:34', 4);
INSERT INTO `data` VALUES (13702, '深***心', 5, '宝贝做工真的非常精细，细节真的棒，爱了爱了，尤其是后面的散热，非常好，风扇声音也能接受，这个价位买红米肯定不会错，面对主流游戏也完全够用了。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-20 15:54:54', 4);
INSERT INTO `data` VALUES (13703, '人***1', 5, '包装保护：外包装下雨天裹了一层保鲜膜，但不知为何外箱口是开的\n外形外观：金属感十足\n画面品质：2k画质，跟1080p差别很大\n跑分评测：跑分只图一乐，实际体验才是最重要的，当然评分也不低\n运行速度：十分流畅\n游戏效果：LOL，cf无压力\n\n在office激活等方面，客服很专业，也十分耐心引导如何一步步的操作', 'Redmi G 2.5K 165hz电竞屏', '2022-11-29 21:49:35', 4);
INSERT INTO `data` VALUES (13704, 'j***U', 5, '首先电脑的颜值非常高，A面是金属的，质感很好，对比去年，简直是质的提升；B面是16:10的屏，屏占比非常高（?&ograve; &forall; &oacute;?）；C面有数字小键盘，以及一个比较大的触摸板，挺好的；D面就是大的散热口。最后旁边以及背后的接口也非常多。', 'Redmi G 2.5K 165hz电竞屏', '2022-09-14 13:20:17', 3);
INSERT INTO `data` VALUES (13705, 'C***凯', 5, '包装保护：包装完美里面还有泡沫点赞\n外形外观：外观挺还看得比第一代好看，12：10屏幕比例不错，边框很窄\n画面品质：2.5K超级清晰，看电影观感不错\n运行速度：快的飞起不错\n游戏效果：挺快的只玩英雄联盟没一点压力', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-27 11:35:48', 4);
INSERT INTO `data` VALUES (13706, 't***6', 5, '包装保护：包装严实，京东物流杠杠的\n外形外观：还算可以，这样的配置和价格，只要不是全塑料就很良心了\n画面品质：这样的屏幕配这样的显卡很完美\n跑分评测：接近180万\n运行速度：非常流畅\n游戏效果：扫雷不卡，斗地主特效全开跑满显示器刷新率', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-25 14:51:16', 4);
INSERT INTO `data` VALUES (13707, '甘***号', 5, '京东快递速度很快，电脑给同学买的，他很喜欢，外观很好看，小米加油是正品很好用，价格便宜了很多，性价比超高，真的特别划算，包装也很高端大气上档次，值得购买', 'Redmi G 2.5K 165hz电竞屏', '2022-11-04 12:45:01', 7);
INSERT INTO `data` VALUES (13708, 'j***N', 5, '包装保护：非常完整\n外形外观：非常炫酷\n跑分评测：很高\n运行速度：非常快\n游戏效果：很流畅', 'Redmi G 2.5K 165hz电竞屏', '2022-10-16 12:52:00', 5);
INSERT INTO `data` VALUES (13709, '愿***逢', 5, '真的要说小米RedmiG 2022酷睿版游戏本外观是我喜欢的，质量还行，小米RedmiG 2022酷睿版性价比比较高,小米RedmiG 2022酷睿版包装保护：包装上面 很用心 里面垫的很多泡沫之类的防碰撞的还有防尘的罩子 很用心 整机还是的外形外观：外观很满意 黑色就显得很深沉霸气 有种范 黑色壳子加上拯救者的那个标志很舒服 个人很满意画面品质：正在使用 过后会追加评论 屏幕的颜色还是很好的 因为自己没事会画几个壁纸 使用起来 都显示正常评测评测：383545分 感觉挺不错的运行速度：开机也挺快的操作起来也挺流畅的游戏效果：暂时只安装了gta5玩起来很顺畅 风扇的声音也还可以接受整理来说很满意。我觉得小米RedmiG 2022酷睿版挺好的，目前的活动还是给力的，很划算，值得入手的！', 'Redmi G 2.5K 165hz电竞屏', '2022-11-26 14:53:53', 4);
INSERT INTO `data` VALUES (13710, 'j***c', 5, '下单隔一天就收到货，收到后第一时间拆开，有被惊艳到，非常喜欢！试用后感觉如下，质感非常好，开机反应很快，画质很棒，有点重，使用过程中运行速度也非常快！', 'Redmi G 2.5K 165hz电竞屏', '2022-11-06 11:14:10', 4);
INSERT INTO `data` VALUES (13711, 'j***V', 5, '正品，物流超级快，性价比真高，用一段时间再来追评。\n因为用的小米的手机，才选择了米家的笔记本。可冲\n包装保护：好\n外形外观：好\n画面品质：拯救者同款\n运行速度：挺快的', 'Redmi G 2.5K 165hz电竞屏', '2022-09-10 20:22:01', 5);
INSERT INTO `data` VALUES (13712, 'e***p', 5, '心心念念的笔记本终于到了，果然没让我失望，金属机\n身，打开显卡直连，调到狂派模式，鲁大师最新版能跑到\n172w，让我最关心的是屏幕的素质240HZ，整体画面细腻满足我的预期，安装了各种游戏，全部开到最高，畅\n玩无压力', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-04 21:06:26', 4);
INSERT INTO `data` VALUES (13713, '牛***文', 5, '就是这么的帅气，很流畅，屏幕超级清晰，这是的第二台小米的笔记本电脑，做设计什么的随便耍，质感真的太好了，不负我这么多天的等待，稍微笨重了一点，不过这种性能太棒了，值得的', '12代I5|RTX3050|2.5K高刷屏', '2022-07-29 11:36:38', 5);
INSERT INTO `data` VALUES (13714, 'M***咩', 5, '包装保护：可以，很不错\n外形外观：无磕碰\n画面品质：强\n运行速度：可以\n \n物流快，服务态度好，期待之后的游戏效果，非常不错的游戏本，屏占比很高，外观我喜欢， 屏幕清晰，很有质感，亮度高，无坏点。控制很好，键盘稳定度也高，目前体验很不错了。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-04 12:17:26', 2);
INSERT INTO `data` VALUES (13715, '居***味', 5, '颜值很高，看起来很舒服，做工不错，很强的金属质感，运行比较流畅，比价不足的是内存16G和硬盘500G，没有更大的选择，如果有更大的选择就更好了！物流包裹很好，双十一的活动也比较给力！', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-20 22:40:35', 4);
INSERT INTO `data` VALUES (13716, 'j***p', 3, '一般般，这个价格，挺好的', 'Redmi G 2.5K 165hz电竞屏', '2022-09-13 20:38:12', 1);
INSERT INTO `data` VALUES (13717, 'N***奶', 5, '外形外观：屏幕是16英寸16：10的2.5K分辨率，240Hz刷新率，91%的屏占比，500尼特亮度。 支持独显直连。支持PD充电。 A面金属材质材质，提升了质感。数字小键盘配大尺寸方向键。 配80Wh的电池。机身最厚28mm，最重达3Kg。 三根热管散热，英特尔版最高180W的整机性能\n包装保护：包装有点夸张，拿到包裹一度怀疑是不是自己的本子\n画面品质：绝\n跑分评测：主要是用于剪辑，修图，对我来说已经很完美了', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-09-19 14:20:21', 3);
INSERT INTO `data` VALUES (13718, '张***迅', 5, '学工科孩子自己挑选的，已经用了一段时间了，感觉很好。外形靓丽，A面金属，很有质感，标志简单时尚。接口丰富，满足需要。画面品质：高色域 250hz的屏幕真的非常亮眼，颜色正，输出效果好，屏占比很高。运行速度：旗舰级配置，运行稳定流畅，暂时没有发现系统和驱动方面的问题。游戏效果：独显直连，输出效果很棒。', 'Redmi G Pro 2.5K 240hz电竞屏', '2023-01-18 13:44:00', 3);
INSERT INTO `data` VALUES (13719, '超***9', 5, '非常好一台游戏本?同寝室的舍友拯救者都没这台好。舍友的拯救者开机都有风扇噪音的问题，而我这台到现在都没有出现问题。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-27 19:04:01', 2);
INSERT INTO `data` VALUES (13720, '灵***舟', 5, '包装保护：外包装精致，黑色纸壳子，看着高级，内部防护到位\n外形外观：外观设计简约时尚，哑光的耐看，手感摸着也不错\n画面品质：这块屏幕对于我来说够用了，很高清，工作游戏都没有啥大问题了\n跑分评测：鲁娱乐大师测下来122万分，纯属娱乐\n整体上机器很好，我对电脑也不是很专业，初步尝试下来，配置够高，运行流畅，并且屏幕观感很好，键盘的键程足够，按着蛮舒服的，扩展接口也够用，散热很给力', 'Redmi G 2.5K 165hz电竞屏', '2022-11-03 10:16:37', 4);
INSERT INTO `data` VALUES (13721, 'r***i', 5, '外形外观：超漂亮，金属A面有感觉\n\n画面品质：屏幕很高清\n跑分评测：很强大，玩游戏也不热\n运行速度：非常快，打开网页和软件都是秒开\n游戏效果：相当给力', '12代I5|RTX3050|2.5K高刷屏', '2022-08-04 22:00:21', 3);
INSERT INTO `data` VALUES (13722, 'j***6', 5, '包装保护：包装好，保护好\n外形外观：漂亮，没有瑕疵\n画面品质：屏幕看着舒服，浏览流畅\n跑分评测：强大，轻松\n运行速度：很快\n游戏效果：给力', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-15 18:07:53', 2);
INSERT INTO `data` VALUES (13723, 'D***6', 5, '包装保护：包装很好，双层包装，很厚实。\n外形外观：金属A面，很有手感，很舒服。\n画面品质：2.5K屏，240高刷，很流畅。\n跑分评测：跑分还是很理想的，满足了\n运行速度：运行很快，超流畅，无卡顿感\n游戏效果：玩游戏一点压力没有，性能全开的话风扇声音有点大，不过可以接受。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-22 17:40:12', 2);
INSERT INTO `data` VALUES (13724, '了***鸽', 5, '不愧是英特尔最新酷睿。12代性能果然还是intel得处理器比较牛逼。整体机器非常有质感。金属面板摸起来很舒服。最亮眼还是屏幕16寸。高刷屏真的舒服。怎么都是真香。', 'Redmi G 2.5K 165hz电竞屏', '2023-01-02 08:53:12', 5);
INSERT INTO `data` VALUES (13725, 'j***L', 5, '外形外观：很不错，颜值很高！\n包装保护：非常的完整\n画面品质：很好，很清晰，屏很大\n键盘的手感也很好，各方面都很好！没有那么差，反正我感觉很值，我很喜欢！', '12代I5|RTX3050|2.5K高刷屏', '2022-07-29 16:36:40', 3);
INSERT INTO `data` VALUES (13726, '小***捺', 5, '物流速度很快 第二天就收到了 打开笔记本瞬间惊艳到了 真的好漂亮，完美的感觉，运行速度杠杠滴，还没装游戏，应该效果不会差的 加油redmi！', '12代I7|RTX3050Ti|2.5K高刷屏', '2022-07-28 22:01:11', 4);
INSERT INTO `data` VALUES (13727, 'p***w', 5, '电脑还是比较满意的，之前也冲了2020款的redmiG 用着一些视频剪辑类软件还算带得动，现在俩年过去了，又给朋友冲一台2022款，新款外壳摸着特别舒服，G系列的电脑也比较保值，在这款的MIUI+上面连接小米手机非常舒适', '12代I5|RTX3050|2.5K高刷屏', '2022-07-30 16:23:05', 5);
INSERT INTO `data` VALUES (13728, 'j***1', 5, '包装保护：还行用了一个很大的箱子装\n外形外观：外形ok，外观好看\n画面品质：非常好\n\n运行速度：快\n游戏效果：舒服', 'Redmi G 2.5K 165hz电竞屏', '2022-11-16 20:24:24', 3);
INSERT INTO `data` VALUES (13729, '青***贝', 5, '外形外观：高端大气有神秘感\n画面品质：清晰感很好\n包装保护：外面纸箱有点破损，里面还有内包装，完全没问题。\n运行速度：目前非常流畅，舒适感爆棚。\n游戏效果：有待测试。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-17 22:09:41', 3);
INSERT INTO `data` VALUES (13730, '壹***壹', 5, '包装保护：京东物流特别的给力\n外形外观：精致 美观\n画面品质：非常的清楚是我喜欢的\n运行速度：特别的快\n游戏效果：收到就试了一把游戏  体验非常的好', '12代I5|RTX3050|2.5K高刷屏', '2022-07-29 10:42:11', 3);
INSERT INTO `data` VALUES (13731, 'p***3', 5, '笔记本刚到手，包装保护，两层纸箱内有海绵包装很安全，外观外形金属质感相当的优雅\n运行速度:运行流畅，4种模式任意切换，2k屏没的说，非常清晰， 非常舒道！', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-16 22:39:55', 3);
INSERT INTO `data` VALUES (13732, 'J***家', 5, '游戏本当工作本用，手感不错，比较沉，男士用着很好，中规中矩，风扇声音很小，速度很快，工作需要，系统回来就被我给改了，浪费了正版的11了，键盘也很好，整体很好，很舒服', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-14 20:01:09', 3);
INSERT INTO `data` VALUES (13733, '时***好', 5, '这次选了好多类似配置笔记本产品，发现红米这款性价比和做工真是不错!???接口后置和工作站似的，外接设备线材不影响使用，金属质感摸着很舒服，高端大气上档次，客服专业，有问必答。\n      如果说建议，那就是建议厂家跟上国家国产化的步伐，本身以软件起家，把国产系统搬进小米，调试自己适配麒麟和统信，Linux系统能用的软件，驱动等，不能让win11系统卡住用户的信息权。', 'Redmi G Pro 2.5K 240hz电竞屏', '2023-01-12 14:57:54', 5);
INSERT INTO `data` VALUES (13734, '烁***利', 5, '外观很酷，摸着很有质感，插口多功能齐全，激活过程很顺利，有活动价格也合适，但是由于工作原因需要win10，重装了系统需要官方驱动要不会闪屏。目前使用稳定。', 'Redmi G 2.5K 165hz电竞屏', '2023-02-25 00:24:51', 5);
INSERT INTO `data` VALUES (13735, '今***天', 5, '东西很棒，略重但在承受范围内，男性提着跑应该不存在障碍，各项参数指标和描述完全一致，运行速度快，原神特效开满完全没有卡顿，非常满意的购物体验。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-07 23:28:16', 5);
INSERT INTO `data` VALUES (13736, 'j***t', 5, '非常厉害的笔记本，性能上非常强大，配备了3060的显卡，任何应用都不在话下，打游戏非常稳定，使用很久也不会卡顿，颜值方面也非常有个性。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-27 10:19:09', 3);
INSERT INTO `data` VALUES (13737, '倾***吟', 5, '快递真快，笔记本不错很赞，静音，速度快，就是系统得适应。值得推荐', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-10-20 09:32:05', 6);
INSERT INTO `data` VALUES (13738, 'F***r', 5, '双十一买的，由于疫情原因12月20号才拿到电脑，用了一段时间来评价。\n包装保护：很到位\n外形外观：很好，设计简洁，不夸张，用来当商务本也没问题\n画面品质：绝，很好\n跑分评测：138万分，要是开独显直连估计能更高\n运行速度：超快\n游戏效果：超好\n是在同等配置下性价比最高的一款电脑了，而且小米售后保障也到位。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-25 20:34:19', 3);
INSERT INTO `data` VALUES (13739, '龙***爷', 5, '用的很不错，桌面很干净，很多东西都很实用，比如控制台，都是中文的，都看的懂，用起来很舒服！', 'Redmi G 2.5K 165hz电竞屏', '2022-09-11 00:19:11', 2);
INSERT INTO `data` VALUES (13740, '阿***名', 5, '包装保护：保护很好，没有破损\n画面品质：屏显示效果非常OK\n外形外观：纯黑 挺有质感\n跑分评测：跑分还没跑\n游戏效果：打了两把永劫无间，还是非常OK的', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-09-03 18:57:48', 2);
INSERT INTO `data` VALUES (13741, 'Q***湘', 5, '看了很久的笔记本，之前看惠普跟拯救者的，同价位这个配置还是很香的，还有高刷跟高分配率，作为半个米粉，果断选择这款，虽然cpu差了点，各方面都不错', 'Redmi G 2.5K 165hz电竞屏', '2022-11-14 14:29:06', 5);
INSERT INTO `data` VALUES (13742, '盛***8', 5, '这个笔记本双十一买的，客服很专业，我的疑问都一一解答了，很喜欢这个，大尺寸的，性能也很好，我种草好久了，买来给娃娃看视频用的，开机时间很快，也很流畅，后期继续支持小米，客服超专业，赞', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-26 15:02:42', 5);
INSERT INTO `data` VALUES (13743, 'j***t', 5, '包装保护：外包装完整，内夹有泡沫夹板，结实\n外形外观：整体感觉舒服，没有损伤\n画面品质：清晰度很好，不伤眼，\n跑分评测：没有装跑分软件，不太清楚哦\n运行速度：感觉用起来还是很流畅的', 'Redmi G 2.5K 165hz电竞屏', '2022-09-14 17:16:18', 3);
INSERT INTO `data` VALUES (13744, '现***能', 5, '包装保护：很严实，用厚纸板包装\n外形外观：本来以为很丑，到了还觉得不错\n画面品质：2.5k屏幕很好用，8bit\n运行速度：运行速度很快\n游戏效果：主要玩我的世界，非常的流畅', 'Redmi G 2.5K 165hz电竞屏', '2022-11-02 16:26:33', 2);
INSERT INTO `data` VALUES (13745, '老***6', 5, '包装保护：很好，有2层包装，很完好，电脑可以\n外形外观：大气很好看，有档次\n画面品质：很好，很清楚，哈哈哈哈哈哈\n跑分评测：可以，挺满意的\n运行速度：很快，很流畅，这点还是很满足的', 'Redmi G 2.5K 165hz电竞屏', '2022-11-02 22:59:55', 2);
INSERT INTO `data` VALUES (13746, '李***8', 5, '包装保护：很好，包了两层，中间还有泡沫纸\n外形外观:很好看！棱角流畅！好酷！\n运行速度:挺快的\n游戏效果:不卡, 240hz很流畅', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-13 19:32:44', 2);
INSERT INTO `data` VALUES (13747, 'M***t', 5, '这代外观很时尚，观感手感都很好。\n性能可以满足绝大部分场景需求。\n屏幕观感非常好，同价位无敌。\n接口非常丰富，满足各种适配要求。', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-12 08:18:12', 4);
INSERT INTO `data` VALUES (13748, 'j***L', 5, '除了封条粘胶不是很好，?从没想过这么实惠的价格，?能买到这么好的宝贝，?性价比非常高，我很喜欢哦?\n游戏效果：暂定\n运行速度：挺快的\n画面品质：杠杠的\n外形外观：不错不错\n包装保护：大箱+小箱  双重保护（就是下次能用自己的箱子嘛，拿着尿不湿大箱贼尴尬）', 'Redmi G 2.5K 165hz电竞屏', '2022-09-12 12:08:18', 2);
INSERT INTO `data` VALUES (13749, 'j***Q', 5, '包装保护：用了一个大大的箱子保护的很好\n外形外观：挺好的嘛\n画面品质：画质可以，这个屏幕满分\n跑分评测：跑了170万分\n运行速度：快啊，根本不打游戏\n游戏效果：不知道', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-03 08:28:59', 2);
INSERT INTO `data` VALUES (13750, '吕***航', 5, '电脑很好，看起来很高端，金属机身拿起来有重量感，屏幕的色域也很好，用了几天没有任何问题，键盘会发亮，打字很轻松，好评', 'Redmi G 2.5K 165hz电竞屏', '2022-11-16 15:09:53', 3);
INSERT INTO `data` VALUES (13751, '牧***鸢', 5, '包装保护：外包转简约\n外形外观：外观大气上档次，手感好\n画面品质：屏幕质量不错显示效果好，整体质感很好\n运行速度：运行速度很快，流畅不卡顿\n游戏效果：游戏效果很好，稳定不掉帧，渲染效果很好，速度快，散热也很好', 'Redmi G 2.5K 165hz电竞屏', '2022-12-05 19:45:32', 2);
INSERT INTO `data` VALUES (13752, 'u***7', 5, '外形外观：外壳有金属质感，模具的质量很不错\n\n画面品质：2.5k屏看起来很舒服\n\n游戏效果：3050玩大多数游戏都没有问题，很流畅，还有显卡直连功能', 'Redmi G 2.5K 165hz电竞屏', '2022-11-08 10:06:14', 2);
INSERT INTO `data` VALUES (13753, '妖***风', 5, '包装保护：外包装有轻微破损，但是内部保护的非常好\n外形外观：A面金属，全黑机身，机器颜值非常高\n画面品质：2K ，255hz刷新率非常棒，画面表现一流\n跑分评测：跑分一百五十多万超过99%电脑很棒\n运行速度：运行速度非常流畅大型3A毫无压力\n游戏效果：游戏效果非常棒', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-03 20:33:38', 2);
INSERT INTO `data` VALUES (13754, '雨***n', 5, '太快了！昨晚八点付尾款，今天九点半就派送，十一点半放学就收货啦。\n外包装很大，还套了另一个更大的保护箱。\n2022版的金属外壳很有质感，摸着很爽，新机爽就对了。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-01 17:38:45', 5);
INSERT INTO `data` VALUES (13755, '小***a', 5, '正品无疑，验机成功，不是翻新机，没有遇到什么问题，鲁大师跑分一百七十多万，i9的处理器搭配3070ti显卡，配置方面可以说是顶级了，手感也极好，抽空再换一个2t的固态上去，就更加完美了，祝红米越来越好！\n包装保护：包装很严实，没有磕碰\n外形外观：金属A面，质感非常好\n画面品质：240hz刷新率屏幕，爽歪歪\n跑分评测：一百七十多万的跑分，就很nice\n运行速度：16g的运行内存，非常快\n游戏效果：3A大作游戏无压力', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-03 16:42:12', 3);
INSERT INTO `data` VALUES (13756, 'j***O', 5, '包装保护：好，双层牛皮纸保护非常好\n外形外观：战舰灰配色非常好看\n画面品质：2.5k240hz观感非常好\n运行速度：快，响应很快\n游戏效果：好，PUBG运行稳定，跑图160多帧', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-28 19:21:09', 2);
INSERT INTO `data` VALUES (13757, 's***3', 5, '性价比高，电脑很酷，打了一个星期游戏爽到飞，包装很好，外观没问题，画质很好，跑分很高，运行速度超快，游戏效果没得说', '12代I5|RTX3050|2.5K高刷屏', '2022-08-06 11:48:23', 4);
INSERT INTO `data` VALUES (13758, 'j***c', 5, '经过仔细对比和精心挑选、最终买了这台小米游戏本、感觉性价比很高、配置完全够用了！屏幕超级清晰、质感也很好！', 'Redmi G 2.5K 165hz电竞屏', '2022-12-13 16:23:19', 5);
INSERT INTO `data` VALUES (13759, '纯***I', 5, '软硬件优化得很好，使用起来感觉非常丝滑，放假了娱乐一下。\n包装保护：双层保护，没有滴点损伤 \n外形外观：很好，散热到位\n 画面品质：很好 \n运行速度：很快 \n游戏效果：不错的。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-25 12:27:17', 2);
INSERT INTO `data` VALUES (13760, '是***吖', 5, '外形外观：非常可以，很喜欢，简单大气\n运行速度：很快，这个价格很值了\n屏幕效果：2.5k效果好到爆，超出自己的想象其他特色：系统是11的，整体运行很快，不影响使用，操作功能很便捷，一直喜欢小米红米！', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-21 20:46:41', 2);
INSERT INTO `data` VALUES (13761, 'i***o', 5, '外形外观：电脑颜值也太高了吧，背面金属高级感满满，键盘超酷！\n画面品质：165HZ屏幕刷新率真的爽，办公游戏一步到位！\n跑分评测：跑分没的说，运行起来顺滑的不要不要的！', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-28 15:53:45', 2);
INSERT INTO `data` VALUES (13762, '踏***香', 5, '包装保护：完美无瑕\n外形外观：非常炫酷\n画面品质：清晰可见\n运行速度：像火箭一样快\n游戏效果：英雄联盟非常的好 体验效果完美反正就是没有缺点。是我第一次使用电脑以来最好的一次体验', '12代I5|RTX3050|2.5K高刷屏', '2022-07-29 10:47:20', 3);
INSERT INTO `data` VALUES (13763, 'u***u', 5, '外甥上大学买了第一台小米，现在大三，工科，需要升级了，果断入手第二天！换下来的就归老二了，老二也果断放弃他的联想。颜值和档次没得比，小米的做工精致，全金属机身，很有质感！', 'Redmi G 2.5K 165hz电竞屏', '2022-12-23 09:55:44', 3);
INSERT INTO `data` VALUES (13764, '夏***风', 5, 'RedmiG Pro 2.5K 240hz电竞屏；新锐龙 Redmi G Pro 2.5K240hz电竞屏；新镜龙R7.. 笔记本使用了半个月总结：包装保护：2层纸 箱，内有海绵包裹很安全外形外观：金属质感，低调的配色，个人很喜 欢。运行速度： 运行流畅，4种模式任意切换，2.5k屏，240hz游戏毫无压力 固面品质：2 k屏没的说，非常清晰，看起来很舒适，跑分评测：R76800 和 3060 非常完美流畅 3 A游戏 其他：首发价抢到的，很香，如今的笔记本比当初好 太多了。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-14 13:34:16', 1);
INSERT INTO `data` VALUES (13765, 'u***t', 5, '画面品质：超棒\n外形外观：酷炫\n包装保护：到位\n跑分评测：不错\n运行速度：很快\n游戏效果：超赞', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-12 16:11:51', 4);
INSERT INTO `data` VALUES (13766, 'j***5', 5, '不错，性价比高，win11系统，非常流畅，好用，十分便利，性能也很好，用起来杠杠的，不担心。小米的产品还是值得信赖的！！！', 'Redmi G 2.5K 165hz电竞屏', '2023-03-11 22:46:29', 3);
INSERT INTO `data` VALUES (13767, 'j***z', 5, '外形外观：颜值不错，很有质感\n运行速度：使用流畅\n画面品质：可以流畅观看4k的直播或视频', 'Redmi G 2.5K 165hz电竞屏', '2022-12-24 18:33:31', 3);
INSERT INTO `data` VALUES (13768, 'j***7', 5, '现在还在用不过不错。\n包装保护：十分好\n外形外观：很酷\n画面品质：很好\n跑分评测：没有测试\n运行速度：块就是游戏显卡需要重启才能独显直连\n游戏效果：待测', 'Redmi G 2.5K 165hz电竞屏', '2022-11-02 15:27:01', 1);
INSERT INTO `data` VALUES (13769, 'j***4', 5, '笔记本很好，很漂亮，性能也很强，我非常满意，我很开心能买到性价比这么高的电脑\n游戏效果：游戏效果很好，现在的大部分游戏都能运行 ，帧率很高，屏幕细腻流畅。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-18 13:11:20', 2);
INSERT INTO `data` VALUES (13770, 'j***a', 5, '外形外观：黑色的感觉看着非常酷?\n画面品质：画面整体比较清晰\n跑分评测：玩游戏的时候非常流畅不卡顿\n游戏效果：跑车的时候画面给人感觉比较真实\n包装保护：包装上面没有破损\n运行速度：运行速度比较快，支持日常游戏办公', 'Redmi G 2.5K 165hz电竞屏', '2023-02-20 02:44:44', 2);
INSERT INTO `data` VALUES (13771, '鼻***溜', 5, '买了红米游戏本里面的最高版本，双11购买的很实惠，用了六天了每天开机玩7、8个小时，非常流畅，发热正常不烫，最爽的是屏幕看上去十分清晰，支持小米的产品高性价比。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-16 11:15:01', 3);
INSERT INTO `data` VALUES (13772, '踏***香', 5, '包装保护：完好无损\n外形外观：完美如初\n画面品质：高清清晰\n运行速度：开机固定快\n游戏效果：游戏流程不卡顿', 'Redmi G 2.5K 165hz电竞屏', '2022-09-22 12:46:32', 3);
INSERT INTO `data` VALUES (13773, 'J***g', 5, '笔记本本想对比我原来的Air来说，大了很多，画面也很好，画质清晰，细腻。\n游戏性能非常强大，特效全开，满帧，设置显卡直连，省去系统自动切换的麻烦', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-28 11:40:15', 2);
INSERT INTO `data` VALUES (13774, '请***裕', 5, '外包装有点破，但里面很完好。电脑无损坏。目前安全下车，先用着，希望不会翻车。客服态度不错。\n包装保护：可以\n外形外观：漂亮，质感好\n画面品质：画面品质：巨 高清 很舒服\n运行速度：很流畅\n游戏效果：良好', 'Redmi G 2.5K 165hz电竞屏', '2022-11-02 18:21:51', 1);
INSERT INTO `data` VALUES (13775, 'j***l', 5, '物流非常快，包装无损，电脑质感非常好，运行速度很快，屏幕很好，笔记本很漂亮', '12代I5|RTX3050|2.5K高刷屏', '2022-07-28 18:25:29', 5);
INSERT INTO `data` VALUES (13776, '走***y', 5, '包装保护：包装严密  每一面都有易碎标签\n外形外观：真帅\n画面品质：画质高清 看着真舒服\n游戏效果：游戏效果很好    虽然画质不能开最高    但毕竟是入门机\n运行速度：12代酷睿真是好用', 'Redmi G 2.5K 165hz电竞屏', '2022-12-30 17:09:24', 1);
INSERT INTO `data` VALUES (13777, '我***乐', 5, '包装保护：外包装完好无损，电脑开机正常。\n外形外观：黑色挺酷的外形，金属翻盖，质感很好。\n画面品质：屏幕高清。高分辨率屏幕看着就是清晰。\n运行速度：满足平时办公用了，也不玩大型游戏。', 'Redmi G 2.5K 165hz电竞屏', '2022-12-16 17:56:53', 2);
INSERT INTO `data` VALUES (13778, '歆***猫', 5, '性能释放挺足的，非常不错的游戏本，屏占比很高，外观我喜欢，游戏性能强，屏幕清晰，很有质感，亮度高，无坏点。控制很好，键盘稳定度也高，目前体验很不错了。', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-22 11:27:53', 2);
INSERT INTO `data` VALUES (13779, 'z***o', 5, '东西非常的好，家人很喜欢，质量也很棒，喜欢！速度没的说，品质不错，把钱花在性能上了，屏幕素质不错，颜色也很艳丽，键盘手感尚可。还有的都有了。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-06 07:30:39', 2);
INSERT INTO `data` VALUES (13780, 'j***7', 5, '红米游戏本G2022性价比高，rtx3050日常游戏够用了，2.5k+165hz高刷屏很丝滑，屏幕很清晰，音效也很不错，i5-12450h处理器日常使用也够了，性价比比较高，玩大型游戏建议上3060以上，不经常玩游戏，也没有跑鲁大师。', 'Redmi G 2.5K 165hz电竞屏', '2023-02-28 20:48:12', 2);
INSERT INTO `data` VALUES (13781, 'd***c', 5, '电脑收到了，挺好的，外观无瑕疵，屏幕也很好，玩游戏特别顺畅，没得说。就是型笔记本有一个通病，他风扇声音特别大，玩大表哥二的时候，风扇声音老大了。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-09-18 11:12:47', 2);
INSERT INTO `data` VALUES (13782, 'j***z', 5, '一款性能非常强大的笔记本，3060的显卡打任何游戏都非常流畅，平时就算办公的话也是绰绰有余，外观方面的做工还是非常不错的，细节做的挺不错的。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-27 10:26:44', 3);
INSERT INTO `data` VALUES (13783, 'r***e', 5, '很好用，性能高配，打开软件网页都很快，游戏运行流畅，满意，风燥声还好，开大型游戏会大一些，屏幕画面挺不错的。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-20 23:01:00', 2);
INSERT INTO `data` VALUES (13784, '亮***g', 5, '包装保护：包装很好，保护的很好。\n外形外观：外观很漂亮，收到货后没有一点瑕疵，很喜欢。\n画面品质：2 K的屏幕看着就是舒服，高刷新率，浏览网页很流畅，看视频也很舒服。\n跑分评测：轻松一跑，120w+，还是可以的', '12代I5|RTX3050|2.5K高刷屏', '2022-07-29 12:36:26', 2);
INSERT INTO `data` VALUES (13785, 'j***g', 5, '这款笔记本非常强大，3060的显卡打游戏是非常流畅的，很厉害的性能，笔记本的屏幕也是非常清楚的，做工这方面非常细节，这个笔记本非常值得购买。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-22 19:03:10', 3);
INSERT INTO `data` VALUES (13786, 'j***彁', 5, '电脑很好\n包装保护:包装有点儿简单，快递员还以为我买的二手的\n外形外观:漂亮，超级漂亮!!!!\n画面品质:画质超级好，顶级屏幕\n跑分评测:没有跑，主要检查了没问题，\n运行速度:超级快!\n总的来说电脑不错', 'Redmi G 2.5K 165hz电竞屏', '2023-01-08 12:55:58', 1);
INSERT INTO `data` VALUES (13787, 'p***g', 5, '非常不错的游戏本，屏占比很高，外观我喜欢，游戏性能强，屏幕清晰，很有质感，亮度高，无坏点。控制很好，键盘稳定度也高，目前体验很不错了。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-16 13:51:55', 1);
INSERT INTO `data` VALUES (13788, '会***坤', 5, '手感很好，打开电脑下载游戏，特效终于可以开到最高，画质清晰，感觉玩游戏手感都变好了，配置高，价格也不贵！不错', 'Redmi G 2.5K 165hz电竞屏', '2022-09-14 13:57:42', 3);
INSERT INTO `data` VALUES (13789, '幸***6', 5, '很快就收到货了，京东物流非常的快非常的方便，这款电脑我是非常的满意，它处理器性能很好，使用起来很舒畅，一点都不卡顿，非常好用，我太喜欢了。。', 'Redmi G 2.5K 165hz电竞屏', '2023-01-09 20:29:08', 3);
INSERT INTO `data` VALUES (13790, '长***日', 5, '客服专业，有问必答，对配置内容解释的都很好！\n包装保护：非常好，安全，也环保\n外形外观：很酷\n画面品质：还刷屏幕看着很舒服，也不刺眼。\n跑分评测：打游戏一般都够用了', 'Redmi G 2.5K 165hz电竞屏', '2023-03-07 21:53:37', 1);
INSERT INTO `data` VALUES (13791, '醉***3', 5, '外形外观：外形简单大方，工艺优秀\n画面品质：暂时没玩游戏，3A大作运行应该没压力\n运行速度：速度很快\n游戏效果：2.5k屏幕就是看着舒服', 'Redmi G 2.5K 165hz电竞屏', '2023-02-04 12:37:25', 1);
INSERT INTO `data` VALUES (13792, '电***祖', 5, '非常好面是金属的很流畅，各方面都不错，游戏打起来都很流畅。屏幕很好，观感很好总结各方面都不错3050也没那么弱\n外形外观：很好\n包装保护：很好\n画面品质：很好\n跑分评测：很好\n运行速度：很快', '12代I5|RTX3050|2.5K高刷屏', '2022-07-28 15:15:23', 2);
INSERT INTO `data` VALUES (13793, '朝***锅', 5, '包装保护：包装的很好，拿到手里第一感觉很有分量\n外形外观：这代外观没得说，好看就完事了\n跑分评测：跑分各个平台都有，玩LOL，原反正是戳戳有余。\n游戏效果：屏幕确实不错，高刷非常流畅清晰', 'Redmi G 2.5K 165hz电竞屏', '2022-12-12 09:27:30', 2);
INSERT INTO `data` VALUES (13794, 'E***e', 5, '游戏本不错，屏幕素质很好，散热还行，第一次买小米的笔记本，体验很不错。电脑运行速度很快，加装固态或者内存也很方便，价格能再低点就更好了。', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-09-03 23:28:51', 3);
INSERT INTO `data` VALUES (13795, '刹***8', 5, '包装保护：包装完好\n外形外观：没有问题\n画面品质：超高\n运行速度：非常nice\n游戏效果：完美', 'Redmi G 2.5K 165hz电竞屏', '2022-12-30 11:14:33', 2);
INSERT INTO `data` VALUES (13796, '等***那', 5, '到货两天了，用起来没什么问题，，非常流畅12代i5-12450h够用，屏幕2.5k观感非常好??，好评', 'Redmi G 2.5K 165hz电竞屏', '2023-01-03 11:18:37', 3);
INSERT INTO `data` VALUES (13797, 'j***k', 5, '前天入手的，性能好，速度也快，屏幕分辨率很清楚，音质高，打游戏没有压力，咨询客服售后问题，客服服务态度很好，温馨解答各种问题?', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-27 22:44:47', 2);
INSERT INTO `data` VALUES (13798, 'N***_', 5, '包装保护：保护得非常到位 盒子没有破损处\n外形外观：很有时尚感 觉得可以媲美y9000p了\n画面品质：240Hz也不是虚标 用起来画面非常流畅\n游戏效果：嘎嘎猛 开高画质基本没问题', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-27 15:42:20', 1);
INSERT INTO `data` VALUES (13799, '蝈***3', 5, '到货速度非常快，笔记本外观大气，很厚重。机器开机快，运行速度也很快，性价比很高，值得推荐！', 'Redmi G Pro 2.5K 240hz电竞屏', '2023-01-11 15:33:49', 6);
INSERT INTO `data` VALUES (13800, 'j***x', 5, '电脑非常好，性能很高，声音也不大，这款可以说是是游戏本里最轻的了。非常好的购物体验', '12代I5|RTX3050|2.5K高刷屏', '2022-08-06 15:59:20', 4);
INSERT INTO `data` VALUES (13801, 'u***7', 5, '电脑外观很漂亮，用起来也很流畅，运行速度很快，屏幕很清晰，要是风扇能开个调速就好了，散热确实很顶，代价就是声音大，能调速会好一点，客服很专业，小米真滴香，希望小米越来越好', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-21 20:53:46', 2);
INSERT INTO `data` VALUES (13802, 'D***9', 5, '配送很快，凌晨买的，下午送到。目前来说非常好，性价比还挺高的。绝地求生超高画质微微微微有一点卡顿，中高画质还是很流畅的。LOL，CF也挺不错，这个电脑的音响感觉很好，放歌可以说跟手机差不多，比手机差一点吧，总的来说还比较满意，用一段时间再追评！', 'Redmi G 2.5K 165hz电竞屏', '2022-09-09 21:47:28', 2);
INSERT INTO `data` VALUES (13803, 'A***s', 5, '外形外观：完全的小米风格，比起2021款有很大的进步。\n\n游戏效果：散热很不错，风扇噪音比一般的风冷散热器声音小', 'Redmi G 2.5K 165hz电竞屏', '2023-03-10 08:25:13', 3);
INSERT INTO `data` VALUES (13804, 'j***c', 5, '期待的电脑终于到手了，屏幕清晰，手感非常好，喜欢的可以入手了，玩游戏这些，非常快，很好', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-09-01 19:04:35', 4);
INSERT INTO `data` VALUES (13805, 'j***6', 5, '颜值与性能并存！屏幕超清晰，超高刷新率超级流畅的体验！ 用上了就回不去了。 性价比还是要看小米。', '12代I7|RTX3050|2.5K高刷屏', '2022-07-28 22:42:25', 4);
INSERT INTO `data` VALUES (13806, 'j***8', 5, '电脑没什么问题，就是包装跟物流有点失望。\n趁着优惠，赶紧入手，是正品，包装也非常的好，没有破损，质量也是没得说，棒?这个真的太?了，?包装很精美，宝贝做工比较精细，商家特别好?，有问题都及时处理?，确实是一次相当满意的网购，还会再来的?这个真的太?了，?包装很精美，宝贝做工比较精细，商家特别好?，有问题都及时处理?，确实是一次相当满意的网购，还会再来的?', 'Redmi G 2.5K 165hz电竞屏', '2022-11-21 17:25:38', 4);
INSERT INTO `data` VALUES (13807, '苕***华', 3, '配送速度没得说，我昨晚9点下的单，今天早上9点就到了，具体等用过再评价。', 'Redmi G Pro 2.5K 240hz电竞屏', '2023-03-15 12:06:59', 5);
INSERT INTO `data` VALUES (13808, 'j***K', 5, '用着感觉很好，网上看了半天的测评才买的，5999的游戏本，对于我这个不扎打游戏的人来说完全够用，性价比很高，使用感觉比较好，整机做工精细，用了几天没啥毛病，这个新的控制中心不错，很好看，第二个硬盘位也很好，自己加了一个t，不然不够用。', 'Redmi G 2.5K 165hz电竞屏', '2022-10-03 09:39:25', 2);
INSERT INTO `data` VALUES (13809, 'u***9', 5, '客服很好！物流很好！笔记本验过了没啥问题，刚到手，感觉很不错，应该可行！\n包装保护：还行，很大\n外形外观：很好\n画面品质：很nice！', 'Redmi G 2.5K 165hz电竞屏', '2022-11-03 16:44:15', 1);
INSERT INTO `data` VALUES (13810, '薇***n', 5, '刚拿到就被颜值惊艳了，太好看了，而且手感也很好，目前使用很舒服，触摸板很灵敏，屏幕也好高清，总之很喜欢?', 'Redmi G 2.5K 165hz电竞屏', '2022-12-16 16:10:56', 3);
INSERT INTO `data` VALUES (13811, 'j***6', 5, '包装保护：包装盒很大，里面很多气袋，电脑盒被保护很好\n外形外观：很精致，触感很丝滑\n画面品质：很清晰，2.5k屏幕不是吹的', 'Redmi G 2.5K 165hz电竞屏', '2022-09-11 13:31:26', 2);
INSERT INTO `data` VALUES (13812, 'j***y', 5, '这太电脑真的非常好，客服态度也非常的好，非常耐心的回答问题，解决各种问题，真的非常值得购买，外观大气非常的好看', 'Redmi G 2.5K 165hz电竞屏', '2023-02-25 19:49:41', 4);
INSERT INTO `data` VALUES (13813, 'j***x', 5, '包装保护：泡沫挺多 包装做得不错\n外形外观：金属质感很好\n画面品质：165hz看的很舒服', 'Redmi G 2.5K 165hz电竞屏', '2022-11-03 07:02:06', 3);
INSERT INTO `data` VALUES (13814, '尚***2', 5, '电脑刚激活 跑分一百多万 我虽然不打游戏但是还是买了游戏本 个人感觉性价比很高 客服很专业 有问必答 期待进一步的使用', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-28 18:00:12', 3);
INSERT INTO `data` VALUES (13815, '铁***河', 5, '目前来讲，比我想的还要好，从1050换到3070ti，游戏流畅度拉满，测试一下2077帧数60以上，至于单硬盘位的问题，建议大家买固态和硬盘盒自己组一个移动固态，速度也很快！win11体验也很好。', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-02 16:48:52', 2);
INSERT INTO `data` VALUES (13816, 'j***i', 5, '开机很快，手感很好。用起来屏幕够大，很喜欢！小米的电脑还是不错', 'Redmi G 2.5K 165hz电竞屏', '2023-01-19 15:44:09', 3);
INSERT INTO `data` VALUES (13817, 'j***u', 5, '包装保护：包装保护：良好 \n画面品质：画面细腻\n运行速度：运行速度极快\n游戏效果：完美运行\n外形外观：完美无暇瑕疵', 'Redmi G 2.5K 165hz电竞屏', '2022-09-20 11:49:45', 1);
INSERT INTO `data` VALUES (13818, '心***鸭', 5, '物流超级超级快！质量也非常不错，的确物有所值\n真心喜欢，颜色、款式都非常棒！质量很好，收到货第一时间打开看了，很不错，很满意', 'Redmi G 2.5K 165hz电竞屏', '2022-11-12 10:22:02', 2);
INSERT INTO `data` VALUES (13819, 'j***v', 5, '包装保护：包装保存的很好\n运行速度：相应速度很快\n外形外观：A面的金属质感很好', 'Redmi G 2.5K 165hz电竞屏', '2022-11-04 14:59:01', 4);
INSERT INTO `data` VALUES (13820, '才***兄', 5, '用起来很爽，运行速度很快，打开3D可以，游戏可以，整体外观可以，重量轻点更好', 'Redmi G 2.5K 165hz电竞屏', '2023-02-11 11:34:10', 2);
INSERT INTO `data` VALUES (13821, '乐***y', 5, '外观漂亮，质感很好，屏幕清晰度高，目前运行速度挺快的，喜欢这个大屏幕，不过游戏本确实重', 'Redmi G 2.5K 165hz电竞屏', '2022-11-16 20:02:19', 2);
INSERT INTO `data` VALUES (13822, '1***何', 5, '物流是真的快包装精致外形炫酷2.5k观感很强，键盘手感都很不错', 'Redmi G 2.5K 165hz电竞屏', '2023-03-12 08:19:51', 6);
INSERT INTO `data` VALUES (13823, 'H***7', 5, '包装保护：包装完好无损\n外形外观：相对于redmi g2021来说外观更好看了\n画面品质：超高刷新率，独显直连\n\n运行速度：快\n游戏效果：2.5k画质', 'Redmi G 2.5K 165hz电竞屏', '2022-09-18 15:44:15', 2);
INSERT INTO `data` VALUES (13824, 'h***q', 5, '给外甥上大学买的，小米的游戏本性价比比较高，做工材质算是第一梯队的了，对得起小米的品质了，娱乐大师的跑分也有110多万了，玩现在的主流游戏都没多大的问题。', 'Redmi G 2.5K 165hz电竞屏', '2023-03-16 15:38:59', 4);
INSERT INTO `data` VALUES (13825, '小***a', 5, '挺好的，包装的很好很安全。外观也特别漂亮，看起来很有质感，分辨率蛮高的，画质很好，打游戏体验感好。给大学生买的，计算机专业也能满足需求，客服专业，服务态度好，售后也不错。家里很多小米的产品，都还可以。', 'Redmi G 2.5K 165hz电竞屏', '2023-02-17 09:43:15', 3);
INSERT INTO `data` VALUES (13826, 'j***6', 5, '包装保护：很完整\n外形外观：比上一代好很多\n画面品质：屏幕很通透\n运行速度：暂时还可以\n游戏效果：很不错', '12代I5|RTX3050|2.5K高刷屏', '2022-07-29 11:10:17', 1);
INSERT INTO `data` VALUES (13827, 'Q***W', 5, '金属外观很好，键盘打字也很舒服，玩游戏屏幕看着比1080 P的好太多了。显卡要是有高的就更好了，小米这款还是比较满意的', '12代I7|RTX3050|2.5K高刷屏', '2022-08-04 23:53:51', 2);
INSERT INTO `data` VALUES (13828, 'j***g', 5, '真的超级喜欢，非常支持，质量非常好与卖家一致，用了几天传热快。性能稳定。非常满意，真的很喜欢，完全超出期望，发货快，包装仔细，严实。客服服务也很好。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-28 14:33:06', 2);
INSERT INTO `data` VALUES (13829, 'w***q', 5, '包装保护：非常完美，不知道的还以为是台式机\n外形外观：外形酷炫，很有机械感\n画面品质：显示相当清晰，万元以内没一个能打的\n跑分评测：独显直连模式下，轻轻松松170万分+', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-09-16 21:27:32', 2);
INSERT INTO `data` VALUES (13830, 'j***x', 5, '物流很快，包装完好，电脑很漂亮，玩原神很流畅，客服专业，服务态度好，满意的一次购物，好评！', 'Redmi G 2.5K 165hz电竞屏', '2022-11-25 12:32:50', 3);
INSERT INTO `data` VALUES (13831, 'j***3', 5, '包装保护：保护得很好。\n画面品质：完美\n跑分评测：跑分挺高的。', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-08-27 16:37:30', 4);
INSERT INTO `data` VALUES (13832, 'j***B', 5, '包装保护：包装很严实\n外形外观：很霸气，很适合学生\n画面品质：画质非常清晰\n游戏效果：非常流畅，几乎大型游戏都没什么问题', 'Redmi G 2.5K 165hz电竞屏', '2022-11-11 13:56:00', 1);
INSERT INTO `data` VALUES (13833, 'w***I', 5, '昨天下单，今天就收到了，物流很快，质量很好\n服务也很不错\n包装保护：外包装两层\n\n画面品质：清晰，画面感不错\n游戏效果：还在测试中', '12代I5|RTX3050|2.5K高刷屏', '2022-08-09 15:09:01', 3);
INSERT INTO `data` VALUES (13834, '人***v', 5, 'redmi g 笔记本上手感非常好，外壳是铝合金的，很有质感，系统非常快，一个字 好。', 'Redmi G 2.5K 165hz电竞屏', '2022-12-16 19:28:14', 3);
INSERT INTO `data` VALUES (13835, 'p***l', 5, '非常具有性价比的一款产品，包装很好，速度很快，做工也还可以在，外观，颜值，在线功能也非常的全面性价比，屠夫下次还会再选小米，但是只有一个可供添加的m。2曹还是有点低配', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-17 00:51:02', 2);
INSERT INTO `data` VALUES (13836, '购***6', 5, '用起来真的很棒，很喜欢，除了硬盘小点，真的很完美！', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-03 20:22:13', 5);
INSERT INTO `data` VALUES (13837, 'j***d', 5, '电脑非常不错，外观很好看，logo也很帅，系统很流畅，运行了一些设计软件都表现得不错，屏幕也很不错2.5k，值得购买！目前没有发现问题。', 'Redmi G 2.5K 165hz电竞屏', '2022-09-11 13:15:00', 2);
INSERT INTO `data` VALUES (13838, 'j***f', 5, '帅到炸裂，LOL 吃鸡 战舰世界 原神高质无压力，颜值高功能强价格低，简直性价比之王啊', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-09-02 14:03:29', 3);
INSERT INTO `data` VALUES (13839, '-***鹰', 5, '用了大概一个多月，物美价廉，屏幕很棒，确实外观比前两年的有很大进步，永劫无间守望先锋LOL完全没有压力。客户服务态度方面也很好。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-22 13:46:59', 3);
INSERT INTO `data` VALUES (13840, '千***凌', 5, '12代酷睿，rtx3050日常随便够用了，我只玩英雄联盟。\n屏幕很不错，现在用着没啥问题。', 'Redmi G 2.5K 165hz电竞屏', '2022-12-22 11:23:12', 3);
INSERT INTO `data` VALUES (13841, '冰***9', 5, '挺好的，比官网还便宜，京东送货非常快啊，昨晚12点下单，第二天下午就收到了，机器也挺好，屏幕非常清晰，亮度高，看着很舒服，配置也高，整体流畅', 'Redmi G 2.5K 165hz电竞屏', '2022-09-11 21:46:02', 2);
INSERT INTO `data` VALUES (13842, '璃***情', 5, '包装保护：包装很完整，没有说的那么多问题\n外形外观：外形外观很酷\n画面品质：画面高刷新率 看着很舒服\n跑分评测：很高', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-12-18 13:36:12', 1);
INSERT INTO `data` VALUES (13843, '彩***糖', 5, '物流很快，包装完整，电脑已经使用一段时间了，大小合适，画面品质高，电脑性能很好，客服很专业，总体很满意，已经推荐给同学了', 'Redmi G 2.5K 165hz电竞屏', '2022-11-22 15:34:54', 2);
INSERT INTO `data` VALUES (13844, '我***由', 5, '一来到就上手了，感觉很好。lol不卡顿。够用了。', '小米 Redmi G 游戏本 2.5K高刷屏', '2022-09-02 15:18:31', 2);
INSERT INTO `data` VALUES (13845, '青***y', 5, '性价比不错，屏幕非常好，3050不玩3a玩些网游也完完全全足够了，外观也比较简约看着很舒服没那些花里胡哨的东西，比较均衡的一个机器，游戏和日常学习工作兼具了', 'Redmi G 2.5K 165hz电竞屏', '2022-12-09 23:05:30', 2);
INSERT INTO `data` VALUES (13846, 'j***7', 5, '电脑外观很漂亮，接口丰富，非常方便实用，屏幕显示效果清晰，运行速度快，只偶尔玩lol完全无压力，价格便宜性价比非常高，完美', 'Redmi G 2.5K 165hz电竞屏', '2022-09-11 06:16:03', 1);
INSERT INTO `data` VALUES (13847, 'z***8', 5, '一直以来都喜欢京东自营买东西，尤其是笔记本，之前买的笔记本电脑就是小米的，已经六年了，还是很好用，这款颜值很高，运行起来也很流畅', 'Redmi G Pro 2.5K 240hz电竞屏', '2023-01-24 22:39:04', 2);
INSERT INTO `data` VALUES (13848, 'u***3', 5, '包装保护：非常好 有两个\n外形外观：不错的\n画面品质：还可以\n跑分评测：非常高', 'Redmi G Pro 2.5K 240hz电竞屏', '2022-11-17 09:40:10', 1);
INSERT INTO `data` VALUES (13849, 'j***d', 5, '很完美，很赞的电脑，开箱激活系统也很快，试着下载了英雄联盟打了几局，完全没有卡顿的感觉，界面也很舒服，性价比很高的一款机型！', 'Redmi G 2.5K 165hz电竞屏', '2022-10-17 11:21:58', 3);
INSERT INTO `data` VALUES (13850, '先***超', 5, '笔记本电脑画面显示清晰，玩游戏不卡不热，电脑手感很好！推荐大家购买！笔记本电脑画面显示清晰，玩游戏不卡不热，电脑手感很好！推荐大家购买！', 'Redmi G 2.5K 165hz电竞屏', '2023-01-13 19:32:14', 3);
INSERT INTO `data` VALUES (13851, 'u***6', 5, '这是我购买的一件非常不错的商品 很难得的 物美价廉 具有性价比 是适合大众的价格 并且我本人自己也非常喜欢这个 客服态度也不错 并且服务性很强 什么都给我解答 物流快递也很快 总而言之 很满意的一次购物 期待下一次合作', 'Redmi G 2.5K 165hz电竞屏', '2022-11-27 12:41:35', 2);
INSERT INTO `data` VALUES (13852, 'j***8', 5, '第一次买笔记本，物流非常快  十一月一日付尾款 ，十一月三日就到了。京东yyds   拆箱第一感觉就惊艳到我了，屏幕素质非常高。包装保护也很好  好评！跑分也是达到了一百一十多万  开机只需要七秒   十月份的机器  很不错', 'Redmi G 2.5K 165hz电竞屏', '2022-11-03 14:00:34', 2);
INSERT INTO `data` VALUES (13853, 'u***h', 5, '包装保护：京东的包装非常到位\n外形外观：很好看\n画面品质：2k很好\n运行速度：快\n游戏效果：好', '12代I5|RTX3050|2.5K高刷屏', '2022-07-30 09:47:16', 1);
INSERT INTO `data` VALUES (13854, 'j***8', 5, '包装保护：保护得很好\n外形外观：不错\n画面品质：很好的', 'Redmi G 2.5K 165hz电竞屏', '2022-10-20 11:39:51', 4);
INSERT INTO `data` VALUES (13855, 'j***a', 5, '包装保护：非常赞无损坏\n外形外观：舒适\n画面品质：2k165丝滑顺畅\n\n\n运行速度：16gdd5非常快了，做什么够都用喜欢的这个屏幕质感非常好以后上班娱乐都会用这个电脑的。', 'Redmi G 2.5K 165hz电竞屏', '2022-11-03 14:08:05', 3);
INSERT INTO `data` VALUES (13856, '擅***蒋', 5, '运行速度：刚买回来，速度很快。价格很可以，不错的电脑。\n屏幕效果：高清上海很靓丽。\n散热性能：下载了60多gb的软件。目前没感觉到发热的迹象。\n外形外观：很ok，买给同事用的。很喜欢\n轻薄程度：比较轻便，轻薄，续航还可以。\n运行速度：打开软件的速度还很ok。\n其他特色：回来就安装了很多软件，没发现有什么问题。', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-22 14:21:24', 8);
INSERT INTO `data` VALUES (13857, 'j***8', 5, '特别特别棒，货比三家才买的，店主人很好，回答问题很有耐心，也很详细，有需要还会再来的?收到立马打开看了一下，非常不错，质量超好，颜值又高?，推荐推荐?大品牌！值得信赖的！效果超级好！贵有贵的道理！很棒的商品！', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-14 09:27:54', 8);
INSERT INTO `data` VALUES (13858, 'j***7', 5, '东西拿到手还是不错的。灰银色比较有金属质感。拿电脑的时候是全程录像，然后也是全程开机验机，完全没问题。电脑包和鼠标是同时送到的，也很不错。而且电脑的尺寸比我预想的要更大，画质可以，通过电脑管家还可以自己调节画面，拿着看了一部电影，很OK。我这个是独显，所以先下的软件就是一些网游，连打了几天，只要网络给力，完全没问题，很爽。键盘的触感也不错。电脑两侧的连接口也很多，我打算自己配一个typeC充电器。总之，目前为止，真的很满意。', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-17 19:15:02', 9);
INSERT INTO `data` VALUES (13859, '罱***穆', 5, '外形外观：十分高级灰，而且还有些冷手，因为没有鼠标，用的触摸板\n轻薄程度：轻薄，很爱！\n屏幕效果：真的震惊，看MV的感觉就是眼前一亮！\n运行速度：是很快的。有一些快捷的触摸板手势真的很棒。而且续航很强从15点到20点，电量从100用到59\n充电也快。150W充电器\n\n其他特色：①预装2021版的office激活即用②指纹识别很方便③摄像头的遮挡板，保护隐私④部分键盘上有指示灯如，大写字母时亮灯、开启摄像头时亮灯&hellip;⑤一些快捷键很棒：开启键盘灯光，有三个档位、静音或者调高/低音量⑥还有分屏多窗的功能&hellip;具体的可以在电脑里找到&ldquo;提示&rdquo;里有很多玩机技巧⑦180&deg;的开合屏幕，爱了\n\n更喜欢的是，它可以和我的手机连接，可以在电脑上查看到我的手机短信，或者拨打电话。但是这个功能对手机有型号局限性。（印象中是荣耀Magic UI6.0以上的系统支持，另一个手机型号忘了）\n\n配件：使用手册、保修卡、充电器、充电线、趣味贴纸\n\n已经使用过几天了。物流真的快，一天就到。真的爱，我的第一台电脑缘分很奇妙，因为双十一都抢的很厉害，买到这个完美的电脑真的不错。目前用于编辑这方面，很nice。后续服装设计的话，再回评论一个吧。', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-16 19:43:26', 7);
INSERT INTO `data` VALUES (13860, '我***洋', 5, '运行速度：很快\n屏幕效果：屏幕很大，很适合看电影\n散热性能：玩游戏散热快，不影响使用\n外形外观：银色太好看了\n轻薄程度：很轻薄\n运行速度：很快\n散热能力：散热很快，特别是玩内存大的游戏的时候\n其他特色：物流很快', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-16 20:34:29', 4);
INSERT INTO `data` VALUES (13861, '随***行', 5, '运行速度：满意满意\n屏幕效果：满意满意！很清楚，给小朋友买的，很清晰，120hz,没有失望！\n外形外观：买的时候没注意，看到实物很漂亮，时尚！儿子应该也喜欢\n轻薄程度：满意！', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-06 14:25:38', 3);
INSERT INTO `data` VALUES (13862, 'y***4', 5, '运行速度：很快\n屏幕效果：很惊艳，比我15年买的笔记本屏幕好很多\n散热性能：正常使用的时候，听不到声音，还没有试试玩游戏的时候，怎么样。\n外形外观：很喜欢\n轻薄程度：比想象的还轻薄', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-05 14:37:35', 6);
INSERT INTO `data` VALUES (13863, 'j***d', 5, '华硕无畏Pro15 2022款2.8K 120Hz OLED屏，标压处理器性能强，之前朋友买过R7 5800处理器的性能很好，跑了一下分，R7 6800强很多，搭配RTX3050显卡我作图够了，值得推荐???', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-30 23:40:13', 4);
INSERT INTO `data` VALUES (13864, '坤***丨', 5, '运行速度：挺快的\n屏幕效果：120hz真好看\n散热性能：不错\n外形外观：挺好看的\n轻薄程度：挺薄的\n\n这款笔记本电脑的屏幕是一大特色120hz，太漂亮了，处理器也挺快的', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-11 19:13:17', 2);
INSERT INTO `data` VALUES (13865, 'j***f', 5, '运行速度：非常快\n屏幕效果：特别清晰\n散热性能：挺好的基本不热\n外形外观：挺好看的16比9大屏幕\n轻薄程度：很轻很薄\n其他特色：屏幕真的绝绝子\n散热能力：挺好的\n运行速度：很快', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-20 08:44:09', 2);
INSERT INTO `data` VALUES (13866, '烧***猫', 5, '非常满意，非常漂亮，边框非常窄，铝合金，轻薄，好评，下次买还的是这次这个', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-20 09:26:52', 6);
INSERT INTO `data` VALUES (13867, 'j***0', 5, '东西收到了，发货速度很快\n运行速度：运行速度用来办公还可以\n屏幕效果：屏幕色彩比较鲜艳\n散热性能：还可以吧，还没有具体运行很久\n外形外观：挺轻薄', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-10 11:09:01', 7);
INSERT INTO `data` VALUES (13868, 'l***6', 5, '华硕的笔记本电脑可以\n散热性能：散热效果不错整机性能释放还行\n外形外观：外观好看颜色漂亮，侄女就是看其他的漂亮了\n运行速度：运行速度很好，软件各方面都不错，用的好话再来评价。\n屏幕效果：屏幕:这款OLED屏幕各方面都不错，显示色效果真不错，有需要的可以考虑一下', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-22 12:33:45', 7);
INSERT INTO `data` VALUES (13869, '万***8', 5, '当时纠结了很久要不要买这款，后来看到屏幕真的很清晰，开始还担心会不会翻车，华硕的电脑真的没让我失望过，这款电脑屏幕非常清晰，看电影真的视觉很棒，运行非常的快，而且声音很小，真的爱不释手，强烈推荐想入手的宝子们', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-27 16:37:29', 4);
INSERT INTO `data` VALUES (13870, '世***y', 5, '对比了很多款笔记本，这一款是各方面最均衡的一款，性能强悍，性价比高。平时不玩游戏，用的最多的是CAD，运行起来毫无压力，绰绰有余。键盘还有背光灯，很喜欢。开机5秒钟！', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-18 22:30:18', 3);
INSERT INTO `data` VALUES (13871, 'j***u', 5, '电脑很好呀，性价比高，快递隔日达很赞，最最最重要的15.6的屏幕超级大，室友都羡慕哭了，处理器也赞，客服的态度也很好，一次很好的购物体验。', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-21 15:18:21', 5);
INSERT INTO `data` VALUES (13872, '墨***之', 5, '帮老妹买的，她上课敲代码会用到，然后平时打打游戏什么的，说是这个机子很流畅，不卡顿的???另外物流速度嘎嘎快呀，上午下单，下午就收到了?\n运行速度：很快\n屏幕效果：很清晰，色彩很棒\n散热性能：不错的\n外形外观：巨好看\n轻薄程度：薄', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-01 19:23:00', 2);
INSERT INTO `data` VALUES (13873, 'u***y', 5, '第二次买asus的笔记本了，香的很，屏幕清晰舒服，按键手感好，锐龙5800H，速度挺快的。\n外形外观：好看\n屏幕效果：显示清晰，看起来很舒服。\n运行速度：快，准，狠', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-12 12:50:16', 5);
INSERT INTO `data` VALUES (13874, '冰***吖', 5, '华硕笔记本收到了，很满意，笔记本的屏幕很清楚，办公看剧都很方便，有需要的小伙伴可以放心购买，推荐的一款，携带也很方便，后期有需要，还会持续购买的，满分好评！', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-14 10:44:00', 5);
INSERT INTO `data` VALUES (13875, 'j***a', 3, '如果学生购买的话建议问一下送不送office', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-13 18:14:40', 4);
INSERT INTO `data` VALUES (13876, '尼***q', 5, '家用办公，绝对够了，主要是性价比超好，特意买的标压，打开办公软件，网页，不会卡顿，华硕品质，坚若磐石', '无畏15 2022 高性能轻薄本', '2022-06-18 18:26:14', 9);
INSERT INTO `data` VALUES (13877, 'j***3', 5, '丰富的接口，好评。\n键盘质感很好，有小数字键盘，好评。\n屏幕窄边框，好评。\n摄像头物理挡板，好评。\n屏幕显示效果，极致好评。\n不是type-c接口，差评。', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-27 09:16:51', 5);
INSERT INTO `data` VALUES (13878, 'j***2', 5, '运行速度：很快\n屏幕效果：鲜艳明亮\n散热性能：好\n外形外观：没想到蓝色的也很好看，不比银色的差\n轻薄程度：很轻便，15寸的电脑才1.65kg', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-12 22:52:31', 1);
INSERT INTO `data` VALUES (13879, 'j***f', 5, '用电脑上了几天网课，一点都不卡，很灵敏，散热效果也很好，没有出现发热，发烫的情况，键盘也很好，灯光暗的话可以开启键盘背光，散热也没有声音，个人感觉，这个电脑很好，值得入手', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-11 09:27:23', 5);
INSERT INTO `data` VALUES (13880, 'j***B', 5, '外形外观：不错，屏幕很大\n运行速度：挺快的\n散热性能：散热性能：声音很小，不吵 \n运行速度：开机速度很快', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-03 19:09:10', 5);
INSERT INTO `data` VALUES (13881, '_***i', 5, '宝贝不错，运行流畅，无卡顿，毕竟和高端笔记本一样的处理器，这价位，这配置知足了，便携，美观，于一身的，对比了很多家！客服很好！不错，满意！电脑出现什么问题，客服都认真解答。屏幕素质是真的\n高，喜欢。选了很久，最终选择了这个，因为配置算是很高的，而且够轻薄。实测原神可以满特效流畅运行，有60fps(游戏设置最高）视频如下（最高特效），反正我是觉得不卡。也不是怎么太烫。不过这个电脑新机优化有点麻烦哦，搞了一天吹，屏幕显示效果还不错，就是不知道会不会烧屏了。毕竟是。LED屏。总之用用先看吧，反正比我以前买的任何电脑都强。如果想打游戏的话还是可以的，原神不算太大，在网上的三a都可以。主流办公，偶尔玩游戏的赶快入手吧！华硕容服服务不错。', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-12 12:25:32', 4);
INSERT INTO `data` VALUES (13882, '李***帥', 5, '真机到手，很薄很轻，屏幕确实有把刷子，效果一级棒，这个价位买到旗舰本才有的高清高刷OLED屏，还要什么自行车，运行过程中风扇声也不大，可能我就是简单办公加追剧看电影吧，足够用了，买高配对我来说也没啥意义，一般的网游也能玩哈哈，相当满意，希望后续不要出问题哦！！！！', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-06 19:51:42', 6);
INSERT INTO `data` VALUES (13883, '肖***5', 5, '散热性能：?以\n运行速度：?以\n屏幕效果：屏幕很清晰很棒。\n外形外观：好看\n轻薄程度：合适\n其他特色：做工不错，质量很好。', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-03 13:08:36', 7);
INSERT INTO `data` VALUES (13884, 'F***n', 5, '优秀，觉得日常不游戏够用，配置相当不错！\n我主要做CAD足够用，赞一个', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-11 18:20:17', 9);
INSERT INTO `data` VALUES (13885, '松***家', 5, '京东自营产品，发货速度快次日达。华硕品质，价格合理。主要看上颜值，漂亮大气有颜值，屏幕精细画质清晰。配置棒棒哒完全不卡顿，电池耐用3-4个小时没问题。', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-10 12:48:13', 2);
INSERT INTO `data` VALUES (13886, 'b***x', 5, '轻薄的设计，深色简约的外型，15.6&ldquo;拿着不大，看着不小的2.8K屏幕，画面鲜艳，速度很快，梦幻般的漂亮。非常满意，超值。第二天上午到货，非常快。', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-04 15:38:17', 5);
INSERT INTO `data` VALUES (13887, '新***月', 5, '运行速度：非常快，不愧是崛起后的AMD，搭配双通道16g内存，性能非常强大。\n屏幕效果：超级惊艳，OLED屏这色彩，简直让人欲罢不能。\n\n散热性能：散热还行，毕竟没有游戏独显。\n\n外形外观：一如既往的非常漂亮。\n轻薄程度：还行，比不上最轻薄的，但是也很不错。\n\n这个型号买第二台了，非常棒，之前还买了6台14Pro，现在单位中高层用的笔记本基本都是这个系列，使用体验也非常好。', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-09 15:53:40', 4);
INSERT INTO `data` VALUES (13888, 'j***e', 5, '运行速度：运行很快，\n屏幕效果：色彩度也很好\n散热性能：散热快\n外形外观：外观漂亮是娃喜欢的\n对此次购买很满意，娃也很喜欢', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-19 16:18:51', 5);
INSERT INTO `data` VALUES (13889, '小***q', 5, '非常漂亮，大气，手感也很好，买来主要办公，剪辑视频用，运行速度很快，画面也很清晰。', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-02 17:35:43', 8);
INSERT INTO `data` VALUES (13890, 'i***3', 5, '运行速度：运行很流畅\n屏幕效果：屏幕效果没得说，奔着这个平屏买的\n散热能力：双风扇散热很强，打游戏比单风扇低二十多度\n轻薄程度：有显卡还这么薄，相当不错', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-14 13:14:38', 4);
INSERT INTO `data` VALUES (13891, 'O***见', 5, '独显效果很好！\n运行速度：R7速度很快\n屏幕效果：oled的显示器效果没有的说！\n散热性能：效果很好的！\n外形外观：银色很漂亮\n轻薄程度：跟合适，家里人很喜欢！', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-30 18:33:24', 4);
INSERT INTO `data` VALUES (13892, 'y***3', 5, '运行速度：很快\n屏幕效果：特别好\n散热性能：一般\n买的第三台本，性能没说的，外观漂亮。\n缺点升级困难。', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-20 17:22:20', 5);
INSERT INTO `data` VALUES (13893, '老***孩', 5, '运行速度：win11的系统，懂得都懂\n屏幕效果：很惊艳，顶级屏幕\n散热性能：散热风扇呼呼的，真给力\n外形外观：外形没有十四寸的看着惊艳，但是也很不错\n轻薄程度：很轻薄，手感不错\n其他特色：奈斯', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-06 12:53:36', 4);
INSERT INTO `data` VALUES (13894, '给***5', 5, '价格不贵，用着也很大气??是正品孩子也很满意，用久了也不会发热，屏幕色彩漂亮不刺眼。\n屏幕效果：好\n运行速度：快\n散热性能：好\n外形外观：漂亮\n轻薄程度：优', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-22 13:11:15', 4);
INSERT INTO `data` VALUES (13895, 'j***5', 3, '触控面板处有电流声，其他不错', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-08 23:35:19', 7);
INSERT INTO `data` VALUES (13896, 'j***r', 5, '晚上11点半下单，下午3点送到，京东相当给力。屏幕相当棒，机器配置高，CPU、GPU配置平衡。整机85W极致性能释放，比肩游戏本，RTX3050独显，实时光追、DLSS 2.0技术，游戏时能实现更加稳定的帧率，还保持了不错的能效比。内置有70Wh大容量电池，标配150W大功率适配器，实测30分钟就能充入50%左右电量，在外出时，也不会有续航焦虑。话说赠品什么时候送我', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-05 08:33:34', 4);
INSERT INTO `data` VALUES (13897, 'c***6', 5, '华硕笔记本刚收到就立马打开体验，键盘多了专业的数字键盘，用起来更方便了。地面的支撑点够高，好散热，再也不用担心温度过高影响电脑使用，体验感很不错。', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-13 20:18:46', 2);
INSERT INTO `data` VALUES (13898, 'u***h', 5, '屏幕效果：屏幕特别清晰\n外形外观：颜色特别好看，挺有高级感的\n轻薄程度：特别适合办公用，也特别轻适合外出携带\n运行速度：感觉还可以', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-05 12:04:02', 4);
INSERT INTO `data` VALUES (13899, '鸡***员', 5, '机子还不错，对比了好几个最后选的这款，感觉性价比高点，主要用来办公偶尔游戏算是很不错了。收到货用了几天了，来说下感受吧，首先电脑外观挺好看的，手感也很舒服，开机速度很快，运行好几个软件没有卡顿，买回来用鲁大师跑分检测了一下，也挺满意的，键盘灯挺炫，可以调节。总体蛮推荐购买的！', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-05 13:49:04', 1);
INSERT INTO `data` VALUES (13900, 'i***3', 5, '屏幕效果：好屏，无可挑剔\n运行速度：三个模式可选，静音模式都很流畅\n散热性能：散热无双单管的好很多\n轻薄程度：有显卡还能这么轻薄\n其他特色：背面有垫高能散热的设计不错', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-26 22:37:54', 4);
INSERT INTO `data` VALUES (13901, 'M***T', 5, '运行速度：非常的流畅\n屏幕效果：显示细腻，观感好，15.6寸很大\n散热性能：还没有进行游戏测试，目前还不错\n外形外观：简约大气，很喜欢这个颜色\n轻薄程度：符合一般轻薄本的要求\n简单的试了一下绝地求生在超高清分辨率下能有四十多帧的帧率，可以玩，别的还不知道，续航感觉掉电挺快的，总体很满意', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-05 08:48:19', 4);
INSERT INTO `data` VALUES (13902, 'v***K', 5, '运行速度：反应很快，顺畅无阻，笔记本电脑的不二之选\n屏幕效果：2.8K屏幕，真不是吹的，特别清晰\n散热性能：散热极强', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-23 20:04:17', 1);
INSERT INTO `data` VALUES (13903, '风***丶', 5, '屏幕是真的爱了 太流畅太惊艳了 无论是色彩还是帧率都给我眼前一亮的感觉 不像那些FHD的屏幕 当然买的时候也是冲着这个屏幕来的 果然没让我失望 其次就是做工摸起来也很舒服 看起来很上档次 开机速度也是杠杠的 客服服务也好 好评', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-19 23:03:22', 5);
INSERT INTO `data` VALUES (13904, 'w***3', 5, '刚到手，非常满意的一款型号，屏幕清晰亮丽，接口全，速度快，快递给力。孩子很喜欢。其它性能用几天再评。', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-05 21:10:32', 5);
INSERT INTO `data` VALUES (13905, 'j***6', 5, '运行速度：非常快\n屏幕效果：屏幕非常清晰，屏幕够大\n外形外观：银色耐看，高大上\n轻薄程度：很薄，随身带着办公非常方便\n散热性能：连续看电视剧都没有感觉烫，散热不错', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-03 22:03:48', 3);
INSERT INTO `data` VALUES (13906, 'u***w', 5, '非常满意的一款产品，色彩好，速度快，颜值高。主要是冲着oled屏幕来的，开机后效果棒棒哒，高色域屏，15.6英寸看着也很舒服，很值。', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-03 21:09:30', 5);
INSERT INTO `data` VALUES (13907, '君***明', 5, '高清屏幕高配置，看久了眼睛也不累，用起来很流畅，也比较安静，散热好。足够了，值得购买。价格也合适，快递也快捷', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-02 09:09:20', 2);
INSERT INTO `data` VALUES (13908, 'u***y', 5, '老华硕用户了。r7+3050真的就全能本了，不接电源办公集显也能胜任工作。在屏幕 重量 内存 扩展性各方面都比小新pro要好，更薄更好看，而且Oled真的很不错，看起来舒服不刺眼。随机附赠了很多贴纸。', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-27 12:12:30', 4);
INSERT INTO `data` VALUES (13909, '刘***悍', 5, '新机，流畅，高清，性价比超高，是我想要的电脑\n轻薄程度：很薄\n外形外观：好看\n运行速度：快', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-07 20:11:23', 1);
INSERT INTO `data` VALUES (13910, 'c***n', 5, '昨天下单今天上午就送到了，拆开简单操作下，运行速度很快，特别是这块屏幕，色彩很惊艳，饱和度很好，看视频真的很爽，电脑造型轻薄，比较时尚', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-08 12:44:00', 4);
INSERT INTO `data` VALUES (13911, 'Y***蚊', 5, '办公完全够用有余，应用开再多也不怕，OLED的屏幕看起来眼睛也不会累。外壳手感也很好，做工无可挑剔。就是数字键盘需要点时间适应。', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-21 09:03:13', 5);
INSERT INTO `data` VALUES (13912, '阿***雷', 5, '非常nice，摸起来质感特别舒服，特别是屏幕的清晰度，色彩度，看起来很正，平常主要学习，打打英雄联盟，足够了，因为不是游戏本，所以比较轻薄，随身携带也刚刚好。', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-21 23:18:11', 5);
INSERT INTO `data` VALUES (13913, 'j***o', 5, '机器性能好，好品质，非常喜欢的一款产品，非常棒！\n屏幕效果：观感性强\n外形外观：美观\n运行速度：快', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-11 10:05:39', 1);
INSERT INTO `data` VALUES (13914, 'j***V', 3, '还可以 ，性价比高，主要是屏幕确实清晰', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-06 14:41:20', 1);
INSERT INTO `data` VALUES (13915, 'j***v', 5, '很好用\n运行速度：挺快的\n屏幕效果：很清晰\n散热性能：不错\n外形外观：是我喜欢的款式\n轻薄程度：很薄，在我接受的范围内', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-03 20:48:46', 4);
INSERT INTO `data` VALUES (13916, '粮***友', 5, '外观简约不简单，手感很好，运行速度流畅无延迟，散热性能优良，屏幕很惊艳，整体轻薄，性能强劲', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-23 22:49:13', 5);
INSERT INTO `data` VALUES (13917, '这***3', 5, '外观很喜欢，看着很有质感。\n散热也不错，声音可以接受，这句AMD  YES\n屏幕素质很好，大屏加高分屏，办公看电影无敌。就是不知道有没有烧屏的情况，使用再看吧。\n重量也可以接受，短距离的移动比较方便。\n总体比较满意。', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-20 16:49:26', 3);
INSERT INTO `data` VALUES (13918, 'j***y', 5, '运行速度：很惊喜的是配的R7 5800和M.2的硬盘速度非常不错，轻度办公几乎秒开，开机速度也很快\n屏幕效果：买这台笔记本最核心的就是这块三星的OLED屏了，效果非常惊艳，后期自己租个校色仪校色一下就能用在设计上\n外形外观：1.4KG，商务轻薄，性能释放后，续航优化一下轻办公也能有3-5个小时，很够用\n最重要的是性价比，非常高~', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-10 18:18:03', 3);
INSERT INTO `data` VALUES (13919, '偷***变', 5, '很棒，音质效果好，屏幕分辨率高，看影片效果好，运行很快，流畅，开机也很快，蓝色外观很耐用，做工精细，触感舒适，方便携带，值得购买。', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-28 21:08:30', 3);
INSERT INTO `data` VALUES (13920, 'u***9', 5, '电脑已经收到了，非常满意，孩子特别喜欢，电脑非常薄，运行速度很快，屏幕特别清晰细腻，外观漂亮。真棒?！', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-18 18:34:48', 4);
INSERT INTO `data` VALUES (13921, 's***9', 5, '看了好几天，入手了这款。我原来买的第一台笔记本电脑就是华硕的。所以对华硕品牌有好印象。这次买电脑是因为现在的形势下哪天就需要家居办公了。所以赶紧入手一台办公电脑。今天拍，第二天就到了。京东效率很高。这个电脑颜值也不错，屏幕色彩很棒。带数字小键盘，方便财务做表。用一段时间再来追评。', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-06 21:24:52', 5);
INSERT INTO `data` VALUES (13922, 'l***8', 5, '物流很快，装上试了一下，运行速度快，不卡顿，屏幕清晰。外观轻薄好看，出门携带方便，非常不错。', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-02 14:44:17', 1);
INSERT INTO `data` VALUES (13923, '樱***颗', 5, '运行速度：很快，多个文件+PS用起来很流畅\n屏幕效果：大屏看的爽，画质很好\n对比了几款笔记本，这个配置和性价比超级赞', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-30 20:40:11', 4);
INSERT INTO `data` VALUES (13924, '尤***y', 5, '运行速度：快！！！真的很流畅，用于一些日常使用很赞\n屏幕效果：好，OLED 华硕好屏很赞，看视频很好\n散热性能：好，没感觉到热\n外形外观：金属质感无敌\n轻薄程度：轻薄\n其他特色：支持150快充', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-29 14:05:58', 3);
INSERT INTO `data` VALUES (13925, '瓜***m', 5, '运行速度：很流畅\n屏幕效果：清晰度高\n散热性能：很好\n外形外观：很漂亮', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-28 15:33:24', 5);
INSERT INTO `data` VALUES (13926, 'k***m', 5, '用了半个多月了，确实不错，特意来评价一下，妹妹很喜欢，配置也很不错，重量不重，白色的适合男女，送的鼠标和包质量也很好，非常nice', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-25 13:44:25', 4);
INSERT INTO `data` VALUES (13927, 'j***k', 5, '运行速度：很快\n屏幕效果：屏幕相当惊艳\n散热性能：还可以\n外形外观：外观很漂亮，整体质感没的说\n轻薄程度：重量不算很重，对一个女孩子来说还可以接受\n其他特色：买来给学设计的学生用的到了之后喜欢的不得了！', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-08 11:35:40', 2);
INSERT INTO `data` VALUES (13928, '我***李', 5, '感觉很好，可以购买\n屏幕效果：很好\n外形外观：很漂亮\n轻薄程度：很适合，薄\n这个价钱，这个一线品牌，真的很好呢，外观颜色非常好看，\n散热能力：不错\n运行速度：目前来看可以\n散热性能：现在嗯嗯可以', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-17 10:22:32', 2);
INSERT INTO `data` VALUES (13929, 'S***z', 5, '运行速度：很快很舒服\n屏幕效果：屏幕很nice\n散热性能：散热也很好\n外形外观：外观是很符合我的感觉\n轻薄程度：很薄', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-05 10:43:18', 3);
INSERT INTO `data` VALUES (13930, 'j***9', 5, '运行速度：速度很快，开机很快，打游戏不卡\n屏幕效果：看电视很棒\n散热性能：很好\n外形外观：很漂亮\n轻薄程度：很轻，不重', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-03 18:09:07', 2);
INSERT INTO `data` VALUES (13931, 'c***夕', 5, '高级灰的质感 很酷炫 比较商务沉稳大气！轻薄携带方便 颜值很棒，开机运行流畅 2.8K的屏幕特别清晰  华硕的品质一如既往稳稳的！', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-14 12:51:35', 4);
INSERT INTO `data` VALUES (13932, 'j***3', 5, '运行速度：运存够大，速度很快，日常办公绝对没问题\n屏幕效果：2.5K oled屏幕显示很棒，清晰\n外形外观：外观简约好看，做工精细，触感舒服，触摸板很大\n轻薄程度：整体不重，小巧轻便', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-17 11:50:56', 2);
INSERT INTO `data` VALUES (13933, 'j***A', 5, '运行速度：开机不超过5秒钟\n屏幕效果：OLED 屏，不错！\n散热性能：还可以！\n外形外观：高端大气上档次\n客服的服务也不错，问什么都能够好好的解答', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-03 18:09:55', 3);
INSERT INTO `data` VALUES (13934, '麒***e', 5, '运行速度：速度很快，非常满意\n屏幕效果：2k屏，效果很惊艳，很细腻\n外形外观：外观简洁大气\n轻薄程度：比想象中的更轻薄些\n散热性能：运行很静音，没有感觉到什么热量，散热系统还是不错的', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-05 17:46:47', 2);
INSERT INTO `data` VALUES (13935, 'j***1', 5, '运行速度：开机很快，运行速度正常没有卡顿\n屏幕效果：屏幕很nice\n外形外观：全银还是不错的\n散热性能：没有开很多软件，正常办公软件散热效果还可以，没有什么声音', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-23 16:56:58', 3);
INSERT INTO `data` VALUES (13936, 'j***w', 5, '外观简约大气，非常有质感。开机键手感非常好，尤其是阻尼回馈。屏幕就不说了，无敌赞。性能嘎嘎滴', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-11 20:14:39', 5);
INSERT INTO `data` VALUES (13937, 'T***8', 5, '终于等到我心心念念的电脑了，华硕笔记本做得还是不错的。快递物流很给力呢，外包装也很精致哦！电脑外观简约大方，大小很适合学生党上学用喔！电脑屏幕真的非常棒，很有质感，显示屏分辨率挺高的，这个屏幕算是我最喜欢的一点了！而且键盘也很有设计感，简约大气！搭配win11，使用非常顺滑！总体灰常不错，很满意哦！', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-02 20:32:24', 4);
INSERT INTO `data` VALUES (13938, 'j***6', 5, '运行速度：很快\n屏幕效果：显示效果很好，色彩鲜艳\n轻薄程度：很轻薄\n散热能力：打游戏也不会很热，噪音也不大', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-23 18:06:51', 3);
INSERT INTO `data` VALUES (13939, '元***喵', 5, '笔记本性能不错，完全能满足日常使用需求，偶尔还能打打游戏，尤其是带着出门，非常轻。笔记本的外壳是金属的，质感不错，屏幕色彩没的说，非常艳丽，OLED屏就是棒！', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-11 08:50:38', 4);
INSERT INTO `data` VALUES (13940, '初***七', 5, '画质一流，开机速度也快，很满意，已经安利给好友，华硕品质确实有保证，屏幕大，运行流畅，散热也不错，续航给力，很满意的一次购物', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-20 17:45:45', 4);
INSERT INTO `data` VALUES (13941, '伴***久', 5, 'OLED屏的效果真心没话说，已经不想再看传统的LCD\n屏了。色彩艳丽，还原精准。分辦率是 1920x1080的足\n够用了。接口很多很齐全，特别 是有Type-C口和\nHDM!口，数据传输和视频传输 非常方便。', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-19 02:18:33', 3);
INSERT INTO `data` VALUES (13942, '汝***爱', 5, '现在大件也在京东买了，质量有保证，春节给孩子买个笔记本电脑，以便于上网课用，电脑很漂亮，银色的外观，超薄的机身，质感很好，运行速度也很快，屏幕效果也不错。', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-25 19:25:11', 3);
INSERT INTO `data` VALUES (13943, 'j***d', 5, '运行速度：不错我很满意\n屏幕效果：很有质感\n散热性能：才刚开始不清楚\n外形外观：非常非常好看', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-30 13:57:51', 3);
INSERT INTO `data` VALUES (13944, 'M***r', 5, '运行速度：运行速度很快，毕竟新电脑，开机以及打开软件的速度都很快。\n屏幕效果：2k oled屏幕，显示效果很棒，不漏光，不发白，显示细腻。\n散热性能：散热目前还没有运行一些吃配置的程序，所以风扇一般都是最低速转，声音只有在特别安静的时候能听到。\n轻薄程度：其实要论轻薄程度，我最多给这个本打3个星。\n外形外观：外形外观很漂亮，银色的，正面的logo很简洁大气。', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-04 09:49:47', 2);
INSERT INTO `data` VALUES (13945, '古***夫', 5, '用了一段時間，感覺非常棒！屏幕細膩，高分辨率，高色域，高亮度，高色準度   ...  開機速度超快（秒開）工作時風扇噪音極低可以忽略不計。電池表現也不錯，待機時間還可以   ...  好評！！！', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-14 00:01:57', 2);
INSERT INTO `data` VALUES (13946, '霜***天', 5, '屏幕效果：屏幕看的很舒服。\n外形外观：外形很精简，很适合商务办公。\n散热性能：散热效果不错，声音也不大。\n轻薄程度：轻薄本，很薄。', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-17 15:22:01', 2);
INSERT INTO `data` VALUES (13947, 'j***C', 5, '颜色很喜欢，键盘敲击感很舒服，风扇声音很轻。 电脑性能：极速体验，非常不错，值得购买。价格便宜实惠，满足众多办公需求，性价比那叫一个字高', '无畏15 2022 高性能轻薄本', '2022-06-26 22:30:23', 5);
INSERT INTO `data` VALUES (13948, '姓***壁', 5, '首先京东自营京东物流快递初六下午秒送，目前为止中国最快速度快递！\n开机设置联网，注册账户，激活免费永久office办公全家桶\n下载各种软件鲁大师跑分等\n正品，屏幕显示效果相当惊艳，8600mad办公和出色的显卡完全可以，值得推荐\n办公工作散热静音，根本听不到声音，简直完美！\n外观漂亮，超薄，看着有档次，键盘唯一不是银色可惜了，不然颜值更高，数字小键盘很实用！\n充满电办公感觉能用5/7小时，续航能力强，唯一改进一下变压器有灯光最好，可以知道再正常充电\n办公电脑性价比很高，处理器完全够用，关键显卡相当于1060看视频玩小型游戏完全够用\n正版office给用户省了很多钱\n电脑值得拥有', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-29 10:36:30', 3);
INSERT INTO `data` VALUES (13949, 'i***u', 5, '屏幕效果：Oled 实在太惊艳了，颜色不是lcd可比的\n运行速度：很流畅很快，华硕没有内置任何流氓软件非常好\n外形外观：银色硬朗清爽，非常好看\n轻薄程度：重量很轻，适合出差当\n运行速度：配了r7 6800h ddr5 5500 3050显卡这个价位性价比很高', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-25 21:42:28', 6);
INSERT INTO `data` VALUES (13950, '箐***_', 5, '屏幕效果：屏幕成像很好\n外形外观：外观挺好看\n运行速度：运行比较快', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-05 18:43:42', 5);
INSERT INTO `data` VALUES (13951, '终***呀', 5, '电脑收到后 使用几天才来评价的 键盘触感非常好 触摸板很光滑 还有背光键盘 看起来非常好看 而且这个屏幕是亮点 看起来很高级  用于大学生学习足够了\n运行速度：开机时间很短 大概就四五秒钟\n散热性能：散热性能也很好 用起来也不热\n外形外观：外观非常好看 适合男女大学生', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-21 16:24:02', 2);
INSERT INTO `data` VALUES (13952, 'j***J', 5, '屏幕效果：很好，色彩度贼棒，15.6英寸看着非常爽，开机五秒不到，反应灵敏，大学生可以入', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-04 09:49:03', 5);
INSERT INTO `data` VALUES (13953, 'j***N', 5, '用了一段时间了，还不错，不怎么玩游戏的，就追剧，学学ps，屏幕很不错，也不怎么热，金融专业的，感觉用起来妥妥的\n运行速度：不卡\n屏幕效果：很棒很棒\n散热性能：打游戏时才会烫\n外形外观：满意\n轻薄程度：商务本，不轻', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-01 21:34:09', 1);
INSERT INTO `data` VALUES (13954, '最***人', 5, '运行速度：还不错\n屏幕效果：挺清晰的\n散热性能：还行\n外形外观：外观不错，简约大方\n轻薄程度：不算重\n\n目前还没发现什么问题，还不错啦，快递很给力，小哥很贴心！', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-17 15:09:07', 2);
INSERT INTO `data` VALUES (13955, 'j***s', 5, '由于疫情，在广州学习提前回家上网课，学校要求要有游戏才能更好的上传画画，选择了这款oLEd高色域2K高清屏，色彩清晰细腻，16G内存，512固态盘，八核处理器，运行速度快，用来办公上课己非常足够了！', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-02 11:05:38', 3);
INSERT INTO `data` VALUES (13956, '江***1', 5, '之前買過華碩無畏pro 14就覺的不錯，開機速度快，oled屏真好看，這次換買大一號的無畏pro,一樣很不錯,讚喔！', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-18 20:03:30', 4);
INSERT INTO `data` VALUES (13957, '艾***g', 5, '运行速度：R7标压处理器，心心念念很久终于下单了\n屏幕效果：屏幕效果没的说，oled就是棒\n散热性能：散热还没试，应该不会差\n外形外观：外形商务范，很有感觉，很有质感。', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-05 21:06:22', 2);
INSERT INTO `data` VALUES (13958, '咳***-', 5, '拿到了心心念念的电脑，外观大气上档次。目前不知道游戏效果如何，后续测试一下游戏效果，应该会很不错。', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-07 12:12:19', 4);
INSERT INTO `data` VALUES (13959, 'j***n', 5, '屏幕真的好，看着舒坦，比我现在用的小新Pro16强太多了，华硕电脑大品牌值得信赖', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-11 22:35:21', 6);
INSERT INTO `data` VALUES (13960, 'x***n', 5, '非常好的电脑，做工好，速度快，发热控制可以，屏幕优秀，性价比高，非常实用的游戏本。', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-08 21:58:17', 4);
INSERT INTO `data` VALUES (13961, 'j***p', 5, '运行速度：办公设计无压力，运行超快，使用流畅\n屏幕效果：音质超级棒，家庭影院的效果\n散热性能：散热超级好，长时间使用没问题\n外形外观：外观时尚，轻薄有质感，超级好看的本', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-03 17:39:19', 1);
INSERT INTO `data` VALUES (13962, '死***m', 5, '冲着它底蓝光，真色彩，反应快的特点买的。专门看了场电影后再来评价，颜值很高，色彩很逼真，看视频很舒服。反应速度也很快。第一次买华硕的笔记本，很满意。', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-07 17:27:03', 3);
INSERT INTO `data` VALUES (13963, 'b***o', 5, '第一次买华硕，听别人说好用，所以就来买一台平常用用，屏幕效果挺好的，声音也挺立体，键盘弹得有感性。先再观察一段时间看看效果如何，就目前而言，还是很不错的性价比。', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-25 19:07:24', 3);
INSERT INTO `data` VALUES (13964, '如***你', 5, '给女朋友买来办公的，之前那个电脑要淘汰了。无畏pro的OLED屏幕真的很棒，锐龙的处理器再加上小数字键盘，无疑是办公的一大助力。', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-10 13:42:11', 5);
INSERT INTO `data` VALUES (13965, 'j***2', 5, '运输过程中保护的很好试了一下\n运行速度：很快\n屏幕效果：2.8K真的惊艳到了！\n散热性能：可以\n外形外观：好看\n轻薄程度：薄', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-29 15:08:09', 2);
INSERT INTO `data` VALUES (13966, 'j***r', 5, '喜欢蛮好哈 这笔记本显示效果好 色彩准确很喜欢哈 我给我表弟买的 他也很喜欢 华硕这款笔记本采用OLED 屏幕显示效果的确一流 比普通液晶显示器显示好太多', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-09 13:17:42', 4);
INSERT INTO `data` VALUES (13967, 'j***u', 5, '运行速度：流畅，快速\n屏幕效果：雾面屏很好，清晰\n散热性能：cpu温度很稳定，不会突然升高\n外形外观：大气，15.6英寸很适合办公看剧等等需要用到屏幕的活动\n轻薄程度：还行\n散热能力：必须能行啊\n其他特色：买来几天后才来评价的，对于很多人说的没有激活office，其实可以用WPS，这个是免费的，不影响办公。第一张图是在验机，验机过后各个参数是没问题的，屏幕无坏点，还得是大厂的品控?', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-11 13:59:20', 2);
INSERT INTO `data` VALUES (13968, 'l***k', 5, '相信华硕，第二台华硕的电脑了，运行很流畅，OLED屏幕也很赞', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-11 11:17:45', 4);
INSERT INTO `data` VALUES (13969, '北***2', 5, '冲着 oled 屏幕来的，观望了很久，赶着活动来的，价格贼便宜。开机后效果棒棒哒，高色域屏幕搭配 olwd ,15.6寸看着很舒服，对于我这种追剧的人，简直不要太适合。16h大内存，512g固态硬盘，感觉很值得。', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-04 17:15:37', 3);
INSERT INTO `data` VALUES (13970, '陳***查', 5, '我是一名设计师，摄影师，3D渲染师，偶尔还做做短视频。主力机是办公室的台式电脑。但有时候周末还需要偶尔的工作，所以轻便和性能选了平衡，这款电脑很好地满足我，而且还有超清晰的oled屏，看视频一流。接下来也要努力成为一名视频博主，希望它陪我一起成长努力。加油吧。', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-09 23:54:52', 2);
INSERT INTO `data` VALUES (13971, '德***信', 5, '高性能的锐龙6代处理器。2.8k屏的oled一下很棒。色彩搭配非常协调&hellip;&hellip;16G内存搭载512硬盘容量很棒。买它不会错', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-26 16:45:38', 4);
INSERT INTO `data` VALUES (13972, '大***檬', 5, '华硕的电脑真的不错，第一次用华硕的笔记本，没想到国产的电脑会这么好，运行速度这么快，包装完好，没有磕碰，发货速度也很快，到货速度也很快，非常完美。点赞', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-18 12:22:49', 4);
INSERT INTO `data` VALUES (13973, '香***宝', 5, '运行速度：运存够大，速度很快\n屏幕效果：特别清晰\n轻薄程度：比较轻便，轻薄\n散热性能：很优秀，声音也很小\n散热性能：运行很静音，没有感觉到什么热量\n轻薄程度：整体重量1.7kg左右 算是比较便携', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-02 17:41:31', 1);
INSERT INTO `data` VALUES (13974, 'j***q', 5, '电脑收到了，物流很快，电脑很薄屏幕清晰孩子上网课用很好，系统流畅。', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-20 19:48:15', 6);
INSERT INTO `data` VALUES (13975, '小***铎', 5, '锐龙标压性能突出 速度快 性价比很高 大尺寸全键盘 OLED屏清晰 高亮度清晰 外观漂亮', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-25 10:55:14', 5);
INSERT INTO `data` VALUES (13976, '嘤***1', 5, '用了一段时间，挺好用的，平常也不玩游戏，就用来学习，这个价位很良心\n运行速度：非常快\n屏幕效果：非常漂亮\n散热性能：散热很好\n外形外观：外观很大气\n轻薄程度：轻薄，拿着不会太累', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-30 13:18:21', 1);
INSERT INTO `data` VALUES (13977, 'j***L', 5, '很好用 目前没发现问题，外观也很好看\n运行速度：很好\n屏幕效果：无敌\n散热性能：很好', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-17 11:25:47', 3);
INSERT INTO `data` VALUES (13978, 'm***s', 5, '屏幕效果出众，运行速度非常快，机子的做工也不错，各方面都符合工作的需求，重量也不是很重，可以随身携带，带出去也很有范，同事看了都说好', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-02 22:23:04', 2);
INSERT INTO `data` VALUES (13979, '燃***树', 5, '发货很快 屏幕分辨率很高 色彩也不错 电脑重量合适 win11的系统用着很新颖', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-06 20:21:19', 5);
INSERT INTO `data` VALUES (13980, 'j***P', 5, '电脑综合性能不好也不差，日常学习办公完全够用，屏幕也很好，性价比很高，非常不错', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-09 16:38:30', 5);
INSERT INTO `data` VALUES (13981, '重***y', 5, '运行速度：运行速度很快\n屏幕效果：OLED屏幕，色彩鲜艳，质感细腻\n散热性能：双风扇散热，效率高\n外形外观：银灰色商务风外形\n轻薄程度：轻薄游戏本的定义', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-10 10:55:43', 1);
INSERT INTO `data` VALUES (13982, '青***璃', 5, '笔记本挺不错的，看着也很舒服，很流畅，手感特别好，明天下载游戏试试3050咋样。', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-19 22:08:04', 4);
INSERT INTO `data` VALUES (13983, 'w***k', 5, '看了很久最终选了华硕这款性价比高的 2.8k屏幕就是清晰 游戏办公两不误  颜值大气时尚 出差用的舒服?', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-15 12:42:23', 5);
INSERT INTO `data` VALUES (13984, '大***C', 5, 'OLED屏幕，色彩很饱满，屏幕刷新率高，R7-6800+3050满足办公以及游戏需求,主流游戏基本上都能流畅运行，对于高性能轻薄本来说性价比很高，推荐', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-19 15:36:04', 3);
INSERT INTO `data` VALUES (13985, '云***d', 5, '买给弟弟的，他说非常好用，屏幕很漂亮，超轻薄，办公神器！还有鼠标和电脑包送，到手即用！', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-06 21:36:10', 5);
INSERT INTO `data` VALUES (13986, 'u***a', 5, '笔记本第二天收到，运输真的快捷，打开包裹第一感觉笔记本高档豪华，赠送的包包和鼠标都有了。试机开机启动快速，屏幕显示惊艳，LED色彩艳丽，清晰度高，试用一天后一切正常运行，nice', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-09 10:17:16', 3);
INSERT INTO `data` VALUES (13987, 'T***K', 5, '没用过华硕，单从外观来看，颜值还是很不错的，使用的系统也还好\n运行速度：不错\n屏幕效果：屏幕效果非常好\n散热性能：散热性能也还行\n外形外观：外观整体感很好\n轻薄程度：办公很适合', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-02 22:28:13', 1);
INSERT INTO `data` VALUES (13988, 'w***冰', 5, '开机七秒钟左右运行速度很快\n屏幕采用了视网膜屏刷新率高达\n全金属机身双风扇散热很棒\n看电影打游戏很流畅画质很高\n活动入手性价比高值得购买', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-27 05:46:33', 4);
INSERT INTO `data` VALUES (13989, 'c***h', 5, '发货很快，配送及时，整体来说质量很好，很有质感，感觉声音小了点，华硕的品质一如既往的好', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-11 21:15:26', 5);
INSERT INTO `data` VALUES (13990, 'j***5', 5, '运行速度：快！\n屏幕效果：屏幕很好，嗯。\n散热性能：散热也很不错。\n外形外观：外观非常简约大气\n轻薄程度：相对于游戏本来说很轻薄啦。', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-20 09:17:38', 3);
INSERT INTO `data` VALUES (13991, '虎***累', 5, '运行速度：好快\n屏幕效果：够清楚\n散热性能：非常好\n轻薄程度：轻薄，拿着很爽\n外形外观：好看', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-15 20:05:26', 2);
INSERT INTO `data` VALUES (13992, 'j***U', 5, '电脑颜值很高，物流很快，还是指纹解锁高级！暂时没有发现什么问题，先用一下看看，很流畅！！！', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-25 15:55:24', 4);
INSERT INTO `data` VALUES (13993, 'm***a', 5, '笔记本外观简洁大方，oled屏幕显示效果明显更加亮丽，预装win11系统，开机速度快，运行流畅。摄像头带物理保护，小细节很用心。', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-13 09:26:52', 2);
INSERT INTO `data` VALUES (13994, '美***a', 5, '外形外观：很漂亮，轻薄\n散热能力：声音小挺好的\n运行速度：挺快\n键盘三段背光很漂亮，还有数字小键盘很赞，不卡顿，屏幕很清晰，物流超级快！', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-02 12:18:14', 2);
INSERT INTO `data` VALUES (13995, 'j***t', 5, '运行速度：非常快，很爽！\n屏幕效果：非常细腻，颜色漂亮！\n散热性能：好，散热Ok！\n外形外观：中规中矩，每个笔记本都差不多了！\n轻薄程度：很轻薄，手感好！', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-17 21:10:54', 1);
INSERT INTO `data` VALUES (13996, '菲***茄', 5, '屏幕效果：非常可以\n散热性能：散热很快\n外形外观：银色很好看\n运行速度：很快，很直观的感受\n京东的配送速度超级快，昨天才下单今天上午立马送到了！', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-29 12:09:27', 3);
INSERT INTO `data` VALUES (13997, '全***p', 5, '运行速度快，主流软件都没有\n屏幕清晰度非常好，色彩非常完美，散热效果也很好\n，这个价位综合性能比较不错的电脑。', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-14 16:58:56', 4);
INSERT INTO `data` VALUES (13998, '蜡***-', 5, '电脑非常好用，买来学习用的，续航时间足够长，性能也完全没有问题，不卡顿，用6个小时左右完全没问题的，京东快递配送也很快，非常满意', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-17 14:36:55', 3);
INSERT INTO `data` VALUES (13999, '孙***飞', 5, '想买台笔记本很久了，做了很多功课，选了几款，最后选择了华硕的这款，看中了它的高性价比，尤其是屏幕，我觉得所有参数同质化话后，屏幕的质量最重要，毕竟保护视力人人有责嘛。', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-07 23:47:27', 3);
INSERT INTO `data` VALUES (14000, 'u***4', 5, '电脑外观非常漂亮，用了几天，非常流畅，屏幕色彩好，，好评', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-23 17:31:06', 5);
INSERT INTO `data` VALUES (14001, 'j***8', 5, '试用了一段时间感觉越来越好，也许刚开始因为自己没接触过华硕的笔记本，有很多不懂的，找了很多次店家，都解决了，总体来说便宜，用着也不差，??', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-20 11:59:45', 4);
INSERT INTO `data` VALUES (14002, 'j***e', 5, '屏幕很清晰，很方便\n运行速度：高\n散热性能：好\n外形外观：很好看\n轻薄程度：我觉得稍微有点重', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-09 14:15:47', 2);
INSERT INTO `data` VALUES (14003, 'j***S', 5, '运行速度：很好嘎嘎快非常建议购买\n屏幕效果：十分棒??平常不用的時候拿來擋住灰塵,讓機器延長使用壽命,就是我螢幕保護得買小瞭一點,再來買塊大的,顏色也是非常小清新,我很喜歡\n\n蛮好的，这个图案我喜欢，不怕键盘脏了，看着也整洁多了\n\n白色太容易脏了，布外面的图案是粘上去的，会容易掉，价格偏贵\n\n宝贝非常好，很满意，老板服务态度很好，希望大家一定要选择她家买东西哦！\n\n显示器那个很合适，键盘、低音', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-12 11:05:55', 2);
INSERT INTO `data` VALUES (14004, 'u***1', 5, '特别好用 和之前的本子比起来屏幕确实好了很多\nLoL这样子的游戏长时间也可以流畅运行\n总体来说很满意\n物流也是飞快', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-17 11:11:25', 4);
INSERT INTO `data` VALUES (14005, 'j***q', 3, '其他没什么问题还可以，就是没有自带的免费office', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-04 15:20:47', 6);
INSERT INTO `data` VALUES (14006, 'j***f', 5, '电脑很好！ 屏幕很好看！很方便，速度也非常快 感觉不算很轻但也适合 散热声音不大', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-14 16:41:57', 3);
INSERT INTO `data` VALUES (14007, 'j***V', 5, '这款电脑非常好用，不卡顿开机13秒，当天买第二天就到了，客服发货很快，关键客服有问必答态度也很好，推存大家购买?', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-27 17:49:57', 2);
INSERT INTO `data` VALUES (14008, 'j***1', 5, '非常满意的一款产品，色彩好，速度快，颜值高，还没开始用，只是全面试了试。办公用首先，2K屏显示清晰细腻。看了舒服。学习用的，看视频很不错！', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-21 13:48:41', 2);
INSERT INTO `data` VALUES (14009, '假***生', 5, '华硕无畏Pro15 2022锐龙版，是台比较均衡的高性能全能本。特别是比起上代无畏Pro15的进步很大，屏幕从上代的1080P分辨率的屏幕换成了2.8K 120Hz刷新率的OLED屏幕。 色彩上也有逐台的潘通校色且支持色彩切换，在开启HDR后全亮度类DC调光，也不用担心OLED的频闪问题。', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-14 10:10:23', 4);
INSERT INTO `data` VALUES (14010, '不***人', 5, '比预期中的要好一些，屏幕素质相当出色！看电影的话很是享受！买来办公用的，这个配置也是绰绰有余了，很不错！', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-20 15:20:47', 2);
INSERT INTO `data` VALUES (14011, 'S***c', 5, '电脑已经那会来好几天了，用了一下来评论了，个人感觉超级好，不管外观呀，屏幕啊等等都是好的也很划算。用起来也很快。超级赞赞赞赞', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-11 18:49:53', 3);
INSERT INTO `data` VALUES (14012, '言***_', 5, '电脑颜值在线，键盘的金属质感好好看?裸机1.8kg，充电器不到一斤，我觉得女孩子拎得动了??发货很快，第二天就到了，迎接第一台笔记本电脑非常激动多多包涵', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-12 10:43:30', 3);
INSERT INTO `data` VALUES (14013, 'u***f', 5, '运行速度：运行流畅不卡顿\n屏幕效果：屏幕外观精美，观影体验极佳\n外形外观：简约\n轻薄程度：十分轻，办公首选', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-11 15:31:58', 2);
INSERT INTO `data` VALUES (14014, 'y***y', 5, '屏幕效果：非常爽，不愧是oled屏\n外形外观：很酷炫，实体数字键非常实用', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-31 18:46:54', 4);
INSERT INTO `data` VALUES (14015, 's***4', 5, '很棒，开关机速度很快，丝滑流畅！画面绚丽，老婆办公用，足够了，Win11用着有点小不习惯，不过无所谓，慢慢就好了，触摸板也很灵敏，完美，跑分略低是正在下载软件！快递给力，第二天就到！', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-24 16:24:22', 2);
INSERT INTO `data` VALUES (14016, '衣***贱', 5, '应朋友要求帮忙挑选一款办公用笔记本，兼顾性能、价格及外观等，最终选定了这款笔记本，性价比算是同价位最高的，而且还用的是OLED屏幕，开机解包进入系统后，屏幕的呈现效果真的是太惊艳了，满星好评', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-13 15:59:31', 3);
INSERT INTO `data` VALUES (14017, 'l***锋', 5, '非常喜欢的一台电脑 屏幕特别鲜艳 运行速度也很快 背光键盘也很亮', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-07 09:22:33', 4);
INSERT INTO `data` VALUES (14018, '温***_', 5, '屏幕效果：键盘亮灯真的很帅\n散热性能：风扇声也很小\n外形外观：很好看 金属外观 银色', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-21 00:15:13', 2);
INSERT INTO `data` VALUES (14019, 'j***5', 5, '拿来追剧学习都很好啊，电脑也很好看！！！颜值很高，客服态度也很好，我有不懂的问客服都给我解答了\n散热能力：还不错\n轻薄程度：一般的\n外形外观：好看\n屏幕效果：很好很清晰', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-21 17:24:57', 2);
INSERT INTO `data` VALUES (14020, '灬***莲', 5, '打开包装的一瞬间超级惊艳，ips果然不是吹得，颜色效果特别好，键盘做了磨砂处理，性能没话说', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-23 12:47:34', 3);
INSERT INTO `data` VALUES (14021, '3***5', 5, '给孩子上网课用的，感觉很轻，清晰度很高，申请还送了电脑包，使用中，暂时无问题\n屏幕效果：效果佳', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-20 22:06:34', 3);
INSERT INTO `data` VALUES (14022, 'j***C', 5, '外形外观：颜值高，真的简洁又高级，这个银色真的好看键盘也是同色，真的爱了\n轻薄程度：全能本，轻薄不重\n运行速度：速度快，不卡。\n当时挑选的时候就是因为颜值才决定买这个的，后来才发现性价比也不错，这个价位买到我挺满足的，办公娱乐妥妥的超爱。', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-02 02:05:20', 2);
INSERT INTO `data` VALUES (14023, '血***舞', 5, '再次购买华硕笔记本电脑，2.5KOLED屏幕120hz高刷，非常清晰，色彩艳丽。配置也是主流，性价比非常高，办公学习首选，推荐！', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-16 12:44:57', 3);
INSERT INTO `data` VALUES (14024, 'l***d', 5, '非常好的一款电脑 配置和外观都很新颖 运行大型游戏不在话下 值得推荐', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-11 11:22:01', 5);
INSERT INTO `data` VALUES (14025, '土***8', 5, '电脑不错，配置挺高，屏幕也很清晰，比原来的游戏本轻，办公画图基本够用了，第三台华硕的本子了，不错不错', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-18 13:39:19', 2);
INSERT INTO `data` VALUES (14026, 'j***C', 5, '屏幕效果：屏幕大，用工具箱测试过无暗点\n运行速度：运行速度挺快的\n外形外观：外观简单大气\n轻薄程度：非常轻薄', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-05 18:04:45', 1);
INSERT INTO `data` VALUES (14027, 'x***6', 5, '散热性能：非常棒，办公的时候非常安静，游戏的时候风扇告诉运转散热也很好。\n\n屏幕效果：屏幕色彩效果很好。\n\n轻薄程度：性能介于游戏本和轻薄本之间，轻薄便携程度也一样，外出想玩游戏又不想带砖头可以考虑这个型号', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-30 19:30:56', 2);
INSERT INTO `data` VALUES (14028, 'i***i', 5, '电脑入手很满意，外观好看，轻薄方便携带，而且开机运行速度快，一般办公用速度给力，散热也很好，不用担心机器温度影响运行速度了，屏幕看着也很舒服', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-31 22:10:51', 2);
INSERT INTO `data` VALUES (14029, 'j***b', 5, '电脑收到了真不错很适合办公用\n运行速度：挺流畅的\n屏幕效果：看着很舒服\n散热性能：散热很好', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-24 12:43:43', 2);
INSERT INTO `data` VALUES (14030, 'j***5', 5, '运行速度：杠杠的，十分流畅！\n屏幕效果：不愧是oled屏幕，我家孩子都说十分清晰！\n\n散热性能：散热挺好，风扇声音也不大！', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-08 20:30:03', 1);
INSERT INTO `data` VALUES (14031, 'b***5', 5, '运行速度：很快，16g内存\n屏幕效果：很清晰ips屏幕\n散热性能：很流畅，\n外形外观：很漂亮', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-08 11:27:52', 2);
INSERT INTO `data` VALUES (14032, 'j***u', 5, '笔记本非常漂亮，用起来非常快，屏幕颜色靓丽，显卡也很给力，玩大型游戏很轻松，最喜欢的就是他的外观了，丝滑感受。', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-08 08:36:55', 3);
INSERT INTO `data` VALUES (14033, 'j***9', 5, '本人小白 第一次买电脑 然后朋友推荐了这个 外观性能都很不错 很值得购买 特别棒 推荐推荐！！\n运行速度：不错\n屏幕效果：oled特别棒\n散热性能：好\n外形外观：好', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-14 09:08:42', 2);
INSERT INTO `data` VALUES (14034, 'j***v', 5, '对比了之后选的蓝色的，颜色很漂亮个人觉得比银色更上档次，机子也比较轻薄，屏幕画质清晰运行速度快，整体比较满意', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-28 12:00:11', 3);
INSERT INTO `data` VALUES (14035, 'j***A', 5, '很好的电脑，学习办公游戏的可以，主要还很轻，性能很好，速度很快，续航很好，美观，很值得入手', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-15 16:51:04', 2);
INSERT INTO `data` VALUES (14036, '南***悠', 5, '对比了很久，最终选择了这款，收到货很惊喜，很激动。外形很漂亮，有质感，键盘也很舒服，运行速度快，散热也很好', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-04 00:40:51', 3);
INSERT INTO `data` VALUES (14037, 'J***货', 5, '这个价位的笔记本里无敌了，屏幕色域够深够亮，内存够用。固态硬盘默认500g且到手无分区，需要手动分区，有存储焦虑的可以加装更大空间的。整体完美！', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-02 15:41:10', 2);
INSERT INTO `data` VALUES (14038, 'I***o', 5, '这款电脑颜值很高，性能综合，Oled屏幕显示效果我只能说太爽了，华硕品质，坚如磐石。', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-22 09:03:15', 5);
INSERT INTO `data` VALUES (14039, '扁***1', 5, '不错，键盘手感好，速度快。特别是屏幕，太清楚了，比LCD的清楚太多，亮的清楚黑的透彻！', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-13 09:48:05', 2);
INSERT INTO `data` VALUES (14040, '浅***K', 5, '运行速度：运行速度非常的快\n屏幕效果：屏幕亮度看着都很舒服\n散热性能：用了半天一点也不烫手，散热效果非常好\n外形外观：很时尚，很美观', '无畏Pro 2.8K OLED 15.6英寸', '2023-01-08 16:13:39', 2);
INSERT INTO `data` VALUES (14041, '拉***笨', 5, '华硕现在的笔记本，越来越好了。性价比贼高，做工也好。\n运行速度：5800H的CPU性能已经过剩，最后使用。\n屏幕效果：Oled的屏幕，算是完美屏了。', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-28 20:56:22', 4);
INSERT INTO `data` VALUES (14042, 'j***k', 5, '大牌没得说就是好，收到体验一下午了，主要用来设计目前很流畅，2.8k屏超清晰这也是我入手理由，总之超棒。', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-12 17:53:48', 4);
INSERT INTO `data` VALUES (14043, '平***l', 5, '鲁大师检测出来的各个配件都是一等品，连锐龙本最受诟病的联发科网卡都换成瑞立网卡了，屏幕是三星原装的，屏幕素质很好，游戏和视频都能运行舒畅。发货速度快，包装非常仔细，严实。', '无畏Pro 2.8K OLED 15.6英寸', '2022-12-03 12:46:39', 4);
INSERT INTO `data` VALUES (14044, 't***d', 5, '心念念的本本终于到了，激活简单，秒开关机，高刷屏配合高清屏幕，大爱，散热性，用ps二小时感觉不到热。推荐', '无畏Pro 2.8K OLED 15.6英寸', '2022-08-15 14:31:23', 3);
INSERT INTO `data` VALUES (14045, 'x***9', 5, '运行速度：快\n屏幕效果：清楚\n散热性能：好\n外形外观：屏幕很大，看的很舒服\n轻薄程度：挺薄的', '无畏Pro 2.8K OLED 15.6英寸', '2022-09-02 07:50:57', 1);
INSERT INTO `data` VALUES (14046, 'j***l', 5, '运行速度：体面\n屏幕效果：可以\n散热性能：还行\n外形外观：好看\n轻薄程度：可以\n其他特色：非常高清', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-04 17:37:24', 1);
INSERT INTO `data` VALUES (14047, 'j***E', 5, '真的选了好久现在拿到手了这款电脑体验感真的不错\n运行速度：快\n屏幕效果：非常好\n散热性能：可以\n外形外观：巨好看\n轻薄程度：可以', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-03 20:21:27', 1);
INSERT INTO `data` VALUES (14048, '枫***境', 5, '用了一年vivobook14，趁今年双十一以旧换新，3千块钱拿下7千电脑，当天晚上10点下的单，第二天上午就拿到新机了，感觉真的不错?(?^o^?)?\n外形外观：跟14几乎一样的金属外壳，质感很好\n轻薄程度：薄，可以轻松塞进背包\n屏幕效果：OLED屏清晰看着舒服', '无畏Pro 2.8K OLED 15.6英寸', '2022-10-27 09:06:44', 1);
INSERT INTO `data` VALUES (14049, '吴***冉', 5, '运行速度：很快\n屏幕效果：很好，看电影，办公都很好\n外形外观：银色的，很好看，颜值高', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-02 12:42:04', 1);
INSERT INTO `data` VALUES (14050, 'j***k', 5, '运行速度：超快，游戏上课足够用\n\n屏幕效果：很清晰，颜色柔和\n散热性能：一级棒，几乎听不到散热器的声音', '无畏Pro 2.8K OLED 15.6英寸', '2023-03-01 07:07:02', 1);
INSERT INTO `data` VALUES (14051, 'j***x', 5, '很好，而且快递速度好快真的好快\n屏幕效果：非常奈斯    ，声音也很好\n散热性能：高 很流畅', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-02 15:48:01', 2);
INSERT INTO `data` VALUES (14052, 'q***1', 5, '电脑配置性价比很值 ，屏幕非常舒适清晰，音效也好 完全静音。活动期间送了包鼠标，对于办公来讲 性能绝对够用，缺点就是没有人脸识别或者指纹识别，不够进步。其他都好。', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-03 13:51:37', 1);
INSERT INTO `data` VALUES (14053, 'L***哈', 5, '电脑很好用，给人高端大气感，非常喜欢，之前也是用华硕的电脑，用了六七年都有了，现在换个新的，价格也很优惠，真的非常喜欢，', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-15 16:41:45', 2);
INSERT INTO `data` VALUES (14054, 'j***n', 5, '发货快价性价比高，电脑叠加保固很实用\n运行速度：快\n屏幕效果：亮丽\n外形外观：大方美观', '无畏Pro 2.8K OLED 15.6英寸', '2022-11-07 20:59:26', 2);
INSERT INTO `data` VALUES (14055, 'j***8', 5, '电脑真的是很不错，轻薄，开机很快，而且用的时间长了，也不发热，买手提电脑还是要买大牌的。', '无畏Pro 2.8K OLED 15.6英寸', '2023-02-02 20:34:46', 3);
INSERT INTO `data` VALUES (14056, 'b***8', 5, '外观材质：外观设计漂亮，美观大方，手感很好，屏幕特别大，看着舒服，色彩饱和度超赞！\n屏幕效果：大屏幕，视觉效果不错。\n运行速度：运行速度非常快。\n轻薄程度：轻薄好用，外出用没问题！轻便！\n其他特色：京东送货很快，次日达，产品质量过硬，苹果平板电脑就从京东上购买绝对信得过。强烈推荐！', '银色', '2022-07-22 16:04:34', 8);
INSERT INTO `data` VALUES (14057, 'j***8', 5, '不错，好用，很薄，运行速度快，很流畅，用着很舒服，京东送货很快，第二天就到了，质量很好，买的教育版，很划算。\n外观材质：轻薄，摸着舒服', '银色', '2023-02-25 15:09:53', 7);
INSERT INTO `data` VALUES (14058, 'j***t', 5, '外观材质：外观是最喜欢的黑 从7到ipad\n屏幕效果：看着很温和 不刺眼\n运行速度：运行很快 永远相信苹果的运行魅力\n轻薄程度：很薄很薄 轻的不敢想象\n其他特色：为了不加班 买了这一台刚好让自己能工作用上的小本本 从此解放了自己 \n 很相信苹果 ipad也是魅力无限', '深空灰色', '2023-02-12 10:05:12', 7);
INSERT INTO `data` VALUES (14059, 't***伟', 5, '不错不错，很好用，目前来说很顺畅，用起来很舒服，打游戏很流畅，拍照效果很清晰??\n外观材质：很好看 非常喜欢这种颜色\n屏幕效果：看电影就用他，非常棒的视觉效果\n运行速度：很快，很快\n轻薄程度：可以随身携带，王者荣耀，玩吃鸡必备\n其他特色：很好我很满意', '深空灰色', '2022-12-14 18:30:33', 5);
INSERT INTO `data` VALUES (14060, '睿***想', 5, '2021款的iPad，10.2寸虽然说比不上2022款的和pro版的，这款入门级的已经很好喽！上网课  追剧够用了&hellip;&hellip;256G的内存绰绰有余了   经典款的设计元素！非常棒哦！销量第一的平板电脑！大尺寸！\n外观材质：经典之作\n屏幕效果：还可以的\n运行速度：iOS13芯片没问题的了\n轻薄程度：厚度可以接受', '深空灰色', '2022-11-16 21:42:12', 5);
INSERT INTO `data` VALUES (14061, '鹿***霜', 5, '真的21版本的做的好高级，之前买过20版本的，也是银色，但是21版本的银色更高级，是黑色的，就很好看，爱死了，256g追剧下载剧，好爽，最近在看小点燃，就很不错哦', '银色', '2022-11-25 01:17:22', 9);
INSERT INTO `data` VALUES (14062, '我***读', 5, '外观材质：外观材质：很轻盈，很薄\n屏幕效果：屏幕效果：平时用来看电视的，足够了\n运行速度：运行速度：很快，毕竟是新机子\n轻薄程度：很轻薄\n其他特色：苹果教育优惠买的，很划算，就是不能配二代笔，可惜', '银色', '2022-10-17 23:43:03', 9);
INSERT INTO `data` VALUES (14063, 'z***2', 5, '很好用啊，买回来上网课的，容量很不错，非常高清，运行速度挺快的，很轻薄，果然名不虚传，看视频和看书都挺不错的，符合我对整个iPad的预期。', '银色', '2022-11-14 21:03:29', 6);
INSERT INTO `data` VALUES (14064, 'u***z', 5, '产品很精致，之前用的iPad4用了快10年，确实卡了一些，现如今还是换iPad，用最新的iPad9(2021款)。重量轻盈，机身浅薄，很舒适。运行速度嘎嘎快，屏幕巨清晰。', '深空灰色', '2022-12-24 14:48:05', 8);
INSERT INTO `data` VALUES (14065, 'j***d', 5, '外观材质：外观深灰色真的很好看，我真的特别喜欢这个颜色，外观没有一丝丝瑕疵，真的很好看，屏幕也非常的不错，真心推荐大家购买??????????????????????????????????????????\n屏幕效果：我觉得我买的屏幕效果真的很不错，尤其是看的时候我真的很喜欢，很清晰，很好看，真心推荐大家购买??????????????????????????????????????????????????\n运行速度：运行速度很好，很快，我真的做什么的时候都很快，我很喜欢???????????????????????????????????????????????\n轻薄程度：对于我来说真的很轻薄，对于这个厚度我真的很喜欢，如果大家预算不够，真的真心推荐，而且真的很便宜???????????????????????', '深空灰色', '2022-12-02 22:23:50', 5);
INSERT INTO `data` VALUES (14066, '期***_', 5, '没失望，一如即往的顺畅好用！包装完好，一层层打开，机器没有磕碰，按顺序开机操作，登陆账号，使用正常，无线和热点都不卡，操作感也很棒，反应灵敏！喜欢！推荐！', '银色', '2022-12-15 06:10:21', 8);
INSERT INTO `data` VALUES (14067, '灵***者', 5, '选来选去还是选择了iPad，选择一定要选择256，省得以后有焦虑症，给学生们绝对是一款利器，简洁大方，内存大系统流畅，屏幕亮丽清晰，使用起来非常方便。旗舰店上客服也会好，物流也很快', '深空灰色', '2022-12-24 10:21:32', 5);
INSERT INTO `data` VALUES (14068, '月***2', 5, '非常不错?，双十一促销抢购到的便宜了不少。外观设计精致使用起来非常舒适，系统识别流畅没有卡顿，就是没货采购等了好几天，总体来看非常满意。', '深空灰色', '2022-10-30 14:58:12', 6);
INSERT INTO `data` VALUES (14069, 'M***2', 5, '物流很快，第一天晚上下单，第二天下午就收到了。拿到手以后激活，非常的轻薄，颜色也非常的低调显大气。买来考研用的，64G足够学生党备考用了，使用流畅，而且学生价有优惠，很满意，值得入手哦！', '深空灰色', '2022-11-09 12:32:36', 5);
INSERT INTO `data` VALUES (14070, '马***绿', 5, 'pad还得买苹果 之前那个用了十年 内存太小了 换个新的继续用 经典造型 经典款式 经典颜色\n外观材质：简单大方\n屏幕效果：清晰画质清楚\n运行速度：流畅 \n轻薄程度：轻薄', '银色', '2022-11-02 11:03:49', 3);
INSERT INTO `data` VALUES (14071, '雏***萋', 5, '外观材质：深灰色很洋气\n\n屏幕效果：效果很好\n运行速度：速度巨快\n轻薄程度：很薄\n其他特色：ipad从第一代买到现在，第一代那会是自己玩，ipad性能好，陪伴自己读书刷剧。现在买来给孩子用，孩子打卡学习，还是选择苹果，其他牌子不考虑', '银色', '2022-11-10 20:05:00', 3);
INSERT INTO `data` VALUES (14072, 'u***8', 5, '方便快捷性能好质量好完美无瑕\n外观材质：好\n屏幕效果：好\n运行速度：好\n轻薄程度：好\n其他特色：好\n分辨率高高端大气上档次 性能测试完美无瑕物流快你值得拥有外观设计漂亮分辨率高端大气上档次 物流快准狠好', '深空灰色', '2023-01-05 12:55:21', 4);
INSERT INTO `data` VALUES (14073, 'l***3', 5, '外观材质：外观好看，时尚大气\n屏幕效果：屏幕分辨率高，效果很好，比例协调\n运行速度：运行流畅不卡顿，速度快，反应灵敏\n轻薄程度：轻巧方便携带\n其他特色：刷剧方便，充电速度快，颜色鲜明', '深空灰色', '2023-01-11 23:17:05', 6);
INSERT INTO `data` VALUES (14074, 'j***x', 3, '像素很模糊，其它还可以?', '深空灰色', '2021-12-09 22:47:56', 4);
INSERT INTO `data` VALUES (14075, 'J***-', 5, '拍了开箱视频，挺不错的，序列号也对了，没有激活，然后给它激活，挺好的，挺大的，买来刷课学习用，我一个女生也觉得这个灰色好看极了，很满意', '深空灰色', '2022-11-12 13:57:17', 8);
INSERT INTO `data` VALUES (14076, '大***娃', 5, '物流挺快的，外观很好看\n外观材质：很轻薄，手感很好\n屏幕效果：感觉分辨率不是特别高\n运行速度：速度挺快的，不卡顿\n轻薄程度：很轻，手感很舒服', '深空灰色', '2023-01-03 09:09:44', 7);
INSERT INTO `data` VALUES (14077, 'j***m', 5, '外观材质：外观完整，非常精美\n屏幕效果：触屏效果特别好，非常灵敏\n运行速度：数度非常流畅\n轻薄程度：机身很饱，拿在手里很舒服\n其他特色：其他特色：用了一段时间质量特别好，下次还会来买', '深空灰色', '2022-11-09 13:21:07', 8);
INSERT INTO `data` VALUES (14078, '兔***-', 5, '外观材质：深灰色简约大气，非常不错\n屏幕效果：效果很不错，屏幕很清晰，音效也特别棒\n运行速度：苹果搭载的系统运行速度都比较快，非常好\n轻薄程度：非常轻薄，就是敲击屏幕的声音比较大\n其他特色：趁着双11有活动入手的，发货时间巨慢，但好歹结果是完美的', '深空灰色', '2022-12-24 10:28:37', 3);
INSERT INTO `data` VALUES (14079, '马***涯', 5, '外观材质：看起来很不错，拿起来更有手感，比我家之前的mini2大了很多，就像是笔记本电脑了。\n运行速度：很快，毕竟是新款的，比我的iPhone11快很多哦！\n屏幕效果：屏幕非常清晰，小孩看动画玩游戏效果不错！之前买的是16G的，真的是不够用阿，这次一步到位256G，希望家人快乐每一天！', '深空灰色', '2022-01-13 19:55:40', 8);
INSERT INTO `data` VALUES (14080, 'k***9', 5, '外观材质：铝合金金属机身，轻薄\n屏幕效果：屏幕分辨率不错，非全合反光严重\n运行速度：看电影小游戏沒说\n其他特色：运行快，耐用', '深空灰色', '2022-12-05 15:38:03', 3);
INSERT INTO `data` VALUES (14081, 'c***l', 5, '外观材质：l铝镁合金材质，手感超级棒！\n屏幕效果：LCD材质，分辨率为1620*2160，500nits视网膜显示屏，原彩显示，满足学习要求了！\n运行速度：A13芯片足够满足日常需求，运行流畅！app响应很快！\n轻薄程度：铝镁合金材质确保iPad的重量！487g满足便携要求！\n其他特色：配合第一代Apple pencil使用，很方便！', '银色', '2022-08-04 09:14:19', 3);
INSERT INTO `data` VALUES (14082, 'j***a', 5, '外观材质：有银色和深灰色，深灰色更好看。背面金属手感，搭配苹果logo，正面4:3屏幕，黑边框，喜欢home键，\n屏幕效果：主要用来学英语、查文献，工作沟通，大屏比手机太香啦，编辑表格便捷性也完胜手机。屏幕支持原彩显示，色温很友好，默认息屏等待时长约15s，屏幕非全贴合，作为工作学习用不影响观感。\n运行速度：第一次购买苹果产品，之前已买了matepad11，处理器参数官网和各种测评可以作参考，就实际使用对比，ipad9和matepad11普通操作顺畅度都很高，2款机型小工具栏均易呼出，非常实用，matepad11在进行登录操作时肉眼可见比ipad9用时短。\n轻薄程度：机身7.5mm，约480g，可接受\n其他特色：苹果特色之一是ios生态，比如notability这样的笔记软件目前只适用ios，特色之二是siri非常高效实用，生态构建要时间，siri这样的语音助手，小度从观感上非常类似，但matepad11几乎没有（小艺忽略不计）。希望苹果和华为都越做越好。\n总之在3000元预算区间，除个人偏好，看视频听音乐，推荐matepad11，工作学习推荐ipad9。', '深空灰色', '2023-01-31 12:42:14', 6);
INSERT INTO `data` VALUES (14083, '守***笑', 5, '外观材质：非常不错，不管颜色还是材质\n屏幕效果：画面清晰 还原度高\n运行速度：iOS系统没得说 不卡 运行快速 反应灵敏\n轻薄程度：轻薄 重量轻\n疫情期间 买给家里的小朋友上网课使用的，?', '深空灰色', '2022-11-14 14:37:12', 2);
INSERT INTO `data` VALUES (14084, 'j***O', 5, '外观材质：非常好，金属材质，美观大气上档次！\n屏幕效果：大屏看着就是舒服！\n运行速度：那是相当可以！\n轻薄程度：比较轻薄！', '银色', '2022-07-23 19:31:44', 4);
INSERT INTO `data` VALUES (14085, 'g***8', 5, '外观材质：外观很漂亮，颜值高，很喜欢，有档次，质量很好，做工精细，设计合理\n屏幕效果：屏幕看着很舒服，显示效果也不错。\n运行速度：随便装了几个小程序，稍微试了一下，反应很不错\n轻薄程度：不厚，也不薄，拿在手上有点份量\n其他特色：感觉有点小贵，虽然质量还不错', '银色', '2022-12-12 16:08:15', 6);
INSERT INTO `data` VALUES (14086, 'h***o', 5, '做工很好，非常丝滑。检查过了，屏幕内，摄像头内干干净净，没有一点瑕疵。边框也是严丝合缝，还是home键用着踏实。快递包装就更不用说了，厚厚的泡沫，很稳。京东物流也很给力！总体感觉很完美，幅图几张，希望对想要购买的您有所帮助。', '深空灰色', '2022-11-02 15:49:17', 4);
INSERT INTO `data` VALUES (14087, 'j***f', 5, '买来学习的 够用 每次都在京东买电子产品 很好\n外观材质：有质感\n屏幕效果：大屏幕显示好\n运行速度：运行正常\n轻薄程度：很薄 方便携带\n其他特色：价格合适 教育优惠便宜一百', '银色', '2022-11-02 15:01:30', 3);
INSERT INTO `data` VALUES (14088, '小***巫', 5, '给儿子作笔记用的。外观设计漂亮，尺寸大小合适，包装仔细完整，宝贝手感不错，感觉很好，发货速度快，服务态度一流，给力！5星好评！\n\n\n?非常漂亮，做工精细，颜值担当，不愧为水果。非常方便，?喜欢的朋友可以下手！', '深空灰色', '2022-12-21 16:27:54', 8);
INSERT INTO `data` VALUES (14089, 'y***y', 5, '收到货超级棒！给孩子上网课学习用。外观漂亮，屏幕清晰度高，速度也快，超薄拿着轻松不累，好评?', '深空灰色', '2022-08-13 18:58:54', 5);
INSERT INTO `data` VALUES (14090, '小***东', 5, '收到货了迫不及待地拆开试试，发现做工很好，系统也很流畅，拍照也很清晰，非常不错，用来上网课画质也很好，还支持手写功能，功能非常强大，物流也很快，快递小哥服务态度也很好，提前打电话，等我下去拿，非常满意！', '深空灰色', '2023-02-10 10:47:00', 7);
INSERT INTO `data` VALUES (14091, '无***书', 5, '平板电脑收到货了，外观漂亮，之前买过一代mini 银色的，感觉还是灰色的好看。屏幕狠细腻，A13芯片，处理速度也很好，作为入门级ipad 学习娱乐正好够用。关键是价格便宜啊，就比八代贵了几百块钱。九代产能原因，一直没货，还好活动前预定了，总体来说，很满，深灰色平板外观材质很好，轻便易携带，屏幕分辨率清晰度较高，机身运行速度很快，性价比较高，适宜网课与追剧需求，信懒京东，平板电脑很好用，运行流畅不卡，画面高清音质好，电池续航给力。轻薄程度：确实很轻薄 手感舒适，很好，外观大方好看，有质感，运行速度快，非常流畅,比一些其他牌子的平板更好用，设计的也很美观。页面美观，滑动流畅，非常开心，顺便夸-夸我的保护套，我的保护套也很好看哈哈，买平板2021没错的，性价比非常高，比别的平板无论是配置还是设计都更好。很好用，不错，运行非常流畅，工作生活都可以方便使用从外观看很美 ,材质做工都不错 感觉买值了,还有物流超级快,点赞!质量没得说,跟专卖店一样,特别特别喜欢,而且价格优惠。', '深空灰色', '2022-01-06 11:14:28', 8);
INSERT INTO `data` VALUES (14092, 'j***z', 5, '还好.最低配iPad，照相很不清晰，和现在手机都没法比，也不用苹果手机，没有互联。就图它耐用，音质也一般。给孩子识字，学习吧！要能推荐育儿的APP就更好了。', '深空灰色', '2023-01-28 10:20:44', 6);
INSERT INTO `data` VALUES (14093, '小***渣', 5, '很好啊 用起来挺快挺流畅的 给小朋友看看动画片 搞搞学习UI啊你不错的！\n外观材质：漂亮！\n屏幕效果：很好?\n运行速度：很快～\n轻薄程度：很轻薄\n其他特色：没有膜 要自己买一个 万一磕坏了还是不好', '银色', '2022-12-23 16:06:48', 2);
INSERT INTO `data` VALUES (14094, 'j***5', 5, '外观材质：外观非常大气，手感舒适。\n屏幕效果：很顺畅，字体大，宝贝看非常合适。\n运行速度：运行流畅。\n轻薄程度：闺女四周岁拿着也很稳，她的iPad。\n其他特色：大屏幕看着就是爽！', '银色', '2023-03-15 20:14:06', 2);
INSERT INTO `data` VALUES (14095, '如***呢', 5, '外观材质：非常不错 但是新机有点味道 不过可以接受\n屏幕效果：很高清 看着很舒服\n运行速度：非常丝滑 比肩120hz了 日常够用\n轻薄程度：很轻\n其他特色：可以和苹果手机关键 很不错', '银色', '2022-08-11 13:40:38', 7);
INSERT INTO `data` VALUES (14096, 'j***v', 3, '净送一些没吊用的赠品', '深空灰色', '2021-12-25 20:35:31', 6);
INSERT INTO `data` VALUES (14097, 'j***l', 5, '外观材质：外观设置很好看 手感很好? 屏幕特别大 很顺畅 最后一代经典型入门的iPad \n性能相当于iPhone11 不过iPad体积更大  散热比双层主板的iPhone11要好', '银色', '2023-02-05 14:37:04', 4);
INSERT INTO `data` VALUES (14098, '我***谁', 5, '外观材质：非常好看的\n屏幕效果：感觉很不错\n运行速度：各个软件运行很快\n轻薄程度：很轻薄\n其他特色：用了好几天过来评价的，真的是学习神器，刷题也方便，专门买了学习的，希望不是爱奇艺', '深空灰色', '2022-07-11 13:56:34', 7);
INSERT INTO `data` VALUES (14099, 'J***6', 5, '电子产品早买早享受吧，一直犹豫要不要买，这次双十一就下单买了ipad9，64g在娱乐学习够了，物流很快48小时就发货了，第二天早上就到了超级快，拿到手上手感很好，买了最基础款、不卡顿不发烫，送的配件一套充电器性价比很高！\n苹果系统是真的好用又顺滑，在ipad大屏发挥优势，搭配电容笔更好用了，屏幕显示效果清晰，色彩艳丽。机身轻薄手感好，操作很流畅性能很强！\n特别是10.2英寸的大屏幕，日常看电影、玩游戏、办公都能带来不错的体验，关键是它的重量没有想象中那么重，长时间把玩感觉不到累，方便携带！', '深空灰色', '2022-11-17 23:33:48', 3);
INSERT INTO `data` VALUES (14100, 'j***y', 5, '外观材质：外观大气，看着高级感满满，拿着大小刚刚好，正适合办公上网课\n屏幕效果：屏幕显示效果清晰，色彩艳丽，显示细腻，音效好，双扬声器外放效果一流\n运行速度：苹果系统运行流畅，A13处理器放到今天依然强悍', '银色', '2022-10-30 11:30:14', 6);
INSERT INTO `data` VALUES (14101, '板***2', 5, '外观材质：外观和原先的型号变化不大，很有质感，\n屏幕效果：显示效果很好，看久不累眼，色彩丰富。\n运行速度：A13处理器配合iOS系统很顺畅，体验感很好。\n轻薄程度：手感较好，拿着不累。\n其他特色：入门级iPad，性价比很高，用来追剧无敌。', '深空灰色', '2022-11-03 18:15:11', 2);
INSERT INTO `data` VALUES (14102, 'j***2', 5, '好好好，太好了，晚上10.30下单第二天下午5.50就到我手上了，立马安排上壳，太爱了\n轻薄程度：好\n运行速度：可以\n屏幕效果：好\n外观材质：好', '深空灰色', '2022-08-08 18:20:04', 7);
INSERT INTO `data` VALUES (14103, 'L***好', 5, '近十年来，从iPad 1代到4代，4代用了很久，确实很强大，后来给我弟小孩看儿童剧了。这款256G对于要上网课，看看视频学习的内存是足够的，深空灰超级好看，超级高级，爱了爱了。收到以后就立刻查了序列号全绿，超级开心。已经使用几天了，就是看看视频，还有34%的，还是不费电的。设置了一些提醒自己学习的提醒，就是左划编辑中可以自己添加，还下载了很多软件看网课和其他方面的学习，生产力搞起来。', '深空灰色', '2022-11-03 22:27:22', 2);
INSERT INTO `data` VALUES (14104, '盒***儿', 5, '外观材质：深空灰 颜色高级低调大气越看越好看\n屏幕效果：清晰明亮 高清没有划痕\n运行速度：反应速度快\n轻薄程度：中等 薄 拿着刚刚合适 带上壳有一点重\n其他特色：配了透明壳  yyds  还DIY了奶牛贴纸 超级好看喜欢?', '深空灰色', '2022-10-28 15:32:20', 5);
INSERT INTO `data` VALUES (14105, 'l***d', 5, '外观材质：一样的轻薄，手感很好。\n屏幕效果：效果很好，颜色正常。\n运行速度：苹果的平板电脑一直都很耐用，七八年前的目前都还能使用。\n轻薄程度：很轻薄，需要加外壳。\n其他特色：平板电脑还是苹果的好。', '深空灰色', '2022-11-07 15:53:57', 5);
INSERT INTO `data` VALUES (14106, '寻***侠', 5, '买的第二台苹果平板电脑了，这个2021版也挺好，性价比高，A13处理器性能也很强，双十一真实惠，到手3千一百多，轻薄好用，不像安卓多广告，多后台程序安全性能差，苹果就是比安卓强大。', '深空灰色', '2022-11-07 02:03:18', 9);
INSERT INTO `data` VALUES (14107, '曉***雯', 5, '外观材质：质量很好，相当可以\n屏幕效果：很清楚\n运行速度：挺快的，没某卡顿，一直想支持国货，可是国货越来越贵\n轻薄程度：很轻很薄\n其他特色：运行内存小了点，买大的又死贵所以还是满足日常需求就行', '深空灰色', '2022-11-13 07:43:09', 2);
INSERT INTO `data` VALUES (14108, '里***卡', 5, '很好，终于有一个苹果????了，很好。看电影，追剧都不错。很轻，拿着很舒服。速度也很快。人性设计。大师级别。不错不错不错。', '深空灰色', '2023-01-14 14:27:43', 7);
INSERT INTO `data` VALUES (14109, '我***啊', 5, '外观材质：塑料材质，不过也很不错了。\n屏幕效果：很清晰，苹果的1080跟1.5k的屏幕相比差不多了。\n运行速度：很不错，用来看看电视，记记笔记，下下棋错错有余。\n轻薄程度：一般，我用来保护套无所谓了\n其他特色：苹果系统值得一用', '深空灰色', '2022-12-26 14:39:34', 1);
INSERT INTO `data` VALUES (14110, 'p***d', 5, '七年前买的一部ipad air 2，一直给小孩上课呀用，七年来一直很丝滑，电池也很耐打，唯一不太好的就是存储太小，只有16G，随着小孩网课内容越来越多，16g内存已经满足不了上课的需要了，因此京东下单了ipad 9,居然还能以旧换新，估算抵扣330，实际现场抵扣了280，也算满意，苹果电子产品真心不错，保值率杠杠的。', '深空灰色', '2023-02-08 13:38:47', 9);
INSERT INTO `data` VALUES (14111, 'w***z', 5, '包装非常精致，送货速度非常快，配送员服务非常好。性价比太高了，虽然是a13加3G运存，看起来有点落伍了，但是配上ios，一点都不卡，运行速度非常快。大屏大电池续航非常优秀，很护眼，用来看识字软件很合适，很久才充一次电。两千多块，竟然还送充电头，这可是149元一个充电头。', '深空灰色', '2022-11-23 21:53:40', 2);
INSERT INTO `data` VALUES (14112, '千***n', 5, '外观材质：很好看的银色，很光滑\n运行速度：运行速度很快，流畅\n屏幕效果：屏幕触感灵敏', '银色', '2022-08-29 20:55:23', 4);
INSERT INTO `data` VALUES (14113, 'j***7', 5, '外观材质：结实耐用\n屏幕效果：大屏幕，视觉效果更佳\n\n运行速度：网页打开速度，app使用顺滑，不卡顿\n\n轻薄程度：便于携带\n\n其他特色：像素能满足日常需求，适合上网课，当做学习机用，功能强大', '银色', '2022-07-04 10:56:24', 1);
INSERT INTO `data` VALUES (14114, '-***-', 5, '外观材质：金属外壳，手感特别棒\n屏幕效果：屏幕显示还是比较细腻的\n运行速度：运行速度非常非常快，没有一点点卡顿\n轻薄程度：非常轻薄的机身，拿在手里也不是太重，加个保护壳应该更舒服', '深空灰色', '2022-11-12 22:01:57', 6);
INSERT INTO `data` VALUES (14115, 'j***t', 5, '外观材质：很好看 手感好 个人很喜欢\n屏幕效果：不错\n运行速度：很流畅 纠结内存买多大的 最后决定买了256g的足够用了\n轻薄程度：很轻薄', '银色', '2023-02-15 10:42:01', 5);
INSERT INTO `data` VALUES (14116, '张***霞', 5, '闺女初三了，今年后半年几次封控在家，买来给闺女上网课用的。外观设计风格独特，材质摸着很舒服，屏幕也特别清晰，运行速度也很顺畅，这次买的大容量256GB', '银色', '2023-01-06 20:23:13', 3);
INSERT INTO `data` VALUES (14117, 'V***t', 3, '玩原神如果开最高，烫手', '深空灰色', '2021-09-29 22:46:05', 7);
INSERT INTO `data` VALUES (14118, '安***乐', 5, '哈哈哈 有活动买的 本来不想买的 针不戳 挺香的\n运行速度：下载东西非常快 嗖嗖的 比手机快多了 就几秒下载完一个app真的好哇\n轻薄程度：又薄 又好看\n其他特色：追剧 啥的 真香\n屏幕效果：超清', '深空灰色', '2022-11-03 10:33:31', 1);
INSERT INTO `data` VALUES (14119, 'j***s', 5, '外观材质：时尚美观手感好，灰色超级好看\n运行速度：很流畅\n轻薄程度：轻薄\n其他特色：质感很好\n对比了很久终于下单了，收到货特地去官网查了序列号和保修日期，都是一样的，深灰色真的很高级，赞', '深空灰色', '2022-07-21 19:35:29', 3);
INSERT INTO `data` VALUES (14120, 'j***w', 5, '比较喜欢苹果平板电脑，从min2到air2，再到现在的这款九代平板电脑，以后如果有条件还会再入手。\n外观材质：优良品质。\n屏幕效果：靓丽细腻。\n运行速度：很快很快。\n轻薄程度：比较轻薄。', '深空灰色', '2023-01-17 23:00:19', 6);
INSERT INTO `data` VALUES (14121, '不***年', 5, '10号拍，20号才收到，第一次买ipad,没想到这么紧俏。孩子考研用，很是喜欢。但愿明年考研成功！\n屏幕效果：好\n运行速度：快\n轻薄程度：适中', '深空灰色', '2021-11-23 23:36:24', 7);
INSERT INTO `data` VALUES (14122, '百***咏', 5, '外观材质：铝合金的，看着轻薄但是很结实\n\n屏幕效果：非常清晰，打游戏画质很棒呢\n运行速度：流畅，吃鸡也很OK哦，电池续航能力也很棒，平时追剧打游戏完全没问题', '银色', '2022-07-01 17:30:25', 2);
INSERT INTO `data` VALUES (14123, 'j***u', 5, '外观材质：外观大方，设计简洁，材质采用优质面料！\n屏幕效果：屏幕颜色靓丽，清晰度很高，是我用过清晰度最高的。\n运行速度：运行速度非常快！从没有过卡过！\n非常智能的系统，已升级到最新版本！非常赞！', '深空灰色', '2022-11-26 20:51:53', 2);
INSERT INTO `data` VALUES (14124, '云***野', 5, '很喜欢的一款iPad 很轻薄 物流是十分的快 包装也不错 性能强劲 新的台前调度功能真好用 颜值也是很好 买了个好看的壳安装上了 哈哈哈哈 真的很爱 尺寸也很好 大小合适 泡面盖子作用强', '银色', '2022-11-17 19:45:07', 6);
INSERT INTO `data` VALUES (14125, 'j***c', 5, '外观材质：非常漂亮\n屏幕效果：屏幕非常清晰丝滑\n运行速度：非常快，毕竟是新的\n轻薄程度：比较薄非常顺手\n其他特色：刚刚使用，待后续追评', '深空灰色', '2022-12-28 08:57:36', 1);
INSERT INTO `data` VALUES (14126, '西***z', 5, '京东618购物节下单购买的，6月25日发货，隔天送到，物流速度很快。到了后，打开是新机，官配了充电器了充电线买个贴膜和壳子就可以用了。10.2的尺寸很不错，大的看着舒服。价格嘛，比平时便宜了百把块，多等了一礼拜。值得推荐。', '银色', '2022-06-30 23:22:34', 9);
INSERT INTO `data` VALUES (14127, '-***V', 5, '来的时候包装很好，相信京东正品，打开里面那个膜一点破损都没有，验机了也没有问题，屏幕也很大，考研预算不是很够的可以选择这款，买了256g的怕有时候存文件不够，总的来说，很不错?', '深空灰色', '2022-10-17 20:37:35', 3);
INSERT INTO `data` VALUES (14128, 'G***3', 5, '外观材质：外观深灰色的，很有质感，摸起来很有手感，看起来就高端大气\n运行速度：运行速度很快，一点我不卡顿，而且是正品保真，带一年保修\n轻薄程度：很轻薄，一点都不厚重，很方便携带', '深空灰色', '2023-01-12 15:51:42', 1);
INSERT INTO `data` VALUES (14129, '顺***9', 5, '为了追剧还有看***等娱乐，果断下单这款iPad，果然没有选错，平时追剧看看抖音微信快手足够用了，质量很好，运行速度快，买到手追的第一个剧是宫崎骏的动漫电影《魔女宅急便》现在看历年的春晚！非常好！超级开心！', '深空灰色', '2023-02-04 21:19:35', 4);
INSERT INTO `data` VALUES (14130, 'j***z', 5, '我是不到就入手的。方法图上说了。外观材质：外观设计漂亮，美观大方，手感很好，屏幕特别大，看着舒服，色彩饱和度超赞！\n屏幕效果：大屏幕，视觉效果不错。\n运行速度：运行速度非常快。\n轻薄程度：轻薄好用，外出用没问题！轻便！\n其他特色：京东送货很快，次日达，产品质量过硬，苹果平板电脑就从京东上购买绝对信得过。京东送货很快，第二天就到了，质量很好，很划算。\n外观材质：轻薄，摸着舒服', '深空灰色', '2023-03-16 15:58:25', 5);
INSERT INTO `data` VALUES (14131, 'j***e', 5, '外观材质：学生党iPad真的是首选，系统流畅度，容量都极具性价比，机身也不是很重。\n\n屏幕效果：iPad9是非全贴合屏，不过对于一般的看视频，记笔记是感觉不出来的。\n\n运行速度：运行速度是真香啊，连开十几个应用再打游戏也没有问题。\n其他特色：目前推荐学生党入手，对于学习完全够用。', '银色', '2023-03-11 10:51:17', 2);
INSERT INTO `data` VALUES (14132, '天***谭', 5, '外观材质：包装完好无损，做工精细\n屏幕效果：显示细腻自然\n运行速度：运行速度很快\n替换家里使用8年的ipad air！孩子上网课用，他觉得满意就可以了。。', '深空灰色', '2022-10-22 12:25:32', 9);
INSERT INTO `data` VALUES (14133, '晓***5', 5, '外观材质：光滑舒服，摸起来很轻薄。很适合带出去临时办公。\n屏幕效果：分辨率还不算很低，效果也不错。操作起来很方便。\n运行速度：还可以。买的内存256G的长期考虑下来还是大一点好。\n轻薄程度：挺轻的。', '深空灰色', '2022-08-22 14:07:52', 5);
INSERT INTO `data` VALUES (14134, '火***i', 5, '抢了一个小时终于抢到了 太爱了吧 第二天一大早就打电话喊我拿快递 快递也贼快 爱了爱了\n屏幕效果：超级清晰\n运行速度：很快 最爱苹果的系统 不卡\n轻薄程度：也很薄\n外观材质：外观简直太好看了吧\n其他特色：我只用来追追剧什么的 64g也够用\n爱了爱了', '银色', '2022-11-02 13:09:31', 6);
INSERT INTO `data` VALUES (14135, '孟***军', 5, '很好?很满意的一次购物，能够送一支手写笔就更好了，电容笔还要自己买，不错哦嘻嘻，喜欢?', '银色', '2023-02-17 08:11:51', 9);
INSERT INTO `data` VALUES (14136, '公***生', 5, '家里老款的ipad的用不了，这不随着疫情的放开在家改成上网课随时都有可能，为了不影响小孩学习，看到双十一京东ipad9有活动就下单购买，购买时也是费了好大一股劲，最后还是在小程序端买到了（且能用京豆），下单后物流挺快第三天送到的，检查包装密封完整，拆包开机激活（非二手机）一切顺利，充电后使用很流畅，容量不大主要是给小孩上网课用，整体还是不错', '银色', '2023-01-01 23:20:08', 7);
INSERT INTO `data` VALUES (14137, 'T***萧', 5, '外观材质：手感很不错，喜欢这个金属手感呀\n屏幕效果：屏幕质量很好，画面很清晰，没有卡顿过。\n运行速度：很快很快的，就是大家都知道的那种。\n轻薄程度：pad很轻薄吧，不重，玩游戏还可以，吃鸡人像很大，容易瞄准。\n其他特色：官方正品。好评', '银色', '2023-03-18 11:46:37', 4);
INSERT INTO `data` VALUES (14138, 'j***Z', 5, '外观很漂亮，轻薄，屏幕，触感，流畅度都不错，小孩拿来看动画片很适合，日常也可以拿来刷剧，浏览新闻，或者工作都行。整体很满意。', '深空灰色', '2022-11-30 05:10:04', 6);
INSERT INTO `data` VALUES (14139, '天***i', 5, '京东商城apple 自营旗舰店好几次购买产品了，官方旗舰店正品保证质量保证，这款平板电脑21款性价比超级无敌高，256G内存足足够用了，还配备新款快充头非常感谢?，操作流畅自如，处理器强大无敌，真的觉得很喜欢这款产品，???！再配上手写笔真的是绝配的存在，还会继续光顾支持京东苹果自营旗舰店的，全五星好评了??????????！超级无敌棒棒哒??????', '深空灰色', '2022-07-19 20:06:35', 5);
INSERT INTO `data` VALUES (14140, 'j***、', 5, '平板很好，也查过了，买了两个，另一个在姥姥\n家。，反应很快，比上一个大，薄，发货也很快。\n电池比较耐用。，手感很好，没有瑕疵，感觉很划\n算，百亿补贴，比较放心。卖家人也不错。', '深空灰色', '2022-12-19 19:36:40', 8);
INSERT INTO `data` VALUES (14141, 'L***l', 5, '外观材质：买的灰色的，颜色高级，很喜欢。整体是10.2的屏幕，屏幕大，比之前的版本好。\n屏幕效果：之前膜没到的时候裸机玩的，很沾指纹\n运行速度：速度快，反映快，256G内存完全没压力\n轻薄程度：我觉得挺薄的，甚至担心容易弯曲，所以就买了一个厚厚的粉色的壳子，做一下必要的保护\n其他特色：追剧确实比较爽', '深空灰色', '2022-11-12 12:32:21', 1);
INSERT INTO `data` VALUES (14142, 'h***5', 5, '刚刚用的两天，画质还是比较细腻的，所谓的全贴合屏幕和非全贴合屏幕我个人觉得毕竟价格差很多，单单上上网课刷刷视频什么的，这款完全够用了，苹果ipad质量还是有口皆碑的，直接上大内存就行，一次到位，现在各种图片App占用内存挺大，还是大内存的好些', '深空灰色', '2023-01-05 12:25:40', 2);
INSERT INTO `data` VALUES (14143, 'j***v', 5, '不错 已经使用好多天了 现在写下感受 整体感觉不错 画质清晰 手感舒服 屏幕挺大的 触感也挺灵敏的 整体机身轻薄 运行流畅不卡顿 很喜欢', '银色', '2023-01-09 11:29:51', 1);
INSERT INTO `data` VALUES (14144, '小***咯', 5, '东西收到啦，真的很满意，真的是超级超级好的卖家，解答的十分详细，关键是东西还不错的呀，包装很仔细，快递也很快，值得信赖的商家，品牌！给力，继续买买买起来！真的给力', '银色', '2022-12-13 11:52:53', 6);
INSERT INTO `data` VALUES (14145, '小***东', 5, '收到货了平板非常不错，做工很精致好物流也很快，手感非常棒，非常喜欢，快递小哥服务也很热情，提前打电话，等我下去拿必须好评，下次有需要还会再来，系统体验也很流畅。', '银色', '2023-02-10 10:45:13', 7);
INSERT INTO `data` VALUES (14146, 'j***9', 5, '外观材质：很棒非常好手感很好\n屏幕效果：苹果效果没的说，非常的棒，给人一种特别惊艳的感觉！\n运行速度：非常快，非常流畅，没的说\n轻薄程度：只能说刚刚好，非常方便，非常好啊', '深空灰色', '2022-11-12 18:40:22', 2);
INSERT INTO `data` VALUES (14147, '鱼***4', 5, '疫情当下，孩子开不了学，全部上网课，赶紧买个设备，这个平板尺寸挺好的，很薄。因为有库存，配送也快，第二天就送到了，周一上课就可以用啦。', '银色', '2022-09-03 13:48:09', 4);
INSERT INTO `data` VALUES (14148, 'T***_', 5, '千呼万唤的iPad9代，买之前也做了功课，主要是给孩子上网课，这款性价比高，双十一前几天买的，价格合适，但是发回来屏幕里有异物，申请换货了，历经将近一个月才到手，万幸的是这次完美没什么毛病，现在又放开了，要终结网课时代了，未来就只有追剧和孩子玩小游戏了，机器性能感觉非常好，比学习机强多了，某多多的盲盒，亿色保护套9.9非常贴合', '深空灰色', '2022-12-29 11:27:32', 7);
INSERT INTO `data` VALUES (14149, 'h***张', 5, '外观材质：符合我的审美观，喜欢\n屏幕效果：虽然是非全贴合屏但依然好用，显示细腻，适合\n运行速度：ios好用，无可厚非的\n轻薄程度：我并不在意，刚刚好\n其他特色：用笔很喜欢，画图好好用。和iphone搭配更好', '银色', '2021-12-23 22:24:21', 6);
INSERT INTO `data` VALUES (14150, '甘***姐', 5, '不错，孩子很喜欢，屏幕很大，买来孩子学习，屏幕大的不容易伤眼睛，手机太小了，所以就选择了一个平板给他们学习。，内存容量很大，外观很好，', '银色', '2023-02-10 21:28:42', 3);
INSERT INTO `data` VALUES (14151, 'j***f', 5, '买的教育优惠版，给小孩做编程，下围棋用的，利用率不高，不用买太好的。之前一个平板已经用了10年了还是很好用，只是被摔坏了屏幕，继续买苹果的，比较耐用。这款薄点，边框小点，反应很快，确实不错。特意买了一个保护性非常好的平板壳，不能再摔坏了', '深空灰色', '2022-08-03 19:47:11', 6);
INSERT INTO `data` VALUES (14152, '韩***家', 5, '外观材质：星空灰铝合金金属\n屏幕效果：非全贴合日常观影凑合\n运行速度：苹果芯片加持不会太差\n轻薄程度：手握持较为满意\n其他特色：苹果自身工业设计美学还是很认可的，2022性价比太低，2021凑合用', '深空灰色', '2022-12-21 14:59:18', 5);
INSERT INTO `data` VALUES (14153, '5***y', 5, '性价比最高的一款苹果平板，屏幕色彩饱和度非常好，操作很简便，系统十分流畅，日常生活使用足够了。就是有些App不兼容，可惜了。', '深空灰色', '2022-11-11 20:59:52', 4);
INSERT INTO `data` VALUES (14154, 'j***a', 5, '外观材质：很好。隔天就到了。京东的派送员很贴心。\n屏幕效果：很好。没发现有划痕。平板保护的很好。拆箱很有仪式感\n运行速度：这个价位还可以\n轻薄程度：女生用可以。大小的话不大不小。看电视方便。出门放水桶包里面。\n其他特色：内存的话平时看电视就够了。音质不会差。之前用的苹果。登录很方便', '银色', '2022-07-13 15:59:12', 6);
INSERT INTO `data` VALUES (14155, 'j***n', 5, '比我想象中好很多，手感不错，上网课 和刷题用的，充满电，仅仅用来听歌的话，可以听很久，还有很多功能不会用呢。', '深空灰色', '2022-12-04 13:18:04', 6);
INSERT INTO `data` VALUES (14156, '静***8', 5, '好用，不卡，快递没得说质量不错，屏幕大，主要孩子们上网课用，机身不算重，很轻薄，运行的速度也很快，就是像素不太好，别的没毛病，物美价廉，值得好评', '银色', '2022-11-11 23:08:48', 2);
INSERT INTO `data` VALUES (14157, '双***半', 5, 'apple ipad没什么好说的，看价位买呗。感觉这款9代性价比蛮高的。而且还是最后一款home键位的iPad，值得纪念。\n外观材质：一入既往的优秀\n屏幕效果：无懈可击\n运行速度：七分迅速，少三分，一分留给十代，一分留给air，一分留给pro。\n轻薄程度：尚可', '银色', '2023-02-04 16:35:47', 2);
INSERT INTO `data` VALUES (14158, 't***1', 5, '心心念念的苹果平板9代终于下手了，趁着有活动 真香啊！\n一直都在用苹果产品，算是忠实粉丝了 非常满意好用！！！\n轻薄程度：挺薄的 喜欢\n运行速度：非常快啊\n外观材质：经典好看', '深空灰色', '2022-10-30 13:34:59', 2);
INSERT INTO `data` VALUES (14159, '洁***a', 5, '外观材质：手感舒服\n\n屏幕效果：屏幕大方美观\n\n运行速度：很快，反应很灵敏\n轻薄程度：轻便\n其他特色：物流很快，没有因为是过年就慢', '银色', '2023-02-16 19:19:04', 3);
INSERT INTO `data` VALUES (14160, '我***凡', 5, '外观材质：亲肤磨砂手感，顺滑，一如既往的苹果?\n屏幕效果：视网膜屏，显示效果很棒\n运行速度：A13加持，很丝滑，不用担心\n轻薄程度：一般', '深空灰色', '2022-12-21 12:26:21', 5);
INSERT INTO `data` VALUES (14161, '-***-', 5, '平板没啥问题，这个也算是新款吧，性价比很高，用两三年没问题，系统很流畅，用来看剧学习完全无压力，带出去也方便，外观简单大气，很喜欢。', '银色', '2022-07-21 11:07:41', 2);
INSERT INTO `data` VALUES (14162, 'w***u', 5, '用了优惠券买的，价格很合适，性价比非常高。平板很好，屏幕很大，反应很快，画面清晰，我只是用来刷个剧或者***，完全够用的，而且电池很耐用，买来自带的电量隔了几天居然都没下多少。', '深空灰色', '2022-11-19 22:40:59', 6);
INSERT INTO `data` VALUES (14163, 'P***8', 5, '还可以，安全下车，拍了银色，银色也很好看啦，ipad挺轻的，就是我的壳好重!\n外观材质：质感很好\n屏幕效果：很清晰，眼睛很舒服\n运行速度：运行很快\n轻薄程度：适中，黄金手感', '银色', '2022-02-18 22:16:21', 4);
INSERT INTO `data` VALUES (14164, '河***景', 5, '外观材质：买的天空灰，颜值超高，真的很好看，以前喜欢买银色是东西，没想到灰的也非常好看，有种贵气感\n屏幕效果：屏幕10.2寸的，体验感很好，屏幕大看的舒服\n运行速度：速度也很快，不卡，流畅\n轻薄程度：拿在手里薄薄的', '深空灰色', '2023-02-07 09:32:03', 1);
INSERT INTO `data` VALUES (14165, '黄***强', 5, '一如既往的好用，256G又可以用好几年了，性价比非常高。小孩上网课，画画，玩游戏都OK。主要还是IOS系统还用。\n外观材质：10.2寸够用\n屏幕效果：显示细腻\n运行速度：快，很流畅', '深空灰色', '2023-01-08 13:44:08', 4);
INSERT INTO `data` VALUES (14166, '橘***柑', 5, '这个Apple  ipad主要是给孩子学习娱乐的，64内存够用了，哈哈，画质清晰，运行流畅，银色很漂亮哦，苹果平板电脑果然好，终于知道为什么大家伙都喜欢用苹果平板电脑了，还会继续支持，争当果粉\n外观材质：好\n屏幕效果：好\n运行速度：嗖嗖的\n轻薄程度：轻便\n其他特色：很好', '银色', '2022-11-02 00:24:26', 5);
INSERT INTO `data` VALUES (14167, '我***喆', 5, '外观精美，大小合适，字体清晰，运行速度很快，非常轻\n薄，颜色也好看，大人喜欢宝宝喜欢，功能不错，画面感\n很不错，学个英语，玩个游戏，喜欢很喜欢，屏幕清晰流\n畅。宝宝学习很方便，屏幕比老款太了不少，看视频很方\n便。菲常完美的一款iPad，这是我人生当中的第1个苹巢\n产品，非常的好用；屏幕啊，运行方面都特别的流畅，而\n且买的这支笔简直非常的好用，比安卓机都好用上万倍，\n真的是已经爱不释手了，他不管是游戏还是画画还是什么', '深空灰色', '2022-08-22 14:14:53', 4);
INSERT INTO `data` VALUES (14168, 'j***d', 5, '外观材质：不错\n屏幕效果：很好\n轻薄程度：很薄很轻便携\n其他特色：颜色也不错\n运行速度：运行速度挺快的\n上网卡追剧基本上可以', '深空灰色', '2023-01-19 09:26:08', 1);
INSERT INTO `data` VALUES (14169, '喝***晕', 5, '挺好的产品，一直信赖京东自营，拿到手后拆机检查一下都是好的，目前没发现其他，\n外观材质：这方便没有问题，\n运行速度：还可以，256内存下载了不少软件，运行棒棒的\n\n其他特色：快递也很给力', '银色', '2022-12-31 21:10:43', 5);
INSERT INTO `data` VALUES (14170, 'j***t', 5, '外观材质：金属质感，拿起来却很轻。\n屏幕效果：很清晰，屏幕很大。\n运行速度：很快，没有卡顿\n轻薄程度：很轻薄，比我朋友买的air5轻薄，重量要请。\n其他特色：侧边也可吸笔，感觉很方便。', '深空灰色', '2022-10-23 08:37:25', 4);
INSERT INTO `data` VALUES (14171, '修***哇', 5, '外观材质：iPad YYDS，平板电脑只有两种，一种是苹果，另一种是其他。外观高端大气上档次，简约时尚有气质。\n屏幕效果：屏幕效果更是不必赘述，视网膜级屏幕显示效果清晰多彩\n运行速度：这更是苹果一贯的擅长之处了，流畅无卡顿，纵享丝滑\n轻薄程度：随身携带犹如无物，非常轻便', '深空灰色', '2022-09-03 14:14:27', 5);
INSERT INTO `data` VALUES (14172, 'h***8', 5, '苹果ipad  9TH,性能好，屏幕大，触摸灵敏，电池耐用，是小孩在家上网课，大人娱乐之首选。打游戏也特别流畅，画面清晣。', '银色', '2022-11-06 17:57:39', 2);
INSERT INTO `data` VALUES (14173, 'j***3', 5, '很喜欢这个平板，性价比就不用说了，买来给宝宝看的，运行速度很快，对于我们来说足够用了主要是尺寸10.2出乎意外的大，因为没有去实体看具体尺寸，然后买之前去看了一眼，简直一眼咯就看中了，好大，大一点不累眼睛吧，对于不外出携带只在家学习看剧完全不觉得厚，俩岁孩子拿起来不错，屏幕效果特别棒，很满意的一次体验', '深空灰色', '2022-06-25 08:48:59', 2);
INSERT INTO `data` VALUES (14174, '研***猪', 5, '入门版的平板，很喜欢用平板看电视，屏幕大，而且很清晰，看着很舒服，也可以用来画画，日常使用刚刚好，不过内存小了点，尽量还是买大内存，这样可以储存更多的东西', '银色', '2022-06-12 22:44:52', 6);
INSERT INTO `data` VALUES (14175, 'L***默', 5, '外观材质：外观很好看，大气深灰色显得比较优雅，摸着磨砂质感，很优秀\n屏幕效果：屏幕反应快，home键灵活，手感好，速度快。\n运行速度：运行速度快，A13处理器，还是很不错的。电池续航好，充满一次电可以看一天电视剧。\n轻薄程度：比手机稍厚一点，10.2寸屏幕，看电视剧打游戏都很好。', '深空灰色', '2022-07-27 16:17:35', 4);
INSERT INTO `data` VALUES (14176, '小***哥', 5, '趁着双十一优惠，非常好用，京东自营还是靠得住的，售后也放心，很有保障，有机会还会升级\n外观材质：手感非常好\n屏幕效果：显示清晰\n运行速度：苹果系统没得说\n轻薄程度：基础款，够用了', '深空灰色', '2022-11-14 23:25:21', 5);
INSERT INTO `data` VALUES (14177, '浅***风', 5, '不错第二天就到了，人生第一台iPad，好看，深空灰很高级。学生党，买来考研考公，希望可以成为生产力，成功上岸。\n外观材质：外观很好\n轻薄程度：很轻薄，比我的华为matebook轻一点\n屏幕效果：非全贴合屏，其实也没多大影响\n运行速度：运行速度杠杠的', '深空灰色', '2022-07-07 11:29:25', 5);
INSERT INTO `data` VALUES (14178, '我***啦', 5, '买来给孩子玩的，屏幕很清晰，运行很流畅，内存也够大，尺寸很大看什么都很方便，头一天下单第二天就到了物流很快，性价比很高。孩子很喜欢呢！', '银色', '2023-02-13 10:26:21', 6);
INSERT INTO `data` VALUES (14179, 'j***1', 5, '外观材质：高大上\n屏幕效果：屏幕效果：2k 分辨率高，清晰\n运行速度：a13速度就是快，比自己的8p要快好多。\n轻薄程度：轻薄\n\n\n第一次买ipad,打算给孩子上网课学习用的。自己也想试着用ipad玩游戏。玩王者觉得太大了，不习惯，可以开到极致画质，原神没玩过，一开始默认最低效果。。。刷视屏真的爽，被老婆抢着玩了?。总结64g新机到手就只有49g,玩游戏肯定不够，看图，但这次领了400优惠劵的，对于我这种打工人来说超值了。', '银色', '2022-11-03 12:08:46', 5);
INSERT INTO `data` VALUES (14180, 'J***1', 5, '给12岁的外甥女买的ipad，平时上上网课，玩玩王者农药和平精英什么的，非常适合，屏幕够大，系统流畅。她也很聪明，虽然平时都是用安卓手机的，但远程教一下子就上手了，苹果系统很傻瓜易用哈。', '深空灰色', '2023-01-25 16:20:26', 1);
INSERT INTO `data` VALUES (14181, '机***迪', 5, '外观材质：外观无瑕疵，手感好，物流速度快\n屏幕效果：屏幕显示清晰，要比18款的更好，买来是上网课用的\n运行速度：运行速度快，真不愧是iOS系统\n轻薄程度：更薄了?，手感更好了', '银色', '2022-12-23 12:59:44', 5);
INSERT INTO `data` VALUES (14182, '嗜***-', 5, '外观材质：经典的外观设计，还有祖传的home键指纹识别\n屏幕效果：非全贴合屏幕，不过显示效果还是苹果的水准。\n运行速度：A13处理器，对比安卓平板来说还是很能打的，简单打打游戏，学习，看看视频完全够用，配上ios系统的流畅性，非常好用\n轻薄程度：很薄，重量也能接受\n其他特色：虽然有很多缺点，但是价格便宜啊，3k入手256g版本，太香了', '银色', '2022-11-05 17:56:41', 4);
INSERT INTO `data` VALUES (14183, '买***啥', 5, '心心念念了好久，终于到手了，追剧学习游戏，样样都能满足我的需求，而且手感非常好，大小也合适，很愉快的一次购物体验，升级后，又能用好多年了。', '深空灰色', '2022-12-31 12:04:28', 6);
INSERT INTO `data` VALUES (14184, '北***员', 5, '外观材质：金属材质的选择，赞赞赞。\n屏幕效果：视网膜屏幕，视觉效果特别棒。\n运行速度：飞快。\n轻薄程度：合适。\n其他特色：系统比其他的系统要流畅很多很多，颜值超高品质保证，非常值得推荐。', '深空灰色', '2022-08-04 21:33:13', 5);
INSERT INTO `data` VALUES (14185, '孤***弟', 5, '手机速度非常快，运行流畅，电池容量大。手机点屏幕非常清晰，分辨率超高。通话音质很棒，没有杂音，处理器是顶级的，非常满意。', '银色', '2022-11-28 11:02:55', 5);
INSERT INTO `data` VALUES (14186, '梦***真', 5, '外观材质：质量非常不错，没有划痕磕碰\n屏幕效果：色彩饱满\n运行速度：苹果依旧很流畅，目标10年不换，只看电视刷个题啥的，没问题\n轻薄程度：正好放在包里\n其他特色：整体还是很满意的，低价入手，才是真的香！', '银色', '2023-03-19 10:31:34', 4);
INSERT INTO `data` VALUES (14187, 'j***8', 5, '外观材质：很漂亮，很时尚芭莎！\n屏幕效果：很清晰，很流畅地色彩斑斓！\n运行速度：速度比保时捷卡宴跑的还快！\n轻薄程度：很轻薄，很喜欢！\n其他特色：比较喜欢，下次还会光顾！', '银色', '2022-12-12 21:42:29', 4);
INSERT INTO `data` VALUES (14188, 'd***0', 5, '外观材质：外观时尚靓丽，苹果的做工精细，很不错的产品\n屏幕效果：屏幕显示细腻，支持触控笔，可以搭配键盘，作为有力的生产工具\n运行速度：日常使用足够了，上网课，刷剧都不错\n轻薄程度：大小适中，轻薄好用', '深空灰色', '2023-01-25 12:01:03', 4);
INSERT INTO `data` VALUES (14189, 'j***w', 5, '外观材质：金属外壳，一如既往的好\n屏幕效果：还没贴屏膜，视觉效果太棒了。颜色比4那会柔和多了\n运行速度：非常快呦。家里的4用了十年了，系统也不能更新了，大多数app都不兼容了', '深空灰色', '2022-12-01 19:44:36', 1);
INSERT INTO `data` VALUES (14190, 'p***李', 5, '外观材质：非常大，看书舒服\n屏幕效果：显示细腻\n运行速度：还阔以，没玩游戏\n轻薄程度：份量很重\n其他特色：画画不错，还得买个笔', '深空灰色', '2022-07-30 09:04:32', 5);
INSERT INTO `data` VALUES (14191, 'j***d', 5, '使用了几天，很流程，耗电量慢，\n外观材质：不错\n屏幕效果：不错\n运行速度：不错\n轻薄程度：不错', '银色', '2023-02-26 11:11:56', 6);
INSERT INTO `data` VALUES (14192, '炊***8', 5, '黑色主流颜色，上一个买的银色，实物更好看，不腻。目前来说，一切正常，没有发现不太好的地方，按键也还行，没有瑕疵，显示效果非常好，很清晰。性能也挺好，使用起来很流畅，', '深空灰色', '2022-08-04 23:09:19', 3);
INSERT INTO `data` VALUES (14193, 'j***7', 5, '颜值爆表，运行流畅，值得购买！\n外观材质：上手高级，皮肤般的感觉\n屏幕效果：非常亮眼，用完都不近视了\n运行速度：特别流畅，玩游戏流畅\n轻薄程度：轻薄顺手，开会拿着毫不费力\n其他特色：还可以防身', '深空灰色', '2022-07-14 13:55:28', 4);
INSERT INTO `data` VALUES (14194, '春***你', 5, '特赞的一次购物，真的很不错，非常满意，快点下手吧，不再犹豫了。\n外观材质：我选的是银色的，超赞的太不错了\n屏幕效果：屏幕效果还算不错\n运行速度：流畅顺滑，A13的运行速度不用担心\n轻薄程度：并不薄，但是很轻，确实挺轻的', '银色', '2022-06-24 09:32:34', 5);
INSERT INTO `data` VALUES (14195, 'e***w', 5, '手机外观材质不错，外观好看，材料应该是也不错（手机的配件应该是中国制造，质量很好）。屏幕效果很好，运行速度很快，厚度适中，手感不错。拍照片的效果很好，外出可以不用带像相了，整体不错，值得购买。', '银色', '2022-11-13 19:12:57', 5);
INSERT INTO `data` VALUES (14196, 'y***3', 5, '怎么能不爱呢，之前的18版都还是好的，真的耐用。男票提前给买的七夕礼物，太开心啦，嘻嘻嘻嘻。画面流畅，运行速度快，电池也比较耐用。\n外观材质：银色很大气，但是如果能有玫瑰金就好了，最喜欢还是这个色号\n屏幕效果：10.2寸屏幕，很清晰流畅\n运行速度：速度杠杠的\n轻薄程度：比较轻薄，还是得用保护套，安全一些', '银色', '2022-07-28 11:21:51', 4);
INSERT INTO `data` VALUES (14197, 'H***y', 5, 'IPad运行速度特别快，比较轻薄，使用非常方便。主要是用着不会特别热，散热效果好。用来学习，追剧，打游戏都没问题，256的内存也足够了，不用担心内存不够的问题', '银色', '2023-03-04 21:49:09', 4);
INSERT INTO `data` VALUES (14198, 'j***m', 5, '外观材质：外观设计非常精美\n屏幕效果：效果特别好\n运行速度：非常流畅\n轻薄程度：很薄，很有手感\n其他特色：好用时尚，下次还会在买，已经买了好几部了', '深空灰色', '2022-11-09 10:08:09', 5);
INSERT INTO `data` VALUES (14199, '颜***6', 5, '很好看，买来送给家人的，运行非常流畅，怕内存不够所以买的256g的，整体给我的感觉非常不错，几个设备之间能进行互联，非常的方便，平时看看电视，刷刷剧什么的，够用了', '深空灰色', '2022-07-26 16:24:22', 6);
INSERT INTO `data` VALUES (14200, 'w***y', 5, '觉得非常不错，\n外观材质：看起来很不错\n屏幕效果：适合\n运行速度：挺快\n轻薄程度：刚好\n其他特色：内存大，放心用', '深空灰色', '2022-11-09 16:30:50', 1);
INSERT INTO `data` VALUES (14201, 'u***7', 5, '京东\n外观材质：好看好用\n其他特色：价格历史最低2999的价格还是合适，现在各大平台付定金都不止这个价格\n轻薄程度：很薄\n运行速度：快准\n屏幕效果：比我之前用iPad2019还是要好很多\n京东物流很快第二天送达，这是我在京东买东西的重要原因', '深空灰色', '2022-10-26 21:53:42', 2);
INSERT INTO `data` VALUES (14202, '_***海', 5, '很赞， 已经入手了，收到后迫不及待打开，用起来很顺滑\n流畅，用来追剧，看网课，看书等等完全可以，对比了\n几家，以及线上线下的，最后选择了这一个.听歌，看电视都很好，小巧，方便携带，真的是很不错的，需要宝宝们可以下手了。屏幕也很清晰声音也很洪亮', '深空灰色', '2022-11-09 15:34:00', 4);
INSERT INTO `data` VALUES (14203, 'Q***n', 5, '外观材质：金属材质\n屏幕效果：清晰度非常好\n运行速度：一如既往的流程\n轻薄程度：拿起来，在手上非常的薄\n其他特色：这产品真的是非常可以了，???????????', '深空灰色', '2022-07-04 20:54:13', 2);
INSERT INTO `data` VALUES (14204, '马***英', 5, '很不错的一款产品，性价比高很不错，这个价位买到这样的东西，真的很不错，\n屏幕效果：很不错\n运行速度：快\n外观材质：好\n轻薄程度：薄\n其他特色：流畅', '银色', '2022-12-10 17:50:32', 1);
INSERT INTO `data` VALUES (14205, 'j***d', 5, '挺好用的，屏幕分辨率很高，反应速度也很快，网速OK的话开网页那简直都是嗖嗖的，确实不错，就是感觉没有老款的那么重，轻多了', '银色', '2023-02-08 22:14:59', 2);
INSERT INTO `data` VALUES (14206, '晨***子', 5, '很喜欢这个平板，买回来每天必玩～\n\n1.学习很方便，记笔记直接插入截图裁剪，然后直接在上面标注，在旁边做笔记，太方便了，各种书写色彩的供选择；\n\n2.追剧也很nice，屏幕大，画面清徐，爱不释手；\n\n3.还可以在上面玩古筝啥的，体验极好，玩的很开心；\n\n4.吾辈学习娱乐之得力小助手哈；\n\n5.还有很多功能还没用过嘻嘻。', '银色', '2022-08-14 10:56:38', 5);
INSERT INTO `data` VALUES (14207, 'u***j', 3, '膜和壳不太行 其他还可以', '银色', '2021-11-25 12:31:39', 3);
INSERT INTO `data` VALUES (14208, '雪***觉', 5, '外观材质：外观精致唯美 材质很有手感\n屏幕效果：屏幕清晰 画质好\n运行速度：运行无卡顿 超级流畅\n轻薄程度：厚度适中\n其他特色：精致', '银色', '2022-10-29 16:38:13', 4);
INSERT INTO `data` VALUES (14209, '用***的', 5, '搭载A13仿生芯片，运行速度起飞，左右切换丝滑流畅，如德芙，超薄质感，质量很轻，手感么么哒，屏幕显示清晰，色彩饱和鲜艳，刷新快，加载速度快，没有一丝丝的卡顿，深空灰简直的经典，非常满意，目前还没有发现缺点。', '深空灰色', '2022-11-07 18:22:03', 4);
INSERT INTO `data` VALUES (14210, '花***酱', 5, '外观材质：银灰色系干净清爽，非常舒服手感超棒\n屏幕效果：清晰色彩饱和，一如既往的好，追剧真的不错\n运行速度：没有一点卡顿延迟，运行速度很快\n轻薄程度：很薄手感超棒\n其他特色：京东物流超级给力', '银色', '2022-12-13 10:03:29', 4);
INSERT INTO `data` VALUES (14211, 'u***2', 5, '外观材质：高端大气上档次\n屏幕效果：非常的清楚\n运行速度：ipad没的说\n轻薄程度：很轻盈\n其他特色：耐用', '银色', '2022-09-02 22:11:35', 2);
INSERT INTO `data` VALUES (14212, '时***谕', 5, '外观材质：超出预期，质量很好，做工精细，满意\n屏幕效果：很吸睛的\n运行速度：很快很流畅\n轻薄程度：轻薄无迪\n其他特色：性价比高，快递发货讯速，客服态度很好，喜欢挺好的，目前没问题，后续追评', '银色', '2022-11-07 01:14:27', 4);
INSERT INTO `data` VALUES (14213, 'f***9', 5, '给孩子买的ipad5用了有5年了，该换一个了，iPad5还很好用的,拿来看个PDF还是很舒服的感觉\n外观材质：很棒\n屏幕效果：很好细腻\n运行速度：很快\n轻薄程度：比现在的5薄多了\n其他特色：之前孩子小没有配上笔这次配齐活了', '深空灰色', '2022-08-15 20:15:06', 5);
INSERT INTO `data` VALUES (14214, 'j***r', 5, 'iPad9很具有性价比，2000多点就可以用到苹果系统，很是流畅，买了看网课的，屏幕大，看着很是得劲，希望能用的时间久一些 真的很不错呐，还可以用教育优惠，推荐推荐', '深空灰色', '2023-02-02 20:24:23', 2);
INSERT INTO `data` VALUES (14215, 'j***r', 5, '电脑外观很好也很实用，键盘很灵活，价钱也很实惠，性价比非常高，联想从来不会让人失望，准备回购男朋友看了非常喜欢', '银色', '2022-11-25 21:48:26', 4);
INSERT INTO `data` VALUES (14216, '黒***伍', 5, '1 1 月 1 0 日 晚 上 8 点 付 的 款 ， 第 二 天 一 大 早 就 送 来 了 ， 东 西 是 正 品 ， 价 格 很 美 丽 ， 好 评', '银色', '2022-11-11 20:00:31', 4);
INSERT INTO `data` VALUES (14217, 'j***f', 5, '外观材质：完好\n屏幕效果：鲜艳\n运行速度：流畅\n轻薄程度：超薄\n其他特色：值得购买京东品质保证确实是值得信赖的，比苹果的官方旗舰店便宜好多还是全新未开封的，以后苹果产品可以放心购买了', '银色', '2022-10-27 17:32:23', 6);
INSERT INTO `data` VALUES (14218, '大***e', 5, '平板没问题 查号是行货 用来看书看报特别舒服 不刺眼 听?效果倍儿棒 上网课 看电子教材很合适 小盆友用平板做了个电子手帐 很开心 现在觉得买的挺直的 感觉64的还是小点 应该买256G的 哈哈', '深空灰色', '2022-07-25 10:59:20', 5);
INSERT INTO `data` VALUES (14219, '快***猫', 5, '一直在京东买东西，质量还是有保证的。10.2寸的屏幕效果很好，显示很清楚，音效也不错。苹果的质量还是不错的，上一个用了四五年，现在是要上网课才换的。运行速度很快，还行', '银色', '2023-01-14 22:47:44', 5);
INSERT INTO `data` VALUES (14220, 'j***c', 5, '很快就收到了，体验感很好，内存大，价位合适，推荐大家购买，冲冲冲！！！\n运行速度：很快，不卡顿\n外观材质：手感很好，磨砂的质感\n轻薄程度：很轻，拿着一点不重', '银色', '2023-03-15 20:55:34', 4);
INSERT INTO `data` VALUES (14221, 'u***7', 5, '外观材质：价格合适，抢的，用来上网课。。。苹果质量没得说\n屏幕效果：很好。。\n运行速度：不卡，ios系统的优势就是不卡，随便用几年都没问题。。。。。。。。。。。\n轻薄程度：很薄。\n其他特色：反正双十一性价比高，够用了。。。。。', '深空灰色', '2022-11-09 13:19:46', 4);
INSERT INTO `data` VALUES (14222, 'j***2', 5, '外观材质：一如既往的好看，比之前的要轻薄了许多\n屏幕效果：屏幕?10.9寸很大\n运行速度：非常快，256G给孩子上网课效果好，感觉可以用到高中毕业之后，孩子非常喜欢?', '深空灰色', '2022-11-03 17:01:28', 6);
INSERT INTO `data` VALUES (14223, '_***静', 5, '趁老公生日，入手了一个平板，其实想买很久了，自营店不管是售前还是售后服务都很好。很满意，物流很快隔天就收到了，非常满意，然后自己买了一个保护套，很合适，不管是学习用还是看电视看电影都非常方便了，满意????推荐', '深空灰色', '2023-01-12 19:30:19', 6);
INSERT INTO `data` VALUES (14224, 'j***0', 5, '外观材质：质感很好\n屏幕效果：屏幕效果当然也是满意啦，不过边框有点宽\n运行速度：棒棒棒\n轻薄程度：厚度很适合！', '深空灰色', '2022-11-11 11:36:00', 1);
INSERT INTO `data` VALUES (14225, 'j***弧', 5, '外观材质：非常干净没有翻车\n屏幕效果：显示清晰\n运行速度：非常快\n轻薄程度：薄', '深空灰色', '2022-10-04 17:47:35', 2);
INSERT INTO `data` VALUES (14226, 'B***d', 5, '之前的ipad mini 被娃玩坏很久了，一直没再换新。这马上寒假了，买来给孩子上课用，平时看看剧也不错，家里唯一不用苹果系统的我，也想试试看，拿回家我先熟悉熟悉，屏幕效果很好，够大！', '深空灰色', '2023-01-10 20:36:18', 5);
INSERT INTO `data` VALUES (14227, 'j***e', 5, '轻薄，反应灵敏，系统不卡顿，屏幕舒适度适中。性价比高，发货速度快，货物完整度强，售后也是非常棒，快又专业。尺寸刚好合适，小巧轻薄，无论是上网课还是追剧，或者玩吃鸡，王者等，拿在手上都非常方便。舒适度高，图像显示也非常清晰，很有质感，颜色艳丽，拍照也好看，而且运行速度快，电池耐用，最主要价格还是很不错哒。', '银色', '2022-08-26 17:08:41', 5);
INSERT INTO `data` VALUES (14228, '张***6', 5, '特别性价比的平板，还是比某为某米性价比高，根据我的需求64g就能满足了，两千多入手很值得，关键是比某为某米能耗低，追剧的神器，孩子上网课也绰绰有余！！！\n外观材质：金属边框，铝合金材质\n屏幕效果：226ppi好像是，但是追剧开通了某腾某迅以后hdr蓝光尊享高清画质和手机一样清晰\n运行速度：流畅的一批，苹果的处理器yyds\n轻薄程度：比一起某米某为都要轻薄，手感好！\n其他特色：能耗低不发热', '深空灰色', '2022-01-20 23:14:29', 5);
INSERT INTO `data` VALUES (14229, 'j***y', 5, '外观材质：金属材质，手感很舒服\n屏幕效果：屏幕杠杠的\n运行速度：很流畅，没有出现卡顿\n轻薄程度：很薄', '深空灰色', '2022-08-25 07:28:16', 1);
INSERT INTO `data` VALUES (14230, '阳***妈', 5, '外形外观：时尚大方，银色太空铝外壳经典，耐看。\n屏幕音效：视网膜屏幕分辨率达2160*1650，高清逼真，细腻，清晰明显，音质也很好2扬声器2麦克风，效果不错。 \n拍照效果：毫无疑问，前摄像头1200W，后摄像头800W，能应付所有旅拍，大片自己掌中搞定。 \n运行速度：苹果A13专用芯片，存储内存256G，流畅灵敏程度一流，弹指间随你所愿。 \n轻薄程度：厚度7.5mm携带轻便，居家可随意摆放。\n其他特色：镜头造型很科技，标配的充电头，做工精细，用料十足，品牌商家，品质保证，环保健康，无异味，大牌手机的佼佼者，满足你的愿望。购物上京东，京东快递最棒，客服态度好，让你无后顾之忧。', '银色', '2022-01-06 17:20:57', 6);
INSERT INTO `data` VALUES (14231, 'C***0', 5, '平板颜值高，手感摸起来也很有质感，屏幕久了也不伤眼睛，有很好的护眼功能，运行很快，也很顺滑，打游戏起来也很丝滑，值得购买。', '银色', '2022-11-13 15:01:12', 2);
INSERT INTO `data` VALUES (14232, 'j***u', 5, '之前一直用的padmini，用了5年，这次终于买了ipad，我先说外观吧。\n外观材质：我个人认为仍然延续了苹果的简约大方，银色的外观还是很高级。也可能是我第一次买pad，觉得很不错。\n屏幕效果：屏幕打开，仍然是标准的苹果介绍界面，我不多说，很舒服，很简洁！\n运行速度：很快，毋庸置疑，我一直觉得苹果的速度真的很快，买过其他的脾气的平板确实不如苹果。\n轻薄程度：这次我感觉比我的padmini都小，不知道为什么，越来越轻薄！这个是好的！\n最后还是觉得苹果的产品没问题，到时候用几天再看看，然后回来给个追评！非常的漂亮！大气！', '银色', '2021-12-13 17:11:21', 7);
INSERT INTO `data` VALUES (14233, '快***0', 5, '平板很不错，包装完好，特地为它买了一个壳，屏幕比想象中的大，很清晰，运行速度快，买的内存256G的，平时习惯用来上网课，看剧，而且方便携带，轻薄很不错。', '银色', '2022-06-25 08:57:07', 1);
INSERT INTO `data` VALUES (14234, '壹***人', 5, '外观漂亮，之前买过一代mini 银色的，感觉还是灰色的好看。屏幕狠细腻，A13芯片，处理速度也很好，作为入门级ipad 学习娱乐正好够用。关键是价格便宜啊，就比八代贵了几百块钱。九代产能原因，一直没货，还好活动前预定了，总体来说，很满意。', '深空灰色', '2021-12-25 13:57:54', 7);
INSERT INTO `data` VALUES (14235, '默***昕', 5, '轻薄程度：设计轻薄，一点都不笨重，携带方便！\n外观材质：外观设计很经典，黑色耐看，不过时！\n屏幕效果：屏幕设计很大，分辨率很高，很清晰，上网课，看电影，玩游戏都很棒！\n运行速度：运行速度很快，一点都不卡！', '深空灰色', '2023-02-16 10:14:02', 3);
INSERT INTO `data` VALUES (14236, 'j***Q', 5, '在京东购物很放心，送货又快，送到家里，服务很周到，有需要还会回购\n外观材质：外观很好，屏幕效果也好\n运行速度：也快\n轻薄程度：非常的轻薄', '银色', '2023-03-12 13:34:03', 2);
INSERT INTO `data` VALUES (14237, '如***7', 5, '这个平板速度不错，价格便宜，颜值不错，手感也不错，玩游戏嘎嘎好，速度也很快，音质也很好的，各方面都不错的，大小也比较合适，满意', '银色', '2022-11-14 17:14:58', 1);
INSERT INTO `data` VALUES (14238, '晒***6', 5, '不错 快递包装非常好  一看就是正品 外观就很精美 屏幕显示效果杠杠的 运行速度很快 很轻薄 儿子很喜欢 现在这大环境 在家上网课必备 很棒的一次购物 真不错', '银色', '2022-10-28 21:07:27', 5);
INSERT INTO `data` VALUES (14239, '小***活', 5, '外观材质：太漂亮了，虽然只有两种颜色，但是这个灰色很酷帅帅的，适用于很多场景\n运行速度：苹果机子毋庸置疑，运行很流畅，终于买到了心心念的ipad，看看用途，入门款性价比很高，64g看剧学习都足够用了，打游戏或者其它用途的话要考虑大内存升级款，性价比就没这么高了', '深空灰色', '2022-09-22 23:56:14', 5);
INSERT INTO `data` VALUES (14240, '玻***8', 5, '送宝贝的新年礼物  她很喜欢   说是用起来很顺畅 可以随意变换自己喜欢的布局  拿着大小刚好  机子相比其他平板比较轻  清晰度够高  音响效果不错  主要还是性价比高  春节买还有优惠  不错', '银色', '2023-01-23 10:02:24', 2);
INSERT INTO `data` VALUES (14241, '污***朵', 5, '非常完美的ipad，这款的性价比是超级高，a13的处理器真的是杠杠的，非常流畅，这种价位的苹果还有让人选择的余地吗，便宜又好用，非常值得入手，京东自营绝对正品信得过，非常满意', '银色', '2023-01-02 21:42:23', 3);
INSERT INTO `data` VALUES (14242, '用***的', 5, 'A13仿生芯片加持下，图形处理提速飞快，可以尽情享受视频剪辑和游戏运行，高清分辨率加大屏幕，攻克项目，观看影片，绘画，处理照片，都是完美，精湛的工艺，太喜欢了。', '深空灰色', '2023-01-10 09:29:36', 4);
INSERT INTO `data` VALUES (14243, 'j***o', 5, '非常好，主要用来看网课的，这个性价比不错，也不玩游戏，就是看看视频，这价位很好了，全新机，开机验证没有任何问题，体验不错，京东物流太牛了，直接第二天一大早就送到', '银色', '2022-07-25 19:01:08', 6);
INSERT INTO `data` VALUES (14244, '葡***了', 5, '外观材质：很满意，一开始本来想买华为或者小米的，最后对比了还是决定买苹果的产品\n屏幕效果：目前使用了几天，还是挺满意的，平常主要用于给娃上网课使用\n运行速度：挺快的，孩子也很喜欢\n轻薄程度：轻薄\n其他特色：一开始看了深空灰，觉得比较商务，想买灰色的，但是拍错了银色，收到货也懒得退了。', '银色', '2022-12-16 14:13:01', 6);
INSERT INTO `data` VALUES (14245, '乐***可', 5, '完美**拍摄方面，前置采用新的原深感镜头，1.9&amp;mu;m像素，支持自动对焦，即使在低亮度环境下也能实现较快的对焦速度，后置依旧依旧采用1200万像素广角/超广角双摄配置，全新的1200万像素主摄像头，传感器更大，单位像素达到1.9&amp;mu;m，F/1.5光圈，传感器位移OIS，低光捕获提高了49%。夜间模式曝光速度提升两倍。视频新增运动防抖模式，动态拍摄更加稳定。用了快半月，没有出现起热，卡顿的现象，对于我不玩游戏的人来说，14挺好的，刚开始买的时候看见评论，各种担心，用了一段时间后感觉很不错，屏幕非常细腻，很好，看上去非常舒服，比一般手机强多了，音效也很高，听歌很舒适，值得推荐。早买早享受！14拍照真的很好看！比13强太多啦，拍视频也绝绝子！很喜欢紫色！而且电池的使用时间也比之前的机型要棒很多，因为不喜欢灵动岛，所以买了这个标准版，还是这个看起来顺眼。续航能力很好，拍照效果很清晰，运行速度很畅快，非常不错，午夜色比较清晰_靓丽，外形外观，没有多大改变，刘海有较大的变化，摄像头排布没有变化，运行速度挺快，流畅度也没的说，总体效果，很满意，很喜欢。', '深空灰色', '2022-11-14 00:13:14', 2);
INSERT INTO `data` VALUES (14246, 'o***5', 5, '外观材质：银色ipad的这款外观没得说，非常时尚，线条都很流畅精美。\n轻薄程度：非常的轻薄，能做到这个程度绝对是工程学运用到极致了。\n这款的性价比非常高，很适合学生学习用，256G的内存也非常充裕。', '银色', '2022-11-27 11:51:48', 1);
INSERT INTO `data` VALUES (14247, '主***存', 5, '京东物流很快。包装也很严实。拆开包装盒之后拿起来这个iPad。手感特别棒，特别轻薄也比较精致。。屏幕非常清晰显示细腻，看电影，听音乐也可以。使用速度挺快，流畅。', '银色', '2022-12-31 11:19:11', 5);
INSERT INTO `data` VALUES (14248, '瘦***4', 5, '包装完整，外形漂亮，做工很好没发现什么瑕疵，大小正合适，反应速度快，画质清晰，触感非常好，用来学习和娱乐非常方便。值得推荐', '银色', '2022-11-29 21:14:04', 5);
INSERT INTO `data` VALUES (14249, '黄***吉', 5, '一直想买个iPad 养女鹅，正好碰上打折，3099入手了，到手非常香，有点小瑕疵但是客服很快就给解决了，使用半个月了，目前没有任何问题，没有太高要求，所以入门款也够用了，非常满意～', '银色', '2022-11-18 19:35:23', 2);
INSERT INTO `data` VALUES (14250, '奥***渡', 5, 'a13的处理器，日常够用，主要是给孩子上网课用的，屏幕也够大，256的内存只用3千多就可以买到，还是很划算的，有点厚重，孩子想用来打游戏也不大方便的??', '深空灰色', '2022-07-05 20:15:51', 5);
INSERT INTO `data` VALUES (14251, '小***9', 5, '挺好用，用了一段时间了，很好用，好评，是正品，物流也很快，系统很流畅\n运行速度：运行速度很快\n屏幕效果：屏幕颜色挺好\n外观材质：外观材质蛮好的\n轻薄程度：很薄很轻便', '深空灰色', '2023-02-12 13:34:09', 4);
INSERT INTO `data` VALUES (14252, '残***忧', 5, '外观材质：银色，外观漂亮，大方\n屏幕效果：非常清晰，分辨率好\n运行速度：苹果自己的处理器系统，运行那是没得说，非常好\n轻薄程度：10.2寸，我自己感觉最合适的大小！\n其他特色：现在全线涨价，优惠券来得及时！果断下单抢购！', '银色', '2022-11-06 12:45:22', 4);
INSERT INTO `data` VALUES (14253, 'j***b', 5, '很好，很流畅，平时看视频很舒服，运行速度很快\n轻薄程度：比较薄\n外观材质：厚实\n屏幕效果：清晰', '银色', '2022-11-11 22:05:14', 1);
INSERT INTO `data` VALUES (14254, 't***l', 5, '性价比最高的ipad了，没有之一！外观和第六代没什么区别，性能够用，如果不玩游戏，不做视频，基本看不出和儿子的M1芯片ipad air有多大差别，不错！如果领个券就更划算了。2099购入，64G版本基本够用，完美！', '银色', '2022-11-06 23:22:08', 4);
INSERT INTO `data` VALUES (14255, '日***乐', 5, '外观材质：好看，要的银色的，很有质感，手感也很好。\n屏幕效果：屏幕很清晰，色彩鲜艳\n运行速度：速度很快，苹果的系统还是可以的，用几年也很速度。\n轻薄程度：厚薄适中，在加个保护壳正好。\n配件好歹还带着充电头和充电线，算是比手机的优势了', '深空灰色', '2022-12-15 08:48:27', 3);
INSERT INTO `data` VALUES (14256, '水***堤', 5, '如果不是家里的ipad air2摔变形了，不能继续再战斗了，也不会入手这台新款的ipad。但是拿到手以后，确实非常招人喜欢，全新外观设计，没有了home键，更大的屏幕，更窄的边框，选择的蓝色也是非常的漂亮，给人眼前一亮的感觉，平板买来主要还是给孩子用的，看个视频上个网课用，pad基本上完胜这些工作，所以满足需求就好了。屏幕清晰亮丽，刷新率高，使用起来系统流畅，操作丝滑，很满意。', '蓝色', '2023-01-01 21:35:55', 8);
INSERT INTO `data` VALUES (14257, 'j***q', 5, '外观材质：看着很高大上，远峰蓝很时尚，很霸气，手感很好！\n屏幕效果：拿来给小学生上网课，尺寸够大，再也不用拿着手机小小屏幕上网课了。\n运行速度：64G完全够用了，刷视频也非常流畅。\n轻薄程度：很薄，拿在手上手感很好，颜值高，苹果系列从手机到ipad平板无可挑剔！', '蓝色', '2022-12-26 19:52:27', 5);
INSERT INTO `data` VALUES (14258, 'd***2', 5, '外观材质：外观很好看，我买的蓝色的，饱和度很高。\n屏幕效果：屏幕效果不错，感觉特别惊艳，显示效果很好。\n运行速度：运行速度快，反应迅速。\n轻薄程度：比较轻薄，不重，携带方便。\n其他特色：双扬声器不错，看世界杯体验很好，比单声道好多了。', '蓝色', '2022-12-26 22:42:00', 4);
INSERT INTO `data` VALUES (14259, 'R***冬', 5, '外观材质：塑料和玻璃吧，反正看着挺结实，用起来没问题。\n屏幕效果：清晰明亮，反正自己家里用和玩儿肯定够用了。\n运行速度：运行速度挺快的，带各种软件没问题，打游戏更是快的不得了。\n轻薄程度：我感觉不属于轻薄吧，因为它毕竟分量还是挺重的，挺厚实的，有厚重感。\n其他特色：可搭配的其他配件比较多，像什么笔呀像什么保护套啊，还有其他的可选条件比较多，整体不错。充电速度也很快，待机时间也很长，尤其是他这个屏幕大拍照片啊拍一些数据非常的清晰，特别直观。', '蓝色', '2023-02-06 13:51:43', 7);
INSERT INTO `data` VALUES (14260, 'O***爵', 5, '老婆甜品店的平板一直用的6代，正好赶上结婚纪念日，给老婆买了新的平板。iPad 10这颜色太棒了。很流畅，很喜欢新系统的开机画面。双扬声器追剧真的也不错，轻薄好用。在京东连着马歇尔S2一起下的单，都是正品。充电器也和以前不一样了，成了C口，充电器也很细节，比之前的线有质感太多了。', '粉色', '2023-02-14 11:27:09', 9);
INSERT INTO `data` VALUES (14261, 'j***f', 5, '给女儿买的，她非常喜欢，外观精致漂亮，系统与系统运行流畅，续航能力优秀，全面屏设计拓展了视觉空间，通畅，游戏追剧都非常棒', '蓝色', '2022-10-30 13:55:09', 4);
INSERT INTO `data` VALUES (14262, '鱼***唷', 5, 'iPad的画质真的非常好 之前买过其他品牌的平板 观感和这个差的不止一点 系统运行也流畅 外观是非常好看的 没有之前那个影响观感的返回键了 看剧非常爽 很喜欢', '银色', '2023-01-10 12:58:10', 5);
INSERT INTO `data` VALUES (14263, 'l***n', 5, '苹果系统就是流畅，本来想买9代，想一想，还是买10代平板，看上了高刷新，高一代C P U，太轻簿了，小伙伴孩上网课好。已经是家里第三台平板电脑了，平板2，平板5，现在平板10，史上最牛平板电脑。????', '蓝色', '2023-03-02 12:24:00', 9);
INSERT INTO `data` VALUES (14264, '七***吃', 5, '犹豫了很久最终选择了ipad十代，果然没让我失望，收货时装了好大一个箱子，预定付款后第二天就到了，快递速度贼快，开机神速，比我的老古董台式机快了好几倍，屏幕也足够大，非常清晰，周末在家体验了两天，越看越喜欢，果真没让我失望，用来办公绰绰有余，玩游戏也不错，买这个主要用来日常办公用，偶尔游戏下也不错，不过还在可接受范围内，这个平板的性价比很高，很满意的一次购物体验！', '蓝色', '2023-02-15 21:33:42', 9);
INSERT INTO `data` VALUES (14265, '柏***4', 5, '外观材质：巴适，蓝色，我的手机也是蓝色的\n屏幕效果：看电影打游戏都很高清，适合追剧和宅在家学习\n运行速度：速度快，不卡顿，打游戏很快\n轻薄程度：轻薄，便携。适合户外写生。', '蓝色', '2023-01-03 14:59:32', 2);
INSERT INTO `data` VALUES (14266, '小***咯', 5, '外观材质：钢化材质真的不错\n屏幕效果：特别的清晰，高效，不错\n运行速度：苹果系统不愧是王者，特别的快！\n轻薄程度：特别的平薄，拿在手里，特别的好用，给力\n其他特色：是网课必选产品之一，真的很给力！', '蓝色', '2022-12-27 11:23:08', 4);
INSERT INTO `data` VALUES (14267, 'z***1', 5, '速度快，新，外观大气上档次且实用，小巧新颖时尚，小巧舒适大品牌就是好，服务周到，配送快，迅速且到位!用起来很舒适,值得推荐!!!!', '银色', '2022-11-12 21:16:23', 5);
INSERT INTO `data` VALUES (14268, '小***咯', 5, '外观材质：是真的不错，超级玻璃钢化材质\n屏幕效果：超清晰超实用\n运行速度：特别的快，而且反应灵敏\n轻薄程度：正好刚刚拿在手里，特别舒服\n其他特色：苹果电子产品依旧是那么的棒棒哒！非常的给力！发货速度也是很快很快，几天时间就送到了！', '黄色', '2022-12-24 15:37:22', 4);
INSERT INTO `data` VALUES (14269, '1***Y', 5, '机子外观简约大气，线条流畅，高级的灰色系，百看不厌，轻薄方便携带，屏幕挺大的，追剧超爽?，玩游戏也是停不下来。当天下单隔日到，京东物流永远不会失望。', '银色', '2023-03-14 11:27:16', 4);
INSERT INTO `data` VALUES (14270, 'u***9', 5, '保护壳大小刚好，背面是透明的硬壳，四周是软壳，能很好的保护边缘，颜色也很漂亮，吸磁吸力很强，保护壳上下可以分开的，用起来很方便，还送了一张膜！', '蓝色', '2023-03-15 13:33:00', 7);
INSERT INTO `data` VALUES (14271, '小***4', 5, '外观材质：很好看手感不错\n屏幕效果：追剧很棒\n运行速度：速度挺快的A14加上ios确实给力\n轻薄程度：厚度和我的手机差不多\n我喜欢深空灰色可惜22款没有这个颜色，21款的Home我不喜欢，最后想了想反正带壳用就选了这个蓝色，Air有我喜欢的颜色但是感觉只是追剧没必要买Air', '蓝色', '2023-02-21 14:20:20', 6);
INSERT INTO `data` VALUES (14272, 'd***u', 3, '东西不错，就是价格大家都懂得', '蓝色', '2023-02-08 20:23:34', 7);
INSERT INTO `data` VALUES (14273, 'j***b', 5, '旧平板是6年前的中奖得的mini1，由于孩子上网课，所以就决定换个大的\n外观材质：我个人很喜欢直角，不喜欢圆角设计，所以外观很符合我的审美\n屏幕效果：屏幕超大，一只手把不住的，这样的大屏对眼睛好。学校老师是不主张用小屏幕上课的。\n运行速度：苹果的速度大家都知道，用久了旧的，觉得新的飞快的，惊人的快\n轻薄程度：平板能做到和手机差不多厚度真的很棒！！！', '银色', '2022-11-11 23:27:22', 3);
INSERT INTO `data` VALUES (14274, 't***r', 5, '很久没有使用过平板电脑，这次买台最新的10代ipad，换成了方形外壳取消了home键，触控集成到开机按钮上，数据线接口也换成了typec，搭配了20w充电器，上手手感还是非常好，10.9寸屏幕够大，配个键盘可以当笔记本用了', '银色', '2023-03-18 15:10:35', 6);
INSERT INTO `data` VALUES (14275, '丑***o', 5, '一一如既往的流程，屏幕也很大，追剧的时候解放手机，还可以跟各种文档匹配，搭配键盘和笔也是比较简便，256的内存也是完全够用了，颜色很有深意，推荐购买！', '蓝色', '2023-03-04 20:53:41', 3);
INSERT INTO `data` VALUES (14276, 'j***5', 5, '外观材质：选择了黄色，很好看\n屏幕效果：显示很清晰，屏幕比手机大很多\n运行速度：很快，没感觉到卡顿\n轻薄程度：比手机重一点点', '黄色', '2023-02-24 21:39:50', 2);
INSERT INTO `data` VALUES (14277, 't***0', 5, '外观材质：颜色好看，质感很好；\n屏幕效果：高清，但没有高刷新率，刷网页快一点的时候回晕晕呼呼的；\n运行速度：不错，非常流畅，玩游戏不卡顿；\n轻薄程度：仟薄，轻便，便携', '蓝色', '2022-12-29 12:40:23', 5);
INSERT INTO `data` VALUES (14278, 'b***e', 5, '外观材质：时隔快10年再次入手iPad还是很满意，第10代了，感觉重量都减少了，单手拿着不觉得难\n屏幕效果：高清视网膜屏幕很满意，主要给孩子网课使用保护眼睛\n运行速度：快，流畅\n轻薄程度：时尚，轻薄', '粉色', '2022-12-05 10:57:34', 5);
INSERT INTO `data` VALUES (14279, '-***-', 5, '可以\n外观材质：外观是我喜欢的，好中意\n是已经中意的。流畅。颜值担当。值得买。\n轻薄程度：美团跳操可以使用。屏幕大大的。超级喜欢\n其他特色：画面比较清晰。对比效果比较好。\n运行速度：特别喜欢，大家都可以去购买', '粉色', '2023-02-04 11:45:41', 2);
INSERT INTO `data` VALUES (14280, 'n***y', 5, '外观材质：外观大气，有型\n屏幕效果：显示流畅，画面清晰\n运行速度：之前的老padmini速度不行了，看着也小，这次速度杠杠的\n轻薄程度：机身轻薄，不要压手\n其他特色：好看，好看，好看。过年刷剧神器，上网课也舒服，看着屏幕大了好多，相当满足。这真是一次愉快的体验，老婆孩子都很开心。快递员送货上门，包装完整，辛苦啦！！！', '银色', '2023-01-10 10:27:57', 1);
INSERT INTO `data` VALUES (14281, 'Y***5', 5, '平板很好，新的，非常喜欢\n64G够用的，上上网课，刷刷视频够了。学生党适合。\n就是下单采购时间很久，希望改善一下\n建议买套装（有保护克和钢化膜）', '银色', '2022-12-11 15:38:18', 6);
INSERT INTO `data` VALUES (14282, '加***量', 5, '不错的，64g也可以下两个游戏玩玩，看看电影听音乐啥的，很方便', '蓝色', '2022-12-16 00:01:14', 9);
INSERT INTO `data` VALUES (14283, 'l***5', 5, '外观材质：最新款的 ipad 非常适合孩子上网课。\n屏幕效果：屏幕彩色没得说，苹果一直做的都不错\n运行速度：现在的处理器对于孩子上网课足够了\n轻薄程度：反正也不拿出去，就在家里用非常合适', '银色', '2022-12-28 12:11:59', 2);
INSERT INTO `data` VALUES (14284, '心***连', 5, '外观材质：苹果平板每款都是非常好看，第十代颜色很多，满足不同需求\n屏幕效果：屏幕清晰，分辨率高，大小刚合适\n运行速度：就是看中苹果的运行速度，毫不卡顿\n轻薄程度：适中', '蓝色', '2023-02-03 20:19:52', 5);
INSERT INTO `data` VALUES (14285, 'j***8', 5, '先试用几天，感觉很不错，电池待机时间很\n满意。2.平板的屏幕大显示效果清晰，机身轻薄\n手感\n好，内存也足够大，东西货真价实，还送了很多\n的礼\n品。3.屏幕刚刚好，运行速度也很快，拿着也挺\n轻快\n的，便携性好，非常满意，A14芯片性能上应该\n够了，\n操作很流畅性能很强。屏幕色彩艳丽,显示效果非\n常\n好，电池也比较耐用！我真的好喜欢呀，大家赶紧下单购买吧！', '银色', '2023-03-20 15:49:04', 4);
INSERT INTO `data` VALUES (14286, 'x***y', 5, '轻薄，屏幕清晰，蓝色外观看着清新素雅，孩子非常喜欢。取消了苹果招牌HOME键，屏幕填满了整个框架，质感相当哇塞，孩子非常喜欢，爱不释手！', '蓝色', '2023-02-13 10:28:55', 7);
INSERT INTO `data` VALUES (14287, '清***u', 5, '感觉很不错，还没下载很多东西不知道卡不卡，游戏也还没玩过也不知道流畅不流畅，这个颜色我很喜欢的，感觉两个喇叭比四个喇叭的小声很多，总体来说还是比较好的', '蓝色', '2022-12-28 22:37:32', 3);
INSERT INTO `data` VALUES (14288, '嗯***子', 5, '刚买回来就安装不少软件，内存足，运行速度快。颜色非常漂亮。音色也不错，没事听听音乐。电池容量比较大，待机时间长，充电一次用了很长时间。', '蓝色', '2022-11-07 19:13:01', 3);
INSERT INTO `data` VALUES (14289, '沐***饭', 5, '外观材质：外观包装完整无破损 打开机器金属材质 手感好\n运行速度：苹果系统一贯的流畅丝滑\n轻薄程度：超薄设计 收纳简单 携带出现方便\n屏幕效果：10点9寸超大屏幕 观看视频打游戏都很喜欢 同时双手单手皆可轻松掌控', '银色', '2022-12-29 10:05:22', 4);
INSERT INTO `data` VALUES (14290, 'c***a', 5, '外观材质：ipad10是第一款大改款的ipad，颠覆了原来ipad的设计，运用了全新的全面屏设计。\n屏幕效果：说实话显示效果较之前的ipad并没有特别大的提升，因为也不是全贴合屏。\n运行速度：运行速度还可以，日常使用足够。', '蓝色', '2023-03-03 17:40:08', 6);
INSERT INTO `data` VALUES (14291, '嘟***6', 5, '感觉还是不错的，焦急等了好几天快递才送过来。平板大小总体上和2018版差不多，比之前稍微大一丢丢，全面屏很爽，比之前屏幕大了一些，看剧很爽，自己贴了类纸膜主要用于学习看文献看书。外形设计很喜欢，蓝色非常好看', '蓝色', '2022-12-27 17:59:33', 5);
INSERT INTO `data` VALUES (14292, 'j***w', 5, '外观材质：质感还是苹果的质感\n屏幕效果：看起来很舒服\n运行速度：太丝滑了\n双十一下的单，免息+优惠，真的比9香多了！', '银色', '2022-11-19 20:23:33', 9);
INSERT INTO `data` VALUES (14293, 'u***a', 5, 'iPad 2022款第十代，目前最新款的产品，256 G超大容量，可以存储超大容量的数据\n外观材质：非常的亮眼\n屏幕效果：色彩鲜艳夺目\n运行速度：快速而便捷\n轻薄程度：非常的轻薄，', '蓝色', '2023-01-14 21:06:04', 1);
INSERT INTO `data` VALUES (14294, '郑***1', 5, '买来上网课用的，轻巧方便，银色也很喜欢，真的很不错。\n外观材质：银色真的无敌好看，经典大方的感觉，五星\n屏幕效果：清晰明亮，视觉效果无敌好，五星\n运行速度：很快，打游戏办公都快，五星\n轻薄程度：轻巧，使用方便，去哪都带着，已经离不开了 五星\n其他特色：iPad就是牛', '银色', '2023-01-12 18:07:50', 3);
INSERT INTO `data` VALUES (14295, 'w***i', 3, '新版本强大了很多，用着很过瘾。', '蓝色', '2023-02-28 04:43:32', 3);
INSERT INTO `data` VALUES (14296, '憨***憨', 5, '轻薄程度：很轻很薄拿起来方便\n屏幕效果：屏幕效果：屏幕还是蛮大的 \n外观材质：挺大气的\n其他的话我对于内存没什么要求所以64G对于日常使用还是很可以的，还有对于我来说音效非常好！', '银色', '2023-01-30 19:43:35', 1);
INSERT INTO `data` VALUES (14297, '逆***吒', 5, '物流很快，服务很好，价格实惠，京东送货很迅速，正好赶上活动，历史最低价，屏幕很大，运行很流畅，蓝色很好看，很有金属感，京东服务满意。', '蓝色', '2023-03-09 20:33:18', 4);
INSERT INTO `data` VALUES (14298, '刘***玲', 5, '非常好，等了三天终于收到啦。现在是type-c接口，也没有home键了。充满一次电可以用7天（二年级的小朋友每天晚上做作业，预习课文）。这个蓝色非常心水，10.9寸的大屏，看电视也非常爽歪歪。关键比官网还便宜几百块钱，赚飞了。', '蓝色', '2022-11-22 14:04:30', 5);
INSERT INTO `data` VALUES (14299, '臭***哥', 5, '内存大，是真实的配置，平板和卖家的介绍是\n一样的，先试用几天，感觉很不错，电池待机时间很\n满意。2.平板的屏幕大显示效果清晰，机身轻薄手感\n好，内存也足够大，东西货真价实，还送了很多的礼\n品。3.屏幕刚刚好，运行速度也很快，拿着也挺轻快\n的，便携性好，非常满意，A14芯片性能上应该够了，\n操作很流畅性能很强。屏幕色彩艳丽,显示效果非常\n好，电池也比较耐用！我真的好喜欢呀，大家赶紧下单购买吧！', '粉色', '2023-03-12 15:56:20', 4);
INSERT INTO `data` VALUES (14300, '钱***了', 5, '外观材质：包装非常结实，东西保护得很好，值得好评\n屏幕效果：整体来说，还是很好的，非常值得再次回购\n运行速度：很好看，制作工艺很精美，材质也很好！给个赞！\n轻薄程度：质量很过关，品质有保障，相当不错的选择，好多朋友看我用都想买，我都推荐了', '蓝色', '2022-12-20 19:07:56', 4);
INSERT INTO `data` VALUES (14301, 'u***9', 5, '用了一段时间才来评价，孩子上网课用，红色的非常漂亮，之前买的苹果AIR第一代，用了10年还好好的，信赖苹果，非常不错', '粉色', '2022-12-21 19:01:08', 3);
INSERT INTO `data` VALUES (14302, '北***丝', 5, '非常喜欢这个平板，速度快，大小合适。type C接口好。', '银色', '2022-12-15 11:54:04', 5);
INSERT INTO `data` VALUES (14303, 'j***L', 5, '运行速度：可以\n屏幕效果：可以\n外观材质：完美\n轻薄程度：非常薄\n其他特色：完美', '银色', '2023-02-23 17:48:46', 5);
INSERT INTO `data` VALUES (14304, 'j***香', 5, '老公送的新年礼物，用来给我画画的，谢谢老公。尺寸刚刚好，质量也非常好，店家的包装太用心了，值得推荐！值得购买的产品，做工非常精细，比想象中的好，推荐大家尝试。', '银色', '2022-12-31 20:11:12', 7);
INSERT INTO `data` VALUES (14305, 'j***萝', 5, '外观非常不错，质感很好\n外观材质：设计的非常棒，材质精细\n屏幕效果：屏幕效果比较亮，色彩比较鲜艳\n运行速度：运行速度很快，满意\n轻薄程度：属于超薄型的，很不错的一款商品\n其他特色：音乐质感非常好', '银色', '2023-01-12 12:35:38', 3);
INSERT INTO `data` VALUES (14306, '爱***6', 5, '显示效果非常不错，平板10.9的大小看电影非常赞，非常清晰，两边都有声道，氛围感满满，作为平板，平时也就是玩个小游戏追追剧，基本上充满电能看五部电影以上，费电很低，粉色带着壳没拍，效果比想象中还美，喜欢就买，买了就没有所谓的这个不好那个不好', '粉色', '2023-02-04 01:13:19', 1);
INSERT INTO `data` VALUES (14307, 'j***U', 5, '外观材质：外观精美，非常漂亮，高大上\n屏幕效果：屏幕分辨率很好，眼睛看着很舒服\n运行速度：运行速度超快，没有一点卡顿\n轻薄程度：很轻薄，方便随身携带\n其他特色：苹果的产品还是信的过的，还会再次购买', '黄色', '2023-02-20 00:32:22', 3);
INSERT INTO `data` VALUES (14308, 'u***7', 5, '首先一拿到手感觉就质感十足，颜值比前几代好多了，屏幕清晰度很棒，以后可以开开心心追剧了，使用非常流畅，真的很香。', '蓝色', '2023-03-11 05:26:17', 5);
INSERT INTO `data` VALUES (14309, 'k***1', 5, '外观材质：最新款的，还是挺漂亮的\n屏幕效果：苹果的屏幕一直都是最顶级的\n运行速度：非常好，性能过剩的\n轻薄程度：还可以吧，直角边颜值担当，但是手感不去弧形边的手感\n其他特色：给孩子上网课用的，操作简单，反应快', '粉色', '2023-01-03 20:45:56', 3);
INSERT INTO `data` VALUES (14310, 'M***N', 5, '外观材质：外观很好看，比上一代要好看\n屏幕效果：屏幕分辨率清晰度很好，很清楚\n运行速度：新机运行速度很快，没有卡顿\n轻薄程度：重量比PRO轻很多，很便携\n其他特色：可以搭配键盘和笔', '蓝色', '2022-11-19 17:53:34', 3);
INSERT INTO `data` VALUES (14311, 'j***a', 5, '之前用的ipad 是16年买的，其实就是好多软件不能用了，才想着换个新的。苹果的东西真的不会失望，和手机，电脑传输快，连接一点没有问题，颜色也喜欢，真的很不错。', '蓝色', '2023-01-20 14:37:40', 1);
INSERT INTO `data` VALUES (14312, '大****', 5, '送给爱画画晚辈的新年礼物。在9代和10代之间纠结了一下，最后还是觉得买性能更好的1代，不过因为换了typeC的接口，所以需要配一个转接头才能用pencil。pad本身很好用，很丝滑。', '蓝色', '2023-01-30 21:56:13', 1);
INSERT INTO `data` VALUES (14313, 'P***0', 3, '这代也就那样吧，我是大冤种', '银色', '2023-02-16 11:17:06', 7);
INSERT INTO `data` VALUES (14314, '淘***货', 5, '外观材质：外观设计比之前产品更美观，显高档，材质好。\n屏幕效果：屏幕一点就开，屏幕显示清晰干净。\n运行速度：运行速度很快，好用。\n轻薄程度：轻薄程度：厚薄度正好轻便。', '蓝色', '2023-01-15 17:08:37', 3);
INSERT INTO `data` VALUES (14315, '想***柔', 5, '外观材质：我给小红买的蓝色版的，非常漂亮。\n屏幕效果：显示效果很好。\n运行速度：运行速度非常流畅，不错的硬件，搭配苹果的iOS系统，完全是绝配。\n轻薄程度：非常轻薄，手感很好。\n其他特色：常用办公、追剧很合适的。', '蓝色', '2023-02-08 23:33:00', 3);
INSERT INTO `data` VALUES (14316, '初***6', 5, '东西不错，物有所值。系统非常的流畅，使用起来很丝滑。一直信赖京东', '蓝色', '2023-02-07 00:34:43', 5);
INSERT INTO `data` VALUES (14317, '丸***女', 5, '公司年会抽奖准备的一等奖?三个pad\n外观材质：简洁清爽，新版越来越好\n屏幕效果：非常清晰，显示的很好\n运行速度：七八年之前买过的，运行速度很快\n轻薄程度：很轻很薄，拿着很舒服', '蓝色', '2023-03-03 19:42:22', 3);
INSERT INTO `data` VALUES (14318, 'i***2', 5, '屏幕效果：屏幕超清晰，显示效果细腻\n外观材质：镁铝合金材质，金属质感让人摸起来很舒服，同时四边是很圆滑的弧度不刮手。西瓜红颜色并不是那种淡粉色很好看\n轻薄程度：苹果的工业设计顶尖，超轻薄\n运行速度：新处理器运行速度确实快，闪存也是顶级，程序响应很快', '粉色', '2022-12-24 19:21:04', 3);
INSERT INTO `data` VALUES (14319, '爱***D', 5, '在外观方面，iPad 10 历改了此前的老旧形象，采用了极具现代化的全面屏设计，正面看起来与高端平板电脑一样，四边等宽的屏幕边框，屏占比非常高，看起来非常漂亮。\n整体机身由金属制成，一体成型的工艺非常出色，边缘方方正正，质感和手感非常好，机身坚固耐用，而且不易留下指纹。新增的配色也给iPad 10添加了活力，你可以在银色、蓝色、粉色和黄色之间进行选择。每种颜色都有自己的美感，适合不同的用户喜好。iPad 10 配备了 Liquid 视网膜显示屏，分辨率为2360 x 1640像素，可提供清晰的图像。不仅如此，再现的图像色彩也极为鲜艳，在看电影、上网或玩游戏时，你一定会获得极佳的视觉体验。\n屏幕尺寸为10.9英寸，虽然不算大，但足以满足你的学习或娱乐需求。值得注意的是，这块屏幕还拥有True Tone技术，它将有助于自定义颜色和光强度以适应照明条件。当你在阳光充足的条件下使用屏幕时，它仍然是相当清晰的。特别是当你长时间看屏幕时，它会帮助你减轻眼睛疲劳。在核心性能方面，是苹果产品最大的优势，iPad 10 尽管搭载了两年前的苹果A14芯片，再加上无广告的流畅系统，但它仍然比竞争对手强许多', '蓝色', '2022-12-25 02:49:46', 2);
INSERT INTO `data` VALUES (14320, '笨***憨', 5, '外观材质：磨砂质感，有份量\n屏幕效果：分辨率很高，屏幕非常清晰\n运行速度：运行速度很快\n轻薄程度：厚度正好，手感很棒，很喜欢\n其他特色：粉色的非常漂亮，配了透明的保护套，很好看，很赞', '粉色', '2023-02-21 15:35:07', 2);
INSERT INTO `data` VALUES (14321, '愛***乐', 5, '一直纠结该给孩子买个什么平板电脑，因为疫情原因，刚好又碰到双十一搞活动就给孩子买了，用来上网课的，流畅，电池耐用，清晰，屏幕大，音量不失真。', '蓝色', '2022-11-25 12:17:24', 1);
INSERT INTO `data` VALUES (14322, '_***九', 5, '物流很快，质感超好，触感很好，很流畅，超级喜欢，蓝色和我手机一个色号，很搭配，超级喜欢，入手不悔。', '蓝色', '2022-11-06 14:37:31', 5);
INSERT INTO `data` VALUES (14323, 'u***y', 5, '轻薄程度：这个本很薄！上手也轻！适合学生党上网课学习之类，追剧也不错！\n外观材质：买了大众的银色，好买保护壳，颜色也看着舒适！\n屏幕效果：很高清，灵敏度也不错！\n自己单买了电容笔、钢化膜and保护壳一系列单品，马上就可以上手用了！！', '银色', '2023-02-09 12:28:56', 3);
INSERT INTO `data` VALUES (14324, '大***情', 5, '家里七年前买的的平板坏了，正好也该换代了，疫情在家上网课还是得平板方便，就在京东自营店里还是选了一款苹果的平板，由于没货等了一个星期才发货，收到平板包装完好，配件齐全，开机设置了一下非常的好用，速度反应就是快，画面显示很柔和，全面屏无边框就是好看，长期看屏幕也不刺眼，非常满意的一款平板。', '蓝色', '2023-02-07 19:11:34', 5);
INSERT INTO `data` VALUES (14325, '柚***f', 5, '外观材质：是真好看啊\n屏幕效果：很不错。\n运行速度：不错呢。\n轻薄程度：刚好哦。\n其他特色：一直很喜欢，看电视啊玩游戏都不错哦！\n朋友生日，送礼用哦，一点也不丢面子！朋友也很喜欢这个颜色！', '粉色', '2023-01-13 14:39:24', 2);
INSERT INTO `data` VALUES (14326, '洪***g', 5, '给宝宝买来看宝宝巴士的，手机屏幕太小对眼睛不好、看平板眼睛不那么累，还可以让宝宝跟着学习一下生活好习惯，平板份量蛮轻的，操作简单明了，很实用，工作学习都OK', '蓝色', '2023-03-01 13:10:29', 4);
INSERT INTO `data` VALUES (14327, 'j***j', 5, '外观材质：挺好的\n屏幕效果：屏幕挺好，色测丰富\n运行速度：速度不错\n轻薄程度：比较重，尺寸不是很好，设计有点方\n其他特色：使用起来还是很流畅的，音质相当好，特别喜欢iPad的音质，令人着迷！', '蓝色', '2023-03-12 11:01:52', 2);
INSERT INTO `data` VALUES (14328, '散***鹿', 5, '外观非常精致，全面屏视觉效果就是不一样；平板和手机不一样，屏幕效果确实差一些，颗粒感很严重，但刷视频还算清晰；64G运行也很快，特别轻薄，而且内存也应该够用，总得来说还不错。', '蓝色', '2023-02-01 17:17:03', 3);
INSERT INTO `data` VALUES (14329, 'S***0', 5, '漂亮的机型，经典的银色，国行新机，很喜欢！平常追剧玩游戏还是够用的，性价比很高！', '银色', '2023-03-10 22:34:15', 7);
INSERT INTO `data` VALUES (14330, 'j***m', 5, '系统流畅，功能强大，速度很快，手感很舒服，苹果真的好用，名不虚传，做工精细，看剧舒服，追剧神器，京东快递物流很快，服务一流，相信京东', '银色', '2023-02-07 18:35:08', 3);
INSERT INTO `data` VALUES (14331, '挖***屎', 5, '外观材质：质量很好，外观也很好看\n屏幕效果：屏幕效果很不错\n运行速度：运行速度很快，很喜欢\n轻薄程度：很薄，特别喜欢\n其他特色：充电速度可以的，电池耐久也不错，关键是好看！！！', '银色', '2022-11-12 23:32:46', 2);
INSERT INTO `data` VALUES (14332, '枼***蝶', 5, '外观材质：蓝色的外壳，看着很舒服\n屏幕效果：屏幕显示效果很好\n运行速度：快\n轻薄程度：轻薄的iPad', '蓝色', '2023-01-04 22:30:04', 4);
INSERT INTO `data` VALUES (14333, '娜***a', 5, '外观材质：还可以，磨砂的感觉\n轻薄程度：非常的轻薄，整个机身也不是很重\n屏幕效果：还是可以的，看起来很舒服，\n运行速度：速度也很快，用来做视频，感觉也很快，加载的也很快。', '银色', '2023-02-03 10:56:49', 2);
INSERT INTO `data` VALUES (14334, 'c***z', 5, '2022年新款10.9英寸Apple iPad\n外观材质：美观大方 材质优良\n屏幕效果：非常清晰\n运行速度：够快，够满意\n轻薄程度：超薄，轻便\n其他特色：苹果的售后服务相当好，和客服沟通是很愉快的体验。', '蓝色', '2022-11-26 17:28:53', 3);
INSERT INTO `data` VALUES (14335, '清***3', 5, '终于收到货了,给孩子买的，给孩子买来上网课用的，孩子很喜欢，爱不释手，操作很流畅，物流速度也很快，系统也很好用！很惊艳，颜色漂亮，系统流畅！金属材质质感超好，屏幕清晰，运行速度很快，轻薄适手！超棒！\n京东物流速度很快，送货上门！赞', '蓝色', '2023-02-10 07:50:20', 3);
INSERT INTO `data` VALUES (14336, 'C***v', 5, '外观材质：外观蓝色高级，应该碰撞都没事\n运行速度：挺快，很流畅。玩游戏玩王者荣耀体验极好\n轻薄程度：很薄，手感舒适。\n屏幕效果：全屏大屏幕，看电视追剧，学习非常不错。', '蓝色', '2023-01-09 19:44:50', 2);
INSERT INTO `data` VALUES (14337, '胖***爸', 5, '相比去年升级了很多，屏幕变大了，方框也变方了，更有质感了，购新机的感觉很棒!以前一直都是在实体店买，这次选择了网上买，不光是正品，价格还实惠！', '银色', '2023-01-05 21:38:49', 5);
INSERT INTO `data` VALUES (14338, 'j***n', 5, '到货速度非常快，当天下单当天到货，非常有京东物流靠谱的保障。\n外观材质：材质很舒服，用起来很有简单就能上手。\n\n运行速度：速度很快，很流畅，系统稳定性很难高，画质也很优秀', '蓝色', '2023-03-04 17:59:55', 4);
INSERT INTO `data` VALUES (14339, 'K***源', 5, '平板很不错，包装严实，孩子学习再也不用看手机了，超级喜欢，\n外观材质：很漂亮，很有质感\n屏幕效果：很清晰，分辨率很高，\n运行速度：很快，\n轻薄程度：很薄\n其他特色：京东快递就是快，发货快', '粉色', '2023-01-30 19:28:11', 2);
INSERT INTO `data` VALUES (14340, 'j***6', 5, '外观材质：外观材质：挺精致挺好看的太喜欢那个蓝色的了手感也不错很容易上手 \n屏幕效果：屏幕效果：非常好 \n运行速度：快\n轻薄程度：挺轻巧的拿着也不会觉得重', '蓝色', '2023-03-18 08:07:24', 3);
INSERT INTO `data` VALUES (14341, '璀***_', 5, '京东小哥刚送到就迫不及待拆箱体验了，打开的刹那间确实被惊艳到了，远峰蓝色真的非常时尚，高端大气上档次，颜值在线，第十代运行速度非常快，整体比较轻薄，携带也方便，买的A+会员版还便宜了不少，非常满意的购物体验。', '蓝色', '2023-03-15 10:50:13', 4);
INSERT INTO `data` VALUES (14342, 'z***a', 5, '2022版新款iPad屏幕大了，厚度也增加，变厚了，拿在手上手感反而轻了。外观很满意。\n另一方面，这款iPad的CPU和分辨度数据，不比上一版高出许多，所以，现在买的话，性价比更高的应该是上一款。', '银色', '2023-03-19 20:01:36', 3);
INSERT INTO `data` VALUES (14343, 'j***1', 5, '话说!~只能用快，好，来形容啦!~嘻嘻!`下次再找你!~信誉很好,,,,,,发货很及时　很喜欢!也喜欢店家,很热情~!买来这个是送人的,她很喜欢.卖家的贴心让我感到很温暖.以后我还会来选的.店主态度特好，我会再次光顾的.质量很好，希望更多的朋友信赖.　很喜欢!也喜欢店家,很热情~!一个字 好，两个字 很好，三个字 太好了!哈哈&hellip;&hellip;', '蓝色', '2022-11-06 21:46:07', 4);
INSERT INTO `data` VALUES (14344, 'j***6', 5, '外观材质：特别高端大气上档次！\n屏幕效果：特别清晰！\n运行速度：特别快！\n轻薄程度：拿着非常轻便！\nipad10代质量品质没得说，绝对是数一数二。颜值也特别棒，我选的蓝色，太喜欢这个配色了！', '蓝色', '2023-01-18 10:19:06', 2);
INSERT INTO `data` VALUES (14345, '超***员', 5, '整体机身由金属制成，一体成型的工艺非常出色，边缘方方正正，质感和手感非常好，机身坚固耐用，而且不易留下指纹。新增的配色也给iPad 10添加了活力，你可以在银色、蓝色、粉色和黄色之间进行选择。每种颜色都有自己的美感，适合不同的用户喜好。iPad 10 配备了 Liquid 视网膜显示屏，分辨率为2360 x 1640像素，可提供清晰的图像。不仅如此，再现的图像色彩也极为鲜艳，在看电影、上网或玩游戏时，你一定会获得极佳的视觉体验。外观材质：外观很好看，我买的蓝色的，饱和度很高。\n屏幕效果：屏幕效果不错，感觉特别惊艳，显示效果很好。\n运行速度：运行速度快，反应迅速。', '蓝色', '2023-01-20 23:44:18', 3);
INSERT INTO `data` VALUES (14346, 'j***i', 5, '外观材质：很好 很漂亮 手感很好啊啊\n屏幕效果：很好 很细腻 效果很好啊啊啊\n运行速度：速度很快 比以前老款好很多啊啊啊\n轻薄程度：非常好 很轻薄 跟以前差不多啊啊 很好啊', '银色', '2023-02-16 17:54:43', 2);
INSERT INTO `data` VALUES (14347, 'm***t', 5, '苹果的东西就是很精致，也不知道现在是第几代了，品质一如既往的好，满意。\n外观材质：结实，有点太滑了\n屏幕效果：非常完美\n运行速度：流畅，很爽\n轻薄程度：还行\n其他特色：电池也很厉害', '黄色', '2022-11-24 18:34:09', 2);
INSERT INTO `data` VALUES (14348, '苏***狗', 5, '真心喜欢好看的东西，哈哈。这个蓝色太好看了，心水。但确实小了一点，不过日常用来发个微信看个剧足够了。流畅，自然，很舒服。虽然吧，我觉得home键放在顶端真的很不方便。但没办法，如果放下面，就需要很大的位置。挺好的。可以入手。', '蓝色', '2022-12-21 00:33:28', 2);
INSERT INTO `data` VALUES (14349, 'j***G', 5, '这个颜色的看起来也特别好看，，买的64g的 就平时看电视剧看视频用的，应该够用了。', '蓝色', '2023-02-14 10:11:18', 3);
INSERT INTO `data` VALUES (14350, 'j***0', 5, '疫情期间儿子上网课，果断买了22最新款iPad，22款无返回键，在外观上有很大提升，性能和电磁续航更好，整体耐用性会更久，整体我们都很满意。\n外观材质：很好\n屏幕效果：很好\n运行速度：流畅\n轻薄程度：很好', '蓝色', '2023-01-02 15:19:22', 2);
INSERT INTO `data` VALUES (14351, '凯***1', 5, '平板电脑外观简洁大方，操作简单，运行速度快平板电脑很好用，功能很强大，很实用，质量也很好平板电脑，外观设计，看着大气，简洁', '银色', '2022-12-07 16:41:19', 3);
INSERT INTO `data` VALUES (14352, 'j***w', 5, '外观材质：全是纸包装，手感很好。\n屏幕效果：不错，看得过去。\n运行速度：很快A14还是可以的。\n轻薄程度：很薄，拿着也不重，大小也足够。\n其他特色：送货很快，凌晨买的下午就到了。', '银色', '2023-02-28 17:50:45', 2);
INSERT INTO `data` VALUES (14353, '清***风', 5, '外观材质：金属包边非常好看\n屏幕效果：十分灵敏\n运行速度：非常快，一点都不卡顿，使用体验非常好\n轻薄程度：很薄，是理想中的样子\n其他特色：按键灵敏，物流也非常快，在镇上第二天一下午就到了', '银色', '2023-02-27 21:26:24', 2);
INSERT INTO `data` VALUES (14354, 'A***儿', 5, '外观材质：外观很漂亮 蓝色的外壳很好看 以前的都是银色 这回换个颜色尝试一下也很值得！！\n屏幕效果：清晰 视觉体验好 无论是刷剧还是视频会议 拍照都和不错\n运行速度：速度很快\n轻薄程度：比较薄', '蓝色', '2022-11-30 08:55:49', 2);
INSERT INTO `data` VALUES (14355, '燕***雨', 5, '超级喜欢这个粉色，真的太爱了，摸起来很舒服，厚度也很薄使用体验感那更不用说，然后这个价格也是非常实惠了，没别的，喜欢就买，用的舒服喜欢就好???', '粉色', '2022-12-03 14:28:31', 4);
INSERT INTO `data` VALUES (14356, '星***5', 5, '生日礼物嘻嘻，咱也不懂啥特专业的那什么运行速度啥的，反正玩了两天了，玩游戏很顺畅，拿着也挺轻便的，有点大，一直担心磕了碰了的，很喜欢很喜欢很喜欢，后边可能会再买配套的笔和壳啊乱七八糟的，就是男朋友说看不出来紫色。他手机就是紫的', '银色', '2022-12-22 22:31:42', 4);
INSERT INTO `data` VALUES (14357, '黄***z', 5, '外观材质：材质铝合金的，很不错\n屏幕效果：屏幕很给力，分辨率很高\n运行速度：运行速度很快，不卡顿\n轻薄程度：不是很厚，方便携带\n其他特色：毕竟是新款，总体来说很好用，体验效果很棒', '蓝色', '2022-12-13 00:14:25', 2);
INSERT INTO `data` VALUES (14358, 'b***3', 5, '已经用上了，孩子喜欢。蓝色也是个男孩子用，很好。京东买过好几次iPad了。旧的发回去回收了！暂时没问题，东西好用。给宝宝生日礼物', '蓝色', '2023-01-07 15:50:57', 4);
INSERT INTO `data` VALUES (14359, '装***猫', 5, '十代iPad，京东购买，能保证原装正品，而且价钱也比官网便宜。另外送货很快，第二天就收到了。新款iPad，外观漂亮，屏幕够大，看着舒服。反应速度快，没有卡顿，比非iOS的平板好用多了。软件丰富，用得非常满意。', '银色', '2023-03-04 13:43:35', 3);
INSERT INTO `data` VALUES (14360, '小***布', 5, '蓝色真的好漂亮啊，好喜欢。屏幕显示也很好，宝宝上网课就更有动力了。\n运行速度：快，很快。\n轻薄程度：很轻，单单手拿久了还是有点吃力。\n屏幕效果：显示细腻，颜色真实。', '蓝色', '2023-02-20 19:31:55', 3);
INSERT INTO `data` VALUES (14361, 'e***4', 5, '外观材质：很不错。铝合金外壳，高端大气上档次\n屏幕效果：还可以。虽然是非全贴合的屏幕，但是性价比高\n运行速度：很快。很快不卡顿\n轻薄程度：很轻薄\n其他特色：苹果的东西没得说', '银色', '2023-01-13 19:55:50', 2);
INSERT INTO `data` VALUES (14362, '蕊***4', 5, '买的生日礼物嘻嘻，咱也不懂啥特专业的那什么运行速度啥的，反正玩了两天了，玩游戏很顺畅，拿着也挺轻便的，有点大，一直担心磕了碰了的，很喜欢很喜欢很喜欢，后边可能会再买配套的笔和壳啊乱七八糟的，就是男朋友说看不出来紫色。他手机就是紫的', '银色', '2022-12-22 22:29:13', 4);
INSERT INTO `data` VALUES (14363, 'u***e', 5, '物流很快。平板轻薄好拿，磨砂外壳，颜色好看，有质感。屏幕反应灵动，屏幕尺寸大，画质清晰，运行速度也不错，色彩和声音还原度高，娃儿上网课和追剧都不卡，电池也耐用。这款平板总体性价比很高', '蓝色', '2023-01-03 23:29:01', 3);
INSERT INTO `data` VALUES (14364, 'j***a', 5, '外观材质：非常好看的外观，材质应该是铝合金，拿在手上很有质感，不愧是最好的平板产品。\n屏幕效果：非常好，支持2k以上视频，清晰度很高，而且比较柔和。\n运行速度：速度很快。使用的是A13芯片，很好。', '蓝色', '2023-03-18 12:39:22', 2);
INSERT INTO `data` VALUES (14365, '零***鸞', 5, '非常流畅很喜欢zhu?ti?o\n屏幕效果：质感超强，屏幕大小也刚好\n运行速度：运行速度快\n轻薄程度：很轻薄\n外观材质：满满的金属质感，手感特别棒\n很喜欢，特别棒！！！！', '银色', '2022-12-18 10:21:59', 2);
INSERT INTO `data` VALUES (14366, '你***吗', 5, '给女朋友买的，她非常喜欢，外观精致漂亮，系统与系统运行流畅，续航能力优秀，全面屏设计拓展了视觉空间，通畅，游戏追剧都非常棒但是拿到手以后，确实非常招人喜欢，全新外观设计，没有了 home 键，更大的屏幕，更窄的边框。', '银色', '2023-02-11 16:05:31', 3);
INSERT INTO `data` VALUES (14367, '心***生', 5, '外观材质：可以可以很OKOK。\n屏幕效果：中规中矩，看起来挺好的?。\n运行速度：给力流畅运行ｇｅｉｌｅｉ游戏，再也不用担心发烫了。\n轻薄程度：嗯不错，拿起来薄薄的哈哈', '银色', '2023-02-11 10:43:34', 2);
INSERT INTO `data` VALUES (14368, 'j***4', 5, '在京东购买平板就是方便、省心。前一晚下的单第二天上午就收到了，包装完好，机子做工精致手感很好，开机运行非常流畅。特别是京东快递的小哥非常给力，下单时忘了地址上的电话号码己换，小哥送到家时因电话打不通一直拍门让我亲手拿到才放心离开。非常满意！', '蓝色', '2023-01-31 12:06:13', 5);
INSERT INTO `data` VALUES (14369, 'c***J', 5, '配送很快，拿着很轻\n有充电线和充电头\n用惯了苹果系统\n很顺畅，有指纹解锁，挺方便的\n屏幕看视频看书很舒服\n其他的再用用看', '银色', '2022-11-18 10:13:18', 3);
INSERT INTO `data` VALUES (14370, '芮***3', 5, '男朋友给买的生日礼物嘻嘻，咱也不懂啥特专业的那什么运行速度啥的，反正玩了两天了，玩游戏很顺畅，拿着也挺轻便的，有点大，一直担心磕了碰了的，很喜欢很喜欢很喜欢，后边可能会再买配套的笔和壳啊乱七八糟的，就是男朋友说看不出来紫色。他手机就是紫的', '银色', '2022-12-22 22:17:39', 4);
INSERT INTO `data` VALUES (14371, 'j***J', 5, '给孩子买来学习用的  大屏幕能比小的对眼睛好点。看屏幕没有那么累。画质清晰。\n外观材质：好\n屏幕效果：清晰\n运行速度：快\n轻薄程度：轻薄\n我和孩子都很喜欢，棒棒棒！！！', '银色', '2023-01-04 12:08:05', 2);
INSERT INTO `data` VALUES (14372, '蕊***青', 5, '男友给买的生日礼物嘻嘻，咱也不懂啥特专业的那什么运行速度啥的，反正玩了两天了，玩游戏很顺畅，拿着也挺轻便的，有点大，一直担心磕了碰了的，很喜欢很喜欢很喜欢，后边可能会再买配套的笔和壳啊乱七八糟的，就是男朋友说看不出来紫色。他手机就是紫的', '银色', '2022-12-22 22:14:28', 4);
INSERT INTO `data` VALUES (14373, 'j***g', 5, '外观材质：好看 手感也比之前那种好 不割手了 \n屏幕效果：色彩饱和度一流 看时间久点也不会累眼睛\n运行速度：打游戏 学习完全够用 电池也耐用\n轻薄程度：很有质感 不是很薄 很舒服', '银色', '2023-03-20 20:26:07', 2);
INSERT INTO `data` VALUES (14374, 'j***y', 5, '外观材质：外观大气漂亮，有质感，\n屏幕效果：分辨率特别高，显示很清晰\n运行速度：运行速度杠杠的啊，太丝滑了\n轻薄程度：很轻很方便，用起来体验很好', '蓝色', '2023-01-17 21:08:05', 2);
INSERT INTO `data` VALUES (14375, '沈***9', 5, '一直都挺喜欢苹果的产品、很流畅，很经久。这一款没有了按钮，全屏，显得更大了。 很舒服、导致不太喜欢用手机了、手机太小、 哈哈 建议购买。 我喜欢粉色来着，但是没货，发现银色也很耐看～', '银色', '2022-11-24 16:27:39', 2);
INSERT INTO `data` VALUES (14376, '少***果', 5, '屏幕效果：高清\n运行速度：丝滑\n轻薄程度：轻薄\n颜色好看的。本来想买粉色的一直没货。蓝色的也很好看喜欢的可以购买啦', '蓝色', '2023-01-07 14:28:46', 3);
INSERT INTO `data` VALUES (14377, 'a***4', 5, '外观材质：四面窄框，很舒适，银色质感极好\n轻薄程度：真是薄啊，不带保护套那在手里感觉就比手机还薄\n屏幕效果：苹果的屏幕就是看着舒适，色彩亮度都是很好的\n运行速度：也是极快的', '银色', '2023-02-25 08:59:29', 2);
INSERT INTO `data` VALUES (14378, '笑***8', 5, '比较喜欢蓝色的，趁着年货节优惠力度大，就迫不及待的下了一个，第二天就到了，画质非常好，分辨率高，运行速度很快，追剧很方便，非常满意', '蓝色', '2023-01-13 11:47:24', 3);
INSERT INTO `data` VALUES (14379, 'j***5', 5, '外观材质：非常好\n屏幕效果：精细\n运行速度：很快\n轻薄程度：轻薄程度：比较 一般\n其他特色：包装与以前比有变化，没有塑膜。', '蓝色', '2022-11-26 10:08:16', 2);
INSERT INTO `data` VALUES (14380, 'x***i', 5, '收到货了哟，包装很精美严实，不用担心有碴\n碰的现象，传输文件非常快，很快就用上了新\n手机，客服服务态度好，遇到不懂的问题也会\n细心讲解，手机外形外观精致，屏幕音效很\n好，运行速度快，第一感觉十分满意，期待后\n续使用情况', '银色', '2023-02-05 14:49:11', 2);
INSERT INTO `data` VALUES (14381, 'W***y', 5, '心心念念收到货了，物流很给力，东西不错，非常棒，超级喜欢，流畅，以后可以用来学习了，c口线更新了，感觉也可以，\n运行速度：黑很快，用了教育优惠，很香', '蓝色', '2023-02-21 20:30:24', 3);
INSERT INTO `data` VALUES (14382, '周***师', 5, '外观材质：非常好。\n屏幕效果：非常好\n运行速度：好。\n轻薄程度：好', '蓝色', '2023-03-16 09:50:29', 1);
INSERT INTO `data` VALUES (14383, 'J***J', 5, '不说别的 只说性价比。这款iPad实际上比iPad Pro要实惠太多。只是普通家用不需要太多移动分屏或者图像处理 足够使用了。芯片至少三年内不落伍 电池很耐用。屏幕看视频很舒服。配合PadOS 效率很高。性价比之选！', '蓝色', '2023-03-04 16:12:52', 5);
INSERT INTO `data` VALUES (14384, 'z***m', 5, '包装完好，很轻薄，外观好看，边框比之前几代产品都要窄一些，看起来很高端，屏幕清晰，色彩鲜艳不刺眼，拍照像素很高，运行也比较流畅，体验感不错。', '银色', '2023-01-30 17:27:26', 3);
INSERT INTO `data` VALUES (14385, 'w***9', 5, '京东自营就是有速度，效率高。即使今年的冬天北方非常寒冷，也做到了今天下单，次日达！打开包装确认了一下机器，首先颜色也是想要的蓝色，非常好！开机速度很快，液晶屏清晰，和之前的型号比较了一下，确实有很大的改进。', '蓝色', '2023-01-27 08:27:22', 3);
INSERT INTO `data` VALUES (14386, '过***l', 5, '外观材质：iPad 10代的外观和最新的iPhone对齐了，和iPad9代一样的合金材质很不错。\n屏幕效果：屏幕还是一贯的好\n运行速度：允许速度流畅\n轻薄程度：重量和厚度均衡', '银色', '2023-01-16 05:09:36', 2);
INSERT INTO `data` VALUES (14387, '活***2', 5, '超级完美，颜色非常好看，清晰度非常赞，超级流畅线条设计完美。爱了。', '粉色', '2023-02-17 13:56:49', 5);
INSERT INTO `data` VALUES (14388, 'j***h', 5, '超级喜欢超级可爱超级无敌，心仪已久的Ipad终于到手啦！看视频方便，上网课方便，追电影电视剧方便，视频聊天方便。物美价廉，你的最爱?', '蓝色', '2023-01-09 11:10:11', 5);
INSERT INTO `data` VALUES (14389, 'n***g', 5, '用了几天才评论的，一切都很完美，无可挑剔，给老婆用的，办公和娱乐都能满足。\n外观材质：金属材质，美观整洁时尚还耐用\n屏幕效果：逼真细腻\n运行速度：顺滑流畅\n轻薄程度：拿起来不感觉沉，放包里刚刚好', '银色', '2023-02-26 22:24:23', 3);
INSERT INTO `data` VALUES (14390, '草***1', 5, '运行流畅，画质清晰，京东还便宜200块，很香，看视频，玩游戏没有任何问题，屏幕尺寸合适，配充电器和线，电池续航8小时没一点问题', '蓝色', '2023-01-23 10:08:09', 2);
INSERT INTO `data` VALUES (14391, '小***咯', 5, '终于收到我需要的宝贝了，东西很好，价美物廉 ，谢谢客服同学!说实在，这是我京东购物来让我最满意的一次购物。无论是客服的态度还是对物品，我都非常满意的。客服态度很专业热\n情，有问必答，回复也很快，我问了不少问题，他都不觉得烦，都会认真回答我，这点我向客服表示由衷的敬意，这样的好店铺可不多。', '粉色', '2022-12-30 16:34:41', 4);
INSERT INTO `data` VALUES (14392, '船***卷', 5, '更大的屏幕，更细巧的边框，看看视频上个网课，玩些游戏也绰绰有余，完美满足了所有需求。屏幕刷新高，系统丝滑，作为礼物也非常合适。', '蓝色', '2023-02-06 14:50:31', 2);
INSERT INTO `data` VALUES (14393, 'j***2', 5, '世界名牌苹果平板电脑，屏幕清晰，外观漂亮，蓝色的我喜欢。运行速度很快，轻薄。上滑回到主菜单，家人都喜欢用。京东自营质量有保障，以后会经常来的。', '蓝色', '2023-03-14 15:13:05', 3);
INSERT INTO `data` VALUES (14394, '七***猫', 5, '屏幕效果：效果清晰\n运行速度：A14的系统 运行速度很快\n轻薄程度：很薄 手感很好\n真的很喜欢，完全超出期望值，发货速度非常快，包装非常仔细、严实，运送速度很快，很满意的一次购物！', '粉色', '2022-11-18 11:23:07', 2);
INSERT INTO `data` VALUES (14395, '鸡***子', 5, '外观材质：包装非常完美 屏幕很大 非常清新 完全可以满足日常的使用\n屏幕效果：屏幕非常大 非常清晰 看电视追剧打游戏都不在话下\n运行速度：苹果平板的运行速度完全是其他品牌的平板不能比的', '蓝色', '2023-01-03 14:50:46', 3);
INSERT INTO `data` VALUES (14396, '南***0', 5, '首先外观上看，十代比九代多了个颜色选择，其次也从圆边改为直角边，我很喜欢这种，指纹解锁也合并在上端电源键，加大屏幕尺寸（从10.2到10.9了），虽然是A14芯片，但也不输A15，本人亲测过，前置摄像头1200万，满足自拍需求，也能4K录像，新一代平板物超所值。', '蓝色', '2023-03-01 13:54:40', 3);
INSERT INTO `data` VALUES (14397, '你***难', 5, '外观材质：铝合边框 无home键的快乐\n屏幕效果：很完美的清晰度 看电影很快乐\n运行速度：嘎嘎快 过多几年就不一定了 先买先享受\n轻薄程度：贼轻薄 手感巨好', '银色', '2022-12-31 13:46:15', 2);
INSERT INTO `data` VALUES (14398, 'L***w', 5, '外观材质：很好的质量，很细腻的那种手感\n屏幕效果：清晰度很好，流畅度很好\n运行速度：很流畅很丝滑\n轻薄程度：轻薄手感好，很好很好很好\n其他特色：最新款基础版ipad，256g价格卡得很准', '蓝色', '2023-01-20 15:17:18', 2);
INSERT INTO `data` VALUES (14399, 'R***x', 5, '外观材质：超出预期，质量很好，做工精细，满意\n屏幕效果：大品牌，屏幕很大，给弟弟学习用\n运行速度：性价比高，性能流畅，舒服\n其他特色：跟描述的是一样的，很显高档，物美价廉', '银色', '2023-03-02 13:03:47', 2);
INSERT INTO `data` VALUES (14400, '迷***妹', 5, '苹果的平板能用很多年都不卡，看到这个新款，很是喜欢，下定决心有买了一个，买来给孩子看动画片用的，反应很快，用起来特别顺手，我自己也能玩会游戏，追追剧！点赞', '蓝色', '2023-02-18 14:48:03', 3);
INSERT INTO `data` VALUES (14401, '成***苟', 5, '1是真实的配置，平板和卖家的介绍是一样的，先试用几天，感觉很不错，电池待机时间很满意。\n2.平板的屏幕大显示效果清晰，机身轻薄手感好，内存也足够大，东西货真价实，还送了很多的礼品。\n3.屏幕刚刚好，运行速度也很快，拿着也挺轻快的，便携性好，非常满意，A12芯片性能上应该够了，操作很流畅性能很强。屏幕色彩艳丽,显示效果非常好，电池也比较充足。', '蓝色', '2023-03-11 10:47:45', 2);
INSERT INTO `data` VALUES (14402, 'j***a', 5, '外观材质：摸起来很舒服，很不错\n屏幕效果：显示很好，看起来很舒服\n运行速度：很快，不卡顿\n轻薄程度：很好', '蓝色', '2022-12-28 10:31:28', 2);
INSERT INTO `data` VALUES (14403, 'B***8', 5, '每一代都那么惊艳，苹果忠粉了。这款已经使用了一段时间，特别流畅好用，比上一代有进步。设计美观，蓝色特别漂亮，很薄很便携。容量大小正好，芯片和内存很也棒，同时运行几个程序完全没压力，使用体验太赞了！?', '蓝色', '2022-12-30 15:07:00', 3);
INSERT INTO `data` VALUES (14404, 'c***k', 5, '粉色外观很好看孩子很喜欢，运行比较流畅，指纹解锁很灵敏，单纯的上网课足够用了，\n轻薄程度：比较轻薄\n运行速度：快\n屏幕效果：可圈可点', '粉色', '2022-12-22 21:05:10', 2);
INSERT INTO `data` VALUES (14405, 'j***3', 5, '一点都不卡 用起来很流畅  看了好久了 终于下单了 屏幕比较大 看剧很舒适 粉色的后屏 很喜欢 不知道后面会不会卡 打游戏也很安逸', '粉色', '2023-02-22 22:20:56', 2);
INSERT INTO `data` VALUES (14406, 'z***0', 3, '还行吧，没有想的那么多好，凑合用吧', '银色', '2022-12-25 18:27:23', 1);
INSERT INTO `data` VALUES (14407, 'j***1', 5, '买了好久终于到了，我很满意，质量也很好，颜色也很正，没有色差，很满意。', '粉色', '2022-12-09 23:40:20', 1);
INSERT INTO `data` VALUES (14408, '樱***1', 5, '拿到手就很喜欢，主要是为了追剧买的，之时想买粉色的，可是没有货了，看了评论后选的蓝颜色，到手很满意，非常经看，暂时用着很好', '蓝色', '2023-02-22 15:15:49', 3);
INSERT INTO `data` VALUES (14409, '俊***爺', 5, '外观材质：手感舒适\n屏幕效果：产品确实好\n运行速度：运行很流畅  不卡顿 电池电量也不错\n轻薄程度：适中 简约大方 \n值得购买 物美价廉 物有所值  客都回复及时', '蓝色', '2023-03-04 08:46:19', 2);
INSERT INTO `data` VALUES (14410, '-***-', 5, '挺好的，一直用来打游戏，画画，虽然没有高刷，但是流畅度没得说，屏幕观感也不错，相当不赖了，性价比也很高，再用个几年，也没啥问题', '粉色', '2023-02-22 18:13:06', 3);
INSERT INTO `data` VALUES (14411, 'u***u', 5, '10代平板外观干净整洁，屏幕清晰度很高，运行速度流畅，反应非常的快，也很轻薄，携带方便，给孩子上网课用保护眼睛，特别是晚上，很喜欢', '蓝色', '2023-01-16 23:40:43', 2);
INSERT INTO `data` VALUES (14412, 'j***U', 5, '这个颜色很喜欢，摸起来质感不错，百搭～包装也很大气，用来送人的话也是不错的选择，买来给孩子上网课的，孩子很喜欢，赞一个！', '银色', '2023-01-25 16:42:04', 6);
INSERT INTO `data` VALUES (14413, '小***8', 5, '这款ipad特别实用，大小可以上课用可以玩游戏，很舒服，就是充电口跟以前不一样，很好用。', '蓝色', '2023-01-31 18:05:51', 1);
INSERT INTO `data` VALUES (14414, 'u***1', 5, '真的是超级棒，之前的平板5年了，虽然还是很流畅，但还是打算换一个，所以换了这个新出的10代，不是专业画画的，所以这个够用了，用来上网课，看视频，等等，体验感良好，屏幕也很清晰，运行速度特别快，声音也挺好，总之买了不亏哎', '银色', '2022-12-31 12:15:27', 2);
INSERT INTO `data` VALUES (14415, '康***6', 5, '外观材质：很漂亮\n运行速度：快快快\n轻薄程度：中等，比较薄', '银色', '2023-02-12 14:21:17', 1);
INSERT INTO `data` VALUES (14416, 'j***y', 5, '屏幕效果：屏幕大小合适 粉色特别好看 给女儿用最合适\n运行速度：运行速度流畅 \n轻薄程度：大小合适 非常薄 拿到手上非常好的体验感\n外观材质：外观特别好看 粉色给人一种亮眼的感觉', '粉色', '2023-01-14 22:30:16', 2);
INSERT INTO `data` VALUES (14417, 'n***n', 5, '快递速度很快，东西很好，效果不错。\n以前的pad旧了，就要换一个，把家里一些无用的电子设备在京东上回收了，正好可以买一台新pad。\n新款确实好用多了，配个键盘就是一台小电脑，非常适合给孩子上网课。', '银色', '2023-01-18 15:42:33', 4);
INSERT INTO `data` VALUES (14418, '大***老', 5, '外观材质：外管质感看着比较高级，简洁的外观看着就挺舒服的\n屏幕效果：感觉iOS系统的桌面用着还是比较流畅的，使用感还不错\n运行速度：目前刚到手感觉还是不错的，没有任何卡顿\n轻薄程度：很薄，体验感真的不错，十代的体验感比九代要好上许多', '银色', '2023-01-29 13:10:34', 2);
INSERT INTO `data` VALUES (14419, '遇***然', 5, '看了一天电脑剧，电脑就没法热，在我印象当中，不发热的就特别好，流畅度也可以，物流很快，包装也很好，买这个主要就是为了追剧用，偶尔让孩子上一个网课，满意。', '银色', '2023-01-14 16:42:24', 3);
INSERT INTO `data` VALUES (14420, 'j***f', 5, '买个爸妈用的，二老很开心。屏幕、字体都变大了，效果比手机好很多。看屏幕再也不眼花了。发货速度很快，送货上门。包装完好，还查了序列号，是新机，没有问题。服务很满意。', '银色', '2023-01-15 16:21:19', 3);
INSERT INTO `data` VALUES (14421, 'j***u', 5, '外观材质：蓝色好看好看好看。\n屏幕效果：清晰度高\n运行速度：超级快。\n轻薄程度：很轻便，喜欢的', '蓝色', '2023-01-16 17:15:17', 3);
INSERT INTO `data` VALUES (14422, 'c***o', 5, '运行速度：很快 反应快，比老机器好用太多了\n屏幕效果：好看，新款就是好看，带出去也有面子\n轻薄程度：比较轻薄，好看，给力\n外观材质：常见的塑料盒吧，好看就行再来个保护套', '银色', '2023-01-30 21:46:17', 2);
INSERT INTO `data` VALUES (14423, 'w***6', 5, '很满意 好用 新颖 就是内存有128的就更完美了\n用来上网课 应该问题不大。颜色也非常好看 选了个蓝色  非常喜欢 屏幕也够大', '蓝色', '2023-01-05 21:31:18', 2);
INSERT INTO `data` VALUES (14424, 's***e', 5, '终于买到满意的商品了，超出期望，非常喜欢，宝贝已收到，是我想要的，手感很好，质量也挺好。\n外观材质：个人觉得黑色的比较好看\n屏幕效果：屏幕高清很舒服\n运行速度：很快，真的不卡\n其他特色：主要是记笔记很流畅，其他的平板比不了', '蓝色', '2023-01-01 11:43:01', 2);
INSERT INTO `data` VALUES (14425, '逃***孩', 5, '很好，收到礼物很开心很开心。小孩子用来看电视和自己追剧，一眼就看中了粉色，到手也很惊艳。比我想象的颜色还要好看很多&hellip;&hellip;物流非常快，上午买的下午就到了。\n轻薄程度：很轻薄\n运行速度：很流畅', '粉色', '2023-02-27 00:04:37', 2);
INSERT INTO `data` VALUES (14426, 's***e', 5, '外观材质：买的灰色的，颜色高级，很喜欢。整体是10.2的屏幕，屏幕大，比之前的版本好。\n屏幕效果：之前膜没到的时候裸机玩的，很沾指纹\n运行速度：速度快，反映快，256G内存完全没压力\n轻薄程度：我觉得挺薄的，甚至担心容易弯曲，所以就买了一个厚厚的粉色的壳子，做一下必要的保护\n其他特色：追剧确实比较爽', '蓝色', '2023-01-01 11:42:46', 2);
INSERT INTO `data` VALUES (14427, 'j***r', 5, '京东的东西还是信得过，想买好东西，就上京东，真的太好了，一分钱一分货，流畅，不卡顿，分享热点就可以啦', '银色', '2023-03-05 20:28:09', 1);
INSERT INTO `data` VALUES (14428, 'j***7', 5, '外观材质：很好看的蓝色，配上蓝色的外壳很搭\n屏幕效果：非常清晰，尺寸也很合适，适合看电影\n运行速度：很流畅\n轻薄程度：很轻巧，比上一代进步很多\n其他特色：这款性价比目前应该是最高的吧', '蓝色', '2023-01-08 00:01:06', 2);
INSERT INTO `data` VALUES (14429, '1***n', 5, '买的时候只剩黄色了，没想到第二天又有货了，别的颜色也有，有点儿坑，懒得退了，装了保护套也看不出来，速度很快，很多操作比老版本方便多了\n屏幕效果：很好，看电影确实其他电脑没法儿比\n运行速度：很快\n轻薄程度：很轻，比保护套轻', '黄色', '2023-01-10 20:34:45', 2);
INSERT INTO `data` VALUES (14430, 'm***n', 5, '非常满意！！京东出品！！很放心??是正品！！价格很优惠，非常不错。是新款的ipad，用的很开心，用来上网课的，一点都不卡，永远都是这样的好用。', '蓝色', '2022-12-10 17:45:10', 4);
INSERT INTO `data` VALUES (14431, 'j***d', 5, '一直很喜欢苹果的产品，折箱后马上开机，做工精致，手感一流，没有令我失望，非常非常喜欢。', '蓝色', '2023-01-06 22:15:40', 4);
INSERT INTO `data` VALUES (14432, '麦***兜', 5, '从IPAD5到IPAD8再到IPAD10，也说明了对iPad产品的喜爱和认可，iPad10相比之前的iPad数字系列有了非常明显的提升，取消了Home键，改用类似全面屏的设计，感官度有了提升，使用两天感受运行速度确实快了不少，屏幕显示效果也不错?', '银色', '2023-02-13 08:44:59', 3);
INSERT INTO `data` VALUES (14433, 's***j', 5, '用来学习的，很顺畅，尺寸大小很合适，不大不小。使用流畅方便。京东买了一系列电子产品，都很好用，送货快，质量有保障，值得信任', '银色', '2023-02-19 15:21:44', 3);
INSERT INTO `data` VALUES (14434, '听***_', 5, '用起来非常流畅，完全没有卡顿的情况，分辨率很高，照相看电视玩游戏办公都可以满足，点赞商家，感谢京东平台提供这么好的产品和服务', '银色', '2023-01-14 16:50:49', 4);
INSERT INTO `data` VALUES (14435, 'u***k', 5, '货收到了！可以说很满意！物流速度也快！大学生真的超级推荐这款平板 外观简介 颜色也好看简约大方 屏幕也大看着很舒服 平常用来看剧什么的很方便 轻薄更没话说 很便携 速度也快 不卡 很棒的哦！??', '银色', '2023-01-20 23:34:49', 2);
INSERT INTO `data` VALUES (14436, 'D***n', 5, '看上它很久了，一直在对比买哪一代实惠，这款全新的外观设计，取消了home键及其窄的边框让它的屏幕显得更大，颜色超级好看，清晰度高运行速度也很流畅，很不错哦', '蓝色', '2023-03-03 10:06:32', 3);
INSERT INTO `data` VALUES (14437, '吴***操', 5, '外观材质：平板电脑收到了，发货到货很快，买完第二天就收到了。很好\n屏幕效果：屏幕效果好\n运行速度：快\n轻薄程度：适中，手感不错\n其他特色：优惠的价格买的，性价比很高。喜欢。触屏效果好，反应灵敏', '蓝色', '2023-01-01 11:44:13', 2);
INSERT INTO `data` VALUES (14438, 'l***8', 5, '外观材质：外观很好看、买的银色的、不会过时\n屏幕效果：屏幕清晰、拍照像素也不错\n轻薄程度：不重、日常学习、追剧刚好\n性价比高、质量放心、推荐给大家、好评的很', '银色', '2022-12-15 16:13:07', 2);
INSERT INTO `data` VALUES (14439, '朱***好', 5, '新版的iPad重量比21年的轻多了，拿在手里手感真的不错，取消了home键，平板速度用起来很快，轻便，容量大，苹果平板确实要买新不买旧', '蓝色', '2023-01-30 20:57:49', 4);
INSERT INTO `data` VALUES (14440, '无***少', 5, '非常满意，大，像素高拍照好，看电视也舒服！买了键盘和笔，简直就是随身笔记本！而且还轻！点赞！\n256G完全够用，估计可以用个5-10年了！自营也放心，以后还会继续购买！', '蓝色', '2022-11-18 14:27:03', 2);
INSERT INTO `data` VALUES (14441, 'j***b', 5, '非常好，用起来很顺滑，外形还看，颜色很符合个人审美风格。屏幕比ipad9大挺多的，薄度适中，拍照很清晰，送给小孩子当礼物，非常喜欢', '银色', '2023-02-28 21:30:43', 2);
INSERT INTO `data` VALUES (14442, 'r***5', 5, '纠结了很久颜色， 蓝色还是银色，最终确定闭眼入的银色。 昨晚下单今天就到， 这个速度是杠杠的。 看测评说显示不行， 对于我要求不高 追剧使用的人来说 完全OK', '银色', '2023-03-05 13:16:18', 3);
INSERT INTO `data` VALUES (14443, 'L***3', 5, '外观很好看 蓝色的看着很舒服 够沉稳大气 买来主要给娃上网课用 感觉内存及运行速度各方面都是很给力的 好用 iPad很轻薄 屏幕也够大 整体很好 ?', '蓝色', '2022-12-26 11:54:34', 2);
INSERT INTO `data` VALUES (14444, 'j***E', 5, '尊好看呀尊好看，女孩子，比起辣妹粉我更喜欢这个低调大气的蓝\n到货就迫不及待打开了，果真没有让我失望，质量特别好，颜值也相当高，满意的一次购物高颜值，高品质，非常好，一分钱一分货，材质外观和质量一看就很上档次，非常喜欢', '蓝色', '2023-03-06 15:12:36', 2);
INSERT INTO `data` VALUES (14445, 'j***I', 5, '外观材质：非常具有现代感，非常轻，做为小朋友上网课的必备神器十分合适\n屏幕效果：非常清晰，亮度合适\n运行速度：很快，小朋友上网课的要求也不高\n轻薄程度：很轻，适合外出', '银色', '2022-11-13 15:22:04', 2);
INSERT INTO `data` VALUES (14446, 'u***s', 5, '日常追剧，学习提升，出门娱乐的神器，简直最好不过了。分期买了蓝色款，真的太喜欢了。质量棒棒哒，非常方便，一如既往的好用，赞赞赞！！！', '蓝色', '2023-02-10 23:28:46', 3);
INSERT INTO `data` VALUES (14447, 'K***源', 5, '平板真不错，送给妹妹的过年礼物，开心的不得了，好看好看真好看，流畅度很高，不卡，很轻薄，方便携带，运行速度很快，太喜欢了', '银色', '2023-01-24 15:13:46', 2);
INSERT INTO `data` VALUES (14448, '哆***啦', 5, 'ipad很好用的 建议可以买大内存的，以备不时之需。颜值非常高，系统很流畅，用来刷剧看视频很爽，可以用个四五年了哈哈镜哦。', '银色', '2023-01-18 16:51:44', 2);
INSERT INTO `data` VALUES (14449, 'k***次', 5, '京东自营调货发货，收到快递充电使用，买的256内存大些，挺好的激活后使用，买的粉色款很喜欢，可以搭配那个粉色保护套，自己搭配了保护膜，好评。', '粉色', '2023-02-27 13:37:53', 3);
INSERT INTO `data` VALUES (14450, '飘***-', 5, '朋友用的同款pad，看有些视屏音效和画质都很好，也买了同款，看电影确实不错，更有感觉一点，然后就听音乐，用着舒服，目前没做其他用。京东活动时间买的，价格比平常划算一点。', '银色', '2023-01-09 22:06:03', 3);
INSERT INTO `data` VALUES (14451, '卖***孩', 5, '自己买了一个蓝色，超好用，朋友看见一个，又帮忙卖了一个，真心不错，京东物流快，服务好，售后无忧，值得信赖的。平板用着也很顺畅。', '银色', '2023-03-18 22:41:47', 4);
INSERT INTO `data` VALUES (14452, '村***-', 5, '终于到手啦！?手机平板都是苹果的，互联互通性很强，互传文件很方便快捷&hellip;到手就很高大上的，太喜欢了！运行流畅，平时都是看视频用，音效也很棒??各方面都很满意，', '蓝色', '2023-02-23 06:15:16', 2);
INSERT INTO `data` VALUES (14453, 'j***2', 5, '外观材质：尺寸比老款大，手感很好，也不重\n运行速度：速度杠杠滴\n屏幕效果：看电影打游戏很不错', '银色', '2022-11-12 23:41:54', 2);
INSERT INTO `data` VALUES (14454, 'l***i', 5, '买来看谱子的，大小合适，苹果的电子产品还是很耐用的，上一个还是ipad2，终于是退休了。新款也是非常的轻便，黄色的壳子也是相当的靓丽。推荐。', '黄色', '2023-02-26 00:03:57', 3);
INSERT INTO `data` VALUES (14455, 'p***l', 5, '以前买的是iPadmini平板电脑，用了好几年，很好用，现在买了最新的平板，用于平时给孩子上网课，娱乐，游戏，很方便。苹果的质量还是很好的，用上几年没有任何问题', '蓝色', '2022-12-22 15:21:06', 2);
INSERT INTO `data` VALUES (14456, 'y***0', 5, '小巧玲珑，老婆拿着刚好。不是曲面屏可以贴钢化膜真香。外观好看，高端大气。最新的系统，操作流畅，特别好用。拍照效果非常好，满意。', '黑色', '2023-01-28 15:44:29', 3);
INSERT INTO `data` VALUES (14457, 'y***s', 5, '外形外观：外观开起来很棒\n屏幕音效：音效不错\n拍照效果：拍照效果很还原\n运行速度：允许速度非常快，一点也不杀后台\n待机时间：才收到手机，还没有感受，等后面补评\n其他特色：玻璃后盖拿起来很有质感，这种绿色饱和度很低，感觉挺不错的，等待使用一段后再评价', '旷野绿', '2022-12-27 19:36:20', 2);
INSERT INTO `data` VALUES (14458, '明***7', 5, '手感丝滑握着舒服，续航持久电池给力，系统运行速度超快，整体很好值得购买\n外形外观：很漂亮，握着舒服\n屏幕音效：屏幕护眼，音响效果很好\n拍照效果：拍照效果很好\n运行速度：运行速度超快\n待机时间：待机持久', '白色', '2023-01-04 18:49:45', 4);
INSERT INTO `data` VALUES (14459, 'b***y', 5, '小米13收到了，用了三天，感觉手感很好，一手掌握操作方便，触感灵敏，颜色干净透亮，照的照片清晰，前置摄像头美颜的也很自然，满意', '白色', '2023-01-27 10:20:18', 6);
INSERT INTO `data` VALUES (14460, '大***人', 5, '外形外观：质感真的没得说，也没有那么硌手。\n屏幕音效：屏幕冲击感很强\n拍照效果：拍照还可以\n运行速度：MIUI14还是很不错的，现在还没有bug，看看后续体验。', '白色', '2022-12-26 20:25:58', 6);
INSERT INTO `data` VALUES (14461, '開***头', 5, '外形外观：很漂亮，太惊艳了\n\n屏幕音效：虽然没上2k屏幕，但是1080P显示效果肉眼看不出来与2K的差别\n\n拍照效果：相机这次拍照速度非常快，构图也很精致，莱卡不是盖的\n待机时间：待机时间中规中矩吧\n\n运行速度：第二代骁龙8，运行速度飞起来', '白色', '2023-01-04 21:38:15', 4);
INSERT INTO `data` VALUES (14462, 'K***R', 5, '外形外观：金属直立边框，远山蓝背面是科技纳米皮，手握感很好\n屏幕音效：专业旗舰屏，超清晰，小屏尺寸刚刚好，音效还过得去吧\n拍照效果：拍照效果就真的一流，徕卡专业光学镜头\n运行速度：快如闪电般\n待机时间：一天忙下来还有电', '远山蓝', '2023-01-11 14:09:36', 5);
INSERT INTO `data` VALUES (14463, '只***称', 5, '期待很久的小米13总算出来了，大爱直角边框，总算不用担心太滑摔了屏幕了，颜值给力！后盖是圆弧的，所以也不会很割手，手感好评！拍照终于加上了2 x，很常用，大师镜头也很给力，排出的照片yyds，就是自己的技术还一般，总之手机很满意，**入了！小米加油！13大卖！', '远山蓝', '2023-01-07 21:34:13', 4);
INSERT INTO `data` VALUES (14464, '锋***9', 5, '小米13是我媳妇最满意的一个手机，特别这个尺寸手感特别好，单手操作很舒服，外观颜色炫酷，直角边框，是我最喜欢的！运行流畅，像素清晰，电池很给力，小米13集优点于一身，真的给我惊喜，物有所值，喜欢的不要犹豫了！', '旷野绿', '2023-01-14 12:04:59', 2);
INSERT INTO `data` VALUES (14465, '冷***O', 5, '外形外观：不错，不喜欢曲面屏，不然就买pro了\n屏幕音效：很清晰，够大声，爸爸听得见\n拍照效果：清晰，防抖不错\n运行速度：顺滑\n待机时间：还不知道，刚刚到货。试了一下充电，很快\n其他特色：无', '黑色', '2023-01-12 20:43:35', 3);
INSERT INTO `data` VALUES (14466, 'j***g', 5, '12月10日新机发布就有留意，刚好哪时朋友换13Pro陪他去了实体店看过，感觉颜值手感都挺不错，主要是手机较小，便于携带。从苹果手机换过来的，多年未用过安卓机，这次的小米13还是挺不错的，从新刷新对安卓的认可，手机显示很清晰，耗电控制很好，重度使用一天一充，充电也超快45分钟充好，系统很人性化，开源软件体验较丰富，但是外放声音真的差劲！手机办公没有苹果好用，不够人性化，综合售价还是挺不错的。', '白色', '2023-02-13 10:35:15', 4);
INSERT INTO `data` VALUES (14467, '暴***蛋', 5, '手机收到了，质量很好，外观漂亮，用起来很顺手，运行速度快，真香?。', '黑色', '2023-02-11 16:37:49', 4);
INSERT INTO `data` VALUES (14468, '日***迪', 5, '外形外观：真的很喜欢直屏手机，完美，一手掌握。\n拍照效果：徕卡加持真的不错，\n运行速度：很好，关闭广告后，运行丝滑，关闭广告真的香啊。\n屏幕音效：屏幕不到两千是个缺憾，不过鱼与熊掌不可兼得啊。', '水泥灰', '2023-03-09 15:45:54', 4);
INSERT INTO `data` VALUES (14469, 'j***g', 5, '外形外观：白色外观真的很好看，yyds\n\n屏幕音效：屏幕大小很合适，用起来刚刚好，很喜欢\n拍照效果：很清晰\n运行速度：畅享丝滑\n待机时间：续航能力强\nps：手机壳也不错。手感挺好。', '白色', '2023-01-08 18:45:56', 3);
INSERT INTO `data` VALUES (14470, '阿***呦', 5, '外形外观：非常漂亮，旷野绿玻璃，是真的好看。\n屏幕音效：屏幕亮度给力，用了才知道。\n拍照效果：在家里，随手拍了几下，反应很快，拍照效果比手上的小米11好。\n手机很好，没有硌手的感觉，米柚14运行速度很快，很流畅。到手立刻申请小米13开发版，开发版才好玩。', '旷野绿', '2023-01-10 20:11:11', 5);
INSERT INTO `data` VALUES (14471, '难***友', 5, '小米13直角边框精致，一体型好，质感好,非常适合女孩子，可视较好，还有护眼很不错了,如果能加上2k屏幕更完美。徕卡相机照相非常棒，长焦也非常清楚，平时拍照绝对够用了。运行也很快，续航一天没问题， 整体来说小米13非常好，手机小巧玲珑，重量也轻，莱卡相机照相也非常完美，特别适合女孩子用。', '旷野绿', '2023-03-06 19:24:42', 3);
INSERT INTO `data` VALUES (14472, '浮***e', 5, '畅快拍照效果:清晰续航能力:很好小米13是我最满意的一块手机，特别这个尺寸手感特别好，单手操作很舒服，外观颜色炫酷，直角边框,是我最喜欢的!运行流畅，像素清晰，电池很给力,小米13集优点于一身，真的给我惊喜，物有所值，喜欢的不要犹豫了!', '白色', '2023-02-03 11:52:33', 4);
INSERT INTO `data` VALUES (14473, '啰***嗦', 5, '外形外观：确实像苹果，都被好几个朋友问这是哪款苹果了，但方方正正中又带点弧度\n屏幕音效：屏幕很清楚，阳光下也够用\n运行速度：动画很快，很流畅\n待机时间：比之前的11好多了\n刚开始由11换过来还不太适应，习惯了还是很不错的', '旷野绿', '2023-01-10 22:46:01', 4);
INSERT INTO `data` VALUES (14474, '折***猪', 3, '外形外观：还行\n屏幕音效：屏幕短暂失灵，还经常出现，音量放到最大会破音\n拍照效果：还行\n运行速度：可以\n待机时间：可以，比之前小米八好太多\n其他特色：无', '黑色', '2023-03-11 13:57:29', 3);
INSERT INTO `data` VALUES (14475, '初***t', 5, '完美，产品很惊艳，性价比合适，希望用的长久！\n屏幕很惊艳，四边框等宽，屏幕很大，画面清晰，运行速度快，MIUI14很流畅', '白色', '2023-02-01 21:48:20', 5);
INSERT INTO `data` VALUES (14476, '德***丿', 5, '外形外观：感觉挺好\n屏幕音效：屏幕感觉不算小屏，不大不小刚刚好\n运行速度：很快很快\n待机时间：电池?耐用\n其他特色：屏占比视觉冲击大\n\n拍照效果：很nice', '旷野绿', '2023-01-27 22:34:01', 3);
INSERT INTO `data` VALUES (14477, '王***4', 5, '拍照效果：清晰\n续航能力：很好\n运行速度：畅快\n外形外观：四边等窄，手感比水果好，尤其是素皮屏幕音效：屏幕素质不错，和三星22u对比也不落下风，音质相对来说中规中矩拍照效果：感觉还差点儿意思，仍有提升空间运行速度：配合miui14速度很快很流畅，基本上没有遇到卡顿待机时间：晚上12点充满电放一边，早上8点拿起来看，电量为\n99%，很满意。其他特色：裸机正面看太像水果14了？，但信号比水果强多了', '黑色', '2022-12-30 10:59:31', 3);
INSERT INTO `data` VALUES (14478, '玫***7', 5, '外形外观：漂亮，手感很好\n屏幕音效：惊艳\n拍照效果：很好\n运行速度：快速，配置很高\n待机时间：很好', '黑色', '2023-02-07 20:03:08', 4);
INSERT INTO `data` VALUES (14479, '十***死', 5, '外形外观：果里果气的，对于直角边框党来说简直完美，重量很轻，称得上是小屏旗舰，非常符合我的预期\n屏幕音效：屏幕颜色感觉比现在用的米10ultra好很多\n拍照效果：不愧是徕卡镜头，很不错\n运行速度：上一个小米8G内存很不够用，这次买了12G的，后期再看看效果咋样\n待机时间：还没具体使用，看评测说耗电控制很好', '白色', '2023-01-05 16:44:40', 3);
INSERT INTO `data` VALUES (14480, 'j***s', 5, '哇，特别好用，小巧，精致，满足了我对小米13的想象，素皮的特别好，很轻，后盖不会再碎，解决了我的一大痛点', '远山蓝', '2023-02-02 19:05:22', 4);
INSERT INTO `data` VALUES (14481, '樱***影', 5, '手机收到了，反应很快，人脸秒接锁，游戏运行流畅，白色很好看，屏幕养眼，电池也还好，中度使用一天没问题，充电速度很快，语音助手和智能音箱一样双手没空的时候也能进行很多操作，手机重量因人而异吧，不觉得太重。充电速度很快，非常不错\n外形外观：白色很好看\n屏幕音效：双扬声器，声音立体\n拍照效果：拍照效果非常不错，\n运行速度：速度快，非常流畅', '白色', '2022-12-24 19:41:07', 4);
INSERT INTO `data` VALUES (14482, '南***B', 5, '在纠结很久之后终于下手小米13了，根据目前半天的使用情况来看，确实是13香了。非常流畅，好看精致，基本上和测评结果一致。\n小米旗舰店送的碎屏险很有安全感。\n快递稍稍不足，顺丰也花了两天多了，还是不如京东的次日达好，京东快递的服务也好一些。', '旷野绿', '2023-01-09 09:39:08', 7);
INSERT INTO `data` VALUES (14483, '末***手', 5, '小屏+直屏手感很棒，蓝色和白色都很赞，一次入手两台，和老婆一人一台。对于我们两个不玩游戏的人来说，续航和性能完全够用，这次的13确实挺让我满意。', '白色', '2023-02-21 19:30:42', 4);
INSERT INTO `data` VALUES (14484, 'j***5', 5, '拿到手机小巧，颜色也很喜欢啊。\n感觉挺好的，还不错呢，具体等后期用了来追评啊\n拍照效果：很棒\n运行速度：挺快的，也不卡顿', '远山蓝', '2023-02-23 17:56:19', 4);
INSERT INTO `data` VALUES (14485, 'z***p', 5, '正面观感很好，续航给力，后盖有弧度处理手感也不错，骁龙8gen2对比8+提升也很大，用了这么多年手机，我总算用上了小屏+白色，以前基本是黑色的，只为了省一点钱，看看这次能钉住吗', '白色', '2023-01-08 12:51:28', 3);
INSERT INTO `data` VALUES (14486, 'j***y', 5, '外形外观：非常漂亮，手感也很好，喜欢小手机不喜欢大的\n屏幕音效：屏幕显示很清晰\n拍照效果：莱卡就是不一样，拍出来的图片很生动\n运行速度：快！\n总体上来说值得购买，小米没让我失望', '旷野绿', '2023-01-08 17:35:12', 3);
INSERT INTO `data` VALUES (14487, 'w***n', 5, '外形外观：小屏手机战斗机，外观不错，握感也可以，如果再小那么一点就更好了！\n拍照效果：拍照效果感觉比之前的12s好点，调试的比较出色\n运行速度：运行速度真的无话可说，完全看不出来有什么毛病，搭载最新的MIUI14，流畅太多了！', '黑色', '2023-01-29 20:21:22', 3);
INSERT INTO `data` VALUES (14488, 'j***p', 5, '这个手机正面真的是嘎嘎好看，四边都很窄，这个蓝色也是真的好看，素皮摸起来很舒服。\n屏幕音效：屏幕看起来很舒服\n拍照效果：徕卡的拍照确实好', '远山蓝', '2023-03-05 12:48:22', 4);
INSERT INTO `data` VALUES (14489, '_***_', 5, '手机收到了，手感润润的，不隔手，屏幕看很清晰，色彩饱满，最喜欢的还是这个外观，终于有了眼前一亮的感觉，以前小米出新机总会等等看，这次果断出手，先用着看，有什么优点再和大家分享。', '旷野绿', '2023-02-05 21:50:29', 4);
INSERT INTO `data` VALUES (14490, 'D***z', 5, '外形外观：好看，非常的好看，简简单单的\n屏幕音效：屏幕效果也是杠杠的，音效更没话说\n拍照效果：照片都是直出，不需要调色\n运行速度：如闪电一般\n待机时间：待机足够玩一天了\n其他特色：比很多品牌的手机，都好用', '白色', '2023-02-27 09:41:03', 2);
INSERT INTO `data` VALUES (14491, '而***夏', 5, '期待很久的小米直屏手机终于到手了，上手感觉很不错，边缘过渡比苹果好，不搁手，屏幕大小也刚合适，在手机屏幕尺寸越做越大的年代，换回稍微小屏一点的手里真的有不一样的感觉，我感觉很不错，MIUI也很流畅，性能不用多说了，拍照很不错，虽然没有13Pro那么惊艳，但对于我一个日常拍拍日落或者其他好看的风景的人，13完全够用了', '白色', '2023-02-28 08:35:55', 3);
INSERT INTO `data` VALUES (14492, 'w***h', 5, '外形外观：大小刚刚好，是我想要的，外观一流，手感很好\n运行速度：非常流畅，性能强劲\n待机时间：普通，没有特别惊艳\n拍照效果：相机响应速度快，拍照清晰', '黑色', '2023-01-27 10:48:35', 3);
INSERT INTO `data` VALUES (14493, '初***3', 5, '充电速度很快，手机手感也不错。质感很好。续航值得称赞。手机流畅度也不错，', '黑色', '2023-01-08 19:01:50', 3);
INSERT INTO `data` VALUES (14494, '沧***奇', 3, '今年新机只有13比较个别，别的都是太商务啦，还是小米十三大小，重量来说，对于女生比较友好，不过看有些\n拍照效果：拍照很好，有徕卡你懂的\n屏幕音效：声音对于我来说很nice\n外形外观：最满意的地方啦\n其他特色：唯一不住就是屏下指纹解锁不灵敏', '白色', '2023-01-15 19:15:50', 1);
INSERT INTO `data` VALUES (14495, '柠***萌', 5, '外观大方，漂亮颜值高 屏幕画质细腻，超清晰 手感握持正好.运行畅快，续航很好 拍照清晰！非常满意的一款手机，等了好久还是值了。', '白色', '2022-12-19 11:13:06', 3);
INSERT INTO `data` VALUES (14496, '一***下', 5, '外形外观：很小巧精致\n屏幕音效：杜比音效不错\n拍照效果：很还原，防抖的话就更好了\n\n\n打游戏开性能模式试了下，不会很烫，总体来说还不错', '白色', '2023-02-18 09:56:54', 3);
INSERT INTO `data` VALUES (14497, 'u***r', 5, '买之前在iqoo11和米13之间反复横跳，之前米8也是用到现在了，所以最后还是选择了米13 白色外观真的很像?，整体尺寸比米8小一点，我要是大屏需求真的直接冲iqoo11去了 拍照拿我米8的话我只能说好了很多 流畅度：很流畅，想不到有什么游戏好玩的没游戏运行评价', '旷野绿', '2023-01-24 22:22:37', 5);
INSERT INTO `data` VALUES (14498, 'j***e', 5, '快递很快，屏幕各方面都是当面验货，没有瑕疵。\n外形外观：很时尚，喜欢。\n拍照效果：就是看中莱卡拍照，确实很不错\n运行速度：巨快巨流畅\n待机时间：还好，拿回来导入了一天数据，晚上才充电\n其他特色：充电也巨快，没有说的很烫那么夸张，感觉小米手机可以的，第一次体验小米产品，以后可能还会买小米。', '黑色', '2023-02-23 00:07:27', 2);
INSERT INTO `data` VALUES (14499, 'j***j', 5, '一如既往的好品质，非常喜欢的一款产品，非常棒！o(*￣︶￣*)o这质量真是太意外了，实物美美哒，触感很好，很推荐哦~挺好的，和想象中一样，满意！\n一次很好的购物体验，服务周到，物流快速，配送也很周到，态度也很好，物有所值啊，果断好评！', '旷野绿', '2023-01-10 18:19:48', 4);
INSERT INTO `data` VALUES (14500, '你***Q', 5, '反应超快，一只手刚好拿捏。喜欢小屏旗舰的可以入手了。个人更喜欢13，直屏，可以贴钢化膜。', '白色', '2023-02-11 12:12:39', 2);
INSERT INTO `data` VALUES (14501, '卢***4', 5, '拍照效果：很真实\n屏幕音效：还可以接受\n运行速度：快，不卡\n待机时间：待机挺好的\n其他特色：手感很好', '白色', '2023-01-16 16:51:10', 3);
INSERT INTO `data` VALUES (14502, 'D***6', 5, '外形外观：重量轻，单手握持很舒服，直边不会有割手感\n屏幕音效：显示效果完美，声音略小\n拍照效果：相机成像效果好\n待机时间：充满电一天中度使用没问题', '黑色', '2022-12-19 20:10:10', 2);
INSERT INTO `data` VALUES (14503, '奔***s', 5, '外形外观：很喜欢\n屏幕音效：可以\n拍照效果：可以\n运行速度：很快，打游戏很好?', '黑色', '2023-01-18 11:00:07', 4);
INSERT INTO `data` VALUES (14504, '0***0', 5, '外形外观：好看！选的绿色超级好看\n屏幕音效：杜比全景声很不错\n拍照效果：徕卡效果特好，随手一拍就是片\n运行速度：无脑12G，后台留存无敌了\n待机时间：电池比11u小一点，但是充电67w够用了\n其他特色：手感特别好，魅族20遥遥无期，小米13就是无敌的安卓小屏旗舰，推荐大家上车', '旷野绿', '2023-02-01 11:22:14', 2);
INSERT INTO `data` VALUES (14505, 'd***0', 5, '还是直面屏舒服！去年刚买的12用着很不爽，已经屏幕摔了下索性换13了！这个颜值爱了！头天下单第二天一大早就到了！', '远山蓝', '2023-03-06 18:41:28', 5);
INSERT INTO `data` VALUES (14506, 'p***黑', 5, '小米13是个很有质感的小屏手机，到手了手感非常好，屏幕清晰，运行流畅，很满意。我的mix2s可以退休了。', '黑色', '2023-01-05 09:47:29', 5);
INSERT INTO `data` VALUES (14507, '四***风', 5, '首先，买这款手机是冲着第二代骁龙8 CPU去的。另外，小米13是直屏手机，这一点也是我比较喜欢的。我的上一个手机是MIX2S,为了等一台直屏的小米手机，这之间我一直没有换手机。现在，小米手机在出厂时已经很贴心的为屏幕加了保护膜，还赠送了一个保护套。这一点非常好。我从小米还没有开始生产手机时，就已经在其它手机上刷入MIUI了。现在的系统已经是MIUI14了，用起来更加方便和流畅。', '黑色', '2023-03-03 20:58:12', 4);
INSERT INTO `data` VALUES (14508, '杨***o', 5, '真的很流畅 而且手感很好 但是裸机的手感会好 带上壳就太厚了 整体很喜欢 昨天拍的今天就到了 喜欢！！！', '白色', '2022-12-24 21:14:10', 4);
INSERT INTO `data` VALUES (14509, '醉***阳', 5, '外形外观：直屏四边窄边框，非常美观\n屏幕音效：1080p小屏的精细度还可以，三星e6的亮度确实很高\n拍照效果：拍照速度很快，有长焦更符合生活需求\n运行速度：骁龙8g2的功耗性能表现都很优秀\n待机时间：日常使用5g下亮屏6小时多一些，WiFi下可以到8小时及以上，续航非常好', '白色', '2023-01-17 15:21:40', 2);
INSERT INTO `data` VALUES (14510, 'j***R', 5, '非常不错的旗舰机，自己用米10。给老婆买的小米13。老婆非常喜欢，拍照有自动美颜，比我这个AI美颜还好看。这次采用小屏，虽然也没小太多，但视觉还是很不错', '白色', '2023-02-13 21:43:55', 3);
INSERT INTO `data` VALUES (14511, '时***宇', 5, '外形外观：很不错，手感很棒\n拍照效果：效果很不错，拍照效果很nice\n运行速度：快，真的看来好的处理器带来的性能提升真不是吹的', '黑色', '2023-01-06 11:45:53', 2);
INSERT INTO `data` VALUES (14512, '一***李', 5, '外形外观：外观好看\n屏幕音效：音效很好，声音大\n拍照效果：拍照清晰\n运行速度：运行速度快\n待机时间：待机时间长，用一天没问题\n其他特色：MIUI很好，速度快', '远山蓝', '2023-03-05 21:12:09', 2);
INSERT INTO `data` VALUES (14513, '返***1', 5, '手机手感超级棒，外观设计优雅，屏幕边框完美。音效逼真，还原真实。拍摄清晰，莱卡联名。夜景很棒，运行速度快，待机时间长，绝对大爱。', '白色', '2023-01-03 14:09:57', 3);
INSERT INTO `data` VALUES (14514, 'u***y', 5, '非常好，宝贝很高大上，质量很好，看上去就给人一种高级感，这次网购很愉快，大赞?，很惊喜，质量非常好，很满意的一次购物。开始买了黑色的，虽然好看但太爱沾指纹了，就换了个白色的，还是白色的更好看一些。第一次用小米，使用看看吧。', '白色', '2022-12-16 21:45:34', 4);
INSERT INTO `data` VALUES (14515, '1***_', 5, '外形外观：小直屏yyds，握持感非常好。\n\n拍照效果：足够应付日常拍摄。\n运行速度：120hz超级丝滑。\n待机时间：电池很耐用。', '黑色', '2023-01-29 13:50:23', 2);
INSERT INTO `data` VALUES (14516, 'e***e', 5, '尺寸不大不小刚刚好，直边直屏，这个尺寸安卓旗舰仅此一款没有竞品。运营流畅目前无任何卡顿超顺滑，手感一流，我是水果13转过来的，应用分身还多。', '白色', '2023-03-11 15:51:03', 4);
INSERT INTO `data` VALUES (14517, 'j***5', 3, '有时有闪退，看起点都有', '旷野绿', '2023-03-06 22:59:10', 4);
INSERT INTO `data` VALUES (14518, '哥***躁', 5, '买的小米13，很可心儿。屏幕清晰，手感不重，语音识别和触屏挺灵敏，总体来说很值得购买，喜欢，点赞?', '黑色', '2023-01-17 13:31:25', 4);
INSERT INTO `data` VALUES (14519, 'w***8', 5, '外形外观：手感舒适，正面颜值无敌\n运行速度：非常流畅，打游戏很舒服\n待机时间：一天一充，没有电量焦虑\n其他特色：小米换机省心省力', '白色', '2023-01-10 23:28:01', 2);
INSERT INTO `data` VALUES (14520, 'j***a', 5, '运行速度：畅快\n续航能力：很好\n拍照效果：清晰\n照片虽然看上去和现在大多数安卓机类似 **无奇。但是到手 特别是黑色还是超级好看的。用惯了MAX可能是会嫌小，但是 有重量和握持手感的超棒提升 。理想状态还是max+这个双持还是比较香的。希望续航顶一点。67w快充还是很不错的，四十分钟充满', '黑色', '2023-01-08 10:28:05', 2);
INSERT INTO `data` VALUES (14521, 'j***蜗', 5, '外形外观：果里果气的，后背玻璃有点弧度，手感非常好\n\n拍照效果：拍照速度比红米note8好多了\n运行速度：精简之后系统非常流畅，真不愧是挥刀自*宫的爷们。', '黑色', '2022-12-26 18:35:55', 3);
INSERT INTO `data` VALUES (14522, '帥***8', 5, '到手前网上看到有人说边框质感像塑料，个人觉得并不像，整机质感很不错，打开切换应用都很流畅的感觉。指纹识别很快（本来挺担心短焦指纹的），应该又是一款钉子户。', '白色', '2022-12-18 17:56:57', 3);
INSERT INTO `data` VALUES (14523, 't***f', 5, '外形外观：绿色蛮好看的 偏灰色的绿色\n屏幕音效：屏幕比小米10小很多所以看着黑边还是蛮大的\n\n拍照效果：很不错', '旷野绿', '2022-12-19 22:00:00', 3);
INSERT INTO `data` VALUES (14524, 'R***能', 5, '外形外观：不喜欢曲面屏，所以选择小米13，屏幕够清晰。爱不释手，小巧玲珑，一支手可以操作，莱卡相机拍照也非常清楚，推荐???', '远山蓝', '2023-02-20 16:39:04', 3);
INSERT INTO `data` VALUES (14525, '乔***嗷', 5, '小米13是我最满意的一块手机，特别这个尺寸手感特别好，单手操作很舒服，外观颜色炫酷，直角边框，是我最喜欢的！运行流畅，像素清晰，电池很给力，小米13集优点于一身，真的给我惊喜，物有所值，喜欢的不要犹豫了！', '黑色', '2023-01-28 21:42:02', 3);
INSERT INTO `data` VALUES (14526, 'W***e', 5, '外形外观：非常棒\n屏幕音效：很不错\n拍照效果：可以\n运行速度：快\n待机时间：很长\n其他特色：非常不错值得推荐', '白色', '2023-02-13 20:57:36', 2);
INSERT INTO `data` VALUES (14527, '水***6', 5, '我觉得miui14这次是真的流畅，配合120刷新率，操作很顺滑。4500的电池差不多正常办公加上下班途中刷视频一天还能剩余10%左右。8g2处理器性能很强，但暂时还没玩游戏就不做评论了。机子手感不错，值得购买，建议运存买12G的，应用多开没压力。', '旷野绿', '2023-01-14 14:33:36', 3);
INSERT INTO `data` VALUES (14528, 'j***z', 5, '小米13感觉手感很好，一手掌握操作方便，很适合女生。触感灵敏，外观好看，颜色干净透亮，照的照片很清晰，使用起来很方便。', '白色', '2023-02-27 09:16:52', 2);
INSERT INTO `data` VALUES (14529, '李***o', 5, '正面颜值无敌，小巧好用，直屏旗舰，续航超级好，奶卡加持拍照?也很好，miui14意外的好用！！！直接钉子户预定！！！', '白色', '2022-12-29 15:00:03', 3);
INSERT INTO `data` VALUES (14530, '凹***o', 5, '外形外观：小屏旗舰，很高端的感觉\n拍照效果：细节把控很到位\n待机时间：充满电轻度游戏一天足够了\n运行速度：软件打开速度特别快，MIUI14也不错', '黑色', '2023-01-15 14:49:51', 2);
INSERT INTO `data` VALUES (14531, 'a***0', 5, '外形外观：非常新潮好看。。。\n屏幕音效：非常清晰细腻。\n拍照效果：徕卡不用说了吧。\n运行速度：这个更不用说了，最新一一代gen2\n待机时间：非常满意\n其他特色：整体非常符合我的审美观。', '黑色', '2023-01-20 01:59:55', 2);
INSERT INTO `data` VALUES (14532, 'm***7', 5, '犹豫很久要白色还是绿色的，最后抢了绿色，手感很好，绿色真机比图片好看，比我拍的颜色浅一些，温润，可以冲', '旷野绿', '2022-12-19 18:08:04', 3);
INSERT INTO `data` VALUES (14533, 'L***h', 5, '外形外观：蓝色外观很好看，纳米材质摸起来很舒服\n\n待机时间：充电半个多小时就能充满，可以用很久\n\n其他特色：机身很轻盈', '远山蓝', '2023-01-10 00:56:05', 3);
INSERT INTO `data` VALUES (14534, 'K***e', 5, '小巧玲珑，不是曲面屏可以贴钢化膜真香。外观好看，高端大气。最新的系统，操作流畅，特别好用。拍照效果非常好，满意。', '黑色', '2023-02-18 20:40:26', 2);
INSERT INTO `data` VALUES (14535, 'k***u', 5, '很喜欢的安卓直屏机器，小米13的外观非常完美，机身小巧，它完美地平衡了尺寸和功能，单手操作起来很顺手。我喜欢小米13的主要原因：比它更好的手机没有它那么小。比它小的手机，不如它好。', '黑色', '2022-12-31 16:54:09', 2);
INSERT INTO `data` VALUES (14536, 'J***y', 5, '一直买的小米手机，新入手的13很小巧。莱卡摄像头很强大，比我小米11ultra表现好，很喜欢。', '黑色', '2023-02-05 21:16:19', 5);
INSERT INTO `data` VALUES (14537, '反***轴', 5, '外形外观：好看，手感舒适\n拍照效果：比我原来的k30好多了\n待机时间：挺长的！没玩游戏玩了好久\n运行速度：真的很快很顺滑\n很喜欢', '白色', '2023-01-20 11:24:26', 2);
INSERT INTO `data` VALUES (14538, 'j***c', 5, '外形好看，和在用的手机大小差不多，新手机就是手感好，弟弟钟爱小米，强烈推荐的这款，昨天买的，今天收到了，速度很快，目前整体还满意，后续使用一段时间再来追评，感受下小米系统。', '旷野绿', '2023-02-10 21:29:53', 3);
INSERT INTO `data` VALUES (14539, '夏***月', 5, '续航能力 好 拍照效果清晰 运行速度畅快 显示效果很好还不错一直想买小屏手机，小米13太适合了，上手手感很好', '白色', '2023-01-30 23:05:48', 2);
INSERT INTO `data` VALUES (14540, 'j***爱', 5, '观望了一段时间，小米13还算是近期性价比比较好的手机了，入手之后使用了感觉还不错，拍照好看，颜色饱满，挺满意的，物流寄的顺丰，也挺快的，外观设计漂亮，尺寸大小合适，包装仔细完整，宝贝手感不错，感觉很好，发货速度快，服务态度一流，给力！5星好评！', '白色', '2023-01-28 19:51:36', 3);
INSERT INTO `data` VALUES (14541, 'j***Y', 5, '快递配送得特别的快   早上九点下单的，下午七点多就到了  速度杠杠的  客服也特别有耐心  及时解答我的疑问。手机质感很不错    也很保电   67W数据线，一个多小时就能充满   小米手机yyds.', '黑色', '2023-01-31 13:55:42', 4);
INSERT INTO `data` VALUES (14542, '風***傷', 5, '小米13，手机不错，性能强悍，拍照很好，手感舒服。值得购买！', '远山蓝', '2023-01-07 12:52:58', 3);
INSERT INTO `data` VALUES (14543, '禾***口', 5, '小米13无论在续航还是发热上，都比12 pro好的多，四等边的屏幕比iphone还要窄，用着很舒服，\n我吃手感也是没得说，跟iPhone同样是直边框设计，但小米把后盖边缘做成弧度的，更贴个手掌，\n想买的朋友们，放心冲', '旷野绿', '2023-01-18 12:49:12', 2);
INSERT INTO `data` VALUES (14544, '成***心', 5, '说起来我也算是一个资深米粉了，记得第一次用直屏手机是小米2，到红米note3再到小米6再换曲面屏的小米10pro，到现在再入手小米13.经历过使用了三年的大尺寸曲面屏，大尺寸曲面屏有很多的细节问题导致用起来不是很顺心，这次入手小米13的初心是，喜欢它的小尺寸直屏给人的手感和耐用的电池，给人的感觉就像久经风尘的人找回了最初最原始的心。这次的13.在今年在今时今日或许它不是最完美的，到我觉得它是最值得的！', '黑色', '2023-01-19 21:43:11', 6);
INSERT INTO `data` VALUES (14545, '小***花', 5, '用小米很多年 米8 11 到现在的13 总体越来越好 手机更有质感了 运行流畅 希望后续使用会很顺畅', '旷野绿', '2023-03-06 23:29:00', 3);
INSERT INTO `data` VALUES (14546, 'u***q', 5, '终于买到了，小米13是我心意很久的手机，正面四边等宽，视觉上就给人震撼，加上最新的MIUI14非常流畅，旷野绿的颜色也让我眼前一亮，总体体验非常完美。赞赞赞', '旷野绿', '2023-02-10 19:21:00', 3);
INSERT INTO `data` VALUES (14547, '机***李', 5, '先到实体店去试了下，手感很舒服，屏幕显示也不错。\n外形外观：直屏，拿在手上有点5S的感觉。\n屏幕音效：效果惊艳！', '黑色', '2023-01-02 15:05:43', 2);
INSERT INTO `data` VALUES (14548, 'w***7', 5, '续航能力很好拍照效果清晰运行速度畅快， 通信音质：挺好的，不错不错 其他特色：远山篮高科技壳子，芜湖 显示效果：直面屏比曲面屏好多了，终于换回来了，曲面屏多长时间都不适应。', '旷野绿', '2022-12-20 17:25:11', 3);
INSERT INTO `data` VALUES (14549, '满***3', 5, '一直是小米的忠实用户，刚好最近手机出故障了，就购买了小米13。快递也很给力，第二天就收到货了。今天刚用上，使用起来非常流畅，通话效果也很好，满意。', '黑色', '2023-03-12 17:12:06', 3);
INSERT INTO `data` VALUES (14550, '五***3', 5, '颜色很好看，店里对比好久，拿下最喜欢的绿色，蓝色也好看，但是素皮不喜欢。比较小巧，手拿着刚刚好。用了几天了，挺好用的', '旷野绿', '2023-03-07 12:25:10', 2);
INSERT INTO `data` VALUES (14551, 'j***c', 5, '手感很不错，充电速度非常快，系统超流畅，自带了保护套和保护膜，老婆很喜欢', '旷野绿', '2023-02-02 21:03:47', 3);
INSERT INTO `data` VALUES (14552, '拉***式', 5, '外观大气，大小适中，手感不错，很有设计感，这个外观我很喜欢。运行很快，打开软件的速度也很快，', '白色', '2023-01-15 10:39:50', 2);
INSERT INTO `data` VALUES (14553, '住***鱼', 5, '手感不错，屏幕也很好，速度真心快，相机我不感兴趣，应该不会差，总体来说最近市面上应该属于很高端配置的手机了', '远山蓝', '2023-01-11 12:24:14', 3);
INSERT INTO `data` VALUES (14554, 'j***o', 5, '外形外观：正面边框很窄\n运行速度：运行速度挺快的\n拍照效果：拍照也可以\n其他特色：手机很轻，适合小屏党', '旷野绿', '2023-02-04 10:05:25', 2);
INSERT INTO `data` VALUES (14555, '念***鑫', 5, '感觉很不错，手感很不错，非常适合不怎么玩游戏的人，单手操作流畅。\n系统也很流畅，有点苹果系统的味道了。', '白色', '2023-01-31 18:31:24', 2);
INSERT INTO `data` VALUES (14556, '卸***g', 5, '外形外观：不错不错，真的很不错\n屏幕音效：屏幕是爱了，我很喜欢\n拍照效果：拍照一如既往的好看\n运行速度：12g的大内存，我很喜欢', '黑色', '2022-12-30 15:14:33', 3);
INSERT INTO `data` VALUES (14557, '领***4', 5, '无论材质还是做工都超出了预期，超值，用起来来也很好看哦。卖家发货也比预计提早了很多，还会再来。买吧，不会后悔的哦！全五分。', '旷野绿', '2023-01-05 10:25:04', 4);
INSERT INTO `data` VALUES (14558, 'j***a', 5, '可以，挺好看的，相机也很清晰，徕卡加持，的确很不错，手感也还行，性能也够用，续航还没试，总得来说还是可以的', '远山蓝', '2023-01-15 17:15:35', 3);
INSERT INTO `data` VALUES (14559, '小***8', 5, '手机挺不错的，运行流畅。而且拍照超好看，成像快，不愧是莱卡。颜值也是杠杠的，素皮挺不错的，手感可以。', '远山蓝', '2022-12-16 23:19:20', 2);
INSERT INTO `data` VALUES (14560, 'b***i', 5, '一直在关注小米出的这款新手机，外观是我一直很喜欢的直角大屏，屏幕显示非常清亮，续航时间也不错。这两年家里的手机都换了小米，希望小米能够再接再厉，持续有好的产品出来哟！', '旷野绿', '2023-02-06 15:22:16', 3);
INSERT INTO `data` VALUES (14561, 'C***Y', 5, '直框远山蓝纳米皮，外观大气漂亮，手感好。运行速度非常快，待机时间一天多点，拍照效果还不错。', '远山蓝', '2023-02-23 23:57:43', 2);
INSERT INTO `data` VALUES (14562, '何***后', 5, '总体来说还是很不错的，流畅度不错，外观质感很好，小屏手感无敌，拍照中规中矩，不过变焦过程相比以前很丝滑，这个价位值得购买', '白色', '2023-02-14 20:33:39', 2);
INSERT INTO `data` VALUES (14563, 's***1', 5, '?宝贝收到了，颜色很好看，质感也很好，样子简单！?是我想要的！！下次还会再来！非常好，宝贝很高大上，质量很好，看上去就给人一种高级感，价格也合适，这次网购很愉快，大赞?是正品，和实体店一样，价格还优惠，果断转粉', '白色', '2023-02-12 20:23:13', 2);
INSERT INTO `data` VALUES (14564, '玮***冠', 5, '给妈妈换的新手机，试用下来没有任何问题，质感非常好，直屏很漂亮，自己贴的钢化膜，非常nice。', '白色', '2023-01-18 23:22:17', 3);
INSERT INTO `data` VALUES (14565, '小***吖', 5, '新入手的小米13，功能真的很强大，国产的优秀代表！选了白色，好看百搭，推荐！出了电池续航不如想象的超长以外，完全满意～', '白色', '2023-02-26 19:10:45', 2);
INSERT INTO `data` VALUES (14566, 'j***b', 5, '外形外观：外观非常漂亮，高大上\n屏幕音效：音质还好吧，比起来10s来说这个确实差了\n拍照效果：比我之前的k40不知道好了多少倍\n待机时间：时间挺长的', '白色', '2023-02-03 21:57:58', 2);
INSERT INTO `data` VALUES (14567, '那***光', 5, '手机小巧，握持感很舒服，屏幕显示效果很棒，小米高端机入门很好，用了两天很舒服', '远山蓝', '2023-01-02 22:23:55', 3);
INSERT INTO `data` VALUES (14568, 'd***3', 5, '手感非常好，手机运行速度快，手机用起来感觉非常棒，白色真是YYDS????????', '白色', '2023-01-10 23:14:55', 3);
INSERT INTO `data` VALUES (14569, 'o***s', 5, '相当不错，直板小屏，徕卡镜头，续航很好，支持无线充电，支持IP68防水，有超越小米6的潜质，值得入手！', '白色', '2023-01-14 19:52:40', 2);
INSERT INTO `data` VALUES (14570, '陌***回', 5, '收到手机，直角很好，用起来也很流畅\n屏幕清晰，运行速度快，音质好，运行流畅', '远山蓝', '2023-01-20 17:01:11', 2);
INSERT INTO `data` VALUES (14571, 's***_', 5, '终于拿到手了，一直以来都是米粉，这次小米13一出也是迫不及待了，上手很不错，系统很流畅，转移数据也很方便，颜值高，拍照效果也挺不错', '白色', '2022-12-27 18:26:51', 2);
INSERT INTO `data` VALUES (14572, 'P***x', 5, '外形外观：直角边框跟直面屏是我喜欢的类型\n屏幕音效：屏幕也还挺好\n运行速度：运行速度很快\n其他特色：其他的还有待发现\n待机时间：还没用多久不好评价', '黑色', '2023-02-05 11:00:05', 2);
INSERT INTO `data` VALUES (14573, '木***毛', 5, '小米13的机身尺寸合适，尤其是裸机拿在手里的感觉非常棒。小米13的直角边框设计看起来很精致、利索。185g重量很不错，性价比高', '黑色', '2023-01-06 20:19:46', 3);
INSERT INTO `data` VALUES (14574, '酷***仔', 5, '小米13真的很不错 小屏旗舰 本来会感觉1k是不是不太够 拿到手屏幕真的很棒 e6就是牛 还省电 拍照也很棒', '黑色', '2023-01-07 12:44:49', 3);
INSERT INTO `data` VALUES (14575, '逃***_', 5, '快递很及时，很快就送到了。拆机迁移数据一气呵成，新手机就是好，直屏和曲面屏各有各的优势吧，直屏也用着挺好的。', '白色', '2022-12-27 20:12:28', 3);
INSERT INTO `data` VALUES (14576, '冷***-', 5, '特别好，很值得推荐。一直用的都是小米的东西。家里生态也是这小钢炮很推荐购买，而且现在还有365只换不修，还有各种东西送，分期免息之类的，特别推荐，物流也很快信赖京东平台，', '远山蓝', '2022-12-31 10:26:16', 3);
INSERT INTO `data` VALUES (14577, 'J***s', 5, '外观真不错，手感一流，特别是背面摸起来很带感。系统非常丝滑，玩游戏嘎嘎好用。', '远山蓝', '2023-01-30 20:13:56', 2);
INSERT INTO `data` VALUES (14578, 'j***4', 5, '外形外观：外形外观：一直以来都在用小米，终于出了款直屏，小巧精致，系统整体不错，使用一段时间待机也很给力，值得拥有！', '旷野绿', '2023-02-17 10:58:43', 3);
INSERT INTO `data` VALUES (14579, '老***生', 5, '虽然买的8+128g的版本，但是已经非常流畅，几年没有用过，MIUI系统真是有不少惊喜，系统动画非常喜欢！', '黑色', '2023-02-26 15:59:15', 2);
INSERT INTO `data` VALUES (14580, 'w***2', 5, '手机颜值很高，打游戏也不发烫，用起来体验很棒，，续航能力也很强，终于不用一天两充了', '旷野绿', '2023-01-14 08:51:00', 2);
INSERT INTO `data` VALUES (14581, 'j***6', 5, '手机尺寸绝对很棒，大小正是想要的，平板玻璃比弧面的用着顺手些，边框也很赞，满分好评', '远山蓝', '2023-01-10 14:15:33', 2);
INSERT INTO `data` VALUES (14582, '3***呀', 5, '小米13到啦到啦，手感很不错，颜色也是我喜欢的。喜欢小米的手机。顺丰物流很快。蛮不错的。拿在手里也很棒，买的12+256的，够用了。', '旷野绿', '2023-01-02 19:23:55', 2);
INSERT INTO `data` VALUES (14583, 'V***w', 5, '?发货很快，两天就到了，这个颜色我很喜欢，性价比很高，非常nice，高刷，嘎嘎丝滑，小直屏真的爱了爱了，从华为换小米真的很不错！', '白色', '2023-01-27 13:28:24', 2);
INSERT INTO `data` VALUES (14584, 'v***1', 5, '买了三台了质量非常好与卖家描述一致，孩子们非常喜欢，系统很流畅，也不发烫', '黑色', '2023-03-10 14:08:25', 3);
INSERT INTO `data` VALUES (14585, 'j***、', 5, '手感很好，买小米十三香就是冲着手感来了，买之前去线下小米之家把玩了一下，很喜欢这种小屏的手感，我用的是苹果XSM有点大，还有一台红米k30至尊，K30至尊比苹果还重。以前买的全是红米，这次买个小米来体验，确实有所不同，这次把小米13主力机，苹果当备用机了，准备做小米13钉子户了。', '黑色', '2023-01-24 23:33:50', 3);
INSERT INTO `data` VALUES (14586, 'j***4', 5, '从华为P40转过来，流畅了很多，双声道音质优秀，续航也强了，最满意拍照，都进化的很完美了！', '远山蓝', '2023-01-05 19:16:12', 3);
INSERT INTO `data` VALUES (14587, '一***丶', 5, '之前一直用的是苹果12pm，苹果的系统确实很流畅，但是用起来感觉处处受限，有种处处被管着的感觉，这两年一直怀念曾经用安卓的时光，去逛了我们这边的小米之家，先是从实体店看的这款小米13黑色，对比各种颜色之后还是黑色比较惊艳，最满意的就是这款小米13的背面设计，真的超好看了，绝绝子', '黑色', '2023-01-07 15:52:53', 1);
INSERT INTO `data` VALUES (14588, 'j***R', 5, '13真香，使用流畅，清晰度高，内存大，米家连用很棒，非常好用，物流特别快', '黑色', '2023-01-11 19:12:39', 3);
INSERT INTO `data` VALUES (14589, 'j***n', 5, '这应该是我用过的最好用的小米手机了，骁龙8gen2加上MIUI14确实非常舒服，丝滑流畅，喜欢它的轻巧以及颜值充电快', '白色', '2023-02-14 16:58:20', 2);
INSERT INTO `data` VALUES (14590, 'C***8', 5, '手机很满意，是我喜欢的小屏旗舰，白色外观也很好看，质感在线，拍照效果好，性能强悍', '白色', '2023-01-08 13:31:09', 3);
INSERT INTO `data` VALUES (14591, 'j***B', 5, '跑分无敌，手感无敌，外观无敌，这么多年的米粉，用过不下5款小米手机，这是我最满意的一台！很好看，制作工艺很精美，材质也很好！给个赞！', '白色', '2022-12-20 16:25:26', 3);
INSERT INTO `data` VALUES (14592, 'j***Z', 5, '使用了几天，6.36寸的手感确实比6.67寸好了很多，单手操作更舒适。手机很流畅，试了下下载速度达到50多M,我现在小米10只能达到15M左右。直屏观感也更舒服，满意。', '黑色', '2023-02-18 23:32:57', 3);
INSERT INTO `data` VALUES (14593, 'j***f', 5, '外形外观：方方正正 还不割手 握起来非常舒服\n运行速度：骁龙8Gen2 这代的提升很大', '黑色', '2023-01-14 19:11:52', 2);
INSERT INTO `data` VALUES (14594, 'j***b', 5, '收到了手机，快递也算给力。手机很丝滑很好用相机中规中矩（没想象中的好）但也不错。很喜欢直屏直屏yyds。拜拜旧手机', '旷野绿', '2023-02-17 20:42:04', 1);
INSERT INTO `data` VALUES (14595, '春***橙', 5, '13真的很香，很轻薄，续航也很强，两天没充电?，相素更是嘎嘎好', '黑色', '2023-02-23 09:44:55', 2);
INSERT INTO `data` VALUES (14596, '似***0', 5, '手机非常有质感，素皮蓝色加金属边框很好看。很喜欢长焦镜头。系统也在持续进步。', '远山蓝', '2023-01-17 09:43:50', 2);
INSERT INTO `data` VALUES (14597, '小***也', 5, '一看到有货就买了，比其他渠道好抢的多。手机很轻，握起来也不硌得慌。系统也比较流畅，不在意拍照的买这个真的好用', '旷野绿', '2022-12-22 15:40:04', 2);
INSERT INTO `data` VALUES (14598, '不***l', 5, '13是一款小型旗舰机，用起来很顺手，我就喜欢这样大小的。大小正合适，运行也很流畅，非常不错的一款机型。绿色看起来没有那么绿，是淡淡的绿色', '旷野绿', '2023-01-29 09:50:13', 2);
INSERT INTO `data` VALUES (14599, 'A***肩', 5, '手感很好，外观大气上档次，好用建议使用\n拍照效果：好好好', '远山蓝', '2023-03-05 15:33:33', 4);
INSERT INTO `data` VALUES (14600, 'u***d', 5, '第一次购买小米手机，确实是我想要的小屏手机，续航、拍照、流畅度目前都是杠杠的，由于华为这几年一直没有出5G手机，转小米了。希望小米高端之路越来越好！', '黑色', '2023-02-20 09:20:39', 4);
INSERT INTO `data` VALUES (14601, 'j***9', 5, '拍照效果：很不错，非常清楚\n外形外观：很像苹果14\n运行速度：玩游戏也非常流畅', '远山蓝', '2023-02-08 15:35:52', 2);
INSERT INTO `data` VALUES (14602, 'j***V', 5, '商品收到咯，特别喜欢，一收到就迫不及待地打开了，这次购物体验不错，手机拿在手机刚好，用的也很顺手', '白色', '2023-01-14 10:00:16', 3);
INSERT INTO `data` VALUES (14603, 'j***g', 5, '之前都是用曲面屏 这次小米的没让我失望  非常好 速度也很快  很小巧拿在手里也非常方便  外观也很大气 上档次 选的颜色也非常好看漂亮  选他就对了', '白色', '2023-02-19 11:34:20', 3);
INSERT INTO `data` VALUES (14604, 'j***6', 5, '颜值，手感，处理器，流畅度都是顶级的，从k30换过来的，感觉很好', '旷野绿', '2023-01-09 23:40:13', 2);
INSERT INTO `data` VALUES (14605, 'j***s', 1, '666等了两天收到货发现开机没声音，真是牛啊', '黑色', '2023-01-08 22:34:54', 6);
INSERT INTO `data` VALUES (14606, 'j***h', 5, '心水水~手机收到用了几天了，MIUI桌面真的太好玩了！实物是温柔的豆绿色的感觉，很喜欢！光线原因照出来偏黄。', '旷野绿', '2023-01-19 17:10:53', 2);
INSERT INTO `data` VALUES (14607, 'j***I', 5, '手机非常好看，手感也不错，王者画质那些开最高也可以稳住120针，用起来特别舒服', '白色', '2023-01-13 11:16:45', 2);
INSERT INTO `data` VALUES (14608, 'j***a', 5, '很轻哦 颜色好看比10u好很多，电池续航也还不错赶紧冲！！\n外形外观：薄轻', '远山蓝', '2022-12-31 15:33:43', 2);
INSERT INTO `data` VALUES (14609, '歪***6', 5, '小米手机就是棒，新一代旗舰，宝贝已收到，是我想要的，手感很好，质量也挺好，有问题客服也很快就解决了，态度非常好，一定好评！', '黑色', '2022-12-17 12:32:53', 5);
INSERT INTO `data` VALUES (14610, '从***果', 5, '手机收到了 感觉手感不错 颜值也很高??????', '白色', '2023-03-07 12:31:50', 2);
INSERT INTO `data` VALUES (14611, '披***3', 5, '系统流畅，运行速度快，外观小巧漂亮，手感好，女朋友超级超级超级喜欢！', '白色', '2023-02-15 13:06:27', 4);
INSERT INTO `data` VALUES (14612, '明***潇', 5, '一直用的小米产品，这次首发入了13，喜欢直屏小屏，快递很快，用用再看看体验', '旷野绿', '2023-01-01 20:27:19', 4);
INSERT INTO `data` VALUES (14613, '小***y', 5, '买就要买最好的，12+512内存杠杠的，拍照效果完美，屏幕适中，手感比较适合我！计算过百分之20到充满只要20分钟。', '旷野绿', '2023-01-18 22:15:37', 2);
INSERT INTO `data` VALUES (14614, '默***爸', 5, '之前买的也是小米，用了四年，当时内存买小了，13上市，果断换个新的，做工精细，边框特别小。', '旷野绿', '2023-01-31 19:21:02', 2);
INSERT INTO `data` VALUES (14615, 'j***延', 5, '很好很好很好！很喜欢小直屏，外观很秀气，主题都是免费的，用起来也很流畅，太喜欢啦~', '黑色', '2023-01-29 19:16:41', 1);
INSERT INTO `data` VALUES (14616, 't***x', 5, '手机手感很好，屏幕清晰。声音明亮清楚。主要是直屏这点好评，曲面屏太反人类了。', '白色', '2023-01-19 15:52:01', 2);
INSERT INTO `data` VALUES (14617, '涵***呢', 5, '手机很流畅，很喜欢，外观真的很耐看，质量手感都不错，爱了爱了，会推荐朋友来买，嘿嘿', '白色', '2023-01-13 17:24:44', 2);
INSERT INTO `data` VALUES (14618, '万***哥', 5, '一直都喜欢小巧的直屏手机，把用了几年的小米9se换成最新的小瓶旗舰小米13，手感还不错，相比小米9se速度续航太给力了。', '黑色', '2023-03-11 23:31:57', 2);
INSERT INTO `data` VALUES (14619, 'j***S', 5, '感觉实物比图片更好看，手感很好，很有苹果的既视感，就是感觉屏幕颜色有点发红 不过可以接受，这次购物非常满意，喜欢的宝宝赶紧下手', '白色', '2023-01-21 10:51:32', 1);
INSERT INTO `data` VALUES (14620, 'j***k', 5, '一直用的小米的手机，从最开始小米2S.再到小米8，直到现在用的小米13，手感特别棒，就是没买到自己喜欢的颜色，手机用了一个月了，也很顺畅，拍照特别棒', '黑色', '2023-01-19 08:37:13', 2);
INSERT INTO `data` VALUES (14621, 'x***y', 5, '新款小米13外观还是很漂亮的 比较精致 和上一代比起来小巧 也流畅不卡顿', '远山蓝', '2023-01-07 21:55:47', 2);
INSERT INTO `data` VALUES (14622, 'j***c', 5, '质量非常好，与卖家描述的完全一致，真的很喜欢，完全超出期望值，发货速度非常快，包装非常仔细、严实，物流公司服务态度很好，运送速度很快，很满意的一次购物，质量很好，希望更多的朋友信赖。店主态度特\n好，会再次光顾的好卖家。赞，发货迅速，态度很好，很\n满意！很好很好！网上购物这么激烈，没想到店家的服\n务这么好，商品质量好而价低廉，很热情的卖家，下次\n还来', '白色', '2023-01-10 13:56:17', 2);
INSERT INTO `data` VALUES (14623, '蛤***人', 5, '收到货了，拍照成片非常好，手机外观很好看，外放音质也很好，使用感觉非常流畅，电池续航能力很不错', '黑色', '2023-02-18 23:23:12', 2);
INSERT INTO `data` VALUES (14624, 'T***占', 5, '手机收到了，用了几天，感觉挺好的，速度快，系统流畅，手机颜值也很高。', '白色', '2023-01-13 19:08:28', 2);
INSERT INTO `data` VALUES (14625, 'j***z', 5, '拿到手确实是很不错的，蓝色素皮的感觉真的太好了，目前还没有问题，大爱！', '远山蓝', '2023-02-15 18:50:51', 3);
INSERT INTO `data` VALUES (14626, '人***如', 5, '外形外观：外观好看简洁\n运行速度：非常快，不卡\n待机时间：待机超强，用一天基本没问题\n拍照效果：很好，很清晰\n屏幕音效：屏幕护眼有dc调光不错', '旷野绿', '2023-01-30 23:25:24', 3);
INSERT INTO `data` VALUES (14627, 'j***y', 5, '小米13非常惊艳 屏幕的边框吊打苹果，莱卡相机和充电速度也非常好，物流速度也很快', '白色', '2023-01-08 21:31:09', 3);
INSERT INTO `data` VALUES (14628, 'j***h', 5, '手机用起来很快，拍照清晰，有很多模式可以选择，还没研究透，充电速度也很快', '远山蓝', '2023-02-21 19:15:13', 2);
INSERT INTO `data` VALUES (14629, 'j***y', 5, '从米4米5到k20p到米13，一直是小米的忠实用户，小屏手感好  配置杠杠的  水泥灰yyds', '水泥灰', '2023-03-16 18:03:50', 3);
INSERT INTO `data` VALUES (14630, 'j***c', 5, '外形外观：旷野绿颜色清新，陶瓷外壳很漂亮，颜值很高\n屏幕音效：屏幕清晰度和音效效果不错', '旷野绿', '2023-01-23 20:31:26', 2);
INSERT INTO `data` VALUES (14631, 'h***2', 5, '总体用起来不错，系统流畅，手感很好，第一次用小米手机，期待下一步表现', '旷野绿', '2023-01-07 11:08:47', 3);
INSERT INTO `data` VALUES (14632, 'c***1', 5, '这个手机真的非常爽  玩原神把画质拉到最高，玩了一下午也不卡一点卡顿都没有硬件超级给力充电也快，大概30多分钟就充满了推荐还是我最爱的平面屏', '黑色', '2023-01-07 12:34:59', 2);
INSERT INTO `data` VALUES (14633, '乾***份', 5, '很不错了，可以说是  非常  满意了，但是用多久要  时间来说明一切?  ?  ?  ?  ?  ?  ?', '远山蓝', '2023-03-06 08:53:36', 3);
INSERT INTO `data` VALUES (14634, '想***切', 5, '拿在手上很舒服，大小很合适，使用很流畅，一天下来没觉得有卡顿。小米13真的太棒了！', '白色', '2023-02-17 19:08:08', 2);
INSERT INTO `data` VALUES (14635, '西***8', 5, '宝贝已收到，是我想要的，手感很好，质量也挺好，性价比超高，手机性能很强悍，真的特别划算，包装也很高端大气上档次，值得购买。', '白色', '2022-12-23 16:13:47', 2);
